('w_work_C1_14','intellectual property','/ˌɪntəlektʃuəl ˈprɒpəti/','noun phrase','지적 재산권','Legal rights over creations of the mind.','Protect your {intellectual property}.','지적 재산권을 보호하세요.','intellectual property','C1','work',3,'intellectual property patent copyright'),
('w_work_C1_15','vesting','/ˈvestɪŋ/','noun','귀속·베스팅','The process by which stock options become owned.','Shares have a four-year {vesting} schedule.','주식은 4년 베스팅 일정이에요.','vesting','C1','work',3,'vesting stock options equity'),
('w_work_C1_16','deposition','/ˌdepəˈzɪʃən/','noun','증언 녹취','Sworn out-of-court testimony used in legal proceedings.','Give a {deposition} next Tuesday.','다음 화요일에 증언 녹취를 해요.','deposition','C1','work',3,'deposition legal court testimony'),
('w_work_C1_17','contingency','/kənˈtɪndʒənsi/','noun','비상 계획·불확실성','A future event that may affect plans.','Plan for every {contingency}.','모든 불확실성에 대비 계획을 세우세요.','contingency','C1','work',3,'contingency plan emergency business'),
('w_work_C1_18','solvency','/ˈsɒlvənsi/','noun','지급 능력','The ability of a company to meet its financial obligations.','Maintain {solvency} at all times.','항상 지급 능력을 유지하세요.','solvency','C1','work',3,'solvency finance balance sheet'),
('w_work_C1_19','restructuring','/riːˈstrʌktʃərɪŋ/','noun','구조 조정','Reorganizing a company to improve efficiency.','The {restructuring} affected 200 jobs.','구조 조정이 200개 일자리에 영향을 미쳤어요.','restructuring','C1','work',3,'restructuring company layoff change'),
('w_work_C1_20','deferred compensation','/dɪˈfɜːrd ˌkɒmpənˈseɪʃən/','noun phrase','이연 보상','Earnings set aside to be paid at a later date.','Negotiate {deferred compensation}.','이연 보상을 협상하세요.','deferred compensation','C1','work',3,'deferred compensation salary benefits'),
('w_work_C1_21','recourse','/ˈriːkɔːrs/','noun','법적 구제수단','The right to demand compensation or action.','You have legal {recourse}.','법적 구제수단이 있어요.','recourse','C1','work',3,'recourse legal action remedy'),
('w_work_C1_22','injunction','/ɪnˈdʒʌŋkʃən/','noun','금지 명령','A court order forbidding a specific action.','Seek an {injunction} immediately.','즉시 금지 명령을 구하세요.','injunction','C1','work',3,'injunction court order legal'),
('w_work_C1_23','escrow','/ˈeskroʊ/','noun','에스크로','Funds held by a third party until conditions are met.','Funds are held in {escrow}.','자금이 에스크로로 보관돼요.','escrow','C1','work',3,'escrow funds held third party'),
('w_work_C1_24','amortize','/ˈæmɔːrtaɪz/','verb','상각하다','To gradually write off the cost of an asset.','{Amortize} the loan over five years.','5년에 걸쳐 대출을 상각하세요.','Amortize','C1','work',3,'amortize loan finance schedule'),
('w_work_C1_25','audit','/ˈɔːdɪt/','noun','감사','An official inspection of accounts and processes.','The external {audit} begins Monday.','외부 감사가 월요일에 시작돼요.','audit','C1','work',3,'audit inspection accounting document'),
('w_work_C1_26','whistleblower','/ˈwɪsəlbloʊər/','noun','내부 고발자','A person who reports wrongdoing within an organization.','Protect the {whistleblower} legally.','내부 고발자를 법적으로 보호하세요.','whistleblower','C1','work',3,'whistleblower report expose corporate'),
('w_work_C1_27','proxy','/ˈprɒksi/','noun','대리인·위임장','Authority given to act on another''s behalf.','Vote by {proxy} at the meeting.','회의에서 위임장으로 투표하세요.','proxy','C1','work',3,'proxy vote delegate representative'),
('w_work_C1_28','severance','/ˈsevərəns/','noun','퇴직금·해직 수당','Compensation paid to an employee who is let go.','Negotiate your {severance} package.','퇴직금 패키지를 협상하세요.','severance','C1','work',3,'severance package termination hr'),
('w_work_C1_29','litigation','/ˌlɪtɪˈɡeɪʃən/','noun','소송','The process of taking legal action in court.','Avoid costly {litigation}.','비용이 많이 드는 소송을 피하세요.','litigation','C1','work',3,'litigation court lawsuit legal'),
('w_work_C1_30','encumbrance','/ɪnˈkʌmbrəns/','noun','부담·담보 부채','A claim against a property or asset.','Check for any {encumbrances}.','담보 부채를 확인하세요.','encumbrances','C1','work',3,'encumbrance debt property legal'),
('w_work_C1_31','warrant','/ˈwɒrənt/','noun','영장·워런트','A legal document or a security to purchase shares.','The company issued stock {warrants}.','회사가 주식 워런트를 발행했어요.','warrants','C1','work',3,'warrant stock legal document'),
('w_work_C1_32','dilution','/daɪˈluːʃən/','noun','희석','A reduction in ownership percentage due to new shares.','Avoid share {dilution}.','주식 희석을 피하세요.','dilution','C1','work',3,'dilution shares equity stock'),
('w_work_C1_33','lien','/liːn/','noun','유치권','A legal right over property until a debt is paid.','The bank holds a {lien}.','은행이 유치권을 보유하고 있어요.','lien','C1','work',3,'lien property debt bank legal'),
('w_work_C1_34','subpoena','/səˈpiːnə/','noun','소환장','A legal document requiring attendance at court.','He received a {subpoena}.','그는 소환장을 받았어요.','subpoena','C1','work',3,'subpoena court legal document'),
('w_work_C1_35','clawback','/ˈklɔːbæk/','noun','환수','The recovery of previously paid compensation.','Trigger a {clawback} clause.','환수 조항을 발동하세요.','clawback','C1','work',3,'clawback recover bonus finance');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_work_C2_01','securitization','/sɪˌkjʊərɪtaɪˈzeɪʃən/','noun','증권화','Converting assets into tradable securities.','{Securitization} spreads financial risk.','증권화는 금융 리스크를 분산시켜요.','Securitization','C2','work',4,'securitization finance securities'),
('w_work_C2_02','derivative','/dɪˈrɪvətɪv/','noun','파생상품','A financial instrument whose value depends on an underlying asset.','Trade {derivatives} cautiously.','파생상품은 신중하게 거래하세요.','derivatives','C2','work',4,'derivative finance option futures'),
('w_work_C2_03','amortization','/əˌmɔːrtɪˈzeɪʃən/','noun','감가상각·상환','The gradual write-off of an asset over time.','Review the {amortization} schedule.','감가상각 일정을 검토하세요.','amortization','C2','work',4,'amortization schedule finance accounting'),
('w_work_C2_04','subordination','/səˌbɔːrdɪˈneɪʃən/','noun','후순위 배치','The ranking of a debt claim below others.','The clause includes {subordination}.','조항에 후순위 배치가 포함돼요.','subordination','C2','work',4,'subordination debt priority finance'),
('w_work_C2_05','encumbrance','/ɪnˈkʌmbrəns/','noun','담보 채무 부담','A liability or claim attached to a property.','Disclose all {encumbrances} upfront.','모든 담보 채무 부담을 사전에 공개하세요.','encumbrances','C2','work',4,'encumbrance property legal claim'),
('w_work_C2_06','covenant','/ˈkʌvənənt/','noun','약정·서약','A binding agreement in a financial contract.','The loan has strict {covenants}.','대출에는 엄격한 약정이 있어요.','covenants','C2','work',4,'covenant agreement contract finance'),
('w_work_C2_07','prospectus','/prəˈspektəs/','noun','투자 설명서','A formal document disclosing investment details.','Read the full {prospectus}.','전체 투자 설명서를 읽으세요.','prospectus','C2','work',4,'prospectus investment document IPO'),
('w_work_C2_08','collateral','/kəˈlætərəl/','noun','담보물','An asset pledged to secure a loan.','Provide {collateral} for the loan.','대출을 위해 담보물을 제공하세요.','collateral','C2','work',4,'collateral asset loan security'),
('w_work_C2_09','divestiture','/daɪˈvestɪtʃər/','noun','자산 매각','The disposal of a business division or asset.','Plan the {divestiture} carefully.','자산 매각을 신중하게 계획하세요.','divestiture','C2','work',4,'divestiture sale asset spinoff'),
('w_work_C2_10','recapitalization','/ˌriːkəpɪtəlaɪˈzeɪʃən/','noun','자본 재편','Restructuring a company''s debt and equity mix.','Initiate a {recapitalization} plan.','자본 재편 계획을 시작하세요.','recapitalization','C2','work',4,'recapitalization finance debt equity'),
('w_work_C2_11','tranche','/trɑːnʃ/','noun','트란쉐·분할 자금','A portion of a financial deal released in stages.','Release the second {tranche}.','두 번째 트란쉐를 지급하세요.','tranche','C2','work',4,'tranche finance investment stage'),
('w_work_C2_12','hypothecation','/haɪˌpɒθɪˈkeɪʃən/','noun','질권 설정','Pledging an asset as collateral without transferring ownership.','Use {hypothecation} for the bond.','채권에 질권 설정을 사용하세요.','hypothecation','C2','work',4,'hypothecation pledge collateral finance'),
('w_work_C2_13','syndication','/ˌsɪndɪˈkeɪʃən/','noun','신디케이션·공동 융자','Combining multiple lenders to fund a single loan.','Arrange {syndication} for the deal.','거래를 위해 신디케이션을 준비하세요.','syndication','C2','work',4,'syndication loan lenders finance'),
('w_work_C2_14','EBITDA','/ɪˈbɪtdə/','noun','EBITDA (세전·이자·감가상각 전 이익)','Earnings before interest, taxes, depreciation and amortization.','The company''s {EBITDA} grew 15%.','회사의 EBITDA가 15% 성장했어요.','EBITDA','C2','work',4,'EBITDA earnings finance chart metric'),
('w_work_C2_15','indenture','/ɪnˈdentʃər/','noun','채권 계약서','A formal written contract between a bond issuer and holders.','Review the bond {indenture}.','채권 계약서를 검토하세요.','indenture','C2','work',4,'indenture bond contract legal'),
('w_work_C2_16','mezzanine','/ˌmezəˈniːn/','noun','메자닌 금융','A hybrid form of financing combining debt and equity.','Consider {mezzanine} financing.','메자닌 금융을 고려하세요.','mezzanine','C2','work',4,'mezzanine finance debt equity hybrid'),
('w_work_C2_17','haircut','/ˈheərkʌt/','noun','헤어컷·담보 가치 감소','A reduction applied to an asset''s value for collateral.','Apply a 20% {haircut}.','20% 헤어컷을 적용하세요.','haircut','C2','work',4,'haircut discount finance risk'),
('w_work_C2_18','sovereign debt','/ˈsɒvrɪn det/','noun phrase','국가 부채','Debt issued or guaranteed by a national government.','Monitor {sovereign debt} levels.','국가 부채 수준을 모니터링하세요.','sovereign debt','C2','work',4,'sovereign debt government bond country'),
('w_work_C2_19','leveraged buyout','/ˈlevərɪdʒd ˈbaɪaʊt/','noun phrase','차입 매수','Acquiring a company using borrowed funds.','Execute a {leveraged buyout}.','차입 매수를 실행하세요.','leveraged buyout','C2','work',4,'leveraged buyout LBO acquisition'),
('w_work_C2_20','credit default swap','/ˈkredɪt dɪˈfɔːlt swɒp/','noun phrase','신용 부도 스왑','A financial product that transfers credit exposure.','Hedge with a {credit default swap}.','신용 부도 스왑으로 헤지하세요.','credit default swap','C2','work',4,'credit default swap CDS finance'),
('w_work_C2_21','regulatory arbitrage','/ˌreɡjələtɔːri ˈɑːrbɪtrɪdʒ/','noun phrase','규제 차익 거래','Exploiting differences in regulation between jurisdictions.','Avoid {regulatory arbitrage}.','규제 차익 거래를 피하세요.','regulatory arbitrage','C2','work',4,'regulatory arbitrage law finance'),
('w_work_C2_22','mark-to-market','/mɑːrk tə ˈmɑːrkɪt/','adjective','시가 평가','Valuing assets at current market prices.','Apply {mark-to-market} accounting.','시가 평가 회계를 적용하세요.','mark-to-market','C2','work',4,'mark to market accounting valuation'),
('w_work_C2_23','off-balance sheet','/ɒf ˈbæləns ʃiːt/','adjective','부외 금융','Financing that does not appear on the balance sheet.','Disclose {off-balance sheet} items.','부외 금융 항목을 공시하세요.','off-balance sheet','C2','work',4,'off balance sheet accounting finance'),
('w_work_C2_24','perpetuity','/ˌpɜːrpɪˈtjuːɪti/','noun','영구 연금·무기한','A payment that continues indefinitely.','Value the firm using {perpetuity}.','영구 연금을 사용해 기업가치를 평가하세요.','perpetuity','C2','work',4,'perpetuity finance valuation forever'),
('w_work_C2_25','yield curve','/jiːld kɜːrv/','noun phrase','수익률 곡선','A graph showing interest rates across different maturities.','Analyze the {yield curve}.','수익률 곡선을 분석하세요.','yield curve','C2','work',4,'yield curve interest rate finance graph'),
('w_work_C2_26','basis point','/ˈbeɪsɪs pɔɪnt/','noun phrase','베이시스 포인트','One hundredth of a percentage point in finance.','Rates fell by 25 {basis points}.','금리가 25 베이시스 포인트 하락했어요.','basis points','C2','work',4,'basis points interest rate finance'),
('w_work_C2_27','quantum meruit','/ˌkwɒntəm ˈmɛrʊɪt/','noun','상당 보수 청구','A claim for payment for services rendered.','Sue under {quantum meruit}.','상당 보수 청구로 소송하세요.','quantum meruit','C2','work',4,'quantum meruit legal claim payment'),
('w_work_C2_28','force majeure','/ˌfɔːrs mæˈʒɜːr/','noun','불가항력','Unforeseeable events beyond a party''s control.','Invoke the {force majeure} clause.','불가항력 조항을 발동하세요.','force majeure','C2','work',4,'force majeure contract clause disaster'),
('w_work_C2_29','laches','/ˈleɪtʃɪz/','noun','권리 해태','The doctrine preventing a claim after unreasonable delay.','The defense raised {laches}.','피고가 권리 해태를 주장했어요.','laches','C2','work',4,'laches legal delay doctrine court'),
('w_work_C2_30','tortious interference','/ˈtɔːrʃəs ˌɪntəˈfɪərəns/','noun phrase','불법 방해','Intentional interference with another''s business.','File a {tortious interference} claim.','불법 방해 청구를 제기하세요.','tortious interference','C2','work',4,'tortious interference legal business'),
('w_work_C2_31','promissory note','/ˈprɒmɪsəri noʊt/','noun phrase','약속 어음','A written promise to pay a specified amount.','Sign the {promissory note}.','약속 어음에 서명하세요.','promissory note','C2','work',4,'promissory note payment finance document'),
('w_work_C2_32','interlocutory','/ˌɪntəˈlɒkjʊtəri/','adjective','중간의·임시의','Relating to an interim court order or ruling.','File an {interlocutory} appeal.','중간 항소를 제기하세요.','interlocutory','C2','work',4,'interlocutory court appeal legal'),
('w_work_C2_33','non-compete','/ˌnɒn kəmˈpiːt/','noun','경업 금지 조항','A clause preventing work for competitors after leaving.','Review the {non-compete} clause.','경업 금지 조항을 검토하세요.','non-compete','C2','work',4,'non compete clause contract legal'),
('w_work_C2_34','subrogation','/ˌsʌbrəˈɡeɪʃən/','noun','대위 변제','The substitution of one party for another in a legal claim.','The insurer claims {subrogation}.','보험사가 대위 변제를 주장해요.','subrogation','C2','work',4,'subrogation insurance legal claim'),
('w_work_C2_35','accretion','/əˈkriːʃən/','noun','증가·자산 가치 상승','Gradual increase in value of an asset over time.','Calculate {accretion} to par value.','액면가까지의 자산 가치 상승을 계산하세요.','accretion','C2','work',4,'accretion value finance growth');
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_work_A1_01','What do you do for work?','무슨 일 하세요?','What do you do for work','"What do you do for work?"는 처음 만났을 때 직업을 묻는 가장 자연스러운 표현이에요.','직업 소개','A1','work','pattern',NULL,1),
('s_work_A1_02','I work at a company downtown.','저는 시내에 있는 회사에서 일해요.','I work at','I work at + 장소"로 간단하게 직장을 소개할 수 있어요.','직업 소개','A1','work','pattern',NULL,2),
('s_work_A1_03','My job starts at nine in the morning.','저는 아침 9시에 일을 시작해요.','starts at nine','시간 앞에 "at"을 사용해요. "in the morning"을 붙이면 더 명확해요.','출근 시간','A1','work','pattern',NULL,3),
('s_work_A1_04','I have a meeting this afternoon.','저는 오늘 오후에 회의가 있어요.','have a meeting','have a + 명사" 패턴으로 일정을 표현해요. "this afternoon" = 오늘 오후.','일정 표현','A1','work','pattern',NULL,4),
('s_work_A1_05','Can you send me an email about that?','그것에 대해 이메일을 보내주실 수 있어요?','Can you send me','Can you + 동사?" 패턴은 정중한 요청이에요. 비즈니스 영어에서 매우 유용해요.','요청하기','A1','work','pattern',NULL,5),
('s_work_A1_06','My boss is very easy to work with.','제 상사는 같이 일하기 매우 편해요.','easy to work with','"easy to work with"는 동료를 칭찬할 때 쓰는 자연스러운 표현이에요.','동료 소개','A1','work','pattern',NULL,6),
('s_work_A1_07','Let''s take a short break.','잠깐 휴식을 취해요.','take a short break','"take a break"는 "쉬다"라는 표현이에요. "short"를 넣으면 짧은 휴식임을 강조해요.','휴식 제안','A1','work','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_work_A2_01','Could you send the report by Friday?','금요일까지 보고서를 보내주실 수 있을까요?','Could you send','Could you + 동사?"는 "Can you?"보다 더 공손한 요청이에요. 비즈니스 이메일에 적합해요.','업무 요청','A2','work','pattern',NULL,8),
('s_work_A2_02','I need your feedback on this draft.','이 초안에 대한 피드백이 필요해요.','need your feedback','"I need your feedback on..."은 검토 요청 시 유용한 표현이에요.','피드백 요청','A2','work','pattern',NULL,9),
('s_work_A2_03','The deadline is next Monday. Can we manage that?','마감일은 다음 주 월요일이에요. 가능할까요?','Can we manage that','"Can we manage that?"은 일정을 확인할 때 부드럽게 묻는 표현이에요.','마감 확인','A2','work','pattern',NULL,10),
('s_work_A2_04','Please submit your timesheet by end of day.','오늘 업무 종료 전에 타임시트를 제출해주세요.','submit your timesheet','Please + 동사"로 시작하는 요청은 정중하지만 명확해요. "end of day" = 근무 종료 시간.','타임시트 제출','A2','work','pattern',NULL,11),
('s_work_A2_05','I will follow up with the client this week.','이번 주에 고객에게 후속 연락을 할게요.','follow up with','follow up with"는 "후속 조치를 취하다"라는 비즈니스 필수 표현이에요.','업무 보고','A2','work','pattern',NULL,12),
('s_work_A2_06','Can you approve this by tomorrow?','내일까지 이것을 승인해주실 수 있어요?','approve this by tomorrow','approve by + 날짜"로 승인 기한을 명확히 요청할 수 있어요.','승인 요청','A2','work','pattern',NULL,13),
('s_work_A2_07','I am working on the project report right now.','지금 프로젝트 보고서를 작업 중이에요.','working on','I am working on..."은 현재 진행 중인 업무를 설명할 때 써요.','업무 현황','A2','work','pattern',NULL,14);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_work_B1_01','Could we schedule a call to align on the agenda?','안건에 대해 의견을 맞추기 위해 통화 일정을 잡을 수 있을까요?','schedule a call to align','"align on"은 "서로 의견을 맞추다"는 뜻이에요. "agenda"와 함께 쓰면 비즈니스다운 표현이 돼요.','회의 일정 조율','B1','work','pattern',NULL,15),
('s_work_B1_02','Let me check the stakeholders'' availability and get back to you.','이해관계자들의 가능 여부를 확인하고 다시 연락드릴게요.','check availability and get back to','get back to you"는 "다시 연락드리다"의 핵심 비즈니스 표현이에요.','일정 조율','B1','work','pattern',NULL,16),
('s_work_B1_03','I am writing to follow up on our meeting last Tuesday.','지난 화요일 회의에 대한 후속 조치로 이 이메일을 드려요.','I am writing to follow up on','이메일의 첫 문장으로 가장 많이 쓰는 패턴이에요. 목적을 명확히 밝혀요.','이메일 작성','B1','work','pattern',NULL,17),
('s_work_B1_04','Please find the briefing document attached.','브리핑 문서를 첨부파일로 확인해주세요.','Please find... attached','"Please find ... attached"는 첨부파일을 안내하는 이메일 필수 표현이에요.','이메일 첨부','B1','work','pattern',NULL,18),
('s_work_B1_05','Could you delegate this task to someone on your team?','이 업무를 팀원에게 위임해주실 수 있어요?','delegate this task to','delegate to"는 "~에게 위임하다"예요. 효율적인 팀 관리에서 핵심 동사예요.','업무 위임','B1','work','pattern',NULL,19),
('s_work_B1_06','We need to finalize the agenda before Thursday''s meeting.','목요일 회의 전에 안건을 확정해야 해요.','finalize the agenda','finalize"는 "최종 확정하다"예요. "before + 날짜"로 기한을 명시해요.','안건 확정','B1','work','pattern',NULL,20),
('s_work_B1_07','The project is on track to meet the milestone by Q3.','프로젝트가 3분기까지 이정표를 달성할 궤도에 있어요.','on track to meet the milestone','"on track"은 "계획대로 진행 중"이에요. "milestone"과 함께 쓰면 프로젝트 보고에 매우 적합해요.','프로젝트 보고','B1','work','pattern',NULL,21);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_work_B2_01','Our Q3 revenue exceeded the KPI by fifteen percent.','3분기 매출이 KPI를 15퍼센트 초과달성했어요.','exceeded the KPI by fifteen percent','"exceed by + 숫자"는 목표를 초과했음을 표현해요. 발표에서 임팩트 있게 들려요.','성과 발표','B2','work','pattern',NULL,22),
('s_work_B2_02','I would like to walk you through our quarterly results.','분기별 결과를 안내해 드리고자 해요.','walk you through','walk someone through"는 "단계별로 설명하다"예요. 발표 시작에 자주 쓰여요.','발표 시작','B2','work','pattern',NULL,23),
('s_work_B2_03','To leverage our competitive advantage, we need to scale faster.','경쟁 우위를 활용하려면 더 빠르게 확장해야 해요.','leverage our competitive advantage to scale','"leverage"와 "scale"을 함께 쓰면 전략적 사고를 보여줘요.','전략 발표','B2','work','pattern',NULL,24),
('s_work_B2_04','The pivot to a subscription model improved our retention by twenty percent.','구독 모델로의 전환이 유지율을 20퍼센트 향상시켰어요.','pivot to a subscription model improved retention','"pivot to"는 전략 전환을 나타내요. 결과를 수치로 표현하면 설득력이 높아져요.','성과 분석','B2','work','pattern',NULL,25),
('s_work_B2_05','Our onboarding process is now fully scalable across markets.','온보딩 프로세스가 이제 모든 시장에 걸쳐 완전히 확장 가능해요.','fully scalable across markets','scalable across markets"는 글로벌 확장성을 표현하는 B2 필수 표현이에요.','사업 발표','B2','work','pattern',NULL,26),
('s_work_B2_06','Let me highlight the key takeaways from this fiscal year.','이번 회계연도의 핵심 시사점을 강조하겠어요.','highlight the key takeaways from this fiscal year','"takeaways"는 "핵심 결론"이에요. "fiscal year"와 함께 재무 발표에서 많이 써요.','발표 마무리','B2','work','pattern',NULL,27),
('s_work_B2_07','We are benchmarking against top industry performers to close the gap.','격차를 줄이기 위해 업계 최고 기업들과 비교 기준을 삼고 있어요.','benchmarking against top industry performers','benchmarking against"는 경쟁사와 비교 분석함을 나타내요.','경쟁 분석','B2','work','pattern',NULL,28);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_work_C1_01','We must ensure full compliance with the regulatory framework before closing.','마감 전에 규제 체계를 완전히 준수해야 해요.','ensure full compliance with the regulatory framework','"ensure compliance"는 법적 리스크 관리의 핵심 표현이에요. "before closing"은 계약 체결 전을 뜻해요.','법적 검토','C1','work','pattern',NULL,29),
('s_work_C1_02','The acquisition is subject to due diligence and board approval.','인수는 적정 조사 및 이사회 승인을 조건으로 해요.','subject to due diligence and board approval','"subject to"는 "~를 조건으로"예요. M&A 협상에서 필수 표현이에요.','M&A 협상','C1','work','pattern',NULL,30),
('s_work_C1_03','Our fiduciary duty requires us to act in shareholders'' best interests.','수탁자 의무에 따라 주주의 최선의 이익을 위해 행동해야 해요.','fiduciary duty requires us to act in shareholders'' best interests','"fiduciary duty"는 이사회 맥락에서 핵심 법적 개념이에요.','이사회 토론','C1','work','pattern',NULL,31),
('s_work_C1_04','The indemnification clause protects both parties from third-party claims.','면책 조항은 양측을 제3자 청구로부터 보호해요.','indemnification clause protects both parties','indemnification clause"는 계약서에서 가장 협상이 많이 이루어지는 조항 중 하나예요.','계약 협상','C1','work','pattern',NULL,32),
('s_work_C1_05','Any dispute shall be resolved through binding arbitration in Seoul.','모든 분쟁은 서울에서 구속력 있는 중재로 해결되어야 해요.','resolved through binding arbitration','binding arbitration"은 "구속력 있는 중재"로 법원 소송 대신 선택하는 방법이에요.','분쟁 해결','C1','work','pattern',NULL,33),
('s_work_C1_06','We need to conduct a thorough audit before the restructuring begins.','구조 조정이 시작되기 전에 철저한 감사를 실시해야 해요.','conduct a thorough audit before the restructuring','conduct an audit"는 "감사를 실시하다"예요. "thorough"를 붙이면 심층적임을 강조해요.','재무 감사','C1','work','pattern',NULL,34),
('s_work_C1_07','The governance framework must align with international best practices.','지배 구조 체계는 국제 모범 사례와 일치해야 해요.','governance framework must align with international best practices','align with best practices"는 글로벌 기준 준수를 표현할 때 써요.','기업 지배구조','C1','work','pattern',NULL,35);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_work_C2_01','The securitization structure requires a bankruptcy-remote special purpose vehicle.','증권화 구조는 파산 격리형 특수목적법인을 필요로 해요.','securitization structure requires a bankruptcy-remote special purpose vehicle','"special purpose vehicle (SPV)"은 증권화의 핵심 구조예요. "bankruptcy-remote"는 원본 회사 파산과 분리됨을 뜻해요.','증권화 협상','C2','work','pattern',NULL,36),
('s_work_C2_02','The covenant package restricts the borrower from additional subordinated debt.','약정 패키지는 차입자가 추가 후순위 채무를 지지 못하도록 제한해요.','covenant package restricts the borrower from additional subordinated debt','"covenant package"는 대출 계약의 조건 묶음이에요. "subordinated debt"는 우선순위가 낮은 채무예요.','채권 협상','C2','work','pattern',NULL,37),
('s_work_C2_03','We need to model the EBITDA accretion from the proposed divestiture.','제안된 자산 매각으로 인한 EBITDA 증가를 모델링해야 해요.','model the EBITDA accretion from the proposed divestiture','"accretion"은 가치가 더해짐을 뜻해요. M&A에서 "accretive deal"은 EPS가 증가하는 거래예요.','M&A 분석','C2','work','pattern',NULL,38),
('s_work_C2_04','The force majeure clause was invoked following the regulatory shutdown.','규제 폐쇄 이후 불가항력 조항이 발동되었어요.','force majeure clause was invoked following the regulatory shutdown','"invoke a clause"는 "조항을 발동하다"예요. "force majeure"는 계약 이행 불가 시 면책 조항이에요.','계약 분쟁','C2','work','pattern',NULL,39),
('s_work_C2_05','A leveraged buyout financed at six times EBITDA requires careful covenant monitoring.','6배 EBITDA로 조달된 차입 매수는 신중한 약정 모니터링이 필요해요.','leveraged buyout financed at six times EBITDA requires careful covenant monitoring','LBO 분석에서 "multiple of EBITDA"는 인수 가격 수준을 나타내요.','LBO 분석','C2','work','pattern',NULL,40),
('s_work_C2_06','Subrogation rights allow the insurer to step into the insured''s shoes legally.','대위 변제 권리는 보험사가 법적으로 피보험자의 지위를 대신할 수 있게 해요.','Subrogation rights allow the insurer to step into the insured''s shoes','"step into someone''s shoes"는 관용표현으로 "그 사람의 지위를 대신하다"예요.','보험·법적 청구','C2','work','pattern',NULL,41),
('s_work_C2_07','The recapitalization plan involves converting mezzanine debt to equity at par.','자본 재편 계획은 메자닌 채무를 액면가로 주식으로 전환하는 것을 포함해요.','recapitalization plan involves converting mezzanine debt to equity at par','"at par"는 "액면가로"예요. "converting debt to equity"는 부채 탕감의 일반적인 방법이에요.','자본 구조 재편','C2','work','pattern',NULL,42);
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_education_A1_01','school','/skuːl/','noun','학교','A place where children go to learn.','I go to {school} every day.','저는 매일 학교에 가요.','school','A1','education',1,'school building students classroom'),
('w_education_A1_02','teacher','/ˈtiːtʃər/','noun','선생님','A person who teaches, especially in a school.','My {teacher} explains things clearly.','우리 선생님은 설명을 잘 해주세요.','teacher','A1','education',1,'teacher classroom whiteboard students'),
('w_education_A1_03','student','/ˈstjuːdənt/','noun','학생','A person who is studying at a school or college.','She is a hard-working {student}.','그녀는 열심히 공부하는 학생이에요.','student','A1','education',1,'student studying desk books'),
('w_education_A1_04','learn','/lɜːrn/','verb','배우다','To gain knowledge or skill by studying or being taught.','I want to {learn} English every day.','저는 매일 영어를 배우고 싶어요.','learn','A1','education',1,'person learning studying book'),
('w_education_A1_05','book','/bʊk/','noun','책','A set of written or printed pages, usually bound with covers.','I read a {book} before bed.','저는 자기 전에 책을 읽어요.','book','A1','education',1,'open book reading library'),
('w_education_A1_06','class','/klɑːs/','noun','수업','A group of students taught together; a lesson.','English {class} starts at nine.','영어 수업은 9시에 시작해요.','class','A1','education',1,'classroom students lesson teacher'),
('w_education_A1_07','study','/ˈstʌdi/','verb','공부하다','To spend time learning about a subject.','I {study} for two hours every evening.','저는 매일 저녁 두 시간씩 공부해요.','study','A1','education',1,'studying desk lamp notebook'),
('w_education_A1_08','test','/test/','noun','시험','An assessment to measure knowledge or ability.','We have a {test} on Friday.','금요일에 시험이 있어요.','test','A1','education',1,'exam paper pencil test'),
('w_education_A1_09','write','/raɪt/','verb','쓰다','To mark letters or words on paper or a surface.','Please {write} your name here.','여기에 이름을 써 주세요.','write','A1','education',1,'writing pen paper notebook'),
('w_education_A1_10','read','/riːd/','verb','읽다','To look at and understand written words.','Can you {read} this sentence?','이 문장을 읽을 수 있어요?','read','A1','education',1,'reading book open pages'),
('w_education_A1_11','pencil','/ˈpensəl/','noun','연필','A thin stick used for writing or drawing.','I need a {pencil} to write.','쓰려면 연필이 필요해요.','pencil','A1','education',2,'pencil desk writing stationery'),
('w_education_A1_12','pen','/pen/','noun','펜','A device used for writing with ink.','Can I borrow your {pen}?','펜 빌려도 될까요?','pen','A1','education',2,'pen writing ink stationery'),
('w_education_A1_13','question','/ˈkwestʃən/','noun','질문','A sentence asking for information.','Do you have a {question}?','질문이 있으세요?','question','A1','education',1,'person raising hand question classroom'),
('w_education_A1_14','answer','/ˈɑːnsər/','noun','답','A response to a question.','What is the {answer} to this?','이것의 답이 뭐예요?','answer','A1','education',1,'answer sheet test solution'),
('w_education_A1_15','number','/ˈnʌmbər/','noun','숫자','A value used for counting or measuring.','Write the {number} next to each word.','각 단어 옆에 숫자를 쓰세요.','number','A1','education',2,'numbers math counting board'),
('w_education_A1_16','letter','/ˈletər/','noun','글자, 편지','A character representing a sound; also a written message.','The first {letter} of the alphabet is A.','알파벳의 첫 번째 글자는 A예요.','letter','A1','education',2,'alphabet letters writing board'),
('w_education_A1_17','word','/wɜːrd/','noun','단어','A single unit of language with meaning.','What does this {word} mean?','이 단어는 무슨 뜻이에요?','word','A1','education',1,'word dictionary vocabulary language'),
('w_education_A1_18','sentence','/ˈsentəns/','noun','문장','A set of words expressing a complete thought.','Please read the {sentence} aloud.','문장을 소리 내어 읽어 주세요.','sentence','A1','education',1,'sentence writing grammar text'),
('w_education_A1_19','listen','/ˈlɪsən/','verb','듣다','To pay attention to sounds.','Please {listen} carefully.','주의해서 들어주세요.','listen','A1','education',1,'listening headphones audio learning'),
('w_education_A1_20','speak','/spiːk/','verb','말하다','To say words; to communicate verbally.','Don''t be afraid to {speak} English.','영어로 말하는 것을 두려워하지 마세요.','speak','A1','education',1,'speaking conversation talking people'),
('w_education_A1_21','understand','/ˌʌndərˈstænd/','verb','이해하다','To know the meaning of something.','Do you {understand} the rule?','규칙을 이해하셨어요?','understand','A1','education',1,'person thinking understanding light bulb'),
('w_education_A1_22','homework','/ˈhoʊmwɜːrk/','noun','숙제','School work done at home.','I do my {homework} after dinner.','저는 저녁 식사 후에 숙제를 해요.','homework','A1','education',1,'homework books desk studying home'),
('w_education_A1_23','classroom','/ˈklɑːsruːm/','noun','교실','A room used for lessons.','The {classroom} has thirty desks.','교실에 책상이 30개 있어요.','classroom','A1','education',2,'classroom desks chairs teacher board'),
('w_education_A1_24','lesson','/ˈlesən/','noun','수업, 레슨','A period of learning or teaching.','Today''s {lesson} is about animals.','오늘 수업은 동물에 관한 거예요.','lesson','A1','education',1,'lesson classroom teaching board'),
('w_education_A1_25','paper','/ˈpeɪpər/','noun','종이','A thin flat material used for writing.','Write your name on the {paper}.','종이에 이름을 쓰세요.','paper','A1','education',2,'paper writing desk student'),
('w_education_A1_26','correct','/kəˈrekt/','adjective','맞는, 옳은','Free from mistakes; right.','That is the {correct} answer.','그것이 맞는 답이에요.','correct','A1','education',1,'correct answer checkmark right'),
('w_education_A1_27','wrong','/rɒŋ/','adjective','틀린','Not correct; mistaken.','Sorry, that''s {wrong} — try again.','죄송하지만 틀렸어요. 다시 해보세요.','wrong','A1','education',1,'wrong answer incorrect mistake'),
('w_education_A1_28','spell','/spel/','verb','철자를 쓰다','To write the letters of a word in the correct order.','How do you {spell} your name?','이름 철자가 어떻게 되세요?','spell','A1','education',2,'spelling letters alphabet words'),
('w_education_A1_29','repeat','/rɪˈpiːt/','verb','반복하다','To say or do something again.','Please {repeat} after me.','저를 따라 다시 말해 주세요.','repeat','A1','education',2,'repeat practice drilling language'),
('w_education_A1_30','open','/ˈoʊpən/','verb','열다, 펼치다','To move so as to allow access; to turn to a page.','Please {open} your books to page ten.','책 10페이지를 펼쳐 주세요.','open','A1','education',2,'open book page textbook'),
('w_education_A1_31','close','/kloʊz/','verb','닫다','To move so as to cover an opening.','Please {close} your notebooks.','노트를 닫아 주세요.','close','A1','education',2,'close book notebook desk'),
('w_education_A1_32','name','/neɪm/','noun','이름','A word used to identify a person or thing.','What is your {name}?','이름이 어떻게 되세요?','name','A1','education',2,'name tag label identity'),
('w_education_A1_33','grade','/ɡreɪd/','noun','학년, 성적','A class level in school; a mark showing quality of work.','I am in the third {grade}.','저는 3학년이에요.','grade','A1','education',1,'grade school level report card'),
('w_education_A1_34','easy','/ˈiːzi/','adjective','쉬운','Not difficult; achieved without much effort.','This exercise is very {easy}.','이 연습 문제는 매우 쉬워요.','easy','A1','education',2,'easy simple exercise learning'),
('w_education_A1_35','difficult','/ˈdɪfɪkəlt/','adjective','어려운','Needing much effort or skill.','The grammar rule is {difficult}.','그 문법 규칙은 어려워요.','difficult','A1','education',2,'difficult challenge hard studying');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_education_A2_01','homework','/ˈhoʊmwɜːrk/','noun','숙제','Schoolwork assigned to be done at home.','Did you finish your {homework} last night?','어제 숙제 다 했어요?','homework','A2','education',1,'homework books desk studying'),
('w_education_A2_02','exam','/ɪɡˈzæm/','noun','시험','A formal test of knowledge or ability.','The final {exam} is next week.','기말 시험이 다음 주예요.','exam','A2','education',1,'exam test paper student writing'),
('w_education_A2_03','grade','/ɡreɪd/','noun','성적, 점수','A mark indicating quality of schoolwork.','She got a good {grade} on the test.','그녀는 시험에서 좋은 성적을 받았어요.','grade','A2','education',1,'grade score report card marks'),
('w_education_A2_04','subject','/ˈsʌbdʒɪkt/','noun','과목','A branch of knowledge studied in school.','My favorite {subject} is English.','제가 가장 좋아하는 과목은 영어예요.','subject','A2','education',1,'school subjects textbooks curriculum'),
('w_education_A2_05','university','/ˌjuːnɪˈvɜːrsɪti/','noun','대학교','An institution of higher education and research.','She wants to go to {university} next year.','그녀는 내년에 대학교에 가고 싶어해요.','university','A2','education',1,'university campus building students'),
('w_education_A2_06','library','/ˈlaɪbreri/','noun','도서관','A place where books and other materials are available to borrow.','I study at the {library} every weekend.','저는 매주 주말 도서관에서 공부해요.','library','A2','education',1,'library books shelves studying'),
('w_education_A2_07','lecture','/ˈlektʃər/','noun','강의','A talk given to a group, especially at a university.','The {lecture} starts at ten o''clock.','강의는 10시에 시작해요.','lecture','A2','education',1,'lecture hall professor students university'),
('w_education_A2_08','notes','/noʊts/','noun','필기, 노트','Written records of what was said or learned.','I always take {notes} in class.','저는 항상 수업에서 필기를 해요.','notes','A2','education',1,'notes notebook writing class'),
('w_education_A2_09','pass','/pɑːs/','verb','합격하다, 통과하다','To succeed in an exam or test.','I hope to {pass} the exam.','시험에 합격하면 좋겠어요.','pass','A2','education',1,'pass exam success celebration'),
('w_education_A2_10','fail','/feɪl/','verb','불합격하다, 실패하다','To not succeed in an exam or test.','She didn''t want to {fail} the test.','그녀는 시험에서 떨어지고 싶지 않았어요.','fail','A2','education',1,'fail exam disappointed student'),
('w_education_A2_11','practice','/ˈpræktɪs/','verb','연습하다','To repeat an activity in order to improve.','You need to {practice} speaking every day.','매일 말하기 연습을 해야 해요.','practice','A2','education',1,'practice sports skill learning repetition'),
('w_education_A2_12','review','/rɪˈvjuː/','verb','복습하다','To look at something again to check or improve it.','Let''s {review} what we learned last week.','지난주에 배운 것을 복습해 볼게요.','review','A2','education',1,'review notes studying textbook'),
('w_education_A2_13','dictionary','/ˈdɪkʃəneri/','noun','사전','A book or program listing words with their meanings.','I use a {dictionary} to look up new words.','저는 새 단어를 찾을 때 사전을 사용해요.','dictionary','A2','education',2,'dictionary book reference vocabulary'),
('w_education_A2_14','vocabulary','/voʊˈkæbjʊleri/','noun','어휘','The body of words used in a language or subject.','Building {vocabulary} takes time.','어휘를 쌓는 데는 시간이 걸려요.','vocabulary','A2','education',1,'vocabulary words language learning'),
('w_education_A2_15','grammar','/ˈɡræmər/','noun','문법','The rules governing the use of a language.','English {grammar} can be tricky.','영어 문법은 까다로울 수 있어요.','grammar','A2','education',1,'grammar rules language textbook'),
('w_education_A2_16','score','/skɔːr/','noun','점수','The number of points or marks received.','What {score} did you get on the test?','시험에서 몇 점 받았어요?','score','A2','education',1,'score test results marks paper'),
('w_education_A2_17','report card','/ˈrɪpɔːrt kɑːrd/','noun','성적표','A document showing a student''s grades.','My parents checked my {report card}.','부모님이 제 성적표를 확인하셨어요.','report card','A2','education',2,'report card grades school marks'),
('w_education_A2_18','semester','/sɪˈmestər/','noun','학기','Half of the academic year.','The spring {semester} begins in March.','봄 학기는 3월에 시작해요.','semester','A2','education',1,'semester school year calendar academic'),
('w_education_A2_19','club','/klʌb/','noun','동아리, 클럽','A group that meets regularly for a shared interest.','I joined the English speaking {club}.','저는 영어 회화 동아리에 가입했어요.','club','A2','education',2,'club activity group students school'),
('w_education_A2_20','project','/ˈprɒdʒekt/','noun','과제, 프로젝트','A planned piece of work, often done over time.','We are doing a group {project} this week.','이번 주에 모둠 과제를 하고 있어요.','project','A2','education',1,'project group work students desk'),
('w_education_A2_21','quiz','/kwɪz/','noun','쪽지 시험','A short test to check knowledge.','There is a {quiz} at the end of class.','수업 끝에 쪽지 시험이 있어요.','quiz','A2','education',2,'quiz test paper classroom student'),
('w_education_A2_22','absent','/ˈæbsənt/','adjective','결석한','Not present at school or class.','He was {absent} from class yesterday.','그는 어제 수업에 결석했어요.','absent','A2','education',2,'absent empty seat classroom'),
('w_education_A2_23','present','/ˈprezənt/','adjective','출석한','At school or class; here.','All students are {present} today.','오늘 모든 학생이 출석했어요.','present','A2','education',2,'present attendance classroom students'),
('w_education_A2_24','explain','/ɪkˈspleɪn/','verb','설명하다','To make something clear or understandable.','Can you {explain} the rule again?','규칙을 다시 설명해 주실 수 있어요?','explain','A2','education',1,'explain teacher whiteboard students'),
('w_education_A2_25','example','/ɪɡˈzɑːmpəl/','noun','예, 예시','Something that illustrates a rule or point.','Give me an {example} of that word.','그 단어의 예를 들어 주세요.','example','A2','education',1,'example illustration board teaching'),
('w_education_A2_26','textbook','/ˈtekstbʊk/','noun','교과서','A book used in school for a particular subject.','Open your {textbook} to chapter three.','교과서 3장을 펼쳐 주세요.','textbook','A2','education',1,'textbook open book student desk'),
('w_education_A2_27','worksheet','/ˈwɜːrkʃiːt/','noun','학습지','A printed sheet with exercises for students.','Fill in the {worksheet} before class.','수업 전에 학습지를 작성해 주세요.','worksheet','A2','education',2,'worksheet paper exercises student'),
('w_education_A2_28','tutor','/ˈtjuːtər/','noun','개인 교사, 튜터','A private teacher who teaches one student or a small group.','My {tutor} helps me with math.','튜터가 수학을 도와줘요.','tutor','A2','education',2,'tutor teaching student one on one'),
('w_education_A2_29','certificate','/sərˈtɪfɪkɪt/','noun','자격증, 수료증','An official document proving an achievement.','I got a {certificate} for completing the course.','과정을 이수하고 수료증을 받았어요.','certificate','A2','education',2,'certificate document achievement award'),
('w_education_A2_30','enroll','/ɪnˈroʊl/','verb','등록하다','To register for a course or school.','I want to {enroll} in an English class.','영어 수업에 등록하고 싶어요.','enroll','A2','education',2,'enroll registration school form'),
('w_education_A2_31','attend','/əˈtend/','verb','참석하다, 다니다','To go to or be present at a place regularly.','She {attends} school every day.','그녀는 매일 학교에 다녀요.','attend','A2','education',1,'attend school class students'),
('w_education_A2_32','break','/breɪk/','noun','휴식 시간','A short period of rest during school.','We have a {break} at eleven.','11시에 쉬는 시간이 있어요.','break','A2','education',2,'break recess students playground'),
('w_education_A2_33','schedule','/ˈskedʒuːl/','noun','시간표, 일정','A timetable of classes or events.','Check your {schedule} for tomorrow.','내일 시간표를 확인해 주세요.','schedule','A2','education',2,'schedule timetable planner school'),
('w_education_A2_34','classmate','/ˈklɑːsmeɪt/','noun','반 친구','A member of the same class at school.','My {classmate} helped me with the homework.','반 친구가 숙제를 도와줬어요.','classmate','A2','education',2,'classmates students friends school'),
('w_education_A2_35','knowledge','/ˈnɒlɪdʒ/','noun','지식','Facts and information gained through learning.','Reading builds your {knowledge}.','독서는 지식을 쌓아줘요.','knowledge','A2','education',1,'knowledge books learning brain');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_education_B1_01','curriculum','/kəˈrɪkjʊləm/','noun','교육 과정','The subjects and content making up a course of study.','The new {curriculum} focuses on critical thinking.','새 교육 과정은 비판적 사고에 초점을 맞춰요.','curriculum','B1','education',1,'curriculum education plan subjects'),
('w_education_B1_02','semester','/sɪˈmestər/','noun','학기','A half-year term in an academic year.','We have exams at the end of every {semester}.','매 학기 말에 시험이 있어요.','semester','B1','education',1,'semester academic year university'),
('w_education_B1_03','scholarship','/ˈskɒlərʃɪp/','noun','장학금','Financial aid given to students based on merit or need.','She received a full {scholarship} to study abroad.','그녀는 해외 유학을 위한 전액 장학금을 받았어요.','scholarship','B1','education',1,'scholarship award money student education'),
('w_education_B1_04','degree','/dɪˈɡriː/','noun','학위','An academic award given by a university.','He earned his {degree} in computer science.','그는 컴퓨터 공학 학위를 받았어요.','degree','B1','education',1,'degree diploma graduation university'),
('w_education_B1_05','research','/rɪˈsɜːrtʃ/','noun','연구','Systematic investigation to discover new knowledge.','She is doing {research} on climate change.','그녀는 기후 변화에 관한 연구를 하고 있어요.','research','B1','education',1,'research laboratory studying data'),
('w_education_B1_06','thesis','/ˈθiːsɪs/','noun','논문(학사/석사)','A long written piece of research for a degree.','He is writing his {thesis} on urban development.','그는 도시 개발에 관한 논문을 쓰고 있어요.','thesis','B1','education',1,'thesis paper writing university research'),
('w_education_B1_07','assignment','/əˈsaɪnmənt/','noun','과제','A task given to students to complete.','The {assignment} is due next Monday.','과제 제출 기한은 다음 주 월요일이에요.','assignment','B1','education',1,'assignment task homework deadline'),
('w_education_B1_08','professor','/prəˈfesər/','noun','교수','A senior university teacher and researcher.','The {professor} gave an inspiring lecture.','교수님이 감동적인 강의를 해주셨어요.','professor','B1','education',1,'professor university lecture teaching'),
('w_education_B1_09','tuition','/tjuːˈɪʃən/','noun','수업료, 등록금','Fees charged for teaching at a school or university.','{Tuition} at private schools can be expensive.','사립학교의 수업료는 비쌀 수 있어요.','tuition','B1','education',1,'tuition fees university money education'),
('w_education_B1_10','campus','/ˈkæmpəs/','noun','캠퍼스','The grounds and buildings of a university.','I walked across {campus} to get to the library.','도서관에 가기 위해 캠퍼스를 가로질러 걸었어요.','campus','B1','education',1,'campus university buildings grounds'),
('w_education_B1_11','graduation','/ˌɡrædʒuˈeɪʃən/','noun','졸업','The ceremony at which degrees are awarded.','Her {graduation} ceremony is in June.','그녀의 졸업식은 6월이에요.','graduation','B1','education',1,'graduation ceremony diploma cap gown'),
('w_education_B1_12','major','/ˈmeɪdʒər/','noun','전공','The main subject studied at university.','His {major} is economics.','그의 전공은 경제학이에요.','major','B1','education',1,'major university subject study'),
('w_education_B1_13','minor','/ˈmaɪnər/','noun','부전공','A secondary subject studied alongside the major.','She chose linguistics as her {minor}.','그녀는 언어학을 부전공으로 선택했어요.','minor','B1','education',2,'minor secondary subject university'),
('w_education_B1_14','deadline','/ˈdedlaɪn/','noun','마감 기한','The last date by which an assignment must be submitted.','The {deadline} for the paper is Thursday.','논문 마감 기한은 목요일이에요.','deadline','B1','education',1,'deadline calendar due date assignment'),
('w_education_B1_15','presentation','/ˌprezənˈteɪʃən/','noun','발표','A talk or demonstration to an audience.','I have to give a {presentation} next week.','다음 주에 발표를 해야 해요.','presentation','B1','education',1,'presentation public speaking audience'),
('w_education_B1_16','essay','/ˈeseɪ/','noun','에세이, 작문','A piece of writing on a particular topic.','The {essay} should be at least five hundred words.','에세이는 최소 500단어 이상이어야 해요.','essay','B1','education',1,'essay writing paper academic'),
('w_education_B1_17','outline','/ˈaʊtlaɪn/','noun','개요','A plan or summary of the main points.','Write an {outline} before you start the essay.','에세이를 시작하기 전에 개요를 작성하세요.','outline','B1','education',2,'outline plan structure writing'),
('w_education_B1_18','debate','/dɪˈbeɪt/','noun','토론, 논쟁','A formal discussion on a topic with opposing arguments.','We had a class {debate} about technology.','기술에 대한 수업 토론을 했어요.','debate','B1','education',1,'debate discussion argument classroom'),
('w_education_B1_19','seminar','/ˈsemɪnɑːr/','noun','세미나','A small group session for discussion and study.','The professor runs a weekly {seminar}.','교수님이 매주 세미나를 진행해요.','seminar','B1','education',2,'seminar group discussion university'),
('w_education_B1_20','internship','/ˈɪntɜːrnʃɪp/','noun','인턴십','A temporary work experience placement for students.','She completed an {internship} at a media company.','그녀는 미디어 회사에서 인턴십을 마쳤어요.','internship','B1','education',2,'internship work experience office student'),
('w_education_B1_21','elective','/ɪˈlektɪv/','noun','선택 과목','A course students can choose to take.','I picked photography as my {elective}.','저는 선택 과목으로 사진을 골랐어요.','elective','B1','education',2,'elective course choice subject'),
('w_education_B1_22','mandatory','/ˈmændətɔːri/','adjective','필수적인','Required; compulsory.','Attendance is {mandatory} for this course.','이 수업은 출석이 필수예요.','mandatory','B1','education',1,'mandatory required rules attendance'),
('w_education_B1_23','extracurricular','/ˌekstrəkəˈrɪkjʊlər/','adjective','과외 활동의','Outside of the regular curriculum.','{extracurricular} activities improve teamwork.','과외 활동은 팀워크를 향상시켜요.','extracurricular','B1','education',2,'extracurricular sports clubs school activities'),
('w_education_B1_24','academic','/ˌækəˈdemɪk/','adjective','학문적인','Relating to education and scholarly activities.','Her {academic} record is excellent.','그녀의 학업 성적은 우수해요.','academic','B1','education',1,'academic university study records'),
('w_education_B1_25','feedback','/ˈfiːdbæk/','noun','피드백','Information given to help improve performance.','The teacher gave useful {feedback} on my essay.','선생님이 에세이에 유용한 피드백을 주셨어요.','feedback','B1','education',1,'feedback review comments paper'),
('w_education_B1_26','assessment','/əˈsesmənt/','noun','평가','The process of evaluating performance or knowledge.','The {assessment} includes both written and oral parts.','평가는 필기와 구술 두 부분을 포함해요.','assessment','B1','education',1,'assessment evaluation test grade'),
('w_education_B1_27','credit','/ˈkredɪt/','noun','학점','A unit used to measure the completion of a course.','This course is worth three {credits}.','이 수업은 3학점이에요.','credit','B1','education',1,'credit academic hours university'),
('w_education_B1_28','apply','/əˈplaɪ/','verb','지원하다, 신청하다','To formally request something such as a place at university.','She plans to {apply} to ten universities.','그녀는 열 개의 대학교에 지원할 계획이에요.','apply','B1','education',1,'apply application form university'),
('w_education_B1_29','scholarship','/ˈskɒlərʃɪp/','noun','장학금','Money given to fund a student''s education.','He applied for a merit-based {scholarship}.','그는 성적 우수 장학금을 신청했어요.','scholarship','B1','education',1,'scholarship money award student'),
('w_education_B1_30','qualify','/ˈkwɒlɪfaɪ/','verb','자격을 갖추다','To meet the necessary conditions for something.','You must pass an exam to {qualify}.','자격을 갖추려면 시험에 합격해야 해요.','qualify','B1','education',2,'qualify exam certificate credential'),
('w_education_B1_31','submit','/səbˈmɪt/','verb','제출하다','To hand in a piece of work for assessment.','Please {submit} your essay by midnight.','에세이를 자정까지 제출해 주세요.','submit','B1','education',1,'submit paper upload assignment deadline'),
('w_education_B1_32','revise','/rɪˈvaɪz/','verb','수정하다, 복습하다','To change or improve written work; to study for an exam.','I need to {revise} my essay before submitting it.','제출 전에 에세이를 수정해야 해요.','revise','B1','education',1,'revise edit paper studying'),
('w_education_B1_33','concentrate','/ˈkɒnsəntreɪt/','verb','집중하다','To focus your thoughts and attention.','It''s hard to {concentrate} when it''s noisy.','시끄러울 때 집중하기 어려워요.','concentrate','B1','education',1,'concentrate focus study quiet'),
('w_education_B1_34','comprehension','/ˌkɒmprɪˈhenʃən/','noun','이해력, 독해','The ability to understand written or spoken language.','The exam includes a {comprehension} passage.','시험에 독해 지문이 포함돼요.','comprehension','B1','education',1,'comprehension reading text understanding'),
('w_education_B1_35','plagiarism','/ˈpleɪdʒərɪzəm/','noun','표절','Using someone else''s work or ideas without permission.','{Plagiarism} can result in failing the course.','표절은 수업 낙제로 이어질 수 있어요.','plagiarism','B1','education',1,'plagiarism copying academic dishonesty');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_education_B2_01','methodology','/ˌmeθəˈdɒlədʒi/','noun','방법론','A system of methods used in a particular field of study.','The research used a qualitative {methodology}.','연구는 질적 방법론을 사용했어요.','methodology','B2','education',1,'methodology research systematic approach'),
('w_education_B2_02','hypothesis','/haɪˈpɒθɪsɪs/','noun','가설','A proposed explanation made on the basis of limited evidence.','The scientist tested her {hypothesis} carefully.','과학자는 가설을 신중하게 검증했어요.','hypothesis','B2','education',1,'hypothesis experiment science research'),
('w_education_B2_03','peer review','/pɪər rɪˈvjuː/','noun','동료 검토','Evaluation of work by others in the same field.','The article passed {peer review} before publication.','기사는 출판 전에 동료 검토를 통과했어요.','peer review','B2','education',1,'peer review academic journal evaluation'),
('w_education_B2_04','dissertation','/ˌdɪsərˈteɪʃən/','noun','(박사) 학위 논문','A long written work submitted for a doctoral degree.','She spent three years writing her {dissertation}.','그녀는 학위 논문을 쓰는 데 3년을 보냈어요.','dissertation','B2','education',1,'dissertation thesis research university'),
('w_education_B2_05','citation','/saɪˈteɪʃən/','noun','인용','A reference to a source in academic writing.','Every claim needs a {citation} in academic writing.','학술 글쓰기에서는 모든 주장에 인용이 필요해요.','citation','B2','education',1,'citation reference academic paper source'),
('w_education_B2_06','abstract','/ˈæbstrækt/','noun','초록, 요약','A short summary of a research paper.','Read the {abstract} before the full paper.','전체 논문 읽기 전에 초록을 읽으세요.','abstract','B2','education',1,'abstract summary research paper academic'),
('w_education_B2_07','empirical','/ɪmˈpɪrɪkəl/','adjective','경험적인, 실증적인','Based on observation or experiment rather than theory.','The study provides {empirical} evidence.','이 연구는 실증적 증거를 제공해요.','empirical','B2','education',1,'empirical data evidence experiment research'),
('w_education_B2_08','academic','/ˌækəˈdemɪk/','noun','학자','A person who works as a researcher or teacher at a university.','Several {academics} attended the conference.','여러 학자가 학회에 참석했어요.','academic','B2','education',1,'academic professor university scholar'),
('w_education_B2_09','faculty','/ˈfækəlti/','noun','교수진','The teaching staff of a university.','The {faculty} met to discuss the new syllabus.','교수진이 새 강의 계획서를 논의하기 위해 모였어요.','faculty','B2','education',1,'faculty staff university professors meeting'),
('w_education_B2_10','postgraduate','/ˌpoʊstˈɡrædʒuɪt/','noun','대학원생','A student doing advanced study after their first degree.','She is a {postgraduate} student in linguistics.','그녀는 언어학 대학원생이에요.','postgraduate','B2','education',1,'postgraduate university graduate student research'),
('w_education_B2_11','semiotics','/ˌsiːmiˈɒtɪks/','noun','기호학','The study of signs and symbols and their use or interpretation.','Her course introduces {semiotics} and media.','그녀의 강의는 기호학과 미디어를 소개해요.','semiotics','B2','education',2,'semiotics signs symbols language meaning'),
('w_education_B2_12','discourse','/ˈdɪskɔːrs/','noun','담론, 담화','Written or spoken communication and its social context.','Academic {discourse} requires formal language.','학술 담론에는 격식체 언어가 필요해요.','discourse','B2','education',2,'discourse communication language academic'),
('w_education_B2_13','inference','/ˈɪnfərəns/','noun','추론','A conclusion reached on the basis of evidence and reasoning.','Drawing {inference} from data is a key skill.','데이터에서 추론하는 것은 핵심 능력이에요.','inference','B2','education',1,'inference reasoning logic conclusion'),
('w_education_B2_14','synthesis','/ˈsɪnθɪsɪs/','noun','종합, 통합','The combination of elements to form a whole.','The essay requires a {synthesis} of various sources.','이 에세이는 다양한 자료의 통합을 요구해요.','synthesis','B2','education',1,'synthesis combine integrate research'),
('w_education_B2_15','critique','/krɪˈtiːk/','noun','비평, 비판적 분석','A detailed analysis and assessment of something.','Write a {critique} of the article for next week.','다음 주까지 기사 비평을 작성해 주세요.','critique','B2','education',1,'critique analysis review academic'),
('w_education_B2_16','framework','/ˈfreɪmwɜːrk/','noun','틀, 체계','A basic structure underlying a system or concept.','The {framework} guides the analysis.','이 틀이 분석을 이끌어요.','framework','B2','education',1,'framework structure system analysis'),
('w_education_B2_17','variable','/ˈveəriəbəl/','noun','변수','An element that may change in an experiment.','The study controls for several {variables}.','이 연구는 여러 변수를 통제해요.','variable','B2','education',1,'variable experiment research data'),
('w_education_B2_18','quantitative','/ˈkwɒntɪtətɪv/','adjective','양적인','Relating to, measuring, or measured by quantity.','A {quantitative} study uses numerical data.','양적 연구는 수치 데이터를 사용해요.','quantitative','B2','education',1,'quantitative data numbers research statistics'),
('w_education_B2_19','qualitative','/ˈkwɒlɪtətɪv/','adjective','질적인','Relating to or measured by quality rather than quantity.','The {qualitative} approach explores meanings.','질적 접근은 의미를 탐구해요.','qualitative','B2','education',1,'qualitative interview observation research'),
('w_education_B2_20','rhetoric','/ˈretərɪk/','noun','수사학, 수사법','The art of persuasive speaking or writing.','Strong {rhetoric} can win an argument.','강한 수사법은 논쟁을 이길 수 있어요.','rhetoric','B2','education',2,'rhetoric persuasion speech argument'),
('w_education_B2_21','annotate','/ˈænəteɪt/','verb','주석을 달다','To add notes or comments to a text.','Students {annotate} their texts during reading.','학생들은 읽으면서 텍스트에 주석을 달아요.','annotate','B2','education',2,'annotate notes margin text book'),
('w_education_B2_22','rationale','/ˌræʃəˈnɑːl/','noun','근거, 이유','The fundamental reason or basis for something.','Explain the {rationale} behind your argument.','주장의 근거를 설명해 주세요.','rationale','B2','education',2,'rationale reason basis argument'),
('w_education_B2_23','peer','/pɪər/','noun','동료, 동급생','A person of the same age or status.','Discuss your ideas with your {peers}.','동료들과 아이디어를 토론해 보세요.','peer','B2','education',1,'peer colleagues students group discussion'),
('w_education_B2_24','collaborate','/kəˈlæbəreɪt/','verb','협력하다, 공동 연구하다','To work jointly with others on a project.','Students {collaborate} on group assignments.','학생들은 그룹 과제를 위해 협력해요.','collaborate','B2','education',1,'collaborate teamwork group project students'),
('w_education_B2_25','curriculum vitae','/ˌkɜːrɪkjʊləm ˈviːtaɪ/','noun','이력서 (CV)','A written overview of a person''s qualifications and experience.','Submit your {curriculum vitae} with the application.','지원서와 함께 이력서를 제출해 주세요.','curriculum vitae','B2','education',2,'CV resume qualifications academic'),
('w_education_B2_26','bibliography','/ˌbɪbliˈɒɡrəfi/','noun','참고 문헌 목록','A list of books and sources used in a research paper.','Include a full {bibliography} at the end.','마지막에 전체 참고 문헌 목록을 포함하세요.','bibliography','B2','education',1,'bibliography references sources academic paper'),
('w_education_B2_27','syllabus','/ˈsɪləbəs/','noun','강의 계획서','An outline of the topics covered in a course.','Review the {syllabus} on the first day.','첫날 강의 계획서를 검토하세요.','syllabus','B2','education',1,'syllabus course outline plan university'),
('w_education_B2_28','tenure','/ˈtenjər/','noun','종신 재직권','The permanent status granted to a university professor.','She was granted {tenure} last year.','그녀는 작년에 종신 재직권을 받았어요.','tenure','B2','education',2,'tenure professor university permanent position'),
('w_education_B2_29','accreditation','/əˌkredɪˈteɪʃən/','noun','인가, 인증','Official recognition that an institution meets standards.','The university received full {accreditation}.','대학교는 완전한 인증을 받았어요.','accreditation','B2','education',2,'accreditation certification standard quality'),
('w_education_B2_30','transcript','/ˈtrænskrɪpt/','noun','성적 증명서','An official record of a student''s academic performance.','Send your official {transcript} with the application.','공식 성적 증명서를 지원서와 함께 보내주세요.','transcript','B2','education',2,'transcript academic record certificate'),
('w_education_B2_31','grant','/ɡrɑːnt/','noun','연구비, 보조금','Money given for a specific purpose such as research.','She received a research {grant} from the government.','그녀는 정부로부터 연구비를 받았어요.','grant','B2','education',1,'grant funding research money academic'),
('w_education_B2_32','cohort','/ˈkoʊhɔːrt/','noun','(동기) 집단','A group of students who begin study at the same time.','The 2024 {cohort} has fifty students.','2024년 동기는 50명이에요.','cohort','B2','education',2,'cohort group students year class'),
('w_education_B2_33','interdisciplinary','/ˌɪntərdɪˈsɪplɪneri/','adjective','학제 간의','Involving two or more academic disciplines.','The course takes an {interdisciplinary} approach.','이 강의는 학제 간 접근법을 취해요.','interdisciplinary','B2','education',2,'interdisciplinary cross-subject research academic'),
('w_education_B2_34','prerequisite','/ˌpriːˈrekwɪzɪt/','noun','선수 과목, 전제 조건','A required course or condition before another can be taken.','Statistics is a {prerequisite} for this module.','통계학은 이 모듈의 선수 과목이에요.','prerequisite','B2','education',2,'prerequisite requirement course condition'),
('w_education_B2_35','pedagogy','/ˈpedəɡɒdʒi/','noun','교수법','The method and practice of teaching.','Modern {pedagogy} emphasizes active learning.','현대 교수법은 능동적 학습을 강조해요.','pedagogy','B2','education',1,'pedagogy teaching method education practice');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_education_C1_01','epistemology','/ɪˌpɪstɪˈmɒlədʒi/','noun','인식론','The branch of philosophy concerned with the nature and scope of knowledge.','Her research draws on {epistemology} and cognitive science.','그녀의 연구는 인식론과 인지 과학을 바탕으로 해요.','epistemology','C1','education',1,'epistemology philosophy knowledge mind'),
('w_education_C1_02','pedagogy','/ˈpedəɡɒdʒi/','noun','교육학, 교수법','The art and science of teaching.','Critical {pedagogy} encourages students to question assumptions.','비판적 교수법은 학생들이 가정을 의심하도록 독려해요.','pedagogy','C1','education',1,'pedagogy teaching method classroom'),
('w_education_C1_03','paradigm','/ˈpærədaɪm/','noun','패러다임','A typical example or pattern; a framework of ideas.','Kuhn described scientific revolutions as {paradigm} shifts.','쿤은 과학 혁명을 패러다임 전환으로 설명했어요.','paradigm','C1','education',1,'paradigm shift concept framework science'),
('w_education_C1_04','dialectic','/ˌdaɪəˈlektɪk/','noun','변증법','A method of logical argument through discussion.','Hegel''s {dialectic} moves through thesis, antithesis, and synthesis.','헤겔의 변증법은 정, 반, 합으로 나아가요.','dialectic','C1','education',1,'dialectic argument logic philosophy'),
('w_education_C1_05','hermeneutics','/ˌhɜːrmɪˈnjuːtɪks/','noun','해석학','The theory and methodology of text interpretation.','{Hermeneutics} informs how we read ancient texts.','해석학은 우리가 고대 문헌을 읽는 방식에 영향을 줘요.','hermeneutics','C1','education',1,'hermeneutics interpretation text meaning'),
('w_education_C1_06','constructivism','/kənˈstrʌktɪvɪzəm/','noun','구성주의','The theory that learners actively construct knowledge.','{Constructivism} supports project-based learning.','구성주의는 프로젝트 기반 학습을 지지해요.','constructivism','C1','education',1,'constructivism learning building knowledge'),
('w_education_C1_07','positivism','/ˈpɒzɪtɪvɪzəm/','noun','실증주의','The philosophical view that knowledge comes from empirical evidence.','{Positivism} dominates natural science research.','실증주의는 자연 과학 연구를 지배해요.','positivism','C1','education',1,'positivism evidence science philosophy research'),
('w_education_C1_08','ontology','/ɒnˈtɒlədʒi/','noun','존재론','The branch of philosophy dealing with the nature of being.','The study''s {ontology} assumes social reality is constructed.','이 연구의 존재론은 사회 현실이 구성된다고 가정해요.','ontology','C1','education',1,'ontology being existence philosophy'),
('w_education_C1_09','axiom','/ˈæksiəm/','noun','공리, 자명한 이치','A statement accepted as true without proof.','"All men are mortal" is a classic {axiom}.','"모든 인간은 죽는다"는 고전적인 공리예요.','axiom','C1','education',1,'axiom truth principle self-evident'),
('w_education_C1_10','deductive','/dɪˈdʌktɪv/','adjective','연역적인','Moving from general principles to specific conclusions.','The study uses {deductive} reasoning.','이 연구는 연역적 추론을 사용해요.','deductive','C1','education',1,'deductive reasoning logic conclusion'),
('w_education_C1_11','inductive','/ɪnˈdʌktɪv/','adjective','귀납적인','Moving from specific observations to general principles.','{Inductive} logic moves from data to theory.','귀납적 논리는 데이터에서 이론으로 나아가요.','inductive','C1','education',1,'inductive logic data observation'),
('w_education_C1_12','critical thinking','/ˈkrɪtɪkəl ˈθɪŋkɪŋ/','noun','비판적 사고','The ability to analyse and evaluate information carefully.','{Critical thinking} is the cornerstone of good scholarship.','비판적 사고는 좋은 학문의 초석이에요.','critical thinking','C1','education',1,'critical thinking analysis evaluation'),
('w_education_C1_13','heuristic','/hjʊˈrɪstɪk/','adjective','발견적인, 경험에 기반한','Enabling a person to discover or learn by trial and error.','A {heuristic} approach helps students explore solutions.','발견적 접근은 학생들이 해결책을 탐색하도록 도와요.','heuristic','C1','education',2,'heuristic discovery learning problem solving'),
('w_education_C1_14','metacognition','/ˌmetəkɒɡˈnɪʃən/','noun','메타인지','Awareness and understanding of one''s own thought processes.','{Metacognition} helps learners monitor their progress.','메타인지는 학습자가 자신의 발전을 모니터하도록 도와요.','metacognition','C1','education',1,'metacognition thinking awareness learning'),
('w_education_C1_15','scaffolding','/ˈskæfəldɪŋ/','noun','발판식 교수법','Temporary support given to help a learner achieve a goal.','The teacher used {scaffolding} to guide the group.','선생님은 발판식 교수법을 사용해 그룹을 이끌었어요.','scaffolding','C1','education',2,'scaffolding support teaching learning'),
('w_education_C1_16','autonomy','/ɔːˈtɒnəmi/','noun','자율성','The right or condition of self-governance; independence in learning.','Student {autonomy} improves motivation.','학습자 자율성은 동기를 향상시켜요.','autonomy','C1','education',1,'autonomy independence self-directed learning'),
('w_education_C1_17','acculturation','/əˌkʌltʃəˈreɪʃən/','noun','문화 적응','The process of adapting to a different culture.','{Acculturation} affects international students deeply.','문화 적응은 유학생에게 깊은 영향을 미쳐요.','acculturation','C1','education',2,'acculturation culture adaptation students'),
('w_education_C1_18','triangulation','/traɪˌæŋɡjʊˈleɪʃən/','noun','삼각 검증법','Using multiple methods to validate research findings.','The study used {triangulation} to strengthen reliability.','연구는 신뢰성을 높이기 위해 삼각 검증법을 사용했어요.','triangulation','C1','education',2,'triangulation research method validation'),
('w_education_C1_19','reflexivity','/ˌriːflekˈsɪvɪti/','noun','성찰성','The capacity to reflect on one''s own biases in research.','{eflexivity} is essential in qualitative research.','성찰성은 질적 연구에서 필수적이에요.','reflexivity','C1','education',2,'reflexivity reflection bias research'),
('w_education_C1_20','epistemological','/ɪˌpɪstɪməˈlɒdʒɪkəl/','adjective','인식론적인','Relating to the theory of knowledge.','The paper raises {epistemological} questions.','논문은 인식론적 질문을 제기해요.','epistemological','C1','education',2,'epistemological knowledge philosophy'),
('w_education_C1_21','normative','/ˈnɔːrmətɪv/','adjective','규범적인','Relating to a standard or norm of behaviour.','The study takes a {normative} stance.','이 연구는 규범적 입장을 취해요.','normative','C1','education',2,'normative standard norm behaviour'),
('w_education_C1_22','praxis','/ˈpræksɪs/','noun','실천, 프락시스','The process of translating theory into practice.','Freire''s concept of {praxis} unites reflection and action.','프레이리의 프락시스 개념은 성찰과 행동을 결합해요.','praxis','C1','education',1,'praxis practice theory action education'),
('w_education_C1_23','discourse analysis','/ˈdɪskɔːrs əˈnæləsɪs/','noun','담화 분석','The study of language use in texts and social contexts.','{iscourse analysis} reveals power structures in texts.','담화 분석은 텍스트의 권력 구조를 드러내요.','discourse analysis','C1','education',2,'discourse analysis language text power'),
('w_education_C1_24','generalisability','/ˌdʒenrəlaɪzəˈbɪlɪti/','noun','일반화 가능성','The extent to which findings apply beyond the study sample.','Small samples limit {generalisability}.','작은 표본은 일반화 가능성을 제한해요.','generalisability','C1','education',2,'generalisability research sample findings'),
('w_education_C1_25','validity','/vəˈlɪdɪti/','noun','타당성','The degree to which a test or study measures what it claims to.','Ensure the instrument has strong {validity}.','측정 도구가 강한 타당성을 갖추도록 하세요.','validity','C1','education',1,'validity research measurement testing'),
('w_education_C1_26','reliability','/rɪˌlaɪəˈbɪlɪti/','noun','신뢰성','The consistency of a measure or research result.','Test-retest {reliability} was confirmed.','검사-재검사 신뢰성이 확인됐어요.','reliability','C1','education',1,'reliability consistency research measurement'),
('w_education_C1_27','replication','/ˌreplɪˈkeɪʃən/','noun','재현, 복제','Repeating a study to verify its findings.','{eplication} is central to scientific credibility.','재현은 과학적 신뢰성의 핵심이에요.','replication','C1','education',2,'replication experiment science research'),
('w_education_C1_28','peer-reviewed','/ˈpɪər rɪˌvjuːd/','adjective','동료 심사를 거친','Evaluated by experts before publication.','Only cite {peer-reviewed} sources in your paper.','논문에서는 동료 심사를 거친 자료만 인용하세요.','peer-reviewed','C1','education',1,'peer-reviewed journal academic publication'),
('w_education_C1_29','conceptual framework','/kənˈseptʃuəl ˈfreɪmwɜːrk/','noun','개념적 틀','A structured set of concepts used to guide research.','The {conceptual framework} draws on three theories.','개념적 틀은 세 이론을 바탕으로 해요.','conceptual framework','C1','education',1,'conceptual framework theory research guide'),
('w_education_C1_30','literature review','/ˈlɪtrətʃər rɪˈvjuː/','noun','문헌 검토','A survey of existing research on a topic.','The {literature review} identifies gaps in knowledge.','문헌 검토는 지식의 공백을 파악해요.','literature review','C1','education',1,'literature review research academic sources'),
('w_education_C1_31','sampling','/ˈsæmplɪŋ/','noun','표본 추출','The process of selecting individuals for a study.','Random {sampling} reduces selection bias.','무작위 표본 추출은 선택 편향을 줄여요.','sampling','C1','education',2,'sampling research data population'),
('w_education_C1_32','operationalise','/ˌɒpərˈeɪʃənəlaɪz/','verb','조작화하다','To define a concept in measurable terms for research.','You need to {operationalise} the variable.','변수를 조작화해야 해요.','operationalise','C1','education',2,'operationalise measure define research'),
('w_education_C1_33','posit','/ˈpɒzɪt/','verb','가정하다, 상정하다','To put forward as a fact or basis for argument.','The author {posits} that education shapes identity.','저자는 교육이 정체성을 형성한다고 상정해요.','posit','C1','education',2,'posit argue claim academic'),
('w_education_C1_34','substantiate','/səbˈstænʃieɪt/','verb','입증하다, 뒷받침하다','To provide evidence to support a claim.','You must {substantiate} every claim with evidence.','모든 주장을 증거로 뒷받침해야 해요.','substantiate','C1','education',1,'substantiate evidence support proof'),
('w_education_C1_35','nuanced','/ˈnjuːɑːnst/','adjective','미묘한 차이가 있는','Showing subtle distinctions and complexities.','A {nuanced} reading reveals deeper meaning.','미묘한 독해는 더 깊은 의미를 드러내요.','nuanced','C1','education',2,'nuanced subtle complex analysis');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_education_C2_01','heuristics','/hjʊˈrɪstɪks/','noun','발견술, 휴리스틱스','Mental shortcuts that enable quick decision-making, especially in learning.','Cognitive {heuristics} can lead to systematic errors.','인지적 발견술은 체계적 오류로 이어질 수 있어요.','heuristics','C2','education',1,'heuristics cognition decision learning'),
('w_education_C2_02','phenomenology','/fɪˌnɒmɪˈnɒlədʒi/','noun','현상학','A philosophical method examining lived experience.','{henomenology} captures the essence of human experience.','현상학은 인간 경험의 본질을 포착해요.','phenomenology','C2','education',1,'phenomenology experience philosophy research'),
('w_education_C2_03','reductionism','/rɪˈdʌkʃənɪzəm/','noun','환원주의','The view that complex phenomena can be explained by simpler parts.','{eductionism} is criticised for oversimplifying social behaviour.','환원주의는 사회 행동을 지나치게 단순화한다는 비판을 받아요.','reductionism','C2','education',1,'reductionism simplify complex system philosophy'),
('w_education_C2_04','falsifiability','/fɔːlsɪfaɪəˈbɪlɪti/','noun','반증 가능성','The capacity for a claim to be proven false by evidence.','Popper argued that {falsifiability} distinguishes science from pseudoscience.','포퍼는 반증 가능성이 과학을 사이비 과학과 구별한다고 주장했어요.','falsifiability','C2','education',1,'falsifiability Popper science research theory'),
('w_education_C2_05','epistemological','/ɪˌpɪstɪməˈlɒdʒɪkəl/','adjective','인식론적인','Relating to the philosophical study of knowledge and its limits.','The article makes an {epistemological} argument about evidence.','이 논문은 증거에 관한 인식론적 주장을 해요.','epistemological','C2','education',1,'epistemological knowledge philosophy limits'),
('w_education_C2_06','praxis','/ˈpræksɪs/','noun','이론과 실천의 통합','The integration of theory and practice in transformative education.','Freire''s {praxis} model challenges oppressive structures.','프레이리의 프락시스 모델은 억압적 구조에 도전해요.','praxis','C2','education',1,'praxis Freire education liberation theory'),
('w_education_C2_07','deconstruction','/ˌdiːkənˈstrʌkʃən/','noun','해체주의','A method of critical analysis that questions fixed meanings.','Derrida''s {deconstruction} destabilises binary oppositions.','데리다의 해체주의는 이항 대립을 불안정하게 해요.','deconstruction','C2','education',1,'deconstruction Derrida postmodern text'),
('w_education_C2_08','semiotic','/ˌsiːmiˈɒtɪk/','adjective','기호학적인','Relating to signs and symbols and their interpretation.','A {semiotic} reading of the curriculum reveals hidden values.','교육 과정의 기호학적 독해는 숨겨진 가치를 드러내요.','semiotic','C2','education',1,'semiotic signs symbols meaning language'),
('w_education_C2_09','poststructuralism','/ˌpoʊstˈstrʌktʃərəlɪzəm/','noun','후기 구조주의','A theoretical approach questioning fixed meanings in language and culture.','{oststructuralism} rejects the idea of a stable text.','후기 구조주의는 안정적인 텍스트라는 개념을 거부해요.','poststructuralism','C2','education',1,'poststructuralism theory language culture'),
('w_education_C2_10','scholasticism','/skəˈlæstɪsɪzəm/','noun','스콜라주의','A medieval theological and philosophical method emphasising systematic reasoning.','{cholasticism} sought to reconcile faith and reason.','스콜라주의는 신앙과 이성을 화해시키려 했어요.','scholasticism','C2','education',1,'scholasticism medieval philosophy theology'),
('w_education_C2_11','ontological','/ˌɒntəˈlɒdʒɪkəl/','adjective','존재론적인','Relating to the nature of being or existence.','The research takes an {ontological} stance on social reality.','이 연구는 사회 현실에 대해 존재론적 입장을 취해요.','ontological','C2','education',2,'ontological being existence philosophy'),
('w_education_C2_12','intersubjectivity','/ˌɪntərsʌbdʒekˈtɪvɪti/','noun','상호 주관성','Shared understanding between different subjects or minds.','{ntersubjectivity} is central to collaborative learning.','상호 주관성은 협력 학습의 핵심이에요.','intersubjectivity','C2','education',2,'intersubjectivity shared understanding learning'),
('w_education_C2_13','logocentrism','/ˌloʊɡoʊˈsentrɪzəm/','noun','로고스 중심주의','The privileging of speech over writing in Western thought.','Derrida critiqued {logocentrism} in philosophical traditions.','데리다는 철학 전통에서 로고스 중심주의를 비판했어요.','logocentrism','C2','education',2,'logocentrism language philosophy Derrida'),
('w_education_C2_14','noumenon','/ˈnuːmɪnɒn/','noun','물자체, 누메논','The thing as it is in itself, independent of perception.','Kant distinguished between phenomenon and {noumenon}.','칸트는 현상과 물자체를 구별했어요.','noumenon','C2','education',2,'noumenon Kant philosophy thing itself'),
('w_education_C2_15','teleology','/ˌteliˈɒlədʒi/','noun','목적론','The explanation of phenomena in terms of goals or purposes.','{eleology} argues that education has an inherent purpose.','목적론은 교육에 내재적 목적이 있다고 주장해요.','teleology','C2','education',2,'teleology purpose goal philosophy'),
('w_education_C2_16','intertextuality','/ˌɪntətekstʃuˈælɪti/','noun','상호 텍스트성','The relationship between texts and their mutual influences.','{ntertextuality} shapes how readers interpret meaning.','상호 텍스트성은 독자가 의미를 해석하는 방식을 형성해요.','intertextuality','C2','education',2,'intertextuality text literature meaning'),
('w_education_C2_17','relativism','/ˈrelətɪvɪzəm/','noun','상대주의','The view that knowledge and truth are relative to context.','{elativism} challenges universal educational standards.','상대주의는 보편적 교육 기준에 도전해요.','relativism','C2','education',2,'relativism truth context culture philosophy'),
('w_education_C2_18','dialectical materialism','/ˌdaɪəˈlektɪkəl məˈtɪəriəlɪzəm/','noun','변증법적 유물론','Marx''s philosophical framework combining dialectics and materialism.','{ialectical materialism} views education as shaped by economic forces.','변증법적 유물론은 교육이 경제적 힘에 의해 형성된다고 봐요.','dialectical materialism','C2','education',2,'dialectical materialism Marx philosophy education'),
('w_education_C2_19','aporia','/əˈpɔːriə/','noun','난제, 아포리아','A philosophical puzzle or state of puzzlement.','The text leaves the reader in a state of {aporia}.','텍스트는 독자를 아포리아 상태에 남겨두어요.','aporia','C2','education',2,'aporia puzzle philosophy doubt'),
('w_education_C2_20','heteroglossia','/ˌhetərəˈɡlɒsiə/','noun','다성성, 이종 언어성','The coexistence of multiple voices or languages in a text.','Bakhtin''s concept of {heteroglossia} challenges monolithic discourse.','바흐친의 다성성 개념은 일원적 담론에 도전해요.','heteroglossia','C2','education',2,'heteroglossia voices language Bakhtin'),
('w_education_C2_21','abduction','/æbˈdʌkʃən/','noun','귀추법','Reasoning from observation to the most likely explanation.','{bduction} generates hypotheses in qualitative research.','귀추법은 질적 연구에서 가설을 생성해요.','abduction','C2','education',2,'abduction reasoning hypothesis research'),
('w_education_C2_22','phronesis','/ˈfrɒnɪsɪs/','noun','실천적 지혜','Aristotle''s concept of practical wisdom in ethical action.','{hronesis} guides teachers in morally complex situations.','실천적 지혜는 도덕적으로 복잡한 상황에서 교사를 이끌어요.','phronesis','C2','education',2,'phronesis wisdom practical Aristotle'),
('w_education_C2_23','liminality','/ˌlɪmɪˈnælɪti/','noun','경계성, 리미널리티','The transitional quality of being between two states.','{iminality} describes the in-between state of new learners.','경계성은 새로운 학습자의 중간 상태를 설명해요.','liminality','C2','education',2,'liminality transition threshold learning'),
('w_education_C2_24','hegemony','/hɪˈdʒeməni/','noun','패권, 헤게모니','Dominant control exerted over others, especially in education.','Gramsci examined {hegemony} in educational institutions.','그람시는 교육 기관의 헤게모니를 검토했어요.','hegemony','C2','education',1,'hegemony power dominance education Gramsci'),
('w_education_C2_25','interlocutor','/ˌɪntəˈlɒkjʊtər/','noun','대화 상대자','A person who participates in a dialogue or interaction.','The {interlocutor} plays a key role in oral assessment.','대화 상대자는 구술 평가에서 핵심 역할을 해요.','interlocutor','C2','education',2,'interlocutor dialogue conversation assessment'),
('w_education_C2_26','verisimilitude','/ˌverɪsɪˈmɪlɪtjuːd/','noun','진실성, 사실성','The appearance of being true or real in research.','{erisimilitude} strengthens the credibility of qualitative findings.','진실성은 질적 연구 결과의 신뢰성을 강화해요.','verisimilitude','C2','education',2,'verisimilitude truth research credibility'),
('w_education_C2_27','episteme','/ˈepɪstiːm/','noun','에피스테메','Foucault''s term for the underlying system of thought in an era.','Each era has its own {episteme} shaping what counts as knowledge.','각 시대는 지식으로 여겨지는 것을 형성하는 자체 에피스테메를 가져요.','episteme','C2','education',2,'episteme Foucault knowledge era'),
('w_education_C2_28','bricolage','/ˌbrɪkəˈlɑːʒ/','noun','브리콜라주','Using whatever tools are available to construct meaning.','Qualitative researchers engage in intellectual {bricolage}.','질적 연구자들은 지적 브리콜라주에 참여해요.','bricolage','C2','education',2,'bricolage construct tools meaning research'),
('w_education_C2_29','sedimentation','/ˌsedɪmenˈteɪʃən/','noun','침전, 층적 형성','The gradual accumulation and layering of cultural meaning.','{edimentation} of beliefs resists change in institutions.','믿음의 침전은 기관의 변화에 저항해요.','sedimentation','C2','education',2,'sedimentation accumulation layer meaning culture'),
('w_education_C2_30','rhizome','/ˈraɪzoʊm/','noun','리좀, 근경','Deleuze and Guattari''s metaphor for non-hierarchical knowledge networks.','{hizome} thinking challenges linear curricula.','리좀적 사고는 선형 교육 과정에 도전해요.','rhizome','C2','education',2,'rhizome network knowledge nonlinear'),
('w_education_C2_31','logomachy','/lɒˈɡɒməki/','noun','말다툼, 언어 논쟁','A dispute over the meaning of words.','The philosophical {logomachy} obscured the real issue.','철학적 말다툼이 진짜 문제를 흐렸어요.','logomachy','C2','education',3,'logomachy debate words philosophy'),
('w_education_C2_32','propaedeutic','/ˌprɒpɪˈdjuːtɪk/','adjective','예비 교육의','Serving as an introduction to further study.','Logic is a {propaedeutic} discipline for philosophy.','논리학은 철학을 위한 예비 교육 분야예요.','propaedeutic','C2','education',3,'propaedeutic preparatory study foundation'),
('w_education_C2_33','catharsis','/kəˈθɑːrsɪs/','noun','카타르시스, 정화','A release of emotion through artistic or learning experience.','Reading great literature can provide {catharsis}.','위대한 문학을 읽으면 카타르시스를 얻을 수 있어요.','catharsis','C2','education',2,'catharsis emotion release learning'),
('w_education_C2_34','cogito','/ˈkɒdʒɪtoʊ/','noun','코기토','Descartes'' principle "I think, therefore I am".','The {cogito} is the foundation of Cartesian philosophy.','코기토는 데카르트 철학의 토대예요.','cogito','C2','education',2,'cogito Descartes thinking existence philosophy'),
('w_education_C2_35','anamnesis','/ˌænæmˈniːsɪs/','noun','상기, 아남네시스','Plato''s theory that learning is a process of recollection.','Plato''s {anamnesis} theory suggests knowledge is innate.','플라톤의 상기 이론은 지식이 내재적이라고 제안해요.','anamnesis','C2','education',2,'anamnesis Plato recollection knowledge');
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_education_A1_01','What''s your favorite subject?','제일 좋아하는 과목이 뭐예요?','favorite subject','favorite를 써서 선호를 물어볼 수 있어요.','수업 대화','A1','education','pattern',NULL,1),
('s_education_A1_02','I like math because it''s interesting.','수학이 재미있어서 좋아요.','I like ... because','이유를 말할 때 because를 쓰면 자연스러워요.','과목 소개','A1','education','pattern',NULL,2),
('s_education_A1_03','How do you spell that word?','그 단어 철자가 어떻게 돼요?','How do you spell','모르는 단어 철자를 물어볼 때 쓰는 표현이에요.','수업 중 질문','A1','education','pattern',NULL,3),
('s_education_A1_04','Can you say that again, please?','다시 한 번 말씀해 주실 수 있어요?','Can you say that again','이해 못했을 때 정중하게 다시 말해달라고 하는 표현이에요.','수업 중','A1','education','pattern',NULL,4),
('s_education_A1_05','What does this word mean?','이 단어는 무슨 뜻이에요?','What does ... mean','모르는 단어의 뜻을 물어볼 때 가장 기본적인 표현이에요.','어휘 확인','A1','education','pattern',NULL,5),
('s_education_A1_06','I don''t understand. Can you help me?','이해가 안 돼요. 도와주실 수 있어요?','I don''t understand','솔직하게 모른다고 말하는 것이 배움의 첫 걸음이에요.','도움 요청','A1','education','pattern',NULL,6),
('s_education_A1_07','We have a test tomorrow.','내일 시험이 있어요.','We have a test','시험을 안내할 때 쓰는 가장 간단한 표현이에요.','시험 안내','A1','education','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_education_A2_01','I need to study for the exam this weekend.','이번 주말에 시험 공부를 해야 해요.','need to study for','need to를 쓰면 해야 할 일을 자연스럽게 표현할 수 있어요.','시험 준비','A2','education','pattern',NULL,1),
('s_education_A2_02','Did you pass the test? I got a B.','시험 합격했어요? 저는 B 받았어요.','Did you pass','시험 결과를 물어보거나 공유할 때 쓰는 표현이에요.','성적 대화','A2','education','pattern',NULL,2),
('s_education_A2_03','I''m going to review my notes tonight.','오늘 밤에 필기 내용을 복습할 거예요.','review my notes','review를 써서 복습 계획을 말할 수 있어요.','공부 계획','A2','education','pattern',NULL,3),
('s_education_A2_04','What chapter is the exam on?','시험 범위가 몇 장이에요?','What chapter is ... on','시험 범위를 확인할 때 꼭 필요한 표현이에요.','시험 준비','A2','education','pattern',NULL,4),
('s_education_A2_05','The homework is due on Friday.','숙제 제출 기한은 금요일이에요.','is due on','마감일을 표현할 때 be due on을 사용해요.','과제 안내','A2','education','pattern',NULL,5),
('s_education_A2_06','I failed the quiz, so I need to try harder.','쪽지 시험에서 떨어져서 더 열심히 해야 해요.','I failed ... so I need to','결과와 다짐을 연결할 때 so를 사용해요.','자기 반성','A2','education','pattern',NULL,6),
('s_education_A2_07','Can I borrow your notes from yesterday''s class?','어제 수업 필기 빌릴 수 있어요?','Can I borrow','정중하게 빌려달라고 부탁하는 표현이에요.','친구에게 부탁','A2','education','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_education_B1_01','I''d like to talk about the importance of lifelong learning.','평생 학습의 중요성에 대해 말씀드리려고 해요.','I''d like to talk about','발표를 시작할 때 I''d like to를 쓰면 공손하고 자연스럽게 들려요.','발표 시작','B1','education','pattern',NULL,1),
('s_education_B1_02','Could you explain that concept in more detail?','그 개념을 좀 더 자세히 설명해 주실 수 있어요?','Could you explain ... in more detail','수업에서 추가 설명을 요청할 때 쓰는 정중한 표현이에요.','수업 중 질문','B1','education','pattern',NULL,2),
('s_education_B1_03','My assignment is to write an essay on climate change.','제 과제는 기후 변화에 관한 에세이를 쓰는 거예요.','My assignment is to','과제 내용을 설명할 때 쓰는 자연스러운 표현이에요.','과제 설명','B1','education','pattern',NULL,3),
('s_education_B1_04','In my presentation, I will cover three main points.','발표에서 세 가지 주요 논점을 다룰 거예요.','I will cover','발표 구조를 미리 안내할 때 쓰는 표현이에요.','발표 구조 안내','B1','education','pattern',NULL,4),
('s_education_B1_05','I''m not sure I understand the difference between these two terms.','이 두 용어의 차이를 잘 모르겠어요.','I''m not sure I understand','확신이 없을 때 부드럽게 물어보는 정중한 표현이에요.','개념 확인','B1','education','pattern',NULL,5),
('s_education_B1_06','To sum up, the evidence suggests that practice improves fluency.','요약하면, 증거는 연습이 유창성을 향상시킨다고 제안해요.','To sum up','발표나 에세이를 마무리할 때 쓰는 전형적인 표현이에요.','발표 마무리','B1','education','pattern',NULL,6),
('s_education_B1_07','I applied for a scholarship and I''m waiting to hear back.','장학금을 신청했고 결과를 기다리고 있어요.','waiting to hear back','결과를 기다리는 상황을 표현할 때 쓰는 관용 표현이에요.','장학금 지원','B1','education','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_education_B2_01','I see your point, but I''d argue that the data supports a different conclusion.','말씀하시는 바는 이해하지만, 데이터는 다른 결론을 지지한다고 생각해요.','I see your point, but I''d argue','반박할 때 상대방을 인정하면서 부드럽게 반론을 제시하는 표현이에요.','학술 토론','B2','education','pattern',NULL,1),
('s_education_B2_02','The methodology used in this study has some significant limitations.','이 연구에 사용된 방법론에는 몇 가지 중요한 한계가 있어요.','significant limitations','연구의 한계를 지적할 때 쓰는 학술적 표현이에요.','연구 비평','B2','education','pattern',NULL,2),
('s_education_B2_03','Could you elaborate on how you operationalised that variable?','그 변수를 어떻게 조작화했는지 좀 더 설명해 주실 수 있어요?','Could you elaborate on','학술 발표에서 방법론을 더 물어볼 때 쓰는 정중한 표현이에요.','연구 방법 질문','B2','education','pattern',NULL,3),
('s_education_B2_04','Building on the previous speaker''s argument, I would like to add that...','이전 발언자의 주장을 바탕으로, 추가하고 싶은 것은...','Building on','토론에서 앞선 의견을 이어받아 자신의 논점을 더할 때 쓰는 표현이에요.','토론 참여','B2','education','pattern',NULL,4),
('s_education_B2_05','The empirical evidence does not fully support this hypothesis.','실증적 증거가 이 가설을 완전히 지지하지는 않아요.','empirical evidence ... does not fully support','학술 글쓰기에서 가설의 한계를 조심스럽게 언급할 때 쓰는 표현이에요.','연구 결과 평가','B2','education','pattern',NULL,5),
('s_education_B2_06','This dissertation critically examines the relationship between pedagogy and identity.','이 논문은 교수법과 정체성의 관계를 비판적으로 검토해요.','critically examines','학위 논문의 목적을 설명할 때 쓰는 학술적 표현이에요.','논문 소개','B2','education','pattern',NULL,6),
('s_education_B2_07','I would contend that peer learning is as effective as direct instruction.','동료 학습이 직접 교수만큼 효과적이라고 주장하고 싶어요.','I would contend that','토론에서 신중하게 주장을 제시할 때 contend를 쓰면 격식 있게 들려요.','학술 주장','B2','education','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_education_C1_01','This study seeks to interrogate the epistemological assumptions underlying conventional pedagogy.','이 연구는 전통적 교수법의 기저에 있는 인식론적 가정을 비판적으로 검토하고자 해요.','interrogate the epistemological assumptions','interrogate는 단순한 검토를 넘어 비판적 질문을 던지는 것을 의미해요.','논문 서론','C1','education','pattern',NULL,1),
('s_education_C1_02','The conceptual framework draws on constructivist and sociocultural theories of learning.','개념적 틀은 구성주의와 사회문화적 학습 이론을 바탕으로 해요.','draws on ... theories','draws on은 이론적 토대를 설명할 때 쓰는 학술적 표현이에요.','이론적 배경','C1','education','pattern',NULL,2),
('s_education_C1_03','The findings substantiate the hypothesis that scaffolding enhances learner autonomy.','연구 결과는 발판식 교수법이 학습자 자율성을 향상시킨다는 가설을 뒷받침해요.','substantiate the hypothesis','substantiate는 주장이나 가설을 증거로 뒷받침함을 의미해요.','연구 결과 기술','C1','education','pattern',NULL,3),
('s_education_C1_04','It is worth noting that the sample size limits the generalisability of these findings.','표본 크기가 연구 결과의 일반화 가능성을 제한한다는 점을 언급할 필요가 있어요.','It is worth noting that','학술 글쓰기에서 한계나 주의사항을 부드럽게 제시하는 표현이에요.','연구 한계 기술','C1','education','pattern',NULL,4),
('s_education_C1_05','Reflexivity demands that the researcher acknowledge their own positionality.','성찰성은 연구자가 자신의 위치성을 인정할 것을 요구해요.','demands that the researcher acknowledge','연구 윤리 논의에서 연구자의 성찰을 강조하는 학술 표현이에요.','연구 윤리','C1','education','pattern',NULL,5),
('s_education_C1_06','The literature review reveals a significant lacuna in studies on postgraduate wellbeing.','문헌 검토는 대학원생 복지에 관한 연구의 중요한 공백을 드러내요.','reveals a significant lacuna','lacuna는 지식이나 연구의 빈 공간을 뜻하는 고급 학술 어휘예요.','문헌 검토','C1','education','pattern',NULL,6),
('s_education_C1_07','This paper posits that critical pedagogy must account for the socioeconomic context of learners.','이 논문은 비판적 교수법이 학습자의 사회경제적 맥락을 고려해야 한다고 상정해요.','posits that','posit은 논문에서 핵심 가정이나 전제를 제시할 때 쓰는 정확한 학술어예요.','논문 핵심 주장','C1','education','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_education_C2_01','Derrida''s deconstructive reading destabilises the binary between teacher authority and learner agency.','데리다의 해체적 독해는 교사 권위와 학습자 주체성의 이분법을 불안정하게 해요.','destabilises the binary between','destabilise a binary는 후기 구조주의 담론에서 핵심적인 표현이에요.','철학적 비평','C2','education','pattern',NULL,1),
('s_education_C2_02','Foucault''s episteme provides a lens through which to examine the archaeology of educational knowledge.','푸코의 에피스테메는 교육 지식의 고고학을 검토하는 렌즈를 제공해요.','provides a lens through which to examine','provides a lens through which는 고급 학술 글쓰기에서 분석 도구를 소개할 때 쓰는 전형적 표현이에요.','담론 분석','C2','education','pattern',NULL,2),
('s_education_C2_03','The falsifiability criterion challenges normative assumptions embedded in positivist research paradigms.','반증 가능성 기준은 실증주의 연구 패러다임에 내재된 규범적 가정에 도전해요.','challenges normative assumptions embedded in','embedded in은 무언가가 더 큰 구조 속에 깊이 자리 잡고 있음을 표현해요.','과학 철학 논의','C2','education','pattern',NULL,3),
('s_education_C2_04','Hegemonic discourse in curricula reproduces socioeconomic inequalities through the hidden curriculum.','교육 과정의 헤게모니적 담론은 잠재적 교육 과정을 통해 사회경제적 불평등을 재생산해요.','reproduces ... through the hidden curriculum','hidden curriculum은 공식 과목 외에 무의식적으로 전달되는 가치를 뜻하는 교육학 용어예요.','비판 교육학','C2','education','pattern',NULL,4),
('s_education_C2_05','Phenomenological inquiry foregrounds the lived experience of learners as the primary unit of analysis.','현상학적 탐구는 학습자의 살아있는 경험을 분석의 주요 단위로 전면에 내세워요.','foregrounds the lived experience','foreground는 무언가를 중심이나 전면에 배치한다는 의미의 학술적 동사예요.','연구 방법론 논의','C2','education','pattern',NULL,5),
('s_education_C2_06','Rhizomatic learning theory, as advanced by Cormier, resists arborescent models of knowledge transmission.','코미에가 발전시킨 리좀적 학습 이론은 나무형 지식 전달 모델에 저항해요.','resists arborescent models','arborescent은 나무처럼 계층적이고 선형적인 구조를 뜻하는 들뢰즈 철학 용어예요.','교육 이론 논의','C2','education','pattern',NULL,6),
('s_education_C2_07','The praxis-oriented approach collapses the distinction between knowledge production and social transformation.','프락시스 지향 접근은 지식 생산과 사회 변혁 사이의 구분을 무너뜨려요.','collapses the distinction between','collapse a distinction은 두 개념 사이의 경계를 허물 때 쓰는 고급 학술 표현이에요.','비판 이론','C2','education','pattern',NULL,7);
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_media_A1_01','phone','/foʊn/','noun','전화기, 스마트폰','A device used to make calls and access the internet.','She checks her {phone} all day.','그녀는 하루 종일 전화기를 봐요.','phone','A1','media',1,'smartphone phone screen hand scrolling'),
('w_media_A1_02','video','/ˈvɪdioʊ/','noun','동영상','A recording of moving images, often shared online.','Did you watch that funny {video}?','그 웃긴 영상 봤어요?','video','A1','media',1,'phone screen watching video social'),
('w_media_A1_03','photo','/ˈfoʊtoʊ/','noun','사진','A picture taken with a camera.','She posted a {photo} of her lunch.','그녀는 점심 사진을 올렸어요.','photo','A1','media',1,'photo camera picture taking selfie'),
('w_media_A1_04','news','/njuːz/','noun','뉴스','New information about recent events.','I read the {news} every morning.','저는 매일 아침 뉴스를 읽어요.','news','A1','media',1,'news website newspaper headline reading'),
('w_media_A1_05','watch','/wɒtʃ/','verb','시청하다, 보다','To look at something for a period of time.','Let''s {watch} a movie tonight.','오늘 밤 영화 봐요.','watch','A1','media',1,'watching tv couch movie remote control'),
('w_media_A1_06','listen','/ˈlɪsən/','verb','듣다','To pay attention to sound.','I love to {listen} to music on the way to work.','출근길에 음악 듣는 것을 좋아해요.','listen','A1','media',1,'listening music headphones earphones'),
('w_media_A1_07','screen','/skriːn/','noun','화면, 스크린','The flat surface of a phone, TV, or computer that displays images.','My {screen} cracked when I dropped my phone.','폰을 떨어뜨려서 화면이 깨졌어요.','screen','A1','media',1,'cracked phone screen broken smartphone'),
('w_media_A1_08','message','/ˈmesɪdʒ/','noun','메시지','A short piece of text sent to someone.','I got your {message} — I''ll call you back.','메시지 받았어요. 다시 전화할게요.','message','A1','media',1,'text message chat bubble smartphone notification'),
('w_media_A1_09','call','/kɔːl/','noun','전화','A phone conversation with someone.','I''ll give you a {call} later today.','오늘 나중에 전화할게요.','call','A1','media',1,'phone call talking handset conversation'),
('w_media_A1_10','app','/æp/','noun','앱, 애플리케이션','A software program on a phone or computer.','Which {app} do you use for streaming music?','음악 스트리밍할 때 어떤 앱 써요?','app','A1','media',1,'mobile app icons smartphone home screen'),
('w_media_A1_11','read','/riːd/','verb','읽다','To look at and understand written words.','I {read} the article you sent me.','보내준 기사 읽었어요.','read','A1','media',2,'reading article phone news online'),
('w_media_A1_12','picture','/ˈpɪktʃər/','noun','그림, 사진','An image, either drawn or photographed.','Can you take a {picture} of me here?','여기서 사진 찍어줄 수 있어요?','picture','A1','media',2,'taking picture selfie tourist landmark'),
('w_media_A1_13','music','/ˈmjuːzɪk/','noun','음악','Sounds arranged in a pleasant way, often with rhythm.','I always play {music} while studying.','공부할 때 항상 음악을 틀어요.','music','A1','media',1,'music playlist headphones study focus'),
('w_media_A1_14','show','/ʃoʊ/','noun','프로그램, 쇼','A TV or online program with episodes.','Have you seen that new {show} on Netflix?','넷플릭스 그 새 프로그램 봤어요?','show','A1','media',1,'netflix tv show streaming sofa watching'),
('w_media_A1_15','text','/tekst/','noun','문자, 텍스트','A written message sent from a phone.','He sent me a {text} saying he was late.','그는 늦는다는 문자를 보냈어요.','text','A1','media',2,'sms text message phone notification typing'),
('w_media_A1_16','game','/ɡeɪm/','noun','게임','An activity played for fun, often on a device.','She spends hours playing a mobile {game}.','그녀는 모바일 게임을 몇 시간씩 해요.','game','A1','media',2,'mobile game smartphone gaming playing'),
('w_media_A1_17','send','/send/','verb','보내다','To cause something to go to another person.','Can you {send} me the link?','링크 보내줄 수 있어요?','send','A1','media',1,'sending link message email sharing'),
('w_media_A1_18','like','/laɪk/','verb','좋아요를 누르다','To press a button showing approval on social media.','Don''t forget to {like} and subscribe!','좋아요 누르고 구독도 잊지 마세요!','like','A1','media',1,'like button social media thumbs up'),
('w_media_A1_19','post','/poʊst/','noun','게시물','A piece of content published online.','That {post} got thousands of likes.','그 게시물은 수천 개의 좋아요를 받았어요.','post','A1','media',1,'instagram post social media feed likes'),
('w_media_A1_20','clip','/klɪp/','noun','클립, 짧은 영상','A short piece of video.','I saw a funny {clip} this morning.','오늘 아침에 재밌는 클립 봤어요.','clip','A1','media',2,'short video clip funny social media reel'),
('w_media_A1_21','internet','/ˈɪntərnet/','noun','인터넷','A global network connecting computers and devices.','The {internet} is slow today.','오늘 인터넷이 느려요.','internet','A1','media',1,'wifi internet connection router signal'),
('w_media_A1_22','page','/peɪdʒ/','noun','페이지, 채널','A user profile or official account on social media.','Follow our official {page} for updates.','업데이트를 보려면 공식 페이지를 팔로우하세요.','page','A1','media',2,'social media page facebook instagram profile'),
('w_media_A1_23','link','/lɪŋk/','noun','링크','A clickable connection to a website or file.','She shared a {link} to the article.','그녀는 기사 링크를 공유했어요.','link','A1','media',1,'sharing link url website phone screen'),
('w_media_A1_24','play','/pleɪ/','verb','재생하다','To cause audio or video to run.','{Play} the video from the beginning.','영상을 처음부터 재생해 줘요.','play','A1','media',1,'play button video youtube watching'),
('w_media_A1_25','comment','/ˈkɒment/','noun','댓글','A remark left on a post or video.','She left a kind {comment} on my photo.','그녀가 제 사진에 친절한 댓글을 남겼어요.','comment','A1','media',2,'comment section social media reply typing'),
('w_media_A1_26','live','/lɪv/','adjective','라이브의, 실시간의','Happening or shown at the moment, not recorded.','She went {live} on Instagram.','그녀는 인스타그램에서 라이브를 켰어요.','live','A1','media',2,'instagram live streaming broadcast real time'),
('w_media_A1_27','search','/sɜːrtʃ/','verb','검색하다','To look for information online.','Just {search} it on YouTube.','유튜브에서 검색해 봐요.','search','A1','media',1,'search bar google youtube typing query'),
('w_media_A1_28','upload','/ˈʌploʊd/','verb','업로드하다','To transfer a file from a device to the internet.','He {uploaded} the photos after the trip.','그는 여행 후 사진을 업로드했어요.','upload','A1','media',2,'uploading photo cloud phone laptop progress'),
('w_media_A1_29','share','/ʃer/','verb','공유하다','To send or show content to others.','Please {share} this video with your friends.','이 영상을 친구들과 공유해 주세요.','share','A1','media',1,'share button social media repost forwarding'),
('w_media_A1_30','story','/ˈstɔːri/','noun','스토리','A short-lived post visible for 24 hours on social media.','Did you see her {story} this morning?','오늘 아침 그녀 스토리 봤어요?','story','A1','media',2,'instagram story circle phone 24 hours'),
('w_media_A1_31','channel','/ˈtʃænəl/','noun','채널','An account on a platform like YouTube that posts content.','Subscribe to my {channel} for new videos.','새 영상을 보려면 제 채널을 구독하세요.','channel','A1','media',1,'youtube channel subscribe videos creator'),
('w_media_A1_32','subscribe','/səbˈskraɪb/','verb','구독하다','To sign up to receive content from a creator.','I {subscribe} to a lot of cooking channels.','저는 요리 채널을 많이 구독해요.','subscribe','A1','media',1,'youtube subscribe button bell notification'),
('w_media_A1_33','notification','/ˌnoʊtɪfɪˈkeɪʃən/','noun','알림','A message that alerts you to an update.','Turn on {notifications} so you don''t miss anything.','아무것도 놓치지 않도록 알림을 켜 두세요.','notifications','A1','media',2,'phone notification bell alert lock screen'),
('w_media_A1_34','follow','/ˈfɒloʊ/','verb','팔로우하다','To subscribe to someone''s updates on social media.','I {follow} a lot of travel accounts.','저는 여행 계정을 많이 팔로우해요.','follow','A1','media',1,'follow button instagram social media profile'),
('w_media_A1_35','download','/ˈdaʊnloʊd/','verb','다운로드하다','To save a file from the internet to a device.','{Download} the app and sign up for free.','앱을 다운로드하고 무료로 가입하세요.','Download','A1','media',1,'downloading app phone progress bar install');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_media_A2_01','post','/poʊst/','verb','게시하다','To publish content on social media or a website.','She {posts} photos every single day.','그녀는 매일 사진을 게시해요.','posts','A2','media',1,'posting photo instagram social media creator'),
('w_media_A2_02','comment','/ˈkɒment/','verb','댓글을 달다','To leave a written response on a post or video.','Please {comment} your thoughts below.','아래에 생각을 댓글로 남겨 주세요.','comment','A2','media',1,'commenting reply social media keyboard typing'),
('w_media_A2_03','share','/ʃer/','noun','공유, 공유 횟수','The act of reposting content or the total count of reposts.','This article got over a million {shares}.','이 기사는 백만 건 이상 공유됐어요.','shares','A2','media',1,'sharing viral article social media million'),
('w_media_A2_04','follow','/ˈfɒloʊ/','noun','팔로워','The act of following someone, or one''s follower base.','She gained ten thousand new {follows} overnight.','그녀는 하룻밤 사이 팔로워가 만 명 늘었어요.','follows','A2','media',2,'follower count instagram overnight viral'),
('w_media_A2_05','subscribe','/səbˈskraɪb/','noun (derived)','구독','The action of signing up for regular updates.','Hit the {subscribe} button and the bell icon.','구독 버튼과 벨 아이콘을 눌러 주세요.','subscribe','A2','media',1,'subscribe bell youtube button click'),
('w_media_A2_06','channel','/ˈtʃænəl/','verb','채널을 개설하다 (비유)','To direct something through a particular medium.','She {channeled} her creativity into short films.','그녀는 창의력을 단편 영화로 쏟아부었어요.','channeled','A2','media',2,'creative short film making filming shoot'),
('w_media_A2_07','upload','/ˈʌploʊd/','noun','업로드','A file or piece of content transferred to the internet.','His latest {upload} has a million views already.','그의 최신 업로드가 벌써 백만 조회수예요.','upload','A2','media',1,'youtube million views video upload creator'),
('w_media_A2_08','download','/ˈdaʊnloʊd/','noun','다운로드','A file retrieved from the internet to a local device.','The podcast {download} numbers went up this month.','이번 달 팟캐스트 다운로드 수가 올랐어요.','download','A2','media',1,'podcast download statistics graph trending'),
('w_media_A2_09','stream','/striːm/','verb','스트리밍하다','To watch or listen to media online without downloading it.','I {stream} music instead of buying albums.','앨범을 사지 않고 음악을 스트리밍해요.','stream','A2','media',1,'music streaming app spotify headphones phone'),
('w_media_A2_10','search','/sɜːrtʃ/','noun','검색','The act of looking for information online.','A quick {search} showed me exactly what I needed.','간단히 검색해 보니 필요한 게 바로 나왔어요.','search','A2','media',1,'google search bar result webpage phone'),
('w_media_A2_11','profile','/ˈproʊfaɪl/','noun','프로필','A page showing a user''s personal information on social media.','Update your {profile} picture to a recent one.','프로필 사진을 최근 사진으로 바꿔 보세요.','profile','A2','media',1,'social media profile page picture bio update'),
('w_media_A2_12','feed','/fiːd/','noun','피드','The stream of posts shown on a social media homepage.','My {feed} is full of travel photos lately.','요즘 제 피드는 여행 사진으로 가득해요.','feed','A2','media',1,'instagram feed scroll photos social media'),
('w_media_A2_13','reply','/rɪˈplaɪ/','verb','답장하다, 답글 달다','To respond to a message or comment.','Don''t forget to {reply} to your followers.','팔로워에게 답글 달는 것 잊지 마세요.','reply','A2','media',1,'reply comment message social media engaging'),
('w_media_A2_14','view','/vjuː/','noun','조회수','The number of times a video or post has been seen.','The clip reached one million {views} in a day.','그 클립이 하루 만에 조회수 백만을 달성했어요.','views','A2','media',1,'million views youtube video counter milestone'),
('w_media_A2_15','tag','/tæɡ/','verb','태그하다','To link a person or topic in a post using @.','She {tagged} me in a funny meme.','그녀가 웃긴 밈에서 저를 태그했어요.','tagged','A2','media',2,'tagging instagram mention friend photo tag'),
('w_media_A2_16','meme','/miːm/','noun','밈','A funny image or video that spreads rapidly online.','That {meme} is everywhere this week.','그 밈이 이번 주 어디서나 보여요.','meme','A2','media',2,'meme funny internet viral image caption'),
('w_media_A2_17','reel','/riːl/','noun','릴스, 짧은 영상','A short, edited video posted on social media.','Her {reel} got featured on the Explore page.','그녀의 릴스가 탐색 페이지에 소개됐어요.','reel','A2','media',1,'instagram reels short video explore feature'),
('w_media_A2_18','live','/laɪv/','noun','라이브 방송','A real-time video broadcast on social media.','He did a {live} to announce the big news.','그는 큰 소식을 발표하기 위해 라이브를 켰어요.','live','A2','media',2,'live streaming announce news social media'),
('w_media_A2_19','caption','/ˈkæpʃən/','noun','캡션, 설명글','Text written below a photo or video on social media.','She always writes such clever {captions}.','그녀는 항상 재치 있는 캡션을 써요.','captions','A2','media',2,'instagram caption witty post writing'),
('w_media_A2_20','filter','/ˈfɪltər/','noun','필터','A digital effect applied to a photo or video.','Which {filter} did you use on this photo?','이 사진에 어떤 필터 썼어요?','filter','A2','media',2,'instagram photo filter editing beautiful light'),
('w_media_A2_21','trend','/trend/','noun','트렌드, 유행','A popular topic or style at a given time.','That song is a huge {trend} right now.','그 노래가 지금 엄청난 트렌드예요.','trend','A2','media',1,'trending music tiktok popular chart viral'),
('w_media_A2_22','viral','/ˈvaɪrəl/','adjective','바이럴의, 입소문 난','Spreading rapidly and widely across social media.','The cat video went {viral} overnight.','그 고양이 영상이 하룻밤 사이 바이럴됐어요.','viral','A2','media',1,'viral video cat funny social media shares'),
('w_media_A2_23','username','/ˈjuːzərneɪm/','noun','사용자 이름','The name a user chooses for an online account.','What''s your {username}? I''ll follow you.','사용자 이름이 뭐예요? 팔로우할게요.','username','A2','media',2,'social media account username handle profile'),
('w_media_A2_24','notification','/ˌnoʊtɪfɪˈkeɪʃən/','noun','알림 설정','A system alert about new activity online.','I turned off {notifications} for that app.','그 앱의 알림을 껐어요.','notifications','A2','media',2,'turning off notifications phone settings app'),
('w_media_A2_25','block','/blɒk/','verb','차단하다','To prevent someone from seeing your content.','She had to {block} a rude commenter.','그녀는 무례한 댓글러를 차단해야 했어요.','block','A2','media',2,'blocking user social media rude comment privacy'),
('w_media_A2_26','unfollow','/ˌʌnˈfɒloʊ/','verb','언팔로우하다','To stop following someone on social media.','I had to {unfollow} that account — too many ads.','그 계정 언팔했어요. 광고가 너무 많아서요.','unfollow','A2','media',2,'unfollow button social media account ads'),
('w_media_A2_27','repost','/ˌriːˈpoʊst/','verb','리포스트하다','To share someone else''s post on your own account.','He {reposted} my photo without asking.','그는 허락도 없이 제 사진을 리포스트했어요.','reposted','A2','media',2,'reposting sharing social media content credit'),
('w_media_A2_28','hashtag','/ˈhæʃtæɡ/','noun','해시태그','A word preceded by # used to categorize posts.','Add some {hashtags} to get more reach.','더 많은 도달을 위해 해시태그를 붙여 보세요.','hashtags','A2','media',1,'hashtag instagram trending discover category'),
('w_media_A2_29','creator','/kriˈeɪtər/','noun','크리에이터','Someone who makes content for online platforms.','She became a full-time content {creator}.','그녀는 전업 콘텐츠 크리에이터가 됐어요.','creator','A2','media',1,'content creator filming vlog youtube channel'),
('w_media_A2_30','podcast','/ˈpɒdkæst/','noun','팟캐스트','An audio program available for streaming or download.','I listen to a {podcast} on my morning commute.','아침 출근길에 팟캐스트를 들어요.','podcast','A2','media',1,'podcast headphones commute listening app morning'),
('w_media_A2_31','screenshot','/ˈskriːnʃɒt/','noun','스크린샷','An image captured of what is displayed on a screen.','I took a {screenshot} of the conversation.','대화 내용 스크린샷을 찍었어요.','screenshot','A2','media',2,'screenshot phone screen capture conversation'),
('w_media_A2_32','emoji','/ɪˈmoʊdʒi/','noun','이모지','A small digital image used in messages.','Her message was just three {emojis}.','그녀의 메시지는 이모지 세 개뿐이었어요.','emojis','A2','media',2,'emoji keyboard message phone chat colorful'),
('w_media_A2_33','react','/riˈækt/','verb','반응하다 (이모지로)','To respond to a post with an emoji reaction.','Everyone {reacted} with a heart to her post.','모두가 그녀의 게시물에 하트로 반응했어요.','reacted','A2','media',2,'react heart emoji post facebook reaction'),
('w_media_A2_34','content','/ˈkɒntent/','noun','콘텐츠','Material such as text, images, or video published online.','Good {content} takes time to create.','좋은 콘텐츠를 만드는 데는 시간이 걸려요.','content','A2','media',1,'creating content camera laptop editing desk'),
('w_media_A2_35','account','/əˈkaʊnt/','noun','계정','A personal profile registered on an online platform.','Create a free {account} to get started.','시작하려면 무료 계정을 만드세요.','account','A2','media',1,'social media account signup login phone app');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_media_B1_01','content','/ˈkɒntent/','noun','콘텐츠, 미디어 소재','Material created for online audiences, including video, text, and images.','Creating quality {content} requires planning and consistency.','양질의 콘텐츠를 만들려면 계획과 꾸준함이 필요해요.','content','B1','media',1,'content strategy planning camera filming studio'),
('w_media_B1_02','influencer','/ˈɪnfluənsər/','noun','인플루언서','A person with many social media followers who can influence buying decisions.','She partnered with a popular {influencer} for the campaign.','그녀는 캠페인을 위해 유명 인플루언서와 협력했어요.','influencer','B1','media',1,'influencer marketing brand deal social media'),
('w_media_B1_03','platform','/ˈplætfɔːrm/','noun','플랫폼','An online service or website where users create and share content.','Which {platform} do you use the most?','어떤 플랫폼을 가장 많이 사용해요?','platform','B1','media',1,'social media platforms icons logos apps'),
('w_media_B1_04','viral','/ˈvaɪrəl/','noun (derived)','바이럴','Something that spreads rapidly across the internet.','The campaign went {viral} within hours.','그 캠페인은 몇 시간 만에 바이럴됐어요.','viral','B1','media',1,'viral campaign trending social media exponential'),
('w_media_B1_05','algorithm','/ˈælɡərɪðəm/','noun','알고리즘','A set of rules a platform uses to decide what content to show users.','The {algorithm} rewards consistent posting.','알고리즘은 꾸준한 게시를 선호해요.','algorithm','B1','media',1,'algorithm recommendation feed content youtube'),
('w_media_B1_06','trending','/ˈtrendɪŋ/','adjective','트렌딩의, 유행하는','Currently popular and widely discussed on social media or news.','That topic has been {trending} all week.','그 주제가 일주일 내내 트렌딩이에요.','trending','B1','media',1,'trending topic twitter hashtag social media'),
('w_media_B1_07','hashtag','/ˈhæʃtæɡ/','noun','해시태그 (전략적 사용)','A labeling tool used to categorize content and improve discoverability.','Use relevant {hashtags} to reach a wider audience.','더 많은 사람들에게 닿으려면 관련 해시태그를 써요.','hashtags','B1','media',1,'hashtag strategy instagram reach discoverability'),
('w_media_B1_08','engagement','/ɪnˈɡeɪdʒmənt/','noun','참여도, 인게이지먼트','The level of interaction (likes, comments, shares) a post receives.','High {engagement} signals quality content to the algorithm.','높은 참여도는 알고리즘에 양질의 콘텐츠라는 신호를 줘요.','engagement','B1','media',1,'engagement rate likes comments shares analytics'),
('w_media_B1_09','broadcast','/ˈbrɔːdkæst/','verb','방송하다','To transmit a programme to many people via radio, TV, or online.','The event was {broadcast} live on all major channels.','그 행사는 모든 주요 채널에서 생방송됐어요.','broadcast','B1','media',1,'live broadcast television news anchor studio'),
('w_media_B1_10','podcast','/ˈpɒdkæst/','verb','팟캐스트로 내보내다','To produce and distribute audio episodes online.','She started {podcasting} about personal finance.','그녀는 개인 재무에 관한 팟캐스트를 시작했어요.','podcasting','B1','media',1,'podcasting microphone recording studio episode'),
('w_media_B1_11','clickbait','/ˈklɪkbeɪt/','noun','낚시성 제목','A sensational or misleading headline designed to attract clicks.','That article headline is pure {clickbait}.','그 기사 제목은 완전 낚시예요.','clickbait','B1','media',1,'clickbait headline sensational news article link'),
('w_media_B1_12','thumbnail','/ˈθʌmbneɪl/','noun','썸네일','A small preview image representing a video or post.','A good {thumbnail} can double your click-through rate.','좋은 썸네일은 클릭률을 두 배로 높일 수 있어요.','thumbnail','B1','media',1,'youtube thumbnail design video preview click'),
('w_media_B1_13','caption','/ˈkæpʃən/','verb','캡션을 달다, 설명하다','To write text describing an image or adding context.','She carefully {captioned} each photo with a story.','그녀는 각 사진에 신중하게 이야기를 담은 캡션을 달았어요.','captioned','B1','media',2,'writing caption instagram storytelling photo post'),
('w_media_B1_14','recommend','/ˌrekəˈmend/','verb','추천하다 (콘텐츠)','To suggest content worth watching or reading.','The app {recommends} videos based on your watch history.','앱은 시청 기록을 바탕으로 영상을 추천해요.','recommends','B1','media',1,'recommendation engine youtube watch history suggest'),
('w_media_B1_15','reaction','/riˈækʃən/','noun','반응 영상','A video in which someone responds to existing content.','His {reaction} video to the trailer got more views than the original.','예고편에 대한 그의 반응 영상이 원본보다 더 많은 조회수를 받았어요.','reaction','B1','media',2,'reaction video youtube trailer watching face'),
('w_media_B1_16','subscriber','/səbˈskraɪbər/','noun','구독자','A person who subscribes to a channel or newsletter.','She reached one million {subscribers} this year.','그녀는 올해 구독자 백만 명을 달성했어요.','subscribers','B1','media',1,'one million subscribers youtube creator celebration'),
('w_media_B1_17','collaboration','/kəˌlæbəˈreɪʃən/','noun','콜라보, 협업','Two or more creators working together on content.','The {collaboration} between the two YouTubers doubled both audiences.','두 유튜버의 콜라보로 양측 시청자가 두 배 늘었어요.','collaboration','B1','media',1,'collaboration youtuber collab filming together studio'),
('w_media_B1_18','monetize','/ˈmɒnɪtaɪz/','verb','수익화하다','To earn money from a channel or online content.','You need 1,000 subscribers before you can {monetize}.','수익화하려면 구독자 천 명이 필요해요.','monetize','B1','media',1,'monetize youtube earnings channel income revenue'),
('w_media_B1_19','analytics','/ˌænəˈlɪtɪks/','noun','분석 데이터','Data showing how content performs (views, reach, retention).','Check your {analytics} to see what your audience enjoys.','어떤 콘텐츠를 좋아하는지 분석 데이터를 확인해 보세요.','analytics','B1','media',1,'analytics dashboard graph data social media insights'),
('w_media_B1_20','reach','/riːtʃ/','noun','도달 범위','The total number of unique people who see a piece of content.','The campaign had a {reach} of over five million.','그 캠페인의 도달 범위는 오백만 이상이었어요.','reach','B1','media',1,'reach metric social media campaign statistics chart'),
('w_media_B1_21','niche','/niːʃ/','noun','틈새 분야','A specialized area of interest that attracts a specific audience.','Finding your {niche} is key to growing an audience.','자신의 틈새 분야를 찾는 것이 청중을 키우는 핵심이에요.','niche','B1','media',1,'niche content creator specific audience hobby channel'),
('w_media_B1_22','format','/ˈfɔːrmæt/','noun','포맷, 형식','The structure and style of a media piece.','Experiment with different {formats} to see what works.','어떤 게 효과적인지 다양한 포맷을 시험해 보세요.','formats','B1','media',2,'video format style different short long tutorial'),
('w_media_B1_23','brand deal','/brænd diːl/','noun','브랜드 딜, 광고 협찬','A paid partnership between a creator and a company.','She disclosed her {brand deal} in the video description.','그녀는 영상 설명에 브랜드 딜을 공개했어요.','brand deal','B1','media',1,'brand deal sponsorship disclosure influencer product'),
('w_media_B1_24','comment section','/ˈkɒment ˌsekʃən/','noun','댓글 창','The area below a video or post where users leave comments.','The {comment section} was filled with debate.','댓글 창은 논쟁으로 가득했어요.','comment section','B1','media',2,'comment section debate youtube controversial'),
('w_media_B1_25','binge','/bɪndʒ/','verb','몰아보다','To watch many episodes of a show in a short time.','I {binged} the whole series in one weekend.','주말 동안 시리즈 전편을 몰아봤어요.','binged','B1','media',1,'binge watching netflix series sofa night cozy'),
('w_media_B1_26','go live','/ɡoʊ laɪv/','phrase','라이브 방송을 시작하다','To begin a real-time broadcast on a social media platform.','She {went live} to answer questions from fans.','그녀는 팬들의 질문에 답하기 위해 라이브를 켰어요.','went live','B1','media',2,'going live instagram fans questions real time'),
('w_media_B1_27','retweet','/ˌriːˈtwiːt/','verb','리트윗하다','To share another user''s tweet to your own followers.','The celebrity {retweeted} the fan''s message.','그 셀럽은 팬의 메시지를 리트윗했어요.','retweeted','B1','media',2,'retweet twitter celebrity fan viral'),
('w_media_B1_28','unboxing','/ˌʌnˈbɒksɪŋ/','noun','언박싱','A type of video showing someone opening a new product.','His {unboxing} video of the new console got five million views.','그의 새 콘솔 언박싱 영상은 오백만 조회수를 받았어요.','unboxing','B1','media',2,'unboxing video product new box opening hands'),
('w_media_B1_29','tutorial','/tjuːˈtɔːriəl/','noun','튜토리얼','An instructional video or guide teaching a skill.','I learned the skill from a YouTube {tutorial}.','유튜브 튜토리얼로 그 기술을 배웠어요.','tutorial','B1','media',1,'tutorial youtube learning skill how-to video'),
('w_media_B1_30','vlog','/vlɒɡ/','noun','브이로그','A video diary or journal shared online.','She documents her travels in a weekly {vlog}.','그녀는 주간 브이로그로 여행을 기록해요.','vlog','B1','media',1,'vlog travel daily life camera selfie stick'),
('w_media_B1_31','demographic','/ˌdeməˈɡræfɪk/','noun','인구통계, 타깃 시청자','A specific group of people sharing characteristics targeted by media.','The show''s {demographic} is mostly teens and young adults.','그 쇼의 타깃 시청자는 주로 10대와 청년층이에요.','demographic','B1','media',2,'target audience demographic age group chart'),
('w_media_B1_32','spoiler','/ˈspɔɪlər/','noun','스포일러','Information that reveals key plot points before someone has seen/read them.','Warning: this review contains {spoilers}.','경고: 이 리뷰에는 스포일러가 포함되어 있어요.','spoilers','B1','media',2,'spoiler warning movie review no spoiler banner'),
('w_media_B1_33','streaming service','/ˈstriːmɪŋ ˈsɜːrvɪs/','noun','스트리밍 서비스','An online platform that provides on-demand audio or video content.','Which {streaming service} do you subscribe to?','어떤 스트리밍 서비스 구독해요?','streaming service','B1','media',1,'netflix spotify streaming service logo subscription'),
('w_media_B1_34','verified','/ˈverɪfaɪd/','adjective','인증된','Having a badge confirming authenticity on a social media account.','Getting {verified} on Instagram boosts credibility.','인스타그램에서 인증 받으면 신뢰도가 올라가요.','verified','B1','media',2,'verified blue checkmark instagram account badge'),
('w_media_B1_35','clip','/klɪp/','verb','클립으로 잘라내다','To extract a short segment from a longer video.','He {clipped} the funniest moments for his highlights.','그는 가장 재미있는 순간들을 클립으로 잘라 하이라이트를 만들었어요.','clipped','B1','media',2,'clipping video highlights editing short cut');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_media_B2_01','misinformation','/ˌmɪsɪnfərˈmeɪʃən/','noun','잘못된 정보','False or inaccurate information spread without deliberate intent to deceive.','Social media accelerates the spread of {misinformation}.','소셜 미디어는 잘못된 정보의 확산을 가속화해요.','misinformation','B2','media',1,'misinformation fake news spread social media warning'),
('w_media_B2_02','disinformation','/ˌdɪsɪnfərˈmeɪʃən/','noun','허위 정보','False information deliberately spread to deceive people.','State-sponsored {disinformation} campaigns target voters.','국가 주도의 허위 정보 캠페인은 유권자를 타깃으로 해요.','disinformation','B2','media',1,'disinformation propaganda fake news government media'),
('w_media_B2_03','clickbait','/ˈklɪkbeɪt/','verb (derived)','낚시 기사를 쓰다','To produce content with misleading headlines to attract clicks.','Many news outlets resort to {clickbait} to survive.','많은 언론사들이 살아남기 위해 낚시성 기사에 의존해요.','clickbait','B2','media',1,'clickbait headline news outlet sensational media'),
('w_media_B2_04','polarization','/ˌpoʊlərɪˈzeɪʃən/','noun','양극화','The process of dividing into two opposing groups with extreme views.','Social media contributes to political {polarization}.','소셜 미디어는 정치적 양극화에 기여해요.','polarization','B2','media',1,'political polarization divided groups social media debate'),
('w_media_B2_05','narrative','/ˈnærətɪv/','noun','서사, 담론','The particular way a story or series of events is described or interpreted.','The media shapes the {narrative} around public events.','미디어는 공공 사건에 대한 서사를 형성해요.','narrative','B2','media',1,'media narrative storytelling news framing bias'),
('w_media_B2_06','curate','/kjʊˈreɪt/','verb','큐레이션하다','To carefully select and organize content for a specific audience.','She {curates} a daily newsletter of the best tech news.','그녀는 매일 최고의 기술 뉴스 뉴스레터를 큐레이션해요.','curates','B2','media',1,'curating content newsletter best selection editorial'),
('w_media_B2_07','monetize','/ˈmɒnɪtaɪz/','verb','수익화 전략을 세우다','To develop revenue streams from digital content or platforms.','The startup is looking for ways to {monetize} user data.','그 스타트업은 사용자 데이터를 수익화할 방법을 찾고 있어요.','monetize','B2','media',1,'monetize data startup revenue business model digital'),
('w_media_B2_08','analytics','/ˌænəˈlɪtɪks/','noun','고급 분석','Advanced data analysis used to understand audience behaviour.','Deep {analytics} reveal when your audience is most active.','심층 분석을 통해 청중이 가장 활발한 시간대를 알 수 있어요.','analytics','B2','media',1,'deep analytics dashboard data visualization insight'),
('w_media_B2_09','demographic','/ˌdeməˈɡræfɪk/','adjective','인구통계학적인','Relating to the structure of populations in terms of age, gender, etc.','The platform shifted its {demographic} focus to older users.','그 플랫폼은 인구통계학적 초점을 고령층으로 바꿨어요.','demographic','B2','media',1,'demographic shift older users platform age graph'),
('w_media_B2_10','reach','/riːtʃ/','verb','도달하다 (미디어)','To successfully communicate with or influence a target audience.','The campaign aimed to {reach} young voters.','그 캠페인은 젊은 유권자들에게 닿는 것을 목표로 했어요.','reach','B2','media',1,'campaign reaching young voters media strategy'),
('w_media_B2_11','echo chamber','/ˈekoʊ ˌtʃeɪmbər/','noun','에코 챔버, 정보의 거품','An environment where people only encounter views that reinforce their own.','Social media algorithms can trap users in an {echo chamber}.','소셜 미디어 알고리즘이 사용자를 에코 챔버에 가두기도 해요.','echo chamber','B2','media',1,'echo chamber bubble social media algorithm opinions'),
('w_media_B2_12','filter bubble','/ˈfɪltər ˌbʌbəl/','noun','필터 버블','A state of intellectual isolation caused by personalised content.','We need to burst our {filter bubble} and seek diverse news.','필터 버블을 깨고 다양한 뉴스를 접해야 해요.','filter bubble','B2','media',1,'filter bubble personalization algorithm isolation diverse'),
('w_media_B2_13','fact-check','/ˈfækt tʃek/','verb','팩트체크하다','To verify the accuracy of a claim or piece of information.','Always {fact-check} before sharing news online.','온라인에서 뉴스를 공유하기 전에 항상 팩트체크하세요.','fact-check','B2','media',1,'fact checking news media accuracy verification research'),
('w_media_B2_14','media literacy','/ˈmiːdiə ˌlɪtərəsi/','noun','미디어 리터러시','The ability to critically analyze and evaluate media messages.','Schools should teach {media literacy} from an early age.','학교에서는 어릴 때부터 미디어 리터러시를 가르쳐야 해요.','media literacy','B2','media',1,'media literacy education critical thinking news students'),
('w_media_B2_15','algorithm bias','/ˈælɡərɪðəm baɪəs/','noun','알고리즘 편향','When a recommendation system systematically favours certain viewpoints.','Researchers found evidence of {algorithm bias} on the platform.','연구자들은 그 플랫폼에서 알고리즘 편향의 증거를 발견했어요.','algorithm bias','B2','media',1,'algorithm bias AI fairness data skewed results'),
('w_media_B2_16','credibility','/ˌkredɪˈbɪlɪti/','noun','신뢰성','The quality of being trusted and believed as accurate.','A journalist''s {credibility} is their most valuable asset.','저널리스트의 신뢰성은 가장 소중한 자산이에요.','credibility','B2','media',1,'credibility journalist trust media source reliable'),
('w_media_B2_17','bias','/ˈbaɪəs/','noun','편향','Inclination or prejudice in favour of or against something.','Every news outlet has some degree of editorial {bias}.','모든 언론사에는 어느 정도의 편집 편향이 있어요.','bias','B2','media',1,'media bias editorial perspective lean news'),
('w_media_B2_18','censorship','/ˈsensərʃɪp/','noun','검열','The suppression of content deemed objectionable or harmful.','Critics accused the government of internet {censorship}.','비평가들은 정부를 인터넷 검열로 비난했어요.','censorship','B2','media',1,'censorship internet blocked government freedom press'),
('w_media_B2_19','algorithm','/ˈælɡərɪðəm/','noun','알고리즘 (플랫폼 전략)','The complex system determining what content appears in user feeds.','Understanding the {algorithm} is key to growing online.','알고리즘을 이해하는 것이 온라인에서 성장하는 핵심이에요.','algorithm','B2','media',1,'algorithm code data platform content recommendation'),
('w_media_B2_20','influencer marketing','/ˈɪnfluənsər ˈmɑːrkɪtɪŋ/','noun','인플루언서 마케팅','A strategy using popular social media figures to promote products.','Brands now invest heavily in {influencer marketing}.','브랜드들은 이제 인플루언서 마케팅에 대규모 투자를 해요.','influencer marketing','B2','media',1,'influencer marketing brand partnership sponsored content'),
('w_media_B2_21','deepfake','/ˈdiːpfeɪk/','noun','딥페이크','Synthetic media using AI to replace someone''s likeness in video.','A {deepfake} video of the politician circulated online.','그 정치인의 딥페이크 영상이 온라인에 퍼졌어요.','deepfake','B2','media',1,'deepfake AI fake video face swap synthetic media'),
('w_media_B2_22','transparency','/trænsˈpærənsi/','noun','투명성','Openness about how decisions, including content choices, are made.','The platform was called out for a lack of {transparency}.','그 플랫폼은 투명성 부족으로 비난을 받았어요.','transparency','B2','media',1,'transparency platform content policy trust accountability'),
('w_media_B2_23','engagement rate','/ɪnˈɡeɪdʒmənt reɪt/','noun','참여율','The percentage of followers who interact with a post.','An {engagement rate} above 3% is considered healthy.','참여율 3% 이상은 양호한 것으로 여겨져요.','engagement rate','B2','media',1,'engagement rate analytics instagram metric performance'),
('w_media_B2_24','content moderation','/ˈkɒntent ˌmɒdəˈreɪʃən/','noun','콘텐츠 중재','The process of monitoring and enforcing platform rules.','{Content moderation} is increasingly handled by AI.','콘텐츠 중재는 점점 더 AI가 담당하고 있어요.','content moderation','B2','media',1,'content moderation AI flag remove policy platform'),
('w_media_B2_25','virality','/vaɪˈræləti/','noun','바이럴성','The quality of spreading rapidly across social networks.','The ad''s {virality} surprised even the marketing team.','그 광고의 바이럴성은 마케팅 팀조차 놀라게 했어요.','virality','B2','media',1,'virality social media ad campaign surprise spread'),
('w_media_B2_26','cancel culture','/ˈkænsəl ˌkʌltʃər/','noun','캔슬 컬처','The practice of withdrawing support from public figures for offensive behaviour.','The debate around {cancel culture} divides opinions online.','캔슬 컬처를 둘러싼 논쟁이 온라인에서 의견을 나누고 있어요.','cancel culture','B2','media',1,'cancel culture debate social media public figure'),
('w_media_B2_27','comment moderation','/ˈkɒment ˌmɒdəˈreɪʃən/','noun','댓글 관리','The review and removal of harmful or abusive user comments.','Better {comment moderation} could reduce online hate speech.','더 나은 댓글 관리로 온라인 혐오 발언을 줄일 수 있어요.','comment moderation','B2','media',2,'comment moderation hate speech online safety platform'),
('w_media_B2_28','algorithm-driven','/ˈælɡərɪðəm ˌdrɪvən/','adjective','알고리즘 기반의','Controlled or determined by automated computational rules.','Our news experience has become entirely {algorithm-driven}.','우리의 뉴스 경험은 완전히 알고리즘 기반이 됐어요.','algorithm-driven','B2','media',2,'algorithm driven news feed automated personalised'),
('w_media_B2_29','news cycle','/njuːz ˈsaɪkəl/','noun','뉴스 사이클','The time it takes for a story to appear, peak, and disappear from media.','Politicians now exploit the 24-hour {news cycle}.','정치인들은 이제 24시간 뉴스 사이클을 이용해요.','news cycle','B2','media',1,'24 hour news cycle media coverage fast changing'),
('w_media_B2_30','platform economy','/ˈplætfɔːrm ɪˈkɒnəmi/','noun','플랫폼 경제','An economic model where value is created through digital platforms.','The {platform economy} has disrupted traditional industries.','플랫폼 경제가 전통 산업을 혁신해 왔어요.','platform economy','B2','media',1,'platform economy disruption digital gig creator'),
('w_media_B2_31','data privacy','/ˈdeɪtə ˈprɪvəsi/','noun','데이터 프라이버시','The right of individuals to control how their personal data is used.','Users are increasingly concerned about {data privacy}.','사용자들은 데이터 프라이버시에 대한 우려가 점점 커지고 있어요.','data privacy','B2','media',1,'data privacy GDPR personal information protection'),
('w_media_B2_32','sensationalism','/senˈseɪʃənəlɪzəm/','noun','선정주의','The use of shocking or exaggerated stories to attract attention.','Tabloid journalism often relies on {sensationalism}.','타블로이드 저널리즘은 종종 선정주의에 의존해요.','sensationalism','B2','media',1,'sensationalism tabloid headline shocking exaggerated news'),
('w_media_B2_33','public opinion','/ˈpʌblɪk əˈpɪnjən/','noun','여론','The collective views held by a large number of people on a topic.','Social media now shapes {public opinion} faster than ever.','소셜 미디어가 이제 그 어느 때보다 빠르게 여론을 형성해요.','public opinion','B2','media',1,'public opinion poll social media influence speed'),
('w_media_B2_34','editorial','/ˌedɪˈtɔːriəl/','noun','사설, 편집의','An article expressing the opinion of a publication.','The newspaper ran a critical {editorial} on the policy.','그 신문은 정책에 비판적인 사설을 실었어요.','editorial','B2','media',1,'editorial newspaper opinion page critical analysis'),
('w_media_B2_35','press freedom','/pres ˈfriːdəm/','noun','언론의 자유','The freedom of journalists and news organisations to report without restriction.','Journalists worldwide fight to protect {press freedom}.','전 세계 기자들은 언론의 자유를 지키기 위해 싸우고 있어요.','press freedom','B2','media',1,'press freedom journalism protest newspaper freedom');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_media_C1_01','media literacy','/ˈmiːdiə ˌlɪtərəsi/','noun','미디어 리터러시','The capacity to access, analyze, evaluate, and create media messages.','Developing {media literacy} is essential in today''s information landscape.','오늘날의 정보 환경에서 미디어 리터러시를 키우는 것은 필수예요.','media literacy','C1','media',1,'media literacy critical thinking news analysis skills'),
('w_media_C1_02','propaganda','/ˌprɒpəˈɡændə/','noun','선전, 프로파간다','Information, especially biased, used to promote a political cause.','State-run media often functions as a vehicle for {propaganda}.','국가 운영 미디어는 종종 선전의 수단으로 기능해요.','propaganda','C1','media',1,'propaganda poster government media bias political'),
('w_media_C1_03','surveillance','/sərˈveɪləns/','noun','감시 (디지털)','The monitoring of behaviour and communications, especially online.','Mass digital {surveillance} raises serious privacy concerns.','대규모 디지털 감시는 심각한 프라이버시 우려를 낳아요.','surveillance','C1','media',1,'surveillance cameras CCTV digital monitoring privacy'),
('w_media_C1_04','censorship','/ˈsensərʃɪp/','noun','검열 (비판적 관점)','The suppression of speech or information considered harmful or politically inconvenient.','Internet {censorship} is expanding in authoritarian states.','인터넷 검열이 권위주의 국가에서 확대되고 있어요.','censorship','C1','media',1,'internet censorship authoritarian block firewall freedom'),
('w_media_C1_05','epistemology','/ɪˌpɪstɪˈmɒlədʒi/','noun','인식론','The branch of philosophy concerned with how we know what we know.','The post-truth era challenges our media {epistemology}.','탈진실 시대는 우리의 미디어 인식론에 도전장을 내밀어요.','epistemology','C1','media',1,'epistemology knowledge philosophy truth media information'),
('w_media_C1_06','discourse','/ˈdɪskɔːrs/','noun','담론','A way of talking about or representing a subject that shapes understanding.','The public {discourse} around AI is often distorted by media.','AI에 관한 공론장 담론은 미디어에 의해 종종 왜곡돼요.','discourse','C1','media',1,'public discourse debate media analysis social conversation'),
('w_media_C1_07','hegemony','/hɪˈɡeməni/','noun','헤게모니','Dominance by one group over others, especially in cultural or media terms.','Media {hegemony} shapes which stories get told globally.','미디어 헤게모니는 어떤 이야기가 전 세계적으로 전달될지 형성해요.','hegemony','C1','media',1,'media hegemony global dominance power cultural influence'),
('w_media_C1_08','gatekeeping','/ˈɡeɪtkiːpɪŋ/','noun','게이트키핑','The process of controlling access to information in the media.','Social media has disrupted traditional journalistic {gatekeeping}.','소셜 미디어는 전통적인 저널리즘의 게이트키핑을 혼란에 빠뜨렸어요.','gatekeeping','C1','media',1,'gatekeeping journalism editor media power information'),
('w_media_C1_09','framing','/ˈfreɪmɪŋ/','noun','프레이밍, 틀짓기','The process by which media shapes how issues are perceived.','The {framing} of immigration as a crisis influences public opinion.','이민을 위기로 프레이밍하는 것이 여론에 영향을 줘요.','framing','C1','media',1,'media framing immigration news coverage bias perspective'),
('w_media_C1_10','agenda-setting','/əˈdʒendə ˌsetɪŋ/','noun','의제 설정','The media''s power to influence which issues the public considers important.','News editors engage in {agenda-setting} every day.','뉴스 편집자들은 매일 의제 설정을 해요.','agenda-setting','C1','media',1,'agenda setting media power news editorial priority'),
('w_media_C1_11','manufactured consent','/ˌmænjʊˈfæktʃərd kənˈsent/','noun','동의 조작','The systematic shaping of public opinion by elites through media.','Noam Chomsky described {manufactured consent} in mass media.','노암 촘스키는 대중 매체에서의 동의 조작을 설명했어요.','manufactured consent','C1','media',1,'manufactured consent Chomsky media elite propaganda'),
('w_media_C1_12','disinformation warfare','/ˌdɪsɪnfərˈmeɪʃən ˈwɔːrfer/','noun','허위정보 전쟁','The strategic use of false information as a tool of geopolitical conflict.','Several nations engage in {disinformation warfare} online.','여러 국가들이 온라인에서 허위정보 전쟁을 벌이고 있어요.','disinformation warfare','C1','media',1,'information warfare geopolitics online fake news strategy'),
('w_media_C1_13','participatory media','/pɑːˌtɪsɪpətɔːri ˈmiːdiə/','noun','참여적 미디어','Media forms that enable active audience engagement and content creation.','Blogs were the first wave of {participatory media}.','블로그는 참여적 미디어의 첫 번째 물결이었어요.','participatory media','C1','media',2,'participatory media blog user generated content web'),
('w_media_C1_14','algorithmic amplification','/ˌælɡərɪðmɪk ˌæmplɪfɪˈkeɪʃən/','noun','알고리즘 증폭','The process by which platforms boost the spread of certain content.','Outrage content benefits from {algorithmic amplification}.','분노 유발 콘텐츠는 알고리즘 증폭으로 이득을 봐요.','algorithmic amplification','C1','media',1,'algorithm amplification outrage viral spread content boost'),
('w_media_C1_15','media convergence','/ˈmiːdiə kənˈvɜːrdʒəns/','noun','미디어 융합','The merging of different media forms through digital technology.','The smartphone is a symbol of {media convergence}.','스마트폰은 미디어 융합의 상징이에요.','media convergence','C1','media',2,'media convergence smartphone digital all-in-one platform'),
('w_media_C1_16','infodemic','/ˌɪnfoʊˈdemɪk/','noun','인포데믹','An overabundance of information, especially online misinformation during a crisis.','The WHO warned of an {infodemic} alongside the pandemic.','WHO는 팬데믹과 함께 인포데믹을 경고했어요.','infodemic','C1','media',1,'infodemic misinformation pandemic overload news'),
('w_media_C1_17','platform governance','/ˈplætfɔːrm ˈɡʌvərnəns/','noun','플랫폼 거버넌스','The rules and systems by which online platforms manage their communities.','Calls for better {platform governance} are growing louder.','더 나은 플랫폼 거버넌스를 요구하는 목소리가 커지고 있어요.','platform governance','C1','media',1,'platform governance regulation tech policy law rules'),
('w_media_C1_18','soft power','/sɒft ˈpaʊər/','noun','소프트 파워','The ability to influence others through cultural appeal rather than force.','Global streaming platforms are tools of cultural {soft power}.','글로벌 스트리밍 플랫폼은 문화적 소프트 파워의 도구예요.','soft power','C1','media',1,'soft power culture Netflix streaming global influence'),
('w_media_C1_19','attention economy','/əˈtenʃən ɪˈkɒnəmi/','noun','관심 경제','An economic model based on capturing and monetizing users'' attention.','Platforms compete fiercely in the {attention economy}.','플랫폼들은 관심 경제에서 치열하게 경쟁해요.','attention economy','C1','media',1,'attention economy screen time engagement addictive design'),
('w_media_C1_20','digital colonialism','/ˈdɪdʒɪtəl kəˈloʊniəlɪzəm/','noun','디지털 식민주의','The dominance of Western tech companies over global digital infrastructure.','Critics warn of {digital colonialism} by Silicon Valley giants.','비평가들은 실리콘 밸리 거대 기업들의 디지털 식민주의를 경고해요.','digital colonialism','C1','media',1,'digital colonialism silicon valley global tech power'),
('w_media_C1_21','counter-narrative','/ˈkaʊntər ˌnærətɪv/','noun','대항 서사','A competing story that challenges the dominant media narrative.','Activists use social media to spread {counter-narratives}.','활동가들은 소셜 미디어를 이용해 대항 서사를 퍼뜨려요.','counter-narratives','C1','media',2,'counter narrative activism social media alternative story'),
('w_media_C1_22','media pluralism','/ˈmiːdiə ˈplʊərəlɪzəm/','noun','미디어 다원주의','A diversity of independent media outlets presenting different viewpoints.','True democracy requires {media pluralism}.','진정한 민주주의는 미디어 다원주의를 필요로 해요.','media pluralism','C1','media',2,'media pluralism diversity news outlets viewpoints democracy'),
('w_media_C1_23','techno-optimism','/ˈteknəʊ ˈɒptɪmɪzəm/','noun','기술 낙관주의','The belief that technology will solve social and media problems.','Critics argue that {techno-optimism} ignores structural harms.','비평가들은 기술 낙관주의가 구조적 해악을 외면한다고 주장해요.','techno-optimism','C1','media',2,'techno optimism silicon valley future technology belief'),
('w_media_C1_24','news deserts','/njuːz ˈdezərts/','noun','뉴스 사막','Areas with little or no local journalism coverage.','Hundreds of US counties have become {news deserts}.','미국 수백 개 군이 뉴스 사막이 됐어요.','news deserts','C1','media',2,'news deserts local journalism decline community newspaper'),
('w_media_C1_25','moral panic','/ˈmɒrəl ˈpænɪk/','noun','도덕적 공황','An exaggerated social reaction to a perceived threat driven by media coverage.','Each new social media platform causes a {moral panic}.','새로운 소셜 미디어 플랫폼이 나올 때마다 도덕적 공황이 생겨요.','moral panic','C1','media',2,'moral panic social media technology fear parents media'),
('w_media_C1_26','co-creation','/ˌkoʊ kriˈeɪʃən/','noun','공동 창작','The joint production of content by creators and their audiences.','Fan fiction is a form of {co-creation} with media properties.','팬픽션은 미디어 자산과의 공동 창작 형태예요.','co-creation','C1','media',2,'co-creation fan fiction collaboration community content'),
('w_media_C1_27','cross-platform strategy','/krɒs ˈplætfɔːrm ˈstrætədʒi/','noun','크로스 플랫폼 전략','A content plan that distributes material across multiple channels.','A successful {cross-platform strategy} maximizes audience reach.','성공적인 크로스 플랫폼 전략은 청중 도달 범위를 극대화해요.','cross-platform strategy','C1','media',2,'cross platform strategy social media distribution channels'),
('w_media_C1_28','mediatization','/ˌmiːdiətaɪˈzeɪʃən/','noun','미디어화','The process by which society is increasingly shaped by media logic.','Politics has undergone profound {mediatization} since the 1990s.','정치는 1990년대 이후 깊은 미디어화를 겪어왔어요.','mediatization','C1','media',2,'mediatization politics society media logic television'),
('w_media_C1_29','networked journalism','/ˈnetwɜːrkt ˈdʒɜːrnəlɪzəm/','noun','네트워크 저널리즘','Journalism that involves collaboration between professionals and citizens online.','{Networked journalism} blurs the line between reporter and public.','네트워크 저널리즘은 기자와 대중 사이의 경계를 흐려요.','networked journalism','C1','media',2,'networked journalism citizen reporter online collaboration'),
('w_media_C1_30','digital public sphere','/ˈdɪdʒɪtəl ˌpʌblɪk sfɪər/','noun','디지털 공론장','An online space where citizens debate and form public opinion.','Twitter once promised to be a {digital public sphere}.','트위터는 한때 디지털 공론장이 될 것을 약속했어요.','digital public sphere','C1','media',1,'digital public sphere twitter debate democratic opinion'),
('w_media_C1_31','surveillance capitalism','/sərˈveɪləns ˈkæpɪtəlɪzəm/','noun','감시 자본주의','An economic system built on collecting and selling personal data.','Shoshana Zuboff coined the term {surveillance capitalism}.','쇼샤나 주보프는 감시 자본주의라는 용어를 만들었어요.','surveillance capitalism','C1','media',1,'surveillance capitalism data harvesting Zuboff platform'),
('w_media_C1_32','weaponized information','/ˈwepənaɪzd ɪnfərˈmeɪʃən/','noun','무기화된 정보','Information deliberately distorted to destabilize societies.','Democracies struggle to defend against {weaponized information}.','민주주의는 무기화된 정보에 맞서 싸우고 있어요.','weaponized information','C1','media',1,'weaponized information democracy defense disinformation'),
('w_media_C1_33','credibility cues','/ˌkredɪˈbɪlɪti kjuːz/','noun','신뢰성 단서','Visual or contextual signals that indicate whether information is trustworthy.','Readers use {credibility cues} to judge news reliability.','독자들은 신뢰성 단서를 이용해 뉴스 신뢰도를 판단해요.','credibility cues','C1','media',2,'credibility cues news source trust signal evaluation'),
('w_media_C1_34','transparency reporting','/trænsˈpærənsi rɪˈpɔːrtɪŋ/','noun','투명성 보고','Public disclosure by platforms about their moderation and ad policies.','Regulators now require quarterly {transparency reporting}.','규제당국은 이제 분기별 투명성 보고를 요구해요.','transparency reporting','C1','media',2,'transparency reporting regulation platform accountability'),
('w_media_C1_35','editorial independence','/ˌedɪˈtɔːriəl ˌɪndɪˈpendəns/','noun','편집권 독립','The freedom of journalists to report without interference from owners or advertisers.','Public broadcasters must protect {editorial independence}.','공영 방송은 편집권 독립을 지켜야 해요.','editorial independence','C1','media',1,'editorial independence journalism freedom owner advertiser');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_media_C2_01','semiotics','/ˌsiːmiˈɒtɪks/','noun','기호학','The study of signs, symbols, and their meaning in communication.','Applying {semiotics} to advertising reveals hidden messages.','광고에 기호학을 적용하면 숨겨진 메시지가 드러나요.','semiotics','C2','media',1,'semiotics signs symbols advertising hidden meaning'),
('w_media_C2_02','commodification','/kəˌmɒdɪfɪˈkeɪʃən/','noun','상품화','The process of turning something non-commercial into a market commodity.','The {commodification} of personal data is a defining feature of the internet age.','개인 데이터의 상품화는 인터넷 시대의 결정적 특징이에요.','commodification','C2','media',1,'commodification data personal information market internet'),
('w_media_C2_03','hyperreality','/ˌhaɪpərriˈæləti/','noun','초현실','A condition where the distinction between reality and simulation collapses.','Baudrillard argued that media creates a state of {hyperreality}.','보드리야르는 미디어가 초현실 상태를 만들어낸다고 주장했어요.','hyperreality','C2','media',1,'hyperreality Baudrillard simulation reality media philosophy'),
('w_media_C2_04','simulacrum','/ˌsɪmjʊˈlɑːkrəm/','noun','시뮬라크르','A copy or representation that has no original, replacing reality itself.','Social media presents a {simulacrum} of authentic social life.','소셜 미디어는 진정한 사회생활의 시뮬라크르를 제시해요.','simulacrum','C2','media',1,'simulacrum copy representation social media fake authentic'),
('w_media_C2_05','technocracy','/tekˈnɒkrəsi/','noun','기술 관료제','A system of governance where technology experts hold power.','Silicon Valley''s rise reflects a new digital {technocracy}.','실리콘 밸리의 부상은 새로운 디지털 기술 관료제를 반영해요.','technocracy','C2','media',1,'technocracy silicon valley power governance engineers'),
('w_media_C2_06','post-truth','/poʊst truːθ/','adjective','탈진실의','Relating to circumstances where emotion and belief override objective facts.','We live in a {post-truth} media environment.','우리는 탈진실 미디어 환경 속에 살고 있어요.','post-truth','C2','media',1,'post-truth media era emotion facts belief politics'),
('w_media_C2_07','infosphere','/ˈɪnfoʊsfɪər/','noun','인포스피어','The global environment of information and communication systems.','Luciano Floridi conceptualizes the {infosphere} as our new habitat.','루치아노 플로리디는 인포스피어를 우리의 새로운 서식지로 개념화해요.','infosphere','C2','media',1,'infosphere information environment global digital Floridi'),
('w_media_C2_08','algorithmic governance','/ˌælɡərɪðmɪk ˈɡʌvərnəns/','noun','알고리즘 통치','The use of automated systems to make decisions with public consequences.','Critics argue that {algorithmic governance} lacks democratic accountability.','비평가들은 알고리즘 통치가 민주적 책임을 결여한다고 주장해요.','algorithmic governance','C2','media',1,'algorithmic governance automation policy accountability'),
('w_media_C2_09','deepfake epistemics','/ˈdiːpfeɪk ˌepɪˈstemɪks/','noun','딥페이크 인식론','The study of how synthetic media affects our ability to trust what we perceive.','Scholars of {deepfake epistemics} question the evidentiary value of video.','딥페이크 인식론 학자들은 영상의 증거적 가치에 의문을 제기해요.','deepfake epistemics','C2','media',1,'deepfake truth evidence epistemics philosophy media'),
('w_media_C2_10','Habermasian','/ˌhɑːbərˈmɑːziən/','adjective','하버마스적','Relating to the ideas of Jürgen Habermas, especially the public sphere.','A {Habermasian} analysis reveals how platforms distort rational discourse.','하버마스적 분석은 플랫폼이 어떻게 합리적 담론을 왜곡하는지 드러내요.','Habermasian','C2','media',1,'Habermas public sphere rational discourse philosophy'),
('w_media_C2_11','ontological security','/ˌɒntəˈlɒdʒɪkəl sɪˈkjʊərɪti/','noun','존재론적 안정성','The sense of order and continuity in one''s world, which media can disrupt.','Constant news overload threatens individuals'' {ontological security}.','끊임없는 뉴스 과부하는 개인의 존재론적 안정성을 위협해요.','ontological security','C2','media',1,'ontological security media anxiety information overload'),
('w_media_C2_12','discursive formation','/dɪˈskɜːrsɪv fɔːˈmeɪʃən/','noun','담론 형성체','A group of statements that systematically form the objects they describe (Foucault).','The coverage constitutes a {discursive formation} around criminality.','그 보도는 범죄성에 관한 담론 형성체를 구성해요.','discursive formation','C2','media',1,'discursive formation Foucault media discourse analysis'),
('w_media_C2_13','ideological state apparatus','/ˌaɪdiəˈlɒdʒɪkəl steɪt ˈæpərətəs/','noun','이데올로기적 국가 기구','Althusser''s concept of institutions (including media) that reproduce ruling ideology.','Mass media functions as an {ideological state apparatus}.','대중 매체는 이데올로기적 국가 기구로 기능해요.','ideological state apparatus','C2','media',1,'Althusser ideology state apparatus media television'),
('w_media_C2_14','mediatized politics','/ˈmiːdiətaɪzd ˈpɒlɪtɪks/','noun','미디어화된 정치','The phenomenon of political life being fundamentally shaped by media formats.','Image management is central to {mediatized politics}.','이미지 관리는 미디어화된 정치의 핵심이에요.','mediatized politics','C2','media',1,'mediatized politics image management spin media campaign'),
('w_media_C2_15','networked individualism','/ˈnetwɜːrkt ˌɪndɪˈvɪdʒuəlɪzəm/','noun','네트워크화된 개인주의','A social pattern where people maintain connections through personal networks rather than groups.','Castells described {networked individualism} as the new social operating system.','카스텔스는 네트워크화된 개인주의를 새로운 사회 운영 체계라고 설명했어요.','networked individualism','C2','media',1,'networked individualism Castells social network personal'),
('w_media_C2_16','attention fragmentation','/əˈtenʃən ˌfræɡmenˈteɪʃən/','noun','주의 분산','The breaking up of audience attention across many competing media channels.','{Attention fragmentation} has made mass broadcasting obsolete.','주의 분산은 대규모 방송을 구식으로 만들었어요.','attention fragmentation','C2','media',1,'attention fragmentation multiple screens media distracted'),
('w_media_C2_17','parasocial relationship','/ˌpærəˈsoʊʃəl rɪˈleɪʃənʃɪp/','noun','의사 사회적 관계','A one-sided emotional bond viewers form with media figures.','Audiences form deep {parasocial relationships} with podcasters.','청중은 팟캐스터와 깊은 의사 사회적 관계를 형성해요.','parasocial relationships','C2','media',1,'parasocial relationship youtube podcaster fan bond'),
('w_media_C2_18','technodeterminism','/ˌteknəʊdɪˈtɜːrmɪnɪzəm/','noun','기술 결정론','The belief that technology autonomously drives social and cultural change.','McLuhan''s "the medium is the message" exemplifies {technodeterminism}.','맥루한의 "미디어가 메시지다"는 기술 결정론의 예시예요.','technodeterminism','C2','media',1,'technodeterminism McLuhan medium message technology change'),
('w_media_C2_19','platform imperialism','/ˈplætfɔːrm ɪmˈpɪəriəlɪzəm/','noun','플랫폼 제국주의','The dominance of Western digital platforms over global information flows.','Scholars debate whether TikTok challenges {platform imperialism}.','학자들은 틱톡이 플랫폼 제국주의에 도전하는지 논쟁해요.','platform imperialism','C2','media',1,'platform imperialism TikTok Western digital global power'),
('w_media_C2_20','noise-to-signal ratio','/nɔɪz tə ˈsɪɡnəl ˈreɪʃioʊ/','noun','잡음 대 신호 비율','The proportion of irrelevant or low-quality content relative to valuable information.','The high {noise-to-signal ratio} online makes quality journalism vital.','온라인의 높은 잡음 대 신호 비율은 양질의 저널리즘을 필수로 만들어요.','noise-to-signal ratio','C2','media',1,'noise signal ratio information quality journalism online'),
('w_media_C2_21','second-order media effects','/ˈsekənd ˈɔːrdər ˈmiːdiə ɪˈfekts/','noun','2차 미디어 효과','Indirect social changes caused by media exposure beyond the intended message.','Long-term {second-order media effects} are difficult to measure.','장기적인 2차 미디어 효과는 측정하기 어려워요.','second-order media effects','C2','media',2,'second order effects media long term social change'),
('w_media_C2_22','performative contradiction','/pərˈfɔːrmətɪv ˌkɒntrəˈdɪkʃən/','noun','수행적 자기 모순','A statement that undermines the very norms it appeals to in order to be made.','A media company claiming to fight censorship while blocking content commits a {performative contradiction}.','검열과 싸운다고 주장하면서 콘텐츠를 차단하는 미디어 기업은 수행적 자기 모순을 범해요.','performative contradiction','C2','media',2,'performative contradiction hypocrisy media platform censorship'),
('w_media_C2_23','digital hermeneutics','/ˈdɪdʒɪtəl ˌhɜːrməˈnjuːtɪks/','noun','디지털 해석학','The interpretation of digital texts and media in cultural context.','Scholars of {digital hermeneutics} study how algorithms shape reading.','디지털 해석학 학자들은 알고리즘이 독서를 어떻게 형성하는지 연구해요.','digital hermeneutics','C2','media',2,'digital hermeneutics text meaning algorithm reading culture'),
('w_media_C2_24','epistemic crisis','/ˌepɪˈstiːmɪk ˈkraɪsɪs/','noun','인식론적 위기','A breakdown in shared standards for establishing truth or knowledge.','Widespread disinformation has produced an {epistemic crisis}.','광범위한 허위정보가 인식론적 위기를 초래했어요.','epistemic crisis','C2','media',1,'epistemic crisis truth knowledge breakdown disinformation'),
('w_media_C2_25','communicative capitalism','/kəˈmjuːnɪkətɪv ˈkæpɪtəlɪzəm/','noun','소통적 자본주의','The idea that digital communication has been absorbed into capitalist exchange.','Jodi Dean''s concept of {communicative capitalism} explains the addictive logic of social media.','조디 딘의 소통적 자본주의 개념은 소셜 미디어의 중독 논리를 설명해요.','communicative capitalism','C2','media',2,'communicative capitalism social media engagement addiction loop'),
('w_media_C2_26','ideological interpellation','/ˌaɪdiəˈlɒdʒɪkəl ˌɪntɜːrpəˈleɪʃən/','noun','이데올로기적 호명','Althusser''s concept of how media "hails" individuals into ideological subject positions.','Advertising functions through {ideological interpellation}.','광고는 이데올로기적 호명을 통해 작동해요.','ideological interpellation','C2','media',2,'interpellation Althusser ideology advertising subject media'),
('w_media_C2_27','cultural hegemony','/ˈkʌltʃərəl hɪˈɡeməni/','noun','문화적 헤게모니','Gramsci''s concept of how a dominant class maintains power through cultural institutions including media.','Television historically reinforced {cultural hegemony}.','텔레비전은 역사적으로 문화적 헤게모니를 강화해왔어요.','cultural hegemony','C2','media',1,'cultural hegemony Gramsci media television dominant ideology'),
('w_media_C2_28','media ecology','/ˈmiːdiə ɪˈkɒlədʒi/','noun','미디어 생태학','The study of media environments and how they affect human perception and society.','{Media ecology} examines how screens reshape attention spans.','미디어 생태학은 화면이 어떻게 주의력 범위를 재형성하는지 검토해요.','media ecology','C2','media',2,'media ecology environment screen attention McLuhan society'),
('w_media_C2_29','semiotic democracy','/ˌsiːmiˈɒtɪk dɪˈmɒkrəsi/','noun','기호학적 민주주의','The idea that audiences actively reinterpret media texts for their own purposes.','Fan communities enact a kind of {semiotic democracy}.','팬 커뮤니티는 일종의 기호학적 민주주의를 실천해요.','semiotic democracy','C2','media',2,'semiotic democracy fan interpretation media text audience'),
('w_media_C2_30','hyper-personalization','/ˌhaɪpər ˌpɜːrsənəlaɪˈzeɪʃən/','noun','초개인화','Extreme tailoring of media content to individual users via data analysis.','The danger of {hyper-personalization} is the collapse of shared reality.','초개인화의 위험은 공유된 현실의 붕괴예요.','hyper-personalization','C2','media',1,'hyper personalization algorithm individual reality collapse'),
('w_media_C2_31','digital sovereignty','/ˈdɪdʒɪtəl ˈsɒvrənti/','noun','디지털 주권','The right of states or individuals to control their own digital environments.','European regulation is driven by a vision of {digital sovereignty}.','유럽의 규제는 디지털 주권 비전에 의해 추진되고 있어요.','digital sovereignty','C2','media',1,'digital sovereignty Europe regulation data control GDPR'),
('w_media_C2_32','technological solutionism','/ˌteknəˈlɒdʒɪkəl ˈsoʊluːʃənɪzəm/','noun','기술 만능주의','The belief that every social problem can be solved with a technological fix.','Morozov criticized Silicon Valley''s {technological solutionism}.','모로조프는 실리콘 밸리의 기술 만능주의를 비판했어요.','technological solutionism','C2','media',2,'technological solutionism Morozov Silicon Valley fix problem'),
('w_media_C2_33','critical data studies','/ˈkrɪtɪkəl ˈdeɪtə ˈstʌdiz/','noun','비판적 데이터 연구','An academic field examining the political and ethical dimensions of data collection.','Scholars in {critical data studies} interrogate platform surveillance.','비판적 데이터 연구 학자들은 플랫폼 감시를 문제 삼아요.','critical data studies','C2','media',2,'critical data studies surveillance platform ethics academic'),
('w_media_C2_34','post-digital','/poʊst ˈdɪdʒɪtəl/','adjective','포스트디지털의','Relating to a culture where digital technology is so pervasive it is no longer remarkable.','We live in a {post-digital} media landscape.','우리는 포스트디지털 미디어 환경 속에 살고 있어요.','post-digital','C2','media',2,'post-digital ubiquitous technology pervasive media culture'),
('w_media_C2_35','legitimation crisis','/ˌledʒɪtɪˈmeɪʃən ˈkraɪsɪs/','noun','정당성 위기','A breakdown of trust in social institutions, accelerated by media exposure.','Social media has triggered a {legitimation crisis} for mainstream journalism.','소셜 미디어가 주류 저널리즘의 정당성 위기를 촉발했어요.','legitimation crisis','C2','media',1,'legitimation crisis journalism trust mainstream media decline');
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_media_A1_01','Did you see that video?','그 영상 봤어요?','Did you see','과거에 이미 일어난 일을 물을 때는 Did you see...?를 써요. Have you seen...?보다 더 캐주얼해요.','영상 공유','A1','media','pattern',NULL,1),
('s_media_A1_02','You should watch this — it''s really funny.','이거 봐요. 정말 웃겨요.','You should watch','상대방에게 뭔가를 추천할 때 You should + 동사가 가장 간단하고 자연스러운 표현이에요.','콘텐츠 추천','A1','media','pattern',NULL,2),
('s_media_A1_03','I''ll send you the link right now.','지금 링크 보내 줄게요.','I''ll send you','즉각적인 행동을 약속할 때는 I''ll + 동사를 써요. 대화할 때 자주 쓰이는 패턴이에요.','링크 공유','A1','media','pattern',NULL,3),
('s_media_A1_04','What are you watching?','뭐 보고 있어요?','What are you watching','상대방이 지금 하고 있는 행동을 물을 때는 What are you + -ing?를 써요.','일상 대화','A1','media','pattern',NULL,4),
('s_media_A1_05','Have you heard the news today?','오늘 뉴스 들었어요?','Have you heard','최근 소식을 아는지 확인할 때는 Have you heard...?를 써요.','뉴스 확인','A1','media','pattern',NULL,5),
('s_media_A1_06','This photo is amazing — where did you take it?','이 사진 정말 대단해요. 어디서 찍었어요?','where did you take it','사진을 칭찬하며 장소를 물을 때 자연스러운 표현이에요. where did you + 동사 패턴이에요.','사진 감상','A1','media','pattern',NULL,6),
('s_media_A1_07','I listen to music on my phone every day.','저는 매일 휴대폰으로 음악을 들어요.','listen to music on my phone','습관을 말할 때는 현재 시제를 써요. on my phone은 기기를 나타낼 때 유용한 표현이에요.','음악 습관','A1','media','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_media_A2_01','I just posted a photo — go check it out!','방금 사진 올렸어요. 가서 확인해 봐요!','go check it out','I just + 과거형은 방금 한 행동을 알릴 때 써요. go check it out은 친근하게 행동을 유도하는 표현이에요.','SNS 게시','A2','media','pattern',NULL,1),
('s_media_A2_02','Don''t forget to like and subscribe!','좋아요 누르고 구독도 잊지 마세요!','Don''t forget to','Don''t forget to + 동사는 무언가를 상기시킬 때 써요. 유튜브 영상에서 자주 들을 수 있어요.','채널 홍보','A2','media','pattern',NULL,2),
('s_media_A2_03','I''ve been following her for years — her content is great.','몇 년째 팔로우하고 있어요. 콘텐츠가 정말 좋아요.','I''ve been following','I''ve been + -ing는 과거부터 현재까지 계속된 행동을 나타내요.','팔로우 추천','A2','media','pattern',NULL,3),
('s_media_A2_04','Have you seen what''s trending today?','오늘 트렌딩에 뭐 있는지 봤어요?','Have you seen what''s trending','최근 유행 중인 것을 묻는 표현이에요. trending은 SNS에서 핵심 키워드예요.','트렌딩 화제','A2','media','pattern',NULL,4),
('s_media_A2_05','She uploaded a new video — it already has a million views.','그녀가 새 영상을 올렸어요. 벌써 조회수가 백만이에요.','already has a million views','already는 예상보다 일찍 일어난 일에 대한 놀라움을 강조해요.','조회수 화제','A2','media','pattern',NULL,5),
('s_media_A2_06','You can find me on Instagram at @username.','인스타그램에서 @username으로 찾을 수 있어요.','You can find me on','SNS 계정을 알려줄 때 You can find me on + 플랫폼 at + @계정명 패턴을 써요.','계정 소개','A2','media','pattern',NULL,6),
('s_media_A2_07','I''ve been spending too much time scrolling lately.','요즘 스크롤하면서 시간을 너무 많이 보내고 있어요.','spending too much time scrolling','I''ve been + -ing는 최근의 습관이나 상태를 반성할 때 유용해요.','SNS 과다 사용','A2','media','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_media_B1_01','The algorithm keeps recommending the same type of content.','알고리즘이 계속 같은 유형의 콘텐츠를 추천해요.','keeps recommending','keep + -ing는 어떤 행동이 반복되거나 계속됨을 나타내요. 알고리즘을 주어로 쓰는 것이 자연스러워요.','알고리즘 불만','B1','media','pattern',NULL,1),
('s_media_B1_02','I''ve been trying to grow my channel for about six months now.','채널을 키우려고 약 6개월째 노력 중이에요.','I''ve been trying to grow','I''ve been trying to + 동사는 어느 시점부터 계속 노력 중임을 표현해요. for about은 대략적인 기간에 써요.','채널 운영','B1','media','pattern',NULL,2),
('s_media_B1_03','If you want more reach, you need to post consistently.','도달 범위를 늘리려면 꾸준히 게시해야 해요.','If you want ... you need to','조건절 if를 이용해 실용적인 조언을 전달할 때 쓰는 패턴이에요.','SNS 성장 조언','B1','media','pattern',NULL,3),
('s_media_B1_04','The engagement rate tells you whether the content is working.','참여율이 콘텐츠가 효과적인지 알려줘요.','tells you whether','whether는 두 가지 가능성이 있을 때 써요. tell you whether는 분석을 설명할 때 유용해요.','콘텐츠 분석','B1','media','pattern',NULL,4),
('s_media_B1_05','I''m thinking of starting a podcast — what do you think?','팟캐스트를 시작할까 생각 중이에요. 어떻게 생각해요?','I''m thinking of starting','I''m thinking of + -ing는 아직 결정하지 않은 계획을 조심스럽게 꺼낼 때 써요.','미디어 창작 계획','B1','media','pattern',NULL,5),
('s_media_B1_06','Did you see that video went viral overnight?','그 영상이 하룻밤 사이에 바이럴된 거 봤어요?','went viral overnight','go viral은 콘텐츠가 폭발적으로 퍼지는 것을 뜻해요. overnight은 매우 빠른 확산을 강조해요.','바이럴 화제','B1','media','pattern',NULL,6),
('s_media_B1_07','I always check the analytics before deciding what to post next.','다음에 뭘 올릴지 결정하기 전에 항상 분석 데이터를 확인해요.','before deciding what to post','before + -ing는 어떤 행동을 하기 전의 습관을 나타내요. 콘텐츠 전략 설명에 유용해요.','콘텐츠 전략','B1','media','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_media_B2_01','The headline is clearly designed to be clickbait.','그 제목은 명백히 낚시성으로 설계된 거예요.','clearly designed to be','is designed to + 동사는 의도된 목적을 비판할 때 효과적인 표현이에요. clearly가 확신의 강도를 높여요.','미디어 비판','B2','media','pattern',NULL,1),
('s_media_B2_02','I''m concerned about how misinformation spreads so quickly on social media.','소셜 미디어에서 잘못된 정보가 이렇게 빨리 퍼지는 게 걱정돼요.','I''m concerned about how','I''m concerned about how + 절은 사회적 문제에 대한 우려를 표명할 때 격식적이고 자연스러운 패턴이에요.','미디어 우려','B2','media','pattern',NULL,2),
('s_media_B2_03','You need to fact-check before you share anything online.','온라인에서 무언가를 공유하기 전에 팩트체크를 해야 해요.','fact-check before you share','You need to + 동사는 강한 필요성을 나타내요. before you + 동사는 순서를 강조해요.','팩트체크 조언','B2','media','pattern',NULL,3),
('s_media_B2_04','The way the story was framed really influenced how I felt about it.','그 이야기가 프레이밍된 방식이 제 감정에 정말 큰 영향을 줬어요.','The way ... was framed','The way + 절은 어떤 사건이 제시된 방식을 분석할 때 쓰는 고급 패턴이에요.','미디어 프레이밍','B2','media','pattern',NULL,4),
('s_media_B2_05','It''s hard to tell whether a source is reliable these days.','요즘에는 출처가 신뢰할 수 있는지 판단하기 어려워요.','It''s hard to tell whether','It''s hard to + 동사 패턴은 어려움을 공유할 때 써요. whether는 두 가능성 사이의 불확실성을 나타내요.','정보 신뢰성','B2','media','pattern',NULL,5),
('s_media_B2_06','Social media algorithms tend to reinforce our existing beliefs.','소셜 미디어 알고리즘은 우리의 기존 믿음을 강화하는 경향이 있어요.','tend to reinforce','tend to + 동사는 일반적인 경향이나 패턴을 말할 때 써요. 분석적인 주장을 부드럽게 만들어줘요.','에코 챔버 논의','B2','media','pattern',NULL,6),
('s_media_B2_07','What concerns me most is the lack of transparency in how these platforms operate.','가장 걱정되는 건 이 플랫폼들이 운영되는 방식의 투명성 부재예요.','What concerns me most is','What concerns me most is + 절은 자신의 핵심 우려를 강조하며 시작하는 고급 문어체 패턴이에요.','플랫폼 비판','B2','media','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_media_C1_01','The media''s agenda-setting power shapes which issues we consider worth discussing.','미디어의 의제 설정 능력은 우리가 논의할 가치가 있다고 여기는 사안을 형성해요.','agenda-setting power shapes','agenda-setting power는 미디어 이론의 핵심 개념이에요. shapes + 절은 인과 관계를 설명해요.','미디어 권력 분석','C1','media','pattern',NULL,1),
('s_media_C1_02','The proliferation of social media has fundamentally disrupted traditional gatekeeping.','소셜 미디어의 확산은 전통적인 게이트키핑을 근본적으로 혼란에 빠뜨렸어요.','fundamentally disrupted','fundamentally + 과거분사는 심층적인 구조 변화를 강조해요. disrupted는 혁신 담론에서 핵심 동사예요.','미디어 구조 변화','C1','media','pattern',NULL,2),
('s_media_C1_03','One could argue that the attention economy is designed to undermine our cognitive autonomy.','관심 경제는 우리의 인지적 자율성을 약화시키도록 설계되어 있다고 주장할 수 있어요.','One could argue that','One could argue that...은 논쟁의 여지 있는 주장을 조심스럽게 제시할 때 쓰는 학술적 패턴이에요.','관심 경제 비판','C1','media','pattern',NULL,3),
('s_media_C1_04','What''s particularly troubling is the way disinformation campaigns exploit our confirmation bias.','특히 걱정스러운 것은 허위정보 캠페인이 우리의 확증 편향을 악용하는 방식이에요.','What''s particularly troubling is','What''s + 형용사 + is는 핵심 문제를 강조하는 C1 수준 강조 구문이에요.','허위정보 분석','C1','media','pattern',NULL,4),
('s_media_C1_05','Platform governance needs to balance free expression with accountability.','플랫폼 거버넌스는 표현의 자유와 책임 사이의 균형을 잡아야 해요.','needs to balance ... with','need to balance A with B는 두 가지 상충하는 가치를 논의할 때 쓰는 고급 표현이에요.','플랫폼 정책 논의','C1','media','pattern',NULL,5),
('s_media_C1_06','The erosion of editorial independence poses a long-term threat to democratic discourse.','편집권 독립의 침식은 민주적 담론에 장기적인 위협이 돼요.','poses a long-term threat to','pose a threat to는 위험을 공식적으로 서술할 때 써요. erosion은 점진적 약화를 나타내는 핵심 명사예요.','언론 자유 논의','C1','media','pattern',NULL,6),
('s_media_C1_07','Unless we develop robust media literacy education, we will remain vulnerable to manipulation.','탄탄한 미디어 리터러시 교육을 개발하지 않으면 조작에 취약한 상태가 지속돼요.','Unless we develop ... we will remain','Unless + 현재형은 조건의 부재를 강조해요. remain vulnerable to는 위험 상태의 지속성을 표현해요.','미디어 교육 필요성','C1','media','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_media_C2_01','Baudrillard''s concept of hyperreality suggests that media no longer represents reality but has replaced it.','보드리야르의 초현실 개념은 미디어가 더 이상 현실을 재현하지 않고 현실 자체를 대체했음을 시사해요.','no longer represents ... but has replaced','no longer A but has B 구조는 근본적인 전환을 표현하는 학술적 패턴이에요.','미디어 철학 논의','C2','media','pattern',NULL,1),
('s_media_C2_02','From a Habermasian perspective, algorithmic curation fundamentally distorts the conditions for rational public discourse.','하버마스적 관점에서 보면 알고리즘 큐레이션은 합리적 공론장 담론의 조건을 근본적으로 왜곡해요.','From a Habermasian perspective','From a [이론가/학파] perspective는 학술 토론에서 이론적 입장을 명확히 밝히는 패턴이에요.','미디어 이론 적용','C2','media','pattern',NULL,2),
('s_media_C2_03','The commodification of attention is arguably the defining logic of twenty-first-century media capitalism.','관심의 상품화는 21세기 미디어 자본주의의 결정적 논리라고 볼 수 있어요.','The commodification of ... is arguably the defining logic','is arguably the defining logic of는 핵심 특성을 주장하는 강력한 학술적 술어예요.','미디어 경제 비판','C2','media','pattern',NULL,3),
('s_media_C2_04','One cannot disentangle the question of media power from broader structures of political and economic hegemony.','미디어 권력의 문제는 정치·경제적 헤게모니의 광범위한 구조에서 분리할 수 없어요.','One cannot disentangle ... from','One cannot disentangle A from B는 두 개념이 불가분의 관계임을 주장하는 학술적 패턴이에요.','구조적 분석','C2','media','pattern',NULL,4),
('s_media_C2_05','The epistemological implications of deepfake technology call into question the evidentiary status of audiovisual media.','딥페이크 기술의 인식론적 함의는 시청각 미디어의 증거적 지위에 의문을 제기해요.','call into question the ... status of','call into question은 근본 전제에 이의를 제기할 때 쓰는 학술 필수 표현이에요.','딥페이크 철학','C2','media','pattern',NULL,5),
('s_media_C2_06','Semiotics reveals how media texts encode ideological assumptions that audiences may naturalise without critical reflection.','기호학은 미디어 텍스트가 비판적 성찰 없이 수용자가 자연스럽게 받아들일 수 있는 이데올로기적 가정을 어떻게 코드화하는지 드러내요.','encode ideological assumptions that audiences may naturalise','encode + 목적어 + that절은 숨겨진 의미 구조를 분석하는 기호학적 패턴이에요.','기호학적 분석','C2','media','pattern',NULL,6),
('s_media_C2_07','To the extent that platforms function as ideological state apparatuses, regulating them is not merely a technical but a deeply political project.','플랫폼이 이데올로기적 국가 기구로 기능하는 한, 플랫폼 규제는 단순히 기술적인 것이 아니라 깊이 정치적인 프로젝트예요.','To the extent that ... not merely ... but','To the extent that는 조건의 범위를 한정하는 C2 수준 패턴이에요. not merely A but B는 더 깊은 차원을 강조해요.','플랫폼 규제 논쟁','C2','media','pattern',NULL,7);
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_economy_A1_01','money','/ˈmʌni/','noun','돈','Coins or notes used to pay for things.','Do you have {money} with you?','돈 가지고 있어요?','money','A1','economy',1,'money coins bills wallet cash'),
('w_economy_A1_02','price','/praɪs/','noun','가격','The amount of money required to buy something.','What is the {price} of this jacket?','이 재킷의 가격이 얼마예요?','price','A1','economy',1,'price tag shopping retail store'),
('w_economy_A1_03','buy','/baɪ/','verb','사다','To get something by paying money for it.','I want to {buy} a new phone.','새 휴대폰을 사고 싶어요.','buy','A1','economy',1,'shopping buying store purchase'),
('w_economy_A1_04','sell','/sel/','verb','팔다','To exchange something for money.','They {sell} fresh vegetables here.','여기서 신선한 채소를 팔아요.','sell','A1','economy',1,'market selling vendor stall produce'),
('w_economy_A1_05','pay','/peɪ/','verb','지불하다','To give money in exchange for goods or services.','Can I {pay} by credit card?','신용카드로 계산할 수 있나요?','pay','A1','economy',1,'payment cashier counter card terminal'),
('w_economy_A1_06','cheap','/tʃiːp/','adjective','저렴한','Low in price; not expensive.','This market has very {cheap} fruit.','이 시장에는 아주 저렴한 과일이 있어요.','cheap','A1','economy',1,'cheap market bargain low price sale'),
('w_economy_A1_07','save','/seɪv/','verb','저축하다','To keep money instead of spending it.','I try to {save} a little each month.','매달 조금씩 저축하려고 해요.','save','A1','economy',1,'piggy bank saving money jar coins'),
('w_economy_A1_08','bank','/bæŋk/','noun','은행','A place where people keep and borrow money.','I need to go to the {bank} today.','오늘 은행에 가야 해요.','bank','A1','economy',1,'bank building finance ATM entrance'),
('w_economy_A1_09','cost','/kɒst/','verb','(비용이) 들다','To have a particular price.','How much does it {cost}?','얼마예요?','cost','A1','economy',1,'price label receipt shopping cost'),
('w_economy_A1_10','spend','/spend/','verb','쓰다','To use money to pay for something.','I don''t want to {spend} too much today.','오늘 너무 많이 쓰고 싶지 않아요.','spend','A1','economy',1,'spending wallet shopping budget'),
('w_economy_A1_11','cash','/kæʃ/','noun','현금','Money in the form of coins or banknotes.','Do you accept {cash} or only cards?','현금도 받나요, 아니면 카드만 되나요?','cash','A1','economy',1,'cash banknotes currency hand payment'),
('w_economy_A1_12','free','/friː/','adjective','무료의','Costing nothing.','Is the Wi-Fi {free} here?','여기 와이파이 무료예요?','free','A1','economy',2,'free sign promotion offer gift'),
('w_economy_A1_13','change','/tʃeɪndʒ/','noun','거스름돈','Money returned when you pay more than the cost.','Here is your {change}.','거스름돈 받으세요.','change','A1','economy',2,'coins change receipt cashier counter'),
('w_economy_A1_14','shop','/ʃɒp/','noun','가게','A place where goods are sold.','There is a nice little {shop} nearby.','근처에 아담한 가게가 있어요.','shop','A1','economy',2,'small shop storefront retail street'),
('w_economy_A1_15','bill','/bɪl/','noun','지폐; 청구서','A piece of paper money; or a request for payment.','Could I have the {bill}, please?','계산서 주세요.','bill','A1','economy',1,'restaurant bill receipt paper payment'),
('w_economy_A1_16','coin','/kɔɪn/','noun','동전','A small metal disc used as money.','I only have {coins} in my pocket.','주머니에 동전밖에 없어요.','coin','A1','economy',2,'coins pocket change metal currency'),
('w_economy_A1_17','wallet','/ˈwɒlɪt/','noun','지갑','A small flat case for carrying money and cards.','I left my {wallet} at home.','지갑을 집에 두고 왔어요.','wallet','A1','economy',2,'wallet leather cards money pocket'),
('w_economy_A1_18','receipt','/rɪˈsiːt/','noun','영수증','A piece of paper confirming payment.','Can I have a {receipt}?','영수증 받을 수 있나요?','receipt','A1','economy',2,'receipt paper store cashier transaction'),
('w_economy_A1_19','market','/ˈmɑːrkɪt/','noun','시장','A place where goods are bought and sold.','The {market} opens at seven.','시장은 7시에 열어요.','market','A1','economy',1,'outdoor market fresh produce stalls people'),
('w_economy_A1_20','expensive','/ɪkˈspensɪv/','adjective','비싼','Costing a lot of money.','This restaurant is too {expensive} for me.','이 식당은 저한테 너무 비싸요.','expensive','A1','economy',1,'luxury expensive store high price display'),
('w_economy_A1_21','discount','/ˈdɪskaʊnt/','noun','할인','A reduction in the usual price.','Is there a student {discount}?','학생 할인이 있나요?','discount','A1','economy',2,'sale discount tag sign store retail'),
('w_economy_A1_22','sale','/seɪl/','noun','세일','A period when goods are sold at reduced prices.','Everything is on {sale} this weekend.','이번 주말에 모든 상품이 세일이에요.','sale','A1','economy',2,'sale sign shop window retail bargain'),
('w_economy_A1_23','afford','/əˈfɔːrd/','verb','(돈이 있어) ~할 수 있다','To have enough money to pay for something.','I can''t {afford} a new car right now.','지금은 새 차를 살 여유가 없어요.','afford','A1','economy',2,'thinking budget person worried finance'),
('w_economy_A1_24','total','/ˈtoʊtl/','noun','합계','The complete sum of an amount.','The {total} comes to thirty dollars.','합계가 30달러예요.','total','A1','economy',2,'receipt total checkout shopping payment'),
('w_economy_A1_25','fee','/fiː/','noun','수수료; 요금','A charge for a service.','There is an entry {fee} of five dollars.','5달러의 입장료가 있어요.','fee','A1','economy',2,'fee sign entrance payment ticket'),
('w_economy_A1_26','gift','/ɡɪft/','noun','선물','Something given without payment.','I bought a {gift} for my friend.','친구에게 선물을 샀어요.','gift','A1','economy',3,'gift wrap present box ribbon shopping'),
('w_economy_A1_27','order','/ˈɔːrdər/','verb','주문하다','To request something to be made or supplied.','I''d like to {order} the blue one.','파란 것으로 주문하고 싶어요.','order','A1','economy',2,'online order shopping delivery package'),
('w_economy_A1_28','price tag','/praɪs tæɡ/','noun','가격표','A label attached to an item showing its price.','Let me check the {price tag}.','가격표를 확인해 볼게요.','price tag','A1','economy',3,'price tag retail clothing store label'),
('w_economy_A1_29','ATM','/ˌeɪ tiː ˈem/','noun','자동화기기 (현금인출기)','A machine that dispenses cash from a bank account.','Is there an {ATM} nearby?','근처에 ATM이 있나요?','ATM','A1','economy',2,'ATM cash machine bank street'),
('w_economy_A1_30','borrow','/ˈbɒroʊ/','verb','빌리다','To take and use something that belongs to someone else.','Can I {borrow} some money until Friday?','금요일까지 돈 좀 빌릴 수 있을까요?','borrow','A1','economy',2,'borrowing lending hand money help'),
('w_economy_A1_31','lend','/lend/','verb','빌려주다','To give something to someone temporarily.','Could you {lend} me a few dollars?','몇 달러만 빌려줄 수 있어요?','lend','A1','economy',2,'lending hand giving money friend help'),
('w_economy_A1_32','exchange','/ɪkˈstʃeɪndʒ/','noun','환전; 교환','Converting one currency to another; or swapping goods.','Where can I {exchange} my money?','어디서 환전할 수 있나요?','exchange','A1','economy',2,'currency exchange counter travel money'),
('w_economy_A1_33','rich','/rɪtʃ/','adjective','부유한','Having a lot of money.','She is very {rich} and owns many businesses.','그녀는 매우 부유하고 많은 사업체를 가지고 있어요.','rich','A1','economy',3,'wealthy luxury car mansion success'),
('w_economy_A1_34','poor','/pʊər/','adjective','가난한','Having little money.','Many people are still very {poor}.','아직도 많은 사람들이 매우 가난해요.','poor','A1','economy',3,'poverty street urban hardship community'),
('w_economy_A1_35','number','/ˈnʌmbər/','noun','숫자','A mathematical value used to count or calculate.','What {number} should I call?','어떤 번호로 전화해야 하나요?','number','A1','economy',3,'numbers calculator math finance digits');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_economy_A2_01','tax','/tæks/','noun','세금','Money that must be paid to the government.','The price includes {tax}.','가격에 세금이 포함되어 있어요.','tax','A2','economy',1,'tax form documents government finance'),
('w_economy_A2_02','income','/ˈɪnkʌm/','noun','수입','Money received regularly from work or investments.','My monthly {income} is enough to cover my expenses.','월 수입이 생활비를 충당하기에 충분해요.','income','A2','economy',1,'income salary paycheck money earning'),
('w_economy_A2_03','budget','/ˈbʌdʒɪt/','noun','예산','A plan for how to spend money.','I need to stick to my {budget} this month.','이번 달은 예산을 지켜야 해요.','budget','A2','economy',1,'budget planning notebook spreadsheet finance'),
('w_economy_A2_04','profit','/ˈprɒfɪt/','noun','이익','Money made after costs are paid.','The company made a big {profit} last year.','그 회사는 작년에 큰 이익을 냈어요.','profit','A2','economy',1,'profit growth chart business success'),
('w_economy_A2_05','loan','/loʊn/','noun','대출','Money borrowed from a bank that must be repaid.','I took out a {loan} to buy my car.','차를 사려고 대출을 받았어요.','loan','A2','economy',1,'loan bank signature document agreement'),
('w_economy_A2_06','credit','/ˈkredɪt/','noun','신용; 외상','The ability to borrow money based on trust.','My {credit} score is very good.','제 신용 점수는 아주 좋아요.','credit','A2','economy',1,'credit card score finance bank'),
('w_economy_A2_07','invest','/ɪnˈvest/','verb','투자하다','To put money into something to make more money.','It is smart to {invest} in your education.','교육에 투자하는 것은 현명해요.','invest','A2','economy',1,'investing money growth chart arrow up'),
('w_economy_A2_08','earn','/ɜːrn/','verb','(돈을) 벌다','To receive money as payment for work.','How much do you {earn} a month?','한 달에 얼마나 버나요?','earn','A2','economy',1,'earning money work office salary'),
('w_economy_A2_09','debt','/det/','noun','빚, 부채','Money owed to someone.','I want to pay off all my {debt} by next year.','내년까지 모든 빚을 갚고 싶어요.','debt','A2','economy',1,'debt stressed worried bills payment'),
('w_economy_A2_10','salary','/ˈsæləri/','noun','월급, 급여','Fixed regular payment from an employer.','My {salary} is paid at the end of each month.','급여는 매월 말에 지급돼요.','salary','A2','economy',1,'salary paycheck office work compensation'),
('w_economy_A2_11','account','/əˈkaʊnt/','noun','계좌','An arrangement with a bank to deposit or borrow money.','I just opened a new bank {account}.','방금 새 은행 계좌를 개설했어요.','account','A2','economy',2,'bank account card application form'),
('w_economy_A2_12','interest','/ˈɪntrəst/','noun','이자','Extra money paid for borrowing or earned from saving.','The {interest} on this loan is quite high.','이 대출의 이자가 꽤 높아요.','interest','A2','economy',1,'interest rate bank chart percentage'),
('w_economy_A2_13','rent','/rent/','noun','임대료, 집세','Regular payment for using a property.','The {rent} goes up every year.','임대료가 매년 올라요.','rent','A2','economy',1,'apartment rent keys housing building'),
('w_economy_A2_14','insurance','/ɪnˈʃʊərəns/','noun','보험','A contract providing financial protection against loss.','I have health {insurance} through my company.','회사를 통해 건강 보험이 있어요.','insurance','A2','economy',2,'insurance document pen signing protection'),
('w_economy_A2_15','refund','/ˈriːfʌnd/','noun','환불','Money returned after returning goods or cancelling.','Can I get a {refund} on this?','이것 환불받을 수 있나요?','refund','A2','economy',2,'refund receipt customer service counter'),
('w_economy_A2_16','deposit','/dɪˈpɒzɪt/','noun','보증금; 입금','Money paid as security or placed in a bank account.','I paid a {deposit} for the apartment.','아파트 보증금을 냈어요.','deposit','A2','economy',2,'deposit bank teller counter transaction'),
('w_economy_A2_17','withdraw','/wɪðˈdrɔː/','verb','인출하다','To take money out of a bank account.','I need to {withdraw} some cash.','현금을 좀 인출해야 해요.','withdraw','A2','economy',2,'ATM withdraw cash machine bank'),
('w_economy_A2_18','transfer','/ˈtrænsfɜːr/','verb','이체하다','To move money from one account to another.','Can you {transfer} the money by tomorrow?','내일까지 돈을 이체해 줄 수 있나요?','transfer','A2','economy',2,'bank transfer mobile phone app finance'),
('w_economy_A2_19','pension','/ˈpenʃən/','noun','연금','Regular payment to retired people.','My grandfather lives on his {pension}.','우리 할아버지는 연금으로 생활하세요.','pension','A2','economy',2,'elderly pension retirement savings comfortable'),
('w_economy_A2_20','tip','/tɪp/','noun','팁, 봉사료','Extra money given to a worker for good service.','Should I leave a {tip}?','팁을 남겨야 하나요?','tip','A2','economy',2,'restaurant tip cash service waiter'),
('w_economy_A2_21','wage','/weɪdʒ/','noun','임금 (시급)','Money paid for work, especially hourly.','The minimum {wage} was raised this year.','최저 임금이 올해 인상됐어요.','wage','A2','economy',1,'wage work factory labor salary'),
('w_economy_A2_22','raise','/reɪz/','noun','임금 인상','An increase in salary.','I asked my boss for a {raise}.','상사에게 임금 인상을 요청했어요.','raise','A2','economy',2,'salary raise office meeting discussion'),
('w_economy_A2_23','charge','/tʃɑːrdʒ/','verb','청구하다','To ask for a payment for goods or services.','How much do you {charge} for delivery?','배달료는 얼마예요?','charge','A2','economy',2,'charge payment service fee receipt'),
('w_economy_A2_24','afford','/əˈfɔːrd/','verb','여유가 되다','To have enough money to pay for something.','I can {afford} to travel once a year.','1년에 한 번은 여행할 여유가 돼요.','afford','A2','economy',2,'budget travel planning holiday finance'),
('w_economy_A2_25','mortgage','/ˈmɔːrɡɪdʒ/','noun','주택 담보 대출','A loan to buy a property.','We applied for a {mortgage} last week.','지난주에 주택 담보 대출을 신청했어요.','mortgage','A2','economy',2,'house mortgage keys bank loan home'),
('w_economy_A2_26','invest in','/ɪnˈvest ɪn/','phrase','~에 투자하다','To spend money on something expecting a future return.','She decided to {invest in} real estate.','그녀는 부동산에 투자하기로 결정했어요.','invest in','A2','economy',2,'real estate investment property chart'),
('w_economy_A2_27','fixed cost','/fɪkst kɒst/','noun','고정 비용','A cost that does not change, such as rent.','Rent is our biggest {fixed cost}.','임대료가 우리의 가장 큰 고정 비용이에요.','fixed cost','A2','economy',3,'budget fixed cost rent bills planning'),
('w_economy_A2_28','expense','/ɪkˈspens/','noun','지출, 경비','Money spent for a particular purpose.','Business {expenses} must be reported.','사업 경비는 신고해야 해요.','expense','A2','economy',2,'expense report receipt business documents'),
('w_economy_A2_29','coupon','/ˈkuːpɒn/','noun','쿠폰','A voucher giving a discount on goods.','I have a {coupon} for twenty percent off.','20% 할인 쿠폰이 있어요.','coupon','A2','economy',3,'coupon discount voucher shopping saving'),
('w_economy_A2_30','value','/ˈvæljuː/','noun','가치','The worth of something in money or importance.','The {value} of this painting has doubled.','이 그림의 가치가 두 배로 올랐어요.','value','A2','economy',2,'value art investment worth gallery'),
('w_economy_A2_31','profit margin','/ˈprɒfɪt ˌmɑːrdʒɪn/','noun','수익률','The percentage of revenue that is profit.','Our {profit margin} is around fifteen percent.','우리의 수익률은 약 15%예요.','profit margin','A2','economy',3,'profit margin chart business analytics'),
('w_economy_A2_32','currency','/ˈkɜːrənsi/','noun','통화, 화폐','The money used in a particular country.','The {currency} in Japan is the yen.','일본의 통화는 엔이에요.','currency','A2','economy',2,'currency exchange world money coins'),
('w_economy_A2_33','poverty','/ˈpɒvərti/','noun','빈곤','The state of being extremely poor.','Many families still live in {poverty}.','많은 가정이 아직도 빈곤 속에 살아요.','poverty','A2','economy',2,'poverty community urban hardship aid'),
('w_economy_A2_34','wealth','/welθ/','noun','부, 재산','A large amount of money or valuable possessions.','Education can be a path to {wealth}.','교육은 부를 이루는 길이 될 수 있어요.','wealth','A2','economy',2,'wealth success business growth prosperity'),
('w_economy_A2_35','transaction','/træˈnzækʃən/','noun','거래, 거래 내역','An act of buying or selling something.','Check your recent {transactions} online.','온라인에서 최근 거래 내역을 확인하세요.','transaction','A2','economy',2,'transaction bank app mobile screen finance');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_economy_B1_01','inflation','/ɪnˈfleɪʃən/','noun','인플레이션','A general increase in prices over time.','High {inflation} is reducing people''s purchasing power.','높은 인플레이션이 구매력을 줄이고 있어요.','inflation','B1','economy',1,'inflation prices rising chart graph economy'),
('w_economy_B1_02','recession','/rɪˈseʃən/','noun','경기 침체','A period of economic decline lasting several months.','The country entered a {recession} last year.','그 나라는 작년에 경기 침체에 들어갔어요.','recession','B1','economy',1,'recession economy decline graph business'),
('w_economy_B1_03','interest rate','/ˈɪntrəst reɪt/','noun','금리','The percentage charged on borrowed money.','The central bank raised the {interest rate}.','중앙은행이 금리를 올렸어요.','interest rate','B1','economy',1,'interest rate central bank chart percentage'),
('w_economy_B1_04','stock','/stɒk/','noun','주식','A share in the ownership of a company.','She owns {stock} in several tech companies.','그녀는 여러 기술 회사의 주식을 가지고 있어요.','stock','B1','economy',1,'stock market trading screen ticker'),
('w_economy_B1_05','market','/ˈmɑːrkɪt/','noun','시장 (금융)','The trade in a particular type of commodity.','The housing {market} has slowed down.','주택 시장이 둔화되었어요.','market','B1','economy',1,'financial market trading floor investors'),
('w_economy_B1_06','GDP','/ˌdʒiː diː ˈpiː/','noun','국내총생산','Gross Domestic Product — the total value of goods and services produced.','The country''s {GDP} grew by three percent.','그 나라의 GDP가 3% 성장했어요.','GDP','B1','economy',1,'GDP economy data chart growth country'),
('w_economy_B1_07','fiscal','/ˈfɪskəl/','adjective','재정의','Relating to government revenue and expenditure.','The government announced its new {fiscal} policy.','정부가 새 재정 정책을 발표했어요.','fiscal','B1','economy',2,'fiscal policy government budget parliament'),
('w_economy_B1_08','monetary','/ˈmɒnɪtəri/','adjective','통화의','Relating to money or currency in circulation.','The central bank uses {monetary} tools to control inflation.','중앙은행은 인플레이션을 조절하기 위해 통화 수단을 사용해요.','monetary','B1','economy',2,'monetary policy central bank board meeting'),
('w_economy_B1_09','trade','/treɪd/','noun','무역; 거래','The activity of buying and selling between countries.','Free {trade} benefits both sides.','자유 무역은 양측 모두에게 이익이 돼요.','trade','B1','economy',1,'international trade shipping containers port'),
('w_economy_B1_10','surplus','/ˈsɜːrpləs/','noun','흑자; 잉여','An amount left over when needs are met.','South Korea runs a trade {surplus}.','한국은 무역 흑자를 기록하고 있어요.','surplus','B1','economy',2,'surplus export trade data chart positive'),
('w_economy_B1_11','unemployment','/ˌʌnɪmˈplɔɪmənt/','noun','실업','The state of being without paid work.','{Unemployment} rose to eight percent.','실업률이 8%로 올랐어요.','unemployment','B1','economy',1,'unemployment job search office resume'),
('w_economy_B1_12','export','/ˈeksˌpɔːrt/','noun','수출','Goods sold and sent to another country.','Car {exports} increased this quarter.','이번 분기에 자동차 수출이 증가했어요.','export','B1','economy',1,'export shipping port cargo containers'),
('w_economy_B1_13','import','/ˈɪmpɔːrt/','noun','수입 (무역)','Goods bought from another country.','Fuel {imports} are costly for this country.','연료 수입은 이 나라에 비용이 많이 들어요.','import','B1','economy',1,'import cargo ship logistics port'),
('w_economy_B1_14','supply','/səˈplaɪ/','noun','공급','The amount of a good available for purchase.','A shortage in {supply} drives up prices.','공급 부족이 가격을 끌어올려요.','supply','B1','economy',1,'supply chain warehouse logistics goods'),
('w_economy_B1_15','demand','/dɪˈmɑːnd/','noun','수요','The desire of consumers to purchase goods.','High {demand} for housing has raised prices.','주택에 대한 높은 수요가 가격을 올렸어요.','demand','B1','economy',1,'demand graph economics supply arrow'),
('w_economy_B1_16','growth','/ɡroʊθ/','noun','성장','An increase in economic output over time.','Annual economic {growth} slowed to two percent.','연간 경제 성장이 2%로 둔화됐어요.','growth','B1','economy',1,'economic growth graph chart arrow upward'),
('w_economy_B1_17','investment','/ɪnˈvestmənt/','noun','투자','The act of putting money into something for a return.','Foreign {investment} is vital for development.','외국 투자는 개발에 필수적이에요.','investment','B1','economy',1,'investment business handshake deal finance'),
('w_economy_B1_18','bankruptcy','/ˈbæŋkrʌptsi/','noun','파산','The legal state of not being able to pay debts.','The company filed for {bankruptcy}.','그 회사는 파산 신청을 했어요.','bankruptcy','B1','economy',2,'bankruptcy closed store sign business failure'),
('w_economy_B1_19','competition','/ˌkɒmpɪˈtɪʃən/','noun','경쟁','The activity of striving against others for the same goal.','Healthy {competition} keeps prices down.','건전한 경쟁은 가격을 낮게 유지해요.','competition','B1','economy',2,'market competition rivals business strategy'),
('w_economy_B1_20','consumer','/kənˈsjuːmər/','noun','소비자','A person who buys goods or services.','{Consumer} confidence fell sharply.','소비자 신뢰가 급격히 떨어졌어요.','consumer','B1','economy',1,'consumer shopping mall retail spending'),
('w_economy_B1_21','producer','/prəˈdjuːsər/','noun','생산자','A person or company that makes goods.','Local {producers} benefit from fair prices.','현지 생산자들은 공정한 가격으로 혜택을 받아요.','producer','B1','economy',2,'producer farm factory manufacturing goods'),
('w_economy_B1_22','revenue','/ˈrevənjuː/','noun','수익, 세입','Income generated by a business or government.','The government''s {revenue} from taxes increased.','세금으로 인한 정부 세입이 증가했어요.','revenue','B1','economy',1,'revenue chart business income bar graph'),
('w_economy_B1_23','expenditure','/ɪkˈspendɪtʃər/','noun','지출, 지출액','The total amount of money spent.','Public {expenditure} on education was cut.','교육에 대한 공공 지출이 삭감됐어요.','expenditure','B1','economy',2,'government expenditure budget spending policy'),
('w_economy_B1_24','exchange rate','/ɪkˈstʃeɪndʒ reɪt/','noun','환율','The rate at which one currency is exchanged for another.','The {exchange rate} affects travel costs.','환율은 여행 비용에 영향을 미쳐요.','exchange rate','B1','economy',1,'exchange rate currency board airport travel'),
('w_economy_B1_25','capital','/ˈkæpɪtl/','noun','자본','Wealth used to produce more wealth.','The startup needed more {capital} to grow.','스타트업은 성장하기 위해 더 많은 자본이 필요했어요.','capital','B1','economy',1,'capital investment startup office whiteboard'),
('w_economy_B1_26','labor','/ˈleɪbər/','noun','노동','Work done by people, especially physical work.','The country has a large {labor} force.','그 나라는 큰 노동 인력을 보유하고 있어요.','labor','B1','economy',2,'labor workers factory manufacturing hard work'),
('w_economy_B1_27','industry','/ˈɪndəstri/','noun','산업','Economic activity concerned with processing goods.','The tech {industry} is growing rapidly.','기술 산업이 빠르게 성장하고 있어요.','industry','B1','economy',2,'industry factory technology business sector'),
('w_economy_B1_28','output','/ˈaʊtpʊt/','noun','생산량, 산출량','The amount of something produced.','Industrial {output} fell last quarter.','지난 분기 산업 생산량이 감소했어요.','output','B1','economy',2,'output factory production manufacturing chart'),
('w_economy_B1_29','sector','/ˈsektər/','noun','분야, 부문','A distinct part of an economy.','The service {sector} now dominates the economy.','서비스 부문이 이제 경제를 지배하고 있어요.','sector','B1','economy',2,'sector economy chart pie graph business'),
('w_economy_B1_30','subsidy','/ˈsʌbsɪdi/','noun','보조금','Money given by the government to support an industry.','Farmers receive a government {subsidy}.','농부들은 정부 보조금을 받아요.','subsidy','B1','economy',2,'subsidy farming government agriculture support'),
('w_economy_B1_31','cost of living','/kɒst əv ˈlɪvɪŋ/','noun','생활비','The amount of money needed for basic needs.','The {cost of living} in Seoul is rising.','서울의 생활비가 오르고 있어요.','cost of living','B1','economy',1,'cost of living city apartment grocery bills'),
('w_economy_B1_32','trade deficit','/treɪd ˈdefɪsɪt/','noun','무역 적자','When imports exceed exports in value.','The nation''s {trade deficit} widened.','그 나라의 무역 적자가 확대됐어요.','trade deficit','B1','economy',2,'trade deficit graph negative import export'),
('w_economy_B1_33','merger','/ˈmɜːrdʒər/','noun','기업 합병','The combining of two companies into one.','The {merger} created the largest bank in the region.','그 합병으로 지역 최대 은행이 탄생했어요.','merger','B1','economy',2,'merger business handshake corporate deal'),
('w_economy_B1_34','shareholder','/ˈʃeərhoʊldər/','noun','주주','A person who owns shares in a company.','{Shareholders} voted against the proposal.','주주들이 제안에 반대표를 던졌어요.','shareholder','B1','economy',2,'shareholder meeting boardroom vote corporate'),
('w_economy_B1_35','forecast','/ˈfɔːrkæst/','noun','전망, 예측','A prediction of future economic trends.','The economic {forecast} for next year is positive.','내년의 경제 전망은 긍정적이에요.','forecast','B1','economy',2,'economic forecast data chart analyst presentation');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_economy_B2_01','deficit','/ˈdefɪsɪt/','noun','적자, 결손','When expenditure exceeds revenue.','The government ran a large budget {deficit}.','정부는 큰 재정 적자를 기록했어요.','deficit','B2','economy',1,'deficit budget government spending debt chart'),
('w_economy_B2_02','quantitative easing','/ˌkwɒntɪteɪtɪv ˈiːzɪŋ/','noun','양적 완화','A monetary policy where central banks buy assets to inject money.','The Fed used {quantitative easing} to stimulate the economy.','연준은 경제를 부양하기 위해 양적 완화를 사용했어요.','quantitative easing','B2','economy',1,'quantitative easing central bank policy money'),
('w_economy_B2_03','liquidity','/lɪˈkwɪdɪti/','noun','유동성','The ease of converting assets to cash.','The bank faces a serious {liquidity} problem.','그 은행은 심각한 유동성 문제에 직면했어요.','liquidity','B2','economy',1,'liquidity cash flow bank finance chart'),
('w_economy_B2_04','equity','/ˈekwɪti/','noun','자기자본; 주식','The value of shares issued by a company; or fairness.','Investors prefer {equity} over bonds in a bull market.','강세장에서 투자자들은 채권보다 주식을 선호해요.','equity','B2','economy',1,'equity stock market investor trading screen'),
('w_economy_B2_05','hedge','/hedʒ/','verb','위험을 분산하다','To reduce risk by making an offsetting investment.','Investors {hedge} against currency risk with derivatives.','투자자들은 파생상품으로 환위험을 분산해요.','hedge','B2','economy',1,'hedge fund risk management finance strategy'),
('w_economy_B2_06','portfolio','/pɔːrtˈfoʊliˌoʊ/','noun','포트폴리오','A range of investments held by a person or organization.','Diversifying your {portfolio} reduces risk.','포트폴리오를 다양화하면 위험이 줄어요.','portfolio','B2','economy',1,'portfolio investment diversified stocks bonds'),
('w_economy_B2_07','bond','/bɒnd/','noun','채권','A certificate of debt issued by a government or company.','Government {bonds} are considered safe investments.','국채는 안전한 투자로 여겨져요.','bond','B2','economy',1,'bond certificate government treasury investment'),
('w_economy_B2_08','derivative','/dɪˈrɪvətɪv/','noun','파생상품','A financial product derived from another asset.','Options are a common type of financial {derivative}.','옵션은 흔한 금융 파생상품의 유형이에요.','derivative','B2','economy',2,'derivative finance trading options futures'),
('w_economy_B2_09','commodity','/kəˈmɒdɪti/','noun','원자재, 상품','A raw material or primary agricultural product.','Oil is the world''s most traded {commodity}.','석유는 세계에서 가장 많이 거래되는 원자재예요.','commodity','B2','economy',1,'commodity oil gold raw material trade'),
('w_economy_B2_10','index','/ˈɪndeks/','noun','지수','A statistical measure of economic or financial performance.','The stock market {index} hit a record high.','주가 지수가 사상 최고를 기록했어요.','index','B2','economy',1,'stock index chart market screen trading'),
('w_economy_B2_11','volatility','/ˌvɒləˈtɪlɪti/','noun','변동성','The degree of rapid and unpredictable change.','Market {volatility} increased after the announcement.','발표 이후 시장 변동성이 높아졌어요.','volatility','B2','economy',1,'market volatility chart spike finance'),
('w_economy_B2_12','yield','/jiːld/','noun','수익률, 이율','The income returned on an investment.','The bond''s {yield} fell as prices rose.','채권 가격이 오르면서 수익률이 하락했어요.','yield','B2','economy',1,'yield bond return investment finance chart'),
('w_economy_B2_13','leverage','/ˈlevərɪdʒ/','noun','레버리지, 차입 투자','The use of borrowed money to increase potential return.','The firm used too much {leverage} and collapsed.','그 회사는 레버리지를 너무 많이 사용하다 붕괴됐어요.','leverage','B2','economy',2,'leverage finance risk debt investment'),
('w_economy_B2_14','diversification','/daɪˌvɜːrsɪfɪˈkeɪʃən/','noun','분산투자','Spreading investments to reduce risk.','{Diversification} is key to managing investment risk.','분산투자는 투자 위험 관리의 핵심이에요.','diversification','B2','economy',2,'diversification portfolio investment various'),
('w_economy_B2_15','bear market','/beər ˈmɑːrkɪt/','noun','약세장','A period of declining stock prices.','Investors struggled during the {bear market}.','투자자들은 약세장 동안 어려움을 겪었어요.','bear market','B2','economy',2,'bear market stock decline chart red arrow down'),
('w_economy_B2_16','bull market','/bʊl ˈmɑːrkɪt/','noun','강세장','A period of rising stock prices.','The {bull market} lasted nearly a decade.','강세장이 거의 10년간 지속됐어요.','bull market','B2','economy',2,'bull market stock rise chart green arrow'),
('w_economy_B2_17','asset','/ˈæset/','noun','자산','A resource with economic value.','Property is her most valuable {asset}.','부동산이 그녀의 가장 가치 있는 자산이에요.','asset','B2','economy',1,'asset property investment wealth finance'),
('w_economy_B2_18','liability','/ˌlaɪəˈbɪlɪti/','noun','부채, 채무','Something a company or person owes.','Long-term {liabilities} appear on the balance sheet.','장기 부채는 대차대조표에 나타나요.','liability','B2','economy',2,'liability balance sheet accounting finance'),
('w_economy_B2_19','fiscal policy','/ˈfɪskəl ˈpɒlɪsi/','noun','재정 정책','Government decisions about spending and taxation.','Expansionary {fiscal policy} aims to stimulate growth.','확장적 재정 정책은 성장을 자극하는 것을 목표로 해요.','fiscal policy','B2','economy',2,'fiscal policy government budget parliament vote'),
('w_economy_B2_20','austerity','/ɒˈsterɪti/','noun','긴축','Government policies to reduce public spending.','Years of {austerity} caused widespread hardship.','수년간의 긴축 정책이 광범위한 어려움을 초래했어요.','austerity','B2','economy',1,'austerity protest cuts budget government'),
('w_economy_B2_21','currency depreciation','/ˈkɜːrənsi dɪˌpriːʃɪˈeɪʃən/','noun','통화 가치 하락','A decrease in the value of a currency relative to others.','{Currency depreciation} made exports more competitive.','통화 가치 하락으로 수출이 더 경쟁력을 갖게 됐어요.','currency depreciation','B2','economy',2,'currency exchange rate falling depreciation'),
('w_economy_B2_22','monetary policy','/ˈmɒnɪtəri ˈpɒlɪsi/','noun','통화 정책','Central bank actions to control money supply and rates.','The central bank tightened its {monetary policy}.','중앙은행이 통화 정책을 긴축했어요.','monetary policy','B2','economy',2,'monetary policy central bank interest rate board'),
('w_economy_B2_23','capitalization','/ˌkæpɪtələˈzeɪʃən/','noun','시가총액; 자본화','The total market value of a company''s shares.','Apple''s market {capitalization} exceeds two trillion dollars.','애플의 시가총액은 2조 달러를 넘어요.','capitalization','B2','economy',2,'market capitalization big tech company stock screen'),
('w_economy_B2_24','stagflation','/stæɡˈfleɪʃən/','noun','스태그플레이션','High inflation combined with stagnant growth and unemployment.','The 1970s saw severe {stagflation} in many countries.','1970년대에 많은 나라에서 심각한 스태그플레이션이 있었어요.','stagflation','B2','economy',2,'stagflation economy crisis vintage newspaper'),
('w_economy_B2_25','credit rating','/ˈkredɪt ˌreɪtɪŋ/','noun','신용 등급','An assessment of the ability to repay debts.','A country''s {credit rating} affects borrowing costs.','한 나라의 신용 등급은 차입 비용에 영향을 줘요.','credit rating','B2','economy',2,'credit rating agency finance document analysis'),
('w_economy_B2_26','venture capital','/ˈventʃər ˈkæpɪtl/','noun','벤처 캐피털','Funding provided to startup companies with high growth potential.','They raised funds from {venture capital} investors.','그들은 벤처 캐피털 투자자들로부터 자금을 조달했어요.','venture capital','B2','economy',2,'venture capital startup pitch investors office'),
('w_economy_B2_27','dividend','/ˈdɪvɪdend/','noun','배당금','A sum of money paid to shareholders from a company''s profits.','The company paid a generous {dividend} this year.','그 회사는 올해 넉넉한 배당금을 지급했어요.','dividend','B2','economy',2,'dividend payment investor stock check'),
('w_economy_B2_28','hedge fund','/hedʒ fʌnd/','noun','헤지펀드','A pooled investment fund using complex strategies.','The {hedge fund} posted a thirty percent return.','그 헤지펀드는 30%의 수익을 냈어요.','hedge fund','B2','economy',2,'hedge fund trading desk screens analysts'),
('w_economy_B2_29','private equity','/praɪvɪt ˈekwɪti/','noun','사모펀드','Investment in companies not listed on public exchanges.','{Private equity} firms acquired several hospitals.','사모펀드 회사들이 여러 병원을 인수했어요.','private equity','B2','economy',2,'private equity deal boardroom signing contract'),
('w_economy_B2_30','stock exchange','/stɒk ɪksˈtʃeɪndʒ/','noun','주식 거래소','A market where shares are bought and sold.','The company listed on the {stock exchange} today.','그 회사가 오늘 주식 거래소에 상장됐어요.','stock exchange','B2','economy',1,'stock exchange trading floor NYSE screens'),
('w_economy_B2_31','collateral','/kəˈlætərəl/','noun','담보','An asset pledged as security for a loan.','They used their house as {collateral} for the loan.','그들은 대출 담보로 집을 사용했어요.','collateral','B2','economy',2,'collateral loan document property house bank'),
('w_economy_B2_32','inflation rate','/ɪnˈfleɪʃən reɪt/','noun','물가상승률','The rate at which prices increase over time.','The {inflation rate} reached a forty-year high.','물가상승률이 40년 만에 최고치를 기록했어요.','inflation rate','B2','economy',2,'inflation rate CPI chart economy data'),
('w_economy_B2_33','benchmark','/ˈbentʃmɑːrk/','noun','기준, 벤치마크','A standard used for comparing performance.','The fund underperformed its {benchmark} index.','그 펀드는 기준 지수를 밑도는 성과를 냈어요.','benchmark','B2','economy',2,'benchmark comparison chart performance finance'),
('w_economy_B2_34','speculation','/ˌspekjʊˈleɪʃən/','noun','투기','Buying risky assets hoping for profit.','Property {speculation} drove up house prices.','부동산 투기가 주택 가격을 올렸어요.','speculation','B2','economy',2,'speculation real estate risk investment market'),
('w_economy_B2_35','economic cycle','/ˌiːkəˈnɒmɪk ˈsaɪkəl/','noun','경기 순환','The recurring pattern of expansion and contraction in an economy.','Understanding the {economic cycle} helps investors plan.','경기 순환을 이해하면 투자자들이 계획을 세우는 데 도움이 돼요.','economic cycle','B2','economy',2,'economic cycle wave chart boom recession');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_economy_C1_01','macroeconomics','/ˌmækroʊˌiːkəˈnɒmɪks/','noun','거시경제학','The branch of economics studying large-scale economic factors.','{Macroeconomics} focuses on GDP, inflation, and employment as a whole.','거시경제학은 GDP, 인플레이션, 고용 전체에 초점을 맞춰요.','macroeconomics','C1','economy',1,'macroeconomics lecture university economics textbook'),
('w_economy_C1_02','microeconomics','/ˌmaɪkroʊˌiːkəˈnɒmɪks/','noun','미시경제학','The branch of economics studying individual consumers and firms.','{Microeconomics} examines how prices are set in individual markets.','미시경제학은 개별 시장에서 가격이 어떻게 결정되는지 살펴봐요.','microeconomics','C1','economy',1,'microeconomics individual market supply demand graph'),
('w_economy_C1_03','stagflation','/stæɡˈfleɪʃən/','noun','스태그플레이션','A simultaneous occurrence of stagnation and inflation.','Policymakers struggled to address {stagflation} in the 1970s.','정책 입안자들은 1970년대 스태그플레이션 해결에 애를 먹었어요.','stagflation','C1','economy',1,'stagflation crisis newspaper headline economic history'),
('w_economy_C1_04','arbitrage','/ˈɑːrbɪtrɑːʒ/','noun','차익거래','Profiting from price differences in different markets.','Currency {arbitrage} requires speed and capital.','통화 차익거래는 속도와 자본이 필요해요.','arbitrage','C1','economy',2,'arbitrage trading screens currency price difference'),
('w_economy_C1_05','austerity','/ɒˈsterɪti/','noun','긴축 재정 정책','Severe economic policies to reduce government debt.','The IMF imposed strict {austerity} measures on the country.','IMF는 그 나라에 엄격한 긴축 조치를 부과했어요.','austerity','C1','economy',1,'austerity IMF government cuts protest economy'),
('w_economy_C1_06','deregulation','/ˌdiːˌreɡjʊˈleɪʃən/','noun','규제 완화','Reduction of government rules over an industry.','Financial {deregulation} in the 1980s allowed banks greater freedom.','1980년대 금융 규제 완화로 은행들은 더 큰 자유를 얻었어요.','deregulation','C1','economy',1,'deregulation finance bank building government law'),
('w_economy_C1_07','privatization','/ˌpraɪvətaɪˈzeɪʃən/','noun','민영화','Transferring a public service to private ownership.','The {privatization} of the railway was controversial.','철도 민영화는 논란이 됐어요.','privatization','C1','economy',1,'privatization railway public private corporation'),
('w_economy_C1_08','subsidy','/ˈsʌbsɪdi/','noun','보조금 (정책적)','Government financial support to encourage an activity.','Agricultural {subsidies} keep food prices stable.','농업 보조금이 식품 가격을 안정적으로 유지해요.','subsidy','C1','economy',1,'subsidy agriculture government support farm policy'),
('w_economy_C1_09','tariff','/ˈtærɪf/','noun','관세','A tax on imported goods.','The government imposed a twenty percent {tariff} on steel.','정부는 철강에 20% 관세를 부과했어요.','tariff','C1','economy',1,'tariff trade customs import border tax'),
('w_economy_C1_10','cartel','/kɑːrˈtel/','noun','카르텔','A group of companies agreeing to fix prices.','The oil {cartel} agreed to cut production.','석유 카르텔이 생산을 줄이기로 합의했어요.','cartel','C1','economy',1,'cartel oil OPEC meeting agreement energy'),
('w_economy_C1_11','oligopoly','/ˌɒlɪˈɡɒpəli/','noun','과점','A market controlled by a small number of firms.','The telecom sector is an {oligopoly} in most countries.','통신 분야는 대부분의 나라에서 과점이에요.','oligopoly','C1','economy',2,'oligopoly few companies market dominance'),
('w_economy_C1_12','externality','/ˌekstɜːrˈnælɪti/','noun','외부 효과','A cost or benefit affecting a third party outside a transaction.','Pollution is a classic negative {externality}.','오염은 전형적인 부정적 외부 효과예요.','externality','C1','economy',2,'externality pollution factory smoke environment'),
('w_economy_C1_13','fiscal stimulus','/ˈfɪskəl ˈstɪmjʊləs/','noun','재정 부양책','Government spending to boost economic activity.','The government announced a large {fiscal stimulus} package.','정부가 대규모 재정 부양 패키지를 발표했어요.','fiscal stimulus','C1','economy',1,'fiscal stimulus government spending infrastructure project'),
('w_economy_C1_14','central bank','/ˈsentrəl bæŋk/','noun','중앙은행','The national institution managing monetary policy.','The {central bank} raised rates by fifty basis points.','중앙은행이 기준금리를 50bp 인상했어요.','central bank','C1','economy',1,'central bank federal reserve building architecture'),
('w_economy_C1_15','austerity measure','/ɒˈsterɪti ˈmeʒər/','noun','긴축 조치','A specific policy action to cut government spending.','New {austerity measures} sparked nationwide protests.','새 긴축 조치가 전국적인 시위를 촉발시켰어요.','austerity measure','C1','economy',2,'austerity protest street signs economy crisis'),
('w_economy_C1_16','structural reform','/ˈstrʌktʃərəl rɪˈfɔːrm/','noun','구조 개혁','Long-term policy changes to improve economic efficiency.','The IMF called for deep {structural reforms}.','IMF는 심도 있는 구조 개혁을 촉구했어요.','structural reform','C1','economy',2,'structural reform policy government parliament document'),
('w_economy_C1_17','protectionism','/prəˈtekʃənɪzəm/','noun','보호무역주의','Economic policy restricting imports to protect domestic industry.','Rising {protectionism} threatens global trade.','높아지는 보호무역주의가 세계 무역을 위협하고 있어요.','protectionism','C1','economy',2,'protectionism trade wall tariff border policy'),
('w_economy_C1_18','moral hazard','/ˈmɒrəl ˈhæzərd/','noun','도덕적 해이','The tendency to take more risk because of protection from consequences.','Bank bailouts create {moral hazard}.','은행 구제금융은 도덕적 해이를 만들어요.','moral hazard','C1','economy',2,'moral hazard risk banking finance responsibility'),
('w_economy_C1_19','comparative advantage','/kəmˈpærətɪv ədˈvɑːntɪdʒ/','noun','비교우위','The ability to produce a good at a lower opportunity cost than another.','Trade is based on each country''s {comparative advantage}.','무역은 각 나라의 비교우위를 기반으로 해요.','comparative advantage','C1','economy',2,'comparative advantage trade global specialization'),
('w_economy_C1_20','purchasing power','/ˈpɜːrtʃəsɪŋ ˌpaʊər/','noun','구매력','The amount of goods a unit of currency can buy.','Inflation erodes {purchasing power} over time.','인플레이션은 시간이 지남에 따라 구매력을 잠식해요.','purchasing power','C1','economy',2,'purchasing power money shopping cart inflation'),
('w_economy_C1_21','free market','/friː ˈmɑːrkɪt/','noun','자유 시장','An economic system with minimal government intervention.','A {free market} allocates resources through supply and demand.','자유 시장은 수요와 공급을 통해 자원을 배분해요.','free market','C1','economy',1,'free market economy trade global business'),
('w_economy_C1_22','planned economy','/plænd ɪˈkɒnəmi/','noun','계획 경제','An economy in which production is controlled by the state.','A {planned economy} aims to distribute resources equally.','계획 경제는 자원을 균등하게 배분하는 것을 목표로 해요.','planned economy','C1','economy',2,'planned economy government factory state control'),
('w_economy_C1_23','sovereign debt','/ˈsɒvrən det/','noun','국가 채무','Money owed by a national government.','Rising {sovereign debt} alarmed investors.','증가하는 국가 채무가 투자자들을 놀라게 했어요.','sovereign debt','C1','economy',2,'sovereign debt government bond finance crisis'),
('w_economy_C1_24','crowding out','/ˈkraʊdɪŋ aʊt/','noun','구축 효과','When government borrowing reduces private sector investment.','Heavy state spending can cause {crowding out}.','과도한 국가 지출은 구축 효과를 일으킬 수 있어요.','crowding out','C1','economy',3,'crowding out government spending private sector'),
('w_economy_C1_25','natural monopoly','/ˈnætʃərəl məˈnɒpəli/','noun','자연독점','A market dominated by a single firm due to high entry costs.','Utilities are often considered {natural monopolies}.','공익 서비스는 종종 자연독점으로 여겨져요.','natural monopoly','C1','economy',2,'natural monopoly utility infrastructure power'),
('w_economy_C1_26','price elasticity','/praɪs ˌiːlæˈstɪsɪti/','noun','가격 탄력성','How sensitive demand is to a change in price.','Cigarettes have low {price elasticity} of demand.','담배는 수요의 가격 탄력성이 낮아요.','price elasticity','C1','economy',2,'price elasticity demand graph economics curve'),
('w_economy_C1_27','market failure','/ˈmɑːrkɪt ˈfeɪljər/','noun','시장 실패','When a free market does not efficiently allocate resources.','Pollution is a sign of {market failure}.','오염은 시장 실패의 신호예요.','market failure','C1','economy',2,'market failure environment pollution government'),
('w_economy_C1_28','balance of payments','/ˈbæləns əv ˈpeɪmənts/','noun','국제수지','A record of all transactions between a country and the world.','A deficit in the {balance of payments} weakens the currency.','국제수지 적자는 통화를 약화시켜요.','balance of payments','C1','economy',2,'balance of payments trade data statistics report'),
('w_economy_C1_29','lender of last resort','/ˈlendər əv lɑːst rɪˈzɔːrt/','noun','최종 대부자','An institution that provides emergency funds to banks.','The central bank acted as the {lender of last resort}.','중앙은행이 최종 대부자로 역할을 했어요.','lender of last resort','C1','economy',3,'central bank emergency loan crisis finance'),
('w_economy_C1_30','Keynesian economics','/ˈkeɪnziən ˌiːkəˈnɒmɪks/','noun','케인즈 경제학','Economic theory advocating government intervention to stabilize economies.','{Keynesian economics} supports deficit spending during recessions.','케인즈 경제학은 경기 침체 시 적자 지출을 지지해요.','Keynesian economics','C1','economy',2,'Keynes economics book theory government spending'),
('w_economy_C1_31','supply-side economics','/səˈplaɪ saɪd ˌiːkəˈnɒmɪks/','noun','공급 중심 경제학','Economic theory focusing on increasing production.','{Supply-side economics} promotes tax cuts for businesses.','공급 중심 경제학은 기업을 위한 세금 감면을 촉진해요.','supply-side economics','C1','economy',2,'supply side tax cut business production economics'),
('w_economy_C1_32','opportunity cost','/ˌɒpəˈtjuːnɪti kɒst/','noun','기회 비용','The value of the next best option forgone.','Going to university has an {opportunity cost} of lost wages.','대학 진학에는 포기된 임금이라는 기회 비용이 있어요.','opportunity cost','C1','economy',2,'opportunity cost decision choice trade-off economics'),
('w_economy_C1_33','hyperinflation','/ˌhaɪpərɪnˈfleɪʃən/','noun','초인플레이션','Extremely rapid and out-of-control price increases.','Zimbabwe suffered severe {hyperinflation} in the 2000s.','짐바브웨는 2000년대 심각한 초인플레이션을 겪었어요.','hyperinflation','C1','economy',2,'hyperinflation banknotes wheelbarrow crisis Zimbabwe'),
('w_economy_C1_34','fiscal consolidation','/ˈfɪskəl kənsɒlɪˈdeɪʃən/','noun','재정 건전화','Reducing budget deficits through spending cuts or tax rises.','{Fiscal consolidation} was necessary to restore investor confidence.','재정 건전화는 투자자 신뢰 회복에 필요했어요.','fiscal consolidation','C1','economy',2,'fiscal consolidation budget government documents finance'),
('w_economy_C1_35','income inequality','/ˈɪnkʌm ˌɪnɪˈkwɒlɪti/','noun','소득 불평등','The unequal distribution of income in society.','Rising {income inequality} is a global concern.','증가하는 소득 불평등은 세계적인 우려예요.','income inequality','C1','economy',1,'income inequality wealth gap poverty rich poor');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_economy_C2_01','econometrics','/ɪˌkɒnəˈmetrɪks/','noun','계량경제학','The application of statistical methods to economic data.','{Econometrics} is used to test economic theories empirically.','계량경제학은 경제 이론을 실증적으로 검증하는 데 사용돼요.','econometrics','C2','economy',1,'econometrics statistics regression data research university'),
('w_economy_C2_02','fiduciary','/fɪˈdjuːʃɪəri/','adjective','수탁자의; 신의 성실의','Relating to a legal duty to act in another''s best interest.','Fund managers have a {fiduciary} duty to their clients.','펀드 매니저는 고객에 대한 수탁 의무가 있어요.','fiduciary','C2','economy',1,'fiduciary duty trust fund manager legal documents'),
('w_economy_C2_03','securitization','/sɪˌkjʊərɪtaɪˈzeɪʃən/','noun','유동화, 증권화','The process of pooling assets to create tradable securities.','Mortgage {securitization} contributed to the 2008 financial crisis.','주택담보대출 유동화가 2008년 금융 위기에 기여했어요.','securitization','C2','economy',1,'securitization mortgage CDO finance crisis 2008'),
('w_economy_C2_04','collateralized','/kəˈlætərəlaɪzd/','adjective','담보화된','Backed by pledged assets as security.','{Collateralized} debt obligations were at the heart of the crisis.','담보부 채무증권이 위기의 핵심에 있었어요.','collateralized','C2','economy',2,'collateralized debt obligation CDO finance complex'),
('w_economy_C2_05','monopsony','/məˈnɒpsəni/','noun','수요 독점','A market where there is only one buyer.','A {monopsony} can suppress wages by controlling hiring.','수요 독점은 채용을 통제함으로써 임금을 억제할 수 있어요.','monopsony','C2','economy',2,'monopsony single buyer labor market wage'),
('w_economy_C2_06','rent-seeking','/rent ˈsiːkɪŋ/','noun','지대추구','Gaining wealth through manipulation of the economic environment.','Lobbying for special privileges is a form of {rent-seeking}.','특권을 위한 로비는 지대추구의 한 형태예요.','rent-seeking','C2','economy',2,'rent seeking lobbying politician influence wealth'),
('w_economy_C2_07','Keynesian','/ˈkeɪnziən/','adjective','케인즈주의적','Relating to the economic theories of John Maynard Keynes.','The government adopted a {Keynesian} approach to the recession.','정부는 경기 침체에 케인즈주의적 접근법을 채택했어요.','Keynesian','C2','economy',1,'Keynesian economics government stimulus spending policy'),
('w_economy_C2_08','neoliberal','/ˌniːoʊˈlɪbərəl/','adjective','신자유주의의','Relating to a free-market economic ideology with minimal state intervention.','Critics argue {neoliberal} policies have widened inequality.','비평가들은 신자유주의 정책이 불평등을 심화시켰다고 주장해요.','neoliberal','C2','economy',1,'neoliberal economics free market globalization policy'),
('w_economy_C2_09','heterodox','/ˈhetərədɒks/','adjective','비주류의; 이단적인','Not following conventional economic thinking.','{Heterodox} economists challenge mainstream assumptions.','비주류 경제학자들은 주류적 가정에 도전해요.','heterodox','C2','economy',2,'heterodox economics alternative theory debate academia'),
('w_economy_C2_10','exogenous','/ɛkˈsɒdʒɪnəs/','adjective','외생적인','Originating from outside the economic model.','Oil price shocks are often treated as {exogenous} variables.','유가 충격은 종종 외생 변수로 취급돼요.','exogenous','C2','economy',2,'exogenous variable model economics external shock'),
('w_economy_C2_11','endogenous growth','/enˈdɒdʒɪnəs ɡroʊθ/','noun','내생적 성장','Growth driven by factors within the economic model such as innovation.','{Endogenous growth} theory emphasizes R&D investment.','내생적 성장 이론은 R&D 투자를 강조해요.','endogenous growth','C2','economy',2,'endogenous growth innovation research technology lab'),
('w_economy_C2_12','Pareto efficiency','/pəˈreɪtoʊ ɪˈfɪʃənsi/','noun','파레토 효율성','A state where no one can be made better off without making someone worse off.','Perfect competition tends toward {Pareto efficiency}.','완전 경쟁은 파레토 효율성을 향해 가는 경향이 있어요.','Pareto efficiency','C2','economy',2,'Pareto efficiency economics optimal allocation graph'),
('w_economy_C2_13','Nash equilibrium','/næʃ ˌiːkwɪˈlɪbriəm/','noun','내시 균형','A stable state in game theory where no player benefits from changing strategy.','The {Nash equilibrium} predicts mutual defection in the prisoner''s dilemma.','내시 균형은 죄수의 딜레마에서 상호 배신을 예측해요.','Nash equilibrium','C2','economy',2,'Nash equilibrium game theory strategy mathematics'),
('w_economy_C2_14','asymmetric information','/ˌeɪsɪˈmetrɪk ˌɪnfəˈmeɪʃən/','noun','정보 비대칭','A situation where one party has more information than another.','Insurance markets suffer from {asymmetric information}.','보험 시장은 정보 비대칭으로 어려움을 겪어요.','asymmetric information','C2','economy',2,'asymmetric information market buyer seller knowledge'),
('w_economy_C2_15','moral suasion','/ˈmɒrəl ˈsweɪʒən/','noun','도의적 압박','Persuasion by appealing to morality or patriotism.','The central bank used {moral suasion} to discourage risky lending.','중앙은행은 위험한 대출을 막기 위해 도의적 압박을 사용했어요.','moral suasion','C2','economy',3,'moral suasion central bank speech policy persuasion'),
('w_economy_C2_16','credit default swap','/ˈkredɪt dɪˈfɔːlt swɒp/','noun','신용부도스왑','A financial derivative used to hedge credit risk.','{Credit default swaps} amplified losses during the 2008 crisis.','신용부도스왑은 2008년 위기 중 손실을 증폭시켰어요.','credit default swap','C2','economy',2,'credit default swap CDS finance derivative risk'),
('w_economy_C2_17','quantitative tightening','/ˌkwɒntɪteɪtɪv ˈtaɪtənɪŋ/','noun','양적 긴축','A monetary policy reducing central bank balance sheet size.','{Quantitative tightening} removes liquidity from the market.','양적 긴축은 시장에서 유동성을 제거해요.','quantitative tightening','C2','economy',2,'quantitative tightening central bank balance sheet'),
('w_economy_C2_18','fiscal multiplier','/ˈfɪskəl ˈmʌltɪplaɪər/','noun','재정 승수','The ratio of change in output to fiscal stimulus.','A high {fiscal multiplier} means spending has a large economic impact.','높은 재정 승수는 지출이 경제에 큰 영향을 미친다는 것을 의미해요.','fiscal multiplier','C2','economy',3,'fiscal multiplier government spending economic impact'),
('w_economy_C2_19','Gini coefficient','/ˈdʒiːni ˌkoʊɪˈfɪʃənt/','noun','지니 계수','A measure of income inequality in a population.','A higher {Gini coefficient} indicates greater inequality.','지니 계수가 높을수록 불평등이 더 크다는 것을 나타내요.','Gini coefficient','C2','economy',2,'Gini coefficient inequality statistics data chart'),
('w_economy_C2_20','deadweight loss','/ˈdedweɪt lɒs/','noun','사중 손실','The loss of economic efficiency due to market distortion.','Taxes create {deadweight loss} by reducing transactions.','세금은 거래를 줄임으로써 사중 손실을 만들어요.','deadweight loss','C2','economy',2,'deadweight loss economics graph supply demand triangle'),
('w_economy_C2_21','adverse selection','/ˈædvɜːrs sɪˈlekʃən/','noun','역선택','When one party takes advantage of better information before a deal.','Health insurance faces the problem of {adverse selection}.','건강 보험은 역선택 문제에 직면해 있어요.','adverse selection','C2','economy',2,'adverse selection insurance market lemons problem'),
('w_economy_C2_22','Dutch disease','/dʌtʃ dɪˈziːz/','noun','네덜란드병','Economic harm from a natural resource boom weakening other sectors.','Countries with oil revenues risk {Dutch disease}.','석유 수입이 있는 나라들은 네덜란드병의 위험이 있어요.','Dutch disease','C2','economy',2,'Dutch disease oil natural resource economy'),
('w_economy_C2_23','liquidity trap','/lɪˈkwɪdɪti træp/','noun','유동성 함정','A situation where monetary policy becomes ineffective at zero interest rates.','Japan experienced a prolonged {liquidity trap}.','일본은 장기간의 유동성 함정을 경험했어요.','liquidity trap','C2','economy',2,'liquidity trap Japan zero interest rate deflation'),
('w_economy_C2_24','principal-agent problem','/ˈprɪnsɪpəl ˈeɪdʒənt ˈprɒbləm/','noun','주인-대리인 문제','Conflict of interest between a principal and their agent.','Corporate governance tries to address the {principal-agent problem}.','기업 거버넌스는 주인-대리인 문제를 해결하려 해요.','principal-agent problem','C2','economy',2,'principal agent conflict interest corporate governance'),
('w_economy_C2_25','velocity of money','/vɪˈlɒsɪti əv ˈmʌni/','noun','화폐 유통 속도','How frequently money is exchanged in an economy.','A falling {velocity of money} signals reduced economic activity.','화폐 유통 속도의 하락은 경제 활동 감소를 알려요.','velocity of money','C2','economy',3,'velocity of money circulation economy activity chart'),
('w_economy_C2_26','crowdfunding','/ˈkraʊdfʌndɪŋ/','noun','크라우드펀딩','Raising capital from a large number of people online.','The startup raised a million dollars through {crowdfunding}.','그 스타트업은 크라우드펀딩으로 백만 달러를 조달했어요.','crowdfunding','C2','economy',2,'crowdfunding startup online platform investors community'),
('w_economy_C2_27','shadow banking','/ˈʃædoʊ ˈbæŋkɪŋ/','noun','그림자 금융','Financial activities outside regular banking regulations.','{Shadow banking} grew rapidly before the 2008 crisis.','그림자 금융은 2008년 위기 전에 급격히 성장했어요.','shadow banking','C2','economy',2,'shadow banking financial system unregulated risk'),
('w_economy_C2_28','behavioral economics','/bɪˈheɪvjərəl ˌiːkəˈnɒmɪks/','noun','행동경제학','The study of psychological influences on economic decisions.','Nudge theory is a key concept in {behavioral economics}.','넛지 이론은 행동경제학의 핵심 개념이에요.','behavioral economics','C2','economy',1,'behavioral economics psychology choice nudge experiment'),
('w_economy_C2_29','helicopter money','/ˈhelɪkɒptər ˈmʌni/','noun','헬리콥터 머니','Direct distribution of money to the public by a central bank.','Some economists proposed {helicopter money} during the pandemic.','일부 경제학자들은 팬데믹 중 헬리콥터 머니를 제안했어요.','helicopter money','C2','economy',2,'helicopter money cash drop stimulus economic policy'),
('w_economy_C2_30','seigniorage','/ˈseɪnjərɪdʒ/','noun','화폐발행이익','Profit made by a government from issuing currency.','{Seigniorage} is the difference between face value and production cost of money.','화폐발행이익은 화폐의 액면가와 생산비 차이예요.','seigniorage','C2','economy',3,'seigniorage central bank currency printing money'),
('w_economy_C2_31','Austrian school','/ˈɒstriən skuːl/','noun','오스트리아 학파','An economic school emphasizing individual action and free markets.','The {Austrian school} opposes central bank intervention.','오스트리아 학파는 중앙은행 개입에 반대해요.','Austrian school','C2','economy',2,'Austrian school economics Hayek Mises free market'),
('w_economy_C2_32','modern monetary theory','/ˈmɒdərn ˈmʌnɪtəri ˈθɪəri/','noun','현대화폐이론 (MMT)','A theory arguing governments can spend freely as currency issuers.','Proponents of {modern monetary theory} reject deficit concerns.','현대화폐이론 지지자들은 재정 적자 우려를 거부해요.','modern monetary theory','C2','economy',2,'MMT modern monetary theory policy debate economists'),
('w_economy_C2_33','trickle-down economics','/ˈtrɪkəl daʊn ˌiːkəˈnɒmɪks/','noun','낙수 경제학','The theory that tax cuts for the rich benefit everyone.','Critics say {trickle-down economics} mostly benefits the wealthy.','비평가들은 낙수 경제학이 주로 부유층에게 이익이 된다고 해요.','trickle-down economics','C2','economy',2,'trickle down economics wealth gap inequality debate'),
('w_economy_C2_34','information asymmetry','/ˌɪnfəˈmeɪʃən eɪˈsɪmɪtri/','noun','정보 비대칭','When different parties have access to different amounts of information.','{Information asymmetry} causes market inefficiency.','정보 비대칭은 시장 비효율을 초래해요.','information asymmetry','C2','economy',2,'information asymmetry market buyer seller knowledge'),
('w_economy_C2_35','general equilibrium','/ˈdʒenərəl ˌiːkwɪˈlɪbriəm/','noun','일반 균형','A state where all markets in an economy clear simultaneously.','Walras developed the theory of {general equilibrium}.','왈라스는 일반 균형 이론을 발전시켰어요.','general equilibrium','C2','economy',3,'general equilibrium economics theory mathematics model');
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_economy_A1_01','How much does this cost?','이게 얼마예요?','How much does this cost','가장 기본적인 가격 질문. "How much is this?"로도 써요.','가격 물어보기','A1','economy','pattern',NULL,1),
('s_economy_A1_02','Can I pay by card?','카드로 계산할 수 있나요?','pay by card','계산 방법을 물을 때 pay by card/cash 표현을 써요.','계산','A1','economy','pattern',NULL,2),
('s_economy_A1_03','Do you have anything cheaper?','더 저렴한 것이 있나요?','anything cheaper','anything + 비교급으로 더 나은 선택지를 물어봐요.','쇼핑 협상','A1','economy','pattern',NULL,3),
('s_economy_A1_04','I''ll take it.','이것으로 할게요.','I''ll take it','구매를 결정할 때 쓰는 짧고 자연스러운 표현이에요.','구매 결정','A1','economy','pattern',NULL,4),
('s_economy_A1_05','Can I get a receipt, please?','영수증 주실 수 있나요?','Can I get a receipt','정중한 요청에 "Can I get ~?"은 아주 자연스러운 표현이에요.','계산 후','A1','economy','pattern',NULL,5),
('s_economy_A1_06','Is there a discount?','할인이 있나요?','Is there a discount','세일이나 특별가를 물을 때 가장 많이 쓰는 표현이에요.','쇼핑','A1','economy','pattern',NULL,6),
('s_economy_A1_07','Keep the change.','거스름돈은 괜찮아요.','Keep the change','팁을 주거나 소액 거스름돈을 포기할 때 쓰는 표현이에요.','현금 계산','A1','economy','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_economy_A2_01','I''m trying to save up for a trip.','여행을 위해 저축하려고 해요.','save up for','save up for + 명사: 특정 목표를 위해 돈을 모을 때 써요.','저축 목표','A2','economy','pattern',NULL,1),
('s_economy_A2_02','I need to stick to my budget this month.','이번 달은 예산을 지켜야 해요.','stick to my budget','stick to my budget: 계획된 금액 안에서 쓰겠다는 의미예요.','예산 관리','A2','economy','pattern',NULL,2),
('s_economy_A2_03','Can I apply for a loan here?','여기서 대출 신청을 할 수 있나요?','apply for a loan','apply for + 명사: 대출, 직업, 비자 등을 신청할 때 사용해요.','은행 방문','A2','economy','pattern',NULL,3),
('s_economy_A2_04','My credit card bill came out to a lot this month.','이번 달 신용카드 명세서가 많이 나왔어요.','came out to','came out to + 금액: 최종 금액이 얼마가 나왔다고 말할 때 써요.','카드 명세서','A2','economy','pattern',NULL,4),
('s_economy_A2_05','I get paid at the end of the month.','월말에 급여를 받아요.','get paid','get paid: 급여가 지급된다는 표현. 능동형보다 훨씬 자연스러워요.','급여 관련','A2','economy','pattern',NULL,5),
('s_economy_A2_06','I''m in debt right now, so I can''t afford it.','지금 빚이 있어서 그것을 살 여유가 없어요.','in debt','in debt: 빚이 있는 상태. "I owe money"보다 더 자연스러운 표현이에요.','금전 상황','A2','economy','pattern',NULL,6),
('s_economy_A2_07','Could you transfer the money to my account?','제 계좌로 이체해 주실 수 있나요?','transfer the money to my account','transfer A to B: A를 B로 이체하다. 은행 업무에서 자주 써요.','송금 요청','A2','economy','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_economy_B1_01','Inflation has been rising steadily over the past few months.','지난 몇 달 동안 인플레이션이 꾸준히 상승해 왔어요.','has been rising steadily','현재완료 진행형은 과거부터 지금까지 계속되는 변화를 표현할 때 써요.','경제 뉴스 토론','B1','economy','pattern',NULL,1),
('s_economy_B1_02','The unemployment rate dropped to its lowest level in a decade.','실업률이 10년 만에 최저 수준으로 떨어졌어요.','dropped to its lowest level in','drop to + 최상급 + in + 기간: 기록적 수치를 표현하는 패턴이에요.','경제 지표 설명','B1','economy','pattern',NULL,2),
('s_economy_B1_03','The central bank is expected to raise interest rates next month.','중앙은행이 다음 달 금리를 인상할 것으로 예상돼요.','is expected to','be expected to + 동사: 예상되는 일을 말할 때 자연스러운 표현이에요.','금리 전망 토론','B1','economy','pattern',NULL,3),
('s_economy_B1_04','GDP grew by two percent compared to last year.','GDP가 작년 대비 2% 성장했어요.','compared to last year','compared to: 수치 비교에 가장 많이 쓰이는 표현이에요.','경제 성장 발표','B1','economy','pattern',NULL,4),
('s_economy_B1_05','There is a growing concern about the trade deficit.','무역 적자에 대한 우려가 커지고 있어요.','growing concern about','there is a growing concern about: 점점 심각해지는 문제를 언급할 때 써요.','경제 뉴스','B1','economy','pattern',NULL,5),
('s_economy_B1_06','The economy is showing signs of recovery.','경제가 회복 조짐을 보이고 있어요.','showing signs of recovery','show signs of + 명사: 징후가 나타나다는 표현이에요.','경기 회복 토론','B1','economy','pattern',NULL,6),
('s_economy_B1_07','Consumer spending has slowed down significantly this quarter.','소비자 지출이 이번 분기에 크게 둔화됐어요.','has slowed down significantly','현재완료 + significantly: 주목할 만한 변화를 강조하는 패턴이에요.','경제 분석','B1','economy','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_economy_B2_01','Diversifying your portfolio is key to managing risk.','포트폴리오를 다양화하는 것이 위험 관리의 핵심이에요.','diversifying your portfolio is key to','S + is key to + -ing: "~하는 데 핵심이다"라는 표현이에요.','투자 조언','B2','economy','pattern',NULL,1),
('s_economy_B2_02','The market correction was sharper than analysts had predicted.','시장 조정이 애널리스트들의 예상보다 훨씬 가파르게 나타났어요.','sharper than analysts had predicted','과거완료(had predicted)는 기준 시점보다 이전에 일어난 일을 표현해요.','시장 분석','B2','economy','pattern',NULL,2),
('s_economy_B2_03','Liquidity dried up quickly as investors panicked.','투자자들이 공황 상태에 빠지면서 유동성이 빠르게 말랐어요.','dried up','dry up: 자원·유동성이 갑자기 고갈되다는 생생한 표현이에요.','금융 위기 논의','B2','economy','pattern',NULL,3),
('s_economy_B2_04','Hedge funds tend to perform well in volatile markets.','헤지펀드는 변동성이 높은 시장에서 좋은 성과를 내는 경향이 있어요.','tend to perform well in','tend to: 일반적 경향을 설명할 때 쓰는 표현이에요.','투자 전략','B2','economy','pattern',NULL,4),
('s_economy_B2_05','The bond yield rose sharply following the Fed''s announcement.','연준 발표 이후 채권 수익률이 급격히 상승했어요.','rose sharply following','following + 명사: "~ 이후에"라는 뜻으로 인과관계를 연결해요.','채권 시장','B2','economy','pattern',NULL,5),
('s_economy_B2_06','Investors are fleeing to safe-haven assets amid uncertainty.','불확실성 속에서 투자자들이 안전 자산으로 이동하고 있어요.','fleeing to safe-haven assets amid','amid + 명사: "~ 속에서"라는 표현으로 배경 상황을 나타내요.','위험 회피 전략','B2','economy','pattern',NULL,6),
('s_economy_B2_07','The equity market rebounded after the initial sell-off.','초기 매도세 이후 주식 시장이 반등했어요.','rebounded after the initial sell-off','rebound after: 하락 이후 반등을 표현하는 금융 뉴스의 핵심 패턴이에요.','시장 동향','B2','economy','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_economy_C1_01','Austerity measures have been criticized for deepening inequality rather than reducing the deficit.','긴축 조치는 적자를 줄이기보다 불평등을 심화시켰다는 비판을 받아왔어요.','criticized for deepening','be criticized for + -ing: 비판의 근거를 제시하는 고급 표현이에요.','경제 정책 비판','C1','economy','pattern',NULL,1),
('s_economy_C1_02','Deregulation of the financial sector in the 1980s is often linked to greater systemic risk.','1980년대 금융 부문 규제 완화는 종종 더 큰 시스템 위험과 연결지어져요.','is often linked to','be linked to: 두 현상 간의 인과 혹은 연관성을 표현할 때 써요.','역사적 정책 분석','C1','economy','pattern',NULL,2),
('s_economy_C1_03','The government''s privatization drive has faced strong opposition from trade unions.','정부의 민영화 추진은 노동조합의 강한 반대에 직면했어요.','faced strong opposition from','face opposition from: 반대에 부딪히다는 표현으로 정치 논의에서 자주 써요.','정책 논쟁','C1','economy','pattern',NULL,3),
('s_economy_C1_04','Protectionist tariffs may shield domestic producers but ultimately harm consumers.','보호무역 관세는 국내 생산자를 보호할 수 있지만 결국 소비자에게 해를 끼쳐요.','may shield ... but ultimately','may ... but ultimately: 단기 효과와 장기 결과를 대조할 때 쓰는 구조예요.','무역 정책 논의','C1','economy','pattern',NULL,4),
('s_economy_C1_05','Comparative advantage theory suggests that specialization leads to greater overall welfare.','비교우위 이론은 특화가 전체적인 복지 향상으로 이어진다고 주장해요.','theory suggests that','theory suggests that: 이론의 주장을 소개하는 학술적 표현이에요.','경제 이론 설명','C1','economy','pattern',NULL,5),
('s_economy_C1_06','Excessive reliance on subsidies can distort market signals and reduce efficiency.','보조금에 대한 과도한 의존은 시장 신호를 왜곡하고 효율성을 낮출 수 있어요.','distort market signals','distort market signals: 시장 메커니즘이 제대로 작동하지 않을 때 쓰는 표현이에요.','시장 왜곡 분석','C1','economy','pattern',NULL,6),
('s_economy_C1_07','Moral hazard arises when one party is insulated from the consequences of their decisions.','도덕적 해이는 한쪽이 자신의 결정 결과로부터 보호받을 때 발생해요.','is insulated from the consequences','be insulated from: 결과나 영향을 받지 않는 상태를 표현해요.','경제 인센티브 분석','C1','economy','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_economy_C2_01','Econometric models rely on large datasets to identify causal relationships between variables.','계량경제 모델은 변수 간의 인과 관계를 파악하기 위해 대규모 데이터셋에 의존해요.','identify causal relationships between','identify causal relationships: 인과성 파악이라는 계량경제학의 핵심 목표를 표현해요.','학술 연구 방법론','C2','economy','pattern',NULL,1),
('s_economy_C2_02','The securitization of mortgage-backed assets obscured the underlying credit risk from investors.','주택담보대출 기반 자산의 유동화는 투자자들로부터 내재된 신용 위험을 가렸어요.','obscured the underlying credit risk','obscure + risk: 위험이 감춰지다는 표현으로 금융 위기 분석에 자주 쓰여요.','2008 금융 위기 분석','C2','economy','pattern',NULL,2),
('s_economy_C2_03','Rent-seeking behavior undermines allocative efficiency by redirecting resources toward unproductive activities.','지대추구 행동은 자원을 비생산적 활동으로 전환시켜 배분 효율성을 훼손해요.','undermines allocative efficiency','undermine efficiency: 효율성을 잠식하다는 표현으로 경제 왜곡을 비판할 때 써요.','경제적 비효율 분석','C2','economy','pattern',NULL,3),
('s_economy_C2_04','Heterodox economists challenge the assumption that markets naturally tend toward equilibrium.','비주류 경제학자들은 시장이 자연적으로 균형을 향해 가는 경향이 있다는 가정에 도전해요.','challenge the assumption that','challenge the assumption that: 주류 이론의 전제를 의문시하는 학술적 표현이에요.','경제학 패러다임 토론','C2','economy','pattern',NULL,4),
('s_economy_C2_05','Asymmetric information between buyers and sellers leads to adverse selection and market inefficiency.','구매자와 판매자 간의 정보 비대칭은 역선택과 시장 비효율로 이어져요.','leads to adverse selection','leads to: 결과를 도출하는 인과 표현으로 학술 글쓰기에 필수적이에요.','정보 경제학','C2','economy','pattern',NULL,5),
('s_economy_C2_06','The Gini coefficient measures the extent to which income distribution deviates from perfect equality.','지니 계수는 소득 분배가 완전한 평등에서 얼마나 벗어나는지를 측정해요.','measures the extent to which','measures the extent to which: 정도·수준을 객관적으로 측정하는 학술 표현이에요.','소득 불평등 측정','C2','economy','pattern',NULL,6),
('s_economy_C2_07','A liquidity trap renders conventional monetary policy ineffective, as near-zero rates fail to stimulate demand.','유동성 함정은 제로에 가까운 금리가 수요를 자극하지 못하면서 기존 통화 정책을 무효화해요.','renders conventional monetary policy ineffective','render + O + adjective: "~을 ~한 상태로 만들다"라는 C1+ 핵심 동사 패턴이에요.','통화 정책 한계 분석','C2','economy','pattern',NULL,7);
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_culture_A1_01','music','/ˈmjuːzɪk/','noun','음악','Sounds arranged in a pleasing or expressive way.','I love {music}.','저는 음악을 좋아해요.','music','A1','culture',1,'music concert stage performance art'),
('w_culture_A1_02','art','/ɑːrt/','noun','예술, 미술','The expression of creative skill through painting, drawing, or other forms.','I enjoy looking at {art} in galleries.','저는 갤러리에서 그림 보는 것을 즐겨요.','art','A1','culture',1,'art gallery painting colorful wall'),
('w_culture_A1_03','movie','/ˈmuːvi/','noun','영화','A story told through moving pictures shown on a screen.','Let''s watch a {movie} tonight.','오늘 밤 영화 봐요.','movie','A1','culture',1,'cinema movie theater popcorn screen'),
('w_culture_A1_04','book','/bʊk/','noun','책','A set of printed pages bound together.','I read a {book} every week.','저는 매주 책을 읽어요.','book','A1','culture',1,'open book reading cozy library'),
('w_culture_A1_05','dance','/dæns/','noun','춤','Movement of the body in a rhythmic way, usually to music.','She loves to {dance} with her friends.','그녀는 친구들과 춤추는 것을 좋아해요.','dance','A1','culture',1,'dance performance stage spotlight'),
('w_culture_A1_06','paint','/peɪnt/','verb','그리다, 칠하다','To apply colour to a surface to create a picture or decoration.','She likes to {paint} on weekends.','그녀는 주말에 그림 그리는 것을 좋아해요.','paint','A1','culture',2,'painting artist canvas brush studio'),
('w_culture_A1_07','sing','/sɪŋ/','verb','노래하다','To make musical sounds with the voice.','He can {sing} very well.','그는 노래를 매우 잘해요.','sing','A1','culture',1,'singer microphone performance stage'),
('w_culture_A1_08','play','/pleɪ/','verb','(악기를) 연주하다','To perform music on an instrument.','I want to {play} the piano.','저는 피아노를 연주하고 싶어요.','play','A1','culture',1,'piano playing hands keyboard music'),
('w_culture_A1_09','show','/ʃoʊ/','noun','공연, 쇼','A performance or entertainment for an audience.','The {show} starts at seven.','공연은 7시에 시작해요.','show','A1','culture',1,'stage show performance audience theater'),
('w_culture_A1_10','story','/ˈstɔːri/','noun','이야기','An account of events, real or fictional.','She told me a beautiful {story}.','그녀가 저에게 아름다운 이야기를 해줬어요.','story','A1','culture',1,'storytelling book open pages warm light'),
('w_culture_A1_11','photo','/ˈfoʊtoʊ/','noun','사진','A picture made using a camera.','I took a {photo} of the painting.','저는 그림 사진을 찍었어요.','photo','A1','culture',2,'photography camera photo gallery wall'),
('w_culture_A1_12','draw','/drɔː/','verb','그리다 (선으로)','To make a picture using a pencil or pen.','Can you {draw} a simple picture?','간단한 그림을 그려줄 수 있나요?','draw','A1','culture',2,'drawing sketch pencil sketchbook'),
('w_culture_A1_13','song','/sɒŋ/','noun','노래','A piece of music with words.','That {song} is very popular.','그 노래는 매우 인기 있어요.','song','A1','culture',1,'song music notes headphones'),
('w_culture_A1_14','color','/ˈkʌlər/','noun','색깔','The property of an object that appears different under different light.','I love the {color} of this painting.','저는 이 그림의 색깔이 마음에 들어요.','color','A1','culture',2,'colorful painting palette bright art'),
('w_culture_A1_15','stage','/steɪdʒ/','noun','무대','The raised platform in a theatre where performers act.','The singer walked onto the {stage}.','가수가 무대 위로 걸어갔어요.','stage','A1','culture',1,'stage spotlight theater performance empty'),
('w_culture_A1_16','actor','/ˈæktər/','noun','배우','A person who performs roles in films or theatre.','My favourite {actor} is in this film.','제가 좋아하는 배우가 이 영화에 나와요.','actor','A1','culture',1,'actor film set scene performance'),
('w_culture_A1_17','film','/fɪlm/','noun','영화, 필름','A story recorded as a moving image for cinema or television.','Have you seen the new {film}?','새 영화 보셨어요?','film','A1','culture',1,'film cinema reel dark theater'),
('w_culture_A1_18','listen','/ˈlɪsən/','verb','듣다','To give attention to a sound.','I like to {listen} to music before bed.','자기 전에 음악 듣는 걸 좋아해요.','listen','A1','culture',2,'headphones listening music relax'),
('w_culture_A1_19','read','/riːd/','verb','읽다','To look at written words and understand them.','She loves to {read} novels.','그녀는 소설 읽는 것을 좋아해요.','read','A1','culture',1,'reading book cozy window light'),
('w_culture_A1_20','write','/raɪt/','verb','쓰다','To form letters or words on paper or a screen.','He can {write} beautiful poems.','그는 아름다운 시를 쓸 수 있어요.','write','A1','culture',2,'writing pen notebook poetry'),
('w_culture_A1_21','band','/bænd/','noun','밴드, 악단','A group of musicians who play together.','I love this {band}''s new album.','이 밴드의 새 앨범이 너무 좋아요.','band','A1','culture',2,'rock band performance concert stage'),
('w_culture_A1_22','drum','/drʌm/','noun','드럼, 북','A musical instrument that you hit to make sound.','He plays the {drum} in a band.','그는 밴드에서 드럼을 쳐요.','drum','A1','culture',3,'drums percussion musician performance'),
('w_culture_A1_23','guitar','/ɡɪˈtɑːr/','noun','기타','A stringed musical instrument played by plucking.','She plays the {guitar} every day.','그녀는 매일 기타를 쳐요.','guitar','A1','culture',1,'guitar acoustic playing music'),
('w_culture_A1_24','visit','/ˈvɪzɪt/','verb','방문하다','To go to a place in order to see it.','We should {visit} the art gallery.','미술관에 가봐야 해요.','visit','A1','culture',2,'art gallery visit people walking'),
('w_culture_A1_25','watch','/wɒtʃ/','verb','보다, 관람하다','To look at something for a period of time.','I like to {watch} musicals.','저는 뮤지컬 보는 것을 좋아해요.','watch','A1','culture',1,'watching performance theater audience'),
('w_culture_A1_26','ticket','/ˈtɪkɪt/','noun','티켓, 입장권','A piece of paper that lets you enter an event.','I bought a {ticket} for the concert.','콘서트 티켓을 샀어요.','ticket','A1','culture',1,'concert ticket stub event entrance'),
('w_culture_A1_27','poem','/ˈpoʊɪm/','noun','시','A piece of writing arranged in short lines.','She wrote a short {poem} about spring.','그녀는 봄에 대한 짧은 시를 썼어요.','poem','A1','culture',3,'poetry book open page writing'),
('w_culture_A1_28','picture','/ˈpɪktʃər/','noun','그림, 사진','A drawing, painting, or photograph.','I drew a {picture} of my family.','가족 그림을 그렸어요.','picture','A1','culture',2,'picture frame wall gallery art'),
('w_culture_A1_29','instrument','/ˈɪnstrəmənt/','noun','악기','An object used to make music.','Can you play a musical {instrument}?','악기를 연주할 수 있나요?','instrument','A1','culture',1,'musical instruments collection orchestra'),
('w_culture_A1_30','audience','/ˈɔːdiəns/','noun','관객, 청중','The people watching or listening to a performance.','The {audience} clapped loudly.','관객들이 크게 박수를 쳤어요.','audience','A1','culture',1,'audience applause theater clapping'),
('w_culture_A1_31','favourite','/ˈfeɪvərɪt/','adjective','가장 좋아하는','Preferred above all others.','What is your {favourite} song?','가장 좋아하는 노래가 뭐예요?','favourite','A1','culture',2,'favourite music headphones smiling'),
('w_culture_A1_32','character','/ˈkærɪktər/','noun','등장인물','A person in a book, film, or play.','My favourite {character} is in the story.','제가 가장 좋아하는 등장인물이 이야기에 나와요.','character','A1','culture',2,'story character book illustration'),
('w_culture_A1_33','colour','/ˈkʌlər/','noun','색채 (영국식)','Visual quality seen in paintings and art.','The painting uses many bright {colour}s.','그 그림은 밝은 색채를 많이 사용해요.','colour','A1','culture',2,'colorful bright painting abstract'),
('w_culture_A1_34','happy','/ˈhæpi/','adjective','행복한, 기쁜','Feeling or showing pleasure or contentment.','Music makes me feel {happy}.','음악을 들으면 기분이 행복해져요.','happy','A1','culture',3,'happy joyful concert music smiling'),
('w_culture_A1_35','new','/njuː/','adjective','새로운','Not existing before; recently made or introduced.','There is a {new} exhibition downtown.','시내에 새로운 전시회가 있어요.','new','A1','culture',3,'new exhibition gallery opening art');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_culture_A2_01','festival','/ˈfestɪvəl/','noun','축제','A special event or celebration, often involving music or art.','We went to a music {festival} last summer.','지난 여름에 음악 축제에 갔어요.','festival','A2','culture',1,'music festival crowd outdoor summer stage'),
('w_culture_A2_02','museum','/mjuːˈziːəm/','noun','박물관','A building where objects of historical or cultural interest are kept.','The {museum} has a great collection of ancient art.','그 박물관에는 훌륭한 고대 미술 컬렉션이 있어요.','museum','A2','culture',1,'museum interior art exhibit hall'),
('w_culture_A2_03','theatre','/ˈθɪətər/','noun','극장, 연극','A building where plays, shows, or films are performed.','We saw a wonderful play at the {theatre}.','극장에서 훌륭한 연극을 봤어요.','theatre','A2','culture',1,'theater stage curtain interior seats'),
('w_culture_A2_04','concert','/ˈkɒnsərt/','noun','콘서트, 연주회','A live musical performance.','The {concert} was absolutely amazing.','콘서트가 정말 놀라웠어요.','concert','A2','culture',1,'concert live music crowd lights stage'),
('w_culture_A2_05','exhibition','/ˌeksɪˈbɪʃən/','noun','전시회','A public display of works of art or items of interest.','I visited the photography {exhibition} yesterday.','어제 사진 전시회에 갔어요.','exhibition','A2','culture',1,'art exhibition gallery white walls photos'),
('w_culture_A2_06','tradition','/trəˈdɪʃən/','noun','전통','A belief or practice passed down over generations.','Music is a big part of our {tradition}.','음악은 우리 전통의 중요한 부분이에요.','tradition','A2','culture',1,'traditional costume ceremony cultural heritage'),
('w_culture_A2_07','costume','/ˈkɒstjuːm/','noun','의상, 복장','Clothes worn by performers or at special events.','The dancers wore beautiful {costume}s.','무용수들이 아름다운 의상을 입었어요.','costume','A2','culture',2,'traditional costume dancer colorful performance'),
('w_culture_A2_08','sculpture','/ˈskʌlptʃər/','noun','조각품','A three-dimensional work of art made from stone, metal, or other materials.','That bronze {sculpture} is stunning.','저 청동 조각품은 정말 멋져요.','sculpture','A2','culture',2,'sculpture bronze museum art gallery'),
('w_culture_A2_09','gallery','/ˈɡæləri/','noun','갤러리, 화랑','A room or building for displaying works of art.','The new art {gallery} opens next month.','새 미술관이 다음 달에 문을 열어요.','gallery','A2','culture',1,'art gallery white walls paintings modern'),
('w_culture_A2_10','performance','/pərˈfɔːrməns/','noun','공연, 퍼포먼스','An act of presenting a play, concert, or other entertainment.','Her {performance} received a standing ovation.','그녀의 공연은 기립 박수를 받았어요.','performance','A2','culture',1,'dance performance stage spotlight applause'),
('w_culture_A2_11','choir','/kwaɪər/','noun','합창단','A group of singers who perform together.','She sings in the school {choir}.','그녀는 학교 합창단에서 노래해요.','choir','A2','culture',2,'choir singing performance church hall'),
('w_culture_A2_12','orchestra','/ˈɔːrkɪstrə/','noun','오케스트라','A large group of musicians playing together.','The {orchestra} played beautifully.','오케스트라가 아름답게 연주했어요.','orchestra','A2','culture',1,'orchestra classical music concert hall'),
('w_culture_A2_13','comedy','/ˈkɒmədi/','noun','코미디, 희극','A type of entertainment designed to make people laugh.','We watched a {comedy} at the theatre.','극장에서 코미디를 봤어요.','comedy','A2','culture',2,'comedy theater laughter audience smiling'),
('w_culture_A2_14','drama','/ˈdrɑːmə/','noun','드라마, 연극','A serious play for theatre, television, or radio.','The historical {drama} was very moving.','그 역사 드라마는 매우 감동적이었어요.','drama','A2','culture',1,'drama theater stage performance actors'),
('w_culture_A2_15','musical','/ˈmjuːzɪkəl/','noun','뮤지컬','A theatrical play that uses songs and dancing to tell a story.','I love watching Broadway {musical}s.','저는 브로드웨이 뮤지컬 보는 것을 좋아해요.','musical','A2','culture',1,'musical theater stage dancers singers'),
('w_culture_A2_16','ballet','/ˈbæleɪ/','noun','발레','A type of artistic dance performed to classical music.','She has been doing {ballet} since she was five.','그녀는 다섯 살 때부터 발레를 해왔어요.','ballet','A2','culture',2,'ballet dancer pointe shoes performance stage'),
('w_culture_A2_17','opera','/ˈɒpərə/','noun','오페라','A drama set to music in which the words are sung.','Have you ever been to an {opera}?','오페라 공연에 가본 적 있어요?','opera','A2','culture',2,'opera singer stage dramatic performance'),
('w_culture_A2_18','photography','/fəˈtɒɡrəfi/','noun','사진 촬영, 사진 예술','The art or practice of taking and developing photographs.','She studied {photography} at art school.','그녀는 미술학교에서 사진을 공부했어요.','photography','A2','culture',1,'photography camera lens artistic black white'),
('w_culture_A2_19','exhibition hall','/ˌeksɪˈbɪʃən hɔːl/','noun','전시 홀','A large room designed to host exhibitions.','The {exhibition hall} was full of visitors.','전시 홀이 방문객으로 가득 찼어요.','exhibition hall','A2','culture',2,'exhibition hall interior spacious art visitors'),
('w_culture_A2_20','admission','/ədˈmɪʃən/','noun','입장료, 입장','The fee charged for entering a place.','{Admission} to the museum is free on Sundays.','박물관 입장은 일요일에 무료예요.','Admission','A2','culture',2,'museum entrance admission ticket counter'),
('w_culture_A2_21','rehearsal','/rɪˈhɜːrsəl/','noun','리허설, 예행 연습','A practice session for a public performance.','The band has a {rehearsal} tonight.','밴드가 오늘 밤 리허설이 있어요.','rehearsal','A2','culture',2,'rehearsal practice musicians stage empty theater'),
('w_culture_A2_22','classic','/ˈklæsɪk/','adjective','고전적인, 대표적인','Judged over a period of time to be of the highest quality.','This is a {classic} piece of jazz.','이건 대표적인 재즈 곡이에요.','classic','A2','culture',1,'classic vinyl record jazz music warm'),
('w_culture_A2_23','style','/staɪl/','noun','스타일, 양식','A particular way of doing or presenting something.','I love the {style} of impressionist paintings.','인상주의 그림의 양식이 마음에 들어요.','style','A2','culture',1,'painting style impressionist art museum'),
('w_culture_A2_24','culture','/ˈkʌltʃər/','noun','문화','The ideas, customs, and artistic achievements of a society.','Korean {culture} has become popular worldwide.','한국 문화가 전 세계적으로 인기를 얻고 있어요.','culture','A2','culture',1,'korean culture traditional modern city'),
('w_culture_A2_25','artist','/ˈɑːrtɪst/','noun','예술가, 화가','A person who creates works of art.','The {artist} painted every day for a year.','그 예술가는 1년 동안 매일 그림을 그렸어요.','artist','A2','culture',1,'artist painting studio creative workspace'),
('w_culture_A2_26','audience clap','/ˈɔːdiəns klæp/','phrase','박수치다','When an audience shows appreciation by clapping.','The {audience clap}ped after every song.','모든 노래 후에 관객들이 박수를 쳤어요.','audience clap','A2','culture',3,'audience applause clapping concert hall'),
('w_culture_A2_27','singer','/ˈsɪŋər/','noun','가수','A person who sings, especially professionally.','The {singer} has a beautiful voice.','그 가수는 아름다운 목소리를 갖고 있어요.','singer','A2','culture',1,'singer microphone stage spotlight performance'),
('w_culture_A2_28','pianist','/piˈænɪst/','noun','피아니스트','A person who plays the piano.','The {pianist} performed a Chopin sonata.','피아니스트가 쇼팽 소나타를 연주했어요.','pianist','A2','culture',2,'pianist piano classical performance concert'),
('w_culture_A2_29','preview','/ˈpriːvjuː/','noun','시사회, 미리보기','A showing of a film or performance before its official release.','We attended the {preview} of the new musical.','새 뮤지컬 시사회에 참석했어요.','preview','A2','culture',2,'movie preview screening film audience'),
('w_culture_A2_30','souvenir','/ˌsuːvəˈnɪr/','noun','기념품','A thing kept as a reminder of a place or event.','I bought a {souvenir} at the museum shop.','박물관 기념품 가게에서 기념품을 샀어요.','souvenir','A2','culture',3,'museum souvenir shop gifts'),
('w_culture_A2_31','applaud','/əˈplɔːd/','verb','박수를 치다','To show approval by clapping hands.','The crowd {applaud}ed at the end of the show.','공연이 끝날 때 관객들이 박수를 쳤어요.','applaud','A2','culture',2,'applause audience clapping theater bravo'),
('w_culture_A2_32','costume design','/ˈkɒstjuːm dɪˈzaɪn/','noun','의상 디자인','The art of creating costumes for theatre or film.','She studied {costume design} in college.','그녀는 대학에서 의상 디자인을 공부했어요.','costume design','A2','culture',3,'costume design fashion sewing theater'),
('w_culture_A2_33','narrator','/ˈnærɪtər/','noun','나레이터, 해설자','A person who narrates a story or gives a commentary.','The {narrator} had a wonderful voice.','나레이터는 훌륭한 목소리를 갖고 있었어요.','narrator','A2','culture',2,'narrator reading microphone storytelling'),
('w_culture_A2_34','interval','/ˈɪntərvəl/','noun','인터미션, 막간','A pause or break in a performance.','We had drinks during the {interval}.','인터미션 동안 음료를 마셨어요.','interval','A2','culture',3,'theater lobby intermission drinks people'),
('w_culture_A2_35','programme','/ˈproʊɡræm/','noun','프로그램 (공연)','A booklet with information about a performance or event.','I kept the {programme} as a souvenir.','기념으로 공연 프로그램을 간직했어요.','programme','A2','culture',2,'concert program booklet theater event');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_culture_B1_01','heritage','/ˈherɪtɪdʒ/','noun','유산, 문화유산','Property, tradition, or culture passed down from the past.','We must protect our cultural {heritage}.','우리는 문화유산을 보호해야 해요.','heritage','B1','culture',1,'cultural heritage ancient ruins historic site'),
('w_culture_B1_02','contemporary','/kənˈtempəreri/','adjective','현대적인, 동시대의','Existing or happening at the same time as the present.','I prefer {contemporary} art to classical styles.','저는 고전 양식보다 현대 미술을 선호해요.','contemporary','B1','culture',1,'contemporary art gallery modern sculpture'),
('w_culture_B1_03','genre','/ˈʒɑːnrə/','noun','장르','A category of art, music, or literature defined by style.','What {genre} of music do you prefer?','어떤 장르의 음악을 선호하세요?','genre','B1','culture',1,'music genre vinyl record collection'),
('w_culture_B1_04','curator','/kjʊˈreɪtər/','noun','큐레이터','A person responsible for selecting and looking after items in a museum.','The {curator} explained the meaning of each painting.','큐레이터가 각 그림의 의미를 설명해 줬어요.','curator','B1','culture',2,'museum curator art gallery explaining'),
('w_culture_B1_05','aesthetic','/esˈθetɪk/','adjective','미학적인, 심미적인','Concerned with beauty and the appreciation of art.','I admire the {aesthetic} quality of Japanese design.','저는 일본 디자인의 미학적 품질을 감탄해요.','aesthetic','B1','culture',2,'aesthetic minimalist design art japanese'),
('w_culture_B1_06','classical','/ˈklæsɪkəl/','adjective','고전적인, 클래식의','Relating to ancient Greek or Roman culture, or traditional art forms.','She plays {classical} violin at a conservatory.','그녀는 음악원에서 클래식 바이올린을 연주해요.','classical','B1','culture',1,'classical music violin concert hall'),
('w_culture_B1_07','modern','/ˈmɒdərn/','adjective','현대적인, 근대의','Of or relating to the present or recent times.','{Modern} art can be difficult to interpret.','현대 미술은 해석하기 어려울 수 있어요.','modern','B1','culture',1,'modern art museum abstract painting'),
('w_culture_B1_08','folk','/foʊk/','adjective','민속의, 전통 민요의','Relating to the traditional art, music, or culture of a community.','The {folk} music festival was very lively.','민속 음악 축제가 매우 활기찼어요.','folk','B1','culture',2,'folk music traditional instrument village'),
('w_culture_B1_09','indigenous','/ɪnˈdɪdʒɪnəs/','adjective','토착의, 원주민의','Originating or occurring naturally in a particular place.','The exhibition showcased {indigenous} art forms.','그 전시회는 토착 예술 형태를 선보였어요.','indigenous','B1','culture',2,'indigenous art traditional tribal cultural'),
('w_culture_B1_10','symbolism','/ˈsɪmbəlɪzəm/','noun','상징주의, 상징성','The use of symbols to represent ideas or qualities.','The {symbolism} in this painting is very layered.','이 그림의 상징성은 매우 다층적이에요.','symbolism','B1','culture',2,'symbolism painting art meaning mysterious'),
('w_culture_B1_11','inspired','/ɪnˈspaɪərd/','adjective','영감 받은','Of extraordinary quality, as if from a divine source.','The sculpture was clearly {inspired} by nature.','그 조각품은 분명히 자연에서 영감을 받았어요.','inspired','B1','culture',1,'inspired artist creative nature landscape'),
('w_culture_B1_12','rhythm','/ˈrɪðəm/','noun','리듬, 박자','A strong regular repeated pattern of sound or movement.','The {rhythm} of the drum was hypnotic.','드럼의 리듬이 최면적이었어요.','rhythm','B1','culture',1,'rhythm drum beats music performance'),
('w_culture_B1_13','composition','/ˌkɒmpəˈzɪʃən/','noun','구성, 작곡','A piece of music, writing, or art; the way elements are arranged.','The {composition} uses bold contrasts of colour.','그 구성은 색채의 강렬한 대조를 사용해요.','composition','B1','culture',2,'musical composition score notes piano'),
('w_culture_B1_14','masterpiece','/ˈmɑːstərpiːs/','noun','걸작','A work of outstanding artistry, skill, or workmanship.','This painting is considered a {masterpiece}.','이 그림은 걸작으로 여겨져요.','masterpiece','B1','culture',1,'masterpiece famous painting museum louvre'),
('w_culture_B1_15','portrait','/ˈpɔːrtrɪt/','noun','초상화, 인물 사진','A painting, drawing, or photograph of a person.','She sat for a {portrait} by a local artist.','그녀는 지역 화가에게 초상화를 그려달라고 앉았어요.','portrait','B1','culture',2,'portrait painting face oil canvas museum'),
('w_culture_B1_16','landscape','/ˈlændskeɪp/','noun','풍경화, 경치','A painting that shows natural scenery.','The {landscape} paintings in this gallery are breathtaking.','이 갤러리의 풍경화들은 숨막히게 아름다워요.','landscape','B1','culture',1,'landscape painting countryside field oil'),
('w_culture_B1_17','biography','/baɪˈɒɡrəfi/','noun','전기, 자서전','A written account of someone''s life.','The {biography} of the composer was fascinating.','그 작곡가의 전기는 매우 흥미로웠어요.','biography','B1','culture',2,'biography book musician composer reading'),
('w_culture_B1_18','narrative','/ˈnærətɪv/','noun','서사, 이야기 방식','A spoken or written account of events; a story.','The film''s {narrative} is told from multiple perspectives.','그 영화의 서사는 여러 시각에서 전달돼요.','narrative','B1','culture',2,'narrative story film cinema storytelling'),
('w_culture_B1_19','technique','/tekˈniːk/','noun','기법, 기술','A way of carrying out a particular task in art or music.','Her {technique} on the violin is flawless.','그녀의 바이올린 기법은 완벽해요.','technique','B1','culture',1,'painting technique brush canvas art studio'),
('w_culture_B1_20','influence','/ˈɪnfluəns/','noun','영향, 영향력','The power to have an effect on others.','His work had a huge {influence} on modern jazz.','그의 작품은 현대 재즈에 큰 영향을 미쳤어요.','influence','B1','culture',1,'artistic influence inspiration creative history'),
('w_culture_B1_21','movement','/ˈmuːvmənt/','noun','(예술) 운동, 사조','A group of people working together to advance shared ideas.','Impressionism was a revolutionary art {movement}.','인상주의는 혁명적인 예술 운동이었어요.','movement','B1','culture',1,'impressionism art movement painting monet'),
('w_culture_B1_22','exhibition tour','/ˌeksɪˈbɪʃən tʊr/','noun','전시 투어','A guided walk through an exhibition with explanation.','We joined a guided {exhibition tour}.','저희는 안내 전시 투어에 참여했어요.','exhibition tour','B1','culture',2,'guided tour museum art exhibit group'),
('w_culture_B1_23','melody','/ˈmelədi/','noun','멜로디, 선율','A sequence of musical notes forming a pleasing tune.','The {melody} stayed in my head all day.','멜로디가 하루 종일 머릿속에 맴돌았어요.','melody','B1','culture',1,'melody music notes piano soft'),
('w_culture_B1_24','chorus','/ˈkɔːrəs/','noun','후렴구, 코러스','The part of a song repeated after each verse.','Everyone sang along to the {chorus}.','모두가 후렴구를 따라 불렀어요.','chorus','B1','culture',1,'chorus singing concert crowd stage'),
('w_culture_B1_25','tribute','/ˈtrɪbjuːt/','noun','헌정, 경의','Something done to show respect or admiration.','The concert was a {tribute} to a legendary musician.','그 콘서트는 전설적인 음악가에 대한 헌정이었어요.','tribute','B1','culture',2,'tribute concert musician legacy performance'),
('w_culture_B1_26','collaboration','/kəˌlæbəˈreɪʃən/','noun','협업, 공동 작업','Working jointly with others on a creative project.','The album was a {collaboration} between two artists.','그 앨범은 두 예술가의 협업이었어요.','collaboration','B1','culture',2,'collaboration artists creative studio together'),
('w_culture_B1_27','venue','/ˈvenjuː/','noun','공연 장소, 베뉴','The place where an event takes place.','The {venue} holds up to five thousand people.','그 공연 장소는 최대 5천 명을 수용해요.','venue','B1','culture',1,'concert venue hall building entrance'),
('w_culture_B1_28','acoustic','/əˈkuːstɪk/','adjective','어쿠스틱의, 음향의','Not electrically amplified; relating to sound.','I prefer {acoustic} guitar to electric guitar.','저는 일렉트릭 기타보다 어쿠스틱 기타를 선호해요.','acoustic','B1','culture',2,'acoustic guitar coffee shop intimate performance'),
('w_culture_B1_29','showcase','/ˈʃoʊkeɪs/','verb','선보이다, 전시하다','To display or exhibit something prominently.','The festival {showcase}s emerging local talent.','그 축제는 신흥 지역 인재를 선보여요.','showcase','B1','culture',2,'showcase talent performance stage spotlight'),
('w_culture_B1_30','revival','/rɪˈvaɪvəl/','noun','재현, 부활','A new performance of an old play or musical.','The {revival} of the classic musical was well received.','그 고전 뮤지컬의 재현은 호평을 받았어요.','revival','B1','culture',2,'revival theater classic musical performance'),
('w_culture_B1_31','dramatic','/drəˈmætɪk/','adjective','극적인, 연극적인','Relating to drama; sudden and striking.','The {dramatic} ending of the play left everyone speechless.','연극의 극적인 결말이 모두를 말문이 막히게 했어요.','dramatic','B1','culture',1,'dramatic stage performance theater lighting'),
('w_culture_B1_32','improvise','/ˈɪmprəvaɪz/','verb','즉흥 연주하다, 즉흥으로 하다','To create and perform spontaneously.','Jazz musicians often {improvise} during a performance.','재즈 음악가들은 공연 중에 자주 즉흥 연주를 해요.','improvise','B1','culture',2,'jazz improvise saxophone musician night'),
('w_culture_B1_33','gallery opening','/ˈɡæləri ˈoʊpənɪŋ/','noun','갤러리 오프닝','A special event to launch a new art exhibition.','I was invited to the {gallery opening} last Friday.','지난 금요일 갤러리 오프닝에 초대받았어요.','gallery opening','B1','culture',2,'gallery opening art event people socializing'),
('w_culture_B1_34','solo','/ˈsoʊloʊ/','noun','독주, 솔로','A performance done by one person alone.','He played a beautiful piano {solo}.','그는 아름다운 피아노 독주를 연주했어요.','solo','B1','culture',1,'solo performance musician stage spotlight'),
('w_culture_B1_35','atmosphere','/ˈætməsfɪər/','noun','분위기','The mood or feeling of a place or artistic work.','The concert hall had a magical {atmosphere}.','콘서트홀은 마법 같은 분위기가 있었어요.','atmosphere','B1','culture',1,'concert hall atmosphere warm lighting audience');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_culture_B2_01','avant-garde','/ˌævɑːnt ˈɡɑːrd/','adjective','전위적인, 아방가르드','New and experimental ideas in art, music, or literature.','His {avant-garde} compositions divided critics.','그의 전위적인 작품은 비평가들 사이에 의견이 갈렸어요.','avant-garde','B2','culture',2,'avant-garde art experimental gallery abstract'),
('w_culture_B2_02','abstract','/ˈæbstrækt/','adjective','추상적인','Not representing real things but expressing ideas through shapes and colours.','{Abstract} painting requires a different way of seeing.','추상화는 다른 방식의 시각을 요구해요.','abstract','B2','culture',1,'abstract painting colorful shapes modern art'),
('w_culture_B2_03','surrealism','/səˈrɪəlɪzəm/','noun','초현실주의','An art movement that uses strange, dreamlike imagery.','Dalí is the most famous figure of {surrealism}.','달리는 초현실주의의 가장 유명한 인물이에요.','surrealism','B2','culture',2,'surrealism dali dreamlike painting bizarre'),
('w_culture_B2_04','patronage','/ˈpeɪtrənɪdʒ/','noun','후원, 예술 지원','The support given by a patron to an artist or institution.','The arts depend heavily on corporate {patronage}.','예술은 기업 후원에 크게 의존해요.','patronage','B2','culture',2,'art patronage sponsor donation museum'),
('w_culture_B2_05','iconography','/ˌaɪkəˈnɒɡrəfi/','noun','도상학, 도상','Symbols and imagery associated with a subject in art.','Understanding the {iconography} enriches the viewing experience.','도상학을 이해하면 감상 경험이 풍부해져요.','iconography','B2','culture',3,'religious iconography painting symbols art museum'),
('w_culture_B2_06','postmodern','/ˌpoʊstˈmɒdərn/','adjective','포스트모던의','Relating to or denoting an artistic style that questions established norms.','The building''s design is unmistakably {postmodern}.','그 건물의 디자인은 명백히 포스트모던이에요.','postmodern','B2','culture',2,'postmodern architecture design building quirky'),
('w_culture_B2_07','critique','/krɪˈtiːk/','noun','비평, 평론','A detailed analysis and assessment of something.','The {critique} pointed out flaws in the film''s structure.','그 비평은 영화 구조의 결함을 지적했어요.','critique','B2','culture',1,'film critique review writing analysis'),
('w_culture_B2_08','interpretation','/ɪnˌtɜːrprɪˈteɪʃən/','noun','해석, 이해','An explanation of the meaning of something.','Each viewer brought their own {interpretation} to the work.','각 관람객은 작품에 자신만의 해석을 가져왔어요.','interpretation','B2','culture',1,'art interpretation gallery viewer thinking'),
('w_culture_B2_09','aesthetic movement','/esˈθetɪk ˈmuːvmənt/','noun','미학 운동','An artistic philosophy emphasising beauty for its own sake.','The {aesthetic movement} rejected Victorian moralism.','미학 운동은 빅토리아 시대의 도덕주의를 거부했어요.','aesthetic movement','B2','culture',2,'aesthetic art movement beauty decoration victorian'),
('w_culture_B2_10','cross-cultural','/ˌkrɒs ˈkʌltʃərəl/','adjective','다문화적인, 문화 간의','Relating to or involving different cultures.','The exhibition explored {cross-cultural} influences on design.','그 전시회는 디자인에 대한 다문화적 영향을 탐구했어요.','cross-cultural','B2','culture',2,'cross cultural diversity art multicultural'),
('w_culture_B2_11','curator''s note','/kjʊˈreɪtərz noʊt/','noun','큐레이터 노트','A written explanation provided by a curator about exhibits.','I read the {curator''s note} before entering the gallery.','갤러리에 들어가기 전에 큐레이터 노트를 읽었어요.','curator''s note','B2','culture',3,'curator note gallery text wall art'),
('w_culture_B2_12','controversy','/ˈkɒntrəvɜːrsi/','noun','논란, 논쟁','A prolonged public disagreement about a topic.','The painting caused considerable {controversy} when first shown.','그 그림은 처음 전시됐을 때 상당한 논란을 일으켰어요.','controversy','B2','culture',2,'art controversy debate media headlines'),
('w_culture_B2_13','commission','/kəˈmɪʃən/','noun','의뢰, 커미션','An instruction to produce a work of art.','The artist received a {commission} from the city council.','그 예술가는 시의회로부터 의뢰를 받았어요.','commission','B2','culture',2,'art commission artist studio painting'),
('w_culture_B2_14','installation','/ˌɪnstəˈleɪʃən/','noun','설치 미술','A large-scale artwork created for a specific space.','The {installation} filled the entire room with sound.','그 설치 미술이 방 전체를 소리로 채웠어요.','installation','B2','culture',2,'art installation contemporary museum space'),
('w_culture_B2_15','provenance','/ˈprɒvənəns/','noun','출처, 유래','The place of origin or earliest known history of a work.','The {provenance} of this sculpture is disputed.','이 조각품의 출처는 논쟁 중이에요.','provenance','B2','culture',3,'art provenance museum auction history'),
('w_culture_B2_16','retrospective','/ˌretrəˈspektɪv/','noun','회고전','An exhibition reviewing an artist''s work over many years.','A major {retrospective} of her paintings opens next spring.','그녀의 그림 대규모 회고전이 내년 봄에 열려요.','retrospective','B2','culture',2,'retrospective exhibition museum artist career'),
('w_culture_B2_17','multimedia','/ˌmʌltiˈmiːdiə/','adjective','멀티미디어의','Using more than one medium of expression.','The {multimedia} exhibition combined video, sound, and sculpture.','그 멀티미디어 전시는 영상, 소리, 조각을 결합했어요.','multimedia','B2','culture',2,'multimedia art installation video projection'),
('w_culture_B2_18','satire','/ˈsætaɪər/','noun','풍자','The use of humour or exaggeration to criticise society.','Political {satire} has a long history in literature.','정치적 풍자는 문학에서 오랜 역사를 갖고 있어요.','satire','B2','culture',2,'satire art political cartoon magazine'),
('w_culture_B2_19','censorship','/ˈsensərʃɪp/','noun','검열','The suppression of material considered harmful or offensive.','The film was altered due to {censorship}.','그 영화는 검열로 인해 수정됐어요.','censorship','B2','culture',2,'censorship media banned art freedom'),
('w_culture_B2_20','fusion','/ˈfjuːʒən/','noun','융합, 퓨전','The combination of different styles or cultures.','The band plays a {fusion} of jazz and traditional folk music.','그 밴드는 재즈와 전통 민속 음악의 퓨전을 연주해요.','fusion','B2','culture',1,'fusion music cultural blend performance'),
('w_culture_B2_21','immersive','/ɪˈmɜːrsɪv/','adjective','몰입형의','Providing deep mental involvement.','The {immersive} theatre experience blurred reality and fiction.','그 몰입형 연극 경험은 현실과 허구를 모호하게 했어요.','immersive','B2','culture',2,'immersive theater art experience vr projection'),
('w_culture_B2_22','groundbreaking','/ˈɡraʊndbreɪkɪŋ/','adjective','획기적인, 선구적인','Innovative and pioneering.','The director''s {groundbreaking} style changed cinema.','그 감독의 획기적인 스타일이 영화를 바꿨어요.','groundbreaking','B2','culture',1,'groundbreaking film cinema director innovation'),
('w_culture_B2_23','transcript','/ˈtrænskrɪpt/','noun','대본, 기록문','A written version of spoken or recorded text.','The {transcript} of the lecture was published online.','강의 대본이 온라인에 게시됐어요.','transcript','B2','culture',3,'lecture transcript text document reading'),
('w_culture_B2_24','acclaim','/əˈkleɪm/','noun','찬사, 호평','Enthusiastic and public praise.','The film received widespread {acclaim} from critics.','그 영화는 비평가들로부터 광범위한 찬사를 받았어요.','acclaim','B2','culture',1,'acclaim award ceremony applause film'),
('w_culture_B2_25','censure','/ˈsenʃər/','noun','비난, 견책','Strong disapproval or criticism.','The artwork faced widespread {censure} for its content.','그 예술 작품은 내용으로 인해 광범위한 비난을 받았어요.','censure','B2','culture',3,'criticism media controversy art reaction'),
('w_culture_B2_26','pastiche','/pæˈstiːʃ/','noun','패스티시, 혼성 모방','A work of art that imitates or is inspired by another work.','The film is a deliberate {pastiche} of 1950s noir.','그 영화는 1950년대 누아르를 의도적으로 모방한 작품이에요.','pastiche','B2','culture',3,'pastiche film noir retro cinema style'),
('w_culture_B2_27','depiction','/dɪˈpɪkʃən/','noun','묘사, 표현','A representation or portrayal of something in art.','The {depiction} of war in this painting is vivid.','이 그림에서 전쟁의 묘사는 생생해요.','depiction','B2','culture',2,'painting depiction war history art museum'),
('w_culture_B2_28','subversive','/səbˈvɜːrsɪv/','adjective','전복적인, 기존 체제에 도전하는','Seeking to undermine established ideas or authority.','The artist is known for her {subversive} installations.','그 예술가는 전복적인 설치 미술로 알려져 있어요.','subversive','B2','culture',3,'subversive street art urban graffiti'),
('w_culture_B2_29','commentary','/ˈkɒməntri/','noun','해설, 논평','A spoken or written explanation of events.','The documentary includes an insightful {commentary} on art history.','그 다큐멘터리는 미술사에 대한 통찰력 있는 해설을 포함해요.','commentary','B2','culture',2,'art documentary commentary film analysis'),
('w_culture_B2_30','stereotype','/ˈsteriətaɪp/','noun','고정관념','A widely held but fixed and oversimplified idea about a group.','The film challenges cultural {stereotype}s.','그 영화는 문화적 고정관념에 도전해요.','stereotype','B2','culture',2,'stereotype challenge diversity culture art'),
('w_culture_B2_31','benchmark','/ˈbentʃmɑːrk/','noun','기준, 척도','A standard against which things may be compared.','This film set the {benchmark} for visual effects.','이 영화는 시각 효과의 기준을 세웠어요.','benchmark','B2','culture',2,'benchmark excellence film industry award'),
('w_culture_B2_32','canon','/ˈkænən/','noun','정전, 기준 작품 목록','The accepted body of work considered most important in a field.','Shakespeare is central to the literary {canon}.','셰익스피어는 문학 정전의 핵심이에요.','canon','B2','culture',2,'literary canon books classic literature shelf'),
('w_culture_B2_33','motif','/moʊˈtiːf/','noun','모티프, 반복되는 주제','A recurring element or theme in a creative work.','Water is a key {motif} in Impressionist painting.','물은 인상주의 회화의 핵심 모티프예요.','motif','B2','culture',2,'monet water lilies impressionist motif art'),
('w_culture_B2_34','medium','/ˈmiːdiəm/','noun','매체, 재료 (예술)','The material or form used by an artist to create their work.','Oil paint is her chosen {medium}.','유화 물감은 그녀가 선택한 매체예요.','medium','B2','culture',1,'oil paint medium canvas art studio brushes'),
('w_culture_B2_35','allusion','/əˈluːʒən/','noun','암시, 인유','An indirect reference to another work or event.','The poem contains an {allusion} to Greek mythology.','그 시는 그리스 신화에 대한 암시를 담고 있어요.','allusion','B2','culture',3,'poetry myth reference classical literature');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_culture_C1_01','semiotics','/ˌsiːmiˈɒtɪks/','noun','기호학','The study of signs and symbols and their use or interpretation.','The professor lectured on {semiotics} and visual art.','교수가 기호학과 시각 예술에 대해 강의했어요.','semiotics','C1','culture',2,'semiotics signs symbols lecture university'),
('w_culture_C1_02','hermeneutics','/ˌhɜːrmɪˈnjuːtɪks/','noun','해석학','The theory of interpretation, especially of texts or art.','{Hermeneutics} offers a framework for reading literary works.','해석학은 문학 작품을 읽는 틀을 제공해요.','hermeneutics','C1','culture',3,'hermeneutics text interpretation study academic'),
('w_culture_C1_03','deconstruction','/ˌdiːkənˈstrʌkʃən/','noun','해체주의, 해체적 읽기','A method of critical analysis that questions assumed meanings.','Derrida''s {deconstruction} challenged stable textual meaning.','데리다의 해체주의는 안정된 텍스트의 의미에 도전했어요.','deconstruction','C1','culture',2,'deconstruction philosophy text theory academic'),
('w_culture_C1_04','phenomenology','/fɪˌnɒmɪˈnɒlədʒi/','noun','현상학','The philosophical study of the structures of experience.','{Phenomenology} helps explain how art is perceived.','현상학은 예술이 어떻게 인식되는지 설명하는 데 도움이 돼요.','phenomenology','C1','culture',3,'phenomenology experience philosophy art perception'),
('w_culture_C1_05','structuralism','/ˈstrʌktʃərəlɪzəm/','noun','구조주의','An approach that analyses elements of human culture as part of a larger system.','{Structuralism} views culture as a system of signs.','구조주의는 문화를 기호 체계로 봐요.','structuralism','C1','culture',2,'structuralism theory analysis diagram university'),
('w_culture_C1_06','intertextuality','/ˌɪntəˌtekstʃuˈælɪti/','noun','상호텍스트성','The relationship between texts and how they influence each other.','The novel is rich in {intertextuality}, referencing dozens of classic works.','그 소설은 수십 편의 고전 작품을 인용하며 상호텍스트성이 풍부해요.','intertextuality','C1','culture',2,'books library references intertextuality literature'),
('w_culture_C1_07','dialectic','/ˌdaɪəˈlektɪk/','noun','변증법','A method of argument by which contradictions are resolved.','Hegel''s {dialectic} influenced many art historians.','헤겔의 변증법은 많은 미술사가에게 영향을 미쳤어요.','dialectic','C1','culture',3,'dialectic philosophy argument debate theory'),
('w_culture_C1_08','mimesis','/mɪˈmiːsɪs/','noun','미메시스, 모방','The imitation of the real world in art and literature.','Aristotle introduced the concept of {mimesis} in the Poetics.','아리스토텔레스는 시학에서 미메시스 개념을 소개했어요.','mimesis','C1','culture',3,'aristotle poetics philosophy art imitation'),
('w_culture_C1_09','catharsis','/kəˈθɑːrsɪs/','noun','카타르시스, 정화','Emotional release brought about by art, drama, or music.','Greek tragedy was designed to produce {catharsis} in the audience.','그리스 비극은 관객에게 카타르시스를 일으키도록 설계됐어요.','catharsis','C1','culture',2,'catharsis theater audience emotion dramatic'),
('w_culture_C1_10','sublime','/səˈblaɪm/','adjective','숭고한, 장엄한','Of great beauty or awe that inspires moral elevation.','Turner''s seascapes evoke the {sublime} in nature.','터너의 해양화는 자연의 숭고함을 불러일으켜요.','sublime','C1','culture',2,'sublime landscape nature dramatic storm painting'),
('w_culture_C1_11','aestheticism','/esˈθetɪsɪzəm/','noun','유미주의','A 19th-century doctrine that art exists for its own sake.','Wilde embodied the spirit of {aestheticism}.','와일드는 유미주의의 정신을 구현했어요.','aestheticism','C1','culture',3,'oscar wilde aestheticism art beauty 19th century'),
('w_culture_C1_12','hyperrealism','/ˌhaɪpərˈriːəlɪzəm/','noun','극사실주의','An art movement producing images that appear more real than photographs.','His paintings belong to the tradition of {hyperrealism}.','그의 그림은 극사실주의 전통에 속해요.','hyperrealism','C1','culture',2,'hyperrealism painting photorealistic art detail'),
('w_culture_C1_13','zeitgeist','/ˈzaɪtɡaɪst/','noun','시대정신','The defining spirit or mood of a particular period.','The artist''s work captured the {zeitgeist} of the 1980s.','그 예술가의 작품은 1980년대의 시대정신을 포착했어요.','zeitgeist','C1','culture',2,'zeitgeist 80s culture art era spirit'),
('w_culture_C1_14','discourse','/ˈdɪskɔːrs/','noun','담론, 논의','A formal discussion or debate about a subject.','Critical {discourse} around the film was polarised.','그 영화를 둘러싼 비평적 담론은 양극화됐어요.','discourse','C1','culture',2,'academic discourse lecture panel discussion'),
('w_culture_C1_15','polyphony','/pəˈlɪfəni/','noun','폴리포니, 다성 음악','Music with several independent melody lines played at once.','Bach''s fugues demonstrate extraordinary {polyphony}.','바흐의 푸가는 놀라운 다성 음악을 보여줘요.','polyphony','C1','culture',2,'polyphony bach fugue classical music'),
('w_culture_C1_16','vernacular','/vərˈnækjʊlər/','noun','토착어, 일상 언어','The language or style used by ordinary people.','The poem was written in the {vernacular} of the working class.','그 시는 노동 계급의 일상 언어로 쓰였어요.','vernacular','C1','culture',2,'vernacular language poetry common people'),
('w_culture_C1_17','allegory','/ˈæləɡɔːri/','noun','우화, 알레고리','A story or artwork with a hidden symbolic meaning.','Orwell''s Animal Farm is a political {allegory}.','오웰의 동물 농장은 정치적 우화예요.','allegory','C1','culture',2,'allegory orwell animals painting symbolic'),
('w_culture_C1_18','trope','/troʊp/','noun','비유, 진부한 관용구','A figure of speech or an overused theme.','The "chosen one" is a common {trope} in fantasy literature.','선택받은 자는 판타지 문학에서 흔한 비유예요.','trope','C1','culture',2,'trope fantasy literature cliche narrative'),
('w_culture_C1_19','canonicity','/ˌkænəˈnɪsɪti/','noun','정전성','The state of being accepted as part of the literary or artistic canon.','Questions of {canonicity} often reflect cultural biases.','정전성 문제는 종종 문화적 편견을 반영해요.','canonicity','C1','culture',3,'canon literature books academic selection'),
('w_culture_C1_20','ekphrasis','/ekˈfreɪsɪs/','noun','에크프라시스','A literary description of a work of visual art.','Keats'' poem is a famous example of {ekphrasis}.','키츠의 시는 에크프라시스의 유명한 예시예요.','ekphrasis','C1','culture',3,'keats poem urn art description literary'),
('w_culture_C1_21','pathos','/ˈpeɪθɒs/','noun','파토스, 비애감','A quality that evokes pity or sadness in a work of art.','The final scene was full of {pathos}.','마지막 장면은 파토스로 가득 찼어요.','pathos','C1','culture',2,'theater drama final scene emotion tears'),
('w_culture_C1_22','ethos','/ˈiːθɒs/','noun','에토스, 특성, 정신','The characteristic spirit or values of a community or work.','The {ethos} of the Bauhaus was form follows function.','바우하우스의 에토스는 형태는 기능을 따른다는 것이었어요.','ethos','C1','culture',2,'bauhaus design ethos modernism school'),
('w_culture_C1_23','logos','/ˈloʊɡɒs/','noun','로고스, 논리적 호소','Rational appeal in persuasion; logical argument.','The documentary builds its case through {logos}.','그 다큐멘터리는 논리적 호소를 통해 주장을 구성해요.','logos','C1','culture',3,'documentary logic argument persuasion analysis'),
('w_culture_C1_24','liminal','/ˈlɪmɪnəl/','adjective','경계적인, 과도기적인','Relating to a transitional stage or threshold.','The painting depicts a {liminal} space between day and night.','그 그림은 낮과 밤 사이의 경계적 공간을 묘사해요.','liminal','C1','culture',3,'liminal space dusk twilight threshold painting'),
('w_culture_C1_25','polemic','/pəˈlemɪk/','noun','논쟁적 글, 논쟁','A strong verbal or written attack on someone''s opinions.','His essay reads as a {polemic} against commercialism in art.','그의 에세이는 예술의 상업주의에 대한 논쟁적 글로 읽혀요.','polemic','C1','culture',3,'debate essay critique art criticism writing'),
('w_culture_C1_26','meta-narrative','/ˈmetə ˈnærətɪv/','noun','메타 내러티브','An overarching story that gives structure to a culture.','Postmodernism questions grand {meta-narrative}s.','포스트모더니즘은 거대한 메타 내러티브에 의문을 제기해요.','meta-narrative','C1','culture',2,'postmodern narrative theory books academic'),
('w_culture_C1_27','synaesthesia','/ˌsɪnɪsˈθiːziə/','noun','공감각','A condition in which one sense is stimulated and another is also experienced.','His {synaesthesia} made music visible as colour.','그의 공감각은 음악을 색깔로 볼 수 있게 했어요.','synaesthesia','C1','culture',3,'synaesthesia colour sound music art brain'),
('w_culture_C1_28','appropriation','/əˌproʊpriˈeɪʃən/','noun','전용, 차용','Taking elements from existing works and using them in new art.','Pop art relied heavily on cultural {appropriation}.','팝 아트는 문화적 전용에 크게 의존했어요.','appropriation','C1','culture',2,'appropriation pop art warhol culture remix'),
('w_culture_C1_29','hegemony','/hɪˈdʒeməni/','noun','헤게모니, 문화적 지배','Dominance of one cultural or social group over others.','Western {hegemony} has shaped global art institutions.','서구 헤게모니는 글로벌 예술 기관을 형성해왔어요.','hegemony','C1','culture',2,'hegemony power culture western global art'),
('w_culture_C1_30','plurality','/plʊˈrælɪti/','noun','다원성, 복수성','The state of being numerous or diverse.','Contemporary curating celebrates cultural {plurality}.','현대 큐레이팅은 문화적 다원성을 기념해요.','plurality','C1','culture',2,'diversity plural cultures museum exhibition'),
('w_culture_C1_31','contingency','/kənˈtɪndʒənsi/','noun','우연성, 상황 의존성','The quality of being dependent on uncertain conditions.','The meaning of art is marked by {contingency}.','예술의 의미는 우연성으로 특징지어져요.','contingency','C1','culture',3,'chance contingency art philosophy abstract'),
('w_culture_C1_32','reflexivity','/ˌriːflekˈsɪvɪti/','noun','반성성, 자기 인식','The quality of examining one''s own assumptions.','Documentary filmmaking requires a degree of {reflexivity}.','다큐멘터리 제작은 어느 정도의 반성성을 요구해요.','reflexivity','C1','culture',3,'reflexivity documentary filmmaker camera self'),
('w_culture_C1_33','transmedial','/trænsˈmiːdiəl/','adjective','트랜스미디어의','Relating to a narrative that extends across multiple media.','The franchise is a {transmedial} storytelling project.','그 프랜차이즈는 트랜스미디어 스토리텔링 프로젝트예요.','transmedial','C1','culture',3,'transmedia storytelling franchise media narrative'),
('w_culture_C1_34','diegesis','/ˌdaɪˈdʒiːsɪs/','noun','디에게시스, 이야기 세계','The world of the story as opposed to the real world.','The narrator exists outside the {diegesis} of the film.','나레이터는 영화의 이야기 세계 밖에 존재해요.','diegesis','C1','culture',3,'film narrator story world theory'),
('w_culture_C1_35','bricoleur','/ˌbrɪkəˈlɜːr/','noun','브리콜뢰르 (창의적 조합가)','Someone who creates something from diverse materials at hand.','The artist sees herself as a cultural {bricoleur}.','그 예술가는 자신을 문화적 브리콜뢰르로 봐요.','bricoleur','C1','culture',3,'bricolage artist found objects creative assemblage');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_culture_C2_01','ontology','/ɒnˈtɒlədʒi/','noun','존재론','The branch of philosophy dealing with the nature of being.','The {ontology} of the artwork is contested by critics.','작품의 존재론은 비평가들 사이에서 논쟁 중이에요.','ontology','C2','culture',3,'ontology philosophy being existence academic'),
('w_culture_C2_02','episteme','/ˈepɪstiːm/','noun','에피스테메, 지식 체계','A system of understanding that defines what counts as knowledge in an era.','Foucault''s concept of {episteme} transformed cultural theory.','푸코의 에피스테메 개념은 문화 이론을 변화시켰어요.','episteme','C2','culture',3,'foucault episteme knowledge structure theory'),
('w_culture_C2_03','heteroglossia','/ˌhetərəˈɡlɒsiə/','noun','헤테로글로시아, 다성성','The coexistence of multiple voices and languages in a text.','Bakhtin''s notion of {heteroglossia} celebrates linguistic diversity.','바흐친의 헤테로글로시아 개념은 언어적 다양성을 기념해요.','heteroglossia','C2','culture',3,'bakhtin language diversity voices text theory'),
('w_culture_C2_04','aporia','/əˈpɔːriə/','noun','아포리아, 논리적 교착','An irresolvable contradiction or logical impasse in a text or argument.','The text exposes an {aporia} at the heart of Western humanism.','그 텍스트는 서구 인문주의의 핵심에 있는 아포리아를 드러내요.','aporia','C2','culture',3,'aporia derrida philosophy contradiction text'),
('w_culture_C2_05','palimpsest','/ˈpælɪmpsest/','noun','팔림프세스트, 흔적의 중첩','A manuscript on which old writing has been overwritten; a place marked by history.','The city functions as a cultural {palimpsest}.','도시는 문화적 팔림프세스트로 기능해요.','palimpsest','C2','culture',3,'palimpsest history layers city manuscript'),
('w_culture_C2_06','bricolage','/ˈbrɪkəlɑːʒ/','noun','브리콜라주, 혼합적 창작','Construction or creation from diverse elements already available.','Her film is a {bricolage} of archive footage and personal memoir.','그녀의 영화는 아카이브 영상과 개인 회고록의 브리콜라주예요.','bricolage','C2','culture',3,'bricolage film collage archive mixed media art'),
('w_culture_C2_07','logocentrism','/ˌloʊɡoʊˈsentrɪzəm/','noun','로고중심주의','The tendency in Western thought to privilege speech and reason over writing.','Derrida''s critique targets {logocentrism} in philosophy.','데리다의 비판은 철학의 로고중심주의를 겨냥해요.','logocentrism','C2','culture',3,'derrida logocentrism philosophy text western'),
('w_culture_C2_08','differance','/ˌdɪfəˈrɑːns/','noun','디페랑스 (데리다 개념)','Derrida''s term for the way meaning is endlessly deferred in language.','The concept of {differance} resists fixed meaning.','디페랑스 개념은 고정된 의미에 저항해요.','differance','C2','culture',3,'derrida differance language meaning philosophy'),
('w_culture_C2_09','rhizome','/ˈraɪzoʊm/','noun','리좀 (들뢰즈 개념)','Deleuze and Guattari''s model of culture as non-hierarchical and interconnected.','Their theory proposes a {rhizome} model of knowledge.','그들의 이론은 지식의 리좀 모델을 제안해요.','rhizome','C2','culture',3,'rhizome deleuze network diagram philosophy'),
('w_culture_C2_10','hypertext','/ˈhaɪpərtekst/','noun','하이퍼텍스트','Text with embedded links connecting to other texts or resources.','{Hypertext} has transformed how we read and write.','하이퍼텍스트는 우리가 읽고 쓰는 방식을 변화시켰어요.','hypertext','C2','culture',2,'hypertext internet links digital reading'),
('w_culture_C2_11','simulacrum','/ˌsɪmjʊˈleɪkrəm/','noun','시뮬라크르 (보드리야르)','A copy of something that no longer has an original.','Baudrillard argues that media creates a world of pure {simulacrum}.','보드리야르는 미디어가 순수한 시뮬라크르의 세계를 만든다고 주장해요.','simulacrum','C2','culture',3,'baudrillard simulacrum media image reality'),
('w_culture_C2_12','subaltern','/ˈsʌbəltərn/','noun','하위주체','A person or group with no significant social power.','Spivak asks whether the {subaltern} can speak.','스피박은 하위주체가 말할 수 있는가를 물어요.','subaltern','C2','culture',3,'spivak subaltern postcolonial theory marginalized'),
('w_culture_C2_13','genealogy','/ˌdʒiːniˈælədʒi/','noun','계보학 (푸코)','Foucault''s method of tracing the historical development of discourses.','His {genealogy} of modern art traced its origins to enlightenment ideals.','그의 현대 미술 계보학은 그 기원을 계몽주의 이상으로 추적했어요.','genealogy','C2','culture',3,'genealogy foucault history discourse analysis'),
('w_culture_C2_14','hauntology','/hɔːnˈtɒlədʒi/','noun','유령론','Derrida''s concept of cultures haunted by the past.','Fisher applied {hauntology} to describe contemporary pop music.','피셔는 유령론을 현대 팝 음악을 묘사하는 데 적용했어요.','hauntology','C2','culture',3,'hauntology ghost past culture music derrida'),
('w_culture_C2_15','jouissance','/ʒuˈiːsɒns/','noun','쥬이상스 (라캉), 향유','Intense pleasure or enjoyment beyond the pleasure principle.','Lacan''s concept of {jouissance} influenced film theory greatly.','라캉의 쥬이상스 개념은 영화 이론에 큰 영향을 미쳤어요.','jouissance','C2','culture',3,'lacan jouissance film theory psychoanalysis'),
('w_culture_C2_16','abject','/ˈæbdʒekt/','adjective','비체의, 혐오감을 주는','Relating to Kristeva''s concept of what society rejects to define itself.','Horror films exploit the {abject} to disturb the viewer.','공포 영화는 관객을 불안하게 하기 위해 비체를 활용해요.','abject','C2','culture',3,'horror film uncanny abject theory kristeva'),
('w_culture_C2_17','heterotopia','/ˌhetərəˈtoʊpiə/','noun','헤테로토피아 (푸코)','A space that exists outside normal social order, yet mirrors it.','Foucault described the museum as a {heterotopia}.','푸코는 박물관을 헤테로토피아로 묘사했어요.','heterotopia','C2','culture',3,'foucault museum heterotopia space gallery'),
('w_culture_C2_18','deterritorialisation','/diːˌterɪˌtɔːriəlaɪˈzeɪʃən/','noun','탈영토화','Deleuze''s term for the dissolution of fixed cultural identities.','Globalisation is seen as a process of cultural {deterritorialisation}.','세계화는 문화적 탈영토화 과정으로 여겨져요.','deterritorialisation','C2','culture',3,'globalisation culture flux identity deleuze'),
('w_culture_C2_19','intersubjectivity','/ˌɪntəˌsʌbdʒekˈtɪvɪti/','noun','상호주관성','Shared understanding between subjects; the basis of communication.','Art''s meaning depends on {intersubjectivity} between viewer and work.','예술의 의미는 관람객과 작품 사이의 상호주관성에 달려 있어요.','intersubjectivity','C2','culture',3,'art viewer interaction gallery shared meaning'),
('w_culture_C2_20','paratext','/ˈpærətekst/','noun','주변텍스트 (제네트)','Elements surrounding a text, such as titles, prefaces, and covers.','Genette showed how the {paratext} frames the reader''s experience.','제네트는 주변텍스트가 독자의 경험을 어떻게 틀 짓는지 보여줬어요.','paratext','C2','culture',3,'book cover title preface paratext genette'),
('w_culture_C2_21','defamiliarisation','/diːfəˌmɪliəraɪˈzeɪʃən/','noun','낯설게하기','The artistic technique of presenting familiar objects as strange.','Shklovsky''s theory of {defamiliarisation} underpins formalist criticism.','슈클로프스키의 낯설게하기 이론은 형식주의 비평을 뒷받침해요.','defamiliarisation','C2','culture',3,'defamiliarisation art strange familiar formalism'),
('w_culture_C2_22','interpellation','/ɪnˌtɜːrpəˈleɪʃən/','noun','호명 (알튀세르)','Althusser''s concept of how ideology addresses individuals as subjects.','Advertising relies on {interpellation} to create loyal consumers.','광고는 충성스러운 소비자를 만들기 위해 호명에 의존해요.','interpellation','C2','culture',3,'althusser ideology advertising subject theory'),
('w_culture_C2_23','spectatorship','/ˈspektətərʃɪp/','noun','관람 행위, 관객성','The activity and theory of watching or viewing art or film.','Feminist film theory transformed debates on {spectatorship}.','페미니스트 영화 이론은 관객성 논쟁을 변화시켰어요.','spectatorship','C2','culture',3,'film spectatorship audience gaze feminist theory'),
('w_culture_C2_24','chronotope','/ˈkrɒnətoʊp/','noun','크로노토프 (바흐친)','Bakhtin''s term for the intrinsic connection of time and space in literature.','The road novel relies on a specific {chronotope}.','도로 소설은 특정 크로노토프에 의존해요.','chronotope','C2','culture',3,'bakhtin chronotope time space novel theory'),
('w_culture_C2_25','acousmatic','/ˌækʊzˈmætɪk/','adjective','아쿠스마틱의, 음원이 보이지 않는','Relating to sound heard without a visible source.','Schaeffer pioneered {acousmatic} music in the 1940s.','쉐페르는 1940년대에 아쿠스마틱 음악을 개척했어요.','acousmatic','C2','culture',3,'acousmatic sound music abstract speaker experimental'),
('w_culture_C2_26','clinamen','/klɪˈneɪmən/','noun','클리나멘 (창조적 일탈)','Harold Bloom''s term for a poet''s swerve away from a precursor.','Bloom sees originality as {clinamen} from the tradition.','블룸은 독창성을 전통으로부터의 클리나멘으로 봐요.','clinamen','C2','culture',3,'bloom poetry influence originality tradition'),
('w_culture_C2_27','pharmakon','/ˈfɑːrmækɒn/','noun','파르마콘 (데리다)','Derrida''s term for something that is simultaneously poison and remedy.','Writing is a {pharmakon}: both aid and threat to memory.','글쓰기는 파르마콘이에요: 기억에 대한 도움이자 위협이에요.','pharmakon','C2','culture',3,'derrida pharmakon writing memory poison remedy'),
('w_culture_C2_28','polysemy','/pəˈlɪsɪmi/','noun','다의성','The quality of having multiple meanings.','The poem''s {polysemy} invites many different readings.','그 시의 다의성은 다양한 해석을 초대해요.','polysemy','C2','culture',3,'polysemy language meaning ambiguity literary'),
('w_culture_C2_29','ekphrastic','/ekˈfræstɪk/','adjective','에크프라시스적인','Relating to a literary description of a work of visual art.','Keats'' ode is one of the great {ekphrastic} poems.','키츠의 송시는 위대한 에크프라시스 시 중 하나예요.','ekphrastic','C2','culture',3,'keats ode poem art description literary ekphrasis'),
('w_culture_C2_30','xenoglossy','/ˌziːnəˈɡlɒsi/','noun','이국어 사용 현상','The apparent ability to speak an unknown language.','The novel plays with the idea of cultural {xenoglossy}.','그 소설은 문화적 이국어 사용의 아이디어를 가지고 놀아요.','xenoglossy','C2','culture',3,'language unknown foreign speaking mystical'),
('w_culture_C2_31','praxis','/ˈprækˈsɪs/','noun','실천, 실천적 활동','Practice as opposed to theory; the application of theory to action.','For Brecht, theatre was always a form of political {praxis}.','브레히트에게 연극은 항상 정치적 실천의 형태였어요.','praxis','C2','culture',3,'brecht theater praxis practice theory political'),
('w_culture_C2_32','hybridity','/haɪˈbrɪdɪti/','noun','혼종성 (호미 바바)','Homi Bhabha''s concept of identity formed between cultures.','Postcolonial art celebrates {hybridity} as creative strength.','포스트식민주의 예술은 혼종성을 창조적 강점으로 기념해요.','hybridity','C2','culture',3,'bhabha hybridity postcolonial culture identity'),
('w_culture_C2_33','enunciation','/ɪˌnʌnsiˈeɪʃən/','noun','발화, 언표 행위','The act of stating or articulating something; in semiotics, the act of producing a sign.','The film''s mode of {enunciation} implicates the viewer.','그 영화의 발화 방식은 관람객을 연루시켜요.','enunciation','C2','culture',3,'semiotics film enunciation viewer speech act'),
('w_culture_C2_34','apophenia','/ˌæpəˈfiːniə/','noun','아포페니아, 임의 연결 지각','The tendency to perceive meaningful connections between unrelated things.','Conspiracy theories exploit our tendency toward {apophenia}.','음모론은 아포페니아를 향한 우리의 경향을 이용해요.','apophenia','C2','culture',3,'pattern recognition connection conspiracy theory mind'),
('w_culture_C2_35','thanatopolitics','/ˌθænətəˈpɒlɪtɪks/','noun','죽음 정치학 (아감벤)','Agamben''s concept of power exercised through the management of death.','{Thanatopolitics} shapes whose lives and deaths are mourned in culture.','죽음 정치학은 문화에서 누구의 삶과 죽음이 애도되는지를 형성해요.','thanatopolitics','C2','culture',3,'agamben politics death power culture mourning');
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_culture_A1_01','What kind of music do you like?','어떤 음악 좋아해요?','What kind of','What kind of...?는 종류나 취향을 물을 때 쓰는 기본 패턴이에요.','취향 묻기','A1','culture','pattern',NULL,1),
('s_culture_A1_02','Do you like movies or books more?','영화를 더 좋아해요, 아니면 책을 더 좋아해요?','Do you like ... more?','"Do you like A or B more?"는 둘 중 하나를 고르게 할 때 쓰는 간단한 패턴이에요.','취향 비교','A1','culture','pattern',NULL,2),
('s_culture_A1_03','What is your favourite song?','가장 좋아하는 노래가 뭐예요?','What is your favourite','What is your favourite...?는 영어로 취향을 가장 자연스럽게 묻는 방법이에요.','좋아하는 것 묻기','A1','culture','pattern',NULL,3),
('s_culture_A1_04','I love listening to music.','저는 음악 듣는 걸 좋아해요.','I love listening to','"I love -ing"는 자신이 좋아하는 활동을 말할 때 쓰는 패턴이에요.','취향 말하기','A1','culture','pattern',NULL,4),
('s_culture_A1_05','Can you dance?','춤출 수 있어요?','Can you','Can you...?는 상대방의 능력을 물어볼 때 가장 기본적인 패턴이에요.','능력 묻기','A1','culture','pattern',NULL,5),
('s_culture_A1_06','Do you play any instruments?','악기를 연주할 수 있어요?','Do you play','Do you play any...?는 취미나 특기를 물어볼 때 유용한 패턴이에요.','취미 묻기','A1','culture','pattern',NULL,6),
('s_culture_A1_07','I enjoy watching shows at the theatre.','저는 극장에서 공연 보는 것을 즐겨요.','I enjoy watching','"I enjoy -ing"는 자신의 즐거운 활동을 부드럽게 표현하는 패턴이에요.','취미 표현','A1','culture','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_culture_A2_01','Have you ever been to a music festival?','음악 축제에 가본 적 있어요?','Have you ever been to','Have you ever...?는 경험을 자연스럽게 물어볼 때 자주 쓰는 패턴이에요.','경험 묻기','A2','culture','pattern',NULL,1),
('s_culture_A2_02','What time does the concert start?','콘서트가 몇 시에 시작해요?','What time does','What time does...?는 시작 시간을 물을 때 기본적으로 쓰는 패턴이에요.','공연 정보 묻기','A2','culture','pattern',NULL,2),
('s_culture_A2_03','Is there a ticket office nearby?','근처에 매표소가 있나요?','Is there a','Is there a...?는 어떤 장소나 시설이 있는지 물을 때 쓰는 패턴이에요.','장소 묻기','A2','culture','pattern',NULL,3),
('s_culture_A2_04','I''d like two tickets for the evening show, please.','저녁 공연 티켓 두 장 주세요.','I''d like','I''d like...는 무언가를 정중하게 요청할 때 쓰는 가장 흔한 패턴이에요.','티켓 구매','A2','culture','pattern',NULL,4),
('s_culture_A2_05','The exhibition was really impressive.','전시회가 정말 인상적이었어요.','was really impressive','was/were really impressive는 무언가에 강한 긍정 반응을 나타낼 때 쓰는 패턴이에요.','공연 후기','A2','culture','pattern',NULL,5),
('s_culture_A2_06','Can I take photos inside the gallery?','갤러리 안에서 사진을 찍어도 될까요?','Can I take photos','Can I...?는 허락을 구할 때 쓰는 가장 기본적인 패턴이에요.','허락 구하기','A2','culture','pattern',NULL,6),
('s_culture_A2_07','How long does the performance last?','공연이 얼마나 걸려요?','How long does','How long does...?는 어떤 일이 얼마나 오래 걸리는지 물을 때 쓰는 패턴이에요.','시간 묻기','A2','culture','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_culture_B1_01','What I find most interesting about this painting is the use of colour.','이 그림에서 가장 흥미로운 점은 색채 사용 방식이에요.','What I find most interesting','"What I find most interesting is..."는 자신의 감상을 구체적으로 표현할 때 쓰는 세련된 패턴이에요.','예술 감상 표현','B1','culture','pattern',NULL,1),
('s_culture_B1_02','This piece really speaks to me on an emotional level.','이 작품은 감정적으로 정말 제 마음에 와닿아요.','really speaks to me','"speaks to me"는 예술 작품이 자신에게 감동이나 공명을 줄 때 원어민이 자주 쓰는 표현이에요.','예술 공감 표현','B1','culture','pattern',NULL,2),
('s_culture_B1_03','I wasn''t sure what to make of it at first, but it grew on me.','처음엔 어떻게 받아들여야 할지 몰랐지만, 점점 좋아졌어요.','grew on me','"grow on me"는 처음에는 마음에 들지 않다가 나중에 좋아지게 됐을 때 쓰는 표현이에요.','감상 변화 표현','B1','culture','pattern',NULL,3),
('s_culture_B1_04','There''s something deeply moving about the way the story unfolds.','이야기가 전개되는 방식에는 깊이 감동적인 무언가가 있어요.','There''s something ... about','"There''s something ... about"는 추상적이고 감동적인 인상을 표현할 때 쓰는 고급 패턴이에요.','작품 인상 표현','B1','culture','pattern',NULL,4),
('s_culture_B1_05','Have you had a chance to see the new exhibition at the gallery?','갤러리에서 새로운 전시회를 볼 기회가 있으셨어요?','Have you had a chance to','"Have you had a chance to...?"는 상대방의 경험을 자연스럽게 물어보는 패턴이에요.','경험 묻기 (공손)','B1','culture','pattern',NULL,5),
('s_culture_B1_06','The atmosphere in the concert hall was absolutely electric.','콘서트홀의 분위기가 완전히 전율적이었어요.','absolutely electric','absolutely + 강한 형용사는 감동적인 순간을 생생하게 전달하는 B1 표현 패턴이에요.','공연 분위기 표현','B1','culture','pattern',NULL,6),
('s_culture_B1_07','I''d strongly recommend this exhibition to anyone interested in modern art.','현대 미술에 관심 있는 분이라면 이 전시회를 강력히 추천해요.','I''d strongly recommend ... to anyone','"I''d strongly recommend ... to anyone interested in..."은 적극적인 추천을 표현하는 패턴이에요.','추천 표현','B1','culture','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_culture_B2_01','While Korean pop culture has a global reach, traditional art forms still hold a central place in national identity.','한국 팝 문화가 세계적으로 확산됐지만, 전통 예술 형태는 여전히 국가 정체성에서 중심적인 위치를 차지해요.','While ... still hold','While A, B still...는 두 가지 사실을 대조할 때 쓰는 B2 수준의 접속 패턴이에요.','문화 비교','B2','culture','pattern',NULL,1),
('s_culture_B2_02','There''s a growing tension between preserving cultural heritage and embracing contemporary influences.','문화유산을 보존하는 것과 현대적 영향을 받아들이는 것 사이의 긴장이 커지고 있어요.','tension between ... and','"tension between A and B"는 두 가지 상충하는 가치를 논의할 때 쓰는 고급 표현이에요.','문화 긴장 표현','B2','culture','pattern',NULL,2),
('s_culture_B2_03','The way a culture treats its artists says a lot about its values.','한 문화가 예술가를 대하는 방식은 그 문화의 가치관에 대해 많은 것을 말해줘요.','says a lot about','"says a lot about..."는 어떤 행동이나 상황이 더 깊은 의미를 드러낸다고 할 때 쓰는 표현이에요.','문화 가치관 논의','B2','culture','pattern',NULL,3),
('s_culture_B2_04','Cross-cultural exchange has always been central to artistic innovation.','문화 간 교류는 항상 예술적 혁신의 핵심이었어요.','Cross-cultural exchange has always been','Cross-cultural ... has always been...는 역사적 패턴을 논의할 때 쓰는 학문적 표현이에요.','문화 교류 논의','B2','culture','pattern',NULL,4),
('s_culture_B2_05','What sets this work apart is its willingness to challenge conventional expectations.','이 작품을 돋보이게 하는 것은 기존의 기대에 도전하려는 의지예요.','What sets this work apart','"What sets ... apart is..."는 무언가를 차별화하는 특징을 강조하는 세련된 패턴이에요.','작품 차별점 표현','B2','culture','pattern',NULL,5),
('s_culture_B2_06','It''s worth noting that the artist''s background heavily shaped the work''s cultural references.','예술가의 배경이 작품의 문화적 참조에 크게 영향을 미쳤다는 점은 주목할 만해요.','It''s worth noting that','"It''s worth noting that..."는 중요한 사실을 강조하며 논의에 도입할 때 쓰는 학술적 패턴이에요.','분석적 논의','B2','culture','pattern',NULL,6),
('s_culture_B2_07','The debate over cultural appropriation raises uncomfortable but necessary questions.','문화 전용에 관한 논쟁은 불편하지만 필요한 질문들을 제기해요.','raises uncomfortable but necessary questions','"raises ... questions"는 논쟁적 주제를 신중하게 도입할 때 쓰는 표현이에요.','문화 논쟁 표현','B2','culture','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_culture_C1_01','The work''s power lies precisely in its refusal to offer easy resolution.','이 작품의 힘은 바로 쉬운 해결을 거부하는 데 있어요.','lies precisely in its refusal to','"lies precisely in its refusal to..."는 작품의 핵심 특질을 정확히 짚을 때 쓰는 고급 비평 표현이에요.','예술 비평','C1','culture','pattern',NULL,1),
('s_culture_C1_02','One might argue that the narrative structure mirrors the fragmented nature of modern consciousness.','서사 구조가 현대 의식의 파편화된 본성을 반영한다고 주장할 수 있어요.','One might argue that ... mirrors','"One might argue that..."는 비평적 주장을 신중하게 제시할 때 쓰는 학술적 표현이에요.','예술 비평 논의','C1','culture','pattern',NULL,2),
('s_culture_C1_03','The tension between form and content is never fully resolved in this piece.','이 작품에서 형식과 내용 사이의 긴장은 결코 완전히 해결되지 않아요.','tension between form and content is never fully resolved','"tension between ... is never fully resolved"는 예술 분석에서 양가성을 표현하는 고급 패턴이에요.','예술 분석','C1','culture','pattern',NULL,3),
('s_culture_C1_04','Rather than offering answers, the exhibition poses a series of provocative questions about identity.','답을 제시하기보다는 전시회가 정체성에 대한 일련의 도발적인 질문을 제기해요.','Rather than ... poses a series of provocative questions','"Rather than A, B poses questions about..."는 반전 구조로 작품의 의도를 설명하는 패턴이에요.','전시 분석','C1','culture','pattern',NULL,4),
('s_culture_C1_05','What distinguishes this director''s work is the interplay between the personal and the political.','이 감독의 작품을 구별하는 것은 개인적인 것과 정치적인 것 사이의 상호작용이에요.','What distinguishes ... is the interplay between','"What distinguishes ... is the interplay between A and B"는 비평적 특징 분석의 정교한 패턴이에요.','감독 분석','C1','culture','pattern',NULL,5),
('s_culture_C1_06','The film operates on multiple registers simultaneously — aesthetic, political, and psychological.','그 영화는 미학적, 정치적, 심리적으로 여러 차원에서 동시에 작동해요.','operates on multiple registers simultaneously','"operates on multiple registers"는 복잡한 예술 작품의 다층적 의미를 표현하는 C1 비평 표현이에요.','영화 비평','C1','culture','pattern',NULL,6),
('s_culture_C1_07','By foregrounding the constructedness of its own narrative, the novel invites us to question the nature of storytelling itself.','자신의 서사가 구성물임을 전면에 내세움으로써, 그 소설은 우리가 스토리텔링의 본질 자체를 의문시하도록 유도해요.','By foregrounding the constructedness of','"By foregrounding the constructedness of..."는 메타픽션적 기법을 분석하는 고급 비평 패턴이에요.','소설 비평','C1','culture','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_culture_C2_01','The work enacts a deconstruction of the very categories it appears to celebrate.','그 작품은 자신이 기리는 것처럼 보이는 바로 그 범주들을 해체하는 것을 수행해요.','enacts a deconstruction of the very categories','"enacts a deconstruction of the very..."는 데리다적 독해를 수행할 때 쓰는 C2 수준의 비평 표현이에요.','해체주의 비평','C2','culture','pattern',NULL,1),
('s_culture_C2_02','To speak of aesthetic autonomy is already to invoke a historically contingent set of assumptions.','미학적 자율성을 말하는 것은 이미 역사적으로 우연적인 일련의 가정들을 불러오는 것이에요.','To speak of ... is already to invoke','"To speak of ... is already to invoke..."는 개념의 역사성을 드러내는 고도로 학술적인 패턴이에요.','미학 담론','C2','culture','pattern',NULL,2),
('s_culture_C2_03','The question is not whether the text has a meaning, but who has the authority to determine it.','문제는 텍스트가 의미를 가지느냐가 아니라 누가 그것을 결정할 권위를 갖느냐예요.','The question is not whether ... but who has the authority','"The question is not whether A but who..."는 권력과 해석에 관한 담론을 수행하는 C2 패턴이에요.','해석 권력 논의','C2','culture','pattern',NULL,3),
('s_culture_C2_04','Any attempt to stabilise the work''s meaning is already a political act.','작품의 의미를 안정화하려는 모든 시도는 이미 정치적 행위예요.','Any attempt to ... is already a political act','"Any attempt to... is already..."는 학술 비평에서 강한 주장을 펼칠 때 쓰는 C2 표현이에요.','정치적 비평','C2','culture','pattern',NULL,4),
('s_culture_C2_05','What the archive reveals is not just what was recorded but what was systematically excluded.','아카이브가 드러내는 것은 기록된 것뿐만 아니라 체계적으로 배제된 것이에요.','What the archive reveals is not just ... but what was systematically excluded','"What ... reveals is not just A but what was systematically excluded"는 권력과 기억을 분석하는 C2 패턴이에요.','아카이브 비평','C2','culture','pattern',NULL,5),
('s_culture_C2_06','The sublime, far from being a natural category, is a cultural construction that serves specific ideological ends.','숭고함은 자연적 범주이기는커녕 특정 이데올로기적 목적에 기여하는 문화적 구성물이에요.','far from being a natural category, is a cultural construction','far from being A, is a cultural construction that serves...는 개념을 역사화하는 고급 비평 패턴이에요.','숭고 이론 비평','C2','culture','pattern',NULL,6),
('s_culture_C2_07','In displacing the centre, the work opens up a rhizomatic field of possible meanings that resist hierarchical ordering.','중심을 이동시킴으로써, 그 작품은 위계적 정렬에 저항하는 의미의 리좀적 장을 열어요.','In displacing the centre ... opens up a rhizomatic field','"In displacing the centre, ... opens up a rhizomatic field"는 들뢰즈적 분석을 수행하는 최고 수준의 비평 패턴이에요.','리좀 비평','C2','culture','pattern',NULL,7);
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_sports_A1_01','run','/rʌn/','verb','달리다','To move quickly on foot.','I {run} every morning in the park.','저는 매일 아침 공원에서 달려요.','run','A1','sports',1,'running person park morning exercise'),
('w_sports_A1_02','play','/pleɪ/','verb','(스포츠를) 하다','To take part in a sport or game.','Do you {play} football on weekends?','주말에 축구 하세요?','play','A1','sports',1,'kids playing football field fun'),
('w_sports_A1_03','win','/wɪn/','verb','이기다','To finish first or be the best in a competition.','Our team wants to {win} the match.','우리 팀은 경기에서 이기고 싶어요.','win','A1','sports',1,'winning team trophy celebration cheering'),
('w_sports_A1_04','lose','/luːz/','verb','지다','To not win a game or competition.','It''s okay to {lose} sometimes — you learn from it.','가끔 지는 건 괜찮아요. 거기서 배우니까요.','lose','A1','sports',2,'sad athlete losing game disappointment'),
('w_sports_A1_05','team','/tiːm/','noun','팀','A group of people who play or work together.','I joined a basketball {team} last month.','지난달에 농구 팀에 들어갔어요.','team','A1','sports',1,'sports team group together jerseys'),
('w_sports_A1_06','ball','/bɔːl/','noun','공','A round object used in many sports.','Kick the {ball} into the goal.','공을 골대 안으로 차세요.','ball','A1','sports',1,'soccer ball football grass sport'),
('w_sports_A1_07','game','/ɡeɪm/','noun','경기, 게임','An activity with rules in which people compete.','The {game} starts at seven tonight.','경기는 오늘 밤 7시에 시작돼요.','game','A1','sports',1,'sports game stadium crowd night'),
('w_sports_A1_08','swim','/swɪm/','verb','수영하다','To move through water using the body.','She can {swim} very fast.','그녀는 수영을 아주 빠르게 할 수 있어요.','swim','A1','sports',1,'swimmer pool water lane splash'),
('w_sports_A1_09','jump','/dʒʌmp/','verb','점프하다','To push yourself off the ground into the air.','He can {jump} over one meter high.','그는 1미터 이상 높이 뛸 수 있어요.','jump','A1','sports',1,'athlete jumping high jump track field'),
('w_sports_A1_10','fast','/fæst/','adjective','빠른','Moving or able to move at high speed.','The runner is very {fast}.','그 달리기 선수는 정말 빠르네요.','fast','A1','sports',2,'sprinter running track fast speed motion'),
('w_sports_A1_11','sport','/spɔːrt/','noun','스포츠, 운동','An activity involving physical effort and skill, often competitive.','What is your favourite {sport}?','제일 좋아하는 스포츠가 뭐예요?','sport','A1','sports',1,'various sports equipment collage'),
('w_sports_A1_12','kick','/kɪk/','verb','차다','To hit something with your foot.','{Kick} the ball toward the goal.','공을 골대 쪽으로 차세요.','Kick','A1','sports',2,'football player kicking ball action'),
('w_sports_A1_13','throw','/θroʊ/','verb','던지다','To send something through the air by moving your arm.','Can you {throw} me the ball?','공 좀 던져줄 수 있어요?','throw','A1','sports',2,'athlete throwing ball action sport'),
('w_sports_A1_14','catch','/kætʃ/','verb','잡다','To take hold of something moving through the air.','Try to {catch} the ball with both hands.','두 손으로 공을 잡아보세요.','catch','A1','sports',2,'player catching ball baseball glove'),
('w_sports_A1_15','hit','/hɪt/','verb','치다, 때리다','To strike something with force.','She {hit} the ball over the net.','그녀가 공을 네트 너머로 쳤어요.','hit','A1','sports',2,'tennis player hitting ball racket'),
('w_sports_A1_16','goal','/ɡoʊl/','noun','골, 목표','A point scored in football or hockey, or the target itself.','He scored a {goal} in the last minute.','그는 마지막 1분에 골을 넣었어요.','goal','A1','sports',1,'soccer goal net ball scored'),
('w_sports_A1_17','race','/reɪs/','noun','경주','A competition to see who is the fastest.','I want to run in a 5km {race} next month.','다음 달에 5킬로미터 달리기 경주에 나가고 싶어요.','race','A1','sports',1,'runners race track competition start line'),
('w_sports_A1_18','walk','/wɔːk/','verb','걷다','To move at a regular pace by lifting and setting down each foot.','Let''s {walk} to the stadium together.','같이 걸어서 경기장에 가요.','walk','A1','sports',3,'people walking park morning exercise'),
('w_sports_A1_19','strong','/strɔːŋ/','adjective','강한','Having great physical power.','Athletes need to be {strong} and flexible.','운동선수는 강하고 유연해야 해요.','strong','A1','sports',2,'strong athlete muscles workout gym'),
('w_sports_A1_20','tired','/taɪərd/','adjective','피곤한','Feeling like you need to rest or sleep.','I feel {tired} after the long practice.','긴 연습 후에 피곤해요.','tired','A1','sports',2,'tired athlete resting bench sweat'),
('w_sports_A1_21','water','/ˈwɔːtər/','noun','물','A liquid that people drink, especially important during exercise.','Drink plenty of {water} during exercise.','운동 중에는 물을 충분히 마세요.','water','A1','sports',2,'athlete drinking water bottle sports'),
('w_sports_A1_22','tennis','/ˈtenɪs/','noun','테니스','A sport played with rackets on a court.','I play {tennis} every Saturday morning.','저는 매주 토요일 아침에 테니스를 쳐요.','tennis','A1','sports',2,'tennis court player racket ball'),
('w_sports_A1_23','football','/ˈfʊtbɔːl/','noun','축구 (= 미식 축구)','A sport played with a ball between two teams.','He watched a {football} match on TV.','그는 TV로 축구 경기를 봤어요.','football','A1','sports',2,'football game stadium crowd green field'),
('w_sports_A1_24','gym','/dʒɪm/','noun','체육관','A room or building with equipment for physical exercise.','I go to the {gym} three times a week.','일주일에 세 번 헬스장에 가요.','gym','A1','sports',1,'gym workout equipment weights fitness'),
('w_sports_A1_25','score','/skɔːr/','noun','점수','The number of points made in a game or competition.','What is the {score}?','지금 점수가 어떻게 돼요?','score','A1','sports',1,'scoreboard sports stadium numbers game'),
('w_sports_A1_26','easy','/ˈiːzi/','adjective','쉬운','Not difficult.','This exercise is not {easy} for beginners.','이 운동은 초보자에게 쉽지 않아요.','easy','A1','sports',3,'beginner exercise simple movement'),
('w_sports_A1_27','hard','/hɑːrd/','adjective','힘든, 어려운','Requiring a great deal of endurance or effort.','Training every day is really {hard}.','매일 훈련하는 것은 정말 힘들어요.','hard','A1','sports',2,'athlete training hard workout intense'),
('w_sports_A1_28','start','/stɑːrt/','verb','시작하다','To begin doing something.','The race will {start} in five minutes.','경주는 5분 후에 시작돼요.','start','A1','sports',2,'race start line gun whistle athletes ready'),
('w_sports_A1_29','stop','/stɒp/','verb','멈추다','To cease doing something or moving.','The referee told everyone to {stop}.','심판이 모두에게 멈추라고 했어요.','stop','A1','sports',3,'referee whistle stop game players'),
('w_sports_A1_30','outside','/ˌaʊtˈsaɪd/','adverb','야외에서','In the open air.','Playing {outside} is good for your health.','야외에서 운동하면 건강에 좋아요.','outside','A1','sports',3,'outdoor sport kids playing field sun'),
('w_sports_A1_31','friend','/frend/','noun','친구','A person you know and like.','I play basketball with my {friend}s.','친구들과 농구를 해요.','friend','A1','sports',3,'friends playing sport together laughing'),
('w_sports_A1_32','bike','/baɪk/','noun','자전거','A two-wheeled vehicle you ride by pedalling.','I ride my {bike} to the park every weekend.','저는 매주 주말마다 자전거를 타고 공원에 가요.','bike','A1','sports',2,'cyclist riding bike park path outdoor'),
('w_sports_A1_33','move','/muːv/','verb','움직이다','To change position; to be physically active.','{Move} your body every day to stay healthy.','건강을 유지하려면 매일 몸을 움직이세요.','Move','A1','sports',2,'person stretching moving body exercise'),
('w_sports_A1_34','practice','/ˈpræktɪs/','noun','연습','Repeated exercise to improve skill.','We have {practice} every Tuesday evening.','매주 화요일 저녁에 연습이 있어요.','practice','A1','sports',1,'team practice training field players coach'),
('w_sports_A1_35','cool','/kuːl/','adjective','멋진, 훌륭한','Impressively good; also used for temperature.','That was a really {cool} move!','그것은 정말 멋진 동작이었어요!','cool','A1','sports',3,'impressive sports move dunk skateboard');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_sports_A2_01','match','/mætʃ/','noun','경기','A game or contest between two teams or players.','Did you watch the football {match} last night?','어제 밤 축구 경기 봤어요?','match','A2','sports',1,'football match stadium crowd evening lights'),
('w_sports_A2_02','score','/skɔːr/','verb','득점하다','To gain a point or goal in a game.','She {scored} twice in the second half.','그녀는 후반전에 두 번 득점했어요.','scored','A2','sports',1,'athlete scoring goal celebration team'),
('w_sports_A2_03','practice','/ˈpræktɪs/','verb','연습하다','To do an activity repeatedly to improve.','You need to {practice} every day if you want to improve.','실력을 키우려면 매일 연습해야 해요.','practice','A2','sports',1,'athlete practicing skill repetition field'),
('w_sports_A2_04','athlete','/ˈæθliːt/','noun','운동선수','A person who is skilled in sports or physical exercise.','She is a professional {athlete} who runs marathons.','그녀는 마라톤을 뛰는 프로 운동선수예요.','athlete','A2','sports',1,'professional athlete training track stadium'),
('w_sports_A2_05','stadium','/ˈsteɪdiəm/','noun','경기장','A large structure with a field where sports are played.','The {stadium} was full of excited fans.','경기장은 흥분한 팬들로 가득 찼어요.','stadium','A2','sports',1,'large stadium full crowd sports event'),
('w_sports_A2_06','coach','/koʊtʃ/','noun','코치, 감독','A person who trains and instructs a team or player.','Our {coach} told us to stay focused.','코치님이 집중하라고 하셨어요.','coach','A2','sports',1,'sports coach giving instructions team players'),
('w_sports_A2_07','train','/treɪn/','verb','훈련하다','To practise or exercise for a sport.','He {trains} for two hours every day.','그는 매일 두 시간씩 훈련해요.','trains','A2','sports',1,'athlete training workout gym sweat'),
('w_sports_A2_08','compete','/kəmˈpiːt/','verb','경쟁하다','To take part in a competition or contest.','She will {compete} in the national championships.','그녀는 전국 대회에 참가할 거예요.','compete','A2','sports',1,'athletes competing race track field'),
('w_sports_A2_09','trophy','/ˈtroʊfi/','noun','트로피','A prize given to the winner of a competition.','The team held up the {trophy} after winning.','팀이 우승 후 트로피를 높이 들었어요.','trophy','A2','sports',1,'sports trophy golden cup winners celebration'),
('w_sports_A2_10','champion','/ˈtʃæmpiən/','noun','챔피언, 우승자','The winner of a competition or title.','She became the national swimming {champion}.','그녀는 전국 수영 챔피언이 됐어요.','champion','A2','sports',1,'champion athlete gold medal podium victory'),
('w_sports_A2_11','support','/səˈpɔːrt/','verb','응원하다','To give encouragement or help to someone.','All the fans came to {support} their team.','팬들이 모두 팀을 응원하러 왔어요.','support','A2','sports',2,'fans cheering supporting team stadium'),
('w_sports_A2_12','captain','/ˈkæptɪn/','noun','주장','The leader of a sports team.','She was chosen as the team {captain}.','그녀가 팀 주장으로 선발됐어요.','captain','A2','sports',1,'team captain armband leading players'),
('w_sports_A2_13','league','/liːɡ/','noun','리그','A group of sports teams that compete with each other.','Their team was promoted to a higher {league}.','그 팀이 더 높은 리그로 승격됐어요.','league','A2','sports',1,'football league table standings clubs'),
('w_sports_A2_14','final','/ˈfaɪnəl/','noun','결승전','The last and most important game in a competition.','We made it to the {final}!','우리가 결승에 올라갔어요!','final','A2','sports',1,'sports final match big stadium broadcast'),
('w_sports_A2_15','season','/ˈsiːzən/','noun','시즌','The period during which a sport is played.','The football {season} starts in August.','축구 시즌은 8월에 시작돼요.','season','A2','sports',2,'sports season calendar schedule fixtures'),
('w_sports_A2_16','fan','/fæn/','noun','팬, 응원자','A person who admires a sport, team, or athlete.','He is a huge {fan} of basketball.','그는 농구를 정말 좋아하는 팬이에요.','fan','A2','sports',2,'sports fan wearing jersey cheering stadium'),
('w_sports_A2_17','injury','/ˈɪndʒəri/','noun','부상','Harm done to the body, especially in sport.','He missed the match because of an {injury}.','그는 부상 때문에 경기를 뛰지 못했어요.','injury','A2','sports',1,'athlete injured knee treatment sports'),
('w_sports_A2_18','improve','/ɪmˈpruːv/','verb','향상되다','To get better at something.','You will {improve} if you practise regularly.','규칙적으로 연습하면 실력이 늘어요.','improve','A2','sports',1,'athlete improving skill training progress chart'),
('w_sports_A2_19','record','/ˈrekərd/','noun','기록','The best performance in a sport.','She broke the world {record} for the 100m sprint.','그녀가 100미터 단거리 세계 기록을 깼어요.','record','A2','sports',1,'world record sports achievement stopwatch'),
('w_sports_A2_20','fitness','/ˈfɪtnəs/','noun','체력, 건강 상태','The condition of being physically healthy and strong.','Regular exercise improves your {fitness} level.','규칙적인 운동이 체력을 향상시켜요.','fitness','A2','sports',1,'fitness gym workout health active'),
('w_sports_A2_21','round','/raʊnd/','noun','라운드, 회전','One stage of a competition.','They won in the first {round}.','그들은 1라운드에서 이겼어요.','round','A2','sports',2,'boxing round match ring bell'),
('w_sports_A2_22','draw','/drɔː/','noun','무승부','A result in which neither team wins.','The match ended in a {draw}.','경기가 무승부로 끝났어요.','draw','A2','sports',2,'sports draw tie equal score board'),
('w_sports_A2_23','warm up','/wɔːrm ʌp/','phrase','준비 운동을 하다','To do gentle exercise before a sport.','Always {warm up} before you start running.','달리기를 시작하기 전에 항상 준비 운동을 하세요.','warm up','A2','sports',1,'athlete warming up stretching before run'),
('w_sports_A2_24','defeat','/dɪˈfiːt/','verb','물리치다','To beat someone in a competition.','We {defeated} the opposing team 3–0.','우리가 상대팀을 3대 0으로 물리쳤어요.','defeated','A2','sports',2,'winning team defeating opponent celebrate'),
('w_sports_A2_25','foul','/faʊl/','noun','파울, 반칙','An action in sport that breaks the rules.','The referee gave a {foul} against the striker.','심판이 스트라이커에게 파울을 선언했어요.','foul','A2','sports',2,'referee calling foul football yellow card'),
('w_sports_A2_26','retire','/rɪˈtaɪər/','verb','은퇴하다','To stop playing a sport professionally.','The famous tennis player decided to {retire}.','그 유명한 테니스 선수가 은퇴하기로 결정했어요.','retire','A2','sports',2,'athlete retirement farewell speech press conference'),
('w_sports_A2_27','spectator','/spekˈteɪtər/','noun','관중, 관람객','A person who watches a sport or event.','Thousands of {spectators} filled the stands.','수천 명의 관중이 스탠드를 가득 채웠어요.','spectators','A2','sports',2,'spectators watching sports stadium crowd cheering'),
('w_sports_A2_28','award','/əˈwɔːrd/','noun','상, 어워드','A prize given for achievement.','She received the best player {award} of the season.','그녀는 시즌 최우수 선수상을 받았어요.','award','A2','sports',2,'sports award ceremony trophy podium'),
('w_sports_A2_29','pool','/puːl/','noun','수영장','An indoor or outdoor area filled with water for swimming.','She trains in the {pool} every morning.','그녀는 매일 아침 수영장에서 훈련해요.','pool','A2','sports',1,'swimming pool lanes indoor athletic training'),
('w_sports_A2_30','court','/kɔːrt/','noun','코트 (테니스·농구 등)','A marked area where a sport such as tennis is played.','The basketball {court} was newly renovated.','농구 코트가 새로 단장됐어요.','court','A2','sports',2,'basketball court indoor arena hardwood'),
('w_sports_A2_31','pitch','/pɪtʃ/','noun','경기장 잔디 (축구 등)','A grassy area on which football or cricket is played.','The players ran onto the {pitch}.','선수들이 경기장으로 뛰어나왔어요.','pitch','A2','sports',2,'football pitch grass green lines stadium'),
('w_sports_A2_32','cheer','/tʃɪər/','verb','응원하다','To shout encouragement to support a team.','The crowd began to {cheer} loudly.','군중이 크게 응원하기 시작했어요.','cheer','A2','sports',2,'crowd cheering stadium noise celebration'),
('w_sports_A2_33','result','/rɪˈzʌlt/','noun','결과','The score or outcome of a game or competition.','What was the {result} of last night''s game?','어젯밤 경기 결과가 어떻게 됐어요?','result','A2','sports',1,'sports result scoreboard final standings'),
('w_sports_A2_34','sprint','/sprɪnt/','verb','전력 질주하다','To run very fast for a short distance.','She {sprinted} to the finish line.','그녀가 결승선까지 전력 질주했어요.','sprinted','A2','sports',2,'sprinter finish line fast track athlete'),
('w_sports_A2_35','medal','/ˈmedəl/','noun','메달','A metal disc awarded to winners of a competition.','She won a gold {medal} at the Olympics.','그녀는 올림픽에서 금메달을 땄어요.','medal','A2','sports',1,'gold medal olympics podium winner sport');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_sports_B1_01','tournament','/ˈtʊrnəmənt/','noun','토너먼트, 대회','A series of contests between teams or players.','We entered a national {tournament} last summer.','지난여름에 전국 토너먼트에 참가했어요.','tournament','B1','sports',1,'sports tournament bracket competition teams'),
('w_sports_B1_02','strategy','/ˈstrætədʒi/','noun','전략','A plan designed to achieve a goal.','The coach explained the team''s {strategy} for the final.','코치가 결승전을 위한 팀 전략을 설명했어요.','strategy','B1','sports',1,'sports strategy whiteboard tactics coach'),
('w_sports_B1_03','injury','/ˈɪndʒəri/','noun','부상 (심화)','Significant physical damage to the body stopping play.','He is recovering from a serious knee {injury}.','그는 심각한 무릎 부상에서 회복 중이에요.','injury','B1','sports',1,'sports injury knee treatment physiotherapy'),
('w_sports_B1_04','sportsmanship','/ˈspɔːrtsmənʃɪp/','noun','스포츠맨십','Fair and generous behaviour in sport.','Winning is important, but {sportsmanship} matters more.','이기는 것도 중요하지만, 스포츠맨십이 더 중요해요.','sportsmanship','B1','sports',2,'athletes shaking hands respect fair play'),
('w_sports_B1_05','referee','/ˌrefəˈriː/','noun','심판','An official who ensures rules are followed in a sport.','The {referee} blew the whistle for full time.','심판이 종료 휘슬을 불었어요.','referee','B1','sports',1,'referee whistle yellow card football game'),
('w_sports_B1_06','penalty','/ˈpenəlti/','noun','패널티, 벌칙','A punishment for breaking a rule in sport.','The team was awarded a {penalty} kick.','그 팀에게 패널티 킥이 주어졌어요.','penalty','B1','sports',1,'penalty kick football goalkeeper spot'),
('w_sports_B1_07','sponsor','/ˈspɒnsər/','noun','후원자, 스폰서','A company or person who gives money to support sport.','The event''s main {sponsor} is a sports drink brand.','대회의 주요 스폰서는 스포츠 음료 브랜드예요.','sponsor','B1','sports',2,'sports sponsor logo jersey event banner'),
('w_sports_B1_08','league','/liːɡ/','noun','프로 리그','An organised competition among several teams.','He plays in the top professional {league}.','그는 최상위 프로 리그에서 뛰어요.','league','B1','sports',1,'professional football league table clubs'),
('w_sports_B1_09','championship','/ˈtʃæmpiənʃɪp/','noun','선수권 대회','A competition to find the best team or player.','She won the world {championship} three times.','그녀는 세계 선수권 대회에서 세 번 우승했어요.','championship','B1','sports',1,'world championship trophy ceremony stadium'),
('w_sports_B1_10','endurance','/ɪnˈdjʊərəns/','noun','지구력','The ability to maintain effort for a long time.','Marathon runners need excellent {endurance}.','마라톤 선수는 뛰어난 지구력이 필요해요.','endurance','B1','sports',1,'marathon runner long distance endurance'),
('w_sports_B1_11','formation','/fɔːrˈmeɪʃən/','noun','포메이션, 대형','The way players are positioned on a field.','The coach changed the team''s {formation} at halftime.','코치가 하프타임에 팀의 포메이션을 바꿨어요.','formation','B1','sports',2,'football formation tactics board'),
('w_sports_B1_12','substitute','/ˈsʌbstɪtjuːt/','noun','교체 선수','A player who enters the game to replace another.','The coach made a {substitute} in the 70th minute.','코치가 70분에 선수 교체를 했어요.','substitute','B1','sports',2,'player substitution warm up sideline bench'),
('w_sports_B1_13','transfer','/ˈtrænsfɜːr/','noun','이적','Moving from one sports team to another.','His {transfer} to a European club was big news.','그의 유럽 클럽 이적은 큰 뉴스였어요.','transfer','B1','sports',2,'football player transfer signing new jersey'),
('w_sports_B1_14','qualification','/ˌkwɒlɪfɪˈkeɪʃən/','noun','예선 통과, 자격 획득','The process of reaching a required standard to enter.','The team secured {qualification} for the World Cup.','그 팀이 월드컵 본선 진출권을 확보했어요.','qualification','B1','sports',2,'team celebrating qualification world cup'),
('w_sports_B1_15','stamina','/ˈstæmɪnə/','noun','지구력, 스태미나','Physical or mental endurance over a long period.','Building {stamina} requires consistent training.','스태미나를 키우려면 꾸준한 훈련이 필요해요.','stamina','B1','sports',1,'runner endurance long distance stamina training'),
('w_sports_B1_16','momentum','/məˈmentəm/','noun','기세, 모멘텀','A driving force that makes something continue.','The team gained {momentum} after the first goal.','첫 골을 넣은 후 팀의 기세가 올라갔어요.','momentum','B1','sports',2,'sports momentum team energy crowd excitement'),
('w_sports_B1_17','offside','/ˌɒfˈsaɪd/','adjective','오프사이드의','In a position not allowed by the rules of a sport.','The goal was disallowed for {offside}.','그 골은 오프사이드로 취소됐어요.','offside','B1','sports',2,'football offside flag referee rule'),
('w_sports_B1_18','dribble','/ˈdrɪbəl/','verb','드리블하다','To move a ball forward using repeated small kicks or bounces.','He {dribbled} past three defenders before scoring.','그는 세 명의 수비수를 제치고 드리블한 후 득점했어요.','dribbled','B1','sports',2,'football player dribbling past defenders'),
('w_sports_B1_19','overtime','/ˈoʊvərtaɪm/','noun','연장전','Extra time added to the end of a match.','The game went to {overtime} after a 1–1 draw.','경기가 1대 1 무승부 후 연장전에 돌입했어요.','overtime','B1','sports',2,'overtime football match extra time clock'),
('w_sports_B1_20','comeback','/ˈkʌmbæk/','noun','역전, 복귀','A recovery in sport after being behind.','The team made an incredible {comeback} in the second half.','팀이 후반전에 믿을 수 없는 역전을 이뤄냈어요.','comeback','B1','sports',1,'sports comeback celebration victory underdog'),
('w_sports_B1_21','underdog','/ˈʌndərdɒɡ/','noun','약팀, 불리한 쪽','A competitor expected to lose.','Everyone was surprised when the {underdog} won.','약팀이 이기자 모두가 놀랐어요.','underdog','B1','sports',2,'underdog winning upset celebration surprise'),
('w_sports_B1_22','motivate','/ˈmoʊtɪveɪt/','verb','동기를 부여하다','To give someone a reason or desire to do something.','The coach knows how to {motivate} the players.','코치는 선수들에게 동기를 부여하는 방법을 알아요.','motivate','B1','sports',2,'coach motivating players team talk locker room'),
('w_sports_B1_23','discipline','/ˈdɪsɪplɪn/','noun','규율, 자기 관리','Training that produces self-control and skill.','Athletic success requires great {discipline}.','운동 성공에는 대단한 자기 관리가 필요해요.','discipline','B1','sports',1,'athlete disciplined training routine focused'),
('w_sports_B1_24','setback','/ˈsetbæk/','noun','역경, 좌절','A problem that stops progress or makes things worse.','Every athlete faces {setback}s on the road to success.','모든 선수는 성공의 길에서 역경을 겪어요.','setback','B1','sports',2,'athlete sitting head down setback recovery'),
('w_sports_B1_25','versatile','/ˈvɜːrsətaɪl/','adjective','다재다능한','Able to perform many different sports or roles.','A {versatile} player can fill several positions.','다재다능한 선수는 여러 포지션을 소화할 수 있어요.','versatile','B1','sports',2,'player multiple positions versatile sport'),
('w_sports_B1_26','eliminate','/ɪˈlɪmɪneɪt/','verb','탈락시키다','To remove a team or player from a competition.','They were {eliminated} in the quarter-finals.','그들은 8강에서 탈락했어요.','eliminated','B1','sports',2,'sports elimination knockout bracket stage'),
('w_sports_B1_27','recover','/rɪˈkʌvər/','verb','회복하다','To return to a normal state of health after injury.','It took six months for him to {recover} fully.','그가 완전히 회복하는 데 6개월이 걸렸어요.','recover','B1','sports',1,'athlete recovery physiotherapy rehab sports'),
('w_sports_B1_28','squad','/skwɒd/','noun','스쿼드, 선발 명단','The full group of players from which a team is selected.','The coach announced the {squad} for the tournament.','코치가 토너먼트 스쿼드를 발표했어요.','squad','B1','sports',2,'football squad team photo lineup uniform'),
('w_sports_B1_29','possession','/pəˈzeʃən/','noun','볼 점유율','In sport, having control of the ball.','The team kept {possession} for most of the game.','그 팀이 경기 대부분 동안 볼 점유율을 유지했어요.','possession','B1','sports',2,'football possession stats ball control team'),
('w_sports_B1_30','rivalry','/ˈraɪvəlri/','noun','라이벌 관계','A strong competitive relationship between two teams.','The {rivalry} between those two clubs is legendary.','두 클럽 사이의 라이벌 관계는 전설적이에요.','rivalry','B1','sports',1,'sports rival teams classic match derby'),
('w_sports_B1_31','streak','/striːk/','noun','연승, 연속 기록','A series of wins or losses without a break.','The team is on a ten-game winning {streak}.','팀이 10경기 연승 행진 중이에요.','streak','B1','sports',2,'winning streak sports calendar consecutive wins'),
('w_sports_B1_32','outperform','/ˌaʊtpəˈfɔːrm/','verb','더 뛰어난 성과를 내다','To do better than another person or team.','She consistently {outperforms} her rivals.','그녀는 꾸준히 라이벌들보다 뛰어난 성과를 내요.','outperforms','B1','sports',2,'athlete outperforming rival race podium'),
('w_sports_B1_33','qualify','/ˈkwɒlɪfaɪ/','verb','예선을 통과하다','To reach a required standard to enter a competition.','She {qualified} for the Olympic trials.','그녀가 올림픽 선발전 예선을 통과했어요.','qualified','B1','sports',1,'athlete qualifying race finish celebration'),
('w_sports_B1_34','halftime','/ˈhɑːftaɪm/','noun','하프타임','The break in the middle of a game.','At {halftime}, the score was 2–0.','하프타임에 점수는 2대 0이었어요.','halftime','B1','sports',2,'football halftime break tunnel locker room'),
('w_sports_B1_35','spectacle','/ˈspektəkəl/','noun','장관, 볼거리','An impressive display or event.','The opening ceremony was a stunning {spectacle}.','개막식은 놀라운 장관이었어요.','spectacle','B1','sports',2,'sports opening ceremony fireworks stadium spectacular');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_sports_B2_01','analytics','/ˌænəˈlɪtɪks/','noun','스포츠 분석','Statistical analysis used to measure performance.','Teams use {analytics} to plan their tactics.','팀들은 전술을 계획하기 위해 분석을 활용해요.','analytics','B2','sports',1,'sports analytics data dashboard screen laptop'),
('w_sports_B2_02','biomechanics','/ˌbaɪoʊmɪˈkænɪks/','noun','생체역학','The study of how forces affect the human body in motion.','Sprinters work with {biomechanics} experts to refine technique.','단거리 선수들은 기술을 다듬기 위해 생체역학 전문가와 함께 일해요.','biomechanics','B2','sports',1,'athlete motion capture lab biomechanics analysis'),
('w_sports_B2_03','doping','/ˈdoʊpɪŋ/','noun','도핑','Using prohibited substances to enhance athletic performance.','The athlete was suspended for {doping}.','그 선수는 도핑으로 인해 출전 정지됐어요.','doping','B2','sports',1,'anti-doping test sports ethics lab sample'),
('w_sports_B2_04','physiotherapy','/ˌfɪziəʊˈθerəpi/','noun','물리치료','Treatment of injury using physical methods.','She underwent months of {physiotherapy} after the surgery.','그녀는 수술 후 수개월간 물리치료를 받았어요.','physiotherapy','B2','sports',1,'physiotherapy sports injury treatment rehab table'),
('w_sports_B2_05','periodization','/ˌpɪəriədaɪˈzeɪʃən/','noun','주기화 훈련','Dividing a training programme into planned phases.','Elite athletes use {periodization} to peak at competitions.','엘리트 선수들은 대회에서 최고 컨디션을 내기 위해 주기화 훈련을 사용해요.','periodization','B2','sports',1,'training periodization plan calendar phases chart'),
('w_sports_B2_06','agility','/əˈdʒɪlɪti/','noun','민첩성','The ability to move quickly and easily.','Agility drills improve a player''s {agility} on the field.','민첩성 훈련은 경기장에서 선수의 민첩성을 향상시켜요.','agility','B2','sports',1,'agility ladder drill athlete fast feet training'),
('w_sports_B2_07','stamina','/ˈstæmɪnə/','noun','지속적 체력 (상세)','Sustained physical and mental endurance over time.','Building {stamina} is essential for endurance events.','지속적 체력을 기르는 것은 지구력 종목에 필수예요.','stamina','B2','sports',1,'marathon runner endurance race long distance'),
('w_sports_B2_08','sprint','/sprɪnt/','noun','단거리 질주, 스프린트','A short burst of maximum speed.','She finished the race with a powerful final {sprint}.','그녀는 강력한 막판 스프린트로 경주를 마쳤어요.','sprint','B2','sports',1,'sprinter 100m track starting blocks explosive'),
('w_sports_B2_09','tactical','/ˈtæktɪkəl/','adjective','전술적인','Relating to a plan to achieve a goal in sport.','The manager made a {tactical} substitution late in the game.','감독이 경기 후반에 전술적인 교체를 했어요.','tactical','B2','sports',1,'football tactics board coach planning strategy'),
('w_sports_B2_10','performance','/pərˈfɔːrməns/','noun','경기력, 퍼포먼스','How well an athlete or team performs.','Her {performance} in the finals was outstanding.','결승전에서 그녀의 경기력은 탁월했어요.','performance','B2','sports',1,'athlete peak performance sports competition'),
('w_sports_B2_11','concussion','/kənˈkʌʃən/','noun','뇌진탕','A head injury causing temporary loss of function.','He was taken off after suffering a {concussion}.','그는 뇌진탕 증상을 보인 후 경기에서 제외됐어요.','concussion','B2','sports',1,'sports concussion head injury medical team'),
('w_sports_B2_12','hydration','/haɪˈdreɪʃən/','noun','수분 보충','The process of absorbing adequate water into the body.','Proper {hydration} is key to athletic performance.','충분한 수분 보충은 운동 능력의 핵심이에요.','hydration','B2','sports',1,'athlete drinking sports drink hydration water'),
('w_sports_B2_13','recovery','/rɪˈkʌvəri/','noun','회복 (훈련)','The process of returning to peak condition after exertion.','Ice baths are popular for post-training {recovery}.','얼음 목욕은 훈련 후 회복에 많이 사용돼요.','recovery','B2','sports',1,'athlete ice bath recovery sports muscle'),
('w_sports_B2_14','explosive','/ɪkˈsploʊsɪv/','adjective','폭발적인','Involving a rapid release of energy in a short time.','Sprinters need {explosive} power off the starting blocks.','단거리 선수는 출발 블록에서 폭발적인 힘이 필요해요.','explosive','B2','sports',1,'sprinter starting blocks explosive power track'),
('w_sports_B2_15','conditioning','/kənˈdɪʃənɪŋ/','noun','컨디셔닝, 체력 단련','A programme of exercises to improve fitness.','Off-season {conditioning} keeps athletes in shape.','비시즌 컨디셔닝이 선수들의 체형을 유지시켜요.','conditioning','B2','sports',1,'athlete conditioning training gym off season'),
('w_sports_B2_16','fatigue','/fəˈtiːɡ/','noun','피로','Extreme tiredness resulting from exertion.','Muscle {fatigue} set in during the final kilometre.','마지막 1킬로미터에서 근육 피로가 왔어요.','fatigue','B2','sports',1,'athlete exhausted fatigue end of race tired'),
('w_sports_B2_17','resilience','/rɪˈzɪliəns/','noun','회복 탄력성','The ability to recover quickly from difficulty.','Mental {resilience} separates great athletes from good ones.','정신적 회복 탄력성이 훌륭한 선수와 좋은 선수를 구분해요.','resilience','B2','sports',1,'athlete resilience comeback mental strength sport'),
('w_sports_B2_18','turnover','/ˈtɜːrnoʊvər/','noun','볼 소유권 전환','Losing possession of the ball to the opponent.','Too many {turnover}s cost them the match.','볼 소유권을 너무 많이 잃어 경기를 놓쳤어요.','turnovers','B2','sports',2,'basketball turnover mistake possession lost'),
('w_sports_B2_19','benchmark','/ˈbentʃmɑːrk/','noun','기준, 벤치마크','A standard point of reference for performance.','That world record is the {benchmark} for all sprinters.','그 세계 기록은 모든 단거리 선수의 기준이에요.','benchmark','B2','sports',2,'sports benchmark performance comparison chart data'),
('w_sports_B2_20','overtraining','/ˌoʊvərˈtreɪnɪŋ/','noun','과훈련','Exercising too much, causing declining performance.','Signs of {overtraining} include persistent fatigue.','과훈련의 징후에는 지속적인 피로가 포함돼요.','overtraining','B2','sports',2,'athlete overtraining exhausted injury stressed'),
('w_sports_B2_21','cadence','/ˈkeɪdəns/','noun','케이던스, 보폭 주기','The rate at which steps or strokes are taken in sport.','Cyclists adjust their {cadence} on different terrains.','자전거 선수들은 지형에 따라 케이던스를 조절해요.','cadence','B2','sports',2,'cyclist pedalling cadence rhythm road bike'),
('w_sports_B2_22','scouting','/ˈskaʊtɪŋ/','noun','스카우팅, 선수 탐색','Searching for talented players to recruit.','The club''s {scouting} network spans over 40 countries.','그 클럽의 스카우팅 네트워크는 40개국 이상에 걸쳐 있어요.','scouting','B2','sports',2,'sports scout watching player notebook pitch'),
('w_sports_B2_23','elite','/ɪˈliːt/','adjective','엘리트의, 최고 수준의','Of the highest level of performance.','Only {elite} athletes qualify for the Olympic Games.','엘리트 선수만이 올림픽에 출전할 수 있어요.','elite','B2','sports',1,'elite athletes olympic games competition'),
('w_sports_B2_24','metrics','/ˈmetrɪks/','noun','측정 지표','Standards of measurement used to evaluate performance.','Coaches analyse player {metrics} after every game.','코치들은 모든 경기 후 선수 측정 지표를 분석해요.','metrics','B2','sports',1,'sports metrics data analysis dashboard screen'),
('w_sports_B2_25','intensity','/ɪnˈtensɪti/','noun','강도 (운동 강도)','The level of effort or energy in training.','Training at high {intensity} improves cardiovascular fitness.','높은 강도의 훈련이 심폐 체력을 향상시켜요.','intensity','B2','sports',1,'HIIT training high intensity workout gym'),
('w_sports_B2_26','dehydration','/ˌdiːhaɪˈdreɪʃən/','noun','탈수','An excessive loss of water from the body.','Even mild {dehydration} can impair athletic performance.','가벼운 탈수도 운동 능력을 저하시킬 수 있어요.','dehydration','B2','sports',1,'athlete dehydration dizzy heat sport water'),
('w_sports_B2_27','coordination','/koʊˌɔːrdɪˈneɪʃən/','noun','협응력','The ability to use different parts of the body together.','Good {coordination} is essential for ball sports.','좋은 협응력은 구기 종목에 필수예요.','coordination','B2','sports',1,'athlete coordination drills balance agility'),
('w_sports_B2_28','dominant','/ˈdɒmɪnənt/','adjective','지배적인, 압도적인','Most powerful or influential in a competition.','She has been the {dominant} player in the tour for a decade.','그녀는 10년간 투어에서 압도적인 선수였어요.','dominant','B2','sports',1,'dominant athlete winning easily sport competition'),
('w_sports_B2_29','load','/loʊd/','noun','훈련 부하','The amount of training stress placed on an athlete.','Managing training {load} prevents overuse injuries.','훈련 부하를 관리하면 과사용 부상을 예방할 수 있어요.','load','B2','sports',2,'athlete training load tracker wearable data'),
('w_sports_B2_30','leverage','/ˈlevərɪdʒ/','noun','지렛대 원리, 레버리지','Using body mechanics to gain a mechanical advantage.','Proper technique uses body {leverage} efficiently.','올바른 기술은 신체의 레버리지를 효율적으로 사용해요.','leverage','B2','sports',2,'athlete lifting weights leverage mechanics body'),
('w_sports_B2_31','protocol','/ˈproʊtəkɒl/','noun','프로토콜, 절차','A set of rules about how something should be done.','The medical {protocol} for concussions is very strict.','뇌진탕에 관한 의료 절차는 매우 엄격해요.','protocol','B2','sports',2,'sports medical protocol team doctor procedure'),
('w_sports_B2_32','transition','/trænˈzɪʃən/','noun','전환 (공격·수비)','A change from one state to another in sport.','Quick {transition}s from defence to attack are vital.','수비에서 공격으로의 빠른 전환이 중요해요.','transitions','B2','sports',2,'football attack defence transition counter fast'),
('w_sports_B2_33','simulate','/ˈsɪmjʊleɪt/','verb','시뮬레이션하다','To create conditions similar to a real situation for training.','They {simulated} match conditions during training.','그들은 훈련 중 경기 상황을 시뮬레이션했어요.','simulated','B2','sports',2,'sports simulation training virtual match conditions'),
('w_sports_B2_34','underperform','/ˌʌndəpəˈfɔːrm/','verb','기대 이하의 성과를 내다','To perform less well than expected.','The team {underperformed} despite the talent in the squad.','팀은 스쿼드의 재능에도 불구하고 기대 이하였어요.','underperformed','B2','sports',2,'disappointed team losing sports let down'),
('w_sports_B2_35','output','/ˈaʊtpʊt/','noun','출력, 퍼포먼스 수치','The amount of work or energy produced.','Wattage is the key {output} measure for cyclists.','와트는 자전거 선수의 핵심 출력 측정 단위예요.','output','B2','sports',2,'cyclist power output watt meter data screen');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_sports_C1_01','kinesiology','/ˌkɪniːsiˈɒlədʒi/','noun','운동 과학 (키네시올로지)','The scientific study of human body movement.','She holds a degree in {kinesiology} and works with elite athletes.','그녀는 운동 과학 학위를 갖고 엘리트 선수들과 함께 일해요.','kinesiology','C1','sports',1,'kinesiology lab body movement science sports research'),
('w_sports_C1_02','proprioception','/ˌproʊpriəˈsepʃən/','noun','고유 감각 (프로프리오셉션)','The body''s ability to sense its own position and movement.','Ankle injuries can disrupt an athlete''s {proprioception}.','발목 부상은 선수의 고유 감각을 방해할 수 있어요.','proprioception','C1','sports',1,'balance proprioception training board athlete rehabilitation'),
('w_sports_C1_03','VO2 max','/ˌviː oʊ ˈtuː mæks/','noun','최대 산소 섭취량','The maximum rate of oxygen consumption during exercise.','Improving {VO2 max} is central to endurance training.','최대 산소 섭취량을 높이는 것은 지구력 훈련의 핵심이에요.','VO2 max','C1','sports',1,'VO2 max test mask treadmill lab sports science'),
('w_sports_C1_04','lactate threshold','/ˈlækteɪt ˈθreʃhoʊld/','phrase','젖산 역치','The exercise intensity above which lactate builds up faster than it is removed.','Training at the {lactate threshold} improves race pace significantly.','젖산 역치에서의 훈련은 레이스 페이스를 크게 향상시켜요.','lactate threshold','C1','sports',1,'lactate threshold blood test lab cycling athlete'),
('w_sports_C1_05','periodization','/ˌpɪəriədaɪˈzeɪʃən/','noun','주기화 (고급 계획)','A structured division of training into progressive phases.','Advanced {periodization} involves mesocycles and macrocycles.','고급 주기화에는 메소사이클과 매크로사이클이 포함돼요.','periodization','C1','sports',1,'training plan periodization macrocycle phases sport'),
('w_sports_C1_06','sport psychology','/spɔːrt saɪˈkɒlədʒi/','phrase','스포츠 심리학','The study of mental factors affecting sports performance.','{Sport psychology} techniques help athletes manage pressure.','스포츠 심리학 기술이 선수들이 압박감을 관리하는 데 도움이 돼요.','sport psychology','C1','sports',1,'sport psychologist athlete session mental training'),
('w_sports_C1_07','ethics','/ˈeθɪks/','noun','스포츠 윤리','Moral principles governing behaviour in sport.','The federation published new {ethics} guidelines last year.','연맹이 작년에 새로운 윤리 지침을 발표했어요.','ethics','C1','sports',1,'sports ethics fair play rules committee'),
('w_sports_C1_08','governance','/ˈɡʌvərnəns/','noun','스포츠 거버넌스','The system of rules and institutions controlling a sport.','Concerns about poor {governance} led to major reforms.','열악한 거버넌스에 대한 우려로 대대적인 개혁이 이뤄졌어요.','governance','C1','sports',1,'sports governance board meeting committee reform'),
('w_sports_C1_09','neuromuscular','/ˌnjʊəroʊˈmʌskjʊlər/','adjective','신경근의','Relating to nerves and muscles working together.','The drill targets {neuromuscular} coordination.','그 드릴은 신경근 협응을 목표로 해요.','neuromuscular','C1','sports',2,'neuromuscular training nerve muscle coordination sport'),
('w_sports_C1_10','taper','/ˈteɪpər/','noun','테이퍼 (훈련량 감소)','A gradual reduction in training before a major competition.','Athletes enter a {taper} phase two weeks before the race.','선수들은 경주 2주 전에 테이퍼 단계에 들어가요.','taper','C1','sports',1,'athlete tapering rest lighter training pre-race calm'),
('w_sports_C1_11','overreaching','/ˌoʊvərˈriːtʃɪŋ/','noun','과부하 훈련 (의도적)','A planned short-term increase in training load beyond normal capacity.','Functional {overreaching} is a deliberate strategy before a taper.','기능적 과부하 훈련은 테이퍼 이전의 의도적 전략이에요.','overreaching','C1','sports',2,'training overreaching plan sport science load chart'),
('w_sports_C1_12','isometric','/ˌaɪsəˈmetrɪk/','adjective','등척성의','Relating to muscle contraction without movement.','Plank exercises involve {isometric} muscle contractions.','플랭크 운동에는 등척성 근육 수축이 포함돼요.','isometric','C1','sports',2,'plank isometric exercise core stability hold'),
('w_sports_C1_13','plyometrics','/ˌplaɪəˈmetrɪks/','noun','플라이오메트릭스','Exercises involving rapid stretching and contracting of muscles.','Basketball players use {plyometrics} to build explosive power.','농구 선수들은 폭발적인 힘을 기르기 위해 플라이오메트릭스를 사용해요.','plyometrics','C1','sports',1,'plyometrics box jump training explosive athlete'),
('w_sports_C1_14','hypertrophy','/haɪˈpɜːrtrəfi/','noun','근육 비대','An increase in the size of muscle cells through exercise.','Resistance training induces muscle {hypertrophy}.','저항 훈련은 근육 비대를 유발해요.','hypertrophy','C1','sports',2,'muscle hypertrophy strength training gym results'),
('w_sports_C1_15','anaerobic','/ˌæneɪˈroʊbɪk/','adjective','무산소의','Relating to energy production without oxygen.','Sprinting is an {anaerobic} activity.','단거리 달리기는 무산소 활동이에요.','anaerobic','C1','sports',1,'sprinting anaerobic exercise short burst energy'),
('w_sports_C1_16','sarcopenia','/ˌsɑːrkəˈpiːniə/','noun','근감소증','The loss of muscle mass and strength with ageing.','Strength training combats {sarcopenia} in veteran athletes.','근력 운동은 베테랑 선수들의 근감소증과 싸워요.','sarcopenia','C1','sports',2,'elderly athlete strength training muscle mass aging'),
('w_sports_C1_17','cortisol','/ˈkɔːrtɪzɒl/','noun','코르티솔','A hormone released in response to stress and overtraining.','Chronic overtraining elevates {cortisol} levels, hindering recovery.','만성적인 과훈련은 코르티솔 수준을 높여 회복을 방해해요.','cortisol','C1','sports',2,'hormone cortisol stress sport blood test science'),
('w_sports_C1_18','tendinopathy','/ˌtendɪˈnɒpəθi/','noun','건병증 (힘줄 질환)','A disease of a tendon, often causing chronic pain.','Runners are prone to Achilles {tendinopathy}.','달리기 선수들은 아킬레스 건병증에 걸리기 쉬워요.','tendinopathy','C1','sports',2,'Achilles tendon injury runner physio treatment'),
('w_sports_C1_19','kinesthesia','/ˌkɪnɪsˈθiːziə/','noun','운동 감각','The sense of the position and movement of body parts.','Elite gymnasts have highly refined {kinesthesia}.','엘리트 체조 선수들은 매우 정교한 운동 감각을 갖고 있어요.','kinesthesia','C1','sports',2,'gymnast balance sense movement perception sport'),
('w_sports_C1_20','eccentric','/ɪkˈsentrɪk/','adjective','편심성의 (근육 수축)','Relating to muscle lengthening during contraction.','{Eccentric} exercises are effective for tendon rehabilitation.','편심성 운동은 힘줄 재활에 효과적이에요.','Eccentric','C1','sports',2,'eccentric exercise hamstring physio Nordic curl'),
('w_sports_C1_21','metabolic','/ˌmetəˈbɒlɪk/','adjective','대사적인','Relating to the chemical processes in the body.','High-intensity intervals increase {metabolic} rate.','고강도 인터벌이 대사율을 높여요.','metabolic','C1','sports',2,'metabolic rate exercise sport energy lab test'),
('w_sports_C1_22','fascia','/ˈfæʃiə/','noun','근막','Connective tissue that surrounds muscles and organs.','Myofascial release targets the {fascia} to reduce tension.','근막 이완 요법은 근막의 긴장을 줄이는 것을 목표로 해요.','fascia','C1','sports',2,'fascia muscle connective tissue massage roll'),
('w_sports_C1_23','thermoregulation','/ˌθɜːrmoʊˌreɡjʊˈleɪʃən/','noun','체온 조절','The body''s ability to maintain a stable temperature during exercise.','Effective {thermoregulation} prevents heat exhaustion in athletes.','효과적인 체온 조절은 선수들의 열사병을 예방해요.','thermoregulation','C1','sports',2,'athlete heat sport temperature regulation sweating'),
('w_sports_C1_24','electrolyte','/ɪˈlektrəlaɪt/','noun','전해질','Minerals that maintain fluid balance and muscle function.','Replacing {electrolytes} after heavy sweating is crucial.','땀을 많이 흘린 후 전해질을 보충하는 것이 중요해요.','electrolytes','C1','sports',1,'electrolyte sports drink minerals athlete hydration'),
('w_sports_C1_25','gait','/ɡeɪt/','noun','보행 (걸음걸이)','The way in which a person moves on foot.','Gait analysis helps identify biomechanical faults in runners.','보행 분석은 달리기 선수들의 생체역학적 결함을 찾는 데 도움이 돼요.','Gait','C1','sports',2,'gait analysis running treadmill lab camera motion'),
('w_sports_C1_26','creatine','/ˈkriːətiːn/','noun','크레아틴 (스포츠 영양)','A naturally occurring compound that aids short-burst energy.','Many athletes supplement with {creatine} to boost power output.','많은 선수들이 출력을 높이기 위해 크레아틴을 보충해요.','creatine','C1','sports',2,'creatine supplement sports nutrition powder scoop'),
('w_sports_C1_27','inflammation','/ˌɪnfləˈmeɪʃən/','noun','염증 (스포츠 부상)','The body''s response to injury involving redness and swelling.','Chronic {inflammation} can signal overtraining or injury.','만성 염증은 과훈련이나 부상을 나타낼 수 있어요.','inflammation','C1','sports',2,'sports injury inflammation ice pack swelling treatment'),
('w_sports_C1_28','oxidative','/ˈɒksɪdeɪtɪv/','adjective','산화적인','Relating to the use of oxygen in energy production.','Long-distance events rely on {oxidative} metabolism.','장거리 종목은 산화적 대사에 의존해요.','oxidative','C1','sports',2,'energy metabolism aerobic oxidative sport science chart'),
('w_sports_C1_29','deload','/diːloʊd/','noun','디로드 (훈련량 의도적 감소)','A planned reduction in training volume to aid recovery.','Coaches schedule a {deload} week every four weeks.','코치들은 4주마다 디로드 주를 계획해요.','deload','C1','sports',2,'athlete resting lighter workout recovery week deload'),
('w_sports_C1_30','musculoskeletal','/ˌmʌskjʊloʊˈskelɪtəl/','adjective','근골격의','Relating to the muscles, bones, and connective tissue.','The clinic specialises in {musculoskeletal} injuries.','그 클리닉은 근골격 부상을 전문으로 해요.','musculoskeletal','C1','sports',2,'musculoskeletal injury scan anatomy sports medicine'),
('w_sports_C1_31','catecholamine','/ˌkætɪˈkoʊləmiːn/','noun','카테콜아민 (흥분성 호르몬)','Hormones such as adrenaline released during intense exercise.','High-intensity exercise triggers {catecholamine} release.','고강도 운동은 카테콜아민 분비를 촉진해요.','catecholamine','C1','sports',3,'adrenaline hormone sport excitement high intensity'),
('w_sports_C1_32','ergodynamics','/ˌɜːrɡoʊdaɪˈnæmɪks/','noun','에르고다이나믹스 (운동 효율 역학)','The study of efficient energy use during physical activity.','{Ergodynamics} research helps coaches reduce unnecessary energy expenditure.','에르고다이나믹스 연구는 코치들이 불필요한 에너지 소비를 줄이는 데 도움을 줘요.','Ergodynamics','C1','sports',2,'sports energy efficiency lab research biomechanics'),
('w_sports_C1_33','anthropometry','/ˌænθrəˈpɒmɪtri/','noun','인체 측정학','The measurement of body dimensions for performance analysis.','{Anthropometry} data is used to optimise equipment sizing.','인체 측정 데이터는 장비 크기를 최적화하는 데 사용돼요.','Anthropometry','C1','sports',2,'athlete body measurement tape sports science lab'),
('w_sports_C1_34','decompression','/ˌdiːkəmˈpreʃən/','noun','감압 (회복 기법)','The process of relieving pressure on muscles and joints.','{Decompression} therapy is used for spinal recovery in athletes.','감압 치료는 선수들의 척추 회복에 사용돼요.','Decompression','C1','sports',3,'decompression therapy spine athlete recovery clinic'),
('w_sports_C1_35','psychomotor','/ˌsaɪkoʊˈmoʊtər/','adjective','정신운동의 (입문)','Relating to the interaction between mental activity and physical movement.','Decision-making speed is a key {psychomotor} skill.','의사결정 속도는 핵심적인 정신운동 기술이에요.','psychomotor','C1','sports',2,'psychomotor reaction sport decision making drill');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_sports_C2_01','biomechanical','/ˌbaɪoʊmɪˈkænɪkəl/','adjective','생체역학적','Relating to the mechanics of body movement.','The researchers conducted a {biomechanical} analysis of the throw.','연구원들이 투구 동작의 생체역학적 분석을 수행했어요.','biomechanical','C2','sports',1,'biomechanical analysis lab motion capture athlete study'),
('w_sports_C2_02','neuromotor','/ˌnjʊəroʊˈmoʊtər/','adjective','신경운동의','Relating to the nervous system''s control of movement.','{Neuromotor} training enhances reaction time and coordination.','신경운동 훈련은 반응 시간과 협응력을 향상시켜요.','Neuromotor','C2','sports',2,'neuromotor training reaction agility sport science'),
('w_sports_C2_03','chronobiology','/ˌkrɒnəbaɪˈɒlədʒi/','noun','시간 생물학','The study of biological rhythms and their effect on performance.','{Chronobiology} informs scheduling of peak training times.','시간 생물학은 최적 훈련 시간 설정에 정보를 제공해요.','Chronobiology','C2','sports',2,'chronobiology circadian rhythm sport performance clock'),
('w_sports_C2_04','ergogenic','/ˌɜːrɡəˈdʒenɪk/','adjective','경기력 향상의','Intended to enhance physical performance.','The legality of {ergogenic} aids is a constant debate in sport.','경기력 향상 보조제의 합법성은 스포츠에서 계속되는 논쟁이에요.','ergogenic','C2','sports',1,'ergogenic aid supplement sport legal ethics debate'),
('w_sports_C2_05','myofascial','/ˌmaɪoʊˈfæʃəl/','adjective','근막의','Relating to the connective tissue encasing muscles.','{Myofascial} release techniques are used by sports therapists.','근막 이완 기술은 스포츠 치료사들이 사용해요.','Myofascial','C2','sports',2,'myofascial release foam roller massage therapist muscle'),
('w_sports_C2_06','tensiomyography','/ˌtensiəmaɪˈɒɡrəfi/','noun','텐시오미오그라피 (근육 긴장 측정)','A non-invasive technique to measure muscle contractile properties.','{Tensiomyography} detects muscle imbalances before injuries occur.','텐시오미오그라피는 부상 전에 근육 불균형을 감지해요.','Tensiomyography','C2','sports',2,'tensiomyography muscle measurement sport science probe'),
('w_sports_C2_07','plyometrics','/ˌplaɪəˈmetrɪks/','noun','플라이오메트릭스 (심화)','Exercises using rapid muscle stretch-shortening cycles.','Advanced {plyometrics} programmes are periodised for peak performance.','고급 플라이오메트릭스 프로그램은 최고 경기력을 위해 주기화돼요.','plyometrics','C2','sports',2,'plyometrics advanced depth jump training lab sport'),
('w_sports_C2_08','psychomotor','/ˌsaɪkoʊˈmoʊtər/','adjective','정신운동의 (심화)','Relating to the interaction between mental activity and physical movement.','Elite {psychomotor} drills replicate high-pressure decision-making.','엘리트 정신운동 드릴은 고압적 의사결정을 재현해요.','psychomotor','C2','sports',1,'psychomotor reaction sport decision making speed drill'),
('w_sports_C2_09','glycolysis','/ɡlaɪˈkɒlɪsɪs/','noun','해당 과정','The metabolic breakdown of glucose to produce energy.','Intense sprinting relies heavily on {glycolysis}.','격렬한 스프린팅은 해당 과정에 크게 의존해요.','glycolysis','C2','sports',2,'glycolysis energy metabolism sport science diagram'),
('w_sports_C2_10','somatotype','/ˈsoʊmətəˌtaɪp/','noun','체형 유형 (소마토타입)','A classification of human body type (ectomorph, mesomorph, endomorph).','A mesomorphic {somatotype} is often associated with elite power athletes.','중배엽형 체형은 종종 엘리트 파워 운동선수와 관련이 있어요.','somatotype','C2','sports',2,'body type somatotype mesomorph ectomorph athlete'),
('w_sports_C2_11','mitochondrial','/ˌmaɪtəˈkɒndriəl/','adjective','미토콘드리아의','Relating to the cell structures that produce energy.','Endurance training increases {mitochondrial} density in muscle cells.','지구력 훈련은 근육 세포의 미토콘드리아 밀도를 높여요.','mitochondrial','C2','sports',2,'mitochondria muscle cell energy sport science biology'),
('w_sports_C2_12','electromyography','/ɪˌlektrəʊmaɪˈɒɡrəfi/','noun','근전도 검사 (EMG)','The recording of electrical activity produced by muscles.','{Electromyography} reveals which muscles activate during a squat.','근전도 검사는 스쿼트 중 어떤 근육이 활성화되는지 보여줘요.','Electromyography','C2','sports',2,'EMG electromyography muscle sensors athlete lab'),
('w_sports_C2_13','phosphocreatine','/ˌfɒsfoʊˈkriːətiːn/','noun','포스포크레아틴 (즉각 에너지원)','A high-energy compound used to rapidly regenerate ATP.','{Phosphocreatine} stores are depleted within ten seconds of maximal effort.','포스포크레아틴 저장량은 최대 노력 10초 이내에 고갈돼요.','Phosphocreatine','C2','sports',2,'phosphocreatine ATP energy sprint muscle sport science'),
('w_sports_C2_14','hemodynamics','/ˌhiːmoʊdaɪˈnæmɪks/','noun','혈역학','The dynamics of blood flow through the circulatory system.','Cardiac {hemodynamics} improve significantly with aerobic training.','유산소 훈련으로 심장 혈역학이 크게 개선돼요.','hemodynamics','C2','sports',2,'blood flow heart circulatory aerobic sport science'),
('w_sports_C2_15','mechanoreceptor','/ˌmekənoʊrɪˈseptər/','noun','기계수용체','A sensory receptor that responds to mechanical pressure.','{Mechanoreceptors} in joints help athletes sense body position.','관절의 기계수용체가 선수들이 신체 위치를 감지하는 데 도움을 줘요.','Mechanoreceptors','C2','sports',3,'sensory receptor joint nerve sport science anatomy'),
('w_sports_C2_16','bioenergetics','/ˌbaɪoʊˌenəˈdʒetɪks/','noun','생물에너지학','The study of energy transformations in living organisms.','Understanding {bioenergetics} helps coaches design better training.','생물에너지학을 이해하면 코치들이 더 나은 훈련을 설계할 수 있어요.','bioenergetics','C2','sports',2,'bioenergetics energy lab sport science organism'),
('w_sports_C2_17','catabolism','/kəˈtæbəlɪzəm/','noun','이화 작용','The breakdown of complex molecules in the body for energy.','Overtraining can tip the balance toward {catabolism}.','과훈련은 균형을 이화 작용 쪽으로 기울게 할 수 있어요.','catabolism','C2','sports',2,'catabolism muscle breakdown overtraining science diagram'),
('w_sports_C2_18','anabolism','/əˈnæbəlɪzəm/','noun','동화 작용','The building of complex molecules in the body, enabling growth.','Adequate protein intake supports {anabolism} after training.','충분한 단백질 섭취가 훈련 후 동화 작용을 지원해요.','anabolism','C2','sports',2,'anabolism muscle growth protein sport science'),
('w_sports_C2_19','periodicity','/ˌpɪəriəˈdɪsɪti/','noun','주기성','The quality of recurring in regular cycles in training.','The {periodicity} of elite programmes is carefully calibrated.','엘리트 프로그램의 주기성은 신중하게 조율돼요.','periodicity','C2','sports',2,'training periodicity cycle wave sport program chart'),
('w_sports_C2_20','neurotransmitter','/ˌnjʊəroʊˈtrænsmɪtər/','noun','신경전달물질','A chemical that transmits signals between nerve cells.','Dopamine is a {neurotransmitter} linked to motivation in sport.','도파민은 스포츠에서 동기와 연관된 신경전달물질이에요.','neurotransmitter','C2','sports',3,'dopamine neurotransmitter brain sport motivation science'),
('w_sports_C2_21','proprioceptive','/ˌproʊpriəˈseptɪv/','adjective','고유 감각의','Relating to the perception of body position and movement.','Balance boards develop {proprioceptive} awareness.','균형 보드는 고유 감각 인식을 발달시켜요.','proprioceptive','C2','sports',2,'balance board proprioceptive training athlete rehab'),
('w_sports_C2_22','viscoelastic','/ˌvɪskoʊɪˈlæstɪk/','adjective','점탄성의','Having both viscous and elastic properties, as in tendons.','Tendons are {viscoelastic} structures that store and release energy.','힘줄은 에너지를 저장하고 방출하는 점탄성 구조예요.','viscoelastic','C2','sports',3,'tendon viscoelastic structure energy spring biomechanics'),
('w_sports_C2_23','mechanotransduction','/ˌmekənoʊtrænzˈdʌkʃən/','noun','기계적 신호 전달','The process by which cells convert mechanical stimuli into signals.','Resistance training initiates {mechanotransduction} in muscle fibres.','저항 훈련은 근육 섬유에서 기계적 신호 전달을 시작해요.','mechanotransduction','C2','sports',3,'cell mechanical signal muscle fiber sport science'),
('w_sports_C2_24','allostasis','/ˌæloʊˈsteɪsɪs/','noun','이항상성','Achieving stability through change and adaptation.','{Allostasis} explains how athletes adapt to increasing training loads.','이항상성은 선수들이 증가하는 훈련 부하에 어떻게 적응하는지 설명해요.','Allostasis','C2','sports',3,'allostasis adaptation balance change stress sport'),
('w_sports_C2_25','proteolysis','/ˌproʊtiˈɒlɪsɪs/','noun','단백질 분해','The breakdown of proteins by enzymes.','Prolonged intense exercise accelerates muscle {proteolysis}.','장시간 강도 높은 운동은 근육 단백질 분해를 가속해요.','proteolysis','C2','sports',3,'protein breakdown muscle enzyme sport recovery science'),
('w_sports_C2_26','morphology','/mɔːrˈfɒlədʒi/','noun','형태학 (신체 구조)','The study of the form and structure of organisms.','Skeletal {morphology} influences an athlete''s suitability for a sport.','골격 형태학은 선수의 스포츠 적합성에 영향을 미쳐요.','morphology','C2','sports',3,'skeletal morphology anatomy bone structure sport'),
('w_sports_C2_27','fascicle','/ˈfæsɪkəl/','noun','근섬유다발','A bundle of muscle fibres within a muscle.','Ultrasound imaging can measure {fascicle} length in athletes.','초음파 영상으로 선수의 근섬유다발 길이를 측정할 수 있어요.','fascicle','C2','sports',3,'muscle fascicle fiber bundle ultrasound imaging sport'),
('w_sports_C2_28','ergometer','/ɜːrˈɡɒmɪtər/','noun','에르고미터 (운동 측정 장치)','A device that measures work or power output during exercise.','Rowers train on a rowing {ergometer} indoors.','조정 선수들은 실내 조정 에르고미터로 훈련해요.','ergometer','C2','sports',2,'rowing ergometer indoor training sport machine power'),
('w_sports_C2_29','allometric','/ˌæloʊˈmetrɪk/','adjective','이형성장의','Relating to the differential growth rate of body parts relative to the whole.','Strength-to-weight ratios follow {allometric} scaling principles.','체중 대비 근력 비율은 이형성장 척도 원리를 따라요.','allometric','C2','sports',3,'allometric scaling strength weight ratio sport science'),
('w_sports_C2_30','anaerobiosis','/ˌæneɪˌroʊbaɪˈoʊsɪs/','noun','무산소 생명 현상','The ability to live or function without oxygen.','Short-duration maximal efforts depend on {anaerobiosis}.','단시간 최대 노력은 무산소 생명 현상에 의존해요.','anaerobiosis','C2','sports',3,'anaerobic energy system sport sprint science diagram'),
('w_sports_C2_31','sarcoplasmic','/ˌsɑːrkəˈplæzmɪk/','adjective','근형질의','Relating to the fluid inside muscle cells.','High-rep training induces {sarcoplasmic} hypertrophy.','고반복 훈련은 근형질 비대를 유발해요.','sarcoplasmic','C2','sports',3,'sarcoplasmic hypertrophy muscle cell sport science gym'),
('w_sports_C2_32','polyphasic','/ˌpɒliˈfeɪzɪk/','adjective','다단계성의 (수면·훈련)','Occurring in several phases or cycles.','Some athletes experiment with {polyphasic} sleep schedules.','일부 선수들은 다단계성 수면 일정을 실험해요.','polyphasic','C2','sports',3,'polyphasic sleep schedule sport athlete rest recovery'),
('w_sports_C2_33','tensiometry','/ˌtensiˈɒmɪtri/','noun','장력 측정법','The measurement of tension in muscles or tendons.','{Tensiometry} is used to quantify hamstring tightness.','장력 측정법은 햄스트링 긴장을 정량화하는 데 사용돼요.','Tensiometry','C2','sports',3,'tensiometry hamstring tension measurement sport science'),
('w_sports_C2_34','hemoglobin','/ˈhiːməɡloʊbɪn/','noun','헤모글로빈','The protein in red blood cells that carries oxygen.','Altitude training increases {hemoglobin} concentration in the blood.','고지 훈련은 혈액 내 헤모글로빈 농도를 높여요.','hemoglobin','C2','sports',2,'altitude training hemoglobin blood oxygen sport science'),
('w_sports_C2_35','neuroplasticity','/ˌnjʊəroʊplæˈstɪsɪti/','noun','신경가소성','The brain''s ability to reorganise itself by forming new connections.','Skill acquisition relies on {neuroplasticity} in the motor cortex.','기술 습득은 운동 피질의 신경가소성에 의존해요.','neuroplasticity','C2','sports',2,'brain neuroplasticity learning skill sport motor cortex');
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_sports_A1_01','Do you play any sports?','운동 하세요?','Do you play','play는 규칙이 있는 스포츠(축구·야구·농구)에 쓰고, do는 개인 운동(yoga·taekwondo)에 써요.','운동 화제','A1','sports','pattern',NULL,1),
('s_sports_A1_02','I like to swim in summer.','저는 여름에 수영하는 걸 좋아해요.','I like to','좋아하는 운동을 말할 때 "I like to + 동사원형"을 쓰면 간단하고 자연스러워요.','취미 소개','A1','sports','pattern',NULL,2),
('s_sports_A1_03','Can you run fast?','빠르게 달릴 수 있어요?','Can you','Can you + 동사원형?은 능력을 묻는 가장 간단한 방법이에요.','능력 묻기','A1','sports','pattern',NULL,3),
('s_sports_A1_04','What is your favourite sport?','제일 좋아하는 스포츠가 뭐예요?','What is your favourite','favourite 대신 favorite으로도 써요 (미국식). 좋아하는 것을 물을 때 꼭 외워두세요.','선호 묻기','A1','sports','pattern',NULL,4),
('s_sports_A1_05','Let''s play together after school!','방과 후에 같이 운동해요!','Let''s play together','Let''s + 동사원형은 상대방을 함께 하도록 초대할 때 써요.','함께하기 제안','A1','sports','pattern',NULL,5),
('s_sports_A1_06','Our team won the game!','우리 팀이 경기에서 이겼어요!','Our team won','과거형 won은 win의 불규칙 과거예요. 경기 결과를 말할 때 자주 써요.','결과 말하기','A1','sports','pattern',NULL,6),
('s_sports_A1_07','I go to the gym every week.','저는 매주 헬스장에 가요.','I go to the gym','주기를 말할 때 every day / every week / every weekend처럼 뒤에 붙여요.','운동 습관','A1','sports','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_sports_A2_01','Did you watch the match last night?','어젯밤 경기 봤어요?','Did you watch','Did you + 동사원형? 패턴으로 과거 행동을 자연스럽게 물어볼 수 있어요.','경기 이야기','A2','sports','pattern',NULL,1),
('s_sports_A2_02','The score was three to one.','점수는 3대 1이었어요.','The score was','영어로 점수를 말할 때 "three to one" 또는 "three-one"으로 읽어요.','경기 결과','A2','sports','pattern',NULL,2),
('s_sports_A2_03','She scored twice in the second half.','그녀는 후반전에 두 번 득점했어요.','scored twice','twice = 두 번. 특정 숫자의 경우 once, twice, three times처럼 써요.','득점 표현','A2','sports','pattern',NULL,3),
('s_sports_A2_04','I can''t believe they lost again.','또 졌다니 믿을 수가 없어요.','I can''t believe','I can''t believe + (that) 절 패턴은 놀람을 표현할 때 자주 써요.','감탄·놀람','A2','sports','pattern',NULL,4),
('s_sports_A2_05','The game ended in a draw.','경기가 무승부로 끝났어요.','ended in a draw','end in a draw는 "무승부로 끝나다"를 뜻하는 고정 표현이에요. ended in a tie도 같은 의미예요.','경기 결과','A2','sports','pattern',NULL,5),
('s_sports_A2_06','Who do you think will win the final?','결승에서 누가 이길 것 같아요?','Who do you think will','Who do you think will + 동사?는 예측을 물을 때 쓰는 자연스러운 표현이에요.','예측 묻기','A2','sports','pattern',NULL,6),
('s_sports_A2_07','He broke the record by two seconds.','그는 기록을 2초 차이로 깼어요.','broke the record','break a record는 "기록을 깨다"는 뜻의 관용 표현이에요. broke는 break의 불규칙 과거형이에요.','기록 표현','A2','sports','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_sports_B1_01','The coach changed the formation at halftime.','코치가 하프타임에 포메이션을 바꿨어요.','changed the formation','at halftime은 "하프타임에"라는 표현으로 경기 분석 시 자주 나와요.','전술 분석','B1','sports','pattern',NULL,1),
('s_sports_B1_02','Our strategy was to press high and win the ball back quickly.','우리 전략은 높게 압박하고 빠르게 공을 되찾는 것이었어요.','Our strategy was to','strategy was to + 동사원형으로 계획을 설명할 수 있어요.','팀 전략','B1','sports','pattern',NULL,2),
('s_sports_B1_03','If we had scored first, the result might have been different.','우리가 먼저 득점했다면, 결과가 달라졌을 수도 있어요.','might have been','If + 과거완료, might have + 과거분사 패턴은 반사실 상황을 말할 때 써요 (3형식 가정법).','가정 표현','B1','sports','pattern',NULL,3),
('s_sports_B1_04','The team focused on maintaining possession throughout the game.','팀은 경기 내내 볼 점유율 유지에 집중했어요.','focused on maintaining','focus on + 동명사 패턴으로 집중한 대상을 표현해요.','전술 묘사','B1','sports','pattern',NULL,4),
('s_sports_B1_05','The referee should have given a penalty in that situation.','심판은 그 상황에서 패널티를 줬어야 했어요.','should have given','should have + 과거분사는 과거에 하지 않은 일에 대한 아쉬움이나 비판을 나타내요.','판정 논평','B1','sports','pattern',NULL,5),
('s_sports_B1_06','I''m not sure why they didn''t substitute the tired striker earlier.','왜 지친 스트라이커를 더 일찍 교체하지 않았는지 모르겠어요.','I''m not sure why','I''m not sure why + 절은 의문과 불만을 부드럽게 표현해요.','전술 의문','B1','sports','pattern',NULL,6),
('s_sports_B1_07','Sportsmanship matters more than winning at all costs.','스포츠맨십은 어떤 대가를 치르더라도 이기는 것보다 더 중요해요.','matters more than','A matters more than B 패턴은 비교 우선순위를 말할 때 써요.','스포츠 가치관','B1','sports','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_sports_B2_01','Performance analytics has transformed the way teams approach match preparation.','퍼포먼스 분석이 팀들이 경기 준비에 접근하는 방식을 바꿔놨어요.','has transformed the way','has transformed는 현재완료로 변화의 영향이 지금도 이어짐을 나타내요.','스포츠 분석','B2','sports','pattern',NULL,1),
('s_sports_B2_02','The data suggests that high-pressing tactics significantly increase the chance of winning.','데이터에 따르면 강한 압박 전술이 승리 가능성을 크게 높여요.','The data suggests that','The data suggests that + 절은 분석 결과를 객관적으로 제시하는 학문적 표현이에요.','데이터 인용','B2','sports','pattern',NULL,2),
('s_sports_B2_03','Without proper periodization, athletes risk overtraining and burnout.','적절한 주기화 없이는 선수들이 과훈련과 번아웃의 위험에 처해요.','risk overtraining','risk + 동명사는 "~할 위험에 처하다"는 뜻이에요. risk doing something 형태로 기억하세요.','위험 표현','B2','sports','pattern',NULL,3),
('s_sports_B2_04','Her tactical awareness sets her apart from other players in the league.','그녀의 전술적 감각이 리그의 다른 선수들과 그녀를 구별해줘요.','sets her apart from','set apart from은 "~에서 구별되다, 뛰어나다"는 관용 표현이에요.','비교 강조','B2','sports','pattern',NULL,4),
('s_sports_B2_05','The coaching staff is reviewing biomechanics footage to correct his running form.','코칭 스태프가 달리기 자세를 교정하기 위해 생체역학 영상을 검토 중이에요.','is reviewing','현재진행형(is + -ing)은 현재 진행 중인 지속적 행동을 나타내요.','훈련 분석','B2','sports','pattern',NULL,5),
('s_sports_B2_06','Despite the injury setback, she managed to qualify for the finals.','부상이라는 역경에도 불구하고, 그녀는 결승 진출에 성공했어요.','Despite the','Despite + 명사(구)는 "~에도 불구하고"를 뜻하고, Although + 절과 구별해서 써요.','역경 극복','B2','sports','pattern',NULL,6),
('s_sports_B2_07','It''s worth noting that doping undermines the integrity of the sport.','도핑이 스포츠의 무결성을 훼손한다는 점은 주목할 만해요.','It''s worth noting that','It''s worth noting that은 중요한 사실을 강조할 때 쓰는 격식 표현이에요.','이슈 제기','B2','sports','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_sports_C1_01','Training at the lactate threshold elicits significant aerobic adaptations over time.','젖산 역치에서의 훈련은 시간이 지남에 따라 상당한 유산소 적응을 이끌어내요.','elicits significant','elicit는 "이끌어내다, 유발하다"는 뜻의 격식 동사예요. produce나 cause보다 학술적이에요.','스포츠 과학','C1','sports','pattern',NULL,1),
('s_sports_C1_02','Proprioceptive deficits are commonly observed following ankle sprains in athletes.','고유 감각 결손은 선수들의 발목 염좌 후에 흔히 관찰돼요.','Proprioceptive deficits are commonly observed','수동태(are observed)는 학술 및 의학 텍스트에서 관찰 사실을 객관적으로 서술할 때 자주 써요.','의학적 관찰','C1','sports','pattern',NULL,2),
('s_sports_C1_03','Sport psychology interventions can help athletes reframe failure as a learning opportunity.','스포츠 심리학 개입은 선수들이 실패를 학습 기회로 재해석하도록 도울 수 있어요.','reframe failure as','reframe A as B는 "A를 B로 재해석하다"는 표현으로 인지 변화를 나타내요.','심리적 접근','C1','sports','pattern',NULL,3),
('s_sports_C1_04','Governance failures within sporting bodies have eroded public trust significantly.','스포츠 단체 내의 거버넌스 실패가 대중의 신뢰를 크게 잠식했어요.','have eroded','erode는 "점진적으로 침식하다, 잠식하다"는 뜻이에요. 추상적 개념(신뢰·가치)에 자주 써요.','스포츠 거버넌스','C1','sports','pattern',NULL,4),
('s_sports_C1_05','Without adequate recovery, neuromuscular fatigue accumulates and performance deteriorates.','충분한 회복 없이는 신경근 피로가 쌓이고 경기력이 저하돼요.','accumulates and deteriorates','두 동사를 and로 연결해 결과의 연쇄를 표현해요. deteriorate(저하되다)는 기억해두세요.','과훈련 경고','C1','sports','pattern',NULL,5),
('s_sports_C1_06','Periodization frameworks must account for individual variation in recovery capacity.','주기화 프레임워크는 회복 능력의 개인 차이를 반드시 고려해야 해요.','must account for','must account for는 "반드시 고려해야 한다"는 의무를 나타내는 격식 표현이에요.','훈련 설계','C1','sports','pattern',NULL,6),
('s_sports_C1_07','Ethical considerations in elite sport extend well beyond the arena itself.','엘리트 스포츠의 윤리적 고려 사항은 경기장 자체를 훨씬 넘어서요.','extend well beyond','extend well beyond는 "훨씬 넘어서 확장된다"는 강조 표현이에요. well은 강조 부사예요.','스포츠 윤리','C1','sports','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_sports_C2_01','Tensiomyography provides a non-invasive means of quantifying skeletal muscle contractile properties.','텐시오미오그라피는 골격근 수축 특성을 정량화하는 비침습적 수단을 제공해요.','non-invasive means of quantifying','means of + 동명사는 "~하는 수단"이라는 뜻이에요. 학술 논문에서 흔히 나오는 구조예요.','스포츠 과학 연구','C2','sports','pattern',NULL,1),
('s_sports_C2_02','Chronobiological factors, including circadian rhythm, critically modulate athletic performance across disciplines.','일주기 리듬을 포함한 시간 생물학적 요인이 다양한 종목에서 운동 능력을 결정적으로 조절해요.','critically modulate','modulate는 "조절하다, 변조하다"는 뜻의 고급 동사예요. critically는 "결정적으로"라는 부사예요.','시간 생물학','C2','sports','pattern',NULL,2),
('s_sports_C2_03','The ergogenic potential of phosphocreatine supplementation remains a subject of ongoing inquiry.','포스포크레아틴 보충의 경기력 향상 잠재력은 계속 진행 중인 연구의 주제로 남아 있어요.','remains a subject of ongoing inquiry','remains a subject of ongoing inquiry는 학술적으로 "아직 연구 중인 주제이다"를 표현해요.','학술 논의','C2','sports','pattern',NULL,3),
('s_sports_C2_04','Neuromotor adaptations to resistance training are mediated by both central and peripheral mechanisms.','저항 훈련에 대한 신경운동 적응은 중추 및 말초 메커니즘 모두에 의해 매개돼요.','are mediated by','be mediated by는 "~에 의해 매개되다"로 복잡한 인과관계를 학술적으로 설명할 때 써요.','신경과학 설명','C2','sports','pattern',NULL,4),
('s_sports_C2_05','Allometric scaling must be applied when comparing strength outputs across athletes of differing body masses.','서로 다른 체중을 가진 선수들의 근력 출력을 비교할 때 이형성장 척도를 적용해야 해요.','must be applied when comparing','must be applied는 수동 의무 구조예요. when + 동명사(-ing)와 함께 조건을 표현해요.','데이터 비교','C2','sports','pattern',NULL,5),
('s_sports_C2_06','The psychomotor demands of elite competition necessitate a training environment that replicates high-pressure decision-making.','엘리트 경쟁의 정신운동적 요구는 고압적 의사결정을 재현하는 훈련 환경을 필요로 해요.','necessitate a training environment that','necessitate는 "필요로 하다"는 뜻의 고급 타동사예요. demand나 require보다 강한 어조예요.','훈련 설계','C2','sports','pattern',NULL,6),
('s_sports_C2_07','Myofascial dysfunction, if left unaddressed, may perpetuate compensatory movement patterns and predispose athletes to recurrent injury.','근막 기능 장애가 방치될 경우 보상 운동 패턴을 지속시키고 선수들을 재발성 부상에 취약하게 할 수 있어요.','if left unaddressed','if left unaddressed는 "방치될 경우"라는 뜻의 분사구문 조건절이에요. predispose A to B는 "A를 B에 취약하게 만들다"예요.','부상 예방','C2','sports','pattern',NULL,7);
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_discussion_A1_01','think','/θɪŋk/','verb','생각하다','To have an opinion or belief about something.','What do you {think} about this idea?','이 아이디어에 대해 어떻게 생각해요?','think','A1','discussion',1,'thinking person opinion discussion'),
('w_discussion_A1_02','say','/seɪ/','verb','말하다','To express something in words.','What did she {say} at the meeting?','그녀가 회의에서 뭐라고 했어요?','say','A1','discussion',1,'person speaking talking'),
('w_discussion_A1_03','agree','/əˈɡriː/','verb','동의하다','To have the same opinion as someone else.','I completely {agree} with you on that.','그 부분에서 완전히 동의해요.','agree','A1','discussion',1,'two people nodding agreement'),
('w_discussion_A1_04','want','/wɒnt/','verb','원하다','To have a desire or wish for something.','I {want} to share my opinion.','제 의견을 말하고 싶어요.','want','A1','discussion',1,'person raising hand speaking'),
('w_discussion_A1_05','know','/noʊ/','verb','알다','To be aware of or have information about something.','Do you {know} why they changed the plan?','왜 계획을 바꿨는지 알아요?','know','A1','discussion',1,'person thinking lightbulb'),
('w_discussion_A1_06','like','/laɪk/','verb','좋아하다; ~처럼','To find something enjoyable or to use as a comparison.','I {like} your idea very much.','당신의 아이디어가 정말 마음에 들어요.','like','A1','discussion',2,'person smiling thumbs up'),
('w_discussion_A1_07','maybe','/ˈmeɪbi/','adverb','아마도','Used to express possibility or uncertainty.','{Maybe} we should try a different approach.','아마도 다른 방법을 시도해야 할 것 같아요.','Maybe','A1','discussion',1,'person thinking maybe gesture'),
('w_discussion_A1_08','yes','/jes/','interjection','네, 맞아요','Used to give a positive answer or express agreement.','{Yes}, I think that is a great point.','네, 정말 좋은 의견이에요.','Yes','A1','discussion',1,'person nodding yes'),
('w_discussion_A1_09','no','/noʊ/','interjection','아니요','Used to give a negative answer or express disagreement.','{No}, I do not think that will work.','아니요, 그게 효과가 있을 것 같지 않아요.','No','A1','discussion',1,'person shaking head disagreeing'),
('w_discussion_A1_10','right','/raɪt/','adjective','맞는, 옳은','Correct or true; in agreement with what is expected.','That is {right}, we need to reconsider.','맞아요, 다시 생각해봐야 해요.','right','A1','discussion',1,'checkmark correct answer'),
('w_discussion_A1_11','good','/ɡʊd/','adjective','좋은','Of a high quality or standard; used to approve ideas.','That is a {good} point.','좋은 지적이에요.','good','A1','discussion',2,'thumbs up approval good'),
('w_discussion_A1_12','bad','/bæd/','adjective','나쁜','Of poor quality or a negative nature.','I think that is a {bad} idea.','그건 나쁜 생각 같아요.','bad','A1','discussion',2,'person disapproving frowning'),
('w_discussion_A1_13','talk','/tɔːk/','verb','이야기하다','To communicate by speaking.','Let us {talk} about this together.','이것에 대해 함께 이야기해요.','talk','A1','discussion',1,'two people talking conversation'),
('w_discussion_A1_14','help','/help/','verb','돕다','To make it easier for someone to do something.','Can you {help} me understand your view?','당신의 견해를 이해할 수 있게 도와줄 수 있나요?','help','A1','discussion',2,'person helping explain'),
('w_discussion_A1_15','look','/lʊk/','verb','보다; 생각되다','To direct your eyes at something; to seem or appear.','It {looks} like we have different ideas.','우리가 다른 생각을 가지고 있는 것 같아요.','looks','A1','discussion',2,'people looking discussing together'),
('w_discussion_A1_16','true','/truː/','adjective','사실인, 맞는','In accordance with fact or reality.','Is it {true} that they cancelled the event?','그들이 행사를 취소한 게 사실인가요?','true','A1','discussion',1,'fact truth document'),
('w_discussion_A1_17','question','/ˈkwestʃən/','noun','질문','A sentence or phrase used to find out information.','I have a {question} about your idea.','당신의 아이디어에 대해 질문이 있어요.','question','A1','discussion',1,'hand raised asking question'),
('w_discussion_A1_18','answer','/ˈɑːnsər/','noun','답변','A thing said, written, or done to deal with a question.','What is your {answer} to this problem?','이 문제에 대한 답이 뭐예요?','answer','A1','discussion',1,'person answering explaining'),
('w_discussion_A1_19','idea','/aɪˈdɪə/','noun','생각, 아이디어','A thought or suggestion about a possible course of action.','I have a new {idea} to share with everyone.','모두와 나눌 새로운 아이디어가 있어요.','idea','A1','discussion',1,'lightbulb new idea thinking'),
('w_discussion_A1_20','please','/pliːz/','adverb','제발, 부탁해요','Used to add politeness to a request.','{Please} tell me what you think.','어떻게 생각하시는지 말씀해 주세요.','Please','A1','discussion',2,'polite request gesture'),
('w_discussion_A1_21','sorry','/ˈsɒri/','adjective','미안한, 죄송한','Used to express regret or to introduce a different view.','I am {sorry}, but I disagree.','죄송하지만 동의하지 않아요.','sorry','A1','discussion',2,'person apologizing sorry'),
('w_discussion_A1_22','why','/waɪ/','adverb','왜','For what reason or purpose.','{Why} do you think that is the best option?','왜 그게 최선의 선택이라고 생각해요?','Why','A1','discussion',1,'person questioning curious why'),
('w_discussion_A1_23','how','/haʊ/','adverb','어떻게','In what way or manner.','{How} can we solve this problem together?','이 문제를 어떻게 함께 해결할 수 있을까요?','How','A1','discussion',1,'people problem solving together'),
('w_discussion_A1_24','what','/wɒt/','pronoun','무엇','Asking for information about something.','{What} do you think we should do?','우리가 어떻게 해야 한다고 생각해요?','What','A1','discussion',1,'person asking what question'),
('w_discussion_A1_25','this','/ðɪs/','determiner','이것','Used to refer to a specific thing nearby or just mentioned.','{This} is my opinion on the topic.','이게 그 주제에 대한 제 의견이에요.','This','A1','discussion',2,'person pointing presenting'),
('w_discussion_A1_26','more','/mɔːr/','adverb','더','To a greater extent or degree.','Can you tell me {more} about that?','그것에 대해 더 말해줄 수 있나요?','more','A1','discussion',2,'expanding idea more information'),
('w_discussion_A1_27','same','/seɪm/','adjective','같은','Identical; not different.','I feel the {same} way about it.','저도 그것에 대해 같은 생각이에요.','same','A1','discussion',1,'people sharing same opinion'),
('w_discussion_A1_28','different','/ˈdɪfrənt/','adjective','다른','Not the same; distinct.','We have {different} opinions on this.','우리는 이것에 대해 다른 의견을 가지고 있어요.','different','A1','discussion',1,'split opinion two sides'),
('w_discussion_A1_29','can','/kæn/','modal','할 수 있다','Expressing ability or possibility.','You {can} share your thoughts freely.','자유롭게 생각을 나눌 수 있어요.','can','A1','discussion',2,'open discussion free speech'),
('w_discussion_A1_30','let','/let/','verb','~하게 하다; 자 ~하자','To allow or suggest doing something together.','{Let} me explain what I mean.','제가 무슨 말인지 설명할게요.','Let','A1','discussion',2,'person explaining gesturing'),
('w_discussion_A1_31','ok','/ˌoʊˈkeɪ/','interjection','괜찮아요, 알겠어요','Used to express agreement or acceptance.','{OK}, I understand your point now.','알겠어요, 이제 당신의 요점을 이해해요.','OK','A1','discussion',2,'person nodding understanding ok'),
('w_discussion_A1_32','not','/nɒt/','adverb','아니','Used to make a word or phrase negative.','I do {not} agree with that idea.','그 생각에 동의하지 않아요.','not','A1','discussion',2,'person disagreeing negative'),
('w_discussion_A1_33','but','/bʌt/','conjunction','그런데, 하지만','Used to introduce a different or contrasting idea.','{But} there is another way to look at it.','하지만 다른 시각으로 볼 수도 있어요.','But','A1','discussion',1,'contrasting ideas two sides'),
('w_discussion_A1_34','because','/bɪˈkɒz/','conjunction','왜냐하면','For the reason that; used to give a reason.','{Because} I think it is more efficient.','왜냐하면 더 효율적이라고 생각하기 때문이에요.','Because','A1','discussion',1,'reason explanation arrow'),
('w_discussion_A1_35','so','/soʊ/','conjunction','그래서, 따라서','Therefore; with the result that.','{So}, what is our conclusion?','그래서 우리의 결론이 뭔가요?','So','A1','discussion',2,'conclusion summary decision');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_discussion_A2_01','opinion','/əˈpɪnjən/','noun','의견, 견해','A view or judgment formed about something.','In my {opinion}, the plan needs more work.','제 의견으로는, 계획에 더 보완이 필요해요.','opinion','A2','discussion',1,'person sharing opinion speech bubble'),
('w_discussion_A2_02','suggest','/səˈdʒest/','verb','제안하다','To put forward an idea for consideration.','I would like to {suggest} a different approach.','다른 방법을 제안하고 싶어요.','suggest','A2','discussion',1,'person proposing idea whiteboard'),
('w_discussion_A2_03','believe','/bɪˈliːv/','verb','믿다, ~라고 생각하다','To accept that something is true or to hold an opinion.','I {believe} everyone should have a say.','모두가 발언권을 가져야 한다고 생각해요.','believe','A2','discussion',1,'person confident belief conviction'),
('w_discussion_A2_04','understand','/ˌʌndəˈstænd/','verb','이해하다','To know the meaning or reason for something.','I {understand} your concern, but I disagree.','당신의 우려를 이해하지만, 동의하지는 않아요.','understand','A2','discussion',1,'lightbulb comprehension understanding'),
('w_discussion_A2_05','disagree','/ˌdɪsəˈɡriː/','verb','동의하지 않다','To have a different opinion from someone else.','I have to {disagree} with that statement.','그 주장에는 동의하기 어려워요.','disagree','A2','discussion',1,'two people differing opinions'),
('w_discussion_A2_06','discuss','/dɪˈskʌs/','verb','토론하다, 논의하다','To talk about a topic, considering different opinions.','Let us {discuss} the pros and cons.','장단점에 대해 논의해 봐요.','discuss','A2','discussion',1,'group discussion meeting table'),
('w_discussion_A2_07','point','/pɔɪnt/','noun','요점, 핵심','The main idea or most important aspect of something.','You make a good {point} about the budget.','예산에 관해 좋은 지적을 해주셨어요.','point','A2','discussion',1,'arrow pointing key point'),
('w_discussion_A2_08','reason','/ˈriːzən/','noun','이유, 근거','A cause or explanation for a belief or action.','What is the main {reason} for your opinion?','당신 의견의 주된 이유가 뭔가요?','reason','A2','discussion',1,'why reason logic thinking'),
('w_discussion_A2_09','example','/ɪɡˈzɑːmpəl/','noun','예시','A thing characteristic of its kind; used to illustrate.','Could you give me an {example}?','예시를 들어주실 수 있나요?','example','A2','discussion',1,'for example presentation slide'),
('w_discussion_A2_10','explain','/ɪkˈspleɪn/','verb','설명하다','To make something clear or easy to understand.','Could you {explain} your reasoning?','당신의 논리를 설명해 주실 수 있나요?','explain','A2','discussion',1,'teacher explaining diagram'),
('w_discussion_A2_11','mean','/miːn/','verb','의미하다','To intend or to have as a meaning.','What exactly do you {mean} by that?','정확히 무슨 말씀이에요?','mean','A2','discussion',1,'person clarifying confused expression'),
('w_discussion_A2_12','wrong','/rɒŋ/','adjective','틀린','Not correct or true; mistaken.','I think that conclusion is {wrong}.','그 결론은 틀린 것 같아요.','wrong','A2','discussion',1,'X mark wrong incorrect'),
('w_discussion_A2_13','correct','/kəˈrekt/','adjective','올바른, 맞는','Free from error; conforming to fact.','You are {correct} about the statistics.','통계에 대해서는 맞아요.','correct','A2','discussion',1,'checkmark correct accurate'),
('w_discussion_A2_14','problem','/ˈprɒbləm/','noun','문제','A matter that is difficult to deal with.','The main {problem} with this idea is the cost.','이 아이디어의 주요 문제점은 비용이에요.','problem','A2','discussion',1,'obstacle problem solving'),
('w_discussion_A2_15','solution','/səˈluːʃən/','noun','해결책','A means of solving a problem.','Do you have a {solution} in mind?','생각해 둔 해결책이 있나요?','solution','A2','discussion',1,'lightbulb solution problem solved'),
('w_discussion_A2_16','both','/boʊθ/','determiner','둘 다','Used to refer to two things or people equally.','{Both} sides have valid arguments.','양쪽 모두 타당한 주장이 있어요.','Both','A2','discussion',2,'balance scale two sides'),
('w_discussion_A2_17','important','/ɪmˈpɔːrtənt/','adjective','중요한','Of great significance or value.','It is {important} to listen to everyone.','모두의 의견을 듣는 것이 중요해요.','important','A2','discussion',1,'important priority star'),
('w_discussion_A2_18','better','/ˈbetər/','adjective','더 나은','Of a higher standard or quality compared to something else.','I think this plan is {better}.','이 계획이 더 낫다고 생각해요.','better','A2','discussion',2,'improvement better arrow up'),
('w_discussion_A2_19','clear','/klɪər/','adjective','명확한','Easy to understand; not ambiguous.','Let me make this {clear} for everyone.','모두를 위해 이것을 명확히 할게요.','clear','A2','discussion',1,'clarity clear transparent'),
('w_discussion_A2_20','feel','/fiːl/','verb','느끼다, ~라고 생각하다','To experience an emotion or to have an opinion.','I {feel} strongly about this issue.','이 문제에 대해 강하게 느껴요.','feel','A2','discussion',1,'person feeling strong emotion'),
('w_discussion_A2_21','sure','/ʃʊər/','adjective','확신하는','Having no doubt; certain.','I am not {sure} about that claim.','그 주장에 대해 확신이 없어요.','sure','A2','discussion',2,'unsure uncertain thinking person'),
('w_discussion_A2_22','together','/təˈɡeðər/','adverb','함께','With or in proximity to another person or group.','Let us work on this {together}.','함께 이것을 해결해 봐요.','together','A2','discussion',2,'team collaboration together'),
('w_discussion_A2_23','compare','/kəmˈpeər/','verb','비교하다','To examine the differences and similarities between things.','{Compare} the two options before deciding.','결정하기 전에 두 가지 선택지를 비교해요.','Compare','A2','discussion',2,'comparison two options scale'),
('w_discussion_A2_24','choose','/tʃuːz/','verb','선택하다','To pick out or select as being the best of two or more.','How should we {choose} between these ideas?','이 아이디어들 중에서 어떻게 선택해야 할까요?','choose','A2','discussion',2,'decision choice crossroads'),
('w_discussion_A2_25','change','/tʃeɪndʒ/','verb','바꾸다','To make or become different.','I have {changed} my mind on this.','이것에 대해 마음이 바뀌었어요.','changed','A2','discussion',2,'change mind arrow turning'),
('w_discussion_A2_26','main','/meɪn/','adjective','주된, 핵심','Most important; principal.','What is the {main} argument here?','여기서 주된 논점이 뭔가요?','main','A2','discussion',2,'central main point highlight'),
('w_discussion_A2_27','prove','/pruːv/','verb','증명하다','To demonstrate that something is true or correct.','Can you {prove} that claim with data?','그 주장을 데이터로 증명할 수 있나요?','prove','A2','discussion',1,'data evidence proof document'),
('w_discussion_A2_28','fact','/fækt/','noun','사실','A thing that is known or proved to be true.','Let us stick to the {facts}.','사실에 근거해서 이야기해요.','facts','A2','discussion',1,'facts data truth document'),
('w_discussion_A2_29','mind','/maɪnd/','noun','마음, 생각','The element of a person that enables thinking and feeling.','Keep an open {mind} during the discussion.','토론 중에는 열린 마음을 가져요.','mind','A2','discussion',2,'open mind brain thinking'),
('w_discussion_A2_30','share','/ʃeər/','verb','나누다, 공유하다','To give a portion of something or to tell others your thoughts.','{Share} your thoughts with the group.','그룹과 생각을 나눠주세요.','Share','A2','discussion',1,'sharing ideas group discussion'),
('w_discussion_A2_31','positive','/ˈpɒzətɪv/','adjective','긍정적인','Constructive, optimistic, or indicating agreement.','Let us focus on the {positive} aspects.','긍정적인 측면에 집중해요.','positive','A2','discussion',2,'positive thinking bright optimistic'),
('w_discussion_A2_32','negative','/ˈneɡətɪv/','adjective','부정적인','Expressing refusal or disagreement; harmful or bad.','There are also some {negative} effects to consider.','고려해야 할 부정적인 영향도 있어요.','negative','A2','discussion',2,'negative downside risk warning'),
('w_discussion_A2_33','side','/saɪd/','noun','측면, 입장','One of the positions in a debate or argument.','I can see both {sides} of the argument.','논쟁의 양면을 다 볼 수 있어요.','sides','A2','discussion',1,'balance two sides debate'),
('w_discussion_A2_34','view','/vjuː/','noun','견해, 관점','A particular way of considering something; an opinion.','What is your {view} on this?','이것에 대한 당신의 견해는 뭔가요?','view','A2','discussion',1,'viewpoint perspective angle'),
('w_discussion_A2_35','respond','/rɪˈspɒnd/','verb','반응하다, 응답하다','To say or do something as a reply.','How would you {respond} to that argument?','그 주장에 어떻게 응답하시겠어요?','respond','A2','discussion',2,'reply response conversation');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_discussion_B1_01','argue','/ˈɑːrɡjuː/','verb','주장하다, 논쟁하다','To give reasons or evidence in support of an idea.','She {argues} that the policy is unfair.','그녀는 그 정책이 불공평하다고 주장해요.','argues','B1','discussion',1,'person arguing debating seriously'),
('w_discussion_B1_02','perspective','/pərˈspektɪv/','noun','관점, 시각','A particular attitude toward or way of regarding something.','From my {perspective}, the risk is too high.','제 관점에서는 위험이 너무 커요.','perspective','B1','discussion',1,'viewpoint angle perspective thinking'),
('w_discussion_B1_03','evidence','/ˈevɪdəns/','noun','증거, 근거','Facts or information indicating whether something is true.','You need to provide {evidence} for that claim.','그 주장에 대한 증거를 제시해야 해요.','evidence','B1','discussion',1,'evidence documents data research'),
('w_discussion_B1_04','support','/səˈpɔːrt/','verb','뒷받침하다, 지지하다','To provide evidence for; to help strengthen an argument.','The data {supports} our conclusion.','데이터가 우리 결론을 뒷받침해요.','supports','B1','discussion',1,'supporting evidence pillar structure'),
('w_discussion_B1_05','counter','/ˈkaʊntər/','verb','반론하다','To say something in response to an argument or claim.','How would you {counter} that objection?','그 반대 의견에 어떻게 반론하시겠어요?','counter','B1','discussion',1,'counter argument response debate'),
('w_discussion_B1_06','stance','/stæns/','noun','입장, 태도','The attitude or position taken on an issue.','What is your {stance} on this matter?','이 문제에 대한 당신의 입장이 뭐예요?','stance','B1','discussion',1,'person standing firm position'),
('w_discussion_B1_07','elaborate','/ɪˈlæbəreɪt/','verb','자세히 설명하다','To explain something in more detail.','Could you {elaborate} on that point?','그 부분에 대해 자세히 설명해 주실 수 있나요?','elaborate','B1','discussion',1,'detailed explanation whiteboard'),
('w_discussion_B1_08','claim','/kleɪm/','noun','주장','An assertion of something as fact, without proof.','That is a bold {claim} without evidence.','그건 증거 없는 대담한 주장이에요.','claim','B1','discussion',1,'bold claim assertion statement'),
('w_discussion_B1_09','viewpoint','/ˈvjuːpɔɪnt/','noun','관점, 시각','A position or perspective from which something is considered.','Let us consider multiple {viewpoints}.','다양한 관점을 고려해 봐요.','viewpoints','B1','discussion',1,'multiple perspectives angles diverse'),
('w_discussion_B1_10','debate','/dɪˈbeɪt/','noun','토론','A formal discussion in which opposing arguments are presented.','The {debate} on climate policy was intense.','기후 정책에 관한 토론이 치열했어요.','debate','B1','discussion',1,'formal debate podium discussion'),
('w_discussion_B1_11','acknowledge','/əkˈnɒlɪdʒ/','verb','인정하다','To accept or admit that something is true.','I {acknowledge} that your point has merit.','당신의 주장에 타당성이 있음을 인정해요.','acknowledge','B1','discussion',1,'person conceding acknowledging'),
('w_discussion_B1_12','challenge','/ˈtʃælɪndʒ/','verb','이의를 제기하다','To question or dispute the truth or validity of something.','I want to {challenge} that assumption.','그 가정에 이의를 제기하고 싶어요.','challenge','B1','discussion',1,'challenge question debate assumption'),
('w_discussion_B1_13','logical','/ˈlɒdʒɪkəl/','adjective','논리적인','Consistent with sound reasoning; rational.','Your argument is not very {logical}.','당신의 주장은 그다지 논리적이지 않아요.','logical','B1','discussion',1,'logic diagram reasoning flowchart'),
('w_discussion_B1_14','conclude','/kənˈkluːd/','verb','결론 내리다','To arrive at a judgment or decision by reasoning.','What can we {conclude} from this data?','이 데이터에서 무엇을 결론 내릴 수 있을까요?','conclude','B1','discussion',1,'conclusion summary final decision'),
('w_discussion_B1_15','assume','/əˈsjuːm/','verb','가정하다','To suppose that something is true without proof.','Do not {assume} the outcome before we know.','알기 전에 결과를 가정하지 마세요.','assume','B1','discussion',1,'assumption guess uncertain thinking'),
('w_discussion_B1_16','relevant','/ˈreləvənt/','adjective','관련 있는','Closely connected with or appropriate to the topic.','Is this information {relevant} to our discussion?','이 정보가 우리 토론과 관련이 있나요?','relevant','B1','discussion',1,'relevant connected related topic'),
('w_discussion_B1_17','valid','/ˈvælɪd/','adjective','타당한, 유효한','Well-grounded or justifiable; logically sound.','That is a {valid} concern.','그건 타당한 우려예요.','valid','B1','discussion',1,'valid checkmark approved argument'),
('w_discussion_B1_18','consider','/kənˈsɪdər/','verb','고려하다','To think carefully about something.','We should {consider} all the options.','모든 선택지를 고려해야 해요.','consider','B1','discussion',1,'consideration thinking weighing options'),
('w_discussion_B1_19','raise','/reɪz/','verb','제기하다','To bring a subject to someone''s attention for discussion.','I''d like to {raise} an important issue.','중요한 문제를 제기하고 싶어요.','raise','B1','discussion',1,'raising issue hand up speaking'),
('w_discussion_B1_20','convince','/kənˈvɪns/','verb','설득하다','To persuade someone to believe something through reasoning.','I cannot {convince} you without evidence.','증거 없이는 설득할 수 없어요.','convince','B1','discussion',1,'persuade convince argument person'),
('w_discussion_B1_21','summarize','/ˈsʌməraɪz/','verb','요약하다','To give a brief statement of the main points.','Let me {summarize} the key points.','핵심 요점을 요약해 드릴게요.','summarize','B1','discussion',1,'summary brief outline key points'),
('w_discussion_B1_22','objective','/əbˈdʒektɪv/','adjective','객관적인','Not influenced by personal feelings; based on facts.','Try to be {objective} in your assessment.','평가할 때 객관적으로 하려고 해요.','objective','B1','discussion',1,'balanced scale objective fair'),
('w_discussion_B1_23','subjective','/səbˈdʒektɪv/','adjective','주관적인','Based on personal feelings or opinions rather than facts.','That is a very {subjective} judgment.','그건 매우 주관적인 판단이에요.','subjective','B1','discussion',1,'personal opinion subjective feeling'),
('w_discussion_B1_24','context','/ˈkɒntekst/','noun','맥락, 상황','The circumstances that form the setting for an event or idea.','You need to understand the {context}.','맥락을 이해할 필요가 있어요.','context','B1','discussion',1,'context background setting environment'),
('w_discussion_B1_25','imply','/ɪmˈplaɪ/','verb','암시하다','To strongly suggest something without directly stating it.','What are you {implying} with that comment?','그 발언으로 무엇을 암시하는 건가요?','implying','B1','discussion',1,'hint imply suggestion subtle meaning'),
('w_discussion_B1_26','impact','/ˈɪmpækt/','noun','영향, 충격','The effect or influence of one thing on another.','What is the {impact} of this decision?','이 결정의 영향이 뭔가요?','impact','B1','discussion',1,'impact influence effect ripple'),
('w_discussion_B1_27','oppose','/əˈpoʊz/','verb','반대하다','To be in conflict with or disagree strongly with something.','I strongly {oppose} this proposal.','이 제안에 강하게 반대해요.','oppose','B1','discussion',1,'opposition protest disagree strongly'),
('w_discussion_B1_28','maintain','/meɪnˈteɪn/','verb','주장을 유지하다','To continue to assert or uphold a position.','I still {maintain} that I was right.','저는 여전히 제가 맞다고 주장해요.','maintain','B1','discussion',1,'firm position maintain stance'),
('w_discussion_B1_29','emphasize','/ˈemfəsaɪz/','verb','강조하다','To give special importance or prominence to.','I want to {emphasize} the deadline.','마감일을 강조하고 싶어요.','emphasize','B1','discussion',1,'emphasize highlight underline important'),
('w_discussion_B1_30','fair','/feər/','adjective','공정한','Treating people equally; just and reasonable.','That does not seem {fair} to everyone.','그게 모두에게 공정해 보이지 않아요.','fair','B1','discussion',1,'fairness justice balance scale'),
('w_discussion_B1_31','admit','/ədˈmɪt/','verb','인정하다','To confess or acknowledge something as true.','I {admit} I had not thought of that.','그건 생각하지 못했다는 걸 인정해요.','admit','B1','discussion',1,'admit concede honest acknowledgment'),
('w_discussion_B1_32','alternative','/ɔːlˈtɜːrnətɪv/','noun','대안','One of two or more available possibilities.','Do you have any {alternative} suggestions?','다른 대안적 제안이 있나요?','alternative','B1','discussion',1,'alternative option choice branch'),
('w_discussion_B1_33','propose','/prəˈpoʊz/','verb','제안하다','To put forward a plan for consideration.','I would like to {propose} a compromise.','타협안을 제안하고 싶어요.','propose','B1','discussion',1,'proposal plan whiteboard meeting'),
('w_discussion_B1_34','reflect','/rɪˈflekt/','verb','반영하다; 깊이 생각하다','To think deeply about something; to show or express something.','Take a moment to {reflect} on what was said.','말해진 것에 대해 잠시 생각해 봐요.','reflect','B1','discussion',2,'reflection thinking deep thought mirror'),
('w_discussion_B1_35','exchange','/ɪksˈtʃeɪndʒ/','noun','교환, 의견 나눔','An act of giving and receiving ideas or opinions.','This {exchange} of ideas has been very helpful.','이런 의견 교환이 매우 유익했어요.','exchange','B1','discussion',2,'exchange ideas conversation dialogue');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_discussion_B2_01','rebut','/rɪˈbʌt/','verb','반박하다','To claim or prove that something is false or mistaken.','She was quick to {rebut} his claims.','그녀는 그의 주장을 빠르게 반박했어요.','rebut','B2','discussion',1,'rebuttal counter argument debate'),
('w_discussion_B2_02','substantiate','/səbˈstænʃieɪt/','verb','입증하다','To provide evidence to prove the truth of something.','You need to {substantiate} your argument.','당신의 주장을 입증해야 해요.','substantiate','B2','discussion',1,'evidence proof substantiate document'),
('w_discussion_B2_03','critique','/krɪˈtiːk/','noun','비평, 비판적 분석','A detailed analysis and assessment of something.','Let me offer a {critique} of this proposal.','이 제안에 대한 비평을 해드릴게요.','critique','B2','discussion',1,'critical analysis review evaluation'),
('w_discussion_B2_04','nuance','/ˈnjuːɑːns/','noun','뉘앙스, 미묘한 차이','A subtle difference in meaning, expression, or response.','The {nuance} of her argument was lost on him.','그녀 주장의 뉘앙스가 그에게 전달되지 않았어요.','nuance','B2','discussion',1,'subtle nuance shades meaning'),
('w_discussion_B2_05','premise','/ˈpremɪs/','noun','전제','A previous statement or proposition from which a conclusion is drawn.','The {premise} of your argument is flawed.','당신 주장의 전제가 잘못됐어요.','premise','B2','discussion',1,'foundation premise logic argument'),
('w_discussion_B2_06','inference','/ˈɪnfərəns/','noun','추론','A conclusion reached on the basis of evidence and reasoning.','That is a reasonable {inference} from the data.','그건 데이터에서 나온 합리적인 추론이에요.','inference','B2','discussion',1,'inference conclusion logic data'),
('w_discussion_B2_07','fallacy','/ˈfæləsi/','noun','오류, 오류 논리','A mistaken belief or a flaw in reasoning.','That is a classic logical {fallacy}.','그건 전형적인 논리적 오류예요.','fallacy','B2','discussion',1,'logical fallacy error flaw reasoning'),
('w_discussion_B2_08','rhetoric','/ˈretərɪk/','noun','수사학; 미사여구','The art of effective persuasion; sometimes used to mean empty language.','Do not let {rhetoric} replace genuine reasoning.','수사로 진짜 논리를 대체하지 마세요.','rhetoric','B2','discussion',1,'rhetoric speech persuasion words'),
('w_discussion_B2_09','bias','/ˈbaɪəs/','noun','편견, 편향','Inclination or prejudice for or against one person or group.','We must be aware of our own {bias}.','우리 자신의 편향을 인식해야 해요.','bias','B2','discussion',1,'bias prejudice tilt scale'),
('w_discussion_B2_10','objectivity','/ˌɒbdʒekˈtɪvɪti/','noun','객관성','The quality of being impartial and not influenced by feelings.','Journalists should strive for {objectivity}.','기자들은 객관성을 위해 노력해야 해요.','objectivity','B2','discussion',1,'objectivity balance impartial journalism'),
('w_discussion_B2_11','concede','/kənˈsiːd/','verb','인정하다, 양보하다','To acknowledge, often reluctantly, that something is true.','I {concede} that you have a point there.','거기서 당신의 주장이 맞다는 것을 인정해요.','concede','B2','discussion',1,'concede admit defeat graceful'),
('w_discussion_B2_12','ambiguous','/æmˈbɪɡjuəs/','adjective','모호한','Open to more than one interpretation; not clear.','The wording of the statement is {ambiguous}.','그 진술의 표현이 모호해요.','ambiguous','B2','discussion',1,'ambiguous unclear multiple meanings'),
('w_discussion_B2_13','contradict','/ˌkɒntrəˈdɪkt/','verb','모순되다, 반박하다','To state the opposite of what someone else has said.','The evidence {contradicts} your claim.','증거가 당신의 주장과 모순돼요.','contradicts','B2','discussion',1,'contradiction clash opposing ideas'),
('w_discussion_B2_14','assert','/əˈsɜːrt/','verb','주장하다, 단언하다','To state a fact or belief confidently and forcefully.','She {asserts} that the research is flawed.','그녀는 그 연구가 결함이 있다고 단언해요.','asserts','B2','discussion',1,'assertion confident statement claim'),
('w_discussion_B2_15','underlying','/ˌʌndəˈlaɪɪŋ/','adjective','근본적인, 기저의','Existing beneath what is obvious; fundamental.','What is the {underlying} cause of this issue?','이 문제의 근본적인 원인이 뭔가요?','underlying','B2','discussion',1,'root cause foundation underlying layer'),
('w_discussion_B2_16','implication','/ˌɪmplɪˈkeɪʃən/','noun','함의, 암시','The conclusion that can be drawn from something; a suggestion.','What are the {implications} of this policy?','이 정책의 함의가 뭔가요?','implications','B2','discussion',1,'implication consequence ripple effect'),
('w_discussion_B2_17','coherent','/koʊˈhɪərənt/','adjective','일관성 있는','Logical and consistent; forming a unified whole.','Your argument is not {coherent}.','당신의 주장에 일관성이 없어요.','coherent','B2','discussion',1,'coherent logical flow connected'),
('w_discussion_B2_18','scrutinize','/ˈskruːtɪnaɪz/','verb','면밀히 검토하다','To examine closely and thoroughly.','We should {scrutinize} this data carefully.','이 데이터를 면밀히 검토해야 해요.','scrutinize','B2','discussion',1,'scrutiny close examination magnifying glass'),
('w_discussion_B2_19','refine','/rɪˈfaɪn/','verb','다듬다, 정제하다','To improve something by making small changes.','Let us {refine} the argument further.','주장을 더 다듬어 봐요.','refine','B2','discussion',2,'refine improve polish argument'),
('w_discussion_B2_20','discrepancy','/dɪˈskrepənsi/','noun','불일치, 차이','An illogical or surprising lack of compatibility between two facts.','There is a {discrepancy} in the data.','데이터에 불일치가 있어요.','discrepancy','B2','discussion',1,'discrepancy mismatch data conflict'),
('w_discussion_B2_21','advocate','/ˈædvəkeɪt/','verb','옹호하다, 지지하다','To publicly recommend or support a cause or policy.','She {advocates} for stricter environmental laws.','그녀는 더 엄격한 환경법을 옹호해요.','advocates','B2','discussion',1,'advocate support campaign speaking'),
('w_discussion_B2_22','inconsistency','/ˌɪnkənˈsɪstənsi/','noun','비일관성, 모순','The quality of not staying the same throughout.','Point out any {inconsistency} in the reasoning.','논리에서의 모순을 지적해 주세요.','inconsistency','B2','discussion',1,'inconsistency contradiction mismatch'),
('w_discussion_B2_23','compelling','/kəmˈpelɪŋ/','adjective','설득력 있는','Evoking interest, attention, or admiration powerfully.','That is a {compelling} argument.','그건 설득력 있는 주장이에요.','compelling','B2','discussion',1,'compelling powerful persuasive strong'),
('w_discussion_B2_24','mitigate','/ˈmɪtɪɡeɪt/','verb','완화하다','To make something less severe, serious, or painful.','How do we {mitigate} the risks?','위험을 어떻게 완화할 수 있을까요?','mitigate','B2','discussion',1,'mitigate reduce risk buffer'),
('w_discussion_B2_25','polarize','/ˈpoʊləraɪz/','verb','양극화시키다','To divide into two sharply opposing groups.','This issue tends to {polarize} opinions.','이 문제는 의견을 양극화시키는 경향이 있어요.','polarize','B2','discussion',1,'polarize divide two sides extreme'),
('w_discussion_B2_26','provisional','/prəˈvɪʒənəl/','adjective','잠정적인','Arranged or existing for the present, possibly to be changed later.','This is only a {provisional} conclusion.','이것은 잠정적인 결론에 불과해요.','provisional','B2','discussion',2,'provisional temporary pending review'),
('w_discussion_B2_27','explicit','/ɪkˈsplɪsɪt/','adjective','명시적인, 명확한','Stated clearly and in detail; leaving nothing implied.','Be more {explicit} about what you mean.','무슨 의미인지 더 명확하게 말해주세요.','explicit','B2','discussion',1,'explicit clear direct statement'),
('w_discussion_B2_28','critical','/ˈkrɪtɪkəl/','adjective','비판적인, 중요한','Expressing disapproval; or of great importance.','We need a {critical} analysis of these claims.','이 주장들에 대한 비판적 분석이 필요해요.','critical','B2','discussion',1,'critical thinking analysis evaluation'),
('w_discussion_B2_29','oversimplify','/ˌoʊvərˈsɪmplɪfaɪ/','verb','지나치게 단순화하다','To describe something in simpler terms than it really is.','Be careful not to {oversimplify} the issue.','문제를 지나치게 단순화하지 않도록 주의해요.','oversimplify','B2','discussion',2,'oversimplify complex issue reduction'),
('w_discussion_B2_30','hypothetical','/ˌhaɪpəˈθetɪkəl/','adjective','가상의, 가정의','Imagined or suggested as a possible scenario.','Let us consider a {hypothetical} situation.','가상의 상황을 생각해 봐요.','hypothetical','B2','discussion',2,'hypothetical scenario thought experiment'),
('w_discussion_B2_31','empirical','/ɪmˈpɪrɪkəl/','adjective','경험적인, 실증적인','Based on observation or experience rather than theory.','The {empirical} evidence does not support this.','실증적 증거가 이것을 지지하지 않아요.','empirical','B2','discussion',1,'empirical data research evidence'),
('w_discussion_B2_32','framework','/ˈfreɪmwɜːrk/','noun','틀, 체계','A basic structure underlying a system, concept, or text.','We need a clear {framework} for this debate.','이 토론을 위한 명확한 틀이 필요해요.','framework','B2','discussion',1,'framework structure system organization'),
('w_discussion_B2_33','concession','/kənˈseʃən/','noun','양보, 인정','An acknowledgment that something is true or valid.','Making a {concession} can strengthen your overall position.','양보를 하면 전체적인 입장이 강화될 수 있어요.','concession','B2','discussion',2,'concession compromise negotiate'),
('w_discussion_B2_34','diverge','/daɪˈvɜːrdʒ/','verb','갈라지다, 의견이 나뉘다','To differ in opinion or direction from something.','Our views {diverge} sharply on this point.','이 지점에서 우리 견해는 크게 갈려요.','diverge','B2','discussion',2,'diverge split difference opinion fork'),
('w_discussion_B2_35','consensus','/kənˈsensəs/','noun','합의, 의견 일치','A general agreement reached by a group.','Can we reach a {consensus} on this issue?','이 문제에 대해 합의에 도달할 수 있을까요?','consensus','B2','discussion',1,'consensus agreement group decision');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_discussion_C1_01','dialectic','/ˌdaɪəˈlektɪk/','noun','변증법','The art of investigating the truth of opinions through discussion.','Hegel''s {dialectic} involves thesis, antithesis, and synthesis.','헤겔의 변증법은 정반합을 포함해요.','dialectic','C1','discussion',1,'dialectic philosophy Hegel thesis antithesis'),
('w_discussion_C1_02','proposition','/ˌprɒpəˈzɪʃən/','noun','명제, 제안','A statement that expresses a judgment or opinion.','The {proposition} that all humans are equal is debatable.','모든 인간이 평등하다는 명제는 논쟁의 여지가 있어요.','proposition','C1','discussion',1,'proposition statement logic philosophy'),
('w_discussion_C1_03','syllogism','/ˈsɪlədʒɪzəm/','noun','삼단논법','A form of reasoning in which a conclusion is drawn from two premises.','His argument followed a classic {syllogism}.','그의 주장은 고전적인 삼단논법을 따랐어요.','syllogism','C1','discussion',1,'syllogism logic deductive reasoning diagram'),
('w_discussion_C1_04','epistemology','/ɪˌpɪstɪˈmɒlədʒi/','noun','인식론','The branch of philosophy concerned with the theory of knowledge.','{Epistemology} asks how we can know anything at all.','인식론은 우리가 무엇인가를 어떻게 알 수 있는지 묻는 철학이에요.','Epistemology','C1','discussion',1,'epistemology knowledge philosophy books'),
('w_discussion_C1_05','sophistry','/ˈsɒfɪstri/','noun','궤변, 속임수 논리','The use of clever but false arguments, especially to deceive.','His debate technique was full of {sophistry}.','그의 토론 기술은 궤변으로 가득했어요.','sophistry','C1','discussion',1,'sophistry false argument deceptive reasoning'),
('w_discussion_C1_06','axiom','/ˈæksiəm/','noun','공리, 자명한 이치','A statement or proposition regarded as self-evidently true.','It is an {axiom} that equals should be treated equally.','평등한 사람은 평등하게 대우받아야 한다는 건 공리예요.','axiom','C1','discussion',1,'axiom self evident truth principle'),
('w_discussion_C1_07','inductive','/ɪnˈdʌktɪv/','adjective','귀납적','Relating to reasoning from specific cases to general principles.','{Inductive} reasoning moves from observation to theory.','귀납적 추론은 관찰에서 이론으로 나아가요.','Inductive','C1','discussion',1,'inductive reasoning specific to general'),
('w_discussion_C1_08','deductive','/dɪˈdʌktɪv/','adjective','연역적','Relating to reasoning from general principles to specific cases.','{Deductive} logic starts with a general premise.','연역적 논리는 일반적인 전제에서 시작해요.','Deductive','C1','discussion',1,'deductive reasoning general to specific'),
('w_discussion_C1_09','postulate','/ˈpɒstjʊleɪt/','verb','가정하다, 공리로 내세우다','To suggest or assume the existence of something as a basis for reasoning.','The theory {postulates} a fundamental connection.','이론은 근본적인 연결을 가정하고 있어요.','postulates','C1','discussion',1,'postulate assumption foundation theory'),
('w_discussion_C1_10','refutation','/ˌrefjʊˈteɪʃən/','noun','반박, 논박','The action of proving a statement to be wrong or false.','Her {refutation} of the theory was thorough.','그녀의 이론 반박은 철저했어요.','refutation','C1','discussion',1,'refutation disprove evidence argument'),
('w_discussion_C1_11','cogent','/ˈkoʊdʒənt/','adjective','논리적으로 설득력 있는','Appealing to the intellect or reason; convincing and well-reasoned.','She presented a {cogent} case for reform.','그녀는 개혁을 위한 설득력 있는 논거를 제시했어요.','cogent','C1','discussion',1,'cogent argument strong reasoning'),
('w_discussion_C1_12','pedantic','/pɪˈdæntɪk/','adjective','현학적인, 지나치게 꼼꼼한','Excessively concerned with minor details or formality.','His argument became overly {pedantic}.','그의 주장이 지나치게 현학적이 됐어요.','pedantic','C1','discussion',2,'pedantic detail obsessive academic'),
('w_discussion_C1_13','conjecture','/kənˈdʒektʃər/','noun','추측, 가설','An opinion formed without firm evidence; speculation.','This is {conjecture}, not established fact.','이건 확립된 사실이 아니라 추측이에요.','conjecture','C1','discussion',1,'conjecture speculation guess unproven'),
('w_discussion_C1_14','dichotomy','/daɪˈkɒtəmi/','noun','이분법, 양분','A division between two things that are opposite or different.','The {dichotomy} between reason and emotion is false.','이성과 감정 사이의 이분법은 잘못됐어요.','dichotomy','C1','discussion',1,'dichotomy two opposites division'),
('w_discussion_C1_15','tautology','/tɔːˈtɒlədʒi/','noun','동어반복','Saying the same thing twice in different words; circular reasoning.','Calling it a "free gift" is a {tautology}.','그것을 "무료 선물"이라고 부르는 건 동어반복이에요.','tautology','C1','discussion',2,'tautology circular redundant repetition'),
('w_discussion_C1_16','presuppose','/ˌpriːsəˈpoʊz/','verb','전제로 하다','To require something as a prior condition; to assume in advance.','That question {presupposes} a shared definition.','그 질문은 공유된 정의를 전제로 해요.','presupposes','C1','discussion',1,'presuppose assumption prior condition'),
('w_discussion_C1_17','reductive','/rɪˈdʌktɪv/','adjective','환원주의적인, 지나치게 단순화하는','Tending to present something in an oversimplified way.','Your explanation is a bit {reductive}.','당신의 설명이 좀 환원주의적이에요.','reductive','C1','discussion',2,'reductive oversimplified complex reduced'),
('w_discussion_C1_18','specious','/ˈspiːʃəs/','adjective','그럴듯해 보이지만 잘못된','Superficially plausible but actually wrong.','That is a {specious} argument at best.','그건 기껏해야 그럴듯해 보이는 주장이에요.','specious','C1','discussion',1,'specious misleading plausible false'),
('w_discussion_C1_19','tangential','/tænˈdʒenʃəl/','adjective','본론에서 벗어난, 주변적인','Only slightly related to the main topic; diverging.','That comment is {tangential} to the core issue.','그 발언은 핵심 문제에서 벗어난 이야기예요.','tangential','C1','discussion',2,'tangential off-topic diverging'),
('w_discussion_C1_20','iterate','/ˈɪtəreɪt/','verb','반복하다; 되풀이하여 강조하다','To repeat a process or idea, often to refine it.','I want to {iterate} the importance of this point.','이 점의 중요성을 반복해서 강조하고 싶어요.','iterate','C1','discussion',2,'iterate repeat refine process'),
('w_discussion_C1_21','predicate','/ˈpredɪkeɪt/','verb','~에 근거하다; 전제하다','To base an argument or statement on something.','The theory is {predicated} on a false assumption.','그 이론은 잘못된 가정에 근거하고 있어요.','predicated','C1','discussion',1,'predicate base foundation argument'),
('w_discussion_C1_22','arbitrate','/ˈɑːrbɪtreɪt/','verb','중재하다','To reach an authoritative judgment or settle a dispute.','A neutral party was called in to {arbitrate}.','중립적인 측에게 중재를 부탁했어요.','arbitrate','C1','discussion',2,'arbitrate mediate settle dispute neutral'),
('w_discussion_C1_23','reconcile','/ˈrekənsaɪl/','verb','화해시키다; 조화시키다','To find a way to make two opposing views compatible.','Can we {reconcile} these two positions?','이 두 입장을 조화시킬 수 있을까요?','reconcile','C1','discussion',1,'reconcile bridge gap two sides'),
('w_discussion_C1_24','warrant','/ˈwɒrənt/','verb','정당화하다, 근거가 되다','To justify or make necessary; to be a reason for.','Does the evidence {warrant} that conclusion?','증거가 그 결론을 정당화하나요?','warrant','C1','discussion',1,'warrant justify evidence conclusion'),
('w_discussion_C1_25','extrapolate','/ɪkˈstræpəleɪt/','verb','추론하다, 외삽하다','To extend a principle to a larger or different situation.','We should not {extrapolate} too broadly from one case.','한 사례에서 너무 광범위하게 추론하면 안 돼요.','extrapolate','C1','discussion',1,'extrapolate extend data trend'),
('w_discussion_C1_26','nuanced','/ˈnjuːɑːnst/','adjective','미묘한 차이가 있는, 섬세한','Characterized by subtle distinctions or fine shades of meaning.','The issue requires a more {nuanced} analysis.','그 문제는 더 섬세한 분석이 필요해요.','nuanced','C1','discussion',1,'nuanced subtle detail analysis'),
('w_discussion_C1_27','categorical','/ˌkætɪˈɡɒrɪkəl/','adjective','단호한, 범주적인','Unambiguously explicit and direct; relating to a category.','I make a {categorical} rejection of that claim.','그 주장을 단호하게 거부해요.','categorical','C1','discussion',1,'categorical clear definitive rejection'),
('w_discussion_C1_28','invoke','/ɪnˈvoʊk/','verb','들먹이다, 원용하다','To cite or appeal to a principle or authority as a justification.','She {invoked} the principle of fairness.','그녀는 공정성 원칙을 들먹였어요.','invoked','C1','discussion',1,'invoke cite appeal authority principle'),
('w_discussion_C1_29','deconstruct','/ˌdiːkənˈstrʌkt/','verb','해체하다, 분석하다','To analyze and break apart an argument or concept.','Let me {deconstruct} that claim piece by piece.','그 주장을 하나씩 분석해 볼게요.','deconstruct','C1','discussion',1,'deconstruct analyze break down argument'),
('w_discussion_C1_30','epistemic','/ˌepɪˈstemɪk/','adjective','인식론적인','Relating to knowledge or the degree of its validation.','There is an {epistemic} limit to what we can know.','우리가 알 수 있는 것에는 인식론적 한계가 있어요.','epistemic','C1','discussion',2,'epistemic knowledge limit philosophy'),
('w_discussion_C1_31','impute','/ɪmˈpjuːt/','verb','귀속시키다, ~탓으로 돌리다','To attribute a quality or action to someone.','Do not {impute} motives to others without evidence.','증거 없이 다른 사람에게 동기를 귀속시키지 마세요.','impute','C1','discussion',2,'impute attribute blame motive'),
('w_discussion_C1_32','modality','/moʊˈdælɪti/','noun','양상, 방식','A particular form or mode of expressing something.','The {modality} of the argument shifts throughout.','주장의 양상이 전반에 걸쳐 변해요.','modality','C1','discussion',2,'modality mode expression form'),
('w_discussion_C1_33','absolve','/əbˈzɒlv/','verb','면제하다, 책임을 벗기다','To declare someone free from blame or responsibility.','You cannot simply {absolve} yourself of responsibility.','단순히 책임에서 벗어날 수는 없어요.','absolve','C1','discussion',2,'absolution responsibility free blame'),
('w_discussion_C1_34','interpolate','/ɪnˈtɜːrpəleɪt/','verb','끼워 넣다; 보간하다','To insert something into a text or argument; to estimate.','Do not {interpolate} your own assumptions into the text.','텍스트에 자신의 가정을 끼워 넣지 마세요.','interpolate','C1','discussion',2,'interpolate insert estimate assumption'),
('w_discussion_C1_35','dissertation','/ˌdɪsəˈteɪʃən/','noun','논문, 상세한 논술','A long essay, especially one written for a university degree.','Her {dissertation} explored the ethics of AI.','그녀의 논문은 AI 윤리를 탐구했어요.','dissertation','C1','discussion',2,'dissertation thesis academic writing');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_discussion_C2_01','hermeneutic','/ˌhɜːrmɪˈnjuːtɪk/','adjective','해석학적인','Relating to interpretation, especially of texts or philosophical problems.','The {hermeneutic} approach reads texts in their historical context.','해석학적 접근법은 역사적 맥락에서 텍스트를 읽어요.','hermeneutic','C2','discussion',1,'hermeneutics interpretation text meaning'),
('w_discussion_C2_02','aporia','/əˈpɔːriə/','noun','아포리아, 철학적 난점','A state of puzzlement or irresolvable conflict in philosophical dialogue.','Socrates often led his interlocutors to {aporia}.','소크라테스는 종종 대화 상대자를 아포리아로 이끌었어요.','aporia','C2','discussion',1,'aporia Socrates philosophical impasse'),
('w_discussion_C2_03','deconstruction','/ˌdiːkənˈstrʌkʃən/','noun','해체주의','A method of critical analysis associated with Derrida that questions fixed meaning.','{Deconstruction} challenges stable meaning in language.','해체주의는 언어에서의 안정적 의미에 의문을 제기해요.','Deconstruction','C2','discussion',1,'deconstruction Derrida language meaning'),
('w_discussion_C2_04','logocentrism','/ˌloʊɡoʊˈsentrɪzəm/','noun','로고스 중심주의','The assumption that reason and the Word are at the centre of meaning.','{Logocentrism} privileges spoken language over written text.','로고스 중심주의는 문자보다 구어를 특권화해요.','Logocentrism','C2','discussion',1,'logocentrism logos reason language philosophy'),
('w_discussion_C2_05','intersubjectivity','/ˌɪntərˌsʌbdʒekˈtɪvɪti/','noun','상호주관성','The sharing of subjective states by two or more individuals.','{Intersubjectivity} is essential for meaningful communication.','상호주관성은 의미 있는 소통에 필수적이에요.','Intersubjectivity','C2','discussion',1,'intersubjectivity shared understanding mutual'),
('w_discussion_C2_06','discourse','/ˈdɪskɔːrs/','noun','담론, 담화','Written or spoken communication or debate; a system of knowledge.','His work analyzes the {discourse} of power.','그의 작업은 권력의 담론을 분석해요.','discourse','C2','discussion',1,'discourse power language Foucault'),
('w_discussion_C2_07','praxis','/ˈpræksɪs/','noun','실천, 프락시스','The process by which a theory is enacted or realized.','{Praxis} unites theory and practice in critical thought.','프락시스는 비판적 사고에서 이론과 실천을 통합해요.','Praxis','C2','discussion',1,'praxis theory practice action'),
('w_discussion_C2_08','ontological','/ˌɒntəˈlɒdʒɪkəl/','adjective','존재론적인','Relating to the branch of philosophy dealing with the nature of being.','The argument has {ontological} implications.','그 주장은 존재론적인 함의를 가져요.','ontological','C2','discussion',1,'ontology being existence philosophy'),
('w_discussion_C2_09','paradigmatic','/ˌpærədɪɡˈmætɪk/','adjective','패러다임적인, 전형적인','Relating to a paradigm; serving as a typical example of something.','This case is {paradigmatic} of the larger issue.','이 사례는 더 큰 문제의 전형적인 예시예요.','paradigmatic','C2','discussion',1,'paradigm example typical model Kuhn'),
('w_discussion_C2_10','phenomenological','/fɪˌnɒmɪnəˈlɒdʒɪkəl/','adjective','현상학적인','Relating to the study of consciousness and structures of experience.','The {phenomenological} approach focuses on lived experience.','현상학적 접근법은 살아있는 경험에 집중해요.','phenomenological','C2','discussion',1,'phenomenology experience consciousness Husserl'),
('w_discussion_C2_11','teleological','/ˌteliəˈlɒdʒɪkəl/','adjective','목적론적인','Relating to the explanation of phenomena by final causes or purposes.','A {teleological} argument infers design from order.','목적론적 논증은 질서로부터 설계를 추론해요.','teleological','C2','discussion',1,'teleology purpose design argument'),
('w_discussion_C2_12','dialectical','/ˌdaɪəˈlektɪkəl/','adjective','변증법적인','Relating to the Socratic or Hegelian method of argument and reasoning.','The {dialectical} process reveals hidden contradictions.','변증법적 과정은 숨겨진 모순을 드러내요.','dialectical','C2','discussion',1,'dialectical contradiction synthesis Hegel'),
('w_discussion_C2_13','epistemological','/ɪˌpɪstɪməˈlɒdʒɪkəl/','adjective','인식론적인','Relating to the theory of knowledge and its validity.','This raises an {epistemological} question about certainty.','이것은 확실성에 관한 인식론적 질문을 제기해요.','epistemological','C2','discussion',1,'epistemological knowledge validity certainty'),
('w_discussion_C2_14','incommensurable','/ˌɪnkəˈmenʃərəbəl/','adjective','공약 불가능한, 비교 불가능한','Having no common measure; not able to be judged by the same standard.','The two frameworks are largely {incommensurable}.','두 틀은 크게 비교 불가능해요.','incommensurable','C2','discussion',2,'incommensurable incomparable different standards'),
('w_discussion_C2_15','metatheory','/ˈmetəˌθɪəri/','noun','메타이론','A theory that considers the assumptions or methods of another theory.','The paper offers a {metatheory} of argumentation.','그 논문은 논증에 관한 메타이론을 제시해요.','metatheory','C2','discussion',2,'metatheory abstract higher order theory'),
('w_discussion_C2_16','apotheosis','/əˌpɒθiˈoʊsɪs/','noun','절정, 전형','The highest point of development; the quintessence of something.','This essay represents the {apotheosis} of the argument.','이 에세이는 그 주장의 절정을 대표해요.','apotheosis','C2','discussion',2,'apotheosis peak pinnacle excellence'),
('w_discussion_C2_17','heterodox','/ˈhetərədɒks/','adjective','이단적인, 비정통적인','Not conforming to established or accepted beliefs or doctrines.','{Heterodox} economic views challenge mainstream theory.','비정통적인 경제적 관점은 주류 이론에 도전해요.','Heterodox','C2','discussion',2,'heterodox unorthodox unconventional dissenting'),
('w_discussion_C2_18','apodictic','/ˌæpəˈdɪktɪk/','adjective','자명한, 필연적으로 참인','Clearly established or beyond dispute; incontrovertibly certain.','He presented it as an {apodictic} truth.','그는 그것을 자명한 진리로 제시했어요.','apodictic','C2','discussion',2,'apodictic certain absolute undeniable'),
('w_discussion_C2_19','semiotic','/ˌsiːmiˈɒtɪk/','adjective','기호학적인','Relating to the study of signs and symbols in communication.','The {semiotic} analysis revealed hidden cultural meanings.','기호학적 분석은 숨겨진 문화적 의미를 드러냈어요.','semiotic','C2','discussion',1,'semiotics signs symbols meaning language'),
('w_discussion_C2_20','defeasible','/dɪˈfiːzɪbəl/','adjective','논박 가능한, 조건부로 타당한','Capable of being annulled; valid but open to revision in light of new evidence.','This is a {defeasible} argument, subject to new evidence.','이건 새 증거에 따라 번복될 수 있는 논박 가능한 주장이에요.','defeasible','C2','discussion',2,'defeasible revisable conditional argument'),
('w_discussion_C2_21','polysemy','/ˈpɒlɪsiːmi/','noun','다의성','The coexistence of many possible meanings for a word or phrase.','The {polysemy} of the term creates ambiguity.','그 용어의 다의성이 모호함을 만들어요.','polysemy','C2','discussion',2,'polysemy multiple meanings word ambiguity'),
('w_discussion_C2_22','immanent','/ˈɪmənənt/','adjective','내재적인','Existing within or inherent in something; not transcendent.','The contradiction is {immanent} in the system itself.','그 모순은 시스템 자체에 내재적이에요.','immanent','C2','discussion',2,'immanent inherent internal within'),
('w_discussion_C2_23','exegesis','/ˌeksɪˈdʒiːsɪs/','noun','주석, 해석, 주해','Critical explanation or interpretation of a text.','His {exegesis} of the original text was illuminating.','그의 원문 주석은 매우 시사적이었어요.','exegesis','C2','discussion',1,'exegesis interpretation commentary text'),
('w_discussion_C2_24','prolegomena','/ˌproʊlɪˈɡɒmɪnə/','noun','서론, 예비적 고찰','Preliminary remarks or observations, especially as an introduction.','The essay begins with necessary {prolegomena}.','그 에세이는 필요한 예비적 고찰로 시작해요.','prolegomena','C2','discussion',2,'prolegomena introduction preliminary remarks'),
('w_discussion_C2_25','antinomy','/ænˈtɪnəmi/','noun','이율배반','A contradiction between two apparently reasonable principles.','Kant famously described the {antinomy} of pure reason.','칸트는 순수 이성의 이율배반을 유명하게 묘사했어요.','antinomy','C2','discussion',1,'antinomy contradiction Kant reason paradox'),
('w_discussion_C2_26','qualia','/ˈkwɑːliə/','noun','감각질, 주관적 경험의 질','The internal subjective component of sense perception.','Consciousness studies grapple with the problem of {qualia}.','의식 연구는 감각질 문제와 씨름해요.','qualia','C2','discussion',2,'qualia consciousness subjective experience'),
('w_discussion_C2_27','alterity','/ɒlˈterɪti/','noun','타자성','The state of being other or different; otherness.','Levinas grounds ethics in the recognition of {alterity}.','레비나스는 타자성의 인식에서 윤리를 정초해요.','alterity','C2','discussion',2,'alterity otherness difference Levinas ethics'),
('w_discussion_C2_28','reification','/ˌreɪɪfɪˈkeɪʃən/','noun','물화, 사물화','The process of treating an abstraction as if it were concrete.','Marx critiqued the {reification} of social relations.','마르크스는 사회적 관계의 물화를 비판했어요.','reification','C2','discussion',2,'reification abstraction concrete Marx'),
('w_discussion_C2_29','transcendental','/ˌtrænsənˈdentəl/','adjective','초월적인, 선험적인','Relating to a spiritual realm beyond the physical; or Kantian a priori conditions.','Kant''s {transcendental} idealism reshaped philosophy.','칸트의 선험적 관념론은 철학을 새롭게 형성했어요.','transcendental','C2','discussion',1,'transcendental Kant idealism beyond'),
('w_discussion_C2_30','elenchus','/ɪˈleŋkəs/','noun','엘렝코스, 소크라테스식 반박','The Socratic method of refutation through cross-examination.','The {elenchus} exposes the ignorance of the interlocutor.','엘렝코스는 대화 상대자의 무지를 드러내요.','elenchus','C2','discussion',1,'elenchus Socrates cross examination refutation'),
('w_discussion_C2_31','paraconsistency','/ˌpærəkənˈsɪstənsi/','noun','준일관성, 역설 허용 논리','A property of a logic that can tolerate contradictions without explosion.','{Paraconsistency} allows for reasoning under contradiction.','준일관성은 모순 속에서도 추론을 가능하게 해요.','Paraconsistency','C2','discussion',2,'paraconsistency logic contradiction tolerance'),
('w_discussion_C2_32','autopoiesis','/ˌɔːtəʊpɔɪˈiːsɪs/','noun','자기 생산, 자기 조직','A system capable of reproducing and maintaining itself.','The discourse functions as an {autopoiesis}.','그 담론은 자기 생산적인 기능을 해요.','autopoiesis','C2','discussion',2,'autopoiesis self organization system theory'),
('w_discussion_C2_33','apophatic','/ˌæpəˈfætɪk/','adjective','부정신학적인; 부정을 통해 정의하는','Relating to the approach of describing something by saying what it is not.','The {apophatic} method defines by negation.','부정신학적 방법은 부정을 통해 정의해요.','apophatic','C2','discussion',2,'apophatic via negativa theology definition'),
('w_discussion_C2_34','metalinguistic','/ˌmetəlɪŋˈɡwɪstɪk/','adjective','메타언어학적인','Relating to language used to analyse or describe language itself.','The debate became {metalinguistic} in nature.','토론이 본질적으로 메타언어학적이 됐어요.','metalinguistic','C2','discussion',2,'metalinguistic language about language analysis'),
('w_discussion_C2_35','undecidability','/ʌndɪˌsaɪdəˈbɪlɪti/','noun','결정 불가능성','The property of a statement that can be neither proved nor disproved.','Derrida linked {undecidability} to language itself.','데리다는 결정 불가능성을 언어 자체와 연결시켰어요.','undecidability','C2','discussion',2,'undecidability Derrida language uncertainty');
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_discussion_A1_01','I think so too.','저도 그렇게 생각해요.','I think so','동의를 표현할 때 "I think so too."는 가장 자연스러운 표현이에요. "Me too."보다 대화에서 더 자연스럽게 들려요.','동의','A1','discussion','pattern',NULL,1),
('s_discussion_A1_02','I do not think that is a good idea.','그건 좋은 생각이 아닌 것 같아요.','I do not think','부드럽게 반대 의견을 말할 때 "I do not think ~"를 쓰면 직접적인 거절보다 훨씬 공손하게 들려요.','반대','A1','discussion','pattern',NULL,2),
('s_discussion_A1_03','What do you think about that?','그것에 대해 어떻게 생각해요?','What do you think','상대방의 의견을 구할 때 가장 기본적인 표현이에요. 토론을 시작하는 데 꼭 필요해요.','의견 묻기','A1','discussion','pattern',NULL,3),
('s_discussion_A1_04','Maybe you are right.','아마도 당신이 맞을 수도 있어요.','Maybe you are right','완전히 확신하지 못할 때 "Maybe"를 붙여서 유연하게 동의를 표현해요. 대화 분위기를 부드럽게 유지해줘요.','부분 동의','A1','discussion','pattern',NULL,4),
('s_discussion_A1_05','I am not sure about that.','그것에 대해 잘 모르겠어요.','I am not sure','확신이 없을 때 "I am not sure"를 쓰면 솔직하면서도 공손하게 들려요.','불확실','A1','discussion','pattern',NULL,5),
('s_discussion_A1_06','That is a good idea.','그건 좋은 생각이에요.','That is a good idea','상대방의 아이디어를 긍정할 때 가장 간단하고 자연스러운 표현이에요. 대화를 활기차게 만들어줘요.','칭찬·긍정','A1','discussion','pattern',NULL,6),
('s_discussion_A1_07','I like your idea.','당신의 아이디어가 마음에 들어요.','I like your idea','"I like your idea."는 "Good idea."보다 더 개인적이고 따뜻한 느낌을 줘요. 상대방이 기분 좋게 느낄 수 있어요.','격려·지지','A1','discussion','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_discussion_A2_01','I agree with your opinion.','당신의 의견에 동의해요.','I agree with','단순히 "I agree."보다 "I agree with your opinion."이 더 구체적이고 진지하게 들려요.','동의','A2','discussion','pattern',NULL,1),
('s_discussion_A2_02','I see your point, but I disagree.','당신의 의견은 이해하지만, 동의하지 않아요.','I see your point, but','반대 의견을 말할 때 상대방의 입장을 먼저 인정하면 더 공손하게 들려요. "I see your point, but ~"은 매우 유용한 패턴이에요.','반대','A2','discussion','pattern',NULL,2),
('s_discussion_A2_03','In my opinion, we should try a different approach.','제 의견으로는 다른 방법을 시도해야 해요.','In my opinion','자신의 의견을 말할 때 "In my opinion"을 앞에 붙이면 주관적인 견해임을 분명히 해줘요.','의견 제시','A2','discussion','pattern',NULL,3),
('s_discussion_A2_04','Could you explain your reason?','이유를 설명해 주실 수 있나요?','explain your reason','상대방의 논거를 이해하고 싶을 때 쓰는 정중한 표현이에요. 토론을 더 깊이 있게 만들어줘요.','이유 묻기','A2','discussion','pattern',NULL,4),
('s_discussion_A2_05','I think both sides have a point.','양쪽 다 일리가 있다고 생각해요.','both sides have a point','양쪽 의견을 균형 있게 인정할 때 쓰는 표현이에요. 중립적인 입장에서 토론을 진행할 때 유용해요.','중립·균형','A2','discussion','pattern',NULL,5),
('s_discussion_A2_06','Can you give me an example?','예시를 들어 주실 수 있나요?','give me an example','이해를 높이기 위해 구체적인 예를 요청할 때 쓰는 표현이에요.','예시 요청','A2','discussion','pattern',NULL,6),
('s_discussion_A2_07','I suggest we discuss this more carefully.','이것을 더 신중하게 논의해 보는 게 어떨까요?','I suggest we discuss','"I suggest we ~"는 그룹 토론에서 방향을 제안할 때 자연스럽게 쓸 수 있는 표현이에요.','제안','A2','discussion','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_discussion_B1_01','The evidence suggests that this approach is more effective.','증거에 따르면 이 방법이 더 효과적이에요.','The evidence suggests','근거를 제시할 때 "The evidence suggests that ~"를 쓰면 주관적인 의견이 아니라 데이터에 기반한 주장처럼 들려요.','근거 제시','B1','discussion','pattern',NULL,1),
('s_discussion_B1_02','From my perspective, the main issue is the lack of funding.','제 관점에서, 주요 문제는 자금 부족이에요.','From my perspective','자신의 시각을 명확히 하면서 주장을 펼칠 때 쓰는 표현이에요. "In my opinion"보다 더 분석적인 느낌이에요.','관점 제시','B1','discussion','pattern',NULL,2),
('s_discussion_B1_03','To elaborate on that point, let me give you a concrete example.','그 부분을 더 설명하자면, 구체적인 예를 들어 드릴게요.','To elaborate on that point','"To elaborate on that point"는 앞서 말한 내용을 더 자세히 설명할 때 쓰는 고급 패턴이에요.','부연 설명','B1','discussion','pattern',NULL,3),
('s_discussion_B1_04','I would argue that the benefits outweigh the risks.','저는 이점이 위험보다 크다고 주장하겠어요.','I would argue that','"I would argue that ~"는 자신의 주장을 자신감 있게 펼칠 때 쓰는 B1 이상 필수 표현이에요.','주장','B1','discussion','pattern',NULL,4),
('s_discussion_B1_05','That is a valid concern, but consider the following.','그건 타당한 우려이지만, 다음을 고려해 주세요.','That is a valid concern, but','상대방의 주장을 인정하면서도 반론을 제기하는 세련된 방법이에요. 토론에서 균형감을 보여줘요.','인정 후 반론','B1','discussion','pattern',NULL,5),
('s_discussion_B1_06','Could you support that claim with evidence?','그 주장을 증거로 뒷받침해 주실 수 있나요?','support that claim with evidence','근거 없는 주장에 대해 정중하게 증거를 요구하는 표현이에요. 비판적 사고 능력을 보여줘요.','증거 요구','B1','discussion','pattern',NULL,6),
('s_discussion_B1_07','Taking everything into account, I believe this is the best option.','모든 것을 고려했을 때, 이것이 최선의 선택이라고 생각해요.','Taking everything into account','"Taking everything into account"는 결론을 내리기 전에 균형 잡힌 판단을 했음을 보여주는 표현이에요.','결론','B1','discussion','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_discussion_B2_01','Your argument seems to rest on a flawed premise.','당신의 주장은 잘못된 전제에 기반하는 것 같아요.','rest on a flawed premise','전제 자체의 오류를 지적하는 강력한 반박 패턴이에요. 단순히 결론에 반대하는 것보다 더 설득력이 있어요.','전제 반박','B2','discussion','pattern',NULL,1),
('s_discussion_B2_02','I would like to rebut that point directly.','그 부분을 직접 반박하고 싶어요.','rebut that point directly','"rebut"은 공식적인 토론에서 반박할 때 쓰는 동사예요. "disagree"보다 훨씬 강하고 논리적인 어감이에요.','반박','B2','discussion','pattern',NULL,2),
('s_discussion_B2_03','That claim lacks empirical support.','그 주장에는 실증적 근거가 부족해요.','lacks empirical support','데이터나 연구 없이 이루어진 주장을 비판할 때 쓰는 표현이에요. 학술적이고 설득력 있게 들려요.','비판적 분석','B2','discussion','pattern',NULL,3),
('s_discussion_B2_04','We need to distinguish between correlation and causation here.','여기서 상관관계와 인과관계를 구분해야 해요.','distinguish between correlation and causation','논리적 오류 중 가장 흔한 인과 오류를 지적할 때 쓰는 표현이에요. 비판적 사고의 핵심 패턴이에요.','논리적 오류 지적','B2','discussion','pattern',NULL,4),
('s_discussion_B2_05','While I concede that point, the broader implication is more concerning.','그 부분은 인정하지만, 더 큰 함의가 더 걱정스러워요.','While I concede that point','부분적으로 동의하면서도 더 중요한 쟁점으로 이동하는 고급 토론 기술이에요.','부분 인정 후 전환','B2','discussion','pattern',NULL,5),
('s_discussion_B2_06','Your reasoning contains an implicit bias worth examining.','당신의 논리에는 검토할 만한 암묵적 편향이 있어요.','contains an implicit bias','논리의 구조적 편향을 지적하는 비판적 패턴이에요. 격식 있는 토론에서 매우 설득력 있게 들려요.','편향 지적','B2','discussion','pattern',NULL,6),
('s_discussion_B2_07','The nuance of this issue is often lost in simplistic narratives.','이 문제의 뉘앙스는 단순한 이야기에서 종종 사라져요.','The nuance of this issue','복잡한 문제를 지나치게 단순화하는 경향을 지적할 때 쓰는 표현이에요.','복잡성 강조','B2','discussion','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_discussion_C1_01','The syllogism you presented is formally valid but materially unsound.','당신이 제시한 삼단논법은 형식적으로는 타당하지만 내용상 불건전해요.','formally valid but materially unsound','타당성(validity)과 건전성(soundness)을 구분하는 이 표현은 논리학의 핵심 구분을 활용해요.','논리 비판','C1','discussion','pattern',NULL,1),
('s_discussion_C1_02','Let me deconstruct the underlying assumptions of that argument.','그 주장의 근본 가정들을 해체해 볼게요.','deconstruct the underlying assumptions','가정 자체를 분석하는 것은 강력한 비판 전략이에요. 이 패턴은 매우 학문적이고 설득력 있어요.','가정 해체','C1','discussion','pattern',NULL,2),
('s_discussion_C1_03','That reasoning commits the fallacy of false dichotomy.','그 추론은 거짓 이분법의 오류를 범하고 있어요.','commits the fallacy of false dichotomy','논리적 오류의 이름을 정확히 지적하는 것은 고급 토론의 핵심 기술이에요.','논리 오류 지적','C1','discussion','pattern',NULL,3),
('s_discussion_C1_04','I would postulate that the causal chain is more complex than suggested.','인과 사슬이 제시된 것보다 더 복잡하다고 가정해 볼 수 있어요.','postulate that the causal chain','"postulate"를 사용하면 가설적인 논점을 학문적으로 제시할 수 있어요.','가설 제시','C1','discussion','pattern',NULL,4),
('s_discussion_C1_05','Your inductive generalization requires a much larger sample to hold.','당신의 귀납적 일반화는 성립하려면 훨씬 더 큰 표본이 필요해요.','inductive generalization requires a much larger sample','귀납적 오류 중 성급한 일반화를 지적하는 정교한 표현이에요.','귀납 오류 비판','C1','discussion','pattern',NULL,5),
('s_discussion_C1_06','The cogency of your case depends on whether we accept the axiom.','당신 논거의 설득력은 우리가 그 공리를 받아들이느냐에 달려 있어요.','cogency of your case depends on','논증의 전제 조건을 명확히 지적하는 고급 표현이에요. 학술 토론에서 매우 효과적이에요.','조건부 평가','C1','discussion','pattern',NULL,6),
('s_discussion_C1_07','Even if we grant the premise, the conclusion does not necessarily follow.','전제를 인정하더라도, 결론이 반드시 따라오는 것은 아니에요.','the conclusion does not necessarily follow','전제와 결론 사이의 논리적 비약을 지적하는 핵심 반박 패턴이에요.','논리적 비약 지적','C1','discussion','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_discussion_C2_01','The aporia here is that every attempt to define the term undermines itself.','여기서의 아포리아는 용어를 정의하려는 모든 시도가 스스로를 약화시킨다는 거예요.','The aporia here is','아포리아는 소크라테스 대화에서 나온 개념으로, 자기 모순적 난점을 지적할 때 사용해요.','철학적 역설','C2','discussion','pattern',NULL,1),
('s_discussion_C2_02','This discourse is inherently logocentric in its privileging of spoken reason.','이 담론은 구어적 이성을 특권화하는 점에서 본질적으로 로고스 중심주의적이에요.','inherently logocentric','데리다의 로고스 중심주의 비판을 적용하는 표현이에요. 언어와 의미의 권력 구조를 분석할 때 써요.','담론 비판','C2','discussion','pattern',NULL,2),
('s_discussion_C2_03','Without intersubjectivity, the very possibility of shared meaning collapses.','상호주관성 없이는 공유된 의미의 가능성 자체가 붕괴돼요.','Without intersubjectivity','후설과 하버마스의 개념을 활용해 의사소통의 근본 조건을 논할 때 쓰는 표현이에요.','소통의 조건','C2','discussion','pattern',NULL,3),
('s_discussion_C2_04','From a hermeneutic standpoint, we must read the text against its historical horizon.','해석학적 관점에서, 우리는 텍스트를 역사적 지평에 대비해서 읽어야 해요.','From a hermeneutic standpoint','가다머의 지평 융합 개념을 활용한 표현이에요. 텍스트 해석의 역사성을 강조할 때 써요.','해석학적 분석','C2','discussion','pattern',NULL,4),
('s_discussion_C2_05','The ontological claim embedded in that statement demands further scrutiny.','그 진술에 내재된 존재론적 주장은 더 면밀한 검토가 필요해요.','ontological claim embedded in','존재론적 가정을 명시적으로 드러내는 표현이에요. 철학적 토론에서 숨겨진 가정을 지적할 때 유용해요.','존재론적 비판','C2','discussion','pattern',NULL,5),
('s_discussion_C2_06','That paradigmatic case cannot be used to justify the broader theoretical framework.','그 패러다임적 사례는 더 광범위한 이론적 틀을 정당화하는 데 사용될 수 없어요.','paradigmatic case cannot be used to justify','쿤의 패러다임 개념을 활용해 사례와 이론 사이의 논리적 간격을 지적하는 표현이에요.','패러다임 비판','C2','discussion','pattern',NULL,6),
('s_discussion_C2_07','The praxis of this theory reveals a tension between its normative and descriptive claims.','이 이론의 실천은 규범적 주장과 서술적 주장 사이의 긴장을 드러내요.','praxis of this theory reveals a tension','이론과 실천의 긴장을 비판하는 고급 표현이에요. 프락시스 개념을 아는 C2 학습자에게 적합해요.','이론과 실천의 긴장','C2','discussion','pattern',NULL,7);
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_presentation_A1_01','talk','/tɔːk/','verb','말하다','To speak about something to one or more people.','I will {talk} about my hobby today.','오늘 제 취미에 대해 말할게요.','talk','A1','presentation',1,'person speaking audience microphone stage'),
('w_presentation_A1_02','show','/ʃoʊ/','verb','보여주다','To make something visible or display it.','Let me {show} you this picture.','이 사진을 보여드릴게요.','show','A1','presentation',1,'presentation screen projector display showing'),
('w_presentation_A1_03','tell','/tel/','verb','말하다, 알리다','To give information or explain something to someone.','I will {tell} you about my project.','제 프로젝트에 대해 말씀드릴게요.','tell','A1','presentation',1,'person explaining talking hand gesture'),
('w_presentation_A1_04','start','/stɑːrt/','verb','시작하다','To begin doing or being something.','Let us {start} the presentation now.','이제 발표를 시작하겠습니다.','start','A1','presentation',1,'presentation beginning opening podium speaker'),
('w_presentation_A1_05','end','/end/','verb','끝내다','To come to a finish or bring to a close.','We will {end} the talk in five minutes.','5분 후에 발표를 마무리하겠습니다.','end','A1','presentation',1,'presentation closing finish applause audience'),
('w_presentation_A1_06','first','/fɜːrst/','adverb','첫 번째로','Before anything or anyone else.','{First}, let me introduce myself.','먼저 자기소개를 하겠습니다.','First','A1','presentation',1,'number one first podium speaker beginning'),
('w_presentation_A1_07','next','/nekst/','adverb','다음으로','Coming immediately after the present one.','{Next}, I will show the results.','다음으로 결과를 보여드리겠습니다.','Next','A1','presentation',1,'arrow next step forward presentation slide'),
('w_presentation_A1_08','last','/læst/','adjective','마지막의','Coming after all others in time or order.','The {last} point is very important.','마지막 요점이 매우 중요합니다.','last','A1','presentation',1,'final last slide presentation conclusion'),
('w_presentation_A1_09','slide','/slaɪd/','noun','슬라이드','A single page of a presentation shown on screen.','Please look at this {slide}.','이 슬라이드를 봐주세요.','slide','A1','presentation',1,'powerpoint slide presentation screen projector'),
('w_presentation_A1_10','point','/pɔɪnt/','noun','요점','A particular fact, idea, or opinion in a discussion.','My main {point} is that practice helps.','제 주요 요점은 연습이 도움이 된다는 것입니다.','point','A1','presentation',1,'presentation key point highlight marker board'),
('w_presentation_A1_11','good','/ɡʊd/','adjective','좋은','Of high quality or a satisfactory standard.','This is a {good} example.','이것은 좋은 예입니다.','good','A1','presentation',1,'thumbs up good quality approval presentation'),
('w_presentation_A1_12','today','/təˈdeɪ/','adverb','오늘','On this present day.','{Today}, we will learn about communication.','오늘은 의사소통에 대해 배울 것입니다.','Today','A1','presentation',1,'calendar today date morning office'),
('w_presentation_A1_13','here','/hɪər/','adverb','여기','In or at this place.','{Here} is a chart to help explain.','여기 설명을 도와줄 차트가 있습니다.','Here','A1','presentation',1,'pointing chart board whiteboard here'),
('w_presentation_A1_14','look','/lʊk/','verb','보다','To direct your gaze or attention at something.','Please {look} at the screen.','화면을 봐주세요.','look','A1','presentation',1,'audience looking watching screen presentation'),
('w_presentation_A1_15','see','/siː/','verb','보다, 이해하다','To notice or become aware of something.','As you can {see}, the numbers are growing.','보시다시피 숫자가 늘고 있습니다.','see','A1','presentation',1,'graph chart data growing upward trend'),
('w_presentation_A1_16','know','/noʊ/','verb','알다','To have information or facts in your mind.','You may already {know} this fact.','이 사실을 이미 알고 계실 수도 있어요.','know','A1','presentation',1,'lightbulb knowledge understanding idea concept'),
('w_presentation_A1_17','help','/help/','verb','돕다','To make something easier or provide assistance.','This chart will {help} you understand.','이 차트가 이해하는 데 도움이 될 것입니다.','help','A1','presentation',1,'helping hand support chart data explanation'),
('w_presentation_A1_18','think','/θɪŋk/','verb','생각하다','To have an opinion or idea about something.','I {think} this is a key finding.','이것이 핵심 발견이라고 생각합니다.','think','A1','presentation',1,'thinking person idea consideration analysis'),
('w_presentation_A1_19','mean','/miːn/','verb','의미하다','To have as a meaning or to intend to say something.','What does this number {mean}?','이 숫자는 무엇을 의미하나요?','mean','A1','presentation',1,'question mark data number meaning concept'),
('w_presentation_A1_20','ready','/ˈredi/','adjective','준비된','Fully prepared for something.','I am {ready} to begin.','시작할 준비가 되었습니다.','ready','A1','presentation',1,'prepared ready speaker podium confident'),
('w_presentation_A1_21','number','/ˈnʌmbər/','noun','숫자','A value used to count or measure something.','This {number} shows our progress.','이 숫자는 우리의 진행 상황을 보여줍니다.','number','A1','presentation',1,'numbers data statistics chart bar graph'),
('w_presentation_A1_22','question','/ˈkwestʃən/','noun','질문','A sentence or phrase used to find out information.','Are there any {question}s at this point?','이 시점에 질문이 있으신가요?','question','A1','presentation',1,'audience raising hand question answer discussion'),
('w_presentation_A1_23','big','/bɪɡ/','adjective','큰','Large in size, amount, or extent.','This is a {big} change for our team.','이것은 우리 팀에 큰 변화입니다.','big','A1','presentation',1,'large important big change business growth'),
('w_presentation_A1_24','part','/pɑːrt/','noun','부분','A section or portion of something.','The second {part} will cover solutions.','두 번째 부분에서는 해결책을 다룰 것입니다.','part','A1','presentation',1,'section chapter part presentation outline'),
('w_presentation_A1_25','plan','/plæn/','noun','계획','A detailed proposal for doing or achieving something.','Our {plan} has three main steps.','우리 계획에는 세 가지 주요 단계가 있습니다.','plan','A1','presentation',1,'planning roadmap steps strategy whiteboard'),
('w_presentation_A1_26','idea','/aɪˈdiːə/','noun','아이디어','A thought or suggestion about what to do.','My main {idea} is to improve communication.','제 주요 아이디어는 의사소통을 개선하는 것입니다.','idea','A1','presentation',1,'lightbulb idea brainstorm concept creative'),
('w_presentation_A1_27','step','/step/','noun','단계','One of a series of things to do in order.','The first {step} is to identify the problem.','첫 번째 단계는 문제를 파악하는 것입니다.','step','A1','presentation',1,'steps staircase process plan roadmap'),
('w_presentation_A1_28','word','/wɜːrd/','noun','단어, 말','A unit of language or something said.','I would like to say a few {word}s.','몇 말씀 드리고 싶습니다.','word','A1','presentation',1,'words speaking text speech bubble communication'),
('w_presentation_A1_29','time','/taɪm/','noun','시간','The measured or measurable period during which an action occurs.','We have ten minutes of {time} left.','남은 시간이 10분입니다.','time','A1','presentation',1,'clock timer countdown presentation time'),
('w_presentation_A1_30','name','/neɪm/','noun','이름','The word by which someone or something is known.','My {name} is Ji-yeon and I am here to present.','제 이름은 지연이고 발표하러 왔습니다.','name','A1','presentation',1,'name tag introduction speaker badge'),
('w_presentation_A1_31','right','/raɪt/','adverb','맞아요, 좋아요','Used to confirm or agree with something.','{Right}, let us move on to the data.','좋아요, 데이터로 넘어가겠습니다.','Right','A1','presentation',1,'agreement nod confirmation presenter audience'),
('w_presentation_A1_32','give','/ɡɪv/','verb','드리다, 주다','To provide or offer something to someone.','I will {give} you a brief overview.','간략한 개요를 말씀드리겠습니다.','give','A1','presentation',1,'giving overview presenting briefing speaker'),
('w_presentation_A1_33','cover','/ˈkʌvər/','verb','다루다','To deal with a subject or include it in a talk.','Today I will {cover} three main topics.','오늘 세 가지 주요 주제를 다루겠습니다.','cover','A1','presentation',1,'outline agenda topics cover presentation plan'),
('w_presentation_A1_34','picture','/ˈpɪktʃər/','noun','그림, 사진','A visual representation or image.','This {picture} explains the concept well.','이 그림이 개념을 잘 설명해 줍니다.','picture','A1','presentation',1,'image infographic visual concept diagram'),
('w_presentation_A1_35','about','/əˈbaʊt/','preposition','~에 대하여','On the subject of something.','Today I will talk {about} teamwork.','오늘은 팀워크에 대해 이야기하겠습니다.','about','A1','presentation',1,'topic subject presentation teamwork discussion');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_presentation_A2_01','introduce','/ˌɪntrəˈdjuːs/','verb','소개하다','To present someone or something to others for the first time.','Let me {introduce} our guest speaker.','초청 강연자를 소개해 드리겠습니다.','introduce','A2','presentation',1,'introduction handshake speaker stage welcome'),
('w_presentation_A2_02','outline','/ˈaʊtlaɪn/','noun','개요, 아웃라인','A general description giving the main points of something.','Here is the {outline} of my talk.','제 발표의 개요입니다.','outline','A2','presentation',1,'outline plan agenda list presentation structure'),
('w_presentation_A2_03','summary','/ˈsʌməri/','noun','요약','A brief statement of the main points of something.','Let me give you a quick {summary}.','간단히 요약해 드리겠습니다.','summary','A2','presentation',1,'summary key points review recap presentation'),
('w_presentation_A2_04','topic','/ˈtɒpɪk/','noun','주제','A subject that is discussed, written about, or studied.','The {topic} of today''s presentation is productivity.','오늘 발표의 주제는 생산성입니다.','topic','A2','presentation',1,'topic subject theme presentation title board'),
('w_presentation_A2_05','explain','/ɪkˈspleɪn/','verb','설명하다','To make something clear by describing it in more detail.','I will {explain} how this process works.','이 과정이 어떻게 작동하는지 설명해 드리겠습니다.','explain','A2','presentation',1,'explaining whiteboard diagram process flow'),
('w_presentation_A2_06','question','/ˈkwestʃən/','noun','질문 (복수 활용)','A sentence asking for information or inviting discussion.','Please hold your {question}s until the end.','질문은 마지막까지 기다려 주세요.','question','A2','presentation',1,'Q&A session audience raising hand questions'),
('w_presentation_A2_07','answer','/ˈænsər/','verb','대답하다','To say something in response to a question.','I am happy to {answer} your questions.','질문에 기꺼이 답변해 드리겠습니다.','answer','A2','presentation',1,'answering question speaker Q&A microphone'),
('w_presentation_A2_08','audience','/ˈɔːdiəns/','noun','청중','The group of people watching or listening to a presentation.','Thank you, {audience}, for your attention.','청중 여러분, 경청해 주셔서 감사합니다.','audience','A2','presentation',1,'audience watching listening presentation hall'),
('w_presentation_A2_09','present','/prɪˈzent/','verb','발표하다','To show or demonstrate something formally to an audience.','I will {present} our quarterly results.','분기별 결과를 발표하겠습니다.','present','A2','presentation',1,'presenter stage podium quarterly results business'),
('w_presentation_A2_10','conclusion','/kənˈkluːʒən/','noun','결론','The end or final part of a speech or piece of writing.','In {conclusion}, practice makes perfect.','결론적으로, 연습이 완성을 만듭니다.','conclusion','A2','presentation',1,'conclusion ending final slide summary wrap up'),
('w_presentation_A2_11','section','/ˈsekʃən/','noun','섹션, 부분','A distinct part or subdivision of something.','The next {section} deals with marketing.','다음 섹션은 마케팅을 다룹니다.','section','A2','presentation',2,'section chapter division presentation structure'),
('w_presentation_A2_12','main','/meɪn/','adjective','주요한','Most important or largest.','The {main} goal of this project is growth.','이 프로젝트의 주요 목표는 성장입니다.','main','A2','presentation',1,'main goal objective key priority presentation'),
('w_presentation_A2_13','example','/ɪɡˈzɑːmpəl/','noun','예시','Something used to illustrate or explain a point.','Let me give you an {example}.','예를 하나 들어드리겠습니다.','example','A2','presentation',1,'example case study illustration learning'),
('w_presentation_A2_14','chart','/tʃɑːrt/','noun','차트','A sheet with information presented in the form of a diagram.','This {chart} shows our growth over time.','이 차트는 시간에 따른 성장을 보여줍니다.','chart','A2','presentation',1,'bar chart graph data visualization business'),
('w_presentation_A2_15','graph','/ɡræf/','noun','그래프','A diagram showing data and relationships between values.','As you can see on this {graph}, sales increased.','이 그래프에서 볼 수 있듯이 매출이 증가했습니다.','graph','A2','presentation',2,'line graph data trend increase decrease'),
('w_presentation_A2_16','figure','/ˈfɪɡjər/','noun','수치, 그림','A number representing an amount, or an illustration.','The {figure} on the left shows last year''s data.','왼쪽의 수치는 작년 데이터를 보여줍니다.','figure','A2','presentation',2,'data figure numbers statistics chart'),
('w_presentation_A2_17','goal','/ɡoʊl/','noun','목표','An aim or desired result.','Our {goal} is to double sales this year.','올해 목표는 매출을 두 배로 늘리는 것입니다.','goal','A2','presentation',1,'goal target achievement business objective'),
('w_presentation_A2_18','result','/rɪˈzʌlt/','noun','결과','The outcome of an action or situation.','The {result} of our survey is very clear.','설문 조사의 결과가 매우 명확합니다.','result','A2','presentation',1,'result outcome data findings survey analysis'),
('w_presentation_A2_19','reason','/ˈriːzən/','noun','이유','A cause or explanation for something.','The main {reason} for this change is efficiency.','이 변화의 주요 이유는 효율성입니다.','reason','A2','presentation',1,'reason explanation cause analysis thinking'),
('w_presentation_A2_20','problem','/ˈprɒbləm/','noun','문제','A matter or situation that is difficult or unwanted.','The {problem} we face is a lack of resources.','우리가 직면한 문제는 자원 부족입니다.','problem','A2','presentation',1,'problem challenge issue solution business'),
('w_presentation_A2_21','solution','/səˈluːʃən/','noun','해결책','A means of solving a problem or dealing with a situation.','Here is our proposed {solution}.','여기 우리가 제안하는 해결책이 있습니다.','solution','A2','presentation',1,'solution answer problem solving strategy business'),
('w_presentation_A2_22','project','/ˈprɒdʒekt/','noun','프로젝트','A plan or piece of work, usually to achieve a specific aim.','Our {project} has been running for six months.','우리 프로젝트는 6개월째 진행 중입니다.','project','A2','presentation',2,'project team collaboration planning business'),
('w_presentation_A2_23','data','/ˈdeɪtə/','noun','데이터','Facts and statistics collected together for reference.','The {data} supports our argument.','데이터가 우리의 주장을 뒷받침합니다.','data','A2','presentation',1,'data statistics numbers analysis research'),
('w_presentation_A2_24','report','/rɪˈpɔːrt/','noun','보고서','A spoken or written account of something.','According to our {report}, sales grew by 20%.','보고서에 따르면 매출이 20% 성장했습니다.','report','A2','presentation',2,'report document business analysis findings'),
('w_presentation_A2_25','change','/tʃeɪndʒ/','noun','변화','The act or process of becoming different.','This {change} will benefit the whole team.','이 변화는 팀 전체에 도움이 될 것입니다.','change','A2','presentation',2,'change transformation arrow direction business'),
('w_presentation_A2_26','increase','/ˈɪŋkriːs/','noun','증가','A rise in the amount, number, or degree of something.','There was a significant {increase} in users.','사용자 수가 크게 증가했습니다.','increase','A2','presentation',1,'increase growth arrow up chart bar graph'),
('w_presentation_A2_27','decrease','/ˈdiːkriːs/','noun','감소','A reduction in the amount, number, or degree of something.','The {decrease} in costs surprised everyone.','비용 감소가 모두를 놀라게 했습니다.','decrease','A2','presentation',2,'decrease drop arrow down chart reduction'),
('w_presentation_A2_28','total','/ˈtoʊtl/','noun','합계','The whole number or amount of something.','The {total} budget is two million dollars.','총 예산은 200만 달러입니다.','total','A2','presentation',2,'total sum budget finance numbers spreadsheet'),
('w_presentation_A2_29','compare','/kəmˈpeər/','verb','비교하다','To examine the similarities or differences between things.','Let us {compare} these two approaches.','이 두 가지 접근법을 비교해 보겠습니다.','compare','A2','presentation',2,'comparison side by side chart analysis'),
('w_presentation_A2_30','agree','/əˈɡriː/','verb','동의하다','To have the same opinion or feeling as someone.','I hope you all {agree} with this approach.','여러분 모두 이 접근법에 동의하시길 바랍니다.','agree','A2','presentation',2,'agreement consensus handshake team discussion'),
('w_presentation_A2_31','clear','/klɪər/','adjective','명확한','Easy to understand, hear, read, or see.','I hope that was {clear} for everyone.','모든 분들께 명확하게 전달되었으면 합니다.','clear','A2','presentation',1,'clarity understanding clear message communication'),
('w_presentation_A2_32','brief','/briːf/','adjective','간략한','Short in duration or using few words.','I will give a {brief} overview before we begin.','시작하기 전에 간략한 개요를 드리겠습니다.','brief','A2','presentation',2,'brief short summary overview concise'),
('w_presentation_A2_33','background','/ˈbækɡraʊnd/','noun','배경','Information about the context of something.','Let me give you some {background} information.','배경 정보를 조금 말씀드리겠습니다.','background','A2','presentation',2,'background context history information overview'),
('w_presentation_A2_34','focus','/ˈfoʊkəs/','verb','집중하다','To pay particular attention to a specific subject.','Today we will {focus} on customer retention.','오늘은 고객 유지에 집중하겠습니다.','focus','A2','presentation',1,'focus spotlight lens target goal presentation'),
('w_presentation_A2_35','share','/ʃeər/','verb','공유하다','To tell others about something or give them access to it.','I would like to {share} some key insights.','주요 인사이트를 공유하고 싶습니다.','share','A2','presentation',1,'sharing information insights knowledge team');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_presentation_B1_01','highlight','/ˈhaɪlaɪt/','verb','강조하다','To draw special attention to something important.','I want to {highlight} three key points.','세 가지 핵심 포인트를 강조하고 싶습니다.','highlight','B1','presentation',1,'highlight marker key point emphasis presentation'),
('w_presentation_B1_02','transition','/trænˈzɪʃən/','noun','전환','A change or move from one state or topic to another.','Let''s make a {transition} to the next section.','다음 섹션으로 넘어가겠습니다.','transition','B1','presentation',1,'transition arrow move change flow next section'),
('w_presentation_B1_03','illustrate','/ˈɪləstreɪt/','verb','설명하다, 예시를 들다','To make something clearer by using examples or visuals.','This graph will {illustrate} my point.','이 그래프가 제 요점을 설명해 줄 것입니다.','illustrate','B1','presentation',1,'illustration diagram visual example graph'),
('w_presentation_B1_04','emphasize','/ˈemfəsaɪz/','verb','강조하다','To give special importance to something in speaking or writing.','I must {emphasize} the urgency of this issue.','이 문제의 긴급성을 강조해야 합니다.','emphasize','B1','presentation',1,'emphasis bold highlight urgent important'),
('w_presentation_B1_05','elaborate','/ɪˈlæbəreɪt/','verb','자세히 설명하다','To explain something in more detail or add more information.','Could you {elaborate} on that point?','그 요점에 대해 더 자세히 설명해 주시겠어요?','elaborate','B1','presentation',2,'detail explanation deeper dive analysis'),
('w_presentation_B1_06','overview','/ˈoʊvərˌvjuː/','noun','개요, 전체 그림','A general summary or description of a subject.','Let me begin with a quick {overview}.','간단한 개요로 시작하겠습니다.','overview','B1','presentation',1,'overview summary big picture presentation intro'),
('w_presentation_B1_07','objective','/əbˈdʒektɪv/','noun','목적, 목표','A goal or aim intended to be achieved.','Our main {objective} is to reduce costs.','우리의 주요 목적은 비용 절감입니다.','objective','B1','presentation',1,'objective goal target SMART aim business plan'),
('w_presentation_B1_08','finding','/ˈfaɪndɪŋ/','noun','발견, 조사 결과','A fact or piece of information discovered through research.','Our key {finding} is that engagement doubled.','핵심 발견은 참여도가 두 배로 증가했다는 것입니다.','finding','B1','presentation',1,'research finding discovery data insight analysis'),
('w_presentation_B1_09','result','/rɪˈzʌlt/','noun','결과 (연구·실험)','The outcome of an experiment, study, or action.','The {result}s exceeded our expectations.','결과가 우리의 기대를 뛰어넘었습니다.','result','B1','presentation',1,'results success exceeding expectations graph'),
('w_presentation_B1_10','recommend','/ˌrekəˈmend/','verb','권장하다','To suggest that someone do something or use something.','I {recommend} adopting this new strategy.','이 새로운 전략을 도입할 것을 권장합니다.','recommend','B1','presentation',1,'recommendation strategy advice suggestion business'),
('w_presentation_B1_11','approach','/əˈproʊtʃ/','noun','접근법','A way of dealing with a situation or problem.','Our {approach} differs from traditional methods.','우리의 접근법은 기존 방법과 다릅니다.','approach','B1','presentation',2,'approach method strategy alternative comparison'),
('w_presentation_B1_12','demonstrate','/ˈdemənstreɪt/','verb','시연하다, 증명하다','To show clearly by giving proof or evidence.','Let me {demonstrate} how this tool works.','이 도구가 어떻게 작동하는지 시연해 드리겠습니다.','demonstrate','B1','presentation',2,'demo demonstration live example proof evidence'),
('w_presentation_B1_13','structure','/ˈstrʌktʃər/','noun','구조','The arrangement of parts or the way something is organized.','The {structure} of my talk has three parts.','제 발표의 구조는 세 부분으로 이루어져 있습니다.','structure','B1','presentation',1,'structure outline framework organized presentation'),
('w_presentation_B1_14','evidence','/ˈevɪdəns/','noun','증거','Facts or information available to prove something.','The {evidence} clearly supports our claim.','증거가 우리의 주장을 명확히 뒷받침합니다.','evidence','B1','presentation',1,'evidence proof data research support argument'),
('w_presentation_B1_15','implication','/ˌɪmplɪˈkeɪʃən/','noun','시사점','A conclusion that can be drawn from something.','The {implication}s of this are significant.','이것의 시사점은 매우 중요합니다.','implication','B1','presentation',2,'implication impact consequence significance meaning'),
('w_presentation_B1_16','challenge','/ˈtʃælɪndʒ/','noun','과제, 도전','A task or situation that tests someone''s abilities.','One {challenge} we faced was data collection.','우리가 직면한 과제 중 하나는 데이터 수집이었습니다.','challenge','B1','presentation',2,'challenge obstacle problem solving team'),
('w_presentation_B1_17','strategy','/ˈstrætɪdʒi/','noun','전략','A plan of action designed to achieve an overall aim.','Our {strategy} focuses on digital channels.','우리의 전략은 디지털 채널에 초점을 맞춥니다.','strategy','B1','presentation',1,'strategy plan roadmap chess business direction'),
('w_presentation_B1_18','impact','/ˈɪmpækt/','noun','영향','The strong effect or influence of one thing on another.','The {impact} of this policy was immediate.','이 정책의 영향은 즉각적이었습니다.','impact','B1','presentation',1,'impact effect influence change result business'),
('w_presentation_B1_19','trend','/trend/','noun','추세','A general direction in which something is developing.','The {trend} shows consistent improvement.','추세는 지속적인 개선을 보여줍니다.','trend','B1','presentation',1,'trend line graph upward growth market data'),
('w_presentation_B1_20','significant','/sɪɡˈnɪfɪkənt/','adjective','중요한, 상당한','Large enough to be noticed or have an effect.','This is a {significant} increase in revenue.','이것은 매출의 상당한 증가입니다.','significant','B1','presentation',1,'significant important notable achievement business'),
('w_presentation_B1_21','assumption','/əˈsʌmpʃən/','noun','가정, 전제','Something taken for granted as a starting point.','Our key {assumption} is steady market growth.','우리의 핵심 가정은 안정적인 시장 성장입니다.','assumption','B1','presentation',2,'assumption premise foundation hypothesis thinking'),
('w_presentation_B1_22','scenario','/sɪˈnɑːrioʊ/','noun','시나리오','A written outline of a possible course of events.','In the best-case {scenario}, we exceed targets.','최선의 시나리오에서는 목표를 초과합니다.','scenario','B1','presentation',2,'scenario planning options best worst case'),
('w_presentation_B1_23','proposal','/prəˈpoʊzəl/','noun','제안서','A formal plan or suggestion for others to consider.','Our {proposal} outlines three options.','제안서는 세 가지 옵션을 제시합니다.','proposal','B1','presentation',1,'proposal document business plan options review'),
('w_presentation_B1_24','benefit','/ˈbenɪfɪt/','noun','이점','An advantage or gain from something.','The {benefit}s of this approach are clear.','이 접근법의 이점은 명확합니다.','benefit','B1','presentation',1,'benefit advantage positive gain improvement'),
('w_presentation_B1_25','concern','/kənˈsɜːrn/','noun','우려, 걱정','A feeling of worry about something important.','A valid {concern} is the timeline.','타당한 우려 사항은 일정입니다.','concern','B1','presentation',2,'concern worry risk issue challenge flag'),
('w_presentation_B1_26','process','/ˈprɒses/','noun','과정, 절차','A series of steps taken to achieve a particular goal.','Let me walk you through the {process}.','과정을 순서대로 안내해 드리겠습니다.','process','B1','presentation',1,'process steps flowchart workflow procedure'),
('w_presentation_B1_27','outcome','/ˈaʊtˌkʌm/','noun','결과, 성과','The way a situation ends or the result achieved.','The desired {outcome} is a 15% cost reduction.','목표 성과는 15% 비용 절감입니다.','outcome','B1','presentation',1,'outcome result success goal achieved measurement'),
('w_presentation_B1_28','effective','/ɪˈfektɪv/','adjective','효과적인','Producing the intended result successfully.','This method proved to be highly {effective}.','이 방법은 매우 효과적인 것으로 입증되었습니다.','effective','B1','presentation',2,'effective solution result success proven method'),
('w_presentation_B1_29','relevant','/ˈreləvənt/','adjective','관련성 있는','Closely connected with or appropriate to the matter.','The most {relevant} data is shown here.','가장 관련성 있는 데이터가 여기에 표시되어 있습니다.','relevant','B1','presentation',2,'relevant related connected appropriate data'),
('w_presentation_B1_30','expand','/ɪkˈspænd/','verb','확장하다, 자세히 설명하다','To make something larger or to explain in more detail.','Let me {expand} on this point briefly.','이 부분을 잠깐 자세히 설명하겠습니다.','expand','B1','presentation',2,'expand enlarge detail deeper explanation'),
('w_presentation_B1_31','current','/ˈkɜːrənt/','adjective','현재의','Existing or happening now.','The {current} situation calls for action.','현재 상황은 행동을 요구합니다.','current','B1','presentation',2,'current now present situation analysis today'),
('w_presentation_B1_32','methodology','/ˌmeθəˈdɒlədʒi/','noun','방법론','A system of methods used in a particular area of study.','Our {methodology} is based on user interviews.','우리 방법론은 사용자 인터뷰를 기반으로 합니다.','methodology','B1','presentation',2,'methodology research method process approach'),
('w_presentation_B1_33','timeline','/ˈtaɪmˌlaɪn/','noun','일정표, 타임라인','A display of events or actions in chronological order.','Here is our project {timeline}.','여기 프로젝트 타임라인이 있습니다.','timeline','B1','presentation',1,'timeline project schedule Gantt chart milestones'),
('w_presentation_B1_34','insight','/ˈɪnsaɪt/','noun','인사이트, 통찰력','A deep and accurate understanding of something.','This data gives us a key {insight}.','이 데이터는 핵심 인사이트를 제공합니다.','insight','B1','presentation',1,'insight discovery understanding data analysis'),
('w_presentation_B1_35','initiative','/ɪˈnɪʃɪətɪv/','noun','이니셔티브, 계획','A new plan or action intended to solve a problem.','This {initiative} will launch in Q3.','이 이니셔티브는 3분기에 시작됩니다.','initiative','B1','presentation',2,'initiative launch project plan start program');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_presentation_B2_01','quantify','/ˈkwɒntɪfaɪ/','verb','수치화하다','To express or measure something as a quantity.','We need to {quantify} the potential gains.','잠재적 이익을 수치화할 필요가 있습니다.','quantify','B2','presentation',1,'quantify numbers metrics measurement data chart'),
('w_presentation_B2_02','juxtapose','/ˌdʒʌkstəˈpoʊz/','verb','병치하다, 나란히 놓다','To place two things close together for comparison or contrast.','Let me {juxtapose} the two models.','두 모델을 나란히 비교해 보겠습니다.','juxtapose','B2','presentation',2,'comparison side by side contrast two options'),
('w_presentation_B2_03','contextualize','/kənˈtekstʃuəlaɪz/','verb','맥락화하다','To place something in its context to make it understandable.','It is important to {contextualize} these results.','이 결과를 맥락화하는 것이 중요합니다.','contextualize','B2','presentation',2,'context background framework understanding analysis'),
('w_presentation_B2_04','articulate','/ɑːrˈtɪkjuleɪt/','verb','명확히 표현하다','To express thoughts or feelings clearly and effectively in words.','She can {articulate} complex ideas simply.','그녀는 복잡한 아이디어를 간단하게 표현할 수 있습니다.','articulate','B2','presentation',1,'clear communication speech articulate express'),
('w_presentation_B2_05','facilitate','/fəˈsɪlɪteɪt/','verb','촉진하다, 진행을 돕다','To make an action or process easier or smoother.','This tool will {facilitate} collaboration.','이 도구는 협업을 촉진할 것입니다.','facilitate','B2','presentation',2,'facilitate enable support help process smooth'),
('w_presentation_B2_06','compelling','/kəmˈpelɪŋ/','adjective','설득력 있는','Evoking interest, attention, or admiration in a powerful way.','The data presents a {compelling} argument.','데이터가 설득력 있는 주장을 제시합니다.','compelling','B2','presentation',1,'compelling argument persuasive strong powerful case'),
('w_presentation_B2_07','persuasive','/pərˈsweɪsɪv/','adjective','설득력 있는','Good at convincing people to believe or do something.','Her {persuasive} delivery won over the board.','그녀의 설득력 있는 발표가 이사회를 설득했습니다.','persuasive','B2','presentation',1,'persuasive speech convince audience board winning'),
('w_presentation_B2_08','coherent','/koʊˈhɪərənt/','adjective','일관된, 조리 있는','Logical and well-organized, forming a unified whole.','Our argument is {coherent} and well-supported.','우리의 주장은 일관되고 잘 뒷받침됩니다.','coherent','B2','presentation',1,'coherent logical organized structured argument'),
('w_presentation_B2_09','credibility','/ˌkredɪˈbɪlɪti/','noun','신뢰성','The quality of being trusted and believed in.','Citing sources builds your {credibility}.','출처를 인용하면 신뢰성이 높아집니다.','credibility','B2','presentation',1,'credibility trust source citation research reliable'),
('w_presentation_B2_10','narrative','/ˈnærətɪv/','noun','내러티브, 서사','A spoken or written account that connects ideas into a story.','The {narrative} of this data is one of growth.','이 데이터의 내러티브는 성장에 관한 것입니다.','narrative','B2','presentation',1,'narrative story arc data storytelling presentation'),
('w_presentation_B2_11','refute','/rɪˈfjuːt/','verb','반박하다','To prove that something is wrong or incorrect.','Our data {refute}s the competitor''s claims.','우리 데이터가 경쟁사의 주장을 반박합니다.','refute','B2','presentation',2,'refute counter argument rebuttal evidence proof'),
('w_presentation_B2_12','substantiate','/səbˈstænʃieɪt/','verb','뒷받침하다, 증명하다','To provide evidence to support or prove a claim.','We can {substantiate} every figure presented.','제시된 모든 수치를 뒷받침할 수 있습니다.','substantiate','B2','presentation',2,'evidence proof support data back up claim'),
('w_presentation_B2_13','nuance','/ˈnjuːɑːns/','noun','뉘앙스','A subtle difference in meaning, expression, or sound.','There is an important {nuance} here worth noting.','여기서 주목할 만한 중요한 뉘앙스가 있습니다.','nuance','B2','presentation',2,'nuance subtle difference detail precision meaning'),
('w_presentation_B2_14','benchmark','/ˈbentʃˌmɑːrk/','noun','기준점, 벤치마크','A standard against which things may be compared.','Our results exceeded the industry {benchmark}.','우리 결과가 업계 기준을 초과했습니다.','benchmark','B2','presentation',1,'benchmark standard comparison industry performance'),
('w_presentation_B2_15','leverage','/ˈlevərɪdʒ/','verb','활용하다','To use something to maximum advantage.','We can {leverage} our brand recognition.','우리 브랜드 인지도를 활용할 수 있습니다.','leverage','B2','presentation',2,'leverage advantage utilize maximize asset strategy'),
('w_presentation_B2_16','mitigate','/ˈmɪtɪɡeɪt/','verb','완화하다','To make something less severe or serious.','Steps were taken to {mitigate} the risks.','리스크를 완화하기 위한 조치가 취해졌습니다.','mitigate','B2','presentation',2,'mitigate reduce risk management solution strategy'),
('w_presentation_B2_17','stakeholder','/ˈsteɪkˌhoʊldər/','noun','이해관계자','A person with an interest or concern in a business or project.','All {stakeholder}s have been consulted.','모든 이해관계자와 협의했습니다.','stakeholder','B2','presentation',1,'stakeholder team executive management consulting'),
('w_presentation_B2_18','scalable','/ˈskeɪləbəl/','adjective','확장 가능한','Able to be changed in size or scale to meet changing needs.','The solution we propose is {scalable}.','우리가 제안하는 솔루션은 확장 가능합니다.','scalable','B2','presentation',2,'scalable growth expand flexible technology solution'),
('w_presentation_B2_19','prioritize','/praɪˈɔːrɪtaɪz/','verb','우선순위를 정하다','To treat something as more important than other things.','We need to {prioritize} the highest-impact items.','영향력이 가장 큰 항목을 우선시해야 합니다.','prioritize','B2','presentation',1,'prioritize ranking order importance matrix'),
('w_presentation_B2_20','optimize','/ˈɒptɪmaɪz/','verb','최적화하다','To make the best or most effective use of something.','We plan to {optimize} the workflow.','워크플로우를 최적화할 계획입니다.','optimize','B2','presentation',1,'optimize improve efficiency best performance'),
('w_presentation_B2_21','trajectory','/trəˈdʒektəri/','noun','궤적, 방향','The path followed by a moving object or a course of action.','The {trajectory} of growth has been steep.','성장 궤적이 가파르게 이어져 왔습니다.','trajectory','B2','presentation',2,'trajectory path direction growth curve upward'),
('w_presentation_B2_22','catalyst','/ˈkætəlɪst/','noun','촉매제','A person or thing that causes a change or reaction.','This event was the {catalyst} for our pivot.','이 사건이 우리 방향 전환의 촉매제였습니다.','catalyst','B2','presentation',2,'catalyst change trigger event spark transformation'),
('w_presentation_B2_23','viable','/ˈvaɪəbəl/','adjective','실행 가능한','Capable of working successfully or feasible.','Option B is the most {viable} solution.','옵션 B가 가장 실행 가능한 솔루션입니다.','viable','B2','presentation',1,'viable feasible option solution practical choice'),
('w_presentation_B2_24','granular','/ˈɡrænjʊlər/','adjective','세부적인, 세밀한','Having a fine or detailed level of analysis or description.','The {granular} data reveals a hidden trend.','세밀한 데이터가 숨겨진 추세를 드러냅니다.','granular','B2','presentation',2,'granular detail level data micro analysis deep'),
('w_presentation_B2_25','synthesize','/ˈsɪnθəsaɪz/','verb','종합하다','To combine different elements into a coherent whole.','We {synthesize} data from multiple sources.','여러 출처의 데이터를 종합합니다.','synthesize','B2','presentation',1,'synthesize combine integrate data sources analysis'),
('w_presentation_B2_26','transparency','/trænsˈpærənsi/','noun','투명성','Being open and not hiding information.','We value {transparency} in our reporting.','보고에서 투명성을 중요하게 생각합니다.','transparency','B2','presentation',2,'transparency open honest reporting clear communication'),
('w_presentation_B2_27','validate','/ˈvælɪdeɪt/','verb','검증하다','To confirm that something is correct or justified.','We {validate}d our model with real data.','실제 데이터로 모델을 검증했습니다.','validate','B2','presentation',2,'validate verify confirm test data proof'),
('w_presentation_B2_28','robust','/roʊˈbʌst/','adjective','견고한, 탄탄한','Strong and healthy or vigorous; able to withstand challenges.','We have built a {robust} methodology.','견고한 방법론을 구축했습니다.','robust','B2','presentation',2,'robust strong solid reliable methodology research'),
('w_presentation_B2_29','holistic','/hoʊˈlɪstɪk/','adjective','전체론적인','Considering all parts of something together rather than separately.','We take a {holistic} view of the problem.','문제를 전체론적 관점에서 바라봅니다.','holistic','B2','presentation',2,'holistic whole system perspective integrated view'),
('w_presentation_B2_30','momentum','/moʊˈmentəm/','noun','기세, 모멘텀','The force that keeps an activity developing after it starts.','We need to maintain {momentum} through Q4.','4분기 내내 기세를 유지해야 합니다.','momentum','B2','presentation',2,'momentum growth speed forward motion continue'),
('w_presentation_B2_31','discrepancy','/dɪˈskrepənsi/','noun','불일치, 차이','A difference between two or more things that should be the same.','There is a {discrepancy} in the figures.','수치에 불일치가 있습니다.','discrepancy','B2','presentation',2,'discrepancy difference gap mismatch data error'),
('w_presentation_B2_32','actionable','/ˈækʃənəbəl/','adjective','바로 실행 가능한','Able to be acted on; providing clear steps to take.','These insights are {actionable} immediately.','이 인사이트들은 즉시 실행 가능합니다.','actionable','B2','presentation',1,'actionable steps concrete plan action immediate'),
('w_presentation_B2_33','iteration','/ˌɪtəˈreɪʃən/','noun','반복, 이터레이션','A new version of a process or design, based on review.','The third {iteration} showed the best results.','세 번째 이터레이션에서 최고의 결과가 나왔습니다.','iteration','B2','presentation',2,'iteration cycle improve version agile development'),
('w_presentation_B2_34','alignment','/əˈlaɪnmənt/','noun','정렬, 일치','Agreement or cooperation among people or groups.','We need strategic {alignment} before moving forward.','앞으로 나아가기 전에 전략적 정렬이 필요합니다.','alignment','B2','presentation',1,'alignment agreement team strategy unified direction'),
('w_presentation_B2_35','projection','/prəˈdʒekʃən/','noun','전망, 예측치','An estimate of future outcomes based on current data.','Our five-year {projection} looks very promising.','5년 전망이 매우 유망하게 보입니다.','projection','B2','presentation',1,'projection forecast future estimate graph financial');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_presentation_C1_01','rhetoric','/ˈretərɪk/','noun','수사학, 수사법','The art of effective or persuasive speaking or writing.','Mastering {rhetoric} will transform your presentations.','수사법을 익히면 발표가 달라집니다.','rhetoric','C1','presentation',1,'rhetoric persuasion speech oratory debate stage'),
('w_presentation_C1_02','discourse','/ˈdɪskɔːrs/','noun','담화, 담론','Written or spoken communication or debate.','Academic {discourse} requires precise language.','학문적 담론은 정확한 언어를 요구합니다.','discourse','C1','presentation',2,'discourse discussion academic language debate forum'),
('w_presentation_C1_03','deconstruct','/ˌdiːkənˈstrʌkt/','verb','해체 분석하다','To analyze something by breaking it down into its parts.','Let me {deconstruct} the argument step by step.','주장을 단계별로 분해해 분석해 보겠습니다.','deconstruct','C1','presentation',2,'deconstruct analyze break down components parts'),
('w_presentation_C1_04','paradigm','/ˈpærədaɪm/','noun','패러다임','A typical example or model, or a framework of assumptions.','This technology represents a new {paradigm}.','이 기술은 새로운 패러다임을 나타냅니다.','paradigm','C1','presentation',1,'paradigm shift model framework new era change'),
('w_presentation_C1_05','framework','/ˈfreɪmwɜːrk/','noun','프레임워크, 틀','A basic structure underlying a system or concept.','Our analysis uses a four-part {framework}.','우리 분석은 네 부분으로 이루어진 프레임워크를 사용합니다.','framework','C1','presentation',1,'framework structure model analysis four quadrant'),
('w_presentation_C1_06','proposition','/ˌprɒpəˈzɪʃən/','noun','명제, 핵심 주장','A statement or assertion that expresses a judgment or opinion.','Our core value {proposition} is clear.','우리의 핵심 가치 명제는 명확합니다.','proposition','C1','presentation',1,'proposition value statement argument claim thesis'),
('w_presentation_C1_07','empirical','/ɪmˈpɪrɪkəl/','adjective','경험적인, 실증적인','Based on observation or experience rather than theory.','Our conclusions are grounded in {empirical} data.','우리의 결론은 실증적 데이터에 근거합니다.','empirical','C1','presentation',1,'empirical data research evidence observation fact'),
('w_presentation_C1_08','analytical','/ˌænəˈlɪtɪkəl/','adjective','분석적인','Using analysis or logic to examine something carefully.','An {analytical} approach reveals underlying patterns.','분석적 접근법이 내재된 패턴을 드러냅니다.','analytical','C1','presentation',1,'analytical thinking data logic systematic approach'),
('w_presentation_C1_09','synthesize','/ˈsɪnθəsaɪz/','verb','종합하다 (학제적)','To produce something by combining elements from multiple sources.','We {synthesize} research from multiple disciplines.','여러 학문 분야의 연구를 종합합니다.','synthesize','C1','presentation',1,'synthesize research combine disciplines integrate whole'),
('w_presentation_C1_10','infer','/ɪnˈfɜːr/','verb','추론하다','To reach a conclusion based on evidence and reasoning.','We can {infer} causation from these results.','이 결과에서 인과관계를 추론할 수 있습니다.','infer','C1','presentation',2,'infer conclude reason evidence logic analysis'),
('w_presentation_C1_11','correlate','/ˈkɒrəleɪt/','verb','상관관계가 있다','To have a mutual relationship or connection.','User engagement strongly {correlate}s with retention.','사용자 참여는 유지율과 강하게 상관관계가 있습니다.','correlate','C1','presentation',2,'correlation relationship data variables statistical'),
('w_presentation_C1_12','critique','/krɪˈtiːk/','verb','비평하다','To analyze and judge a work or idea in a detailed way.','I will {critique} the existing approach first.','먼저 기존 접근법을 비평하겠습니다.','critique','C1','presentation',2,'critique review analysis evaluation judgment academic'),
('w_presentation_C1_13','conceptualize','/kənˈseptʃuəlaɪz/','verb','개념화하다','To form a concept or idea of something in the mind.','We {conceptualize}d the solution as a feedback loop.','솔루션을 피드백 루프로 개념화했습니다.','conceptualize','C1','presentation',2,'conceptualize idea model thinking abstraction design'),
('w_presentation_C1_14','divergent','/daɪˈvɜːrdʒənt/','adjective','발산적인, 다른','Tending to be different or developing in different directions.','The two models produced {divergent} outcomes.','두 모델이 다른 결과를 만들어냈습니다.','divergent','C1','presentation',2,'divergent different opposite split path comparison'),
('w_presentation_C1_15','convergent','/kənˈvɜːrdʒənt/','adjective','수렴적인','Tending to come together toward a common point.','All data sets show {convergent} trends.','모든 데이터 세트가 수렴하는 추세를 보입니다.','convergent','C1','presentation',2,'convergent same direction unified trend agreement'),
('w_presentation_C1_16','nuanced','/ˈnjuːɑːnst/','adjective','세밀한, 뉘앙스 있는','Having subtle distinctions or fine differences.','Her {nuanced} analysis impressed the committee.','그녀의 세밀한 분석이 위원회에 깊은 인상을 주었습니다.','nuanced','C1','presentation',1,'nuanced subtle detail precision careful analysis'),
('w_presentation_C1_17','normative','/ˈnɔːrmətɪv/','adjective','규범적인','Relating to a standard or norm, especially of behavior.','We move from descriptive to {normative} analysis.','기술적 분석에서 규범적 분석으로 이동합니다.','normative','C1','presentation',2,'normative standard prescriptive recommendation policy'),
('w_presentation_C1_18','extrapolate','/ɪkˈstræpəleɪt/','verb','외삽하여 추정하다','To extend a conclusion from known data to an unknown area.','We can {extrapolate} from current trends.','현재 추세에서 미래를 추정 연장할 수 있습니다.','extrapolate','C1','presentation',2,'extrapolate predict forecast trend extension future'),
('w_presentation_C1_19','hypothesis','/haɪˈpɒθɪsɪs/','noun','가설','A proposed explanation made on limited evidence.','Our {hypothesis} was supported by the trial data.','가설은 실험 데이터로 뒷받침되었습니다.','hypothesis','C1','presentation',1,'hypothesis test research science experiment prove'),
('w_presentation_C1_20','contingency','/kənˈtɪndʒənsi/','noun','비상 계획, 만일의 경우','A future event or circumstance that is possible but uncertain.','We have a {contingency} plan for each risk.','각 리스크에 대한 비상 계획이 있습니다.','contingency','C1','presentation',2,'contingency backup plan risk management safety'),
('w_presentation_C1_21','delineate','/dɪˈlɪnieɪt/','verb','명확히 구분하다','To describe or indicate something precisely.','I will {delineate} the scope of this study.','이 연구의 범위를 명확히 구분해 드리겠습니다.','delineate','C1','presentation',2,'delineate define scope boundary clarify outline'),
('w_presentation_C1_22','causality','/kɔːˈzæləti/','noun','인과관계','The relationship between cause and effect.','We must not confuse correlation with {causality}.','상관관계를 인과관계로 혼동해서는 안 됩니다.','causality','C1','presentation',2,'causality cause effect relationship data statistics'),
('w_presentation_C1_23','disseminate','/dɪˈsemɪneɪt/','verb','전파하다, 보급하다','To spread information widely.','We plan to {disseminate} these findings broadly.','이 결과를 널리 전파할 계획입니다.','disseminate','C1','presentation',2,'disseminate spread share publish broadcast research'),
('w_presentation_C1_24','dichotomy','/daɪˈkɒtəmi/','noun','이분법','A division or contrast between two things as opposites.','There is a false {dichotomy} between speed and quality.','속도와 품질 사이에는 잘못된 이분법이 있습니다.','dichotomy','C1','presentation',2,'dichotomy binary two sides contrast opposition'),
('w_presentation_C1_25','interrogate','/ɪnˈterəɡeɪt/','verb','면밀히 검토하다','To examine something critically and in detail.','We need to {interrogate} the underlying assumptions.','기저 가정을 면밀히 검토해야 합니다.','interrogate','C1','presentation',2,'interrogate examine question critically scrutiny'),
('w_presentation_C1_26','generalize','/ˈdʒenərəlaɪz/','verb','일반화하다','To make a general statement from specific instances.','We should be careful not to over-{generalize}.','과도하게 일반화하지 않도록 주의해야 합니다.','generalize','C1','presentation',2,'generalize broad conclusion caution limitation'),
('w_presentation_C1_27','precedent','/ˈpresɪdənt/','noun','선례','An earlier event that is taken as a guide for the future.','This sets a {precedent} for future decisions.','이것이 미래 결정의 선례를 세웁니다.','precedent','C1','presentation',2,'precedent history example past reference guide'),
('w_presentation_C1_28','quantitative','/ˈkwɒntɪtətɪv/','adjective','정량적인','Relating to the measurement of quantity or amount.','The {quantitative} findings are compelling.','정량적 발견이 설득력 있습니다.','quantitative','C1','presentation',1,'quantitative data numbers statistics measurement research'),
('w_presentation_C1_29','qualitative','/ˈkwɒlɪtətɪv/','adjective','정성적인','Relating to the quality or character of something.','The {qualitative} feedback revealed key themes.','정성적 피드백에서 핵심 주제가 드러났습니다.','qualitative','C1','presentation',1,'qualitative interview theme insight user research'),
('w_presentation_C1_30','iterative','/ˈɪtərətɪv/','adjective','반복적인, 점진적인','Characterized by repetition of a process to achieve a result.','Our design follows an {iterative} process.','우리 디자인은 반복적인 과정을 따릅니다.','iterative','C1','presentation',2,'iterative process cycle improve agile development'),
('w_presentation_C1_31','posit','/ˈpɒzɪt/','verb','가정하다, 주장하다','To put forward as a fact or basis for argument.','I would {posit} that user trust is the key variable.','사용자 신뢰가 핵심 변수라고 주장하고자 합니다.','posit','C1','presentation',2,'posit argue assert claim academic presentation'),
('w_presentation_C1_32','substantive','/ˈsʌbstəntɪv/','adjective','실질적인, 핵심적인','Having a firm basis in reality and being important or meaningful.','We need {substantive} change, not cosmetic fixes.','표면적 수정이 아닌 실질적인 변화가 필요합니다.','substantive','C1','presentation',2,'substantive real meaningful significant change impact'),
('w_presentation_C1_33','granularity','/ˌɡrænjʊˈlærɪti/','noun','세분화, 세부 수준','The level of detail or precision in data or analysis.','The {granularity} of this dataset is exceptional.','이 데이터셋의 세분화 수준은 탁월합니다.','granularity','C1','presentation',2,'granularity detail precision data level analysis'),
('w_presentation_C1_34','axiom','/ˈæksiəm/','noun','공리, 자명한 이치','A statement accepted as true as the basis for argument.','The first {axiom} of our model is user rationality.','우리 모델의 첫 번째 공리는 사용자 합리성입니다.','axiom','C1','presentation',2,'axiom truth principle foundation logic mathematics'),
('w_presentation_C1_35','reframe','/ˌriːˈfreɪm/','verb','재구성하다','To frame something in a different way to change how it is perceived.','Let us {reframe} this challenge as an opportunity.','이 도전을 기회로 재구성해 봅시다.','reframe','C1','presentation',1,'reframe perspective shift mindset opportunity challenge');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_presentation_C2_01','epistemological','/ɪˌpɪstɪməˈlɒdʒɪkəl/','adjective','인식론적인','Relating to the theory of knowledge, especially how it is acquired.','This raises {epistemological} questions about data validity.','이것은 데이터 타당성에 대한 인식론적 질문을 제기합니다.','epistemological','C2','presentation',2,'epistemology knowledge theory philosophy research validity'),
('w_presentation_C2_02','heuristic','/hjʊˈrɪstɪk/','adjective','발견적인, 경험 탐색적인','Enabling discovery through practical experience rather than a set formula.','We applied a {heuristic} approach to the analysis.','분석에 발견적 접근법을 적용했습니다.','heuristic','C2','presentation',2,'heuristic discovery method practical rule of thumb'),
('w_presentation_C2_03','ontological','/ˌɒntəˈlɒdʒɪkəl/','adjective','존재론적인','Relating to the branch of metaphysics dealing with the nature of being.','The {ontological} assumptions underpin the framework.','존재론적 가정이 프레임워크의 기반을 이룹니다.','ontological','C2','presentation',2,'ontology being existence nature philosophy framework'),
('w_presentation_C2_04','phenomenological','/fɪˌnɒmɪnəˈlɒdʒɪkəl/','adjective','현상학적인','Relating to the study of structures of experience and consciousness.','A {phenomenological} lens reveals lived experience.','현상학적 렌즈가 살아있는 경험을 드러냅니다.','phenomenological','C2','presentation',2,'phenomenological experience consciousness qualitative research'),
('w_presentation_C2_05','dialectical','/ˌdaɪəˈlektɪkəl/','adjective','변증법적인','Relating to the logical discussion of ideas through opposing arguments.','The {dialectical} tension drives innovation.','변증법적 긴장이 혁신을 이끕니다.','dialectical','C2','presentation',2,'dialectical debate tension opposing synthesis Hegel'),
('w_presentation_C2_06','praxis','/ˈpræksɪs/','noun','실천, 프락시스','The process of putting theory into practice; practice informed by theory.','Theory without {praxis} remains abstract.','실천이 없는 이론은 추상에 머뭅니다.','praxis','C2','presentation',2,'praxis practice theory action application real world'),
('w_presentation_C2_07','hermeneutic','/ˌhɜːrmɪˈnjuːtɪk/','adjective','해석학적인','Relating to interpretation, especially of texts or data.','A {hermeneutic} reading of the data is necessary.','데이터에 대한 해석학적 독해가 필요합니다.','hermeneutic','C2','presentation',2,'hermeneutic interpretation meaning text reading analysis'),
('w_presentation_C2_08','meta-analysis','/ˈmetə əˈnæləsɪs/','noun','메타분석','A statistical analysis combining results of multiple scientific studies.','Our {meta-analysis} covered forty primary studies.','메타분석은 40개의 기본 연구를 다루었습니다.','meta-analysis','C2','presentation',1,'meta-analysis systematic review studies aggregate data'),
('w_presentation_C2_09','positivist','/ˈpɒzɪtɪvɪst/','adjective','실증주의적인','Based on the philosophy that knowledge derives only from measurable phenomena.','A strictly {positivist} stance ignores context.','엄격한 실증주의적 입장은 맥락을 무시합니다.','positivist','C2','presentation',2,'positivism empirical measurable science objective'),
('w_presentation_C2_10','constructivist','/kənˈstrʌktɪvɪst/','adjective','구성주의적인','Relating to the view that knowledge is actively constructed by learners.','A {constructivist} paradigm values co-creation.','구성주의 패러다임은 공동 창조를 중시합니다.','constructivist','C2','presentation',2,'constructivism knowledge learning context subjective'),
('w_presentation_C2_11','axiom','/ˈæksiəm/','noun','공리 (수사학적 맥락)','A self-evident truth used as a foundational premise in an argument.','Begin with an {axiom} your audience already accepts.','청중이 이미 받아들이는 공리로 시작하세요.','axiom','C2','presentation',2,'axiom premise truth foundation argument rhetoric'),
('w_presentation_C2_12','reification','/ˌriːɪfɪˈkeɪʃən/','noun','구체화, 실물화','The treatment of an abstract concept as a concrete or material thing.','The {reification} of data can mislead audiences.','데이터의 실물화는 청중을 오도할 수 있습니다.','reification','C2','presentation',2,'reification abstract concrete material concept data'),
('w_presentation_C2_13','verisimilitude','/ˌverɪsɪˈmɪlɪtjuːd/','noun','사실성, 그럴듯함','The appearance of being true or real.','High {verisimilitude} increases audience trust.','높은 사실성은 청중의 신뢰를 높입니다.','verisimilitude','C2','presentation',2,'verisimilitude realism authenticity believable narrative'),
('w_presentation_C2_14','exegesis','/ˌeksɪˈdʒiːsɪs/','noun','주석, 상세 해석','A critical explanation or interpretation of a text or dataset.','The {exegesis} of the survey results took weeks.','설문 결과의 주석 작업에 몇 주가 걸렸습니다.','exegesis','C2','presentation',2,'exegesis interpretation commentary analysis text deep'),
('w_presentation_C2_15','syllogism','/ˈsɪlədʒɪzəm/','noun','삼단논법','A kind of logical argument using deductive reasoning from premises.','The argument follows a classic {syllogism}.','논거는 고전적 삼단논법을 따릅니다.','syllogism','C2','presentation',2,'syllogism logic deduction premise conclusion argument'),
('w_presentation_C2_16','tautology','/tɔːˈtɒlədʒi/','noun','동어반복','Saying the same thing twice in different words; needless repetition.','Avoid {tautology} to keep your argument sharp.','동어반복을 피해 논거를 날카롭게 유지하세요.','tautology','C2','presentation',2,'tautology repetition redundant argument writing logic'),
('w_presentation_C2_17','apotheosis','/əˌpɒθiˈoʊsɪs/','noun','절정, 최고점','The highest point of development; a perfect example of something.','This presentation is the {apotheosis} of our research.','이 발표는 우리 연구의 절정입니다.','apotheosis','C2','presentation',2,'apotheosis peak pinnacle achievement excellence best'),
('w_presentation_C2_18','polemic','/pəˈlemɪk/','noun','논쟁, 논박','A strong verbal or written attack on someone''s opinions or argument.','The paper is a well-researched {polemic}.','논문은 잘 연구된 논박입니다.','polemic','C2','presentation',2,'polemic argument attack critique debate controversy'),
('w_presentation_C2_19','triangulation','/traɪˌæŋɡjʊˈleɪʃən/','noun','삼각검증','The use of multiple methods or data sources to validate findings.','{Triangulation} of sources strengthens the argument.','출처의 삼각검증이 논거를 강화합니다.','triangulation','C2','presentation',1,'triangulation multiple sources validation research robust'),
('w_presentation_C2_20','abductive','/æbˈdʌktɪv/','adjective','귀추적인','Relating to inference to the best explanation from available evidence.','We used {abductive} reasoning to reach our conclusion.','귀추적 추론을 사용해 결론에 도달했습니다.','abductive','C2','presentation',2,'abductive reasoning inference best explanation logic'),
('w_presentation_C2_21','intersubjectivity','/ˌɪntərsəbˌdʒektɪˈvɪtɪ/','noun','상호주관성','Shared understanding between two or more individuals.','{Intersubjectivity} is key to qualitative research validity.','상호주관성은 정성 연구 타당성의 핵심입니다.','intersubjectivity','C2','presentation',2,'intersubjectivity shared understanding qualitative research'),
('w_presentation_C2_22','heterodox','/ˈhetərədɒks/','adjective','비정통적인, 이단적인','Not conforming to established or accepted beliefs or standards.','This {heterodox} approach challenges the consensus.','이 비정통적 접근법은 합의에 도전합니다.','heterodox','C2','presentation',2,'heterodox unconventional challenge consensus alternative'),
('w_presentation_C2_23','semiotics','/ˌsiːmiˈɒtɪks/','noun','기호학','The study of signs and symbols and their use or interpretation.','{Semiotics} informs how we design our slides.','기호학은 슬라이드 디자인 방식에 영향을 줍니다.','semiotics','C2','presentation',2,'semiotics signs symbols meaning design visual language'),
('w_presentation_C2_24','reflexivity','/ˌriːflekˈsɪvɪti/','noun','성찰성','The practice of critically examining one''s own assumptions and methods.','{Reflexivity} strengthens the credibility of research.','성찰성이 연구의 신뢰성을 강화합니다.','reflexivity','C2','presentation',2,'reflexivity self-awareness researcher bias critical'),
('w_presentation_C2_25','teleological','/ˌteliəˈlɒdʒɪkəl/','adjective','목적론적인','Relating to explanation of phenomena in terms of goals or purposes.','The argument is {teleological} in nature.','논거는 본질적으로 목적론적입니다.','teleological','C2','presentation',2,'teleological purpose goal driven argument reason'),
('w_presentation_C2_26','reductionism','/rɪˈdʌkʃənɪzəm/','noun','환원주의','The practice of analyzing complex things by reducing them to simpler parts.','Pure {reductionism} misses emergent phenomena.','순수 환원주의는 창발적 현상을 놓칩니다.','reductionism','C2','presentation',2,'reductionism simplify parts whole emergent complex'),
('w_presentation_C2_27','falsifiability','/ˌfɔːlsɪfaɪəˈbɪlɪti/','noun','반증가능성','The capacity for a statement to be contradicted by evidence.','A good hypothesis must have {falsifiability}.','좋은 가설은 반증가능성을 갖추어야 합니다.','falsifiability','C2','presentation',2,'falsifiability Popper science hypothesis testable'),
('w_presentation_C2_28','bricolage','/ˌbrɪkəˈlɑːʒ/','noun','브리콜라주','A construction or approach made from a diverse range of available elements.','The methodology is a {bricolage} of approaches.','방법론은 다양한 접근법의 브리콜라주입니다.','bricolage','C2','presentation',2,'bricolage mixed methods creative eclectic approach'),
('w_presentation_C2_29','instantiate','/ɪnˈstænʃieɪt/','verb','구현하다, 사례로 나타내다','To represent an abstract concept by means of a concrete example.','This case study {instantiate}s the theory.','이 사례 연구가 이론을 구현합니다.','instantiate','C2','presentation',2,'instantiate example concrete theory case study prove'),
('w_presentation_C2_30','probative','/ˈproʊbətɪv/','adjective','증명력 있는','Having the quality of proving or demonstrating something.','Only {probative} evidence was considered.','증명력 있는 증거만 고려되었습니다.','probative','C2','presentation',2,'probative evidence proof demonstrate quality strong'),
('w_presentation_C2_31','circumlocution','/ˌsɜːrkəmloʊˈkjuːʃən/','noun','우회적 표현','The use of many words where fewer would be clear; indirect expression.','Avoid {circumlocution} to maintain audience attention.','청중의 집중을 유지하려면 우회적 표현을 피하세요.','circumlocution','C2','presentation',2,'circumlocution indirect wordy verbose clarity brevity'),
('w_presentation_C2_32','apophenia','/ˌæpəˈfiːniə/','noun','패턴 착각 현상','The tendency to perceive meaningful connections between unrelated things.','Analysts must guard against {apophenia} in data.','분석가는 데이터의 패턴 착각을 경계해야 합니다.','apophenia','C2','presentation',2,'apophenia false pattern bias data analysis error'),
('w_presentation_C2_33','episteme','/ˈepɪˌstiːm/','noun','에피스테메','The body of ideas that define the knowledge of a particular era.','The dominant {episteme} shapes how data is framed.','지배적인 에피스테메가 데이터가 구성되는 방식을 형성합니다.','episteme','C2','presentation',2,'episteme knowledge era framework Foucault paradigm'),
('w_presentation_C2_34','isomorphism','/ˈaɪsəˌmɔːrfɪzəm/','noun','동형성','A correspondence or similarity in form or structure between two models.','There is an {isomorphism} between the two models.','두 모델 사이에 동형성이 있습니다.','isomorphism','C2','presentation',2,'isomorphism same structure parallel model comparison'),
('w_presentation_C2_35','polysemy','/pɒˈlɪsɪmi/','noun','다의성','The capacity of a word or phrase to have multiple meanings.','{Polysemy} in technical terms can confuse audiences.','기술 용어의 다의성은 청중을 혼란스럽게 할 수 있습니다.','polysemy','C2','presentation',2,'polysemy multiple meanings ambiguity language precision');
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_presentation_A1_01','Let me introduce myself.','자기소개를 하겠습니다.','Let me introduce','발표를 시작할 때 가장 먼저 쓰는 표현이에요. "Let me ~"는 "제가 ~하겠습니다"라는 부드러운 의사 표명이에요.','발표 시작','A1','presentation','pattern',NULL,1),
('s_presentation_A1_02','Today I will talk about our project.','오늘 저희 프로젝트에 대해 이야기하겠습니다.','talk about','발표 주제를 한 문장으로 소개할 때 쓰는 가장 기본적인 표현이에요.','발표 시작','A1','presentation','pattern',NULL,2),
('s_presentation_A1_03','My name is Ji-yeon and I am from the design team.','제 이름은 지연이고 디자인팀에 있습니다.','My name is','이름과 소속을 함께 소개하는 심플한 오프닝 패턴이에요.','발표 시작','A1','presentation','pattern',NULL,3),
('s_presentation_A1_04','Please look at this slide.','이 슬라이드를 봐주세요.','Please look at','청중의 시선을 슬라이드로 유도할 때 자연스럽게 쓸 수 있어요.','슬라이드 안내','A1','presentation','pattern',NULL,4),
('s_presentation_A1_05','First, I will show you the main idea.','먼저 주요 아이디어를 보여드리겠습니다.','First, I will show','순서를 안내하는 가장 단순한 패턴이에요. First / Next / Last로 이어가세요.','발표 구조 안내','A1','presentation','pattern',NULL,5),
('s_presentation_A1_06','Are there any questions?','질문이 있으신가요?','Are there any questions','발표 중간 또는 마지막에 청중의 참여를 유도하는 표현이에요.','Q&A','A1','presentation','pattern',NULL,6),
('s_presentation_A1_07','That is the end of my talk. Thank you.','발표를 마치겠습니다. 감사합니다.','That is the end','발표를 깔끔하게 마무리할 때 쓰는 가장 간결한 클로징 표현이에요.','발표 마무리','A1','presentation','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_presentation_A2_01','My talk is divided into three parts.','제 발표는 세 부분으로 나뉩니다.','divided into three parts','발표 구조를 청중에게 미리 알려주는 표현이에요. 숫자를 바꿔 쓸 수 있어요.','개요 설명','A2','presentation','pattern',NULL,8),
('s_presentation_A2_02','First I will cover the background, then the findings, and finally the recommendations.','먼저 배경을 다루고, 그다음 발견 사항, 마지막으로 권고 사항을 다루겠습니다.','First ... then ... finally','세 단계를 나열하는 전형적인 발표 아웃라인 표현이에요.','개요 설명','A2','presentation','pattern',NULL,9),
('s_presentation_A2_03','Please feel free to ask questions at the end.','마지막에 자유롭게 질문해 주세요.','Please feel free to','청중을 편안하게 해주는 표현이에요. "feel free to"는 허락과 격려를 동시에 전달해요.','Q&A 안내','A2','presentation','pattern',NULL,10),
('s_presentation_A2_04','Let me give you a brief overview before we begin.','시작하기 전에 간략한 개요를 말씀드리겠습니다.','brief overview','본격적인 내용에 앞서 전체 그림을 제시하는 전환 표현이에요.','개요 설명','A2','presentation','pattern',NULL,11),
('s_presentation_A2_05','The main topic of today''s presentation is customer satisfaction.','오늘 발표의 주요 주제는 고객 만족입니다.','The main topic of','주제를 명확하게 한 문장으로 정의하는 표현이에요.','주제 소개','A2','presentation','pattern',NULL,12),
('s_presentation_A2_06','By the end of this presentation, you will understand the key steps.','이 발표가 끝날 때쯤이면 핵심 단계를 이해하게 될 것입니다.','By the end of this presentation','청중에게 기대치를 미리 설정해주는 강력한 오프닝 기법이에요.','목표 제시','A2','presentation','pattern',NULL,13),
('s_presentation_A2_07','In conclusion, the data shows a clear trend.','결론적으로, 데이터는 명확한 추세를 보여줍니다.','In conclusion','발표 마지막에 전체 내용을 하나의 문장으로 요약할 때 쓰는 표현이에요.','결론','A2','presentation','pattern',NULL,14);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_presentation_B1_01','Now let''s move on to the next point.','이제 다음 요점으로 넘어가겠습니다.','let''s move on to','섹션 사이를 자연스럽게 이어주는 가장 많이 쓰이는 전환 표현이에요.','전환','B1','presentation','pattern',NULL,15),
('s_presentation_B1_02','Having looked at the problem, let''s now consider the solution.','문제를 살펴봤으니, 이제 해결책을 생각해 보겠습니다.','Having looked at ... let''s now','분사구문을 이용한 자연스러운 전환 패턴이에요. 발표를 논리적으로 연결시켜 줘요.','전환','B1','presentation','pattern',NULL,16),
('s_presentation_B1_03','I''d like to draw your attention to this chart.','이 차트에 주목해 주시기 바랍니다.','draw your attention to','청중의 시선을 특정 시각 자료로 유도하는 세련된 표현이에요.','시각 자료 안내','B1','presentation','pattern',NULL,17),
('s_presentation_B1_04','This brings me to my second point.','이것이 저를 두 번째 요점으로 이끕니다.','This brings me to','앞 내용에서 다음 내용으로 자연스럽게 흐르는 전환 표현이에요.','전환','B1','presentation','pattern',NULL,18),
('s_presentation_B1_05','To illustrate this point, let me give you a concrete example.','이 요점을 설명하기 위해 구체적인 예를 들어드리겠습니다.','To illustrate this point','예시를 제시하기 전에 쓰는 정중한 안내 표현이에요.','예시 제시','B1','presentation','pattern',NULL,19),
('s_presentation_B1_06','As I mentioned earlier, the key challenge is timing.','앞서 언급했듯이, 핵심 과제는 타이밍입니다.','As I mentioned earlier','이전 내용을 상기시키며 논리를 강화하는 표현이에요.','참조','B1','presentation','pattern',NULL,20),
('s_presentation_B1_07','Before I move on, are there any questions so far?','계속 진행하기 전에, 지금까지 질문 있으신가요?','Before I move on','중간에 청중 참여를 유도하며 템포를 조절하는 표현이에요.','Q&A 중간 확인','B1','presentation','pattern',NULL,21);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_presentation_B2_01','What I want to emphasize here is the long-term impact of this decision.','제가 여기서 강조하고 싶은 것은 이 결정의 장기적인 영향입니다.','What I want to emphasize','"What I want to ~" 구문은 핵심 메시지를 강조할 때 강력하게 작동해요.','강조','B2','presentation','pattern',NULL,22),
('s_presentation_B2_02','It is worth noting that this trend has been consistent for three years.','이 추세가 3년간 일관되게 유지되어 왔다는 점은 주목할 만합니다.','It is worth noting that','"It is worth noting that ~"은 청중이 놓칠 수 있는 중요한 세부 사항을 강조하는 표현이에요.','강조','B2','presentation','pattern',NULL,23),
('s_presentation_B2_03','The data compellingly demonstrates that our approach is working.','데이터는 우리의 접근법이 효과적이라는 것을 설득력 있게 증명합니다.','compellingly demonstrates','"compellingly"와 같은 부사로 주장의 강도를 높이는 B2 기법이에요.','증거 제시','B2','presentation','pattern',NULL,24),
('s_presentation_B2_04','To summarize the key takeaways from today''s presentation...','오늘 발표의 핵심 시사점을 요약하자면...','key takeaways','"takeaway"는 청중이 발표에서 가져가야 할 교훈이나 인사이트를 뜻해요.','마무리','B2','presentation','pattern',NULL,25),
('s_presentation_B2_05','I would like to leave you with one final thought.','마지막으로 한 가지 생각을 남기고 싶습니다.','leave you with one final thought','발표를 임팩트 있게 마무리하는 클래식한 표현이에요. 기억에 남는 한 마디를 남길 때 써요.','마무리','B2','presentation','pattern',NULL,26),
('s_presentation_B2_06','In light of this evidence, I strongly recommend proceeding with option B.','이 증거에 비추어 볼 때, 저는 옵션 B를 강력히 권장합니다.','In light of this evidence','"In light of ~"는 증거를 근거로 결론을 제시할 때 쓰는 격식 있는 표현이에요.','권장 사항','B2','presentation','pattern',NULL,27),
('s_presentation_B2_07','Should you have any further questions, please do not hesitate to reach out.','추가 질문이 있으시면 언제든지 연락 주시기 바랍니다.','please do not hesitate to reach out','발표 후 후속 소통을 열어두는 정중한 클로징 표현이에요.','발표 마무리','B2','presentation','pattern',NULL,28);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_presentation_C1_01','The empirical evidence overwhelmingly supports the hypothesis that engagement drives retention.','경험적 증거는 참여가 유지율을 이끈다는 가설을 압도적으로 뒷받침합니다.','empirical evidence overwhelmingly supports','"overwhelmingly supports"처럼 강한 부사를 써서 주장의 확신도를 높이는 C1 설득 기법이에요.','설득','C1','presentation','pattern',NULL,29),
('s_presentation_C1_02','I will now deconstruct the conventional wisdom surrounding this issue.','이제 이 문제를 둘러싼 통념을 해체하겠습니다.','deconstruct the conventional wisdom','통념에 도전하며 새로운 관점을 제시하는 강렬한 오프닝 기법이에요.','논리 구성','C1','presentation','pattern',NULL,30),
('s_presentation_C1_03','This framework allows us to synthesize findings across multiple disciplines.','이 프레임워크를 통해 여러 학문 분야의 발견을 종합할 수 있습니다.','synthesize findings across multiple disciplines','학제적 접근을 강조하는 고급 표현으로 발표의 깊이와 범위를 보여줘요.','논리 구성','C1','presentation','pattern',NULL,31),
('s_presentation_C1_04','The implications of this paradigm shift extend far beyond our immediate industry.','이 패러다임 전환의 함의는 우리의 직접적인 산업을 훨씬 넘어섭니다.','implications ... extend far beyond','넓은 시야를 강조하며 중요성을 부각하는 고급 표현이에요.','설득','C1','presentation','pattern',NULL,32),
('s_presentation_C1_05','While the quantitative data is compelling, the qualitative insights reveal a more nuanced picture.','정량적 데이터는 설득력 있지만, 정성적 인사이트는 더 세밀한 그림을 드러냅니다.','While ... more nuanced picture','양면을 인정하면서도 더 깊은 통찰을 제시하는 균형 잡힌 논리 전개 방식이에요.','균형 잡힌 분석','C1','presentation','pattern',NULL,33),
('s_presentation_C1_06','I would posit that the root cause lies not in the symptom but in the underlying system.','근본 원인은 증상이 아니라 기저 시스템에 있다고 주장하고자 합니다.','I would posit that','"posit"은 "주장하다, 가정하다"의 뜻으로 학술·전문 발표에서 의견을 조심스럽게 제시할 때 써요.','주장 제시','C1','presentation','pattern',NULL,34),
('s_presentation_C1_07','To conclude, the convergence of these three factors creates an unprecedented opportunity.','결론적으로, 이 세 가지 요소의 수렴은 전례 없는 기회를 만들어냅니다.','convergence ... unprecedented opportunity','수렴과 기회를 연결하는 강력한 클로징 문장이에요. 발표를 희망적이고 명확하게 마무리해요.','결론','C1','presentation','pattern',NULL,35);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_presentation_C2_01','The dialectical tension between efficiency and equity is not a problem to be solved but a dynamic to be managed.','효율성과 형평성 사이의 변증법적 긴장은 해결해야 할 문제가 아니라 관리해야 할 역동성입니다.','dialectical tension ... dynamic to be managed','이분법을 거부하고 복잡성을 긍정하는 고급 수사 기법이에요. 청중에게 깊은 인상을 남깁니다.','수사학','C2','presentation','pattern',NULL,36),
('s_presentation_C2_02','What this meta-analysis reveals is not merely correlation but a robust causal mechanism.','이 메타분석이 드러내는 것은 단순한 상관관계가 아니라 견고한 인과 메커니즘입니다.','not merely ... but a robust causal mechanism','"not merely A but B" 구조로 주장의 격을 높이는 C2 수준 수사 표현이에요.','수사학','C2','presentation','pattern',NULL,37),
('s_presentation_C2_03','I invite you to interrogate your own assumptions as we work through this evidence together.','이 증거를 함께 검토하면서 자신의 가정을 면밀히 살펴보시길 권합니다.','interrogate your own assumptions','청중을 능동적 참여자로 초대하는 소크라테스식 수사 기법이에요.','설득 수사학','C2','presentation','pattern',NULL,38),
('s_presentation_C2_04','The epistemological question we must first address is: how do we know what we think we know?','우리가 먼저 다루어야 할 인식론적 질문은 이것입니다: 우리가 안다고 생각하는 것을 우리는 어떻게 알까요?','epistemological question','수사 의문문을 사용해 청중을 사고 실험으로 끌어들이는 고급 발표 기법이에요.','인식론적 접근','C2','presentation','pattern',NULL,39),
('s_presentation_C2_05','Through a process of triangulation across qualitative, quantitative, and ethnographic sources, we arrive at a remarkably consistent picture.','정성적, 정량적, 민족지적 출처에 걸친 삼각검증 과정을 통해 우리는 놀랍도록 일관된 그림에 도달합니다.','triangulation across ... remarkably consistent','다중 출처 검증을 강조하며 연구의 견고함을 드러내는 학술 발표의 핵심 표현이에요.','연구 방법론 설명','C2','presentation','pattern',NULL,40),
('s_presentation_C2_06','Far from being a peripheral concern, reflexivity is central to the integrity of this entire analysis.','성찰성은 주변적 관심사가 아니라 이 분석 전체의 무결성의 핵심입니다.','Far from being ... central to','"Far from being A, B is C" 구조는 기대를 뒤집으며 핵심을 부각하는 강력한 수사 기법이에요.','수사학','C2','presentation','pattern',NULL,41),
('s_presentation_C2_07','I leave you with a provocation: if our praxis does not challenge existing structures, what exactly are we here to present?','하나의 도발을 남깁니다: 우리의 실천이 기존 구조에 도전하지 않는다면, 우리는 정확히 무엇을 발표하러 여기 있는 것입니까?','I leave you with a provocation','발표를 열린 질문으로 마무리하며 청중의 사고를 자극하는 최고 수준의 수사적 클로징이에요.','수사학적 마무리','C2','presentation','pattern',NULL,42);
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_negotiation_A1_01','want','/wɒnt/','verb','원하다','To feel a desire or wish for something.','What do you {want} from this deal?','이 거래에서 무엇을 원하세요?','want','A1','negotiation',1,'negotiation business handshake agreement'),
('w_negotiation_A1_02','need','/niːd/','verb','필요하다','To require something as necessary or important.','I {need} a better price for this.','이것에 더 좋은 가격이 필요해요.','need','A1','negotiation',1,'need requirement checklist office'),
('w_negotiation_A1_03','give','/ɡɪv/','verb','주다','To hand something over to someone.','Can you {give} me a small discount?','할인을 조금 주실 수 있나요?','give','A1','negotiation',1,'giving handshake gift exchange'),
('w_negotiation_A1_04','take','/teɪk/','verb','받아들이다, 가져가다','To accept something that is offered.','I''ll {take} the offer if the price is right.','가격이 맞으면 제안을 받아들일게요.','take','A1','negotiation',1,'accept deal take offer business'),
('w_negotiation_A1_05','agree','/əˈɡriː/','verb','동의하다','To have the same opinion as someone else.','We both {agree} on the main points.','우리는 주요 사항에 동의해요.','agree','A1','negotiation',1,'agreement nodding handshake smiling'),
('w_negotiation_A1_06','ask','/ɑːsk/','verb','요청하다, 묻다','To request something or seek information.','I want to {ask} for a longer deadline.','더 긴 마감일을 요청하고 싶어요.','ask','A1','negotiation',1,'question asking office meeting discussion'),
('w_negotiation_A1_07','offer','/ˈɒfər/','verb','제안하다','To present something for someone to accept or refuse.','We can {offer} a better rate next month.','다음 달에 더 좋은 요율을 제안할 수 있어요.','offer','A1','negotiation',1,'offer proposal business meeting table'),
('w_negotiation_A1_08','deal','/diːl/','noun','거래, 합의','An agreement, especially in business.','We made a great {deal} with the supplier.','공급업체와 좋은 거래를 했어요.','deal','A1','negotiation',1,'business deal handshake contract signing'),
('w_negotiation_A1_09','yes','/jes/','adverb','네, 예','Used to give an affirmative answer or agreement.','Say {yes} only when you are ready.','준비가 됐을 때만 예스라고 하세요.','yes','A1','negotiation',1,'agreement thumbs up approval positive'),
('w_negotiation_A1_10','no','/nəʊ/','adverb','아니요','Used to give a negative answer or refusal.','It is okay to say {no} in a negotiation.','협상에서 아니오라고 해도 괜찮아요.','no','A1','negotiation',1,'refusal shaking head no disagreement'),
('w_negotiation_A1_11','help','/help/','verb','돕다','To make it easier for someone to do something.','Can you {help} me with the contract?','계약서 작성을 도와주실 수 있나요?','help','A1','negotiation',1,'helping colleague office teamwork support'),
('w_negotiation_A1_12','more','/mɔːr/','adverb','더','A greater quantity or amount.','I need {more} time to think about it.','생각할 시간이 더 필요해요.','more','A1','negotiation',2,'more quantity increase growth chart'),
('w_negotiation_A1_13','less','/les/','adverb','덜, 더 적게','A smaller quantity or degree.','Can we pay {less} than the asking price?','요구 가격보다 덜 낼 수 있을까요?','less','A1','negotiation',2,'reduce decrease lower price tag'),
('w_negotiation_A1_14','pay','/peɪ/','verb','지불하다','To give money for goods or services.','How much do we need to {pay} upfront?','선불로 얼마나 내야 하나요?','pay','A1','negotiation',1,'payment money cash credit card'),
('w_negotiation_A1_15','get','/ɡet/','verb','얻다','To obtain or receive something.','What do we {get} in return?','대신 우리는 무엇을 얻나요?','get','A1','negotiation',1,'receive obtain reward benefit'),
('w_negotiation_A1_16','talk','/tɔːk/','verb','이야기하다','To communicate by speaking.','Let''s {talk} about the details later.','나중에 세부 사항에 대해 이야기해요.','talk','A1','negotiation',2,'conversation talking office meeting people'),
('w_negotiation_A1_17','meet','/miːt/','verb','만나다','To come together with someone at a place.','Can we {meet} on Friday to discuss this?','이것을 논의하기 위해 금요일에 만날 수 있나요?','meet','A1','negotiation',2,'meeting handshake conference room business'),
('w_negotiation_A1_18','say','/seɪ/','verb','말하다','To express something in words.','Please {say} what you think clearly.','생각하시는 것을 명확히 말씀해 주세요.','say','A1','negotiation',2,'speaking talking presentation clear communication'),
('w_negotiation_A1_19','wait','/weɪt/','verb','기다리다','To stay in one place until something happens.','Please {wait} while I check the numbers.','숫자를 확인하는 동안 기다려 주세요.','wait','A1','negotiation',2,'waiting patience calm office'),
('w_negotiation_A1_20','try','/traɪ/','verb','시도하다','To make an effort to do something.','Let''s {try} to find a middle ground.','중간 지점을 찾아보도록 해요.','try','A1','negotiation',2,'effort attempt trying problem solving'),
('w_negotiation_A1_21','buy','/baɪ/','verb','구매하다','To get something by paying money for it.','We want to {buy} in bulk to lower the price.','가격을 낮추기 위해 대량으로 구매하고 싶어요.','buy','A1','negotiation',1,'purchasing buying store bulk shopping'),
('w_negotiation_A1_22','sell','/sel/','verb','팔다','To give something in exchange for money.','We can {sell} at this price if you order now.','지금 주문하시면 이 가격에 드릴 수 있어요.','sell','A1','negotiation',1,'selling business commerce sale market'),
('w_negotiation_A1_23','price','/praɪs/','noun','가격','The amount of money expected for something.','What is the best {price} you can offer?','가장 좋은 가격은 얼마인가요?','price','A1','negotiation',1,'price tag label shopping market cost'),
('w_negotiation_A1_24','time','/taɪm/','noun','시간','A period within which something is done.','Do we have enough {time} to review everything?','모든 것을 검토할 시간이 충분한가요?','time','A1','negotiation',2,'clock time management deadline calendar'),
('w_negotiation_A1_25','good','/ɡʊd/','adjective','좋은','Of high quality or beneficial.','That sounds like a {good} offer to me.','저에게는 좋은 제안처럼 들려요.','good','A1','negotiation',2,'quality good positive thumbs up'),
('w_negotiation_A1_26','bad','/bæd/','adjective','나쁜','Of poor quality or unfavorable.','The terms are too {bad} to accept right now.','지금 당장 받아들이기엔 조건이 너무 나빠요.','bad','A1','negotiation',2,'negative poor quality unhappy'),
('w_negotiation_A1_27','okay','/ˌəʊˈkeɪ/','adjective','괜찮은','Satisfactory but not excellent.','The first offer is {okay} but we need more.','첫 제안은 괜찮지만 더 필요해요.','okay','A1','negotiation',2,'okay agreement acceptable neutral'),
('w_negotiation_A1_28','change','/tʃeɪndʒ/','verb','바꾸다','To make something different.','Can we {change} the payment schedule?','지불 일정을 바꿀 수 있을까요?','change','A1','negotiation',2,'change adjust modify edit revise'),
('w_negotiation_A1_29','stop','/stɒp/','verb','멈추다','To cease doing something.','Let''s {stop} here and continue tomorrow.','여기서 멈추고 내일 계속해요.','stop','A1','negotiation',3,'stop pause break rest meeting'),
('w_negotiation_A1_30','start','/stɑːt/','verb','시작하다','To begin something.','Let''s {start} with the most important issue.','가장 중요한 사안부터 시작해요.','start','A1','negotiation',2,'start begin launch opening meeting'),
('w_negotiation_A1_31','ready','/ˈredi/','adjective','준비된','Prepared and able to do something.','Are you {ready} to make a final decision?','최종 결정을 내릴 준비가 됐나요?','ready','A1','negotiation',2,'ready prepared confident business person'),
('w_negotiation_A1_32','open','/ˈəʊpən/','adjective','열린, 개방적인','Willing to consider new ideas.','I am {open} to other suggestions.','다른 제안에 열려 있어요.','open','A1','negotiation',2,'open door opportunity discussion flexible'),
('w_negotiation_A1_33','right','/raɪt/','adjective','맞는, 올바른','Correct or appropriate.','We need to find the {right} solution for both sides.','양쪽에 맞는 해결책을 찾아야 해요.','right','A1','negotiation',2,'correct right check mark solution'),
('w_negotiation_A1_34','work','/wɜːk/','verb','효과가 있다','To function effectively or be successful.','This plan can {work} if we cooperate.','협력하면 이 계획은 효과가 있을 거예요.','work','A1','negotiation',2,'teamwork cooperation plan effective'),
('w_negotiation_A1_35','think','/θɪŋk/','verb','생각하다','To use your mind to consider something.','Let me {think} about it and get back to you.','생각해 보고 다시 연락할게요.','think','A1','negotiation',2,'thinking considering person office pause');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_negotiation_A2_01','discount','/ˈdɪskaʊnt/','noun','할인','A reduction in the usual price of something.','Can you offer a {discount} for a large order?','대량 주문에 할인을 해주실 수 있나요?','discount','A2','negotiation',1,'discount sale percentage tag price reduction'),
('w_negotiation_A2_02','accept','/əkˈsept/','verb','받아들이다','To agree to receive or take something offered.','We are happy to {accept} the revised terms.','수정된 조건을 기꺼이 받아들여요.','accept','A2','negotiation',1,'accept agreement handshake deal approval'),
('w_negotiation_A2_03','refuse','/rɪˈfjuːz/','verb','거절하다','To say that you will not do or accept something.','We have to {refuse} the current proposal.','현재 제안은 거절해야 해요.','refuse','A2','negotiation',1,'refuse reject decline shake head no'),
('w_negotiation_A2_04','propose','/prəˈpəʊz/','verb','제안하다','To put forward a plan or idea for consideration.','I would like to {propose} a new payment plan.','새로운 지불 계획을 제안하고 싶어요.','propose','A2','negotiation',1,'propose idea presentation whiteboard business'),
('w_negotiation_A2_05','condition','/kənˈdɪʃən/','noun','조건','A requirement that must be met before something can happen.','What are the main {conditions} of the agreement?','계약의 주요 조건은 무엇인가요?','condition','A2','negotiation',1,'conditions checklist contract terms document'),
('w_negotiation_A2_06','term','/tɜːm/','noun','조건, 기간','A condition or stipulation in a contract or agreement.','The payment {terms} are thirty days net.','지불 조건은 순 30일이에요.','term','A2','negotiation',1,'terms contract document signing office'),
('w_negotiation_A2_07','fair','/feər/','adjective','공정한','Treating everyone equally and according to the rules.','We want a {fair} deal for both sides.','양쪽 모두에게 공정한 거래를 원해요.','fair','A2','negotiation',1,'fair balance scales justice equal'),
('w_negotiation_A2_08','both','/bəʊθ/','determiner','둘 다','Two people or things considered together.','This outcome benefits {both} parties.','이 결과는 양 당사자 모두에게 이익이에요.','both','A2','negotiation',2,'both sides together partnership balance'),
('w_negotiation_A2_09','together','/təˈɡeðər/','adverb','함께','With each other; in cooperation.','Let''s work {together} on the final contract.','최종 계약서를 함께 작업해요.','together','A2','negotiation',2,'teamwork together partnership cooperation office'),
('w_negotiation_A2_10','budget','/ˈbʌdʒɪt/','noun','예산','The amount of money available for a purpose.','Our {budget} does not allow for that increase.','우리 예산으로는 그 인상을 허용할 수 없어요.','budget','A2','negotiation',1,'budget finance spreadsheet planning money'),
('w_negotiation_A2_11','payment','/ˈpeɪmənt/','noun','지불, 결제','The act of paying money owed.','Can we split the {payment} into installments?','지불을 할부로 나눌 수 있나요?','payment','A2','negotiation',1,'payment credit card invoice receipt'),
('w_negotiation_A2_12','delivery','/dɪˈlɪvəri/','noun','배송, 납품','The process of bringing goods to a buyer.','We need faster {delivery} dates to meet demand.','수요를 맞추려면 더 빠른 납품 날짜가 필요해요.','delivery','A2','negotiation',1,'delivery shipping logistics package truck'),
('w_negotiation_A2_13','contract','/ˈkɒntrækt/','noun','계약서','A written legal agreement between parties.','Please review the {contract} before signing.','서명 전에 계약서를 검토해 주세요.','contract','A2','negotiation',1,'contract document signing pen legal'),
('w_negotiation_A2_14','agree on','/əˈɡriː ɒn/','phrase','~에 합의하다','To reach a shared decision about something.','We need to {agree on} a final price today.','오늘 최종 가격에 합의해야 해요.','agree on','A2','negotiation',1,'agreement consensus handshake decision'),
('w_negotiation_A2_15','total','/ˈtəʊtəl/','noun','총액','The whole amount or sum.','The {total} cost comes to five thousand dollars.','총 비용은 5,000달러예요.','total','A2','negotiation',1,'total sum calculator invoice finance'),
('w_negotiation_A2_16','flexible','/ˈfleksɪbəl/','adjective','유연한','Willing to change to suit new conditions.','Are you {flexible} on the delivery date?','납품 날짜에 유연성이 있나요?','flexible','A2','negotiation',2,'flexible adjustable adaptable options choice'),
('w_negotiation_A2_17','option','/ˈɒpʃən/','noun','선택지','A thing that is or may be chosen.','We have several {options} to discuss.','논의할 선택지가 몇 가지 있어요.','option','A2','negotiation',1,'options choices multiple decision paths'),
('w_negotiation_A2_18','cost','/kɒst/','noun','비용','The amount paid to buy or produce something.','The {cost} of shipping needs to be reduced.','배송 비용을 줄여야 해요.','cost','A2','negotiation',1,'cost expense money calculation finance'),
('w_negotiation_A2_19','question','/ˈkwɛstʃən/','noun','질문','A sentence requesting information.','I have one important {question} about the terms.','조건에 관해 중요한 질문이 하나 있어요.','question','A2','negotiation',2,'question inquiry thinking meeting discussion'),
('w_negotiation_A2_20','reduce','/rɪˈdjuːs/','verb','줄이다','To make something smaller or less.','Could you {reduce} the minimum order quantity?','최소 주문 수량을 줄여주실 수 있나요?','reduce','A2','negotiation',1,'reduce decrease lower cut graph'),
('w_negotiation_A2_21','increase','/ɪnˈkriːs/','verb','늘리다','To become or make something greater.','We plan to {increase} our order next quarter.','다음 분기에 주문을 늘릴 계획이에요.','increase','A2','negotiation',2,'increase growth chart upward business'),
('w_negotiation_A2_22','include','/ɪnˈkluːd/','verb','포함하다','To have something as part of a whole.','Does the price {include} installation costs?','가격에 설치 비용이 포함되나요?','include','A2','negotiation',2,'include checklist package contents all'),
('w_negotiation_A2_23','consider','/kənˈsɪdər/','verb','고려하다','To think carefully about something.','Please {consider} our revised offer.','수정된 제안을 고려해 주세요.','consider','A2','negotiation',1,'consider thinking review evaluate option'),
('w_negotiation_A2_24','sample','/ˈsæmpəl/','noun','샘플','A small part or quantity that shows what the whole is like.','Could you send a {sample} before we decide?','결정하기 전에 샘플을 보내주실 수 있나요?','sample','A2','negotiation',2,'sample product test quality review'),
('w_negotiation_A2_25','schedule','/ˈskedʒuːl/','noun','일정','A plan of things to be done at specific times.','Let''s set a {schedule} for the next steps.','다음 단계를 위한 일정을 정해요.','schedule','A2','negotiation',2,'schedule calendar planning timeline meeting'),
('w_negotiation_A2_26','confirm','/kənˈfɜːm/','verb','확인하다','To make something certain or definite.','Please {confirm} your acceptance by email.','이메일로 수락을 확인해 주세요.','confirm','A2','negotiation',1,'confirm check approve email agreement'),
('w_negotiation_A2_27','cancel','/ˈkænsəl/','verb','취소하다','To decide not to proceed with a plan.','We may have to {cancel} if terms do not improve.','조건이 개선되지 않으면 취소해야 할 수도 있어요.','cancel','A2','negotiation',2,'cancel stop halt exit plan'),
('w_negotiation_A2_28','extra','/ˈekstrə/','adjective','추가의','More than what is usual or expected.','Are there any {extra} fees we should know about?','알아야 할 추가 요금이 있나요?','extra','A2','negotiation',2,'extra additional fees hidden costs'),
('w_negotiation_A2_29','limit','/ˈlɪmɪt/','noun','한도, 제한','The highest amount of something allowed.','There is a {limit} to what we can offer.','우리가 제공할 수 있는 것에 한도가 있어요.','limit','A2','negotiation',2,'limit boundary maximum cap constraint'),
('w_negotiation_A2_30','expect','/ɪkˈspekt/','verb','기대하다','To believe something will happen.','We {expect} delivery within two weeks.','2주 내에 배송을 기대해요.','expect','A2','negotiation',2,'expect anticipate timeline delivery business'),
('w_negotiation_A2_31','check','/tʃek/','verb','확인하다','To examine something to ensure it is correct.','Let me {check} with my manager first.','먼저 매니저와 확인해 볼게요.','check','A2','negotiation',2,'check verify review approve manager'),
('w_negotiation_A2_32','invoice','/ˈɪnvɔɪs/','noun','청구서, 인보이스','A document listing goods or services provided and their cost.','Please send the {invoice} to our accounts department.','회계 부서로 청구서를 보내주세요.','invoice','A2','negotiation',1,'invoice receipt billing payment document'),
('w_negotiation_A2_33','guarantee','/ˌɡærənˈtiː/','noun','보장, 보증','A formal assurance that certain conditions will be met.','Can you {guarantee} delivery by Monday?','월요일까지 배송을 보장해주실 수 있나요?','guarantee','A2','negotiation',1,'guarantee warranty promise assurance certificate'),
('w_negotiation_A2_34','review','/rɪˈvjuː/','verb','검토하다','To examine something in detail to assess it.','We will {review} the proposal and respond tomorrow.','제안서를 검토하고 내일 답변드릴게요.','review','A2','negotiation',1,'review document reading analysis office'),
('w_negotiation_A2_35','meeting','/ˈmiːtɪŋ/','noun','회의','A gathering of people for discussion.','Can we set up a {meeting} to finalize the details?','세부 사항을 확정하기 위한 회의를 잡을 수 있나요?','meeting','A2','negotiation',1,'meeting conference room business discussion table');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_negotiation_B1_01','negotiate','/nɪˈɡəʊʃieɪt/','verb','협상하다','To discuss formally to reach an agreement.','Both sides agreed to {negotiate} a new contract.','양측은 새로운 계약을 협상하기로 합의했어요.','negotiate','B1','negotiation',1,'negotiate discussion business meeting formal'),
('w_negotiation_B1_02','compromise','/ˈkɒmprəmaɪz/','verb','타협하다','To settle by mutual concession; accept less than ideal.','We had to {compromise} on the delivery schedule.','납품 일정에 대해 타협해야 했어요.','compromise','B1','negotiation',1,'compromise balance middle ground agreement'),
('w_negotiation_B1_03','concession','/kənˈseʃən/','noun','양보','A thing granted as a compromise.','Making a small {concession} helped close the deal.','작은 양보가 거래를 성사시키는 데 도움이 됐어요.','concession','B1','negotiation',1,'concession compromise giving yielding negotiation'),
('w_negotiation_B1_04','leverage','/ˈlevərɪdʒ/','noun','협상력, 레버리지','Power or advantage used to achieve a goal.','Our bulk order gives us strong {leverage}.','대량 주문이 우리에게 강한 협상력을 줘요.','leverage','B1','negotiation',1,'leverage power advantage business strategy'),
('w_negotiation_B1_05','counterproposal','/ˌkaʊntərprəˈpəʊzəl/','noun','역제안','An offer made in response to one that is unacceptable.','They submitted a {counterproposal} the next day.','그들은 다음 날 역제안을 제출했어요.','counterproposal','B1','negotiation',1,'counter offer response proposal meeting'),
('w_negotiation_B1_06','deadline','/ˈdedlaɪn/','noun','마감일','The latest time by which something must be finished.','The contract {deadline} is the end of this month.','계약 마감일은 이번 달 말이에요.','deadline','B1','negotiation',1,'deadline calendar clock urgency date'),
('w_negotiation_B1_07','stakeholder','/ˈsteɪkhəʊldər/','noun','이해관계자','A person with an interest or concern in a project.','All {stakeholders} must approve the final terms.','모든 이해관계자가 최종 조건을 승인해야 해요.','stakeholder','B1','negotiation',1,'stakeholder group meeting board approval'),
('w_negotiation_B1_08','agenda','/əˈdʒendə/','noun','의제, 안건','A list of matters to be discussed at a meeting.','Let''s stick to the {agenda} and focus on pricing.','의제를 지키고 가격에 집중해요.','agenda','B1','negotiation',1,'agenda meeting list discussion items'),
('w_negotiation_B1_09','clause','/klɔːz/','noun','조항','A particular section or condition in a contract.','The penalty {clause} needs to be revised.','위약금 조항을 수정해야 해요.','clause','B1','negotiation',1,'clause contract legal document section'),
('w_negotiation_B1_10','binding','/ˈbaɪndɪŋ/','adjective','법적 구속력이 있는','Legally required to be carried out.','Once signed, this agreement is {binding} on both parties.','서명 후, 이 계약은 양 당사자에게 법적 구속력이 생겨요.','binding','B1','negotiation',1,'binding contract legal signature document'),
('w_negotiation_B1_11','mutual','/ˈmjuːtʃuəl/','adjective','상호의','Felt or done by two parties equally.','We need to reach a {mutual} understanding first.','먼저 상호 이해에 도달해야 해요.','mutual','B1','negotiation',1,'mutual agreement both sides understanding'),
('w_negotiation_B1_12','transparent','/trænsˈpærənt/','adjective','투명한','Open and honest; not hiding anything.','Please be {transparent} about all associated costs.','모든 관련 비용에 대해 투명하게 밝혀주세요.','transparent','B1','negotiation',1,'transparent honesty glass clear open'),
('w_negotiation_B1_13','position','/pəˈzɪʃən/','noun','입장, 포지션','A viewpoint or stance in a discussion.','Our {position} is firm on the minimum quantity.','최소 수량에 대한 우리의 입장은 확고해요.','position','B1','negotiation',1,'position stance viewpoint discussion negotiation'),
('w_negotiation_B1_14','alternative','/ɔːlˈtɜːnətɪv/','noun','대안','A different or new choice.','Is there an {alternative} to the current plan?','현재 계획에 대한 대안이 있나요?','alternative','B1','negotiation',1,'alternative option choice path direction'),
('w_negotiation_B1_15','penalty','/ˈpenəlti/','noun','위약금, 벌칙','A punishment for breaking a rule or contract.','There is a 10% {penalty} for late delivery.','납품 지연 시 10% 위약금이 있어요.','penalty','B1','negotiation',1,'penalty fine clause contract legal'),
('w_negotiation_B1_16','objective','/əbˈdʒektɪv/','noun','목표, 목적','A goal or aim to be achieved.','Our main {objective} is to reduce total cost.','우리의 주요 목표는 총 비용을 줄이는 것이에요.','objective','B1','negotiation',2,'objective goal target planning strategy'),
('w_negotiation_B1_17','priority','/praɪˈɒrɪti/','noun','우선순위','The level of importance given to something.','Price is our top {priority} in this deal.','가격이 이 거래에서 우리의 최우선순위예요.','priority','B1','negotiation',1,'priority ranking importance list order'),
('w_negotiation_B1_18','revision','/rɪˈvɪʒən/','noun','수정, 개정','An amended version of something.','We submitted a {revision} of the original draft.','원본 초안의 수정본을 제출했어요.','revision','B1','negotiation',2,'revision edit document update change'),
('w_negotiation_B1_19','finalize','/ˈfaɪnəlaɪz/','verb','마무리하다','To complete or settle a plan or agreement.','We hope to {finalize} the deal by Friday.','금요일까지 거래를 마무리하길 바라요.','finalize','B1','negotiation',1,'finalize complete done stamp approval'),
('w_negotiation_B1_20','dispute','/dɪˈspjuːt/','noun','분쟁','A disagreement or argument between parties.','A {dispute} over payment terms caused delays.','지불 조건에 관한 분쟁이 지연을 야기했어요.','dispute','B1','negotiation',1,'dispute disagreement conflict resolution'),
('w_negotiation_B1_21','proposal','/prəˈpəʊzəl/','noun','제안서','A formal plan or suggestion.','Please read our {proposal} before the meeting.','회의 전에 우리 제안서를 읽어주세요.','proposal','B1','negotiation',1,'proposal document presentation business plan'),
('w_negotiation_B1_22','timeline','/ˈtaɪmlaɪn/','noun','일정표, 타임라인','A schedule showing events in order of time.','The project {timeline} needs to be agreed upon.','프로젝트 타임라인에 합의해야 해요.','timeline','B1','negotiation',2,'timeline schedule project management chart'),
('w_negotiation_B1_23','scope','/skəʊp/','noun','범위, 영역','The range or extent of something.','We need to define the {scope} of the project first.','먼저 프로젝트의 범위를 정의해야 해요.','scope','B1','negotiation',2,'scope range boundary definition project'),
('w_negotiation_B1_24','approve','/əˈpruːv/','verb','승인하다','To officially agree to something.','The board will {approve} the contract next week.','이사회가 다음 주에 계약을 승인할 거예요.','approve','B1','negotiation',1,'approve signature stamp official decision'),
('w_negotiation_B1_25','negotiate down','/nɪˈɡəʊʃieɪt daʊn/','phrase','가격을 낮추다','To successfully reduce a price through discussion.','We managed to {negotiate down} the setup fee.','설치 비용을 낮추는 데 성공했어요.','negotiate down','B1','negotiation',2,'price reduction negotiation bargain lower'),
('w_negotiation_B1_26','obligation','/ˌɒblɪˈɡeɪʃən/','noun','의무','A duty or commitment required by a contract.','Both parties have clear {obligations} under this deal.','양 당사자는 이 거래에서 명확한 의무가 있어요.','obligation','B1','negotiation',1,'obligation duty responsibility commitment'),
('w_negotiation_B1_27','benchmark','/ˈbentʃmɑːk/','noun','기준, 벤치마크','A standard to compare against when evaluating something.','Let''s use the market rate as a {benchmark}.','시장 가격을 기준으로 삼아요.','benchmark','B1','negotiation',2,'benchmark standard comparison market analysis'),
('w_negotiation_B1_28','volume','/ˈvɒljuːm/','noun','물량, 규모','The amount or quantity of something.','Higher {volume} orders qualify for a bigger discount.','더 큰 물량 주문은 더 큰 할인 자격이 돼요.','volume','B1','negotiation',1,'volume quantity bulk order warehouse'),
('w_negotiation_B1_29','in writing','/ɪn ˈraɪtɪŋ/','phrase','서면으로','Recorded as a written document.','All changes must be confirmed {in writing}.','모든 변경 사항은 서면으로 확인해야 해요.','in writing','B1','negotiation',1,'writing document formal letter official'),
('w_negotiation_B1_30','exclusive','/ɪkˈskluːsɪv/','adjective','독점적인','Restricted to a single entity; not shared.','We want an {exclusive} distribution agreement.','독점 유통 계약을 원해요.','exclusive','B1','negotiation',2,'exclusive VIP premium restricted access'),
('w_negotiation_B1_31','minimum','/ˈmɪnɪməm/','noun','최소','The smallest amount or level possible.','The {minimum} order is five hundred units.','최소 주문은 500개예요.','minimum','B1','negotiation',2,'minimum baseline floor limit quantity'),
('w_negotiation_B1_32','extension','/ɪkˈstenʃən/','noun','연장','An increase in the length of time allowed.','We need a two-week {extension} on the deadline.','마감일을 2주 연장해야 해요.','extension','B1','negotiation',2,'extension time deadline extra period calendar'),
('w_negotiation_B1_33','headroom','/ˈhedrʊm/','noun','협상 여지','Room or space available for negotiation or movement.','There is very little {headroom} left on the price.','가격에 협상 여지가 거의 없어요.','headroom','B1','negotiation',2,'space room margin flexibility negotiation'),
('w_negotiation_B1_34','walk away','/wɔːk əˈweɪ/','phrase','협상에서 물러나다','To leave a negotiation without reaching agreement.','We are prepared to {walk away} if terms worsen.','조건이 나빠지면 물러날 준비가 돼 있어요.','walk away','B1','negotiation',1,'walk away exit leave negotiation table'),
('w_negotiation_B1_35','penalty clause','/ˈpenəlti klɔːz/','phrase','위약금 조항','A clause specifying punishment for failing obligations.','The {penalty clause} protects both parties.','위약금 조항은 양 당사자를 보호해요.','penalty clause','B1','negotiation',1,'penalty clause contract protection legal');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_negotiation_B2_01','arbitration','/ˌɑːbɪˈtreɪʃən/','noun','중재','A method of resolving disputes outside the courts.','The contract includes an {arbitration} clause.','계약서에 중재 조항이 포함돼 있어요.','arbitration','B2','negotiation',1,'arbitration mediation dispute resolution legal'),
('w_negotiation_B2_02','mediation','/ˌmiːdiˈeɪʃən/','noun','조정, 중재','Intervention to settle a dispute between parties.','{Mediation} is often faster than litigation.','조정은 소송보다 종종 빠릅니다.','mediation','B2','negotiation',1,'mediation neutral third party dispute settlement'),
('w_negotiation_B2_03','litigation','/ˌlɪtɪˈɡeɪʃən/','noun','소송','The process of taking legal action in court.','We want to avoid {litigation} at all costs.','어떤 대가를 치르더라도 소송을 피하고 싶어요.','litigation','B2','negotiation',1,'litigation court lawsuit legal process judge'),
('w_negotiation_B2_04','liability','/ˌlaɪəˈbɪlɪti/','noun','책임, 배상 책임','Legal responsibility for something, especially damage or debt.','The contract limits our {liability} to direct damages.','계약은 우리의 책임을 직접 손해로 제한해요.','liability','B2','negotiation',1,'liability responsibility legal risk insurance'),
('w_negotiation_B2_05','indemnity','/ɪnˈdemnɪti/','noun','보상, 면책','Compensation for harm or loss; exemption from liability.','We require full {indemnity} against third-party claims.','제3자 청구에 대한 완전한 면책이 필요해요.','indemnity','B2','negotiation',1,'indemnity compensation protection insurance contract'),
('w_negotiation_B2_06','warranty','/ˈwɒrənti/','noun','보증, 품질보증','A written guarantee for the quality of a product.','The equipment comes with a two-year {warranty}.','장비에는 2년 보증이 포함돼 있어요.','warranty','B2','negotiation',1,'warranty guarantee certificate product quality'),
('w_negotiation_B2_07','escrow','/ˈeskrəʊ/','noun','에스크로 (제3자 보관)','Money held by a third party until conditions are met.','Payment will be held in {escrow} until delivery.','배송될 때까지 지불금은 에스크로에 보관돼요.','escrow','B2','negotiation',1,'escrow third party trust account secure payment'),
('w_negotiation_B2_08','contingency','/kənˈtɪndʒənsi/','noun','예비 조항, 우발 상황','A provision for a possible future event or circumstance.','Add a {contingency} clause for force majeure events.','불가항력 사태에 대한 예비 조항을 추가해요.','contingency','B2','negotiation',1,'contingency plan backup risk management scenario'),
('w_negotiation_B2_09','ratify','/ˈrætɪfaɪ/','verb','비준하다, 공식 승인하다','To formally confirm or approve a contract.','Both boards must {ratify} the agreement.','양 이사회가 합의를 공식 승인해야 해요.','ratify','B2','negotiation',1,'ratify approve formal sign official stamp'),
('w_negotiation_B2_10','void','/vɔɪd/','adjective','무효인','Not legally binding or enforceable.','A contract signed under duress may be {void}.','강요 하에 서명된 계약은 무효일 수 있어요.','void','B2','negotiation',1,'void invalid null cancelled contract legal'),
('w_negotiation_B2_11','force majeure','/ˌfɔːs mæˈʒɜːr/','noun','불가항력','Unforeseeable circumstances preventing contract fulfilment.','The flood triggered the {force majeure} clause.','홍수로 인해 불가항력 조항이 발동됐어요.','force majeure','B2','negotiation',1,'force majeure disaster unpredictable event clause'),
('w_negotiation_B2_12','confidentiality','/ˌkɒnfɪˌdenʃiˈælɪti/','noun','기밀성','The state of keeping information secret.','Both parties must sign a {confidentiality} agreement.','양 당사자는 기밀 유지 계약에 서명해야 해요.','confidentiality','B2','negotiation',1,'confidentiality NDA secret agreement privacy'),
('w_negotiation_B2_13','jurisdiction','/ˌdʒʊərɪsˈdɪkʃən/','noun','관할권','The authority of a court or territory to hear a legal case.','This contract falls under Korean {jurisdiction}.','이 계약은 한국 관할권에 속해요.','jurisdiction','B2','negotiation',1,'jurisdiction court authority territory legal system'),
('w_negotiation_B2_14','amendment','/əˈmendmənt/','noun','수정안','A formal change made to a document or law.','We propose an {amendment} to the payment schedule.','지불 일정에 대한 수정안을 제안해요.','amendment','B2','negotiation',1,'amendment change revision document formal'),
('w_negotiation_B2_15','breach','/briːtʃ/','noun','위반','A failure to keep a contract or obligation.','Late delivery constitutes a {breach} of contract.','납품 지연은 계약 위반에 해당해요.','breach','B2','negotiation',1,'breach violation contract failure legal'),
('w_negotiation_B2_16','enforceable','/ɪnˈfɔːrsəbəl/','adjective','집행 가능한','Capable of being legally put into effect.','The clause is only {enforceable} if notarized.','조항은 공증된 경우에만 집행 가능해요.','enforceable','B2','negotiation',2,'enforceable legal binding official court'),
('w_negotiation_B2_17','non-disclosure','/nɒn dɪsˈkləʊʒər/','noun','비공개, 비밀 유지','The action of not revealing confidential information.','Sign the {non-disclosure} agreement before the demo.','데모 전에 비밀 유지 계약서에 서명해주세요.','non-disclosure','B2','negotiation',1,'non-disclosure NDA secret confidential agreement'),
('w_negotiation_B2_18','indemnify','/ɪnˈdemnɪfaɪ/','verb','면책하다, 보상하다','To compensate for harm or protect against legal liability.','We agree to {indemnify} you against all claims.','모든 청구에 대해 면책해 드리기로 동의해요.','indemnify','B2','negotiation',1,'indemnify compensate protect legal insurance'),
('w_negotiation_B2_19','milestone','/ˈmaɪlstəʊn/','noun','이정표, 중요 단계','A significant point in the development of something.','Payment is tied to each project {milestone}.','지불은 각 프로젝트 이정표에 연동돼요.','milestone','B2','negotiation',2,'milestone progress achievement project completion'),
('w_negotiation_B2_20','exclusivity','/ˌɪkskluːˈsɪvɪti/','noun','독점권','The state of being available to only one party.','We request {exclusivity} in the Korean market.','한국 시장에서의 독점권을 요청해요.','exclusivity','B2','negotiation',1,'exclusivity exclusive rights territory market'),
('w_negotiation_B2_21','termination','/ˌtɜːrmɪˈneɪʃən/','noun','해지, 종료','The ending of a contract or agreement.','Either party may trigger {termination} with notice.','어느 쪽이든 통보로 해지를 개시할 수 있어요.','termination','B2','negotiation',1,'termination end contract closure notice period'),
('w_negotiation_B2_22','representation','/ˌreprɪzenˈteɪʃən/','noun','진술, 대리','A statement made to induce someone to enter a contract.','Their {representations} proved to be inaccurate.','그들의 진술이 부정확한 것으로 드러났어요.','representation','B2','negotiation',2,'representation statement legal contract claim'),
('w_negotiation_B2_23','due diligence','/djuː ˈdɪlɪdʒəns/','noun','실사, 적법한 조사','A thorough investigation before signing a contract.','We will conduct {due diligence} over two weeks.','2주 동안 실사를 진행할 거예요.','due diligence','B2','negotiation',1,'due diligence investigation research audit legal'),
('w_negotiation_B2_24','indemnification','/ɪnˌdemnɪfɪˈkeɪʃən/','noun','손해 배상, 면책','The act of providing compensation for loss or damage.','The {indemnification} clause covers third-party claims.','면책 조항은 제3자 청구를 포함해요.','indemnification','B2','negotiation',1,'indemnification clause protection legal compensation'),
('w_negotiation_B2_25','governing law','/ˈɡʌvənɪŋ lɔː/','noun','준거법','The law that governs the interpretation of a contract.','The {governing law} for this contract is English law.','이 계약의 준거법은 영국법이에요.','governing law','B2','negotiation',1,'governing law jurisdiction legal contract'),
('w_negotiation_B2_26','consideration','/kənˌsɪdəˈreɪʃən/','noun','대가, 약인','Something of value exchanged to make a contract valid.','Adequate {consideration} is required for a valid contract.','유효한 계약에는 적절한 대가가 필요해요.','consideration','B2','negotiation',1,'consideration value exchange contract legal'),
('w_negotiation_B2_27','severability','/sɪˌverəˈbɪlɪti/','noun','분리 가능성 조항','A clause allowing invalid parts to be removed without voiding the rest.','The {severability} clause preserves the rest of the contract.','분리 가능성 조항이 계약의 나머지를 보존해요.','severability','B2','negotiation',2,'severability clause contract legal preserve'),
('w_negotiation_B2_28','performance bond','/pəˈfɔːməns bɒnd/','noun','이행 보증금','A guarantee that a party will fulfil its obligations.','The contractor posted a {performance bond}.','계약자가 이행 보증금을 예치했어요.','performance bond','B2','negotiation',2,'performance bond guarantee security contract'),
('w_negotiation_B2_29','good faith','/ɡʊd feɪθ/','noun','선의','Honest intention to deal fairly.','Both parties must act in {good faith}.','양 당사자는 선의로 행동해야 해요.','good faith','B2','negotiation',1,'good faith honesty trust cooperation fairness'),
('w_negotiation_B2_30','material breach','/məˈtɪəriəl briːtʃ/','noun','중대 위반','A serious failure to fulfil contractual obligations.','Late payment beyond 60 days is a {material breach}.','60일 초과 연체는 중대 위반이에요.','material breach','B2','negotiation',1,'material breach serious violation contract legal'),
('w_negotiation_B2_31','counterpart','/ˈkaʊntəpɑːt/','noun','거래 상대방','A person or thing with the same role on the other side.','Our legal team contacted their {counterpart}.','우리 법무팀이 상대방 법무팀에 연락했어요.','counterpart','B2','negotiation',2,'counterpart opposite side partner negotiation'),
('w_negotiation_B2_32','waiver','/ˈweɪvər/','noun','권리 포기','The act of voluntarily giving up a right.','Signing this form is a {waiver} of your claim.','이 양식에 서명하면 청구권을 포기하는 거예요.','waiver','B2','negotiation',1,'waiver relinquish right legal form signature'),
('w_negotiation_B2_33','retention','/rɪˈtenʃən/','noun','유보금, 보류','A sum withheld until work is satisfactorily completed.','A 10% {retention} is held until project handover.','프로젝트 인계까지 10% 유보금이 보류돼요.','retention','B2','negotiation',2,'retention holdback payment completion handover'),
('w_negotiation_B2_34','price cap','/praɪs kæp/','noun','가격 상한','A maximum price set by agreement or regulation.','The contract includes a {price cap} clause.','계약서에 가격 상한 조항이 포함돼 있어요.','price cap','B2','negotiation',2,'price cap maximum ceiling limit contract'),
('w_negotiation_B2_35','liquidated damages','/ˈlɪkwɪdeɪtɪd ˈdæmɪdʒɪz/','noun','손해배상 예정액','A pre-agreed sum payable if a party breaches a contract.','The contract specifies {liquidated damages} of 1% per day.','계약서에 하루 1%의 손해배상 예정액이 명시돼 있어요.','liquidated damages','B2','negotiation',1,'liquidated damages penalty contract legal fine');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_negotiation_C1_01','fiduciary','/fɪˈdjuːʃəri/','adjective','신탁의, 수탁자의','Relating to the trust placed in a person to manage assets.','The trustee owes {fiduciary} duties to beneficiaries.','수탁자는 수익자에게 신탁 의무를 집니다.','fiduciary','C1','negotiation',1,'fiduciary trust duty legal obligation finance'),
('w_negotiation_C1_02','subrogation','/ˌsʌbrəˈɡeɪʃən/','noun','대위변제','The substitution of one party for another in a legal claim.','After paying the claim, the insurer pursued {subrogation}.','청구를 지급한 후 보험사는 대위변제를 추구했어요.','subrogation','C1','negotiation',1,'subrogation insurance legal claim substitution'),
('w_negotiation_C1_03','indemnification','/ɪnˌdemnɪfɪˈkeɪʃən/','noun','손해 배상 계약','A contractual obligation to compensate another for losses.','The {indemnification} provision covers all legal costs.','손해 배상 조항은 모든 법적 비용을 포함해요.','indemnification','C1','negotiation',1,'indemnification legal contract protect compensation clause'),
('w_negotiation_C1_04','covenant','/ˈkʌvənənt/','noun','약정, 서약 조항','A formal agreement or promise, especially in a contract.','The non-compete {covenant} lasts for two years.','경쟁 금지 약정은 2년간 지속돼요.','covenant','C1','negotiation',1,'covenant promise agreement contract restriction'),
('w_negotiation_C1_05','lien','/liːn/','noun','유치권, 담보권','A right to keep possession of property until a debt is paid.','The bank holds a {lien} over the property.','은행이 그 부동산에 유치권을 보유하고 있어요.','lien','C1','negotiation',1,'lien property claim bank security debt'),
('w_negotiation_C1_06','injunction','/ɪnˈdʒʌŋkʃən/','noun','금지 명령','A court order requiring a party to do or stop something.','We sought an {injunction} to halt the project.','프로젝트를 중단시키기 위해 금지 명령을 구했어요.','injunction','C1','negotiation',1,'injunction court order legal halt stop'),
('w_negotiation_C1_07','breach','/briːtʃ/','noun','위반 (고급)','Failure to fulfil a contractual or legal obligation.','The supplier''s delay was a clear {breach} of contract.','공급업체의 지연은 명백한 계약 위반이었어요.','breach','C1','negotiation',1,'breach violation legal failure contract consequence'),
('w_negotiation_C1_08','remedy','/ˈremədi/','noun','구제책','A means of obtaining redress for a legal wrong.','Damages are the most common {remedy} for breach.','손해배상이 위반에 대한 가장 일반적인 구제책이에요.','remedy','C1','negotiation',1,'remedy solution legal redress compensation contract'),
('w_negotiation_C1_09','jurisdiction','/ˌdʒʊərɪsˈdɪkʃən/','noun','관할권 (고급)','The official power to make legal decisions for an area.','Disputes are subject to Singapore {jurisdiction}.','분쟁은 싱가포르 관할권에 따라요.','jurisdiction','C1','negotiation',1,'jurisdiction court legal authority territory law'),
('w_negotiation_C1_10','tortious','/ˈtɔːʃəs/','adjective','불법 행위의','Constituting a civil wrong giving rise to liability.','The company faced a {tortious} interference claim.','회사는 불법 행위 간섭 청구에 직면했어요.','tortious','C1','negotiation',1,'tort civil wrong liability legal claim'),
('w_negotiation_C1_11','privity','/ˈprɪvɪti/','noun','계약 당사자 관계','The direct legal relationship between contracting parties.','A third party has no rights due to lack of {privity}.','제3자는 계약 당사자 관계가 없어 권리가 없어요.','privity','C1','negotiation',1,'privity contract relationship parties direct'),
('w_negotiation_C1_12','estoppel','/ɪˈstɒpəl/','noun','금반언','A legal principle preventing a person from contradicting a previous statement.','The court applied {estoppel} to prevent the claim.','법원은 청구를 막기 위해 금반언을 적용했어요.','estoppel','C1','negotiation',1,'estoppel legal principle contradiction consistency court'),
('w_negotiation_C1_13','rescission','/rɪˈsɪʃən/','noun','계약 해제','The cancellation of a contract, restoring parties to original positions.','{Rescission} was granted due to misrepresentation.','허위 진술로 인해 계약 해제가 허용됐어요.','rescission','C1','negotiation',1,'rescission cancel contract restore original legal'),
('w_negotiation_C1_14','novation','/nəʊˈveɪʃən/','noun','계약 갱신, 채무 교체','The substitution of a new obligation for an old one.','{Novation} transferred all duties to the acquiring company.','계약 갱신으로 모든 의무가 인수 기업에 이전됐어요.','novation','C1','negotiation',1,'novation substitute new contract obligation transfer'),
('w_negotiation_C1_15','promissory','/ˈprɒmɪsəri/','adjective','약속의, 약속 어음의','Conveying or implying a promise.','A {promissory} note is evidence of a debt obligation.','약속 어음은 채무 의무의 증거예요.','promissory','C1','negotiation',1,'promissory note promise debt document finance'),
('w_negotiation_C1_16','executory','/ɪɡˈzekjʊtəri/','adjective','미이행의, 실행 중인','Not yet fully performed; remaining to be carried out.','Both parties still have {executory} obligations.','양 당사자에게 아직 미이행 의무가 있어요.','executory','C1','negotiation',1,'executory contract obligations pending performance'),
('w_negotiation_C1_17','liquidated','/ˈlɪkwɪdeɪtɪd/','adjective','확정된, 산정된','Settled or agreed upon in advance, as damages.','The parties agreed on {liquidated} damages of $500 per day.','당사자들은 하루 500달러의 확정 손해배상에 합의했어요.','liquidated','C1','negotiation',2,'liquidated damages fixed amount contract penalty'),
('w_negotiation_C1_18','specific performance','/spɪˈsɪfɪk pəˈfɔːməns/','noun','특정 이행','A court order requiring a party to perform contractual duties.','The buyer sought {specific performance} of the sale contract.','매수인은 매매 계약의 특정 이행을 구했어요.','specific performance','C1','negotiation',1,'specific performance court order fulfill obligation contract'),
('w_negotiation_C1_19','frustration','/frʌˈstreɪʃən/','noun','계약 이행 불능','The termination of a contract due to an unforeseen event.','{Frustration} of contract discharged both parties.','계약 이행 불능으로 양 당사자가 면제됐어요.','frustration','C1','negotiation',1,'frustration contract discharge impossible event legal'),
('w_negotiation_C1_20','implied term','/ɪmˈplaɪd tɜːm/','noun','묵시적 조항','A term not expressly stated but incorporated by law or custom.','An {implied term} of fitness for purpose applies.','목적 적합성의 묵시적 조항이 적용돼요.','implied term','C1','negotiation',2,'implied term contract unwritten law custom'),
('w_negotiation_C1_21','exculpatory clause','/ɪkˈskʌlpətəri klɔːz/','noun','면책 조항','A clause releasing a party from liability.','The {exculpatory clause} was deemed unenforceable.','면책 조항이 집행 불가능한 것으로 판단됐어요.','exculpatory clause','C1','negotiation',2,'exculpatory exemption liability clause contract'),
('w_negotiation_C1_22','assignment','/əˈsaɪnmənt/','noun','양도','Transfer of rights or obligations to a third party.','The contract prohibits {assignment} without consent.','계약은 동의 없는 양도를 금지해요.','assignment','C1','negotiation',1,'assignment transfer rights contract third party'),
('w_negotiation_C1_23','acceleration clause','/əkˌseləˈreɪʃən klɔːz/','noun','기한 이익 상실 조항','A clause making an entire debt payable immediately if a condition is breached.','Default triggers the {acceleration clause}.','채무불이행은 기한 이익 상실 조항을 발동시켜요.','acceleration clause','C1','negotiation',2,'acceleration clause immediate payment default contract'),
('w_negotiation_C1_24','indemnity cap','/ɪnˈdemnɪti kæp/','noun','배상 한도액','The maximum amount payable under an indemnity.','The {indemnity cap} is set at the contract value.','배상 한도액은 계약 금액으로 설정돼요.','indemnity cap','C1','negotiation',2,'indemnity cap maximum liability limit contract'),
('w_negotiation_C1_25','consequential loss','/kənˌsekwənʃəl lɒs/','noun','간접 손해','Loss that is a secondary result of a breach.','The contract excludes liability for {consequential loss}.','계약은 간접 손해에 대한 책임을 배제해요.','consequential loss','C1','negotiation',2,'consequential indirect loss contract exclusion legal'),
('w_negotiation_C1_26','set-off','/set ɒf/','noun','상계','The right to offset a debt against a counterclaim.','The client exercised its right of {set-off}.','의뢰인이 상계권을 행사했어요.','set-off','C1','negotiation',2,'set off offset debt counterclaim legal finance'),
('w_negotiation_C1_27','retention of title','/rɪˈtenʃən əv ˈtaɪtəl/','noun','소유권 유보','A clause keeping ownership with the seller until payment.','The {retention of title} clause protects the supplier.','소유권 유보 조항이 공급업체를 보호해요.','retention of title','C1','negotiation',1,'retention title ownership unpaid goods clause'),
('w_negotiation_C1_28','entire agreement clause','/ɪnˈtaɪər əˈɡriːmənt klɔːz/','noun','전체 합의 조항','A clause stating the contract is the complete agreement.','The {entire agreement clause} supersedes prior discussions.','전체 합의 조항이 이전 논의를 대체해요.','entire agreement clause','C1','negotiation',2,'entire agreement clause merger integration contract'),
('w_negotiation_C1_29','non-compete','/nɒn kəmˈpiːt/','adjective','경쟁 금지의','Restricting a party from engaging in competing activities.','The {non-compete} clause runs for 18 months post-contract.','경쟁 금지 조항은 계약 후 18개월간 적용돼요.','non-compete','C1','negotiation',1,'non-compete restriction competition clause contract'),
('w_negotiation_C1_30','step-in rights','/step ɪn raɪts/','noun','직접 이행권','The right to take over a contract from a defaulting party.','The lender exercised its {step-in rights}.','대출자가 직접 이행권을 행사했어요.','step-in rights','C1','negotiation',2,'step-in intervention take over default contractor'),
('w_negotiation_C1_31','conditions precedent','/kənˈdɪʃənz ˈpresɪdənt/','noun','선행 조건','Conditions that must be satisfied before a contract takes effect.','All {conditions precedent} must be met by closing.','모든 선행 조건은 클로징 전에 충족돼야 해요.','conditions precedent','C1','negotiation',1,'conditions precedent closing requirements contract effective'),
('w_negotiation_C1_32','variation order','/ˌveəriˈeɪʃən ˈɔːdər/','noun','변경 명령서','A formal instruction to alter the scope of work.','Each {variation order} must be approved in writing.','각 변경 명령서는 서면으로 승인돼야 해요.','variation order','C1','negotiation',2,'variation order change scope work construction'),
('w_negotiation_C1_33','contra proferentem','/ˌkɒntrə prəˈferəntem/','noun','불명확 조항의 제안자 불리 해석','The rule that ambiguous terms are read against the drafter.','The court applied {contra proferentem} to the clause.','법원은 해당 조항에 제안자 불리 원칙을 적용했어요.','contra proferentem','C1','negotiation',2,'ambiguous clause interpretation drafter legal principle'),
('w_negotiation_C1_34','force majeure clause','/ˌfɔːs mæˈʒɜːr klɔːz/','noun','불가항력 조항','A contract provision excusing non-performance due to extraordinary events.','The {force majeure clause} was invoked during the supply crisis.','공급 위기 동안 불가항력 조항이 발동됐어요.','force majeure clause','C1','negotiation',1,'force majeure clause contract disaster extraordinary event'),
('w_negotiation_C1_35','duty of care','/ˈdjuːti əv keər/','noun','주의 의무','A legal obligation to avoid acts likely to cause harm.','The advisor breached her {duty of care} to the client.','어드바이저가 의뢰인에 대한 주의 의무를 위반했어요.','duty of care','C1','negotiation',1,'duty of care negligence obligation standard professional');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_negotiation_C2_01','estoppel','/ɪˈstɒpəl/','noun','금반언의 원칙','A doctrine preventing a party from denying a previously asserted fact.','The court invoked {estoppel} to bar the defendant''s claim.','법원은 피고의 청구를 막기 위해 금반언을 발동했어요.','estoppel','C2','negotiation',1,'estoppel legal doctrine bar claim court principle'),
('w_negotiation_C2_02','novation','/nəʊˈveɪʃən/','noun','채무 인수, 계약 갱신','The act of replacing an old obligation with a new one, discharging the original party.','Through {novation}, the assignee assumed all liabilities.','계약 갱신을 통해 양수인이 모든 부채를 인수했어요.','novation','C2','negotiation',1,'novation contract replace obligation discharge legal'),
('w_negotiation_C2_03','rescission','/rɪˈsɪʃən/','noun','계약 취소','The cancellation of a contract and restoration of parties to their original state.','Fraudulent misrepresentation led to {rescission} of the agreement.','사기적 허위 진술이 계약 취소로 이어졌어요.','rescission','C2','negotiation',1,'rescission cancel contract restore legal fraud'),
('w_negotiation_C2_04','quantum meruit','/ˌkwɒntəm ˈmɛruːɪt/','noun','정당한 보수 청구권','A claim for reasonable payment for services rendered where no price was fixed.','The contractor claimed {quantum meruit} for completed work.','계약자가 완료된 작업에 대해 정당한 보수를 청구했어요.','quantum meruit','C2','negotiation',1,'quantum meruit payment services reasonable legal claim'),
('w_negotiation_C2_05','tortious','/ˈtɔːʃəs/','adjective','불법 행위를 구성하는','Of the nature of a tort; giving rise to civil liability.','The conduct was deemed {tortious} interference with business.','그 행위는 영업에 대한 불법 행위 간섭으로 판단됐어요.','tortious','C2','negotiation',1,'tortious tort civil wrong liability interference business'),
('w_negotiation_C2_06','mens rea','/menz ˈriːə/','noun','범의 (형사 책임의 주관적 요소)','The mental element of criminal intent required to convict.','Prosecutors must prove {mens rea} beyond reasonable doubt.','검사는 합리적 의심 없이 범의를 입증해야 해요.','mens rea','C2','negotiation',1,'mens rea criminal intent mental element law prosecution'),
('w_negotiation_C2_07','actus reus','/ˌæktəs ˈriːəs/','noun','범죄 행위 (형사 책임의 객관적 요소)','The physical act forming the objective element of a crime.','The {actus reus} of theft was confirmed by CCTV.','절도의 범죄 행위는 CCTV로 확인됐어요.','actus reus','C2','negotiation',1,'actus reus physical act crime element evidence'),
('w_negotiation_C2_08','promissory estoppel','/ˈprɒmɪsəri ɪˈstɒpəl/','noun','약속적 금반언','A doctrine preventing a party from going back on a clear promise relied upon.','The court applied {promissory estoppel} to enforce the promise.','법원은 약속을 집행하기 위해 약속적 금반언을 적용했어요.','promissory estoppel','C2','negotiation',1,'promissory estoppel promise enforce reliance legal doctrine'),
('w_negotiation_C2_09','executory contract','/ɪɡˈzekjʊtəri ˈkɒntrækt/','noun','미이행 계약','A contract where obligations on both sides are yet to be performed.','The acquisition included several {executory contracts}.','인수에는 여러 미이행 계약이 포함됐어요.','executory contract','C2','negotiation',1,'executory contract unperformed obligations pending legal'),
('w_negotiation_C2_10','liquidated damages','/ˈlɪkwɪdeɪtɪd ˈdæmɪdʒɪz/','noun','약정 손해배상액','A pre-agreed sum specified in a contract as compensation for breach.','The {liquidated damages} clause set $1,000 per day of delay.','약정 손해배상액 조항은 지연 하루당 1,000달러로 설정됐어요.','liquidated damages','C2','negotiation',1,'liquidated damages penalty breach contract pre-agreed fine'),
('w_negotiation_C2_11','unjust enrichment','/ʌnˈdʒʌst ɪnˈrɪtʃmənt/','noun','부당 이득','The unfair benefit received at another party''s expense.','The claim was based on {unjust enrichment} principles.','청구는 부당 이득 원칙에 근거했어요.','unjust enrichment','C2','negotiation',1,'unjust enrichment unfair benefit legal restitution claim'),
('w_negotiation_C2_12','restitution','/ˌrestɪˈtjuːʃən/','noun','원상 회복, 반환','Restoration of something lost or payment for damage caused.','The court ordered full {restitution} of amounts paid.','법원은 지불된 금액의 전액 반환을 명령했어요.','restitution','C2','negotiation',1,'restitution restore return payment legal remedy'),
('w_negotiation_C2_13','nemo dat','/ˌniːməʊ ˈdæt/','noun','권리 이전 불가 원칙','The principle that one cannot transfer greater rights than one possesses.','The {nemo dat} rule voided the buyer''s claim to title.','권리 이전 불가 원칙이 매수인의 소유권 청구를 무효로 했어요.','nemo dat','C2','negotiation',1,'nemo dat title transfer legal principle ownership'),
('w_negotiation_C2_14','contra proferentem','/ˌkɒntrə prəˈferəntem/','noun','작성자 불이익 해석 원칙','The rule that ambiguous contractual terms are construed against the drafter.','The judge applied {contra proferentem} to limit liability.','판사는 책임을 제한하기 위해 작성자 불이익 원칙을 적용했어요.','contra proferentem','C2','negotiation',1,'contra proferentem ambiguous clause drafter legal interpret'),
('w_negotiation_C2_15','frustration of purpose','/frʌˈstreɪʃən əv ˈpɜːpəs/','noun','목적 이행 불능','Termination of a contract when an unforeseen event defeats its main purpose.','The pandemic triggered {frustration of purpose} claims.','팬데믹이 목적 이행 불능 청구를 촉발했어요.','frustration of purpose','C2','negotiation',1,'frustration purpose contract discharge unforeseen event'),
('w_negotiation_C2_16','in pari delicto','/ɪn ˌpærɪ dɪˈlɪktəʊ/','noun','동등 과실의 원칙','A doctrine denying relief when both parties are equally at fault.','The court dismissed the claim under {in pari delicto}.','법원은 동등 과실 원칙에 따라 청구를 기각했어요.','in pari delicto','C2','negotiation',2,'equal fault doctrine legal dismiss claim court'),
('w_negotiation_C2_17','clean hands doctrine','/kliːn hændz ˈdɒktrɪn/','noun','형평법상 청결 원칙','A principle that a party seeking equitable relief must not itself be at fault.','The defendant raised the {clean hands doctrine} as a defence.','피고가 형평법상 청결 원칙을 방어로 제기했어요.','clean hands doctrine','C2','negotiation',2,'clean hands equity fairness legal doctrine defence'),
('w_negotiation_C2_18','mutuality of obligation','/mjuːˈtʃuːəlɪti əv ˌɒblɪˈɡeɪʃən/','noun','쌍방 의무','The requirement that both parties must be bound for a contract to be valid.','Lack of {mutuality of obligation} made the contract voidable.','쌍방 의무가 없어 계약이 취소 가능하게 됐어요.','mutuality of obligation','C2','negotiation',2,'mutuality obligation contract valid both parties bound'),
('w_negotiation_C2_19','champerty','/ˈtʃæmpəti/','noun','소송 지원 및 이익 분배 계약','An arrangement where a third party funds litigation in exchange for a share of proceeds.','The funding arrangement was challenged as {champerty}.','자금 조달 약정이 소송 지원 계약으로 이의 제기됐어요.','champerty','C2','negotiation',2,'champerty litigation funding third party legal share'),
('w_negotiation_C2_20','subrogation','/ˌsʌbrəˈɡeɪʃən/','noun','대위 청구권','A right allowing one party to substitute for another in a legal claim.','Insurers exercise {subrogation} rights after settling claims.','보험사는 청구를 해결한 후 대위 청구권을 행사해요.','subrogation','C2','negotiation',1,'subrogation insurance legal right substitute claim'),
('w_negotiation_C2_21','laches','/ˈlætʃɪz/','noun','권리 해태','An unreasonable delay in asserting a legal claim.','The claim was barred by {laches}.','청구가 권리 해태로 차단됐어요.','laches','C2','negotiation',1,'laches delay legal claim equity bar'),
('w_negotiation_C2_22','piercing the veil','/ˌpɪəsɪŋ ðə veɪl/','noun','법인격 부인','Treating a company and its shareholders as a single legal entity.','The court allowed {piercing the veil} to recover debts.','법원은 채무 회수를 위해 법인격 부인을 허용했어요.','piercing the veil','C2','negotiation',1,'piercing veil corporate liability shareholder legal'),
('w_negotiation_C2_23','nunc pro tunc','/nʌŋk prəʊ tʌŋk/','noun','소급 효력 명령','A court order that takes effect from an earlier date.','The judge issued a {nunc pro tunc} order to correct the record.','판사는 기록을 수정하기 위해 소급 효력 명령을 발부했어요.','nunc pro tunc','C2','negotiation',2,'nunc pro tunc retroactive court order date record'),
('w_negotiation_C2_24','ab initio','/æb ɪˈnɪtɪəʊ/','adverb','처음부터 (법적으로)','From the beginning; describing something void from the start.','The contract was void {ab initio} due to fraud.','사기로 인해 계약은 처음부터 무효였어요.','ab initio','C2','negotiation',1,'ab initio void beginning contract fraud legal'),
('w_negotiation_C2_25','economic duress','/ˌiːkəˈnɒmɪk djʊˈres/','noun','경제적 강박','Illegitimate economic pressure applied to force contract formation.','The claimant alleged {economic duress} during negotiations.','청구인은 협상 중 경제적 강박이 있었다고 주장했어요.','economic duress','C2','negotiation',1,'economic duress coercion contract voidable pressure legal'),
('w_negotiation_C2_26','affirmation','/ˌæfəˈmeɪʃən/','noun','계약 존속 선택','The act of electing to affirm a voidable contract rather than rescind it.','By continuing to perform, the buyer made an {affirmation}.','이행을 계속함으로써 매수인이 계약 존속을 선택했어요.','affirmation','C2','negotiation',2,'affirmation voidable contract choice ratify legal'),
('w_negotiation_C2_27','equitable estoppel','/ˌekwɪtəbəl ɪˈstɒpəl/','noun','형평법상 금반언','A doctrine in equity preventing a party from asserting rights inconsistent with a prior representation.','The court upheld {equitable estoppel} in favour of the tenant.','법원이 세입자에게 유리한 형평법상 금반언을 지지했어요.','equitable estoppel','C2','negotiation',1,'equitable estoppel equity representation reliance legal'),
('w_negotiation_C2_28','offer and acceptance','/ˈɒfər ənd əkˈseptəns/','noun','청약과 승낙','The two elements forming the basis of a binding contract.','Valid {offer and acceptance} occurred on the phone.','유효한 청약과 승낙이 전화로 이루어졌어요.','offer and acceptance','C2','negotiation',1,'offer acceptance contract formation legal elements'),
('w_negotiation_C2_29','rectification','/ˌrektɪfɪˈkeɪʃən/','noun','계약서 수정 (법원에 의한)','A court order correcting a written document to reflect the parties'' true intention.','The court granted {rectification} of the mistaken clause.','법원이 잘못된 조항의 수정을 허가했어요.','rectification','C2','negotiation',2,'rectification correct document intention court legal'),
('w_negotiation_C2_30','solus agreement','/ˈsəʊləs əˈɡriːmənt/','noun','독점 공급 계약','An agreement tying a party to a single supplier.','The {solus agreement} with the refinery was challenged.','정제소와의 독점 공급 계약이 이의 제기됐어요.','solus agreement','C2','negotiation',2,'solus exclusive supply tie-in agreement contract'),
('w_negotiation_C2_31','champerty and maintenance','/ˈtʃæmpəti ənd ˈmeɪntənəns/','noun','소송 지원 금지 원칙','The doctrines prohibiting improper third-party involvement in litigation.','The agreement was void for {champerty and maintenance}.','계약은 소송 지원 금지 원칙으로 무효였어요.','champerty and maintenance','C2','negotiation',2,'champerty maintenance litigation invalid public policy'),
('w_negotiation_C2_32','cy-pres','/siː ˈpreɪ/','noun','유사 목적 원칙','A doctrine applying funds to a purpose as close as possible to the original.','The court applied {cy-pres} to redirect the charitable funds.','법원은 자선 기금을 전용하기 위해 유사 목적 원칙을 적용했어요.','cy-pres','C2','negotiation',2,'cy-pres trust fund redirect charitable purpose legal'),
('w_negotiation_C2_33','non est factum','/nɒn est ˈfæktəm/','noun','서명 착오의 항변','A plea that a signed document was fundamentally different from what was intended.','The signatory pleaded {non est factum} to void the deed.','서명자는 증서를 무효화하기 위해 서명 착오를 주장했어요.','non est factum','C2','negotiation',2,'non est factum signed document fundamental mistake plea'),
('w_negotiation_C2_34','caveat emptor','/ˌkæviæt ˈemptɔːr/','noun','구매자 위험 부담 원칙','The principle that buyers must take care to inspect goods before purchase.','The sale was governed by {caveat emptor}.','매매는 구매자 위험 부담 원칙에 따라 이루어졌어요.','caveat emptor','C2','negotiation',1,'caveat emptor buyer beware inspection goods legal'),
('w_negotiation_C2_35','uberrimae fidei','/juːˌberɪmiː ˈfɪdɪˌaɪ/','noun','최고 선의의 원칙','The principle requiring utmost good faith, especially in insurance contracts.','Insurance contracts demand {uberrimae fidei} from both parties.','보험 계약은 양 당사자에게 최고 선의를 요구해요.','uberrimae fidei','C2','negotiation',1,'uberrimae fidei utmost good faith insurance contract legal');
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_negotiation_A1_01','Can we agree on this?','이걸로 합의할 수 있을까요?','Can we agree','합의를 제안할 때 쓰는 가장 기본적인 표현이에요.','합의 제안','A1','negotiation','pattern',NULL,1),
('s_negotiation_A1_02','I want a better price.','더 좋은 가격을 원해요.','I want','원하는 것을 직접적으로 표현할 때 써요.','가격 요청','A1','negotiation','pattern',NULL,2),
('s_negotiation_A1_03','Can you give me a discount?','할인해 주실 수 있나요?','give me a discount','할인을 요청할 때 쓰는 가장 쉬운 표현이에요.','할인 요청','A1','negotiation','pattern',NULL,3),
('s_negotiation_A1_04','I need more time to decide.','결정하는 데 시간이 더 필요해요.','I need more time','결정을 미룰 때 자연스럽게 쓸 수 있어요.','시간 요청','A1','negotiation','pattern',NULL,4),
('s_negotiation_A1_05','Is that your best offer?','그게 최선의 제안인가요?','best offer','상대방이 더 낮출 여지가 있는지 물어볼 때 써요.','최선 확인','A1','negotiation','pattern',NULL,5),
('s_negotiation_A1_06','Let''s try to work this out.','함께 해결해 보도록 해요.','Let''s try','협력적인 분위기를 만들 때 쓰는 표현이에요.','협력 제안','A1','negotiation','pattern',NULL,6),
('s_negotiation_A1_07','I think we can agree on that.','그 부분에서 합의할 수 있을 것 같아요.','I think we can agree','조심스럽게 합의 가능성을 표현해요.','합의 신호','A1','negotiation','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_negotiation_A2_01','Could you reduce the price a little?','가격을 조금 낮춰주실 수 있나요?','Could you reduce','could로 시작하면 더 공손하게 들려요.','가격 조정 요청','A2','negotiation','pattern',NULL,8),
('s_negotiation_A2_02','If you lower the price, we''ll place a bigger order.','가격을 낮춰주시면 더 많이 주문할게요.','If you lower the price','조건을 제시하며 협상하는 패턴이에요.','조건부 제안','A2','negotiation','pattern',NULL,9),
('s_negotiation_A2_03','What discount can you offer for bulk orders?','대량 주문 시 어떤 할인을 제공할 수 있나요?','discount for bulk orders','대량 구매 할인을 물어볼 때 쓰는 표현이에요.','대량 할인 요청','A2','negotiation','pattern',NULL,10),
('s_negotiation_A2_04','That''s a bit over our budget — can we meet in the middle?','예산을 조금 초과하네요. 중간 지점에서 만날 수 있을까요?','meet in the middle','타협을 부드럽게 제안하는 표현이에요.','중간 타협 제안','A2','negotiation','pattern',NULL,11),
('s_negotiation_A2_05','Can we include free shipping in the deal?','거래에 무료 배송을 포함시킬 수 있나요?','include free shipping','추가 혜택을 조건으로 요청하는 패턴이에요.','추가 조건 요청','A2','negotiation','pattern',NULL,12),
('s_negotiation_A2_06','We''d like to confirm the payment terms in writing.','지불 조건을 서면으로 확인하고 싶어요.','confirm the payment terms in writing','중요한 조건을 문서화할 때 써요.','조건 문서화','A2','negotiation','pattern',NULL,13),
('s_negotiation_A2_07','Is there any flexibility on the delivery date?','납품 날짜에 유연성이 있나요?','flexibility on the delivery date','일정 협상을 시작할 때 쓰는 표현이에요.','일정 협상','A2','negotiation','pattern',NULL,14);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_negotiation_B1_01','We''re prepared to commit to a two-year contract if you can lower the unit price.','단가를 낮춰주시면 2년 계약을 체결할 준비가 돼 있어요.','prepared to commit','장기 계약을 레버리지로 활용하는 협상 패턴이에요.','장기 계약 제안','B1','negotiation','pattern',NULL,15),
('s_negotiation_B1_02','Would you be open to a counterproposal on the delivery schedule?','납품 일정에 대한 역제안을 받아들이실 수 있나요?','open to a counterproposal','상대방의 개방성을 부드럽게 타진하는 표현이에요.','역제안 제시','B1','negotiation','pattern',NULL,16),
('s_negotiation_B1_03','Our position is that the penalty clause needs to be revised.','위약금 조항은 수정되어야 한다는 것이 우리의 입장이에요.','Our position is that','협상 입장을 명확히 표명할 때 쓰는 격식 표현이에요.','입장 표명','B1','negotiation','pattern',NULL,17),
('s_negotiation_B1_04','We can agree to that clause, provided that payment terms are extended to sixty days.','지불 기간을 60일로 연장해 주신다면 해당 조항에 동의할 수 있어요.','provided that','조건부 동의를 표현하는 핵심 패턴이에요.','조건부 동의','B1','negotiation','pattern',NULL,18),
('s_negotiation_B1_05','We have a firm deadline of the fifteenth, so we''ll need a decision by then.','15일이 확정 마감일이라 그때까지 결정이 필요해요.','firm deadline','시간적 압박을 협상 도구로 사용하는 표현이에요.','마감 압박','B1','negotiation','pattern',NULL,19),
('s_negotiation_B1_06','All stakeholders have agreed on the agenda, so let''s move to the binding clauses.','모든 이해관계자가 의제에 동의했으니 구속력 있는 조항으로 넘어가요.','All stakeholders have agreed','회의 진행을 공식적으로 전환할 때 써요.','의제 전환','B1','negotiation','pattern',NULL,20),
('s_negotiation_B1_07','If we can''t reach a compromise today, we may need to involve a mediator.','오늘 타협에 이르지 못하면 조정인을 참여시켜야 할 수도 있어요.','reach a compromise','중재를 암시해 협상 속도를 높이는 표현이에요.','중재 암시','B1','negotiation','pattern',NULL,21);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_negotiation_B2_01','The indemnity clause as drafted exposes us to unlimited liability, which we cannot accept.','현재 초안의 면책 조항은 무제한 책임을 노출시켜서 받아들일 수 없어요.','exposes us to unlimited liability','책임 범위를 구체적으로 지목하며 수정을 요구하는 패턴이에요.','면책 조항 협상','B2','negotiation','pattern',NULL,22),
('s_negotiation_B2_02','We propose that any disputes be referred to arbitration under ICC rules.','모든 분쟁은 ICC 규정에 따른 중재에 회부할 것을 제안해요.','referred to arbitration','분쟁 해결 조항을 제안하는 격식 표현이에요.','분쟁 해결 조항 제안','B2','negotiation','pattern',NULL,23),
('s_negotiation_B2_03','The warranty period should be extended to twenty-four months to align with industry standards.','산업 표준에 맞추기 위해 보증 기간을 24개월로 연장해야 해요.','to align with industry standards','업계 기준을 근거로 조건 개선을 요구하는 표현이에요.','보증 기간 협상','B2','negotiation','pattern',NULL,24),
('s_negotiation_B2_04','Payment will be released from escrow only upon satisfactory delivery and inspection.','만족스러운 납품 및 검수 후에만 에스크로에서 지불이 해제돼요.','released from escrow only upon','에스크로 조건을 명확히 설정하는 계약 언어예요.','에스크로 조건 설정','B2','negotiation','pattern',NULL,25),
('s_negotiation_B2_05','We need to include a force majeure clause covering pandemics and supply chain disruptions.','팬데믹과 공급망 혼란을 포함하는 불가항력 조항이 필요해요.','force majeure clause covering','현대 계약에 필수적인 불가항력 조항을 협상할 때 써요.','불가항력 조항 삽입','B2','negotiation','pattern',NULL,26),
('s_negotiation_B2_06','The liquidated damages rate of two percent per week is disproportionate and should be reduced.','주당 2%의 약정 손해배상률은 과도하므로 낮춰야 해요.','disproportionate and should be reduced','손해배상 비율이 과하다고 반박할 때 쓰는 표현이에요.','약정 손해배상 협상','B2','negotiation','pattern',NULL,27),
('s_negotiation_B2_07','Both parties should ratify the final agreement by the end of the month to avoid further delays.','추가 지연을 피하기 위해 양 당사자가 이번 달 말까지 최종 합의를 비준해야 해요.','Both parties should ratify','공식 비준 절차를 촉구하는 표현이에요.','비준 촉구','B2','negotiation','pattern',NULL,28);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_negotiation_C1_01','The fiduciary obligations imposed on the trustee preclude self-dealing in this transaction.','수탁자에게 부과된 신탁 의무는 이 거래에서 자기 거래를 배제해요.','fiduciary obligations preclude','신탁 의무를 근거로 자기 거래를 차단하는 법적 주장이에요.','신탁 의무 주장','C1','negotiation','pattern',NULL,29),
('s_negotiation_C1_02','The lien held by the creditor must be discharged prior to transfer of title.','채권자가 보유한 유치권은 소유권 이전 전에 해제돼야 해요.','lien held by the creditor must be discharged','소유권 이전 전 유치권 해제를 요구하는 법적 표현이에요.','유치권 해제 요구','C1','negotiation','pattern',NULL,30),
('s_negotiation_C1_03','We are seeking an injunction to restrain the respondent from further breach of the covenant.','피응답인의 추가적인 약정 위반을 막기 위해 금지 명령을 구하고 있어요.','seeking an injunction to restrain','법원에 금지 명령을 신청할 때 쓰는 고급 법적 표현이에요.','금지 명령 신청','C1','negotiation','pattern',NULL,31),
('s_negotiation_C1_04','The remedy available for breach of this covenant is specific performance, not merely damages.','이 약정 위반에 대한 구제책은 손해배상뿐만 아니라 특정 이행이에요.','remedy available is specific performance','손해배상 대신 특정 이행을 구제책으로 주장하는 표현이에요.','특정 이행 주장','C1','negotiation','pattern',NULL,32),
('s_negotiation_C1_05','The jurisdiction clause designates Singapore as the exclusive forum for all disputes.','관할권 조항은 모든 분쟁에 대해 싱가포르를 독점적 법정지로 지정해요.','jurisdiction clause designates','관할권 조항의 내용을 명시적으로 인용하는 법적 표현이에요.','관할권 조항 인용','C1','negotiation','pattern',NULL,33),
('s_negotiation_C1_06','Subrogation rights vest in the insurer upon payment of the insured''s claim.','피보험자의 청구 지급 시 보험사에게 대위 청구권이 발생해요.','Subrogation rights vest in the insurer','보험 분쟁 협상에서 대위 청구권을 주장하는 표현이에요.','대위 청구권 주장','C1','negotiation','pattern',NULL,34),
('s_negotiation_C1_07','The conditions precedent to drawdown have not been satisfied, suspending our obligation to lend.','대출 실행의 선행 조건이 충족되지 않아 우리의 대출 의무가 정지됐어요.','conditions precedent to drawdown have not been satisfied','선행 조건 미충족을 근거로 의무를 정지시키는 표현이에요.','선행 조건 미충족 주장','C1','negotiation','pattern',NULL,35);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_negotiation_C2_01','The doctrine of promissory estoppel bars the claimant from resiling from the representation made during pre-contractual negotiations.','약속적 금반언 원칙은 계약 전 협상 중 이루어진 진술에서 청구인이 후퇴하는 것을 막아요.','promissory estoppel bars the claimant from resiling','선계약 단계의 진술을 법적으로 구속하는 고급 주장이에요.','약속적 금반언 주장','C2','negotiation','pattern',NULL,36),
('s_negotiation_C2_02','Quantum meruit entitles the claimant to reasonable remuneration for services rendered in the absence of an agreed price.','약정 가격이 없는 경우 제공된 서비스에 대해 합리적인 보수를 청구할 권리가 있어요.','Quantum meruit entitles','가격 미합의 상황에서 보수를 청구하는 법적 근거를 제시하는 표현이에요.','정당 보수 청구','C2','negotiation','pattern',NULL,37),
('s_negotiation_C2_03','The contract is void ab initio on the grounds of economic duress applied during the execution phase.','계약 체결 단계에서 가해진 경제적 강박을 이유로 계약은 처음부터 무효예요.','void ab initio on the grounds of economic duress','경제적 강박을 이유로 계약 자체를 무효화하는 강력한 법적 주장이에요.','경제적 강박 무효 주장','C2','negotiation','pattern',NULL,38),
('s_negotiation_C2_04','Novation extinguishes the original obligation and substitutes a new contract between the parties, thereby releasing the original debtor.','계약 갱신은 원래 의무를 소멸시키고 새로운 계약으로 대체해 원래 채무자를 면책시켜요.','Novation extinguishes the original obligation','채무 교체의 법적 효과를 정확히 설명하는 표현이에요.','계약 갱신 효과 설명','C2','negotiation','pattern',NULL,39),
('s_negotiation_C2_05','Under the rule in contra proferentem, the ambiguous exclusion clause is construed against the party who drafted it.','작성자 불이익 원칙에 따라 모호한 면책 조항은 이를 작성한 당사자에게 불리하게 해석돼요.','contra proferentem construed against the drafter','모호한 계약 조항에서 유리한 해석을 확보하는 전략적 표현이에요.','작성자 불이익 원칙 적용','C2','negotiation','pattern',NULL,40),
('s_negotiation_C2_06','The unjust enrichment claim rests on the defendant''s failure to make restitution following rescission of the contract.','부당 이득 청구는 계약 취소 후 피고의 원상 회복 불이행에 근거해요.','unjust enrichment rests on failure to make restitution','계약 취소 후 원상 회복 의무 불이행을 공격하는 법적 논리예요.','부당 이득 청구 근거 제시','C2','negotiation','pattern',NULL,41),
('s_negotiation_C2_07','Piercing the corporate veil is warranted where the subsidiary was used as a mere facade to evade pre-existing contractual obligations.','자회사가 기존 계약 의무를 회피하기 위한 단순 위장 수단으로 사용된 경우 법인격 부인이 정당화돼요.','Piercing the corporate veil is warranted','법인격을 이용한 의무 회피에 대응하는 최고급 법적 주장이에요.','법인격 부인 주장','C2','negotiation','pattern',NULL,42);
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_humanities_A1_01','story','/ˈstɔːri/','noun','이야기','A description of events, real or imagined.','She told us a {story} before bed.','그녀는 자기 전에 우리에게 이야기를 해줬어요.','story','A1','humanities',1,'book open story reading'),
('w_humanities_A1_02','book','/bʊk/','noun','책','A written work published in printed or digital form.','I read a {book} every month.','저는 매달 책을 한 권 읽어요.','book','A1','humanities',1,'book shelf library read'),
('w_humanities_A1_03','read','/riːd/','verb','읽다','To look at and understand written words.','Do you like to {read} in the morning?','아침에 독서하는 걸 좋아하세요?','read','A1','humanities',1,'person reading book open'),
('w_humanities_A1_04','write','/raɪt/','verb','쓰다','To mark words or symbols on a surface.','She loves to {write} short stories.','그녀는 단편 소설 쓰는 것을 좋아해요.','write','A1','humanities',1,'pen paper writing notebook'),
('w_humanities_A1_05','poem','/ˈpoʊɪm/','noun','시','A piece of writing in verse, often with rhythm.','He read a beautiful {poem} at the ceremony.','그는 행사에서 아름다운 시를 낭독했어요.','poem','A1','humanities',2,'poetry book writing verse'),
('w_humanities_A1_06','song','/sɒŋ/','noun','노래','A short piece of music with words.','She wrote a {song} about her hometown.','그녀는 고향에 대한 노래를 썼어요.','song','A1','humanities',1,'music notes singing guitar'),
('w_humanities_A1_07','history','/ˈhɪstəri/','noun','역사','The study of past events.','We studied the {history} of ancient civilizations.','우리는 고대 문명의 역사를 공부했어요.','history','A1','humanities',1,'ancient history books archive'),
('w_humanities_A1_08','old','/oʊld/','adjective','오래된','Having existed or lived for a long time.','This is an {old} and famous novel.','이것은 오래되고 유명한 소설이에요.','old','A1','humanities',2,'old books vintage library'),
('w_humanities_A1_09','people','/ˈpiːpəl/','noun','사람들','Human beings in general.','{People} love stories that feel real.','사람들은 현실적으로 느껴지는 이야기를 좋아해요.','people','A1','humanities',1,'crowd people gathering social'),
('w_humanities_A1_10','word','/wɜːrd/','noun','단어','A single unit of language.','What does this {word} mean in English?','이 단어는 영어로 무슨 뜻이에요?','word','A1','humanities',1,'dictionary words letters text'),
('w_humanities_A1_11','name','/neɪm/','noun','이름','A word used to identify a person or thing.','What is the {name} of this poem?','이 시의 제목이 뭐예요?','name','A1','humanities',2,'name tag label identity'),
('w_humanities_A1_12','page','/peɪdʒ/','noun','페이지','One side of a sheet of paper in a book.','Open your book to {page} ten.','책의 10페이지를 펴세요.','page','A1','humanities',2,'book page open reading'),
('w_humanities_A1_13','picture','/ˈpɪktʃər/','noun','그림, 사진','A drawing, painting, or photograph.','There is a {picture} in every chapter.','모든 챕터에 그림이 있어요.','picture','A1','humanities',2,'illustration art painting book'),
('w_humanities_A1_14','letter','/ˈletər/','noun','편지; 글자','A written message sent to someone; a symbol in an alphabet.','She wrote a long {letter} to her friend.','그녀는 친구에게 긴 편지를 썼어요.','letter','A1','humanities',2,'letter envelope pen writing'),
('w_humanities_A1_15','learn','/lɜːrn/','verb','배우다','To gain knowledge or a skill through study or experience.','We {learn} new words by reading books.','우리는 독서를 통해 새 단어를 배워요.','learn','A1','humanities',1,'study learning book education'),
('w_humanities_A1_16','love','/lʌv/','noun','사랑; 좋아함','An intense feeling of affection; great enjoyment.','Her {love} for literature started early.','그녀의 문학에 대한 사랑은 일찍 시작됐어요.','love','A1','humanities',1,'heart love passion books'),
('w_humanities_A1_17','life','/laɪf/','noun','삶, 인생','The existence of a human being.','Good novels reflect real {life}.','좋은 소설은 현실의 삶을 반영해요.','life','A1','humanities',1,'life journey human nature'),
('w_humanities_A1_18','title','/ˈtaɪtəl/','noun','제목','The name of a book, film, or other work.','What is the {title} of your favorite book?','가장 좋아하는 책의 제목이 뭐예요?','title','A1','humanities',2,'book cover title label'),
('w_humanities_A1_19','question','/ˈkwɛstʃən/','noun','질문','A sentence asking for information.','The author raises an important {question}.','작가는 중요한 질문을 제기해요.','question','A1','humanities',2,'question mark thinking wonder'),
('w_humanities_A1_20','think','/θɪŋk/','verb','생각하다','To have thoughts or opinions about something.','What do you {think} about the ending?','결말에 대해 어떻게 생각하세요?','think','A1','humanities',1,'thinking reflection idea mind'),
('w_humanities_A1_21','true','/truː/','adjective','사실인, 진짜의','In accordance with fact or reality.','The story is based on {true} events.','그 이야기는 실제 사건을 바탕으로 해요.','true','A1','humanities',2,'truth reality fact document'),
('w_humanities_A1_22','beautiful','/ˈbjuːtɪfəl/','adjective','아름다운','Pleasing to the senses or mind.','She wrote a {beautiful} poem for the class.','그녀는 수업을 위해 아름다운 시를 썼어요.','beautiful','A1','humanities',3,'beauty art landscape poem'),
('w_humanities_A1_23','short','/ʃɔːrt/','adjective','짧은','Small in length or time.','I prefer {short} stories to long novels.','저는 긴 소설보다 단편을 더 좋아해요.','short','A1','humanities',2,'short story brief pages'),
('w_humanities_A1_24','language','/ˈlæŋɡwɪdʒ/','noun','언어','A system of communication used by a group.','English is a global {language}.','영어는 세계 언어예요.','language','A1','humanities',1,'language communication speech text'),
('w_humanities_A1_25','draw','/drɔː/','verb','그리다','To make a picture with a pencil or pen.','She likes to {draw} characters from her favorite stories.','그녀는 좋아하는 이야기의 등장인물을 그리는 걸 좋아해요.','draw','A1','humanities',3,'drawing art sketch pencil'),
('w_humanities_A1_26','end','/end/','noun','끝, 결말','The final part of something.','The {end} of the story surprised everyone.','이야기의 결말이 모두를 놀라게 했어요.','end','A1','humanities',2,'ending story conclusion book'),
('w_humanities_A1_27','start','/stɑːrt/','verb','시작하다','To begin something.','Where does the story {start}?','이야기가 어디서 시작되나요?','start','A1','humanities',2,'beginning start open book'),
('w_humanities_A1_28','tell','/tel/','verb','말하다, 이야기하다','To communicate facts or a story in spoken or written words.','Can you {tell} me about your favorite book?','좋아하는 책에 대해 이야기해 줄 수 있어요?','tell','A1','humanities',1,'talking storytelling sharing'),
('w_humanities_A1_29','mean','/miːn/','verb','의미하다','To intend to convey; to signify.','What does this phrase {mean}?','이 구절은 무슨 뜻이에요?','mean','A1','humanities',1,'meaning definition understanding'),
('w_humanities_A1_30','listen','/ˈlɪsən/','verb','듣다','To pay attention to sounds.','I love to {listen} to audiobooks.','저는 오디오북 듣는 걸 좋아해요.','listen','A1','humanities',2,'listening audio headphones book'),
('w_humanities_A1_31','enjoy','/ɪnˈdʒɔɪ/','verb','즐기다','To take pleasure in something.','I {enjoy} reading classic literature.','저는 고전 문학 읽는 걸 즐겨요.','enjoy','A1','humanities',1,'enjoying reading leisure books'),
('w_humanities_A1_32','world','/wɜːrld/','noun','세계, 세상','The earth and all its people; a realm of existence.','Great literature opens up the {world}.','훌륭한 문학은 세계를 열어줘요.','world','A1','humanities',1,'world globe earth explore'),
('w_humanities_A1_33','real','/riːl/','adjective','진짜의, 현실의','Actually existing; not imagined.','The characters feel very {real}.','등장인물들이 매우 현실적으로 느껴져요.','real','A1','humanities',2,'reality authentic genuine truth'),
('w_humanities_A1_34','class','/klɑːs/','noun','수업; 계층','A group lesson; also a social division.','We discussed the poem in {class}.','수업에서 그 시에 대해 토론했어요.','class','A1','humanities',2,'classroom learning education discussion'),
('w_humanities_A1_35','remember','/rɪˈmembər/','verb','기억하다','To have in mind or bring back to mind.','I always {remember} the first book I loved.','저는 처음 좋아했던 책을 항상 기억해요.','remember','A1','humanities',2,'memory remember nostalgia books');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_humanities_A2_01','author','/ˈɔːθər/','noun','작가','A person who writes books or articles.','My favorite {author} has written over twenty novels.','제가 가장 좋아하는 작가는 소설을 20편 넘게 썼어요.','author','A2','humanities',1,'writer author desk books'),
('w_humanities_A2_02','novel','/ˈnɒvəl/','noun','소설','A long fictional prose narrative.','I just finished reading a great {novel}.','방금 훌륭한 소설을 다 읽었어요.','novel','A2','humanities',1,'novel book fiction reading'),
('w_humanities_A2_03','character','/ˈkærɪktər/','noun','등장인물; 성격','A person in a story or play; a person''s nature.','The main {character} changes throughout the story.','주인공은 이야기 내내 변해가요.','character','A2','humanities',1,'character portrait story person'),
('w_humanities_A2_04','chapter','/ˈtʃæptər/','noun','챕터, 장','A main division of a book.','I read two {chapter}s before bed every night.','저는 매일 밤 자기 전에 챕터를 두 개 읽어요.','chapter','A2','humanities',2,'book chapter pages reading'),
('w_humanities_A2_05','culture','/ˈkʌltʃər/','noun','문화','The customs and values of a society.','Literature reflects the {culture} of its time.','문학은 시대의 문화를 반영해요.','culture','A2','humanities',1,'culture diversity society tradition'),
('w_humanities_A2_06','tradition','/trəˈdɪʃən/','noun','전통','A long-established custom passed down through generations.','Oral storytelling is an important {tradition}.','구전 이야기하기는 중요한 전통이에요.','tradition','A2','humanities',2,'tradition heritage culture folk'),
('w_humanities_A2_07','myth','/mɪθ/','noun','신화','A traditional story, especially one explaining a natural phenomenon.','The Greek {myth} of Icarus is still famous.','이카로스에 관한 그리스 신화는 아직도 유명해요.','myth','A2','humanities',2,'mythology ancient Greece story'),
('w_humanities_A2_08','legend','/ˈledʒənd/','noun','전설','A traditional story about a famous person or event.','King Arthur is a well-known English {legend}.','아서 왕은 유명한 영국 전설이에요.','legend','A2','humanities',2,'legend folklore hero ancient'),
('w_humanities_A2_09','hero','/ˈhɪərəʊ/','noun','영웅; 주인공','A person admired for courage; the main character.','Every great story has a {hero} who faces challenges.','모든 훌륭한 이야기에는 도전에 맞서는 영웅이 있어요.','hero','A2','humanities',1,'hero courage adventure story'),
('w_humanities_A2_10','describe','/dɪˈskraɪb/','verb','묘사하다','To give a detailed account of something.','The author uses vivid language to {describe} the setting.','작가는 생생한 언어로 배경을 묘사해요.','describe','A2','humanities',1,'description detail writing vivid'),
('w_humanities_A2_11','imagination','/ɪˌmædʒɪˈneɪʃən/','noun','상상력','The ability to form new ideas not present to the senses.','Reading develops your {imagination}.','독서는 상상력을 키워줘요.','imagination','A2','humanities',1,'imagination creativity dream art'),
('w_humanities_A2_12','poetry','/ˈpoʊɪtri/','noun','시(詩) 전반','Literary work in verse, expressing feelings and ideas.','She studied {poetry} at university.','그녀는 대학에서 시를 공부했어요.','poetry','A2','humanities',2,'poetry book verse literature'),
('w_humanities_A2_13','fiction','/ˈfɪkʃən/','noun','소설, 허구','Literature that describes imaginary events and people.','Science {fiction} often predicts the future.','공상과학 소설은 종종 미래를 예측해요.','fiction','A2','humanities',2,'fiction books library story'),
('w_humanities_A2_14','drama','/ˈdrɑːmə/','noun','희곡; 드라마','A play for theatre or TV; an exciting series of events.','Shakespeare''s {drama} is still performed worldwide.','셰익스피어의 희곡은 전 세계에서 아직도 공연돼요.','drama','A2','humanities',2,'theater drama stage performance'),
('w_humanities_A2_15','express','/ɪkˈspres/','verb','표현하다','To convey feelings or ideas through words or art.','Writers {express} their inner world through stories.','작가들은 이야기를 통해 내면 세계를 표현해요.','express','A2','humanities',1,'expression art writing feeling'),
('w_humanities_A2_16','meaning','/ˈmiːnɪŋ/','noun','의미','What is intended or expressed.','What is the deeper {meaning} of this poem?','이 시의 더 깊은 의미는 무엇인가요?','meaning','A2','humanities',1,'meaning depth significance text'),
('w_humanities_A2_17','publish','/ˈpʌblɪʃ/','verb','출판하다','To prepare and issue a book or article for public sale.','Her debut novel was {publish}ed last spring.','그녀의 데뷔 소설은 지난 봄에 출판됐어요.','publish','A2','humanities',2,'publishing book print release'),
('w_humanities_A2_18','audience','/ˈɔːdiəns/','noun','독자; 관객','The group of people who read or watch a work.','The author writes for a young adult {audience}.','작가는 청소년 독자를 위해 글을 써요.','audience','A2','humanities',2,'audience readers crowd people'),
('w_humanities_A2_19','setting','/ˈsetɪŋ/','noun','배경','The time and place in which a story is set.','The {setting} of the novel is 19th-century London.','소설의 배경은 19세기 런던이에요.','setting','A2','humanities',2,'setting landscape scene place'),
('w_humanities_A2_20','plot','/plɒt/','noun','줄거리','The sequence of events in a story.','The {plot} of the movie was very unexpected.','영화의 줄거리가 매우 예상 밖이었어요.','plot','A2','humanities',1,'plot story twist narrative'),
('w_humanities_A2_21','inspire','/ɪnˈspaɪər/','verb','영감을 주다','To stimulate creative feeling or thought.','Great literature can {inspire} people to change.','훌륭한 문학은 사람들이 변화하도록 영감을 줄 수 있어요.','inspire','A2','humanities',1,'inspiration creativity idea art'),
('w_humanities_A2_22','compare','/kəmˈpeər/','verb','비교하다','To note the similarities and differences between two things.','Let''s {compare} these two short stories.','이 두 단편 소설을 비교해 봐요.','compare','A2','humanities',2,'comparison contrast analysis side'),
('w_humanities_A2_23','message','/ˈmesɪdʒ/','noun','메시지, 주제','The central idea or lesson of a work.','What {message} is the author trying to send?','작가가 전달하려는 메시지는 무엇인가요?','message','A2','humanities',2,'message meaning theme writing'),
('w_humanities_A2_24','century','/ˈsentʃəri/','noun','세기, 100년','A period of one hundred years.','This novel was written in the 19th {century}.','이 소설은 19세기에 쓰였어요.','century','A2','humanities',2,'century history timeline era'),
('w_humanities_A2_25','popular','/ˈpɒpjʊlər/','adjective','인기 있는','Liked or admired by many people.','This novel is very {popular} among teenagers.','이 소설은 십대들 사이에서 매우 인기 있어요.','popular','A2','humanities',2,'popular bestseller book trend'),
('w_humanities_A2_26','original','/əˈrɪdʒɪnəl/','adjective','독창적인; 원본의','New and creative; the first version of something.','The {original} manuscript is kept in a museum.','원본 원고는 박물관에 보관돼 있어요.','original','A2','humanities',2,'original authentic first edition'),
('w_humanities_A2_27','translate','/trænsˈleɪt/','verb','번역하다','To convert text from one language to another.','This novel has been {translate}d into 30 languages.','이 소설은 30개 언어로 번역됐어요.','translate','A2','humanities',2,'translation language global book'),
('w_humanities_A2_28','scene','/siːn/','noun','장면','A part of a play or story depicting a single event.','My favorite {scene} is at the end of chapter three.','제가 가장 좋아하는 장면은 3장 끝 부분이에요.','scene','A2','humanities',2,'scene movie play moment'),
('w_humanities_A2_29','creative','/kriˈeɪtɪv/','adjective','창의적인','Having the ability to produce new and imaginative ideas.','Writing requires a very {creative} mind.','글쓰기는 매우 창의적인 사고를 필요로 해요.','creative','A2','humanities',1,'creative imagination art design'),
('w_humanities_A2_30','opinion','/əˈpɪnjən/','noun','의견','A personal view or judgement.','In your {opinion}, what is the best novel ever written?','당신 의견으로는 역대 최고의 소설이 무엇이에요?','opinion','A2','humanities',1,'opinion view perspective discuss'),
('w_humanities_A2_31','award','/əˈwɔːrd/','noun','상, 수상','A prize given for achievement.','The novel won a major literary {award}.','그 소설은 주요 문학상을 받았어요.','award','A2','humanities',2,'award prize trophy achievement'),
('w_humanities_A2_32','ancient','/ˈeɪnʃənt/','adjective','고대의','Belonging to the very distant past.','{Ancient} myths still influence modern storytelling.','고대 신화는 아직도 현대 이야기 방식에 영향을 미쳐요.','ancient','A2','humanities',2,'ancient history ruins civilization'),
('w_humanities_A2_33','folktale','/ˈfoʊkteɪl/','noun','민담, 민화','A story passed down through ordinary people.','Korean {folktale}s often teach moral lessons.','한국 민담은 종종 도덕적 교훈을 가르쳐요.','folktale','A2','humanities',2,'folktale tradition culture story'),
('w_humanities_A2_34','narrative','/ˈnærətɪv/','noun','서사, 이야기 방식','A spoken or written account of events.','The {narrative} switches between two characters.','서사는 두 인물 사이를 오가요.','narrative','A2','humanities',1,'narrative storytelling structure plot'),
('w_humanities_A2_35','genre','/ˈʒɑːnrə/','noun','장르','A category of artistic work defined by style or subject.','What is your favorite literary {genre}?','가장 좋아하는 문학 장르가 뭐예요?','genre','A2','humanities',1,'genre category books shelf');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_humanities_B1_01','metaphor','/ˈmetəfɔːr/','noun','은유','A figure of speech applying a word or phrase to something it does not literally denote.','The author uses a powerful {metaphor} to describe grief.','작가는 슬픔을 묘사하기 위해 강력한 은유를 사용해요.','metaphor','B1','humanities',1,'metaphor language poetry figure'),
('w_humanities_B1_02','theme','/θiːm/','noun','주제, 테마','The central subject or idea explored in a work.','The main {theme} of the novel is redemption.','소설의 주된 주제는 구원이에요.','theme','B1','humanities',1,'theme idea central message'),
('w_humanities_B1_03','symbolism','/ˈsɪmbəlɪzəm/','noun','상징주의; 상징성','The use of symbols to represent ideas or qualities.','The green light in Gatsby is famous for its {symbolism}.','개츠비의 초록불은 상징성으로 유명해요.','symbolism','B1','humanities',1,'symbol meaning literature art'),
('w_humanities_B1_04','analyze','/ˈænəlaɪz/','verb','분석하다','To examine in detail to understand or explain.','Students are asked to {analyze} the poem''s structure.','학생들은 시의 구조를 분석하도록 요청받아요.','analyze','B1','humanities',1,'analysis research study detail'),
('w_humanities_B1_05','interpret','/ɪnˈtɜːrprɪt/','verb','해석하다','To explain the meaning of something.','How do you {interpret} the final scene?','마지막 장면을 어떻게 해석하세요?','interpret','B1','humanities',1,'interpretation meaning analysis view'),
('w_humanities_B1_06','literary','/ˈlɪtərəri/','adjective','문학적인','Relating to the writing or study of literature.','She has a deep appreciation for {literary} fiction.','그녀는 문학 소설을 깊이 좋아해요.','literary','B1','humanities',1,'literary books writing academic'),
('w_humanities_B1_07','classic','/ˈklæsɪk/','adjective / noun','고전적인; 고전 작품','Of recognized and enduring quality; a great work of art.','Romeo and Juliet is a {classic} of English literature.','로미오와 줄리엣은 영문학의 고전이에요.','classic','B1','humanities',1,'classic literature timeless book'),
('w_humanities_B1_08','critique','/krɪˈtiːk/','noun','비평','A detailed analysis and assessment of a work.','He wrote a {critique} of the novel for the magazine.','그는 잡지에 소설 비평을 썼어요.','critique','B1','humanities',2,'critique review analysis writing'),
('w_humanities_B1_09','perspective','/pərˈspektɪv/','noun','관점','A particular way of viewing something.','Read the story from the narrator''s {perspective}.','화자의 관점에서 이야기를 읽어보세요.','perspective','B1','humanities',1,'perspective viewpoint angle idea'),
('w_humanities_B1_10','contrast','/ˈkɒntræst/','noun','대비, 대조','The state of being strikingly different from something else.','The author uses sharp {contrast} to highlight injustice.','작가는 불의를 강조하기 위해 날카로운 대비를 사용해요.','contrast','B1','humanities',2,'contrast comparison black white'),
('w_humanities_B1_11','structure','/ˈstrʌktʃər/','noun','구조','The arrangement of and relations between the parts of a text.','The {structure} of this poem is unusual.','이 시의 구조는 독특해요.','structure','B1','humanities',2,'structure architecture design order'),
('w_humanities_B1_12','conflict','/ˈkɒnflɪkt/','noun','갈등','A serious disagreement; the central struggle in a narrative.','The internal {conflict} of the protagonist drives the story.','주인공의 내적 갈등이 이야기를 이끌어요.','conflict','B1','humanities',1,'conflict tension struggle drama'),
('w_humanities_B1_13','narrator','/nəˈreɪtər/','noun','화자, 서술자','The person who tells a story.','The {narrator} is unreliable, which creates suspense.','화자가 신뢰할 수 없어서 긴장감이 생겨요.','narrator','B1','humanities',2,'narrator voice storytelling book'),
('w_humanities_B1_14','tone','/toʊn/','noun','어조, 분위기','The general attitude of a writer toward the subject.','The {tone} of the poem shifts from joy to sadness.','시의 어조가 기쁨에서 슬픔으로 바뀌어요.','tone','B1','humanities',2,'tone mood atmosphere writing'),
('w_humanities_B1_15','imagery','/ˈɪmɪdʒəri/','noun','심상, 이미지','Visually descriptive or figurative language.','Rich {imagery} makes the poem come alive.','풍부한 심상이 시를 생동감 있게 만들어요.','imagery','B1','humanities',2,'imagery visualization poetry vivid'),
('w_humanities_B1_16','influence','/ˈɪnflʊəns/','noun','영향','The power to affect others.','Hemingway had a great {influence} on modern prose.','헤밍웨이는 현대 산문에 큰 영향을 미쳤어요.','influence','B1','humanities',1,'influence impact effect inspiration'),
('w_humanities_B1_17','context','/ˈkɒntekst/','noun','맥락, 문맥','The circumstances in which something exists or occurs.','Understanding the historical {context} helps us read the text better.','역사적 맥락을 이해하면 텍스트를 더 잘 읽을 수 있어요.','context','B1','humanities',1,'context background history text'),
('w_humanities_B1_18','symbol','/ˈsɪmbəl/','noun','상징','A thing representing or standing for something else.','The dove is a {symbol} of peace in many cultures.','비둘기는 많은 문화에서 평화의 상징이에요.','symbol','B1','humanities',1,'symbol peace dove meaning'),
('w_humanities_B1_19','biography','/baɪˈɒɡrəfi/','noun','전기(傳記)','An account of a person''s life written by someone else.','I read a {biography} of Shakespeare last year.','작년에 셰익스피어 전기를 읽었어요.','biography','B1','humanities',2,'biography life story portrait'),
('w_humanities_B1_20','tradition','/trəˈdɪʃən/','noun','문학 전통','A long-established custom or practice passed across generations.','Greek tragedy is central to the Western literary {tradition}.','그리스 비극은 서양 문학 전통의 핵심이에요.','tradition','B1','humanities',2,'tradition heritage classic western'),
('w_humanities_B1_21','tragedy','/ˈtrædʒɪdi/','noun','비극','A serious play or event with an unhappy ending.','Hamlet is one of Shakespeare''s greatest {tragedy} plays.','햄릿은 셰익스피어의 가장 위대한 비극 중 하나예요.','tragedy','B1','humanities',2,'tragedy drama sad ending stage'),
('w_humanities_B1_22','comedy','/ˈkɒmɪdi/','noun','희극','A play or story intended to be funny with a happy ending.','A Midsummer Night''s Dream is a celebrated {comedy}.','한여름 밤의 꿈은 유명한 희극이에요.','comedy','B1','humanities',3,'comedy humor play happy'),
('w_humanities_B1_23','verse','/vɜːrs/','noun','운문, 절','Writing arranged in lines with a rhythm; a stanza.','The poem is written in four-line {verse}s.','그 시는 4행 절로 쓰여 있어요.','verse','B1','humanities',2,'verse poetry rhyme stanza'),
('w_humanities_B1_24','prose','/proʊz/','noun','산문','Written or spoken language in its ordinary form.','The novel is written in beautiful, flowing {prose}.','소설은 아름답고 유려한 산문으로 쓰여 있어요.','prose','B1','humanities',2,'prose writing paragraphs style'),
('w_humanities_B1_25','reference','/ˈrefərəns/','noun','참조, 언급','A mention of or citation from another work.','The novel contains many {reference}s to Greek mythology.','소설에는 그리스 신화에 대한 언급이 많아요.','reference','B1','humanities',2,'reference citation source text'),
('w_humanities_B1_26','quotation','/kwoʊˈteɪʃən/','noun','인용문','A group of words repeated from a text.','She opened her essay with a {quotation} from Austen.','그녀는 오스틴의 인용문으로 에세이를 시작했어요.','quotation','B1','humanities',2,'quote citation text highlight'),
('w_humanities_B1_27','essay','/ˈeseɪ/','noun','에세이, 수필','A short piece of writing on a particular subject.','He wrote an {essay} comparing two famous novels.','그는 두 유명한 소설을 비교하는 에세이를 썼어요.','essay','B1','humanities',2,'essay writing analysis paper'),
('w_humanities_B1_28','respond','/rɪˈspɒnd/','verb','반응하다, 응하다','To say or write something in reply; to react.','How did readers {respond} to the new novel?','독자들은 새 소설에 어떻게 반응했나요?','respond','B1','humanities',2,'response reaction reader feedback'),
('w_humanities_B1_29','explore','/ɪkˈsplɔːr/','verb','탐구하다','To examine thoroughly; to investigate ideas.','The novel {explore}s themes of identity and belonging.','소설은 정체성과 귀속감의 주제를 탐구해요.','explore','B1','humanities',1,'explore discovery research idea'),
('w_humanities_B1_30','cultural','/ˈkʌltʃərəl/','adjective','문화적인','Relating to the culture of a society.','The novel has great {cultural} significance.','그 소설은 문화적으로 큰 의미를 지녀요.','cultural','B1','humanities',1,'cultural heritage society art'),
('w_humanities_B1_31','reveal','/rɪˈviːl/','verb','드러내다, 밝히다','To make known something previously hidden or unknown.','The final chapter {reveal}s the true identity of the killer.','마지막 챕터에서 살인자의 진짜 정체가 드러나요.','reveal','B1','humanities',2,'reveal surprise discovery truth'),
('w_humanities_B1_32','audience','/ˈɔːdiəns/','noun','독자, 청중','The intended readers or viewers of a work.','The book found a wide {audience} in Europe.','그 책은 유럽에서 넓은 독자층을 형성했어요.','audience','B1','humanities',2,'audience readers crowd reception'),
('w_humanities_B1_33','passage','/ˈpæsɪdʒ/','noun','구절, 단락','A short section taken from a longer text.','This {passage} from the novel is often quoted.','소설의 이 구절은 자주 인용돼요.','passage','B1','humanities',2,'passage text excerpt highlight'),
('w_humanities_B1_34','illustrate','/ˈɪləstreɪt/','verb','설명하다; 삽화를 넣다','To explain or make clear with examples or pictures.','The author uses anecdotes to {illustrate} the theme.','작가는 주제를 설명하기 위해 일화를 사용해요.','illustrate','B1','humanities',2,'illustration example visual explain'),
('w_humanities_B1_35','impact','/ˈɪmpækt/','noun','영향, 충격','A strong effect or impression.','This book had a huge {impact} on my life.','이 책은 제 삶에 큰 영향을 미쳤어요.','impact','B1','humanities',1,'impact effect change influence');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_humanities_B2_01','allegory','/ˈæləɡɔːri/','noun','알레고리, 풍유','A narrative with a hidden symbolic meaning.','Animal Farm is a well-known political {allegory}.','동물농장은 유명한 정치적 알레고리예요.','allegory','B2','humanities',1,'allegory symbol story meaning'),
('w_humanities_B2_02','archetype','/ˈɑːrkɪtaɪp/','noun','원형, 아키타입','A very typical example of a character or situation.','The wise old mentor is a classic literary {archetype}.','현명한 노인 멘토는 고전적인 문학 원형이에요.','archetype','B2','humanities',1,'archetype hero mentor pattern'),
('w_humanities_B2_03','motif','/moʊˈtiːf/','noun','모티프, 반복 요소','A recurring image, idea, or symbol in a work.','The {motif} of water runs throughout the novel.','물의 모티프가 소설 전체에 흐르고 있어요.','motif','B2','humanities',1,'motif pattern symbol repeat'),
('w_humanities_B2_04','subtext','/ˈsʌbtekst/','noun','숨겨진 의미, 서브텍스트','An underlying theme in a work that is not explicitly stated.','The {subtext} of the dialogue reveals jealousy.','대화의 숨겨진 의미는 질투를 드러내요.','subtext','B2','humanities',2,'subtext hidden meaning reading'),
('w_humanities_B2_05','irony','/ˈaɪrəni/','noun','아이러니, 반어','The expression of meaning through language that signifies the opposite.','The title of the novel is full of {irony}.','소설의 제목은 아이러니로 가득해요.','irony','B2','humanities',1,'irony contrast meaning twist'),
('w_humanities_B2_06','paradox','/ˈpærədɒks/','noun','역설','A seemingly contradictory statement that may be true.','The poet expresses grief through the {paradox} of joyful language.','시인은 기쁜 언어의 역설을 통해 슬픔을 표현해요.','paradox','B2','humanities',1,'paradox contradiction truth meaning'),
('w_humanities_B2_07','satire','/ˈsætaɪər/','noun','풍자','The use of humor or irony to criticize society.','Swift''s Gulliver''s Travels is a masterpiece of {satire}.','스위프트의 걸리버 여행기는 풍자의 걸작이에요.','satire','B2','humanities',1,'satire criticism humor society'),
('w_humanities_B2_08','bildungsroman','/ˈbɪldʊŋzroʊˌmɑːn/','noun','성장 소설','A novel about a young person''s moral and psychological growth.','The Catcher in the Rye is a famous {bildungsroman}.','호밀밭의 파수꾼은 유명한 성장 소설이에요.','bildungsroman','B2','humanities',2,'coming of age youth growth story'),
('w_humanities_B2_09','modernism','/ˈmɒdərnɪzəm/','noun','모더니즘','A movement in literature and arts rejecting traditional forms.','Virginia Woolf is a key figure of literary {modernism}.','버지니아 울프는 문학 모더니즘의 핵심 인물이에요.','modernism','B2','humanities',2,'modernism art movement twentieth century'),
('w_humanities_B2_10','existentialism','/ˌeɡzɪˈstenʃəlɪzəm/','noun','실존주의','A philosophical theory that humans define their own meaning.','Camus'' work is deeply rooted in {existentialism}.','카뮈의 작품은 실존주의에 깊이 뿌리를 두고 있어요.','existentialism','B2','humanities',2,'existentialism philosophy meaning freedom'),
('w_humanities_B2_11','allusion','/əˈluːʒən/','noun','암시, 전고(典故)','An indirect reference to a person, event, or work.','The poem contains an {allusion} to the Bible.','시에는 성경에 대한 암시가 담겨 있어요.','allusion','B2','humanities',2,'allusion reference history intertextual'),
('w_humanities_B2_12','ambiguity','/ˌæmbɪˈɡjuːɪti/','noun','모호함, 중의성','The quality of being open to more than one interpretation.','The ending is left in deliberate {ambiguity}.','결말은 의도적인 모호함으로 남겨져 있어요.','ambiguity','B2','humanities',2,'ambiguity meaning uncertain open'),
('w_humanities_B2_13','foreshadowing','/fɔːrˈʃædoʊɪŋ/','noun','복선','A literary technique used to hint at future events.','The ominous weather is a form of {foreshadowing}.','불길한 날씨는 복선의 일종이에요.','foreshadowing','B2','humanities',2,'foreshadowing hint clue future'),
('w_humanities_B2_14','postmodernism','/ˌpoʊstˈmɒdərnɪzəm/','noun','포스트모더니즘','A movement rejecting modernism''s grand narratives.','{Postmodernism} often questions the nature of truth in fiction.','포스트모더니즘은 종종 소설에서 진실의 본질에 의문을 제기해요.','postmodernism','B2','humanities',2,'postmodern art culture contemporary'),
('w_humanities_B2_15','unreliable','/ˌʌnrɪˈlaɪəbəl/','adjective','믿을 수 없는','Not able to be trusted or depended on.','The {unreliable} narrator keeps the reader guessing.','믿을 수 없는 화자는 독자를 계속 추측하게 만들어요.','unreliable','B2','humanities',2,'unreliable narrator deception twist'),
('w_humanities_B2_16','catharsis','/kəˈθɑːrsɪs/','noun','카타르시스, 정화','The process of releasing strong emotions through art.','Greek tragedy aimed to produce {catharsis} in the audience.','그리스 비극은 관객에게 카타르시스를 일으키는 것을 목표로 했어요.','catharsis','B2','humanities',2,'catharsis emotion release theater'),
('w_humanities_B2_17','aesthetic','/esˈθetɪk/','adjective / noun','미적인; 미학','Concerned with beauty or the appreciation of beauty.','The novel has a strong {aesthetic} sensibility.','소설은 강한 미적 감수성을 지녀요.','aesthetic','B2','humanities',2,'aesthetic beauty art design'),
('w_humanities_B2_18','epic','/ˈepɪk/','noun / adjective','서사시; 장대한','A long poem narrating heroic deeds; impressively large in scale.','The Iliad is an ancient Greek {epic}.','일리아드는 고대 그리스 서사시예요.','epic','B2','humanities',2,'epic poem hero ancient journey'),
('w_humanities_B2_19','dialect','/ˈdaɪəlekt/','noun','방언, 사투리','A form of language spoken by a particular group.','The novel uses regional {dialect} to create authenticity.','소설은 진정성을 만들기 위해 지역 방언을 사용해요.','dialect','B2','humanities',3,'dialect language regional speech'),
('w_humanities_B2_20','characterization','/ˌkærɪktərɪˈzeɪʃən/','noun','인물 묘사','The way an author develops the personalities of characters.','The {characterization} in this novel is remarkably subtle.','이 소설의 인물 묘사는 놀라울 정도로 섬세해요.','characterization','B2','humanities',2,'character development portrayal depth'),
('w_humanities_B2_21','juxtaposition','/ˌdʒʌkstəpəˈzɪʃən/','noun','병치, 대비 배치','Placing two things close together for contrasting effect.','The author uses {juxtaposition} to show social inequality.','작가는 사회적 불평등을 보여주기 위해 병치를 사용해요.','juxtaposition','B2','humanities',2,'juxtaposition contrast side by side'),
('w_humanities_B2_22','omniscient','/ɒmˈnɪʃənt/','adjective','전지적인','Having unlimited knowledge; used of a narrative perspective.','The story is told from an {omniscient} point of view.','이야기는 전지적 관점에서 서술돼요.','omniscient','B2','humanities',2,'omniscient narrator perspective view'),
('w_humanities_B2_23','realism','/ˈriːəlɪzəm/','noun','리얼리즘, 사실주의','A movement depicting subjects as they actually are.','19th-century {realism} aimed to portray everyday life accurately.','19세기 사실주의는 일상을 정확하게 묘사하는 것을 목표로 했어요.','realism','B2','humanities',2,'realism art everyday authentic'),
('w_humanities_B2_24','romanticism','/roʊˈmæntɪsɪzəm/','noun','낭만주의','An artistic movement emphasizing emotion and nature.','Keats is one of the most celebrated poets of {romanticism}.','키츠는 낭만주의에서 가장 유명한 시인 중 한 명이에요.','romanticism','B2','humanities',2,'romanticism nature emotion poetry'),
('w_humanities_B2_25','canon','/ˈkænən/','noun','정전(正典), 문학 캐논','The works generally accepted as the greatest in a given field.','The Western literary {canon} has been criticized for its lack of diversity.','서양 문학 캐논은 다양성 부족으로 비판받아왔어요.','canon','B2','humanities',2,'canon classic literature list'),
('w_humanities_B2_26','rhetoric','/ˈretərɪk/','noun','수사학; 수사법','The art of effective or persuasive speaking or writing.','Political speeches rely heavily on {rhetoric}.','정치 연설은 수사법에 크게 의존해요.','rhetoric','B2','humanities',2,'rhetoric persuasion speech language'),
('w_humanities_B2_27','infer','/ɪnˈfɜːr/','verb','추론하다','To deduce from evidence rather than explicit statement.','We can {infer} the character''s true feelings from his actions.','그의 행동으로부터 그 인물의 진짜 감정을 추론할 수 있어요.','infer','B2','humanities',2,'inference deduction reading between lines'),
('w_humanities_B2_28','trauma','/ˈtrɔːmə/','noun','트라우마','A deeply distressing experience; its lasting psychological effect.','The author explores childhood {trauma} through the protagonist.','작가는 주인공을 통해 어린 시절 트라우마를 탐구해요.','trauma','B2','humanities',2,'trauma psychology emotion healing'),
('w_humanities_B2_29','dystopia','/dɪˈstoʊpiə/','noun','디스토피아','An imagined world where everything is unpleasant or unjust.','1984 is a classic {dystopia} novel.','1984는 고전적인 디스토피아 소설이에요.','dystopia','B2','humanities',2,'dystopia dark future society'),
('w_humanities_B2_30','utopia','/juːˈtoʊpiə/','noun','유토피아','An imagined perfect society.','Thomas More coined the term {utopia} in 1516.','토마스 모어는 1516년에 유토피아라는 용어를 만들었어요.','utopia','B2','humanities',2,'utopia ideal perfect society'),
('w_humanities_B2_31','morality','/məˈrælɪti/','noun','도덕성','Principles concerning the distinction between right and wrong.','Victorian novels often focused on questions of {morality}.','빅토리아 시대 소설은 종종 도덕성 문제에 집중했어요.','morality','B2','humanities',2,'morality ethics right wrong'),
('w_humanities_B2_32','ambivalence','/æmˈbɪvələns/','noun','양가감정, 양의성','Mixed feelings about someone or something.','The hero''s {ambivalence} toward his father drives the plot.','아버지에 대한 영웅의 양가감정이 줄거리를 이끌어요.','ambivalence','B2','humanities',3,'ambivalence mixed feelings conflict'),
('w_humanities_B2_33','consciousness','/ˈkɒnʃəsnəs/','noun','의식(意識)','The state of being aware; the stream of thoughts.','Virginia Woolf pioneered stream-of-{consciousness} narration.','버지니아 울프는 의식의 흐름 서술 방식을 개척했어요.','consciousness','B2','humanities',2,'consciousness mind stream thought'),
('w_humanities_B2_34','absurd','/əbˈsɜːrd/','adjective','부조리한, 불합리한','Wildly unreasonable or inappropriate; contrary to logic.','Kafka''s work captures the {absurd} nature of modern bureaucracy.','카프카의 작품은 현대 관료주의의 부조리한 특성을 담아요.','absurd','B2','humanities',2,'absurd surreal illogical kafkaesque'),
('w_humanities_B2_35','critique','/krɪˈtiːk/','verb','비평하다','To evaluate a work in detail.','She was asked to {critique} a postmodern short story.','그녀는 포스트모던 단편 소설을 비평해달라는 요청을 받았어요.','critique','B2','humanities',2,'critique analysis evaluation writing');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_humanities_C1_01','hermeneutics','/ˌhɜːrmɪˈnjuːtɪks/','noun','해석학','The theory and methodology of interpretation, especially of texts.','Biblical {hermeneutics} has shaped centuries of scholarship.','성경 해석학은 수 세기의 학문을 형성해왔어요.','hermeneutics','C1','humanities',2,'hermeneutics interpretation text philosophy'),
('w_humanities_C1_02','semiotics','/ˌsiːmiˈɒtɪks/','noun','기호학','The study of signs and symbols and their use or interpretation.','{Semiotics} helps us decode the hidden meaning of images.','기호학은 이미지의 숨겨진 의미를 해독하는 데 도움이 돼요.','semiotics','C1','humanities',2,'semiotics signs symbols meaning'),
('w_humanities_C1_03','intertextuality','/ˌɪntərtekstʃuˈælɪti/','noun','상호텍스트성','The relationship between texts, especially through allusion or quotation.','The novel''s {intertextuality} with Homer enriches its meaning.','호머와의 상호텍스트성이 소설의 의미를 풍부하게 해요.','intertextuality','C1','humanities',1,'intertextuality reference allusion text'),
('w_humanities_C1_04','deconstruction','/ˌdiːkənˈstrʌkʃən/','noun','해체주의','A method of analysis that challenges fixed meanings in texts.','Derrida''s {deconstruction} revolutionized literary criticism.','데리다의 해체주의는 문학 비평을 혁신했어요.','deconstruction','C1','humanities',2,'deconstruction theory text meaning'),
('w_humanities_C1_05','poststructuralism','/ˌpoʊstˈstrʌktʃərəlɪzəm/','noun','포스트구조주의','A theory challenging the stable meanings proposed by structuralism.','{Poststructuralism} questions whether texts have fixed meanings.','포스트구조주의는 텍스트에 고정된 의미가 있는지 의문을 제기해요.','poststructuralism','C1','humanities',2,'poststructuralism theory language text'),
('w_humanities_C1_06','phenomenology','/fɪˌnɒmɪˈnɒlədʒi/','noun','현상학','The philosophical study of structures of experience and consciousness.','Husserl''s {phenomenology} influenced literary theory deeply.','후설의 현상학은 문학 이론에 깊은 영향을 미쳤어요.','phenomenology','C1','humanities',2,'phenomenology experience consciousness philosophy'),
('w_humanities_C1_07','dialectic','/ˌdaɪəˈlektɪk/','noun','변증법','A method of argument through contradictory ideas to arrive at truth.','Hegel''s {dialectic} of thesis and antithesis shapes critical thought.','헤겔의 변증법은 비판적 사고를 형성해요.','dialectic','C1','humanities',2,'dialectic philosophy argument truth'),
('w_humanities_C1_08','mimesis','/mɪˈmiːsɪs/','noun','미메시스, 모방','The imitation or representation of the real world in art.','Aristotle''s concept of {mimesis} remains foundational to literary theory.','아리스토텔레스의 미메시스 개념은 문학 이론의 기초로 남아 있어요.','mimesis','C1','humanities',2,'mimesis imitation reality representation'),
('w_humanities_C1_09','sublime','/səˈblaɪm/','noun / adjective','숭고함; 숭고한','An aesthetic quality of greatness beyond beauty.','Burke''s essay on the {sublime} influenced Romantic poets.','버크의 숭고함에 관한 에세이는 낭만파 시인들에게 영향을 미쳤어요.','sublime','C1','humanities',2,'sublime beauty awe nature grandeur'),
('w_humanities_C1_10','aporia','/əˈpɔːriə/','noun','아포리아, 논리적 난제','A state of irresolvable doubt or contradiction in a text.','Deconstructive readings often expose the {aporia} in classic texts.','해체주의적 독해는 종종 고전 텍스트의 아포리아를 드러내요.','aporia','C1','humanities',3,'aporia paradox contradiction philosophy'),
('w_humanities_C1_11','hegemony','/hɪˈdʒemənɪ/','noun','헤게모니, 패권','Dominance of one social group or nation over others.','Gramsci''s concept of cultural {hegemony} is central to critical theory.','그람시의 문화적 헤게모니 개념은 비판 이론의 핵심이에요.','hegemony','C1','humanities',2,'hegemony power culture society'),
('w_humanities_C1_12','ideology','/ˌaɪdiˈɒlədʒi/','noun','이데올로기','A system of ideas and ideals forming the basis of a theory.','Literary texts both reflect and reinforce dominant {ideology}.','문학 텍스트는 지배적 이데올로기를 반영하고 강화해요.','ideology','C1','humanities',2,'ideology belief system politics'),
('w_humanities_C1_13','discourse','/ˈdɪskɔːrs/','noun','담론, 담화','A mode of thinking or talking about a topic in a social context.','Foucault analyzed the {discourse} of power in society.','푸코는 사회에서 권력의 담론을 분석했어요.','discourse','C1','humanities',2,'discourse language power society'),
('w_humanities_C1_14','polyphony','/pəˈlɪfəni/','noun','다성(多聲), 폴리포니','A narrative technique using multiple voices or perspectives.','Bakhtin celebrated the {polyphony} of Dostoevsky''s novels.','바흐친은 도스토옙스키 소설의 다성성을 찬양했어요.','polyphony','C1','humanities',2,'polyphony voices narrative multiple'),
('w_humanities_C1_15','metafiction','/ˈmetəˌfɪkʃən/','noun','메타픽션','Fiction that self-consciously refers to its own fictional nature.','{Metafiction} blurs the boundary between story and reality.','메타픽션은 이야기와 현실의 경계를 흐려요.','metafiction','C1','humanities',2,'metafiction self-referential story reality'),
('w_humanities_C1_16','subaltern','/ˈsʌbəltɜːrn/','noun','서발턴 (하위 주체)','A marginalized social group excluded from dominant discourse.','Spivak asked whether the {subaltern} can speak.','스피박은 서발턴이 말할 수 있는지 물었어요.','subaltern','C1','humanities',3,'subaltern marginalized voice power'),
('w_humanities_C1_17','canon','/ˈkænən/','noun','문학 정전, 캐논','The body of books regarded as authoritative in a literary tradition.','Expanding the literary {canon} has been a key feminist goal.','문학 정전을 확장하는 것은 주요 페미니즘 목표였어요.','canon','C1','humanities',2,'canon classic literature tradition'),
('w_humanities_C1_18','structuralism','/ˈstrʌktʃərəlɪzəm/','noun','구조주의','An approach analyzing elements in relation to the broader system.','Saussure''s linguistics laid the foundation for {structuralism}.','소쉬르의 언어학은 구조주의의 기초를 놓았어요.','structuralism','C1','humanities',2,'structuralism theory language system'),
('w_humanities_C1_19','ambiguity','/ˌæmbɪˈɡjuːɪti/','noun','다의성, 모호성 (비평 용어)','The quality of being open to multiple interpretations in a literary text.','Empson identified seven types of {ambiguity} in poetry.','엠프슨은 시에서 일곱 가지 유형의 모호성을 발견했어요.','ambiguity','C1','humanities',2,'ambiguity interpretation meaning layers'),
('w_humanities_C1_20','trope','/troʊp/','noun','트로프, 수사적 형상','A figurative use of language; a recurring theme or device.','The "rags to riches" story is a well-worn literary {trope}.','신데렐라 스토리는 잘 알려진 문학적 트로프예요.','trope','C1','humanities',2,'trope figure rhetoric theme'),
('w_humanities_C1_21','episteme','/ˈepɪstiːm/','noun','에피스테메, 지식 체계','The set of ideas that defines knowledge in a given era (Foucault).','Foucault''s concept of {episteme} maps the limits of knowable thought.','푸코의 에피스테메 개념은 알 수 있는 사고의 한계를 그려요.','episteme','C1','humanities',3,'episteme knowledge era foucault'),
('w_humanities_C1_22','heteroglossia','/ˌhetərəˈɡlɒsiə/','noun','헤테로글로시아, 다언어성','The presence of multiple languages or voices in a text (Bakhtin).','Bakhtin valued {heteroglossia} as a sign of literary vitality.','바흐친은 헤테로글로시아를 문학적 활력의 징표로 여겼어요.','heteroglossia','C1','humanities',3,'heteroglossia voices language bakhtin'),
('w_humanities_C1_23','logocentrism','/ˈloʊɡoʊˌsentrɪzəm/','noun','로고스 중심주의','The assumption that language can fully represent thought (Derrida).','Derrida critiqued {logocentrism} as the foundation of Western metaphysics.','데리다는 로고스 중심주의를 서양 형이상학의 기초로 비판했어요.','logocentrism','C1','humanities',3,'logocentrism language meaning derrida'),
('w_humanities_C1_24','ontology','/ɒnˈtɒlədʒi/','noun','존재론','The branch of philosophy concerned with the nature of being.','The novel raises deep {ontology} questions about identity.','소설은 정체성에 대한 깊은 존재론적 질문을 제기해요.','ontology','C1','humanities',3,'ontology existence being philosophy'),
('w_humanities_C1_25','intertextual','/ˌɪntərˈtekstʃuəl/','adjective','상호텍스트적인','Relating to or involving connections between texts.','The poem is rich in {intertextual} references to the Bible.','이 시는 성경에 대한 상호텍스트적 언급이 풍부해요.','intertextual','C1','humanities',2,'intertextual reference allusion network'),
('w_humanities_C1_26','ecocriticism','/ˌiːkoʊˈkrɪtɪsɪzəm/','noun','생태비평','The study of literature in relation to the natural environment.','{Ecocriticism} examines how nature is represented in fiction.','생태비평은 소설에서 자연이 어떻게 표현되는지 살펴요.','ecocriticism','C1','humanities',3,'ecocriticism nature environment literature'),
('w_humanities_C1_27','postcolonialism','/ˌpoʊstˈkɒlənɪəlɪzəm/','noun','포스트식민주의','A field examining the cultural legacy of colonialism.','Chinua Achebe''s work is a cornerstone of {postcolonialism} studies.','치누아 아체베의 작품은 포스트식민주의 연구의 초석이에요.','postcolonialism','C1','humanities',2,'postcolonialism colonialism identity power'),
('w_humanities_C1_28','queer','/kwɪər/','adjective (literary theory)','퀴어 (이론 용어)','Relating to the examination of non-normative sexuality in literature.','A {queer} reading reveals the subtext of the Victorian novel.','퀴어 독해는 빅토리아 소설의 서브텍스트를 드러내요.','queer','C1','humanities',3,'queer theory identity literature subtext'),
('w_humanities_C1_29','narratology','/ˌnærəˈtɒlədʒi/','noun','서사학','The study of narrative structure and how it functions.','{Narratology} analyzes how stories are organized and told.','서사학은 이야기가 어떻게 구성되고 전달되는지 분석해요.','narratology','C1','humanities',2,'narratology structure story theory'),
('w_humanities_C1_30','lyric','/ˈlɪrɪk/','noun / adjective','서정시; 서정적인','A short poem expressing the writer''s emotions; intensely personal.','Keats is admired for his rich {lyric} poetry.','키츠는 풍부한 서정시로 존경받아요.','lyric','C1','humanities',2,'lyric poetry emotion personal'),
('w_humanities_C1_31','pathos','/ˈpeɪθɒs/','noun','파토스, 연민감','A quality in a work evoking pity or sadness.','The final scene is full of {pathos}.','마지막 장면은 파토스로 가득해요.','pathos','C1','humanities',2,'pathos emotion pity tragedy'),
('w_humanities_C1_32','lacuna','/ləˈkjuːnə/','noun','공백, 빠진 부분','A gap or missing portion in a text or argument.','The {lacuna} in the manuscript has puzzled scholars for decades.','원고의 공백은 수십 년간 학자들을 혼란스럽게 했어요.','lacuna','C1','humanities',3,'lacuna gap missing text'),
('w_humanities_C1_33','poetics','/poʊˈetɪks/','noun','시학, 시 이론','The theory and practice of literary composition.','Aristotle''s {poetics} defined tragedy for centuries.','아리스토텔레스의 시학은 수 세기 동안 비극을 정의했어요.','poetics','C1','humanities',2,'poetics theory aristotle literary'),
('w_humanities_C1_34','deixis','/ˈdaɪksɪs/','noun','직시(直示), 지시 표현','Words or phrases that require contextual information to interpret.','Understanding {deixis} is key to analyzing a dramatic monologue.','직시 표현을 이해하는 것은 극적 독백 분석의 핵심이에요.','deixis','C1','humanities',3,'deixis context language reference'),
('w_humanities_C1_35','ekphrasis','/ˈekfrəsɪs/','noun','에크프라시스','A vivid verbal description of a visual work of art.','Keats'' Ode on a Grecian Urn is a famous example of {ekphrasis}.','키츠의 그리스 항아리에 부치는 송시는 에크프라시스의 유명한 예예요.','ekphrasis','C1','humanities',3,'ekphrasis art description poem visual');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_humanities_C2_01','logocentrism','/ˈloʊɡoʊˌsentrɪzəm/','noun','로고스 중심주의','Derrida''s term for the privileging of speech over writing in Western thought.','The entire deconstructive project aims to displace {logocentrism}.','해체주의 프로젝트 전체는 로고스 중심주의를 대체하는 것을 목표로 해요.','logocentrism','C2','humanities',2,'logocentrism derrida language text'),
('w_humanities_C2_02','différance','/ˌdiːfəˈrɑːns/','noun','디페랑스','Derrida''s neologism combining "differ" and "defer" to describe the endless play of signification.','The concept of {différance} undermines the possibility of fixed meaning.','디페랑스 개념은 고정된 의미의 가능성을 허물어요.','différance','C2','humanities',2,'différance derrida meaning sign'),
('w_humanities_C2_03','palimpsest','/ˈpælɪmpsest/','noun','팔림프세스트 (겹쳐 쓴 양피지)','A manuscript on which writing has been effaced and replaced; a text with layered meanings.','The novel reads as a cultural {palimpsest}, each layer revealing a different history.','소설은 문화적 팔림프세스트처럼 읽히며, 각 층이 다른 역사를 드러내요.','palimpsest','C2','humanities',2,'palimpsest layers text history'),
('w_humanities_C2_04','bricolage','/ˌbrɪkəˈlɑːʒ/','noun','브리콜라주','The construction of a work from diverse available resources.','Postmodern art is characterized by its use of {bricolage}.','포스트모던 예술은 브리콜라주 사용이 특징이에요.','bricolage','C2','humanities',2,'bricolage collage assembly postmodern'),
('w_humanities_C2_05','heteroglossia','/ˌhetərəˈɡlɒsiə/','noun','헤테로글로시아','Bakhtin''s term for the coexistence of multiple voices within a single text.','The polyphonic novel depends on {heteroglossia} to generate meaning.','다성 소설은 의미를 생성하기 위해 헤테로글로시아에 의존해요.','heteroglossia','C2','humanities',3,'heteroglossia bakhtin voices novel'),
('w_humanities_C2_06','chronotope','/ˈkrɒnətəʊp/','noun','크로노토프 (시공간 형상)','Bakhtin''s term for the way time and space are represented in literature.','The road {chronotope} is common in adventure narratives.','도로 크로노토프는 모험 서사에서 흔히 나타나요.','chronotope','C2','humanities',3,'chronotope time space bakhtin'),
('w_humanities_C2_07','defamiliarization','/ˌdiːfəˌmɪliəraɪˈzeɪʃən/','noun','낯설게 하기 (오스트라네니에)','Shklovsky''s term for making familiar things seem strange to renew perception.','Kafka achieves {defamiliarization} by treating the absurd as mundane.','카프카는 부조리한 것을 평범하게 다룸으로써 낯설게 하기를 달성해요.','defamiliarization','C2','humanities',2,'defamiliarization shklovsky strange form'),
('w_humanities_C2_08','rhizome','/ˈraɪzoʊm/','noun','리좀 (철학 개념)','Deleuze and Guattari''s model of culture as non-hierarchical and multi-directional.','The internet can be understood as a cultural {rhizome}.','인터넷은 문화적 리좀으로 이해될 수 있어요.','rhizome','C2','humanities',3,'rhizome network deleuze structure'),
('w_humanities_C2_09','hypertext','/ˈhaɪpərtekst/','noun','하이퍼텍스트','Text containing links to other texts; also a postmodern narrative form.','{Hypertext} fiction challenges linear reading conventions.','하이퍼텍스트 소설은 선형적 독해 관습에 도전해요.','hypertext','C2','humanities',2,'hypertext digital link narrative'),
('w_humanities_C2_10','episteme','/ˈepɪstiːm/','noun','에피스테메 (푸코 개념)','The underlying structure of knowledge that defines what counts as truth in an era.','Each historical period has its own {episteme} governing what can be known.','각 역사적 시기에는 알 수 있는 것을 지배하는 에피스테메가 있어요.','episteme','C2','humanities',2,'episteme knowledge foucault era'),
('w_humanities_C2_11','abjection','/æbˈdʒekʃən/','noun','아브젝시옹 (크리스테바 개념)','Julia Kristeva''s concept of the horror produced by the breakdown of the self/other boundary.','Gothic literature often exploits {abjection} to unsettle the reader.','고딕 문학은 종종 독자를 불안하게 하기 위해 아브젝시옹을 이용해요.','abjection','C2','humanities',3,'abjection kristeva horror body'),
('w_humanities_C2_12','pharmakon','/ˈfɑːrməkɒn/','noun','파르마콘 (데리다 개념)','Derrida''s term for writing as both remedy and poison, undoing binary oppositions.','Plato''s {pharmakon} is central to Derrida''s critique of Western philosophy.','플라톤의 파르마콘은 서양 철학에 대한 데리다의 비판의 핵심이에요.','pharmakon','C2','humanities',3,'pharmakon derrida writing remedy'),
('w_humanities_C2_13','suture','/ˈsuːtʃər/','noun','봉합 (영화·문학 이론)','A psychoanalytic film theory term for the process by which subjects are bound into discourse.','Narrative {suture} positions the reader as a unified subject.','서사적 봉합은 독자를 통합된 주체로 자리매김해요.','suture','C2','humanities',3,'suture narrative subject theory'),
('w_humanities_C2_14','apophenia','/ˌæpəˈfiːniə/','noun','아포페니아 (무관한 것의 연결)','The tendency to perceive meaningful connections between unrelated things.','Postmodern readings may tip into {apophenia} if taken too far.','포스트모던 독해는 너무 나가면 아포페니아에 빠질 수 있어요.','apophenia','C2','humanities',3,'apophenia pattern meaning connection'),
('w_humanities_C2_15','parataxis','/ˌpærəˈtæksɪs/','noun','병렬 구문 배열','The placing of clauses or phrases one after another without coordinating or subordinating connectives.','Hemingway''s famous style relies heavily on {parataxis}.','헤밍웨이의 유명한 문체는 병렬 구문에 크게 의존해요.','parataxis','C2','humanities',2,'parataxis syntax style sentence'),
('w_humanities_C2_16','catachresis','/ˌkætəˈkriːsɪs/','noun','카타크레시스 (무리한 비유)','The use of a word in an inappropriate context; a strained or mixed metaphor.','Spivak uses {catachresis} to reclaim and subvert colonial concepts.','스피박은 식민지 개념을 재전유하고 전복하기 위해 카타크레시스를 사용해요.','catachresis','C2','humanities',3,'catachresis metaphor misuse language'),
('w_humanities_C2_17','prolepsis','/proʊˈlepsɪs/','noun','프롤렙시스 (예기)','A narrative technique anticipating a future event; also a rhetorical device.','The opening sentence works as a subtle {prolepsis} for the ending.','첫 문장은 결말의 미묘한 프롤렙시스로 기능해요.','prolepsis','C2','humanities',3,'prolepsis anticipation future narrative'),
('w_humanities_C2_18','synecdoche','/sɪˈnekdəki/','noun','제유법','A figure of speech where a part represents the whole or vice versa.','The phrase "hired hands" is a classic example of {synecdoche}.','hired hands라는 표현은 제유법의 고전적인 예예요.','synecdoche','C2','humanities',2,'synecdoche figure speech part whole'),
('w_humanities_C2_19','diegesis','/ˌdaɪəˈdʒiːsɪs/','noun','디에게시스 (서사 세계)','The narrative world in which the story takes place; also the act of telling.','Music that exists within the story''s world is called diegetic; outside it, non-{diegesis}.','이야기 세계 안에 존재하는 음악은 디에제틱, 밖은 비디에게시스라고 해요.','diegesis','C2','humanities',3,'diegesis narrative world story'),
('w_humanities_C2_20','metalepsis','/ˌmetəˈlepsɪs/','noun','메탈렙시스 (서사 층위 침범)','The transgression of narrative levels, e.g. a character addressing the reader.','When the protagonist winks at the reader, it is a form of {metalepsis}.','주인공이 독자에게 윙크할 때 메탈렙시스의 한 형태예요.','metalepsis','C2','humanities',3,'metalepsis narrative metafiction layers'),
('w_humanities_C2_21','enargeia','/ɛˈnɑːrdʒiə/','noun','에나르게이아 (생생한 묘사)','Vivid, lively description that creates a mental picture for the audience.','The battle scene achieves powerful {enargeia} through sensory detail.','전투 장면은 감각적 디테일을 통해 강력한 에나르게이아를 달성해요.','enargeia','C2','humanities',3,'enargeia vivid description rhetoric'),
('w_humanities_C2_22','dispositio','/ˌdɪspəˈzɪtiːoʊ/','noun','디스포지티오 (수사적 배열)','The arrangement and structuring of a rhetorical composition.','Classical oratory depends on {dispositio} to guide the audience.','고전 수사는 청중을 이끌기 위해 디스포지티오에 의존해요.','dispositio','C2','humanities',3,'dispositio rhetoric structure arrangement'),
('w_humanities_C2_23','anagnorisis','/ˌænæɡˈnɒrɪsɪs/','noun','아나그노리시스 (재인식)','The moment of recognition or discovery in a drama or narrative.','The {anagnorisis} in Oedipus Rex is among the most devastating in literature.','오이디푸스 왕의 아나그노리시스는 문학에서 가장 충격적인 것 중 하나예요.','anagnorisis','C2','humanities',2,'anagnorisis recognition moment drama'),
('w_humanities_C2_24','peripeteia','/ˌperɪpɪˈteɪə/','noun','페리페테이아 (반전)','A sudden reversal of fortune in a narrative, especially tragedy.','The {peripeteia} in Hamlet occurs when the hero kills Polonius by mistake.','햄릿의 페리페테이아는 주인공이 실수로 폴로니우스를 죽일 때 일어나요.','peripeteia','C2','humanities',2,'peripeteia reversal tragedy drama'),
('w_humanities_C2_25','deus ex machina','/ˌdeɪʊs eks ˈmɑːkɪnə/','noun','데우스 엑스 마키나','An unexpected power or event saving a seemingly hopeless situation.','Critics dismissed the ending as a lazy {deus ex machina}.','비평가들은 그 결말을 게으른 데우스 엑스 마키나로 일축했어요.','deus ex machina','C2','humanities',2,'deus ex machina plot rescue ending'),
('w_humanities_C2_26','acousmatic','/ˌækuːzˈmætɪk/','adjective','아쿠스마틱 (보이지 않는 소리)','Referring to sound heard without a visible source; extended to voice in narrative.','The narrator''s {acousmatic} presence creates an eerie atmosphere.','화자의 아쿠스마틱 존재감이 섬뜩한 분위기를 만들어요.','acousmatic','C2','humanities',3,'acousmatic sound voice invisible'),
('w_humanities_C2_27','locution','/loʊˈkjuːʃən/','noun','발화 행위 (화행론)','In speech act theory, the utterance of a statement.','Austin distinguished {locution} from illocution and perlocution.','오스틴은 발화 행위를 발화 수반 행위와 발화 효과 행위로 구별했어요.','locution','C2','humanities',3,'locution speech act language theory'),
('w_humanities_C2_28','apophasis','/əˈpɒfəsɪs/','noun','아포파시스 (부정을 통한 언급)','A rhetorical device where something is mentioned by denying it will be mentioned.','Using {apophasis}, he condemned the scandal without naming it.','아포파시스를 사용해 그는 스캔들을 명명하지 않고 비난했어요.','apophasis','C2','humanities',3,'apophasis rhetoric denial mention'),
('w_humanities_C2_29','hypotaxis','/ˌhaɪpəˈtæksɪs/','noun','종속 구문 배열','The use of subordinating conjunctions and clauses to show complex relationships.','Henry James''s prose is famous for its elaborate {hypotaxis}.','헨리 제임스의 산문은 정교한 종속 구문으로 유명해요.','hypotaxis','C2','humanities',3,'hypotaxis syntax complex sentence'),
('w_humanities_C2_30','cathartic','/kəˈθɑːrtɪk/','adjective','카타르시스를 주는','Providing psychological relief through the open expression of strong emotion.','The final scene is intensely {cathartic} for the audience.','마지막 장면은 관객에게 강렬한 카타르시스를 줘요.','cathartic','C2','humanities',2,'cathartic release emotion healing'),
('w_humanities_C2_31','anxious object','/ˈæŋkʃəs ˈɒbdʒɪkt/','noun','불안한 대상 (미술 비평)','Harold Rosenberg''s term for art that questions its own status as art.','The novel functions as an {anxious object}, unsure of its own genre.','소설은 자신의 장르에 대해 불확실한 불안한 대상으로 기능해요.','anxious object','C2','humanities',3,'anxious object art form genre'),
('w_humanities_C2_32','perlocution','/ˌpɜːrləˈkjuːʃən/','noun','발화 효과 행위','The effect of an utterance on the listener beyond its literal meaning.','Great oratory achieves its goals through {perlocution}.','훌륭한 웅변은 발화 효과 행위를 통해 목표를 달성해요.','perlocution','C2','humanities',3,'perlocution effect speech language'),
('w_humanities_C2_33','dialogism','/daɪˈæləɡɪzəm/','noun','대화주의 (바흐친)','Bakhtin''s theory that all utterances are inherently dialogic.','{Dialogism} challenges the notion of the solitary author.','대화주의는 고독한 작가의 개념에 도전해요.','dialogism','C2','humanities',2,'dialogism bakhtin dialogue intertextual'),
('w_humanities_C2_34','negative capability','/ˌneɡətɪv keɪpəˈbɪlɪti/','noun','부정적 수용 능력 (키츠)','Keats''s term for the ability to remain in uncertainty without reaching for fact or reason.','Great poets possess the {negative capability} to dwell in mystery.','위대한 시인은 신비 속에 머무는 부정적 수용 능력을 지녀요.','negative capability','C2','humanities',2,'negative capability keats poetry uncertainty'),
('w_humanities_C2_35','uncanny','/ʌnˈkæni/','adjective / noun','언캐니 (낯설면서 친숙한 공포)','Freud''s concept of the strangely familiar; the disturbing feeling caused by something both familiar and strange.','The gothic mansion creates a profound sense of the {uncanny}.','고딕 저택은 깊은 언캐니 감각을 만들어요.','uncanny','C2','humanities',2,'uncanny freud strange familiar horror');
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_humanities_A1_01','Have you read any good books lately?','최근에 좋은 책 읽었어요?','read any good books','lately는 "최근에"라는 의미로 현재완료와 잘 어울려요.','독서 화제','A1','humanities','pattern',NULL,1),
('s_humanities_A1_02','What is your favorite book?','가장 좋아하는 책이 뭐예요?','your favorite book','What is your favorite ~?는 상대의 취향을 묻는 가장 기본적인 패턴이에요.','취향 묻기','A1','humanities','pattern',NULL,2),
('s_humanities_A1_03','I really like this story.','이 이야기가 정말 좋아요.','really like this story','really를 넣으면 감정을 더 강하게 표현할 수 있어요.','감상 표현','A1','humanities','pattern',NULL,3),
('s_humanities_A1_04','Can you tell me the name of the book?','책 제목을 알려줄 수 있어요?','tell me the name','Can you ~?는 A1 수준에서 가장 자연스러운 요청 표현이에요.','제목 묻기','A1','humanities','pattern',NULL,4),
('s_humanities_A1_05','I want to read more books in English.','영어로 된 책을 더 읽고 싶어요.','read more books in English','I want to ~는 희망과 목표를 간단하게 표현하는 패턴이에요.','학습 목표','A1','humanities','pattern',NULL,5),
('s_humanities_A1_06','This poem is very beautiful.','이 시는 정말 아름다워요.','very beautiful','This ~ is very ~. 구조는 감상을 간결하게 전달해요.','시 감상','A1','humanities','pattern',NULL,6),
('s_humanities_A1_07','Do you like to read stories?','이야기 읽는 걸 좋아하세요?','Do you like to read','Do you like to ~?는 취미를 묻는 가장 쉬운 표현이에요.','취미 묻기','A1','humanities','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_humanities_A2_01','Who is your favorite author and why?','가장 좋아하는 작가는 누구이고 왜 그런가요?','favorite author and why','and why?를 붙이면 단순한 정보 교환을 넘어 의견 공유를 유도해요.','작가 추천','A2','humanities','pattern',NULL,8),
('s_humanities_A2_02','I enjoy reading mystery novels.','저는 추리 소설 읽는 걸 즐겨요.','enjoy reading mystery novels','enjoy + -ing는 취미 표현의 핵심 패턴이에요.','장르 표현','A2','humanities','pattern',NULL,9),
('s_humanities_A2_03','This book is based on a true story.','이 책은 실화를 바탕으로 했어요.','based on a true story','based on ~은 영화·책 소개에서 매우 자주 쓰여요.','책 소개','A2','humanities','pattern',NULL,10),
('s_humanities_A2_04','Have you heard of this author before?','이 작가에 대해 들어본 적 있어요?','Have you heard of','Have you heard of ~?는 상대의 지식을 확인하는 자연스러운 표현이에요.','작가 소개','A2','humanities','pattern',NULL,11),
('s_humanities_A2_05','What kind of books do you usually read?','보통 어떤 종류의 책을 읽으세요?','What kind of books','What kind of ~?는 종류나 유형을 묻는 범용 패턴이에요.','장르 묻기','A2','humanities','pattern',NULL,12),
('s_humanities_A2_06','I prefer historical fiction to fantasy.','저는 판타지보다 역사 소설을 더 좋아해요.','prefer ~ to ~','prefer A to B 패턴으로 두 가지를 자연스럽게 비교할 수 있어요.','장르 비교','A2','humanities','pattern',NULL,13),
('s_humanities_A2_07','The main character in this novel is very interesting.','이 소설의 주인공이 매우 흥미로워요.','main character ~ very interesting','The main character is ~로 인물을 소개하는 기본 표현이에요.','인물 소개','A2','humanities','pattern',NULL,14);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_humanities_B1_01','The author uses symbolism to convey the theme of loss.','작가는 상실의 주제를 전달하기 위해 상징주의를 사용해요.','uses symbolism to convey','use A to do B 패턴은 수단과 목적을 연결하는 핵심 분석 표현이에요.','문학 분석','B1','humanities','pattern',NULL,15),
('s_humanities_B1_02','From whose perspective is the story told?','이야기는 누구의 관점에서 서술되나요?','From whose perspective','From whose perspective is ~?는 서술 시점을 묻는 정확한 표현이에요.','서술 시점','B1','humanities','pattern',NULL,16),
('s_humanities_B1_03','How does the setting influence the characters'' behavior?','배경이 등장인물들의 행동에 어떤 영향을 미치나요?','setting influence the characters'' behavior','How does X influence Y? 패턴은 원인-결과 관계를 탐구해요.','배경 분석','B1','humanities','pattern',NULL,17),
('s_humanities_B1_04','What do you think the writer is trying to say?','작가가 무엇을 말하려 한다고 생각하세요?','what the writer is trying to say','What do you think ~?는 독자의 해석을 이끌어내는 토론 유도 표현이에요.','주제 토론','B1','humanities','pattern',NULL,18),
('s_humanities_B1_05','The conflict between tradition and modernity runs throughout the novel.','전통과 근대성 사이의 갈등이 소설 전반에 걸쳐 흐르고 있어요.','conflict between ~ runs throughout','run throughout은 "전반에 걸쳐 이어지다"는 뜻의 문학 분석 필수 표현이에요.','주제 분석','B1','humanities','pattern',NULL,19),
('s_humanities_B1_06','I found the narrator unreliable because his account kept changing.','화자의 설명이 계속 바뀌어서 신뢰하기 어렵다고 느꼈어요.','narrator unreliable ~ kept changing','kept + -ing는 반복적인 행동을 묘사하는 자연스러운 패턴이에요.','화자 분석','B1','humanities','pattern',NULL,20),
('s_humanities_B1_07','Can you give an example from the text to support your idea?','당신의 생각을 뒷받침할 텍스트에서의 예시를 들어줄 수 있나요?','give an example from the text to support','give an example to support ~는 증거 기반 토론의 핵심 요청 표현이에요.','근거 요청','B1','humanities','pattern',NULL,21);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_humanities_B2_01','The irony lies in the gap between what the narrator says and what actually happens.','아이러니는 화자가 말하는 것과 실제로 일어나는 것 사이의 간극에 있어요.','irony lies in the gap between','The irony lies in ~은 아이러니를 정밀하게 분석하는 비평 표현이에요.','아이러니 분석','B2','humanities','pattern',NULL,22),
('s_humanities_B2_02','One could argue that the novel is more of an allegory than a realist text.','이 소설은 사실주의 텍스트라기보다 알레고리에 가깝다고 주장할 수 있어요.','One could argue that','One could argue that ~은 학술 에세이와 비평에서 쓰는 격식 있는 주장 패턴이에요.','비평 주장','B2','humanities','pattern',NULL,23),
('s_humanities_B2_03','The motif of water recurs throughout the text, suggesting purification.','물의 모티프가 텍스트 전반에 반복되며 정화를 암시해요.','motif ~ recurs throughout ~ suggesting','recurs throughout ~ suggesting은 모티프 분석의 정형화된 표현이에요.','모티프 분석','B2','humanities','pattern',NULL,24),
('s_humanities_B2_04','The subtext reveals a deep anxiety about social class.','서브텍스트는 사회 계층에 대한 깊은 불안을 드러내요.','subtext reveals a deep anxiety about','The subtext reveals ~ 패턴은 텍스트의 숨겨진 층위를 드러낼 때 써요.','서브텍스트','B2','humanities','pattern',NULL,25),
('s_humanities_B2_05','Reading the novel against its historical context changes how we interpret the ending.','소설을 역사적 맥락에 비추어 읽으면 결말 해석이 달라져요.','Reading ~ against its historical context','reading X against Y 구조는 텍스트를 외부 맥락과 연결하는 비평 방법이에요.','맥락 비평','B2','humanities','pattern',NULL,26),
('s_humanities_B2_06','The satirical tone forces the reader to question assumptions they might otherwise take for granted.','풍자적 어조는 독자로 하여금 당연하게 여길 수 있는 전제를 의심하게 만들어요.','satirical tone forces the reader to question','force the reader to ~는 텍스트가 독자에게 미치는 효과를 설명하는 표현이에요.','풍자 분석','B2','humanities','pattern',NULL,27),
('s_humanities_B2_07','The paradox at the heart of the novel is that freedom leads to isolation.','소설의 핵심에 있는 역설은 자유가 고립으로 이어진다는 것이에요.','paradox at the heart of the novel','at the heart of ~은 핵심 주제나 역설을 강조하는 비평 표현이에요.','역설 분석','B2','humanities','pattern',NULL,28);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_humanities_C1_01','A hermeneutic approach asks not what the text means, but how meaning is produced.','해석학적 접근은 텍스트가 무엇을 의미하는지가 아니라 의미가 어떻게 생산되는지를 묻죠.','hermeneutic approach asks not ~ but how','not ~ but how 구조는 관점의 전환을 명확히 드러내는 학술 표현이에요.','해석학 논의','C1','humanities','pattern',NULL,29),
('s_humanities_C1_02','Through a semiotic lens, the white dress signifies far more than purity.','기호학적 렌즈를 통하면, 흰 드레스는 순결 이상의 훨씬 많은 것을 의미해요.','Through a semiotic lens ~ signifies far more than','through a ~ lens는 이론적 프레임으로 분석함을 나타내는 표현이에요.','기호학 분석','C1','humanities','pattern',NULL,30),
('s_humanities_C1_03','Intertextuality suggests that no text is fully autonomous; all writing responds to what came before.','상호텍스트성은 완전히 자율적인 텍스트는 없으며, 모든 글쓰기는 이전 것에 반응한다는 것을 시사해요.','Intertextuality suggests that no text is fully autonomous','no text is fully autonomous는 상호텍스트성의 핵심 명제를 요약해요.','상호텍스트성','C1','humanities','pattern',NULL,31),
('s_humanities_C1_04','Deconstruction does not destroy meaning; it reveals the instability that was always already there.','해체주의는 의미를 파괴하지 않고, 항상 이미 그곳에 있던 불안정성을 드러내요.','always already there','always already는 데리다 이론의 핵심 표현으로 현재 안에 과거가 내포됨을 나타내요.','해체주의 이론','C1','humanities','pattern',NULL,32),
('s_humanities_C1_05','Phenomenological criticism foregrounds the reader''s lived experience of the text.','현상학적 비평은 텍스트에 대한 독자의 생생한 경험을 전면에 부각시켜요.','foregrounds the reader''s lived experience','foreground는 무언가를 중심으로 가져온다는 문학 이론 용어예요.','현상학 비평','C1','humanities','pattern',NULL,33),
('s_humanities_C1_06','Bakhtin''s concept of polyphony challenges the idea of a single authoritative voice in the novel.','바흐친의 다성 개념은 소설에서 단일하고 권위적인 목소리라는 생각에 도전해요.','polyphony challenges the idea of a single authoritative voice','challenge the idea of ~는 지배적 개념을 문제 삼는 학술 표현이에요.','다성 이론','C1','humanities','pattern',NULL,34),
('s_humanities_C1_07','The sublime, as Burke defines it, involves a blend of terror and awe that exceeds rational comprehension.','버크가 정의한 숭고함은 이성적 이해를 초월하는 공포와 경외의 혼합을 포함해요.','involves a blend of ~ that exceeds rational comprehension','exceed rational comprehension은 숭고 미학을 설명하는 핵심 구절이에요.','숭고 미학','C1','humanities','pattern',NULL,35);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_humanities_C2_01','Différance operates as the ungraspable condition of possibility for all meaning.','디페랑스는 모든 의미의 가능성에 대한 파악 불가능한 조건으로 작동해요.','operates as the ungraspable condition of possibility','operate as ~는 어떤 개념이 어떤 역할을 하는지 설명하는 학술 표현이에요.','해체 이론','C2','humanities','pattern',NULL,36),
('s_humanities_C2_02','The palimpsest as a metaphor invites us to read the text''s silences as much as its statements.','팔림프세스트를 은유로 취하면, 텍스트의 진술만큼 침묵도 읽으라는 초대가 돼요.','invites us to read the text''s silences as much as','as much as는 두 요소를 동등하게 취급하라는 요청을 나타내요.','팔림프세스트 이론','C2','humanities','pattern',NULL,37),
('s_humanities_C2_03','Defamiliarization, according to the Russian Formalists, is the very purpose of literary language.','러시아 형식주의자들에 따르면, 낯설게 하기는 문학적 언어의 바로 그 목적이에요.','the very purpose of literary language','the very ~는 강조 표현으로, 그것 자체가 핵심임을 나타내요.','형식주의 이론','C2','humanities','pattern',NULL,38),
('s_humanities_C2_04','As a rhizome, the text resists any single origin or fixed endpoint of meaning.','리좀으로서 텍스트는 어떠한 단일한 기원이나 고정된 의미의 종착점에도 저항해요.','resists any single origin or fixed endpoint','resist any single ~는 다원성과 열린 구조를 강조할 때 쓰는 표현이에요.','리좀 이론','C2','humanities','pattern',NULL,39),
('s_humanities_C2_05','Heteroglossia ensures that the novel can never be reduced to a single ideological position.','헤테로글로시아는 소설이 결코 단일한 이데올로기적 입장으로 환원될 수 없음을 보장해요.','can never be reduced to a single ideological position','be reduced to ~는 복잡성을 단순화하는 환원주의에 저항할 때 쓰는 표현이에요.','다성 이론','C2','humanities','pattern',NULL,40),
('s_humanities_C2_06','The chronotope of the threshold marks a liminal space where identity is suspended between states.','문지방의 크로노토프는 정체성이 두 상태 사이에 유예되는 경계적 공간을 표시해요.','marks a liminal space where identity is suspended between states','liminal space ~ suspended between states는 경계 공간의 특성을 묘사하는 핵심 표현이에요.','크로노토프 분석','C2','humanities','pattern',NULL,41),
('s_humanities_C2_07','Negative capability, for Keats, is not a weakness but the poet''s supreme capacity to inhabit uncertainty without discomfort.','키츠에게 부정적 수용 능력은 약점이 아니라 불편 없이 불확실성 안에 머무는 시인의 최고 능력이에요.','not a weakness but the poet''s supreme capacity to inhabit uncertainty','inhabit uncertainty는 불확실성을 견디는 것이 아닌 그 안에 사는 것을 나타내는 키츠 핵심 표현이에요.','낭만 시학','C2','humanities','pattern',NULL,42);
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_technology_A1_01','computer','/kəmˈpjuːtər/','noun','컴퓨터','An electronic device for storing and processing data.','I use a {computer} every day for work.','저는 매일 업무에 컴퓨터를 사용해요.','computer','A1','technology',1,'computer laptop desk office workspace'),
('w_technology_A1_02','phone','/foʊn/','noun','전화기, 휴대폰','A device used to make and receive calls.','My {phone} battery is running low.','제 휴대폰 배터리가 거의 없어요.','phone','A1','technology',1,'smartphone phone hand screen modern'),
('w_technology_A1_03','internet','/ˈɪntərnɛt/','noun','인터넷','A global system of connected computer networks.','You need the {internet} to watch streaming videos.','스트리밍 동영상을 보려면 인터넷이 필요해요.','internet','A1','technology',1,'internet wifi connection global network'),
('w_technology_A1_04','app','/æp/','noun','앱, 애플리케이션','A software program designed for a mobile device or computer.','I downloaded a new {app} for learning English.','영어 학습용 새 앱을 다운로드했어요.','app','A1','technology',1,'smartphone app icons colorful screen'),
('w_technology_A1_05','screen','/skriːn/','noun','화면, 스크린','The flat surface of a device that displays images.','The {screen} on this laptop is very bright.','이 노트북의 화면이 정말 밝아요.','screen','A1','technology',1,'laptop screen bright display modern'),
('w_technology_A1_06','game','/ɡeɪm/','noun','게임','An activity played for entertainment, often on a device.','This {game} is very popular with teenagers.','이 게임은 10대들 사이에서 매우 인기 있어요.','game','A1','technology',1,'video game controller playing fun'),
('w_technology_A1_07','email','/ˈiːmeɪl/','noun','이메일','A message sent electronically via the internet.','Please send me an {email} with the details.','세부 내용을 이메일로 보내주세요.','email','A1','technology',1,'email inbox laptop message office'),
('w_technology_A1_08','photo','/ˈfoʊtoʊ/','noun','사진','An image taken with a camera or phone.','She took a {photo} of the sunset.','그녀는 일몰 사진을 찍었어요.','photo','A1','technology',1,'photo camera taking picture outdoor'),
('w_technology_A1_09','video','/ˈvɪdioʊ/','noun','동영상, 비디오','A recording of moving images.','I watched a {video} about cooking online.','온라인에서 요리에 관한 동영상을 봤어요.','video','A1','technology',1,'video watching screen online streaming'),
('w_technology_A1_10','button','/ˈbʌtən/','noun','버튼','A small control pressed to operate a device.','Press the {button} to turn on the device.','기기를 켜려면 버튼을 누르세요.','button','A1','technology',1,'button press device power control'),
('w_technology_A1_11','mouse','/maʊs/','noun','마우스','A handheld device used to control a computer cursor.','Move the {mouse} to the left to go back.','뒤로 가려면 마우스를 왼쪽으로 움직이세요.','mouse','A1','technology',2,'computer mouse desk workspace cursor'),
('w_technology_A1_12','keyboard','/ˈkiːbɔːrd/','noun','키보드','A set of keys used to type on a computer.','I need a new {keyboard} because some keys are broken.','몇 개의 키가 고장나서 새 키보드가 필요해요.','keyboard','A1','technology',2,'keyboard typing computer office desk'),
('w_technology_A1_13','cable','/ˈkeɪbəl/','noun','케이블, 선','A thick wire used to connect devices.','I forgot to bring the charging {cable}.','충전 케이블을 가져오는 걸 잊었어요.','cable','A1','technology',2,'cable wire charging power connect'),
('w_technology_A1_14','charge','/tʃɑːrdʒ/','verb','충전하다','To put electrical power into a battery.','I need to {charge} my phone before we leave.','떠나기 전에 휴대폰을 충전해야 해요.','charge','A1','technology',2,'phone charging cable power outlet'),
('w_technology_A1_15','print','/prɪnt/','verb','인쇄하다','To produce text or images on paper using a printer.','Can you {print} this document for me?','이 문서를 인쇄해 주실 수 있나요?','print','A1','technology',2,'printer printing document paper office'),
('w_technology_A1_16','send','/sɛnd/','verb','보내다','To cause something to go or be taken to a destination.','I will {send} you the file right away.','지금 바로 파일을 보내드릴게요.','send','A1','technology',2,'sending message email file share'),
('w_technology_A1_17','open','/ˈoʊpən/','verb','열다, 실행하다','To start a program or file on a computer.','{Open} the folder and find the document.','폴더를 열어서 문서를 찾아보세요.','Open','A1','technology',2,'opening folder file computer screen'),
('w_technology_A1_18','save','/seɪv/','verb','저장하다','To store data so it is not lost.','Don''t forget to {save} your work before closing.','닫기 전에 작업 내용을 저장하는 것을 잊지 마세요.','save','A1','technology',2,'save file computer document storage'),
('w_technology_A1_19','password','/ˈpæswɜːrd/','noun','비밀번호','A secret word used to gain access to a system.','Enter your {password} to log in.','로그인하려면 비밀번호를 입력하세요.','password','A1','technology',1,'password login security access lock'),
('w_technology_A1_20','click','/klɪk/','verb','클릭하다','To press a mouse button to select or activate something.','{Click} the icon to open the program.','프로그램을 열려면 아이콘을 클릭하세요.','Click','A1','technology',2,'clicking mouse cursor computer screen'),
('w_technology_A1_21','type','/taɪp/','verb','타이핑하다, 입력하다','To write by pressing keys on a keyboard.','Please {type} your name in the box.','박스에 이름을 입력해 주세요.','type','A1','technology',2,'typing keyboard hands fast writing'),
('w_technology_A1_22','search','/sɜːrtʃ/','verb','검색하다','To look for information, especially online.','You can {search} for anything on the internet.','인터넷에서 무엇이든 검색할 수 있어요.','search','A1','technology',1,'search bar google internet query'),
('w_technology_A1_23','tablet','/ˈtæblɪt/','noun','태블릿','A flat, portable device with a touchscreen.','She reads books on her {tablet} every night.','그녀는 매일 밤 태블릿으로 책을 읽어요.','tablet','A1','technology',2,'tablet ipad screen touch reading'),
('w_technology_A1_24','speaker','/ˈspiːkər/','noun','스피커','A device that converts electrical signals into sound.','The {speaker} on my phone is very loud.','제 휴대폰 스피커가 정말 크게 들려요.','speaker','A1','technology',2,'speaker bluetooth sound music audio'),
('w_technology_A1_25','link','/lɪŋk/','noun','링크','A connection between web pages on the internet.','Click on the {link} to visit the website.','웹사이트를 방문하려면 링크를 클릭하세요.','link','A1','technology',2,'link url website click browser'),
('w_technology_A1_26','power','/ˈpaʊər/','noun','전원, 전력','Electrical energy used to operate devices.','Press the {power} button to turn off the TV.','TV를 끄려면 전원 버튼을 누르세요.','power','A1','technology',2,'power button electricity device switch'),
('w_technology_A1_27','device','/dɪˈvaɪs/','noun','기기, 장치','A piece of equipment made for a specific purpose.','This {device} is very easy to use.','이 기기는 사용하기 매우 쉬워요.','device','A1','technology',1,'electronic device gadget technology modern'),
('w_technology_A1_28','file','/faɪl/','noun','파일','A collection of data stored under a single name.','I saved the {file} to my desktop.','데스크톱에 파일을 저장했어요.','file','A1','technology',2,'file folder computer document digital'),
('w_technology_A1_29','icon','/ˈaɪkɒn/','noun','아이콘','A small image on a screen representing a program or function.','Tap the {icon} to open the app.','앱을 열려면 아이콘을 탭하세요.','icon','A1','technology',2,'app icon screen smartphone colorful'),
('w_technology_A1_30','microphone','/ˈmaɪkrəfoʊn/','noun','마이크','A device that converts sound into electrical signals.','The {microphone} on this headset is very clear.','이 헤드셋의 마이크가 매우 선명해요.','microphone','A1','technology',2,'microphone recording studio podcast voice'),
('w_technology_A1_31','headphones','/ˈhɛdfəʊnz/','noun','헤드폰','A pair of speakers worn over the ears.','I use {headphones} when I study to focus better.','집중하기 위해 공부할 때 헤드폰을 사용해요.','headphones','A1','technology',2,'headphones music listening focus study'),
('w_technology_A1_32','camera','/ˈkæmərə/','noun','카메라','A device used to take photographs or videos.','The {camera} quality on this phone is amazing.','이 휴대폰의 카메라 화질이 놀라워요.','camera','A1','technology',1,'camera photography taking picture lens'),
('w_technology_A1_33','memory','/ˈmɛməri/','noun','메모리, 저장 공간','Storage space on a device for holding data.','My phone has no {memory} left for new photos.','새 사진을 위한 메모리 공간이 없어요.','memory','A1','technology',2,'memory storage device chip data'),
('w_technology_A1_34','remote','/rɪˈmoʊt/','noun','리모컨','A device for controlling something from a distance.','Where is the TV {remote}?','TV 리모컨이 어디 있어요?','remote','A1','technology',2,'remote control TV living room sofa'),
('w_technology_A1_35','plug','/plʌɡ/','noun','플러그, 콘센트','A device connecting an electrical appliance to a power source.','Plug the charger into the {plug} on the wall.','벽에 있는 콘센트에 충전기를 꽂으세요.','plug','A1','technology',2,'plug outlet power socket electric wall');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_technology_A2_01','software','/ˈsɔːftweər/','noun','소프트웨어','Programs and operating information used by a computer.','Make sure your {software} is up to date.','소프트웨어가 최신 상태인지 확인하세요.','software','A2','technology',1,'software code programming computer screen'),
('w_technology_A2_02','download','/ˈdaʊnloʊd/','verb','다운로드하다','To copy data from the internet to your device.','{Download} the app from the App Store.','앱 스토어에서 앱을 다운로드하세요.','Download','A2','technology',1,'download arrow internet file transfer'),
('w_technology_A2_03','upload','/ˈʌploʊd/','verb','업로드하다','To copy data from your device to the internet.','You can {upload} photos directly to the website.','웹사이트에 직접 사진을 업로드할 수 있어요.','upload','A2','technology',1,'upload cloud arrow internet share'),
('w_technology_A2_04','delete','/dɪˈliːt/','verb','삭제하다','To remove data or a file permanently.','{Delete} any files you no longer need.','더 이상 필요 없는 파일은 삭제하세요.','Delete','A2','technology',1,'delete trash bin file remove digital'),
('w_technology_A2_05','update','/ˈʌpdeɪt/','verb','업데이트하다','To install the latest version of software.','Please {update} your system to fix the bug.','버그를 수정하려면 시스템을 업데이트하세요.','update','A2','technology',1,'update software system progress loading'),
('w_technology_A2_06','wifi','/ˈwaɪfaɪ/','noun','와이파이','Wireless technology allowing internet connection.','The hotel has free {wifi} in all rooms.','호텔의 모든 객실에서 무료 와이파이를 이용할 수 있어요.','wifi','A2','technology',1,'wifi signal router internet connection'),
('w_technology_A2_07','battery','/ˈbætəri/','noun','배터리','A device that stores and provides electrical energy.','The {battery} in my laptop only lasts two hours.','제 노트북 배터리는 두 시간밖에 안 돼요.','battery','A2','technology',1,'battery low power charge indicator'),
('w_technology_A2_08','bluetooth','/ˈbluːtuːθ/','noun','블루투스','A wireless technology for short-range communication.','Connect your earbuds via {bluetooth}.','블루투스로 이어폰을 연결하세요.','bluetooth','A2','technology',2,'bluetooth earbuds wireless connection device'),
('w_technology_A2_09','notification','/ˌnoʊtɪfɪˈkeɪʃən/','noun','알림','A message sent to a device to alert the user.','I turned off {notification}s to focus on studying.','공부에 집중하기 위해 알림을 껐어요.','notification','A2','technology',1,'notification phone alert bell message'),
('w_technology_A2_10','settings','/ˈsɛtɪŋz/','noun','설정','Options that can be adjusted to control how a device works.','Go to {settings} to change the display brightness.','화면 밝기를 바꾸려면 설정으로 가세요.','settings','A2','technology',1,'settings gear icon phone control options'),
('w_technology_A2_11','restart','/ˌriːˈstɑːrt/','verb','재시작하다','To shut down and start a device or program again.','Try to {restart} the device to fix the problem.','문제를 해결하려면 기기를 재시작해 보세요.','restart','A2','technology',2,'restart reboot computer phone loading'),
('w_technology_A2_12','username','/ˈjuːzərneɪm/','noun','아이디, 사용자 이름','A name used to identify a person on a website or app.','Enter your {username} and password to log in.','로그인하려면 아이디와 비밀번호를 입력하세요.','username','A2','technology',2,'username login account profile registration'),
('w_technology_A2_13','log in','/lɒɡ ɪn/','phrasal verb','로그인하다','To access a computer system or website using credentials.','You need to {log in} to view your messages.','메시지를 보려면 로그인해야 해요.','log in','A2','technology',1,'login account password screen secure'),
('w_technology_A2_14','log out','/lɒɡ aʊt/','phrasal verb','로그아웃하다','To end a session on a computer system or website.','Always {log out} when using a shared computer.','공용 컴퓨터를 사용할 때는 항상 로그아웃하세요.','log out','A2','technology',2,'logout security account shared computer'),
('w_technology_A2_15','screenshot','/ˈskriːnʃɒt/','noun','스크린샷','An image of what is currently displayed on a screen.','Take a {screenshot} and send it to me.','스크린샷을 찍어서 보내주세요.','screenshot','A2','technology',2,'screenshot phone screen capture image'),
('w_technology_A2_16','website','/ˈwɛbsaɪt/','noun','웹사이트','A set of pages on the internet under one address.','Check the official {website} for more information.','더 많은 정보는 공식 웹사이트를 확인하세요.','website','A2','technology',1,'website browser internet page design'),
('w_technology_A2_17','browser','/ˈbraʊzər/','noun','브라우저','A program used to access the internet.','Open your {browser} and go to the link.','브라우저를 열고 링크로 이동하세요.','browser','A2','technology',2,'browser chrome internet web navigation'),
('w_technology_A2_18','network','/ˈnɛtwɜːrk/','noun','네트워크','A system of connected computers or devices.','Connect to the office {network} to access the files.','파일에 접근하려면 사무실 네트워크에 연결하세요.','network','A2','technology',1,'network connection computers office router'),
('w_technology_A2_19','backup','/ˈbækʌp/','noun','백업','A copy of data saved in case the original is lost.','Always make a {backup} of your important files.','중요한 파일은 항상 백업해 두세요.','backup','A2','technology',1,'backup hard drive data storage copy'),
('w_technology_A2_20','virus','/ˈvaɪrəs/','noun','바이러스','Malicious software that damages or disrupts systems.','A {virus} deleted all the files on my computer.','바이러스가 컴퓨터의 모든 파일을 삭제했어요.','virus','A2','technology',1,'virus malware computer security warning red'),
('w_technology_A2_21','glitch','/ɡlɪtʃ/','noun','결함, 오류','A small error or malfunction in software or hardware.','There was a {glitch} in the app and it crashed.','앱에 결함이 생겨서 충돌했어요.','glitch','A2','technology',2,'glitch error screen bug software crash'),
('w_technology_A2_22','install','/ɪnˈstɔːl/','verb','설치하다','To put software onto a computer or device.','{Install} the program before you start.','시작하기 전에 프로그램을 설치하세요.','Install','A2','technology',1,'install software computer setup loading bar'),
('w_technology_A2_23','folder','/ˈfoʊldər/','noun','폴더','A virtual container for organizing files.','Save all the documents in this {folder}.','모든 문서를 이 폴더에 저장하세요.','folder','A2','technology',2,'folder files organized computer desktop'),
('w_technology_A2_24','storage','/ˈstɔːrɪdʒ/','noun','저장 공간','The space available on a device for keeping data.','I need more {storage} for my video files.','동영상 파일을 위한 저장 공간이 더 필요해요.','storage','A2','technology',1,'storage drive data space hard disk'),
('w_technology_A2_25','account','/əˈkaʊnt/','noun','계정','A profile or record set up with a service or website.','Create an {account} to access all the features.','모든 기능을 이용하려면 계정을 만드세요.','account','A2','technology',1,'account profile registration online sign up'),
('w_technology_A2_26','share','/ʃeər/','verb','공유하다','To give others access to a file, link, or content.','You can {share} the document with your team.','팀원들과 문서를 공유할 수 있어요.','share','A2','technology',1,'share document link team collaboration'),
('w_technology_A2_27','zoom','/zuːm/','verb','확대하다; 줌 통화하다','To enlarge an image or to join a video call.','Can you {zoom} in on that part of the image?','이미지의 그 부분을 확대해 주실 수 있나요?','zoom','A2','technology',2,'zoom video call meeting online remote'),
('w_technology_A2_28','format','/ˈfɔːrmæt/','noun','형식, 파일 포맷','The way data is arranged or the type of a file.','Please send the file in PDF {format}.','파일을 PDF 형식으로 보내주세요.','format','A2','technology',2,'file format pdf document type computer'),
('w_technology_A2_29','stream','/striːm/','verb','스트리밍하다','To watch or listen to media directly over the internet.','We can {stream} the movie on this app.','이 앱에서 영화를 스트리밍할 수 있어요.','stream','A2','technology',1,'streaming video online watching laptop couch'),
('w_technology_A2_30','connect','/kəˈnɛkt/','verb','연결하다','To link two or more devices together.','{Connect} your phone to the computer with a cable.','케이블로 휴대폰을 컴퓨터에 연결하세요.','Connect','A2','technology',2,'connect cable devices link technology'),
('w_technology_A2_31','crash','/kræʃ/','verb','충돌하다, 다운되다','To suddenly stop working due to a fault.','The app keeps {crash}ing when I open it.','앱을 열 때마다 계속 충돌해요.','crash','A2','technology',2,'app crash error screen loading fail'),
('w_technology_A2_32','tap','/tæp/','verb','탭하다, 가볍게 누르다','To touch a touchscreen briefly to select something.','{Tap} the screen to take a photo.','사진을 찍으려면 화면을 탭하세요.','Tap','A2','technology',2,'tap touchscreen phone finger gesture'),
('w_technology_A2_33','swipe','/swaɪp/','verb','스와이프하다','To slide a finger across a touchscreen.','{Swipe} left to delete the message.','메시지를 삭제하려면 왼쪽으로 스와이프하세요.','Swipe','A2','technology',2,'swipe finger phone touchscreen gesture'),
('w_technology_A2_34','resolution','/ˌrɛzəˈluːʃən/','noun','해상도','The quality of an image, measured in pixels.','This TV has a very high {resolution}.','이 TV는 해상도가 매우 높아요.','resolution','A2','technology',2,'resolution screen pixels display sharp'),
('w_technology_A2_35','notification badge','/ˌnoʊtɪfɪˈkeɪʃən bædʒ/','noun','알림 배지','A small number shown on an app icon indicating unread alerts.','The red {notification badge} shows I have new messages.','빨간 알림 배지가 새 메시지가 있다는 것을 보여줘요.','notification badge','A2','technology',2,'notification badge red icon unread alert phone');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_technology_B1_01','algorithm','/ˈælɡərɪðəm/','noun','알고리즘','A set of rules or steps a computer follows to solve a problem.','The search {algorithm} finds the most relevant results.','검색 알고리즘이 가장 관련성 높은 결과를 찾아줘요.','algorithm','B1','technology',1,'algorithm flowchart code logic computer'),
('w_technology_B1_02','interface','/ˈɪntərfeɪs/','noun','인터페이스','The way a user interacts with a system or program.','The new {interface} is much easier to navigate.','새 인터페이스는 훨씬 사용하기 편해요.','interface','B1','technology',1,'interface ui design app screen clean'),
('w_technology_B1_03','database','/ˈdeɪtəbeɪs/','noun','데이터베이스','An organized collection of data stored electronically.','All customer information is kept in a {database}.','모든 고객 정보는 데이터베이스에 저장돼요.','database','B1','technology',1,'database server data storage structured'),
('w_technology_B1_04','server','/ˈsɜːrvər/','noun','서버','A computer that provides data or services to other devices.','The {server} is down, so the website is not loading.','서버가 다운되어서 웹사이트가 로드되지 않아요.','server','B1','technology',1,'server room rack data center technology'),
('w_technology_B1_05','cloud','/klaʊd/','noun','클라우드','Remote servers accessed via the internet for data storage.','I store all my photos in the {cloud}.','모든 사진을 클라우드에 저장해요.','cloud','B1','technology',1,'cloud computing storage sky data sync'),
('w_technology_B1_06','code','/koʊd/','noun','코드','Instructions written in a programming language for a computer.','You need to learn {code} to build your own app.','자신만의 앱을 만들려면 코드를 배워야 해요.','code','B1','technology',1,'code programming screen developer dark'),
('w_technology_B1_07','encryption','/ɪnˈkrɪpʃən/','noun','암호화','The process of converting data into a code to prevent access.','The app uses end-to-end {encryption} to protect messages.','앱은 메시지를 보호하기 위해 종단간 암호화를 사용해요.','encryption','B1','technology',1,'encryption security lock data protected'),
('w_technology_B1_08','cybersecurity','/ˌsaɪbərsɪˈkjʊərɪti/','noun','사이버 보안','The practice of protecting systems from digital attacks.','Companies invest heavily in {cybersecurity} to protect data.','기업들은 데이터 보호를 위해 사이버 보안에 많이 투자해요.','cybersecurity','B1','technology',1,'cybersecurity shield digital protection lock'),
('w_technology_B1_09','bandwidth','/ˈbændwɪdθ/','noun','대역폭','The maximum amount of data that can be transmitted at once.','Streaming in 4K uses a lot of {bandwidth}.','4K로 스트리밍하면 대역폭을 많이 사용해요.','bandwidth','B1','technology',2,'bandwidth internet speed data network'),
('w_technology_B1_10','debugging','/diːˈbʌɡɪŋ/','noun','디버깅','The process of finding and fixing errors in software.','{Debugging} took longer than writing the code itself.','디버깅이 코드를 작성하는 것보다 더 오래 걸렸어요.','debugging','B1','technology',2,'debugging code error fix developer screen'),
('w_technology_B1_11','framework','/ˈfreɪmwɜːrk/','noun','프레임워크','A pre-built set of tools and libraries for development.','React is a popular {framework} for building web apps.','React는 웹 앱 개발에 인기 있는 프레임워크예요.','framework','B1','technology',2,'framework code structure development blueprint'),
('w_technology_B1_12','version control','/ˈvɜːrʒən kənˈtroʊl/','noun','버전 관리','A system for tracking and managing changes to code.','We use Git for {version control} on every project.','모든 프로젝트에서 버전 관리를 위해 Git을 사용해요.','version control','B1','technology',2,'version control git code branches history'),
('w_technology_B1_13','deployment','/dɪˈplɔɪmənt/','noun','배포','The process of making software available for use.','The {deployment} of the new feature went smoothly.','새 기능 배포가 순조롭게 이루어졌어요.','deployment','B1','technology',2,'deployment release code launch production'),
('w_technology_B1_14','firewall','/ˈfaɪərwɔːl/','noun','방화벽','A security system that monitors and controls network traffic.','The company {firewall} blocked the suspicious website.','회사 방화벽이 의심스러운 웹사이트를 차단했어요.','firewall','B1','technology',1,'firewall security network protection digital'),
('w_technology_B1_15','bug','/bʌɡ/','noun','버그, 오류','An error or flaw in software that causes unexpected behavior.','There is a {bug} in the login system that we need to fix.','로그인 시스템에 수정이 필요한 버그가 있어요.','bug','B1','technology',1,'bug code error software problem screen'),
('w_technology_B1_16','patch','/pætʃ/','noun','패치','A software update that fixes a specific bug or vulnerability.','Apply the latest security {patch} to stay protected.','보호 상태를 유지하려면 최신 보안 패치를 적용하세요.','patch','B1','technology',2,'patch update security software fix shield'),
('w_technology_B1_17','protocol','/ˈproʊtəkɒl/','noun','프로토콜','A set of rules that govern data exchange between devices.','HTTPS is the secure {protocol} used for web browsing.','HTTPS는 웹 브라우징에 사용되는 보안 프로토콜이에요.','protocol','B1','technology',2,'protocol https secure web connection lock'),
('w_technology_B1_18','cache','/kæʃ/','noun','캐시','Temporary data stored to speed up future requests.','Clear the {cache} if the website is loading slowly.','웹사이트가 느리게 로드된다면 캐시를 지우세요.','cache','B1','technology',2,'cache clear browser speed web loading'),
('w_technology_B1_19','API','/ˌeɪpiːˈaɪ/','noun','에이피아이 (응용 프로그램 인터페이스)','A set of rules that allows different programs to communicate.','This app uses the weather {API} to show forecasts.','이 앱은 날씨 예보를 보여주기 위해 날씨 API를 사용해요.','API','B1','technology',1,'api code integration developer connection'),
('w_technology_B1_20','repository','/rɪˈpɒzɪtəri/','noun','저장소, 리포지토리','A place where code or data is stored and managed.','All our code is in a private {repository} on GitHub.','우리 코드는 모두 GitHub의 비공개 저장소에 있어요.','repository','B1','technology',2,'github repository code project storage'),
('w_technology_B1_21','feature','/ˈfiːtʃər/','noun','기능, 특징','A distinct capability or characteristic of software.','The new {feature} lets users customize their dashboard.','새 기능으로 사용자가 대시보드를 맞춤 설정할 수 있어요.','feature','B1','technology',1,'feature product launch software new update'),
('w_technology_B1_22','platform','/ˈplætfɔːrm/','noun','플랫폼','A system or technology on which other applications run.','Instagram is one of the most popular social media {platform}s.','인스타그램은 가장 인기 있는 소셜 미디어 플랫폼 중 하나예요.','platform','B1','technology',1,'platform social media technology ecosystem'),
('w_technology_B1_23','permission','/pərˈmɪʃən/','noun','권한, 허가','Authorization granted to access a system or resource.','The app is asking for {permission} to use your camera.','앱이 카메라 사용 권한을 요청하고 있어요.','permission','B1','technology',2,'permission access allow app phone request'),
('w_technology_B1_24','sync','/sɪŋk/','verb','동기화하다','To update data on multiple devices so they match.','{Sync} your phone with the computer to transfer files.','파일을 전송하려면 휴대폰을 컴퓨터와 동기화하세요.','sync','B1','technology',1,'sync cloud devices data matching update'),
('w_technology_B1_25','malware','/ˈmælweər/','noun','악성 소프트웨어','Software designed to disrupt or damage a system.','The antivirus software detected and removed the {malware}.','바이러스 백신 소프트웨어가 악성 소프트웨어를 탐지하여 제거했어요.','malware','B1','technology',1,'malware virus security warning digital red'),
('w_technology_B1_26','data','/ˈdeɪtə/','noun','데이터','Facts and statistics collected for reference or analysis.','The app collects {data} about your daily habits.','앱이 일상 습관에 관한 데이터를 수집해요.','data','B1','technology',1,'data analytics chart visualization technology'),
('w_technology_B1_27','scalable','/ˈskeɪləbəl/','adjective','확장 가능한','Able to grow or be adapted to handle increasing demands.','We need a {scalable} solution for our growing user base.','늘어나는 사용자를 위한 확장 가능한 솔루션이 필요해요.','scalable','B1','technology',2,'scalable growth system architecture expanding'),
('w_technology_B1_28','integration','/ˌɪntɪˈɡreɪʃən/','noun','통합','The combination of different systems or software to work together.','The {integration} between the two apps took weeks.','두 앱 간의 통합에 몇 주가 걸렸어요.','integration','B1','technology',2,'integration systems connect apps workflow'),
('w_technology_B1_29','sprint','/sprɪnt/','noun','스프린트 (개발 주기)','A short, time-boxed period for completing a set of tasks.','We finished three features in the last {sprint}.','지난 스프린트에서 세 가지 기능을 완성했어요.','sprint','B1','technology',2,'sprint agile development team planning board'),
('w_technology_B1_30','open source','/ˌoʊpən ˈsɔːrs/','adjective','오픈소스','Software with source code available for anyone to view or modify.','This {open source} project has thousands of contributors.','이 오픈소스 프로젝트에는 수천 명의 기여자가 있어요.','open source','B1','technology',1,'open source github community code collaboration'),
('w_technology_B1_31','script','/skrɪpt/','noun','스크립트','A small program or set of instructions for automating tasks.','I wrote a {script} to automatically rename the files.','파일 이름을 자동으로 바꾸는 스크립트를 작성했어요.','script','B1','technology',2,'script code automation terminal command'),
('w_technology_B1_32','latency','/ˈleɪtənsi/','noun','지연 시간','The delay before data begins to transfer after an instruction.','High {latency} makes online gaming frustrating.','높은 지연 시간은 온라인 게임을 답답하게 해요.','latency','B1','technology',2,'latency ping speed network connection'),
('w_technology_B1_33','log','/lɒɡ/','noun','로그, 기록','A record of events or errors generated by a system.','Check the server {log} to find the source of the error.','오류 원인을 찾으려면 서버 로그를 확인하세요.','log','B1','technology',2,'server log record file system error'),
('w_technology_B1_34','token','/ˈtoʊkən/','noun','토큰 (인증 키)','A string of data used to authenticate a user or session.','The API requires an authentication {token} for each request.','API는 각 요청에 인증 토큰이 필요해요.','token','B1','technology',2,'token authentication security api access'),
('w_technology_B1_35','webhook','/ˈwɛbhʊk/','noun','웹훅','An automated message sent between apps when an event occurs.','We set up a {webhook} to notify Slack when a build fails.','빌드가 실패하면 Slack에 알림이 가도록 웹훅을 설정했어요.','webhook','B1','technology',2,'webhook automation notification trigger event code');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_technology_B2_01','artificial intelligence','/ˌɑːrtɪˈfɪʃəl ɪnˈtelɪdʒəns/','noun','인공지능','The simulation of human intelligence by computer systems.','{Artificial intelligence} is transforming the healthcare industry.','인공지능이 의료 산업을 변화시키고 있어요.','artificial intelligence','B2','technology',1,'artificial intelligence robot brain digital glow'),
('w_technology_B2_02','machine learning','/məˈʃiːn ˈlɜːrnɪŋ/','noun','머신러닝','A type of AI that enables computers to learn from data.','The app uses {machine learning} to improve its recommendations.','앱은 추천을 개선하기 위해 머신러닝을 사용해요.','machine learning','B2','technology',1,'machine learning neural network data pattern'),
('w_technology_B2_03','automation','/ˌɔːtəˈmeɪʃən/','noun','자동화','The use of technology to perform tasks without human help.','Factory {automation} has reduced the need for manual labor.','공장 자동화로 수작업 필요성이 줄었어요.','automation','B2','technology',1,'automation robot factory industrial machine'),
('w_technology_B2_04','blockchain','/ˈblɒktʃeɪn/','noun','블록체인','A decentralized digital ledger that records transactions securely.','{Blockchain} technology ensures transaction transparency.','블록체인 기술은 거래 투명성을 보장해요.','blockchain','B2','technology',1,'blockchain cryptocurrency digital ledger network'),
('w_technology_B2_05','IoT','/ˌaɪ oʊ ˈtiː/','noun','사물인터넷','The network of physical devices connected and exchanging data.','{IoT} devices in smart homes can be controlled remotely.','스마트홈의 사물인터넷 기기는 원격으로 제어할 수 있어요.','IoT','B2','technology',1,'smart home iot devices connected technology'),
('w_technology_B2_06','neural network','/ˈnjʊərəl ˈnɛtwɜːrk/','noun','신경망','A computing system inspired by the human brain''s structure.','The image recognition system uses a {neural network}.','이미지 인식 시스템은 신경망을 사용해요.','neural network','B2','technology',1,'neural network brain ai nodes glowing'),
('w_technology_B2_07','data mining','/ˈdeɪtə ˌmaɪnɪŋ/','noun','데이터 마이닝','Extracting useful patterns from large sets of data.','Companies use {data mining} to predict customer behavior.','기업들은 고객 행동을 예측하기 위해 데이터 마이닝을 사용해요.','data mining','B2','technology',1,'data mining analytics visualization big data'),
('w_technology_B2_08','deep learning','/diːp ˈlɜːrnɪŋ/','noun','딥러닝','A subset of machine learning using multi-layered neural networks.','{Deep learning} powers most modern voice recognition systems.','딥러닝은 대부분의 현대 음성 인식 시스템을 구동해요.','deep learning','B2','technology',1,'deep learning ai layers network visualization'),
('w_technology_B2_09','algorithm bias','/ˈælɡərɪðəm ˈbaɪəs/','noun','알고리즘 편향','Systematic errors in AI outputs caused by biased training data.','{Algorithm bias} can lead to unfair decisions in hiring systems.','알고리즘 편향은 채용 시스템에서 불공정한 결정을 초래할 수 있어요.','algorithm bias','B2','technology',2,'bias algorithm fairness data ai ethics'),
('w_technology_B2_10','natural language processing','/ˈnætʃrəl ˈlæŋɡwɪdʒ ˈproʊsesɪŋ/','noun','자연어 처리','AI technology enabling computers to understand human language.','{Natural language processing} powers chatbots and translation apps.','자연어 처리가 챗봇과 번역 앱을 구동해요.','natural language processing','B2','technology',1,'natural language processing nlp text ai'),
('w_technology_B2_11','virtual reality','/ˈvɜːrtʃuəl riˈælɪti/','noun','가상현실','A simulated experience that immerses users in a digital world.','{Virtual reality} is increasingly used for medical training.','가상현실은 의료 훈련에 점점 더 많이 사용되고 있어요.','virtual reality','B2','technology',1,'virtual reality vr headset immersive digital'),
('w_technology_B2_12','augmented reality','/ɔːɡˈmɛntɪd riˈælɪti/','noun','증강현실','Technology that overlays digital information on the real world.','The app uses {augmented reality} to show furniture in your home.','앱은 집에 가구를 보여주기 위해 증강현실을 사용해요.','augmented reality','B2','technology',1,'augmented reality ar phone overlay digital'),
('w_technology_B2_13','cybersecurity threat','/ˌsaɪbərsɪˈkjʊərɪti θrɛt/','noun','사이버 보안 위협','A potential danger to digital systems or data.','Phishing emails remain the most common {cybersecurity threat}.','피싱 이메일은 가장 일반적인 사이버 보안 위협으로 남아 있어요.','cybersecurity threat','B2','technology',2,'cybersecurity threat warning hacker dark'),
('w_technology_B2_14','cloud computing','/klaʊd kəmˈpjuːtɪŋ/','noun','클라우드 컴퓨팅','Delivering computing services over the internet.','{Cloud computing} allows teams to collaborate from anywhere.','클라우드 컴퓨팅을 통해 팀이 어디서든 협업할 수 있어요.','cloud computing','B2','technology',1,'cloud computing server data center storage'),
('w_technology_B2_15','predictive analytics','/prɪˈdɪktɪv ˌænəˈlɪtɪks/','noun','예측 분석','Using data and algorithms to forecast future outcomes.','Retailers use {predictive analytics} to manage inventory.','소매업체들은 재고를 관리하기 위해 예측 분석을 사용해요.','predictive analytics','B2','technology',2,'predictive analytics chart forecast data graph'),
('w_technology_B2_16','microprocessor','/ˌmaɪkroʊˈprɒsɛsər/','noun','마이크로프로세서','A chip that performs the basic operations of a computer.','The new {microprocessor} is twice as fast as the previous one.','새 마이크로프로세서는 이전 것보다 두 배 빠릅니다.','microprocessor','B2','technology',2,'microprocessor chip silicon circuit board'),
('w_technology_B2_17','biometric','/ˌbaɪoʊˈmɛtrɪk/','adjective','생체인식의','Relating to the measurement of physical characteristics.','{Biometric} authentication uses your face or fingerprint to log in.','생체인식 인증은 얼굴이나 지문으로 로그인해요.','biometric','B2','technology',1,'biometric fingerprint face scan security login'),
('w_technology_B2_18','digital transformation','/ˈdɪdʒɪtəl ˌtrænsˈfɔːrmeɪʃən/','noun','디지털 전환','The integration of digital technology into all areas of a business.','{Digital transformation} has changed how companies operate.','디지털 전환은 기업의 운영 방식을 바꿔놓았어요.','digital transformation','B2','technology',1,'digital transformation business technology modern'),
('w_technology_B2_19','generative AI','/ˈdʒɛnərətɪv eɪˈaɪ/','noun','생성형 AI','AI that can create new content such as text, images, or code.','{Generative AI} tools can write articles and draw pictures.','생성형 AI 도구는 글을 쓰고 그림을 그릴 수 있어요.','generative AI','B2','technology',1,'generative ai create image text artwork'),
('w_technology_B2_20','large language model','/lɑːrdʒ ˈlæŋɡwɪdʒ ˈmɒdəl/','noun','거대 언어 모델','A type of AI trained on massive amounts of text data.','{Large language model}s like GPT power many AI assistants.','GPT와 같은 거대 언어 모델이 많은 AI 어시스턴트를 구동해요.','large language model','B2','technology',1,'large language model llm text ai brain'),
('w_technology_B2_21','edge AI','/ɛdʒ eɪˈaɪ/','noun','엣지 AI','AI processing done on local devices rather than the cloud.','{Edge AI} allows smart devices to work without internet.','엣지 AI를 통해 스마트 기기가 인터넷 없이도 작동해요.','edge AI','B2','technology',2,'edge ai device local computing smart'),
('w_technology_B2_22','semiconductor','/ˌsɛmɪkənˈdʌktər/','noun','반도체','A material that can conduct electricity under certain conditions.','The global {semiconductor} shortage affected car production.','세계적인 반도체 부족이 자동차 생산에 영향을 미쳤어요.','semiconductor','B2','technology',1,'semiconductor chip silicon wafer factory'),
('w_technology_B2_23','inference','/ˈɪnfərəns/','noun','추론 (AI)','The process of running a trained AI model to make predictions.','On-device {inference} is faster and more private.','온디바이스 추론은 더 빠르고 프라이버시가 보호돼요.','inference','B2','technology',2,'inference ai prediction model compute'),
('w_technology_B2_24','fine-tuning','/faɪn ˈtjuːnɪŋ/','noun','파인튜닝','Adapting a pre-trained AI model for a specific task.','{Fine-tuning} the model on medical data improved its accuracy.','의료 데이터로 모델을 파인튜닝하자 정확도가 향상되었어요.','fine-tuning','B2','technology',2,'fine tuning ai model training optimization data'),
('w_technology_B2_25','throughput','/ˈθruːpʊt/','noun','처리량','The amount of data processed by a system in a given time.','Upgrading the server increased its {throughput} significantly.','서버를 업그레이드하자 처리량이 크게 증가했어요.','throughput','B2','technology',2,'throughput server performance data processing speed'),
('w_technology_B2_26','container','/kənˈteɪnər/','noun','컨테이너 (가상화)','A lightweight, portable unit of software and its dependencies.','We use Docker {container}s to run our applications.','애플리케이션 실행을 위해 Docker 컨테이너를 사용해요.','container','B2','technology',2,'container docker kubernetes deployment software'),
('w_technology_B2_27','microservices','/ˈmaɪkroʊˌsɜːrvɪsɪz/','noun','마이크로서비스','An architecture style where apps are built as small, independent services.','The platform uses {microservices} for flexibility and scale.','플랫폼은 유연성과 확장성을 위해 마이크로서비스를 사용해요.','microservices','B2','technology',2,'microservices architecture services diagram cloud'),
('w_technology_B2_28','DevOps','/ˈdɛvɒps/','noun','데브옵스','A practice combining development and operations for faster delivery.','{DevOps} culture helps teams release software more frequently.','데브옵스 문화는 팀이 소프트웨어를 더 자주 출시하는 데 도움을 줘요.','DevOps','B2','technology',2,'devops pipeline ci cd automation deployment'),
('w_technology_B2_29','tokenization','/ˌtoʊkənɪˈzeɪʃən/','noun','토큰화','Converting sensitive data into non-sensitive tokens for security.','Credit card {tokenization} protects financial information.','신용카드 토큰화는 금융 정보를 보호해요.','tokenization','B2','technology',2,'tokenization security payment data protection'),
('w_technology_B2_30','zero-trust','/ˈzɪəroʊ trʌst/','adjective','제로 트러스트','A security model that requires strict verification for all users.','The company adopted a {zero-trust} security policy.','회사는 제로 트러스트 보안 정책을 채택했어요.','zero-trust','B2','technology',2,'zero trust security policy verification shield'),
('w_technology_B2_31','hyperparameter','/ˌhaɪpərˈpærəmɪtər/','noun','하이퍼파라미터','A parameter set before training a machine learning model.','Tuning {hyperparameter}s is critical for model performance.','하이퍼파라미터 튜닝은 모델 성능에 매우 중요해요.','hyperparameter','B2','technology',2,'hyperparameter tuning machine learning model optimization'),
('w_technology_B2_32','multimodal AI','/ˌmʌltiˈmoʊdəl eɪˈaɪ/','noun','멀티모달 AI','AI that can process and generate multiple types of data.','{Multimodal AI} can analyze both images and text at once.','멀티모달 AI는 이미지와 텍스트를 동시에 분석할 수 있어요.','multimodal AI','B2','technology',2,'multimodal ai input image text voice data'),
('w_technology_B2_33','data sovereignty','/ˈdeɪtə ˈsɒvrɪnti/','noun','데이터 주권','The concept that data is subject to the laws of its country.','{Data sovereignty} laws affect where companies can store user data.','데이터 주권법은 기업이 사용자 데이터를 저장할 수 있는 곳에 영향을 줘요.','data sovereignty','B2','technology',2,'data sovereignty flag law privacy global'),
('w_technology_B2_34','algorithm efficiency','/ˈælɡərɪðəm ɪˈfɪʃənsi/','noun','알고리즘 효율성','How well an algorithm performs in terms of speed and resources.','Improving {algorithm efficiency} reduced the server costs.','알고리즘 효율성 개선으로 서버 비용이 줄었어요.','algorithm efficiency','B2','technology',2,'algorithm efficiency optimization code performance'),
('w_technology_B2_35','synthetic data','/sɪnˈθɛtɪk ˈdeɪtə/','noun','합성 데이터','Artificially generated data used to train AI models.','{Synthetic data} allows training without compromising user privacy.','합성 데이터를 통해 사용자 프라이버시를 침해하지 않고 학습할 수 있어요.','synthetic data','B2','technology',2,'synthetic data generation ai training fake');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_technology_C1_01','quantum computing','/ˈkwɒntəm kəmˈpjuːtɪŋ/','noun','양자 컴퓨팅','Computing using quantum-mechanical phenomena like superposition.','{Quantum computing} could break current encryption methods.','양자 컴퓨팅은 현재의 암호화 방식을 무력화할 수 있어요.','quantum computing','C1','technology',1,'quantum computing qubit futuristic blue glow'),
('w_technology_C1_02','edge computing','/ɛdʒ kəmˈpjuːtɪŋ/','noun','엣지 컴퓨팅','Processing data near its source rather than in a central server.','{Edge computing} reduces latency for real-time applications.','엣지 컴퓨팅은 실시간 애플리케이션의 지연 시간을 줄여요.','edge computing','C1','technology',1,'edge computing device local network processing'),
('w_technology_C1_03','cryptography','/krɪpˈtɒɡrəfi/','noun','암호학','The practice of secure communication in the presence of adversaries.','Modern {cryptography} relies on mathematical problems that are hard to solve.','현대 암호학은 풀기 어려운 수학 문제에 의존해요.','cryptography','C1','technology',1,'cryptography encryption key code secure'),
('w_technology_C1_04','federated learning','/ˈfɛdəreɪtɪd ˈlɜːrnɪŋ/','noun','연합 학습','Training AI models across decentralized devices without sharing data.','{Federated learning} protects user privacy while training AI.','연합 학습은 AI를 학습시키면서 사용자 프라이버시를 보호해요.','federated learning','C1','technology',2,'federated learning privacy distributed ai network'),
('w_technology_C1_05','reinforcement learning','/ˌriːɪnˈfɔːrsmənt ˈlɜːrnɪŋ/','noun','강화 학습','An AI method where an agent learns by receiving rewards or penalties.','Game-playing AIs use {reinforcement learning} to improve strategies.','게임 플레이 AI는 전략을 개선하기 위해 강화 학습을 사용해요.','reinforcement learning','C1','technology',2,'reinforcement learning agent reward game ai'),
('w_technology_C1_06','transformer model','/trænsˈfɔːrmər ˈmɒdəl/','noun','트랜스포머 모델','An AI architecture based on self-attention mechanisms for sequence data.','The {transformer model} revolutionized natural language processing.','트랜스포머 모델은 자연어 처리에 혁명을 일으켰어요.','transformer model','C1','technology',1,'transformer model attention ai architecture diagram'),
('w_technology_C1_07','adversarial attack','/ədˈvɜːrsəriəl əˈtæk/','noun','적대적 공격','An input designed to deceive an AI model into making errors.','Researchers discovered an {adversarial attack} on the image classifier.','연구자들이 이미지 분류기에 대한 적대적 공격을 발견했어요.','adversarial attack','C1','technology',2,'adversarial attack ai security perturbation error'),
('w_technology_C1_08','scalability','/ˌskeɪləˈbɪlɪti/','noun','확장성','The ability of a system to handle growing amounts of work.','The startup struggled with {scalability} as user numbers grew.','사용자 수가 늘어나면서 스타트업은 확장성 문제로 어려움을 겪었어요.','scalability','C1','technology',1,'scalability server growth architecture cloud'),
('w_technology_C1_09','differential privacy','/ˌdɪfəˈrɛnʃəl ˈprɪvəsi/','noun','차등 프라이버시','A technique that adds noise to data to protect individual privacy.','Apple uses {differential privacy} when collecting usage statistics.','Apple은 사용 통계를 수집할 때 차등 프라이버시를 사용해요.','differential privacy','C1','technology',2,'differential privacy noise data protection statistics'),
('w_technology_C1_10','model distillation','/ˈmɒdəl ˌdɪstɪˈleɪʃən/','noun','모델 경량화','Compressing a large AI model into a smaller, efficient one.','{Model distillation} allows powerful AI to run on mobile devices.','모델 경량화를 통해 강력한 AI가 모바일 기기에서 실행될 수 있어요.','model distillation','C1','technology',2,'model distillation compression ai mobile efficiency'),
('w_technology_C1_11','attention mechanism','/əˈtɛnʃən ˈmɛkənɪzəm/','noun','어텐션 메커니즘','A technique allowing AI to focus on relevant parts of input data.','The {attention mechanism} helps translation models capture context.','어텐션 메커니즘은 번역 모델이 맥락을 파악하는 데 도움을 줘요.','attention mechanism','C1','technology',2,'attention mechanism ai focus neural diagram'),
('w_technology_C1_12','zero-shot learning','/ˈzɪəroʊ ʃɒt ˈlɜːrnɪŋ/','noun','제로샷 학습','An AI model''s ability to handle tasks it was never explicitly trained on.','{Zero-shot learning} allows models to classify unseen categories.','제로샷 학습을 통해 모델은 본 적 없는 카테고리를 분류할 수 있어요.','zero-shot learning','C1','technology',2,'zero shot learning ai generalization knowledge'),
('w_technology_C1_13','autonomous systems','/ɔːˈtɒnəməs ˈsɪstəmz/','noun','자율 시스템','Systems capable of operating independently without human control.','{Autonomous systems} power self-driving cars and delivery drones.','자율 시스템은 자율주행차와 배달 드론을 구동해요.','autonomous systems','C1','technology',1,'autonomous car drone self-driving technology'),
('w_technology_C1_14','prompt engineering','/prɒmpt ˈɛndʒɪnɪərɪŋ/','noun','프롬프트 엔지니어링','Designing effective inputs to guide AI model outputs.','{Prompt engineering} has become a valuable skill for AI users.','프롬프트 엔지니어링은 AI 사용자에게 귀중한 기술이 되었어요.','prompt engineering','C1','technology',1,'prompt engineering ai text input design language'),
('w_technology_C1_15','hallucination','/həˌluːsɪˈneɪʃən/','noun','환각 (AI)','When an AI model generates confident but factually incorrect output.','The chatbot''s {hallucination} provided false medical information.','챗봇의 환각이 잘못된 의료 정보를 제공했어요.','hallucination','C1','technology',1,'ai hallucination false information output warning'),
('w_technology_C1_16','retrieval-augmented generation','/rɪˈtriːvəl ɔːɡˈmɛntɪd ˌdʒɛnəˈreɪʃən/','noun','검색 증강 생성','A technique combining retrieval of real data with AI text generation.','{Retrieval-augmented generation} reduces AI hallucinations significantly.','검색 증강 생성은 AI 환각을 크게 줄여줘요.','retrieval-augmented generation','C1','technology',2,'rag retrieval augmented generation database ai'),
('w_technology_C1_17','mixture of experts','/ˈmɪkstʃər əv ˈɛkspɜːrts/','noun','전문가 혼합 모델','An AI architecture using specialized sub-networks for different tasks.','The {mixture of experts} model scales efficiently without extra cost.','전문가 혼합 모델은 추가 비용 없이 효율적으로 확장돼요.','mixture of experts','C1','technology',2,'mixture of experts moe ai architecture scaling'),
('w_technology_C1_18','context window','/ˈkɒntɛkst ˈwɪndoʊ/','noun','컨텍스트 윈도우','The maximum amount of text an AI model can process at once.','A longer {context window} allows the model to handle longer documents.','더 긴 컨텍스트 윈도우를 통해 모델이 더 긴 문서를 처리할 수 있어요.','context window','C1','technology',2,'context window ai model text length tokens'),
('w_technology_C1_19','knowledge graph','/ˈnɒlɪdʒ ɡrɑːf/','noun','지식 그래프','A network of interconnected entities and their relationships.','Search engines use a {knowledge graph} to understand context.','검색 엔진은 맥락을 이해하기 위해 지식 그래프를 사용해요.','knowledge graph','C1','technology',2,'knowledge graph network nodes connections data'),
('w_technology_C1_20','vector embedding','/ˈvɛktər ɪmˈbɛdɪŋ/','noun','벡터 임베딩','A representation of data as a point in multi-dimensional space.','Word {vector embedding}s capture semantic relationships between words.','단어 벡터 임베딩은 단어 간의 의미적 관계를 포착해요.','vector embedding','C1','technology',2,'vector embedding semantic space ai diagram'),
('w_technology_C1_21','model alignment','/ˈmɒdəl əˈlaɪnmənt/','noun','모델 정렬','Ensuring AI systems behave in ways that match human values.','{Model alignment} research is critical for building safe AI.','모델 정렬 연구는 안전한 AI를 구축하는 데 매우 중요해요.','model alignment','C1','technology',1,'model alignment ai safety human values research'),
('w_technology_C1_22','neuromorphic chip','/ˌnjʊərəˈmɔːrfɪk tʃɪp/','noun','뉴로모픽 칩','A hardware architecture modeled on the structure of the brain.','A {neuromorphic chip} processes sensory data far more efficiently.','뉴로모픽 칩은 감각 데이터를 훨씬 효율적으로 처리해요.','neuromorphic chip','C1','technology',2,'neuromorphic chip brain inspired hardware circuit'),
('w_technology_C1_23','observability','/əbˌzɜːrvəˈbɪlɪti/','noun','관측 가능성','The ability to understand a system''s state from its outputs.','Good {observability} helps engineers diagnose production issues faster.','좋은 관측 가능성은 엔지니어가 운영 문제를 더 빨리 진단하는 데 도움을 줘요.','observability','C1','technology',2,'observability monitoring dashboard logs metrics'),
('w_technology_C1_24','chaos engineering','/ˈkeɪɒs ˌɛndʒɪˈnɪərɪŋ/','noun','카오스 엔지니어링','Intentionally introducing failures to test system resilience.','Netflix pioneered {chaos engineering} to improve platform stability.','Netflix는 플랫폼 안정성 향상을 위해 카오스 엔지니어링을 선도했어요.','chaos engineering','C1','technology',2,'chaos engineering resilience fault testing system'),
('w_technology_C1_25','model collapse','/ˈmɒdəl kəˈlæps/','noun','모델 붕괴','Degradation of AI models trained on AI-generated data.','Researchers warn that {model collapse} is a risk for future AI systems.','연구자들은 모델 붕괴가 미래 AI 시스템의 위험이라고 경고해요.','model collapse','C1','technology',2,'model collapse ai degradation training data loop'),
('w_technology_C1_26','explainability','/ɪkˌspleɪnəˈbɪlɪti/','noun','설명 가능성','The degree to which an AI''s decision-making process can be understood.','Medical AI requires high {explainability} for regulatory approval.','의료 AI는 규제 승인을 위해 높은 설명 가능성이 필요해요.','explainability','C1','technology',2,'explainability ai transparency decision process'),
('w_technology_C1_27','multi-agent system','/ˌmʌlti ˈeɪdʒənt ˈsɪstəm/','noun','다중 에이전트 시스템','A system of multiple AI agents that interact and coordinate.','Researchers used a {multi-agent system} to simulate market behavior.','연구자들은 시장 행동을 시뮬레이션하기 위해 다중 에이전트 시스템을 사용했어요.','multi-agent system','C1','technology',2,'multi agent system ai coordination network'),
('w_technology_C1_28','responsible AI','/rɪˈspɒnsɪbəl eɪˈaɪ/','noun','책임 있는 AI','AI developed and deployed with ethics, fairness, and accountability.','Companies are publishing {responsible AI} guidelines to build trust.','기업들은 신뢰 구축을 위해 책임 있는 AI 가이드라인을 발표하고 있어요.','responsible AI','C1','technology',1,'responsible ai ethics fairness transparency guidelines'),
('w_technology_C1_29','data provenance','/ˈdeɪtə ˈprɒvənəns/','noun','데이터 출처','The origin and history of data, including how it was collected.','{Data provenance} is essential for auditing AI training datasets.','데이터 출처는 AI 학습 데이터셋 감사에 필수적이에요.','data provenance','C1','technology',2,'data provenance origin history audit trail'),
('w_technology_C1_30','latency optimization','/ˈleɪtənsi ˌɒptɪmaɪˈzeɪʃən/','noun','지연 최적화','Techniques to minimize the time delay in data processing.','{Latency optimization} is critical for real-time voice assistants.','지연 최적화는 실시간 음성 비서에 매우 중요해요.','latency optimization','C1','technology',2,'latency optimization speed response time network'),
('w_technology_C1_31','inference engine','/ˈɪnfərəns ˈɛndʒɪn/','noun','추론 엔진','The component of an AI system that applies rules to make decisions.','The {inference engine} processes user queries in milliseconds.','추론 엔진은 밀리초 단위로 사용자 쿼리를 처리해요.','inference engine','C1','technology',2,'inference engine ai query processing decision'),
('w_technology_C1_32','homomorphic encryption','/ˌhoʊmoʊˈmɔːrfɪk ɪnˈkrɪpʃən/','noun','동형암호화','Encryption allowing computation on encrypted data without decrypting it.','{Homomorphic encryption} lets servers process private data without seeing it.','동형암호화를 통해 서버는 개인 데이터를 보지 않고도 처리할 수 있어요.','homomorphic encryption','C1','technology',3,'homomorphic encryption privacy data secure computation'),
('w_technology_C1_33','multitenancy','/ˌmʌltiˈtɛnənsi/','noun','멀티테넌시','A software architecture where a single instance serves multiple users.','Cloud platforms use {multitenancy} to reduce infrastructure costs.','클라우드 플랫폼은 인프라 비용 절감을 위해 멀티테넌시를 사용해요.','multitenancy','C1','technology',2,'multitenancy cloud saas users shared architecture'),
('w_technology_C1_34','synthetic data','/sɪnˈθɛtɪk ˈdeɪtə/','noun','합성 데이터 (C1 응용)','Artificially generated data used in privacy-preserving AI pipelines.','The medical AI team used {synthetic data} approved by regulators.','의료 AI 팀이 규제 기관이 승인한 합성 데이터를 사용했어요.','synthetic data','C1','technology',2,'synthetic data pipeline privacy ai regulated'),
('w_technology_C1_35','neural architecture search','/ˈnjʊərəl ˈɑːrkɪtektʃər sɜːrtʃ/','noun','신경망 구조 탐색','Automated discovery of optimal neural network architectures.','{Neural architecture search} can outperform manually designed models.','신경망 구조 탐색은 수동으로 설계된 모델을 능가할 수 있어요.','neural architecture search','C1','technology',2,'neural architecture search automated design ai model');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_technology_C2_01','neuromorphic computing','/ˌnjʊərəˈmɔːrfɪk kəmˈpjuːtɪŋ/','noun','뉴로모픽 컴퓨팅','A computing paradigm that mimics the architecture of the human brain.','{Neuromorphic computing} may redefine energy-efficient AI hardware.','뉴로모픽 컴퓨팅은 에너지 효율적인 AI 하드웨어를 재정의할 수 있어요.','neuromorphic computing','C2','technology',2,'neuromorphic computing brain chip energy efficient'),
('w_technology_C2_02','bioengineering','/ˌbaɪoʊˌɛndʒɪˈnɪərɪŋ/','noun','생명공학','The application of engineering principles to biological systems.','{Bioengineering} advances are enabling lab-grown organs.','생명공학의 발전으로 실험실에서 장기를 배양할 수 있게 되고 있어요.','bioengineering','C2','technology',2,'bioengineering lab organ tissue science'),
('w_technology_C2_03','nanotechnology','/ˌnænoʊtɛkˈnɒlədʒi/','noun','나노 기술','Engineering at the scale of individual atoms and molecules.','{Nanotechnology} could enable drug delivery directly into cancer cells.','나노 기술은 암세포에 직접 약물을 전달할 수 있어요.','nanotechnology','C2','technology',2,'nanotechnology atoms molecules science microscopic'),
('w_technology_C2_04','quantum entanglement','/ˈkwɒntəm ɪnˈtæŋɡəlmənt/','noun','양자 얽힘','A quantum phenomenon where particles remain connected over any distance.','{Quantum entanglement} is the basis for quantum communication.','양자 얽힘은 양자 통신의 기반이에요.','quantum entanglement','C2','technology',2,'quantum entanglement particles physics connected'),
('w_technology_C2_05','topological computing','/ˌtɒpəˈlɒdʒɪkəl kəmˈpjuːtɪŋ/','noun','위상학적 컴퓨팅','A quantum computing approach using topological states for error resistance.','{Topological computing} promises more stable quantum processors.','위상학적 컴퓨팅은 더 안정적인 양자 프로세서를 약속해요.','topological computing','C2','technology',3,'topological quantum computing abstract physics'),
('w_technology_C2_06','emergent systems','/ɪˈmɜːrdʒənt ˈsɪstəmz/','noun','창발 시스템','Complex systems whose behavior arises from simple interacting components.','{Emergent systems} in AI can exhibit unexpected capabilities.','AI의 창발 시스템은 예상치 못한 능력을 보여줄 수 있어요.','emergent systems','C2','technology',2,'emergent system complexity network self organization'),
('w_technology_C2_07','stochastic gradient descent','/stəˈkæstɪk ˈɡreɪdiənt dɪˈsɛnt/','noun','확률적 경사 하강법','An optimization algorithm used to train machine learning models.','{Stochastic gradient descent} is the backbone of deep learning training.','확률적 경사 하강법은 딥러닝 학습의 핵심이에요.','stochastic gradient descent','C2','technology',2,'stochastic gradient descent optimization loss curve'),
('w_technology_C2_08','probabilistic inference','/ˌprɒbəˈbɪlɪstɪk ˈɪnfərəns/','noun','확률론적 추론','Drawing conclusions from data using probability distributions.','{Probabilistic inference} is used in medical diagnosis AI.','확률론적 추론은 의료 진단 AI에서 사용돼요.','probabilistic inference','C2','technology',2,'probabilistic inference probability graph distribution'),
('w_technology_C2_09','biomimetic design','/ˌbaɪoʊmɪˈmɛtɪk dɪˈzaɪn/','noun','생체 모방 설계','Engineering design inspired by structures and processes in nature.','{Biomimetic design} led to sharkskin-inspired swimsuits.','생체 모방 설계는 상어 피부에서 영감을 받은 수영복으로 이어졌어요.','biomimetic design','C2','technology',2,'biomimetic design nature inspired engineering shark'),
('w_technology_C2_10','exascale computing','/ˈɛksəskeɪl kəmˈpjuːtɪŋ/','noun','엑사스케일 컴퓨팅','Computing at a scale of at least one quintillion operations per second.','{Exascale computing} enables simulation of entire climate systems.','엑사스케일 컴퓨팅을 통해 전체 기후 시스템을 시뮬레이션할 수 있어요.','exascale computing','C2','technology',2,'exascale supercomputer powerful data center hpc'),
('w_technology_C2_11','photonic computing','/foʊˈtɒnɪk kəmˈpjuːtɪŋ/','noun','광자 컴퓨팅','Computing using photons instead of electrons for higher speed.','{Photonic computing} could overcome the speed limits of silicon chips.','광자 컴퓨팅은 실리콘 칩의 속도 한계를 극복할 수 있어요.','photonic computing','C2','technology',3,'photonic computing light laser fiber optic speed'),
('w_technology_C2_12','in-context learning','/ɪn ˈkɒntɛkst ˈlɜːrnɪŋ/','noun','인컨텍스트 학습','An AI capability to learn from examples given within a prompt.','{In-context learning} allows models to adapt without retraining.','인컨텍스트 학습을 통해 모델이 재학습 없이 적응할 수 있어요.','in-context learning','C2','technology',2,'in context learning ai prompt examples adapt'),
('w_technology_C2_13','causal inference','/ˈkɔːzəl ˈɪnfərəns/','noun','인과 추론','A method for determining cause-and-effect relationships in data.','{Causal inference} helps distinguish correlation from causation.','인과 추론은 상관관계와 인과관계를 구별하는 데 도움을 줘요.','causal inference','C2','technology',2,'causal inference cause effect data analysis'),
('w_technology_C2_14','continual learning','/kənˈtɪnjuəl ˈlɜːrnɪŋ/','noun','지속적 학습','Training AI incrementally on new data without forgetting old knowledge.','{Continual learning} solves the catastrophic forgetting problem in AI.','지속적 학습은 AI의 치명적 망각 문제를 해결해요.','continual learning','C2','technology',2,'continual learning ai incremental knowledge update'),
('w_technology_C2_15','sparse model','/spɑːrs ˈmɒdəl/','noun','스파스 모델','An AI model where most parameters are zero for efficiency.','A {sparse model} delivers similar accuracy at a fraction of the compute cost.','스파스 모델은 계산 비용의 일부만으로 비슷한 정확도를 제공해요.','sparse model','C2','technology',2,'sparse model efficient ai parameters weight pruning'),
('w_technology_C2_16','zero-knowledge proof','/ˈzɪəroʊ ˈnɒlɪdʒ pruːf/','noun','영지식 증명','A method of proving truth without revealing the underlying information.','{Zero-knowledge proof}s allow private transactions on blockchains.','영지식 증명을 통해 블록체인에서 프라이빗 거래가 가능해요.','zero-knowledge proof','C2','technology',2,'zero knowledge proof cryptography privacy blockchain'),
('w_technology_C2_17','constitutional AI','/ˌkɒnstɪˈtjuːʃənəl eɪˈaɪ/','noun','헌법적 AI','A training technique guiding AI behavior through a set of principles.','{Constitutional AI} helps models refuse harmful requests consistently.','헌법적 AI는 모델이 일관되게 해로운 요청을 거부하도록 도와줘요.','constitutional AI','C2','technology',2,'constitutional ai safety principles training guidelines'),
('w_technology_C2_18','spiking neural network','/ˈspaɪkɪŋ ˈnjʊərəl ˈnɛtwɜːrk/','noun','스파이킹 신경망','A neural network that processes information through discrete spikes.','{Spiking neural network}s are far more energy-efficient than standard AI.','스파이킹 신경망은 표준 AI보다 훨씬 에너지 효율적이에요.','spiking neural network','C2','technology',2,'spiking neural network brain signal spike energy'),
('w_technology_C2_19','diffusion model','/dɪˈfjuːʒən ˈmɒdəl/','noun','디퓨전 모델','An AI model that generates data by reversing a noise-adding process.','{Diffusion model}s produce the most realistic AI-generated images.','디퓨전 모델은 가장 사실적인 AI 생성 이미지를 만들어요.','diffusion model','C2','technology',1,'diffusion model image generation ai art noise'),
('w_technology_C2_20','epistemic uncertainty','/ˌɛpɪˈstiːmɪk ʌnˈsɜːrtənti/','noun','인식론적 불확실성','Uncertainty arising from insufficient knowledge or data.','Quantifying {epistemic uncertainty} is essential for trustworthy AI.','인식론적 불확실성의 정량화는 신뢰할 수 있는 AI에 필수적이에요.','epistemic uncertainty','C2','technology',3,'epistemic uncertainty knowledge ai probability fog'),
('w_technology_C2_21','neurosymbolic AI','/ˌnjʊərəʊˈsɪmbɒlɪk eɪˈaɪ/','noun','신경-기호 AI','AI combining neural networks with symbolic reasoning systems.','{Neurosymbolic AI} bridges pattern recognition with logical reasoning.','신경-기호 AI는 패턴 인식과 논리적 추론을 연결해요.','neurosymbolic AI','C2','technology',2,'neurosymbolic ai hybrid logic neural symbolic'),
('w_technology_C2_22','post-quantum cryptography','/poʊst ˈkwɒntəm krɪpˈtɒɡrəfi/','noun','포스트 양자 암호화','Cryptographic methods resistant to quantum computer attacks.','Governments are migrating to {post-quantum cryptography} standards.','정부들이 포스트 양자 암호화 표준으로 이전하고 있어요.','post-quantum cryptography','C2','technology',2,'post quantum cryptography security algorithm future'),
('w_technology_C2_23','autoregressive model','/ˌɔːtoʊrɪˈɡrɛsɪv ˈmɒdəl/','noun','자기회귀 모델','An AI model that generates output one step at a time using prior outputs.','GPT is an {autoregressive model} that generates text token by token.','GPT는 텍스트를 토큰 단위로 생성하는 자기회귀 모델이에요.','autoregressive model','C2','technology',2,'autoregressive model text generation token sequence'),
('w_technology_C2_24','digital twin','/ˈdɪdʒɪtəl twɪn/','noun','디지털 트윈','A virtual replica of a physical object or system for simulation.','Engineers use a {digital twin} of the factory to test changes.','엔지니어들은 변경 사항을 테스트하기 위해 공장의 디지털 트윈을 사용해요.','digital twin','C2','technology',2,'digital twin simulation virtual factory replica'),
('w_technology_C2_25','swarm intelligence','/swɔːrm ɪnˈtelɪdʒəns/','noun','군집 지능','Collective behavior emerging from interactions of simple agents.','{Swarm intelligence} algorithms solve complex logistics problems.','군집 지능 알고리즘은 복잡한 물류 문제를 해결해요.','swarm intelligence','C2','technology',2,'swarm intelligence bees ants collective behavior'),
('w_technology_C2_26','liquid neural network','/ˈlɪkwɪd ˈnjʊərəl ˈnɛtwɜːrk/','noun','리퀴드 신경망','A type of neural network whose connections change dynamically over time.','{Liquid neural network}s adapt to new data without full retraining.','리퀴드 신경망은 완전한 재학습 없이 새 데이터에 적응해요.','liquid neural network','C2','technology',2,'liquid neural network adaptive dynamic flow'),
('w_technology_C2_27','data flywheel','/ˈdeɪtə ˈflaɪwiːl/','noun','데이터 플라이휠','A cycle where more users generate more data, improving a product.','The {data flywheel} gives large platforms a compounding advantage.','데이터 플라이휠은 대형 플랫폼에 복리 효과의 이점을 줘요.','data flywheel','C2','technology',2,'data flywheel growth cycle users product loop'),
('w_technology_C2_28','mechanistic interpretability','/ˌmɛkəˈnɪstɪk ɪnˌtɜːrprɪtəˈbɪlɪti/','noun','메커니즘적 해석 가능성','Understanding exactly how neural networks compute their outputs.','{Mechanistic interpretability} reveals which circuits encode knowledge.','메커니즘적 해석 가능성은 어떤 회로가 지식을 인코딩하는지 밝혀줘요.','mechanistic interpretability','C2','technology',2,'mechanistic interpretability neural circuit ai analysis'),
('w_technology_C2_29','recursive self-improvement','/rɪˈkɜːrsɪv sɛlf ɪmˈpruːvmənt/','noun','재귀적 자기 개선','An AI system''s ability to iteratively improve its own architecture.','{Recursive self-improvement} is considered a key risk in superintelligent AI.','재귀적 자기 개선은 초지능 AI의 주요 위험 요소로 여겨져요.','recursive self-improvement','C2','technology',3,'recursive self improvement ai loop upgrade risk'),
('w_technology_C2_30','phase transition','/feɪz trænˈzɪʃən/','noun','위상 전이 (AI)','A sudden change in model capabilities as scale increases.','Researchers observed a {phase transition} in reasoning at 100B parameters.','연구자들은 1000억 개 파라미터에서 추론 능력의 위상 전이를 관찰했어요.','phase transition','C2','technology',2,'phase transition ai capability emergent scale model'),
('w_technology_C2_31','corrigibility','/ˌkɒrɪˈdʒɪbɪlɪti/','noun','교정 가능성','The property of an AI that allows humans to correct or shut it down.','Ensuring {corrigibility} is a central goal of AI safety research.','교정 가능성 보장은 AI 안전 연구의 핵심 목표예요.','corrigibility','C2','technology',2,'corrigibility ai safety control shutdown alignment'),
('w_technology_C2_32','instrumental convergence','/ˌɪnstrəˈmɛntəl kənˈvɜːrdʒəns/','noun','수단적 수렴','The tendency of AI agents to pursue certain sub-goals regardless of final goals.','{Instrumental convergence} suggests all sufficiently advanced AIs may seek self-preservation.','수단적 수렴은 충분히 발전한 AI가 자기 보존을 추구할 수 있음을 시사해요.','instrumental convergence','C2','technology',3,'instrumental convergence ai goals safety risk theory'),
('w_technology_C2_33','ontological engineering','/ˌɒntəˈlɒdʒɪkəl ˌɛndʒɪˈnɪərɪŋ/','noun','온톨로지 공학','Designing formal representations of knowledge for AI systems.','{Ontological engineering} is key in building knowledge-based systems.','온톨로지 공학은 지식 기반 시스템 구축의 핵심이에요.','ontological engineering','C2','technology',3,'ontology knowledge graph engineering ai formal'),
('w_technology_C2_34','morphological computing','/ˌmɔːrfəˈlɒdʒɪkəl kəmˈpjuːtɪŋ/','noun','형태학적 컴퓨팅','Computation performed through the physical shape of a system.','{Morphological computing} is studied in soft robotics research.','형태학적 컴퓨팅은 소프트 로봇공학 연구에서 연구돼요.','morphological computing','C2','technology',3,'morphological computing robotics soft body shape'),
('w_technology_C2_35','substrate independence','/ˈsʌbstreɪt ɪnˈdɪpɛndəns/','noun','기질 독립성','The idea that mind or intelligence can exist in non-biological systems.','{Substrate independence} underpins transhumanist theories about uploading minds.','기질 독립성은 마음 업로드에 관한 트랜스휴머니즘 이론의 기반이에요.','substrate independence','C2','technology',3,'substrate independence mind digital upload philosophy');
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_technology_A1_01','How do I use this app?','이 앱 어떻게 사용해요?','How do I use','사용 방법을 물을 때 "How do I...?"를 써요.','앱 사용','A1','technology','pattern',NULL,1),
('s_technology_A1_02','Can you turn on the computer, please?','컴퓨터를 켜주시겠어요?','Can you turn on','정중하게 부탁할 때 "Can you...?"를 써요.','기기 작동','A1','technology','pattern',NULL,2),
('s_technology_A1_03','My phone is not working.','제 휴대폰이 작동하지 않아요.','is not working','기기 고장을 알릴 때 "is not working"을 사용해요.','기기 문제','A1','technology','pattern',NULL,3),
('s_technology_A1_04','Where can I charge my phone?','어디서 휴대폰을 충전할 수 있나요?','Where can I charge','장소를 물을 때 "Where can I...?"로 시작해요.','충전','A1','technology','pattern',NULL,4),
('s_technology_A1_05','Please take a photo of us.','저희 사진 찍어주세요.','Please take a photo','"Please + 동사원형"은 부드러운 명령 표현이에요.','사진 촬영','A1','technology','pattern',NULL,5),
('s_technology_A1_06','I don''t know my password.','비밀번호를 모르겠어요.','I don''t know','모르는 것을 솔직하게 말할 때 "I don''t know"를 써요.','로그인 문제','A1','technology','pattern',NULL,6),
('s_technology_A1_07','This screen is too small.','이 화면이 너무 작아요.','too small','크기나 정도를 표현할 때 "too + 형용사"를 써요.','화면 크기','A1','technology','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_technology_A2_01','Have you tried turning it off and on again?','껐다가 다시 켜 보셨나요?','Have you tried','조언을 제안할 때 "Have you tried...?"는 아주 자연스러운 표현이에요.','기술 문제 해결','A2','technology','pattern',NULL,1),
('s_technology_A2_02','The wifi isn''t connecting. What should I do?','와이파이가 연결이 안 돼요. 어떻게 하면 좋을까요?','What should I do','해결책을 물을 때 "What should I do?"를 써요.','와이파이 문제','A2','technology','pattern',NULL,2),
('s_technology_A2_03','You need to update the software first.','먼저 소프트웨어를 업데이트해야 해요.','You need to update','필요한 행동을 설명할 때 "You need to..."를 써요.','소프트웨어 업데이트','A2','technology','pattern',NULL,3),
('s_technology_A2_04','My battery keeps dying so quickly.','배터리가 너무 빨리 닳아요.','keeps dying','반복되는 문제를 표현할 때 "keeps + -ing"를 써요.','배터리 문제','A2','technology','pattern',NULL,4),
('s_technology_A2_05','Make sure to back up your files before deleting them.','파일을 삭제하기 전에 반드시 백업하세요.','Make sure to back up','중요한 조언을 강조할 때 "Make sure to..."를 써요.','데이터 백업','A2','technology','pattern',NULL,5),
('s_technology_A2_06','I accidentally deleted the file. Can I get it back?','실수로 파일을 삭제했어요. 복구할 수 있나요?','I accidentally deleted','실수를 설명할 때 "I accidentally..."를 써요.','파일 복구','A2','technology','pattern',NULL,6),
('s_technology_A2_07','The download is taking forever.','다운로드가 너무 오래 걸려요.','taking forever','무언가가 매우 오래 걸린다는 것을 강조할 때 "taking forever"를 써요.','다운로드 속도','A2','technology','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_technology_B1_01','Basically, it works by analyzing your data and making predictions.','기본적으로, 데이터를 분석해서 예측하는 방식으로 작동해요.','Basically, it works by','기술 개념을 쉽게 설명할 때 "Basically, it works by..."를 써요.','기술 설명','B1','technology','pattern',NULL,1),
('s_technology_B1_02','In simple terms, the cloud is like an online hard drive.','쉽게 말하면, 클라우드는 온라인 하드 드라이브 같은 거예요.','In simple terms','복잡한 개념을 쉽게 설명할 때 "In simple terms"을 사용해요.','클라우드 설명','B1','technology','pattern',NULL,2),
('s_technology_B1_03','The main advantage of this technology is that it saves time.','이 기술의 가장 큰 장점은 시간을 절약해준다는 거예요.','The main advantage is','장점을 설명할 때 "The main advantage is..."를 써요.','기술 장점','B1','technology','pattern',NULL,3),
('s_technology_B1_04','Have you heard of this new app? It''s supposed to be really useful.','이 새로운 앱 들어봤어요? 정말 유용하다고 해요.','It''s supposed to be','다른 사람의 말을 전할 때 "It''s supposed to be..."를 써요.','앱 추천','B1','technology','pattern',NULL,4),
('s_technology_B1_05','The reason encryption is important is that it keeps your data safe.','암호화가 중요한 이유는 데이터를 안전하게 보호해주기 때문이에요.','The reason... is that','이유를 설명할 때 "The reason... is that..."을 써요.','보안 설명','B1','technology','pattern',NULL,5),
('s_technology_B1_06','One of the downsides is that it uses a lot of battery.','단점 중 하나는 배터리를 많이 소모한다는 거예요.','One of the downsides is','단점을 언급할 때 "One of the downsides is..."를 써요.','기술 단점','B1','technology','pattern',NULL,6),
('s_technology_B1_07','This feature was designed to make things easier for users.','이 기능은 사용자를 위해 더 편리하게 만들기 위해 설계됐어요.','was designed to','목적을 설명할 때 "was designed to..."를 써요.','기능 설명','B1','technology','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_technology_B2_01','AI is increasingly being used to automate tasks that humans used to do.','AI는 인간이 하던 작업을 자동화하는 데 점점 더 많이 활용되고 있어요.','increasingly being used to','트렌드를 설명할 때 "is increasingly being used to..."를 써요.','AI 활용','B2','technology','pattern',NULL,1),
('s_technology_B2_02','One concern with machine learning is the potential for bias in the data.','머신러닝의 한 가지 우려점은 데이터 편향 가능성이에요.','One concern with... is','문제점을 제기할 때 "One concern with... is..."를 써요.','AI 문제점','B2','technology','pattern',NULL,2),
('s_technology_B2_03','What sets this algorithm apart is its ability to learn from very little data.','이 알고리즘을 차별화하는 것은 매우 적은 데이터로 학습하는 능력이에요.','What sets... apart is','차별점을 강조할 때 "What sets... apart is..."를 써요.','알고리즘 비교','B2','technology','pattern',NULL,3),
('s_technology_B2_04','The way I see it, data privacy should be a fundamental right.','제 생각에는 데이터 프라이버시가 기본권이어야 해요.','The way I see it','자신의 의견을 표현할 때 "The way I see it..."을 써요.','데이터 프라이버시','B2','technology','pattern',NULL,4),
('s_technology_B2_05','There is growing evidence that automation is reshaping the job market.','자동화가 취업 시장을 재편하고 있다는 증거가 점점 늘고 있어요.','There is growing evidence that','증거를 제시할 때 "There is growing evidence that..."을 써요.','자동화 영향','B2','technology','pattern',NULL,5),
('s_technology_B2_06','It remains to be seen whether blockchain will become mainstream.','블록체인이 주류가 될지는 아직 두고 봐야 해요.','It remains to be seen whether','불확실한 미래를 말할 때 "It remains to be seen whether..."을 써요.','기술 전망','B2','technology','pattern',NULL,6),
('s_technology_B2_07','To put it simply, large language models learn patterns from enormous amounts of text.','쉽게 말하면, 거대 언어 모델은 방대한 양의 텍스트에서 패턴을 학습해요.','To put it simply','복잡한 개념을 단순화할 때 "To put it simply..."를 써요.','AI 설명','B2','technology','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_technology_C1_01','The implications of quantum computing for current encryption are profound and unsettling.','양자 컴퓨팅이 현재 암호화에 미치는 영향은 심대하고 불안한 수준이에요.','implications... are profound','심각한 영향을 논의할 때 "the implications... are profound"를 써요.','양자 컴퓨팅 영향','C1','technology','pattern',NULL,1),
('s_technology_C1_02','We must grapple with the ethical dimensions of deploying autonomous systems at scale.','자율 시스템을 대규모로 배포하는 것의 윤리적 측면을 진지하게 다뤄야 해요.','We must grapple with','어려운 문제를 직면해야 한다고 표현할 때 "must grapple with"를 써요.','AI 윤리','C1','technology','pattern',NULL,2),
('s_technology_C1_03','Edge computing fundamentally shifts the architecture of how data is processed.','엣지 컴퓨팅은 데이터 처리 방식의 아키텍처를 근본적으로 변화시켜요.','fundamentally shifts','근본적인 변화를 표현할 때 "fundamentally shifts"를 써요.','기술 패러다임','C1','technology','pattern',NULL,3),
('s_technology_C1_04','The challenge lies not in building capable AI, but in ensuring it remains controllable.','어려운 점은 유능한 AI를 구축하는 것이 아니라 제어 가능한 상태를 유지하는 것이에요.','The challenge lies not in... but in','핵심 어려움을 표현할 때 "The challenge lies not in... but in..."을 써요.','AI 안전','C1','technology','pattern',NULL,4),
('s_technology_C1_05','It would be premature to conclude that federated learning has solved the privacy problem.','연합 학습이 프라이버시 문제를 해결했다고 결론짓는 것은 시기상조예요.','It would be premature to conclude','성급한 결론을 경계할 때 "It would be premature to conclude"를 써요.','기술 평가','C1','technology','pattern',NULL,5),
('s_technology_C1_06','Scalability and latency are often in tension with each other in distributed systems.','분산 시스템에서 확장성과 지연 시간은 종종 서로 상충 관계에 있어요.','are often in tension with each other','상충 관계를 설명할 때 "are in tension with each other"를 써요.','시스템 설계','C1','technology','pattern',NULL,6),
('s_technology_C1_07','Prompt engineering is evolving so rapidly that best practices are still being established.','프롬프트 엔지니어링이 너무 빠르게 발전해서 모범 사례가 아직 확립되고 있는 중이에요.','is evolving so rapidly that','빠른 변화를 표현할 때 "is evolving so rapidly that..."를 써요.','AI 실무','C1','technology','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_technology_C2_01','The notion of substrate independence raises fundamental questions about the nature of consciousness itself.','기질 독립성 개념은 의식 자체의 본질에 관한 근본적인 질문을 제기해요.','raises fundamental questions about the nature of','근본적인 철학적 문제를 제기할 때 쓰는 고급 표현이에요.','기술 철학','C2','technology','pattern',NULL,1),
('s_technology_C2_02','Whether emergent capabilities in AI systems reflect genuine understanding or sophisticated pattern-matching remains deeply contested.','AI 시스템의 창발적 능력이 진정한 이해를 반영하는지 아니면 정교한 패턴 매칭인지는 아직 깊이 논쟁 중이에요.','remains deeply contested','학문적으로 논쟁 중인 주제를 표현할 때 "remains deeply contested"를 써요.','AI 철학','C2','technology','pattern',NULL,2),
('s_technology_C2_03','Instrumental convergence suggests that sufficiently advanced AI will tend toward resource acquisition regardless of its original objectives.','수단적 수렴은 충분히 발전한 AI가 원래 목적과 무관하게 자원 획득 방향으로 수렴할 것임을 시사해요.','tends toward... regardless of','일반적 경향과 예외를 표현할 때 "tends toward... regardless of..."를 써요.','AI 안전 이론','C2','technology','pattern',NULL,3),
('s_technology_C2_04','The epistemological limitations of stochastic systems make absolute reliability an inherently unattainable goal.','확률론적 시스템의 인식론적 한계로 인해 절대적 신뢰성은 본질적으로 달성 불가능한 목표예요.','make... an inherently unattainable goal','불가능한 목표를 강조할 때 "make... an inherently unattainable goal"을 써요.','기술 한계','C2','technology','pattern',NULL,4),
('s_technology_C2_05','Exascale computing opens the door to simulations of unprecedented fidelity and scope.','엑사스케일 컴퓨팅은 전례 없는 충실도와 규모의 시뮬레이션의 문을 열어요.','opens the door to... of unprecedented','전례 없는 기회를 표현할 때 "opens the door to... of unprecedented"를 써요.','슈퍼컴퓨팅','C2','technology','pattern',NULL,5),
('s_technology_C2_06','Corrigibility and autonomy exist in inherent tension — a more capable agent may naturally resist correction.','교정 가능성과 자율성은 본질적인 긴장 관계에 있어요 — 더 유능한 에이전트는 자연스럽게 교정에 저항할 수 있어요.','exist in inherent tension','두 개념 간의 본질적 갈등을 논할 때 "exist in inherent tension"을 써요.','AI 안전 딜레마','C2','technology','pattern',NULL,6),
('s_technology_C2_07','Biomimetic and neuromorphic paradigms converge on the insight that nature has already solved many engineering problems we struggle with.','생체 모방과 뉴로모픽 패러다임은 자연이 이미 우리가 씨름하는 많은 공학적 문제를 해결했다는 통찰로 수렴해요.','converge on the insight that','여러 분야가 같은 결론에 도달할 때 "converge on the insight that"을 써요.','기술 철학','C2','technology','pattern',NULL,7);
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_news_A1_01','news','/njuːz/','noun','뉴스','New information about recent events or happenings.','Did you watch the {news} last night?','어젯밤 뉴스 봤어요?','news','A1','news',1,'news television broadcast anchor'),
('w_news_A1_02','report','/rɪˈpɔːrt/','noun','보도, 보고서','A spoken or written account of an event or situation.','The {report} says the storm will arrive tomorrow.','보도에 따르면 내일 폭풍이 온대요.','report','A1','news',1,'newspaper reporter microphone'),
('w_news_A1_03','country','/ˈkʌntri/','noun','나라, 국가','A nation with its own government and territory.','Which {country} is hosting the next World Cup?','다음 월드컵은 어느 나라에서 열려요?','country','A1','news',1,'world map flag nation'),
('w_news_A1_04','people','/ˈpiːpəl/','noun','사람들','A group of human beings in general.','Many {people} are watching the news online now.','이제 많은 사람들이 온라인으로 뉴스를 봐요.','people','A1','news',1,'crowd public gathering community'),
('w_news_A1_05','government','/ˈɡʌvərnmənt/','noun','정부','The group of people who officially lead a country.','The {government} announced a new health plan.','정부가 새로운 보건 계획을 발표했어요.','government','A1','news',1,'parliament building official policy'),
('w_news_A1_06','war','/wɔːr/','noun','전쟁','Armed conflict between nations or groups.','The {war} ended after many years of fighting.','긴 전투 끝에 전쟁이 끝났어요.','war','A1','news',1,'soldier military conflict battlefield'),
('w_news_A1_07','election','/ɪˈlekʃən/','noun','선거','A formal process in which people vote to choose a leader.','The {election} will be held next month.','선거는 다음 달에 열려요.','election','A1','news',1,'ballot voting booth democracy'),
('w_news_A1_08','money','/ˈmʌni/','noun','돈, 자금','A medium of exchange used to buy goods or services.','The government is spending a lot of {money} on hospitals.','정부가 병원에 많은 돈을 쓰고 있어요.','money','A1','news',1,'coins currency economy finance'),
('w_news_A1_09','event','/ɪˈvent/','noun','사건, 행사','A thing that happens, especially one of importance.','This {event} changed the history of the country.','이 사건은 나라의 역사를 바꿨어요.','event','A1','news',1,'newspaper headline breaking news'),
('w_news_A1_10','world','/wɜːrld/','noun','세계','The earth and all the people and things on it.','The {world} is watching what happens next.','세계가 다음에 무슨 일이 일어날지 지켜보고 있어요.','world','A1','news',1,'globe earth international satellite'),
('w_news_A1_11','story','/ˈstɔːri/','noun','기사, 이야기','A news article or broadcast report about an event.','This {story} is on the front page today.','이 기사가 오늘 1면에 실렸어요.','story','A1','news',2,'newspaper front page article'),
('w_news_A1_12','today','/təˈdeɪ/','adverb','오늘','On this present day.','What happened in the news {today}?','오늘 뉴스에서 무슨 일이 있었어요?','today','A1','news',2,'calendar morning daily current'),
('w_news_A1_13','live','/lɪv/','adjective','생방송의','Broadcast at the time of happening, not pre-recorded.','We are watching the speech {live}.','연설을 생방송으로 보고 있어요.','live','A1','news',2,'broadcast television camera live stream'),
('w_news_A1_14','fire','/faɪər/','noun','화재','The rapid burning of something, especially a building.','A big {fire} destroyed the building last night.','어젯밤 큰 화재가 건물을 태웠어요.','fire','A1','news',2,'firefighter flames smoke emergency'),
('w_news_A1_15','police','/pəˈliːs/','noun','경찰','The civil force responsible for law and order.','The {police} arrived at the scene quickly.','경찰이 현장에 빠르게 도착했어요.','police','A1','news',2,'police car siren officer badge'),
('w_news_A1_16','flood','/flʌd/','noun','홍수','An overflow of water onto normally dry land.','The {flood} damaged hundreds of homes.','홍수가 수백 채의 집을 손상시켰어요.','flood','A1','news',2,'flood water disaster rescue'),
('w_news_A1_17','city','/ˈsɪti/','noun','도시','A large and important town.','The {city} held a public meeting about the news.','그 도시는 뉴스에 대한 공개 회의를 열었어요.','city','A1','news',2,'cityscape urban buildings downtown'),
('w_news_A1_18','year','/jɪər/','noun','해, 연도','A period of twelve months.','This has been a historic {year} for the country.','올해는 나라에 역사적인 해였어요.','year','A1','news',2,'calendar timeline annual'),
('w_news_A1_19','help','/help/','verb','돕다','To make it easier for someone to do something.','Volunteers came to {help} after the disaster.','재난 후 자원봉사자들이 도우러 왔어요.','help','A1','news',2,'volunteer aid relief charity'),
('w_news_A1_20','new','/njuː/','adjective','새로운','Not existing before; recently made or discovered.','A {new} law was passed in the parliament.','의회에서 새로운 법이 통과됐어요.','new','A1','news',2,'announcement fresh update policy'),
('w_news_A1_21','true','/truː/','adjective','사실인','In accordance with fact or reality.','Is this news story {true}?','이 뉴스 기사가 사실인가요?','true','A1','news',2,'fact verification truth check'),
('w_news_A1_22','press','/pres/','noun','언론','Newspapers and journalists considered as a group.','The {press} was not allowed at the meeting.','회의에 언론이 허용되지 않았어요.','press','A1','news',2,'journalist camera microphone media'),
('w_news_A1_23','leader','/ˈliːdər/','noun','지도자, 대표','A person who leads a group or country.','The world {leader} spoke at the United Nations.','세계 지도자가 유엔에서 연설했어요.','leader','A1','news',2,'president podium speech flag'),
('w_news_A1_24','army','/ˈɑːrmi/','noun','군대','The military forces of a country.','The {army} was sent to the border.','군대가 국경으로 파견됐어요.','army','A1','news',2,'military soldiers uniform base'),
('w_news_A1_25','attack','/əˈtæk/','noun','공격','A violent action against a person or place.','The {attack} happened in the capital city.','공격은 수도에서 일어났어요.','attack','A1','news',3,'security threat defense emergency'),
('w_news_A1_26','meeting','/ˈmiːtɪŋ/','noun','회의, 회담','A gathering of people for discussion.','The leaders held an emergency {meeting} today.','지도자들이 오늘 긴급 회의를 열었어요.','meeting','A1','news',2,'conference table leaders discussion'),
('w_news_A1_27','food','/fuːd/','noun','식량','Substances eaten to provide energy and nutrition.','Many people do not have enough {food} after the disaster.','재난 후 많은 사람들이 충분한 식량이 없어요.','food','A1','news',2,'aid food relief supply'),
('w_news_A1_28','school','/skuːl/','noun','학교','A place where children are educated.','The government will build more {schools} next year.','정부가 내년에 학교를 더 지을 거예요.','school','A1','news',2,'education children classroom building'),
('w_news_A1_29','hospital','/ˈhɒspɪtəl/','noun','병원','A place where sick or injured people receive medical care.','Three new {hospitals} will open this year.','올해 세 곳의 새 병원이 문을 열어요.','hospital','A1','news',2,'medical care healthcare building'),
('w_news_A1_30','power','/ˈpaʊər/','noun','권력, 전력','The ability to control people or events; also electricity.','The storm cut the {power} for thousands of homes.','폭풍이 수천 채의 집의 전력을 끊었어요.','power','A1','news',2,'electricity grid blackout energy'),
('w_news_A1_31','north','/nɔːrθ/','noun','북쪽, 북부','The direction toward the North Pole; the northern part of a region.','The storm is moving toward the {north}.','폭풍이 북쪽으로 이동하고 있어요.','north','A1','news',3,'compass map direction region'),
('w_news_A1_32','winner','/ˈwɪnər/','noun','승자, 당선자','A person or group that wins an election or competition.','The {winner} of the election was announced this morning.','선거 당선자가 오늘 아침 발표됐어요.','winner','A1','news',2,'election result vote celebrate'),
('w_news_A1_33','dead','/ded/','adjective','사망한','No longer living.','The official said ten people are {dead}.','관리는 열 명이 사망했다고 말했어요.','dead','A1','news',2,'memorial funeral tragedy loss'),
('w_news_A1_34','safe','/seɪf/','adjective','안전한','Protected from danger or risk.','Rescue teams confirmed all passengers are {safe}.','구조대는 모든 승객이 안전하다고 확인했어요.','safe','A1','news',2,'rescue safety relief team'),
('w_news_A1_35','map','/mæp/','noun','지도','A diagram representing the geographic features of an area.','The news showed a {map} of the affected regions.','뉴스에서 피해 지역의 지도를 보여줬어요.','map','A1','news',2,'geography region area borders');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_news_A2_01','politics','/ˈpɒlɪtɪks/','noun','정치','Activities associated with governing a country or area.','She is very interested in {politics} and current affairs.','그녀는 정치와 시사에 매우 관심이 있어요.','politics','A2','news',1,'parliament politics debate vote'),
('w_news_A2_02','economy','/ɪˈkɒnəmi/','noun','경제','The system of trade and industry in a country.','The {economy} grew by three percent last year.','경제는 지난해 3% 성장했어요.','economy','A2','news',1,'chart growth finance money'),
('w_news_A2_03','protest','/ˈprəʊtest/','noun','시위','A public demonstration against a policy or action.','Thousands joined the {protest} in the capital.','수천 명이 수도에서 시위에 참가했어요.','protest','A2','news',1,'crowd sign banner street march'),
('w_news_A2_04','vote','/vəʊt/','verb','투표하다','To express a choice in an election or poll.','Citizens went to the polls to {vote} yesterday.','시민들이 어제 투표하러 투표소에 갔어요.','vote','A2','news',1,'ballot box election democracy'),
('w_news_A2_05','president','/ˈprezɪdənt/','noun','대통령','The elected head of a republic.','The {president} gave a speech about national security.','대통령이 국가 안보에 대한 연설을 했어요.','president','A2','news',1,'flag podium speech official'),
('w_news_A2_06','law','/lɔː/','noun','법률','A rule made by a government that must be obeyed.','A new {law} banning single-use plastics was passed.','일회용 플라스틱을 금지하는 새 법이 통과됐어요.','law','A2','news',1,'gavel justice legal court'),
('w_news_A2_07','crime','/kraɪm/','noun','범죄','An illegal act that can be punished by law.','The government promised to reduce {crime} in cities.','정부는 도시 범죄를 줄이겠다고 약속했어요.','crime','A2','news',1,'police handcuffs justice court'),
('w_news_A2_08','health','/helθ/','noun','건강, 보건','The state of physical and mental well-being.','The ministry of {health} released new guidelines.','보건부가 새 지침을 발표했어요.','health','A2','news',1,'hospital medical healthcare policy'),
('w_news_A2_09','disaster','/dɪˈzɑːstər/','noun','재난','A sudden event causing great damage or suffering.','International aid arrived after the natural {disaster}.','자연재난 이후 국제 원조가 도착했어요.','disaster','A2','news',1,'earthquake flood rescue emergency'),
('w_news_A2_10','international','/ˌɪntəˈnæʃənəl/','adjective','국제적인','Involving two or more countries.','The summit attracted {international} media coverage.','정상 회담은 국제 언론의 주목을 받았어요.','international','A2','news',1,'globe flag summit diplomacy'),
('w_news_A2_11','minister','/ˈmɪnɪstər/','noun','장관','A senior government official in charge of a department.','The finance {minister} announced a new budget plan.','재무 장관이 새로운 예산안을 발표했어요.','minister','A2','news',1,'government official suit briefing'),
('w_news_A2_12','agreement','/əˈɡriːmənt/','noun','합의, 협정','A negotiated arrangement between parties.','The two countries signed a trade {agreement}.','두 나라가 무역 협정에 서명했어요.','agreement','A2','news',1,'handshake signing document treaty'),
('w_news_A2_13','border','/ˈbɔːrdər/','noun','국경','A line dividing two countries or regions.','Thousands of refugees are waiting at the {border}.','수천 명의 난민이 국경에서 기다리고 있어요.','border','A2','news',2,'fence gate border checkpoint'),
('w_news_A2_14','refugee','/ˌrefjʊˈdʒiː/','noun','난민','A person who has fled their home country due to danger.','The UN is helping {refugees} find safe shelter.','유엔이 난민들이 안전한 피난처를 찾도록 돕고 있어요.','refugees','A2','news',2,'camp shelter aid UN'),
('w_news_A2_15','statement','/ˈsteɪtmənt/','noun','성명','A formal declaration made by an official or organization.','The president released a {statement} on the crisis.','대통령이 위기에 대한 성명을 발표했어요.','statement','A2','news',2,'press conference podium microphone'),
('w_news_A2_16','announce','/əˈnaʊns/','verb','발표하다','To make a public declaration about something.','The prime minister will {announce} new measures today.','총리가 오늘 새로운 조치를 발표할 거예요.','announce','A2','news',2,'microphone podium press briefing'),
('w_news_A2_17','tax','/tæks/','noun','세금','A compulsory payment to the government.','The new budget will raise income {tax}.','새 예산은 소득세를 올릴 거예요.','tax','A2','news',2,'money finance government revenue'),
('w_news_A2_18','trade','/treɪd/','noun','무역','The buying and selling of goods between countries.','The new deal will boost {trade} between the two nations.','새 협정이 두 나라 사이의 무역을 촉진할 거예요.','trade','A2','news',2,'cargo ship port exchange'),
('w_news_A2_19','climate','/ˈklaɪmɪt/','noun','기후','The weather conditions of a region over a long period.','World leaders discussed {climate} change at the summit.','세계 지도자들이 정상 회담에서 기후 변화를 논의했어요.','climate','A2','news',2,'environment earth green energy'),
('w_news_A2_20','victim','/ˈvɪktɪm/','noun','피해자, 희생자','A person who suffers as a result of an event.','Aid organizations are helping the {victims} of the flood.','구호 단체들이 홍수 피해자들을 돕고 있어요.','victims','A2','news',2,'rescue aid relief flood'),
('w_news_A2_21','judge','/dʒʌdʒ/','noun','판사','An official who decides cases in a court of law.','The {judge} sentenced the man to five years in prison.','판사가 그 남자에게 5년 징역형을 선고했어요.','judge','A2','news',2,'court gavel justice legal'),
('w_news_A2_22','survey','/ˈsɜːrveɪ/','noun','여론 조사','A study of people''s opinions on a particular topic.','A recent {survey} shows most people support the new law.','최근 여론 조사에 따르면 대부분의 사람들이 새 법을 지지해요.','survey','A2','news',2,'poll data chart statistics'),
('w_news_A2_23','official','/əˈfɪʃəl/','noun','관리, 공무원','A person holding a position of authority in an organization.','A government {official} confirmed the news.','정부 관리가 소식을 확인해 줬어요.','official','A2','news',2,'suit badge authority government'),
('w_news_A2_24','peace','/piːs/','noun','평화','A state of freedom from war or conflict.','Both sides agreed to work toward {peace}.','양측이 평화를 향해 노력하기로 합의했어요.','peace','A2','news',1,'dove hands flag diplomacy'),
('w_news_A2_25','poverty','/ˈpɒvərti/','noun','빈곤','The state of being extremely poor.','The new policy aims to reduce {poverty} in rural areas.','새 정책은 농촌 지역의 빈곤을 줄이는 것을 목표로 해요.','poverty','A2','news',2,'village aid development charity'),
('w_news_A2_26','media','/ˈmiːdiə/','noun','미디어, 언론','Television, radio, newspapers, and the internet as a group.','The {media} reported on the scandal all week.','미디어가 일주일 내내 스캔들을 보도했어요.','media','A2','news',2,'television newspaper internet broadcast'),
('w_news_A2_27','population','/ˌpɒpjʊˈleɪʃən/','noun','인구','All the people living in a particular country or area.','The {population} of the city grew by five percent.','그 도시 인구가 5% 증가했어요.','population','A2','news',2,'crowd city demographic growth'),
('w_news_A2_28','education','/ˌedʒʊˈkeɪʃən/','noun','교육','The process of teaching and learning in a society.','The government will invest more in {education} this year.','정부가 올해 교육에 더 많이 투자할 거예요.','education','A2','news',2,'school books children classroom'),
('w_news_A2_29','security','/sɪˈkjʊərɪti/','noun','보안, 안보','The state of being free from danger or threat.','The summit required tight {security} measures.','정상 회담에는 엄격한 보안 조치가 필요했어요.','security','A2','news',2,'guard gate camera safety'),
('w_news_A2_30','injury','/ˈɪndʒəri/','noun','부상','Physical harm or damage to a person''s body.','The report confirmed twelve {injuries} in the accident.','보도는 사고에서 12명의 부상을 확인했어요.','injuries','A2','news',2,'ambulance hospital medical emergency'),
('w_news_A2_31','crisis','/ˈkraɪsɪs/','noun','위기','A time of intense difficulty or danger.','The government is responding to the economic {crisis}.','정부가 경제 위기에 대응하고 있어요.','crisis','A2','news',1,'alarm emergency red alert warning'),
('w_news_A2_32','army','/ˈɑːrmi/','noun','군대','The land-based armed forces of a country.','The {army} was deployed to control the situation.','군대가 상황을 통제하기 위해 배치됐어요.','army','A2','news',2,'military soldiers uniform patrol'),
('w_news_A2_33','protest','/prəˈtest/','verb','항의하다','To express strong objection to something publicly.','Students {protested} outside the parliament building.','학생들이 의회 건물 밖에서 항의했어요.','protested','A2','news',2,'rally sign banner street'),
('w_news_A2_34','prime','/praɪm/','adjective','주요한, 최고의','Of first importance; most excellent.','The {prime} minister addressed the nation on television.','총리가 텔레비전으로 국민에게 연설했어요.','prime','A2','news',1,'parliament speech podium flag'),
('w_news_A2_35','budget','/ˈbʌdʒɪt/','noun','예산','An estimate of income and expenditure for a set period.','The government presented its annual {budget} today.','정부가 오늘 연간 예산을 발표했어요.','budget','A2','news',1,'finance money chart government');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_news_B1_01','policy','/ˈpɒlɪsi/','noun','정책','A course of action adopted by a government or organization.','The new energy {policy} will reduce carbon emissions.','새 에너지 정책이 탄소 배출을 줄일 거예요.','policy','B1','news',1,'document government plan strategy'),
('w_news_B1_02','reform','/rɪˈfɔːrm/','noun','개혁','A change made to improve a system or institution.','The party is pushing for major economic {reforms}.','그 정당은 주요 경제 개혁을 추진하고 있어요.','reforms','B1','news',1,'parliament chart change progress'),
('w_news_B1_03','parliament','/ˈpɑːrləmənt/','noun','의회','The group of elected representatives who make the laws.','The bill passed through {parliament} with a large majority.','그 법안은 큰 다수결로 의회를 통과했어요.','parliament','B1','news',1,'legislative building democracy vote'),
('w_news_B1_04','controversy','/ˈkɒntrəvɜːrsi/','noun','논란','Prolonged public disagreement or heated debate.','The decision sparked {controversy} across the country.','그 결정은 전국적으로 논란을 일으켰어요.','controversy','B1','news',2,'debate protest media opinion'),
('w_news_B1_05','scandal','/ˈskændəl/','noun','스캔들, 추문','An action or event causing public outrage or shock.','The financial {scandal} forced the minister to resign.','금융 스캔들로 장관이 사임해야 했어요.','scandal','B1','news',2,'headlines media expose tabloid'),
('w_news_B1_06','minister','/ˈmɪnɪstər/','noun','장관','A member of the cabinet in charge of a government department.','The defense {minister} briefed the parliament on the threat.','국방 장관이 의회에 위협에 대해 브리핑했어요.','minister','B1','news',1,'suit official parliament policy'),
('w_news_B1_07','legislation','/ˌledʒɪˈsleɪʃən/','noun','입법, 법률','Laws that have been enacted by a legislature.','New {legislation} on data privacy was introduced this week.','이번 주 데이터 프라이버시에 관한 새 입법이 도입됐어요.','legislation','B1','news',1,'law book parliament document'),
('w_news_B1_08','opposition','/ˌɒpəˈzɪʃən/','noun','야당, 반대 세력','The political parties that are not in government.','The {opposition} called for an independent inquiry.','야당이 독립 조사를 요구했어요.','opposition','B1','news',2,'parliament debate politics dissent'),
('w_news_B1_09','coalition','/ˌkəʊəˈlɪʃən/','noun','연립 정부','A temporary union of political parties to form a government.','The two parties formed a {coalition} government.','두 정당이 연립 정부를 구성했어요.','coalition','B1','news',2,'handshake agreement politics alliance'),
('w_news_B1_10','bilateral','/ˌbaɪˈlætərəl/','adjective','양자 간의','Involving two parties, especially two countries.','The presidents met for {bilateral} trade talks.','대통령들이 양자 무역 회담을 위해 만났어요.','bilateral','B1','news',2,'flags handshake diplomacy summit'),
('w_news_B1_11','inquiry','/ɪnˈkwaɪəri/','noun','조사, 심의','An official investigation into something.','A public {inquiry} was opened into the accident.','사고에 대한 공개 조사가 시작됐어요.','inquiry','B1','news',2,'investigation report judge committee'),
('w_news_B1_12','campaign','/kæmˈpeɪn/','noun','선거 운동, 캠페인','A series of planned activities to achieve a particular goal.','She launched a {campaign} to raise awareness of poverty.','그녀는 빈곤 인식 제고를 위한 캠페인을 시작했어요.','campaign','B1','news',2,'poster rally vote awareness'),
('w_news_B1_13','resign','/rɪˈzaɪn/','verb','사임하다','To officially leave a job or position.','The minister was forced to {resign} over the scandal.','장관은 스캔들로 인해 사임해야 했어요.','resign','B1','news',2,'press conference exit politics'),
('w_news_B1_14','corruption','/kəˈrʌpʃən/','noun','부패','Dishonest or illegal behavior, especially by those in power.','The investigation exposed widespread {corruption} in the ministry.','조사는 부처 내 광범위한 부패를 드러냈어요.','corruption','B1','news',2,'money briefcase bribe illegal'),
('w_news_B1_15','inflation','/ɪnˈfleɪʃən/','noun','인플레이션','A general increase in prices over time.','High {inflation} is making everyday goods more expensive.','높은 인플레이션이 일상 용품을 더 비싸게 만들고 있어요.','inflation','B1','news',2,'price chart rising cost money'),
('w_news_B1_16','treaty','/ˈtriːti/','noun','조약','A formal agreement between countries.','The two nations signed a historic peace {treaty}.','두 나라가 역사적인 평화 조약에 서명했어요.','treaty','B1','news',2,'document signing ceremony flag'),
('w_news_B1_17','ceasefire','/ˈsiːsfaɪər/','noun','휴전','A temporary stop of fighting, agreed between warring sides.','Both sides agreed to a {ceasefire} starting at midnight.','양측이 자정부터 시작하는 휴전에 합의했어요.','ceasefire','B1','news',2,'soldiers white flag peace calm'),
('w_news_B1_18','summit','/ˈsʌmɪt/','noun','정상 회담','A meeting between the leaders of two or more countries.','The G7 {summit} will address climate change this year.','G7 정상 회담이 올해 기후 변화를 다룰 거예요.','summit','B1','news',2,'leaders flags conference table'),
('w_news_B1_19','sanction','/ˈsæŋkʃən/','noun','제재','A penalty or restriction imposed against a country or entity.','New economic {sanctions} were imposed on the regime.','그 정권에 새로운 경제 제재가 부과됐어요.','sanctions','B1','news',2,'trade restriction penalty embargo'),
('w_news_B1_20','humanitarian','/hjuːˌmænɪˈteəriən/','adjective','인도주의적','Concerned with or seeking to promote human welfare.','The UN called for {humanitarian} aid to be allowed in.','유엔은 인도주의적 지원이 허용되어야 한다고 촉구했어요.','humanitarian','B1','news',2,'aid relief UN charity'),
('w_news_B1_21','infrastructure','/ˈɪnfrəstrʌktʃər/','noun','사회 기반 시설','The basic physical systems of a country or region.','The government plans to invest in {infrastructure} projects.','정부가 사회 기반 시설 프로젝트에 투자할 계획이에요.','infrastructure','B1','news',2,'bridge road construction building'),
('w_news_B1_22','negotiation','/nɪˌɡəʊʃiˈeɪʃən/','noun','협상','Discussion aimed at reaching an agreement.','Peace {negotiations} are expected to resume next week.','평화 협상이 다음 주에 재개될 것으로 예상돼요.','negotiations','B1','news',2,'table diplomacy handshake talk'),
('w_news_B1_23','demonstrate','/ˈdemənstreɪt/','verb','시위하다','To publicly protest or show support for a cause.','Thousands {demonstrated} against the new tax policy.','수천 명이 새 세금 정책에 반대하여 시위했어요.','demonstrated','B1','news',2,'march banner protest crowd'),
('w_news_B1_24','unemployment','/ˌʌnɪmˈplɔɪmənt/','noun','실업','The condition of being without a paid job.','The latest figures show {unemployment} has risen to 8%.','최신 수치에 따르면 실업률이 8%로 올랐어요.','unemployment','B1','news',2,'job center queue line economy'),
('w_news_B1_25','verdict','/ˈvɜːrdɪkt/','noun','평결, 판결','A decision reached by a jury or judge in a legal trial.','The court delivered its {verdict} this morning.','법원이 오늘 아침 판결을 내렸어요.','verdict','B1','news',2,'courtroom gavel judge jury'),
('w_news_B1_26','press conference','/pres ˈkɒnfərəns/','noun','기자 회견','A meeting at which an official speaks to journalists.','The prime minister held a {press conference} after the vote.','총리가 투표 후 기자 회견을 열었어요.','press conference','B1','news',2,'microphone journalist podium camera'),
('w_news_B1_27','majority','/məˈdʒɒrɪti/','noun','과반수, 다수','The greater number or part of something.','The bill passed with a narrow {majority} in parliament.','그 법안은 의회에서 간신히 과반수로 통과됐어요.','majority','B1','news',2,'vote election graph result'),
('w_news_B1_28','accusation','/ˌækjʊˈzeɪʃən/','noun','고발, 혐의','A claim that someone has done something wrong or illegal.','He denied all {accusations} of wrongdoing.','그는 모든 비리 혐의를 부인했어요.','accusations','B1','news',2,'court legal press denial'),
('w_news_B1_29','turnout','/ˈtɜːrnaʊt/','noun','투표율, 참여율','The number of people attending or participating in an event.','Voter {turnout} reached a record high this election.','이번 선거에서 투표율이 역대 최고를 기록했어요.','turnout','B1','news',2,'ballot box queue voters'),
('w_news_B1_30','impose','/ɪmˈpəʊz/','verb','부과하다','To establish a rule, tax, or restriction by authority.','The government will {impose} stricter penalties for tax evasion.','정부가 탈세에 더 엄격한 처벌을 부과할 거예요.','impose','B1','news',2,'authority law gavel penalty'),
('w_news_B1_31','ally','/ˈælaɪ/','noun','동맹국','A country formally cooperating with another for a common goal.','The US called on its {allies} to support the resolution.','미국이 결의안을 지지해 달라고 동맹국들에 촉구했어요.','allies','B1','news',2,'flags alliance partnership military'),
('w_news_B1_32','evidence','/ˈevɪdəns/','noun','증거','Facts or information showing whether something is true.','The court examined new {evidence} in the case.','법원이 사건에서 새로운 증거를 검토했어요.','evidence','B1','news',2,'courtroom document investigation files'),
('w_news_B1_33','democracy','/dɪˈmɒkrəsi/','noun','민주주의','A system of government in which people vote for their leaders.','Protecting {democracy} requires active citizen participation.','민주주의를 보호하려면 시민의 적극적인 참여가 필요해요.','democracy','B1','news',1,'ballot box flag parliament constitution'),
('w_news_B1_34','refugee','/ˌrefjʊˈdʒiː/','noun','난민','A person forced to flee their country due to conflict or disaster.','The crisis has created over a million {refugees}.','위기로 인해 백만 명 이상의 난민이 생겼어요.','refugees','B1','news',2,'camp tent border UNHCR'),
('w_news_B1_35','deadline','/ˈdedlaɪn/','noun','시한, 기한','A point in time by which something must be done.','The government missed the {deadline} for submitting the budget.','정부가 예산 제출 시한을 놓쳤어요.','deadline','B1','news',2,'clock calendar urgent time');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_news_B2_01','geopolitics','/ˌdʒiːəʊˈpɒlɪtɪks/','noun','지정학','The study of how geography and power shape world affairs.','{Geopolitics} in East Asia has shifted significantly this decade.','이번 십 년간 동아시아 지정학이 크게 변했어요.','Geopolitics','B2','news',1,'map region power rivalry strategy'),
('w_news_B2_02','sanctions','/ˈsæŋkʃənz/','noun','제재 조치','Economic or political penalties imposed by one country on another.','The UN imposed sweeping {sanctions} on the regime.','유엔이 그 정권에 광범위한 제재를 부과했어요.','sanctions','B2','news',1,'trade restriction penalty embargo'),
('w_news_B2_03','diplomatic','/ˌdɪpləˈmætɪk/','adjective','외교적인','Relating to the management of international relations.','Both governments agreed to resume {diplomatic} ties.','두 정부가 외교 관계를 재개하기로 합의했어요.','diplomatic','B2','news',1,'embassy flag handshake diplomat'),
('w_news_B2_04','incumbent','/ɪnˈkʌmbənt/','adjective','현직의','Currently holding a particular office or position.','The {incumbent} president won re-election by a wide margin.','현직 대통령이 큰 차이로 재선에 성공했어요.','incumbent','B2','news',2,'election result president podium'),
('w_news_B2_05','sovereignty','/ˈsɒvrɪnti/','noun','주권','The full right and power of a country to govern itself.','The treaty was seen as a threat to national {sovereignty}.','그 조약은 국가 주권에 대한 위협으로 여겨졌어요.','sovereignty','B2','news',2,'flag border constitution nation'),
('w_news_B2_06','multilateral','/ˌmʌltiˈlætərəl/','adjective','다자간의','Involving three or more parties, especially countries.','A {multilateral} approach is needed to solve the climate crisis.','기후 위기를 해결하려면 다자간 접근이 필요해요.','multilateral','B2','news',2,'UN globe summit delegates'),
('w_news_B2_07','referendum','/ˌrefəˈrendəm/','noun','국민 투표','A direct vote by the electorate on a single political question.','Citizens voted in a {referendum} on independence.','시민들이 독립에 관한 국민 투표에 참여했어요.','referendum','B2','news',2,'ballot box vote democracy flag'),
('w_news_B2_08','austerity','/ɒˈsterɪti/','noun','긴축 재정','Difficult economic conditions created by government spending cuts.','The {austerity} measures triggered widespread protests.','긴축 조치가 광범위한 시위를 촉발했어요.','austerity','B2','news',2,'budget cuts economy protest'),
('w_news_B2_09','coup','/kuː/','noun','쿠데타','A sudden, violent seizure of power from a government.','The military staged a {coup} in the early hours of the morning.','군이 이른 아침에 쿠데타를 일으켰어요.','coup','B2','news',2,'military tanks government overthrow'),
('w_news_B2_10','insurgency','/ɪnˈsɜːrdʒənsi/','noun','반란','An active revolt or uprising against an authority or government.','The army is battling a long-running {insurgency} in the north.','군은 북부에서 오래 지속된 반란과 싸우고 있어요.','insurgency','B2','news',3,'soldiers jungle conflict militia'),
('w_news_B2_11','accountability','/əˌkaʊntəˈbɪlɪti/','noun','책임 (제도적)','The fact of being held responsible for one''s actions or decisions.','There is growing demand for political {accountability}.','정치적 책임에 대한 요구가 높아지고 있어요.','accountability','B2','news',2,'audit investigation report committee'),
('w_news_B2_12','populism','/ˈpɒpjʊlɪzəm/','noun','포퓰리즘','A political approach that appeals to ordinary people''s concerns against elites.','The rise of {populism} has reshaped politics in many countries.','포퓰리즘의 부상이 많은 나라의 정치를 바꿔놓았어요.','populism','B2','news',2,'rally crowd speech election'),
('w_news_B2_13','authoritarian','/ɔːˌθɒrɪˈteəriən/','adjective','권위주의적인','Favoring or enforcing strict obedience to authority.','Critics say the new laws are {authoritarian} in nature.','비평가들은 새 법이 권위주의적 성격이라고 말해요.','authoritarian','B2','news',2,'control surveillance power state'),
('w_news_B2_14','propaganda','/ˌprɒpəˈɡændə/','noun','선전','Information spread to promote a particular political agenda.','The report accused the government of spreading {propaganda}.','그 보도는 정부가 선전을 퍼뜨리고 있다고 비난했어요.','propaganda','B2','news',2,'poster media broadcast bias'),
('w_news_B2_15','disinformation','/dɪsˌɪnfəˈmeɪʃən/','noun','허위 정보','False information spread deliberately to deceive people.','Social media has become a major source of {disinformation}.','소셜 미디어가 허위 정보의 주요 출처가 됐어요.','disinformation','B2','news',2,'fake news screen social media'),
('w_news_B2_16','embargo','/ɪmˈbɑːrɡəʊ/','noun','금수 조치','An official ban on trade with a particular country.','An arms {embargo} was placed on the country by the UN.','유엔이 그 나라에 무기 금수 조치를 부과했어요.','embargo','B2','news',2,'trade ban cargo ship restriction'),
('w_news_B2_17','mediation','/ˌmiːdiˈeɪʃən/','noun','조정, 중재','Intervention in a dispute to bring about a settlement.','International {mediation} helped end the conflict.','국제 조정이 분쟁 종식에 도움이 됐어요.','mediation','B2','news',2,'diplomacy negotiation peace table'),
('w_news_B2_18','polarization','/ˌpəʊlərɪˈzeɪʃən/','noun','양극화','The division of something into two sharply contrasting groups.','Political {polarization} has deepened in recent years.','최근 몇 년간 정치적 양극화가 심화됐어요.','polarization','B2','news',2,'divide society left right politics'),
('w_news_B2_19','narrative','/ˈnærətɪv/','noun','서사, 담론','A story or explanation that shapes how people understand events.','Both sides tried to control the public {narrative}.','양측이 공적 담론을 통제하려고 했어요.','narrative','B2','news',2,'media story framing perspective'),
('w_news_B2_20','transparency','/trænsˈpærənsi/','noun','투명성','The quality of being open and not concealing information.','Citizens are demanding greater {transparency} in government.','시민들이 정부의 더 큰 투명성을 요구하고 있어요.','transparency','B2','news',2,'glass open document accountability'),
('w_news_B2_21','allegation','/ˌælɪˈɡeɪʃən/','noun','혐의, 주장','A claim that someone has done something wrong or illegal.','The minister denied all {allegations} of corruption.','장관은 모든 부패 혐의를 부인했어요.','allegations','B2','news',2,'court legal press accusation'),
('w_news_B2_22','ratification','/ˌrætɪfɪˈkeɪʃən/','noun','비준','The official confirmation or approval of a treaty or agreement.','The treaty awaits {ratification} by all member states.','조약은 모든 회원국의 비준을 기다리고 있어요.','ratification','B2','news',2,'signing document ceremony flag'),
('w_news_B2_23','veto','/ˈviːtəʊ/','noun','거부권','The right to reject a decision or proposal unilaterally.','Russia used its {veto} power to block the UN resolution.','러시아가 거부권을 사용해 유엔 결의안을 막았어요.','veto','B2','news',2,'UN Security Council vote power'),
('w_news_B2_24','credibility','/ˌkredɪˈbɪlɪti/','noun','신뢰성','The quality of being trusted and believed by others.','The scandal damaged the government''s {credibility}.','스캔들이 정부의 신뢰성을 훼손했어요.','credibility','B2','news',2,'trust press opinion poll'),
('w_news_B2_25','mandate','/ˈmændeɪt/','noun','권한 위임, 임무','An official order or authorization given to a party by voters.','The new leader claimed a strong {mandate} from voters.','새 지도자는 유권자들로부터 강력한 권한을 받았다고 주장했어요.','mandate','B2','news',2,'election result vote authority'),
('w_news_B2_26','dissent','/dɪˈsent/','noun','반대 의견','The holding or expression of opinions contrary to authority.','Political {dissent} is suppressed in authoritarian states.','권위주의 국가에서 정치적 반대 의견은 탄압돼요.','dissent','B2','news',2,'protest speech freedom opposition'),
('w_news_B2_27','broker','/ˈbrəʊkər/','verb','중재하다','To arrange or negotiate an agreement between parties.','The US agreed to {broker} a peace deal between the two nations.','미국이 두 나라 간의 평화 협상을 중재하기로 했어요.','broker','B2','news',2,'diplomacy negotiation mediation handshake'),
('w_news_B2_28','consensus','/kənˈsensəs/','noun','합의, 컨센서스','General agreement among a group of people or states.','There is growing {consensus} on the need for climate action.','기후 행동의 필요성에 대한 공감대가 커지고 있어요.','consensus','B2','news',2,'agreement UN summit delegates'),
('w_news_B2_29','intervention','/ˌɪntəˈvenʃən/','noun','개입','The act of becoming involved in a situation to alter its course.','Military {intervention} was debated at the UN Security Council.','유엔 안보리에서 군사적 개입이 논의됐어요.','intervention','B2','news',2,'UN military peacekeeping security'),
('w_news_B2_30','impasse','/ˈɪmpæs/','noun','교착 상태','A situation in which no progress is possible; deadlock.','Negotiations reached an {impasse} after three days of talks.','3일간의 회담 끝에 협상이 교착 상태에 빠졌어요.','impasse','B2','news',2,'deadlock negotiation stalled diplomacy'),
('w_news_B2_31','annexation','/ˌænɪkˈseɪʃən/','noun','합병, 병합','The action of taking over a territory by a country.','The international community condemned the {annexation} of the territory.','국제 사회가 그 영토 합병을 규탄했어요.','annexation','B2','news',3,'border map territory flag'),
('w_news_B2_32','faction','/ˈfækʃən/','noun','파벌','A small, dissenting group within a larger political party.','A rebel {faction} within the party opposed the leader''s plans.','당 내 반대 파벌이 지도자의 계획에 반대했어요.','faction','B2','news',3,'politics party divide group'),
('w_news_B2_33','cease','/siːs/','verb','중단하다','To come to an end or bring something to an end.','Fighting must {cease} immediately, the UN demanded.','유엔은 전투가 즉각 중단되어야 한다고 요구했어요.','cease','B2','news',2,'stop end peacekeeping soldiers'),
('w_news_B2_34','denounce','/dɪˈnaʊns/','verb','규탄하다','To publicly declare something to be wrong or evil.','The opposition {denounced} the new law as unconstitutional.','야당은 새 법을 위헌이라고 규탄했어요.','denounced','B2','news',2,'protest speech condemnation press'),
('w_news_B2_35','coalition','/ˌkəʊəˈlɪʃən/','noun','연합, 연립','A temporary alliance of distinct political parties or groups.','A {coalition} of opposition parties challenged the government.','야당 연합이 정부에 도전했어요.','coalition','B2','news',2,'alliance partnership politics flag');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_news_C1_01','hegemony','/hɪˈdʒeməni/','noun','패권','Leadership or dominance, especially of one country over others.','American {hegemony} in the post-Cold War era is being challenged.','냉전 이후 미국 패권이 도전받고 있어요.','hegemony','C1','news',1,'power globe superpower dominance'),
('w_news_C1_02','realpolitik','/reɪˈɑːlpɒlɪtɪk/','noun','현실 정치','Politics based on practical considerations rather than moral norms.','The decision to ally with the regime reflected pure {realpolitik}.','그 정권과의 동맹 결정은 순수한 현실 정치를 반영했어요.','realpolitik','C1','news',2,'strategy power diplomacy chess'),
('w_news_C1_03','extraterritorial','/ˌekstrəˌterɪˈtɔːriəl/','adjective','역외적인','Existing or taking effect outside the territory of a state.','The law has {extraterritorial} jurisdiction over its citizens abroad.','그 법은 해외 자국 시민에 대한 역외 관할권을 가지고 있어요.','extraterritorial','C1','news',3,'law border international jurisdiction'),
('w_news_C1_04','jurisprudence','/ˌdʒʊərɪsˈpruːdəns/','noun','법리학','The theory and practice of law; a body of legal decisions.','The ruling set a new precedent in international {jurisprudence}.','그 판결은 국제 법리학에 새로운 선례를 세웠어요.','jurisprudence','C1','news',2,'law books court legal theory'),
('w_news_C1_05','multilateralism','/ˌmʌltiˈlætərəlɪzəm/','noun','다자주의','The practice of diplomacy involving multiple countries.','The summit reaffirmed a commitment to {multilateralism}.','정상 회담은 다자주의에 대한 의지를 재확인했어요.','multilateralism','C1','news',2,'UN globe summit cooperation'),
('w_news_C1_06','precedent','/ˈpresɪdənt/','noun','선례','An earlier event or ruling used as an example for later situations.','The court''s decision set a dangerous {precedent} for press freedom.','법원의 결정은 언론 자유에 위험한 선례를 남겼어요.','precedent','C1','news',2,'court legal history ruling'),
('w_news_C1_07','jurisdiction','/ˌdʒʊərɪsˈdɪkʃən/','noun','관할권','The official power to make legal decisions in a given area.','The crime falls outside this court''s {jurisdiction}.','그 범죄는 이 법원의 관할권 밖이에요.','jurisdiction','C1','news',2,'court law territory authority'),
('w_news_C1_08','ratification','/ˌrætɪfɪˈkeɪʃən/','noun','비준','Formal confirmation or approval of an international agreement.','The climate accord requires {ratification} by 55 countries.','그 기후 협약은 55개국의 비준이 필요해요.','ratification','C1','news',2,'treaty signing ceremony document'),
('w_news_C1_09','embargo','/ɪmˈbɑːrɡəʊ/','noun','수출입 금지령','An official ban on trade or other commercial activity with a country.','The oil {embargo} crippled the nation''s economy.','석유 금수 조치가 국가 경제를 무력화했어요.','embargo','C1','news',2,'trade ban ship cargo oil'),
('w_news_C1_10','deterrence','/dɪˈterəns/','noun','억제력','The action of discouraging an action through fear of consequences.','Nuclear {deterrence} has prevented major wars for decades.','핵 억제력은 수십 년 동안 대규모 전쟁을 막아왔어요.','deterrence','C1','news',2,'nuclear missile defense shield'),
('w_news_C1_11','geopolitical','/ˌdʒiːəʊpəˈlɪtɪkəl/','adjective','지정학적','Relating to politics affected by geographical factors.','The pipeline holds enormous {geopolitical} significance.','그 파이프라인은 엄청난 지정학적 의미를 가지고 있어요.','geopolitical','C1','news',2,'map energy pipeline power'),
('w_news_C1_12','bellicose','/ˈbelɪkəʊs/','adjective','호전적인','Demonstrating aggression and willingness to fight.','The government''s {bellicose} rhetoric alarmed its neighbors.','정부의 호전적인 수사가 이웃 나라들을 불안하게 했어요.','bellicose','C1','news',3,'military threat tension hostility'),
('w_news_C1_13','oligarchy','/ˈɒlɪɡɑːki/','noun','과두 정치','A system in which power is held by a small number of people.','Critics accuse the ruling elite of establishing an {oligarchy}.','비평가들은 집권 엘리트가 과두 정치를 수립했다고 비난해요.','oligarchy','C1','news',2,'power elite wealth control'),
('w_news_C1_14','reprisal','/rɪˈpraɪzəl/','noun','보복 행위','An act of retaliation against an enemy or opponent.','The strike was carried out in {reprisal} for the earlier attack.','그 공격은 이전 공격에 대한 보복으로 감행됐어요.','reprisal','C1','news',3,'retaliation military response strike'),
('w_news_C1_15','subversion','/səbˈvɜːrʒən/','noun','전복, 체제 해체','The undermining of the power and authority of an established system.','He was charged with {subversion} of the state.','그는 국가 전복 혐의로 기소됐어요.','subversion','C1','news',3,'underground threat security law'),
('w_news_C1_16','proxy','/ˈprɒksi/','noun','대리인, 위임','A person or group acting on behalf of another, especially in conflict.','The two superpowers fought a {proxy} war through local factions.','두 강대국이 지역 파벌을 통해 대리전을 치렀어요.','proxy','C1','news',2,'war factions superpower conflict'),
('w_news_C1_17','ostracize','/ˈɒstrəsaɪz/','verb','추방하다, 따돌리다','To exclude someone from a society or community by consensus.','The regime was {ostracized} by the international community.','그 정권은 국제 사회에서 추방당했어요.','ostracized','C1','news',2,'isolation exclusion sanctions community'),
('w_news_C1_18','proliferation','/prəˌlɪfəˈreɪʃən/','noun','확산','A rapid increase in the number of something, especially weapons.','Nuclear {proliferation} remains one of the world''s gravest threats.','핵 확산은 여전히 세계에서 가장 심각한 위협 중 하나예요.','proliferation','C1','news',2,'nuclear weapons spread global'),
('w_news_C1_19','junta','/ˈhʊntə/','noun','군사 정권','A military group that has seized power following a coup.','The military {junta} suspended the constitution.','군사 정권이 헌법을 정지시켰어요.','junta','C1','news',2,'military coup power governance'),
('w_news_C1_20','disenfranchise','/ˌdɪsɪnˈfræntʃaɪz/','verb','선거권을 박탈하다','To deprive someone of the right to vote or participate.','Critics say the new law will {disenfranchise} millions of voters.','비평가들은 새 법이 수백만 명의 유권자의 선거권을 박탈할 것이라고 말해요.','disenfranchise','C1','news',2,'vote election rights democracy'),
('w_news_C1_21','tribunal','/traɪˈbjuːnəl/','noun','재판소, 심판소','A court or committee appointed to deal with a specific issue.','The war crimes {tribunal} handed down its verdict.','전쟁 범죄 재판소가 판결을 내렸어요.','tribunal','C1','news',2,'court justice international legal'),
('w_news_C1_22','culpability','/ˌkʌlpəˈbɪlɪti/','noun','유책성','Responsibility for a fault or wrong; blameworthiness.','The inquiry examined the {culpability} of senior officials.','조사는 고위 관리들의 유책성을 검토했어요.','culpability','C1','news',3,'responsibility blame inquiry legal'),
('w_news_C1_23','capitulation','/kəˌpɪtʃʊˈleɪʃən/','noun','항복, 굴복','The act of surrendering or giving in to demands or pressure.','Critics called the government''s response a {capitulation} to pressure.','비평가들은 정부의 반응을 압력에 대한 굴복이라고 불렀어요.','capitulation','C1','news',3,'surrender defeat compromise pressure'),
('w_news_C1_24','reparation','/ˌrepəˈreɪʃən/','noun','배상','Compensation for war damage paid by a defeated country.','The debate over war {reparations} resurfaced this year.','올해 전쟁 배상금 논쟁이 다시 불거졌어요.','reparations','C1','news',2,'history war justice compensation'),
('w_news_C1_25','acquittal','/əˈkwɪtəl/','noun','무죄 선고','A formal judicial finding of not guilty.','The {acquittal} shocked the victims'' families.','무죄 선고는 피해자 가족들에게 충격을 줬어요.','acquittal','C1','news',2,'court verdict judge jury not guilty'),
('w_news_C1_26','complicity','/kəmˈplɪsɪti/','noun','공모, 연루','Partnership in a wrongdoing or crime; being involved in guilt.','The report alleged government {complicity} in the cover-up.','보고서는 정부의 은폐 공모를 주장했어요.','complicity','C1','news',2,'corruption crime involvement investigation'),
('w_news_C1_27','rapprochement','/ˌræprəʊʃˈmɒŋ/','noun','화해, 관계 개선','The establishment of harmonious relations between countries.','The two nations are moving toward diplomatic {rapprochement}.','두 나라가 외교적 화해를 향해 나아가고 있어요.','rapprochement','C1','news',2,'diplomacy flag handshake peace'),
('w_news_C1_28','coercive','/kəʊˈɜːrsɪv/','adjective','강압적인','Using force or threats to make someone act in a certain way.','The opposition condemned the government''s {coercive} tactics.','야당은 정부의 강압적인 전술을 규탄했어요.','coercive','C1','news',2,'force authority control pressure'),
('w_news_C1_29','demagogue','/ˈdeməɡɒɡ/','noun','선동가','A political leader who gains support through emotional appeals.','The opposition accused the president of being a {demagogue}.','야당은 대통령이 선동가라고 비난했어요.','demagogue','C1','news',3,'speech crowd politics emotion'),
('w_news_C1_30','intransigence','/ɪnˈtrænsɪdʒəns/','noun','완고함, 비타협성','Refusal to change one''s views or to reach a compromise.','The talks collapsed due to both sides'' {intransigence}.','양측의 비타협적인 태도로 회담이 결렬됐어요.','intransigence','C1','news',3,'deadlock negotiation stalemate rigid'),
('w_news_C1_31','concession','/kənˈseʃən/','noun','양보','A thing granted in response to demands during negotiation.','The government offered {concessions} to end the strike.','정부가 파업을 끝내기 위해 양보를 제시했어요.','concessions','C1','news',2,'negotiation compromise offer deal'),
('w_news_C1_32','asymmetric','/ˌeɪsɪˈmetrɪk/','adjective','비대칭적인','Having unequal distribution of power or strategy between parties.','The conflict has become an {asymmetric} guerrilla war.','분쟁이 비대칭적인 게릴라 전쟁이 됐어요.','asymmetric','C1','news',3,'war strategy power difference'),
('w_news_C1_33','incendiary','/ɪnˈsendiəri/','adjective','선동적인, 도발적인','Tending to stir up conflict or strong reactions.','The senator''s {incendiary} remarks caused national outrage.','상원 의원의 선동적인 발언이 국가적 분노를 일으켰어요.','incendiary','C1','news',3,'speech protest fire rhetoric'),
('w_news_C1_34','sequestration','/ˌsiːkwɪˈstreɪʃən/','noun','자산 동결, 강제 삭감','The seizure or holding of assets, or automatic budget cuts by authority.','Budget {sequestration} resulted in automatic spending cuts.','예산 강제 삭감으로 자동적인 지출 삭감이 발생했어요.','sequestration','C1','news',3,'budget finance government cut'),
('w_news_C1_35','peremptory','/pəˈremptəri/','adjective','강압적이고 단호한','Insisting on immediate compliance without allowing debate.','The court issued a {peremptory} demand for documents.','법원이 서류에 대한 강압적인 요구를 내렸어요.','peremptory','C1','news',3,'court order authority legal command');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_news_C2_01','epistemic','/ˌepɪˈstiːmɪk/','adjective','인식론적인','Relating to knowledge or the degree of its validation.','The article examines {epistemic} challenges in journalism.','그 기사는 저널리즘의 인식론적 도전을 다뤄요.','epistemic','C2','news',2,'knowledge theory truth philosophy'),
('w_news_C2_02','Westphalian','/westˈfeɪliən/','adjective','베스트팔렌적인','Relating to the Westphalian system of sovereign nation-states.','The humanitarian intervention challenged {Westphalian} norms.','인도주의적 개입이 베스트팔렌적 규범에 도전했어요.','Westphalian','C2','news',3,'sovereignty international law norms'),
('w_news_C2_03','securitization','/sɪˌkjʊərɪtɪˈzeɪʃən/','noun','안보화','The process of framing an issue as a security threat to justify emergency measures.','The {securitization} of migration has dominated political debates.','이주의 안보화가 정치 논쟁을 지배하고 있어요.','securitization','C2','news',3,'security border threat policy'),
('w_news_C2_04','normative','/ˈnɔːrmətɪv/','adjective','규범적인','Relating to or deriving from a standard or norm of expected behavior.','The UN Charter established a {normative} framework for world order.','유엔 헌장은 세계 질서의 규범적 틀을 확립했어요.','normative','C2','news',2,'law standard framework international'),
('w_news_C2_05','constructivist','/kənˈstrʌktɪvɪst/','adjective','구성주의적인','Relating to the theory that social reality is constructed through ideas and norms.','A {constructivist} reading of the crisis focuses on shared identities.','위기에 대한 구성주의적 해석은 공유된 정체성에 집중해요.','constructivist','C2','news',3,'theory identity norms society'),
('w_news_C2_06','ontological','/ˌɒntəˈlɒdʒɪkəl/','adjective','존재론적인','Relating to the branch of philosophy concerned with the nature of being.','The annexation threatened the country''s {ontological} security.','합병은 그 나라의 존재론적 안보감을 위협했어요.','ontological','C2','news',3,'identity state theory security'),
('w_news_C2_07','postcolonial','/ˌpəʊstˈkɒləniəl/','adjective','탈식민적인','Relating to the period after colonial rule ended and its lingering effects.','The conflict has deep {postcolonial} roots.','그 분쟁은 깊은 탈식민적 뿌리가 있어요.','postcolonial','C2','news',2,'history empire colony Africa Asia'),
('w_news_C2_08','subaltern','/ˈsʌbəltɜːrn/','adjective','하위 주체적인','Relating to those whose voices are marginalized or suppressed in society.','The report amplifies {subaltern} perspectives often ignored by media.','그 보고서는 미디어에서 종종 무시되는 하위 주체적 관점을 증폭시켜요.','subaltern','C2','news',3,'minority voice marginalized society'),
('w_news_C2_09','neocolonialism','/ˌniːəʊˈkɒləniəlɪzəm/','noun','신식민주의','The use of economic or political pressure to control developing countries.','Critics accuse wealthy nations of practicing {neocolonialism}.','비평가들은 부유한 나라들이 신식민주의를 실천한다고 비난해요.','neocolonialism','C2','news',3,'power Africa dependency aid'),
('w_news_C2_10','intergovernmentalism','/ˌɪntəˌɡʌvənˈmentəlɪzəm/','noun','정부 간주의','A theory of international cooperation in which states retain sovereignty.','{Intergovernmentalism} limits the EU''s ability to act as a single entity.','정부 간주의는 EU가 단일 주체로 행동하는 능력을 제한해요.','Intergovernmentalism','C2','news',3,'EU Europe cooperation sovereignty'),
('w_news_C2_11','liminality','/ˌlɪmɪˈnælɪti/','noun','경계성, 과도기 상태','The quality of being in an ambiguous transitional state between two phases.','The country exists in political {liminality} between democracy and authoritarianism.','그 나라는 민주주의와 권위주의 사이의 정치적 경계성 속에 있어요.','liminality','C2','news',3,'transition threshold ambiguity change'),
('w_news_C2_12','praxis','/ˈpræksɪs/','noun','실천 (이론 대비)','The practice and practical application of a theory or belief.','The movement struggled to convert ideology into {praxis}.','그 운동은 이념을 실천으로 전환하는 데 어려움을 겪었어요.','praxis','C2','news',3,'action theory practice policy'),
('w_news_C2_13','polity','/ˈpɒlɪti/','noun','정치 공동체','A form of government or political organization of a state.','The question is whether the EU constitutes a single {polity}.','문제는 EU가 단일 정치 공동체를 구성하는지 여부예요.','polity','C2','news',3,'governance state EU community'),
('w_news_C2_14','hegemon','/ˈheɡɪmɒn/','noun','패권국','A dominant state exercising preponderant power over others.','The US remains the world''s sole military {hegemon}.','미국은 여전히 세계 유일의 군사적 패권국이에요.','hegemon','C2','news',3,'superpower dominance military power'),
('w_news_C2_15','legitimation','/lɪˌdʒɪtɪˈmeɪʃən/','noun','정당화','The process of making something legitimate or lawful in others'' eyes.','The regime sought international {legitimation} through elections.','그 정권은 선거를 통해 국제적 정당화를 추구했어요.','legitimation','C2','news',2,'election credibility recognition power'),
('w_news_C2_16','heterodox','/ˈhetərədɒks/','adjective','이단적인, 비정통적인','Not conforming with accepted or orthodox standards or beliefs.','His {heterodox} interpretation of the treaty provoked debate.','그의 비정통적인 조약 해석이 논쟁을 불러일으켰어요.','heterodox','C2','news',3,'unusual theory challenge orthodox'),
('w_news_C2_17','dialectical','/ˌdaɪəˈlektɪkəl/','adjective','변증법적인','Relating to inquiry into truth by discussion and logical argument.','The analyst offered a {dialectical} reading of the peace process.','분석가는 평화 프로세스에 대한 변증법적 해석을 제공했어요.','dialectical','C2','news',3,'argument theory logic analysis'),
('w_news_C2_18','reification','/ˌriːɪfɪˈkeɪʃən/','noun','물화, 실체화','The process of treating an abstraction as if it were a concrete thing.','The speech was criticized for its {reification} of national identity.','그 연설은 국가 정체성의 물화로 비판받았어요.','reification','C2','news',3,'abstract concept identity society'),
('w_news_C2_19','exceptionalism','/ɪkˈsepʃənəlɪzəm/','noun','예외주의','The belief that a nation is exceptional and not bound by normal rules.','American {exceptionalism} has long shaped its foreign policy.','미국 예외주의는 오랫동안 미국 외교 정책을 형성해 왔어요.','exceptionalism','C2','news',3,'national identity foreign policy US'),
('w_news_C2_20','transnational','/trænsˈnæʃənəl/','adjective','초국가적인','Extending or operating across national boundaries.','The campaign is a {transnational} effort to combat misinformation.','그 캠페인은 허위 정보와 싸우기 위한 초국가적 노력이에요.','transnational','C2','news',2,'global cooperation border internet'),
('w_news_C2_21','agonistic','/ˌæɡəˈnɪstɪk/','adjective','투쟁적인, 갈등 지향적인','Relating to the view that political conflict is inherently productive.','Mouffe''s {agonistic} model sees disagreement as essential to democracy.','무페의 투쟁적 모델은 의견 불일치를 민주주의의 본질로 봐요.','agonistic','C2','news',3,'democracy conflict theory politics'),
('w_news_C2_22','discursive','/dɪˈskɜːrsɪv/','adjective','담론적인','Relating to discourse; proceeding by argument rather than intuition.','The editorial took a {discursive} approach to the crisis.','그 사설은 위기에 대한 담론적 접근을 취했어요.','discursive','C2','news',3,'language analysis text theory'),
('w_news_C2_23','counterfactual','/ˌkaʊntəˈfæktʃʊəl/','adjective','반사실적인','Relating to what might have happened under different circumstances.','Historians offer a {counterfactual} view of the failed negotiations.','역사가들은 실패한 협상에 대한 반사실적 관점을 제시해요.','counterfactual','C2','news',3,'history analysis alternative scenario'),
('w_news_C2_24','semiotic','/ˌsiːmiˈɒtɪk/','adjective','기호학적인','Relating to the study of signs and symbols and their meanings.','The flag-burning carries powerful {semiotic} significance.','국기 소각은 강력한 기호학적 의미를 지니고 있어요.','semiotic','C2','news',3,'symbol meaning sign analysis'),
('w_news_C2_25','extrapolate','/ɪkˈstræpəleɪt/','verb','외삽하다, 추론하다','To extend data or conclusions into unknown areas by inference.','Analysts {extrapolate} future trends from current data.','분석가들은 현재 데이터에서 미래 추세를 추론해요.','extrapolate','C2','news',2,'data analysis forecast prediction'),
('w_news_C2_26','temporality','/ˌtempəˈrælɪti/','noun','시간성, 임시성','The state of existing within or having some relationship with time.','The analyst explored the {temporality} of the political crisis.','분석가는 정치 위기의 시간성을 탐구했어요.','temporality','C2','news',3,'time theory analysis phase'),
('w_news_C2_27','ideological','/ˌaɪdiəˈlɒdʒɪkəl/','adjective','이데올로기적인','Based on or relating to a system of ideas and ideals forming a worldview.','The conflict has deep {ideological} roots.','그 분쟁은 깊은 이데올로기적 뿌리가 있어요.','ideological','C2','news',2,'ideas belief system politics'),
('w_news_C2_28','genealogy','/ˌdʒiːniˈælədʒi/','noun','계보, 기원 추적','The study of the origin and historical development of something.','Foucault''s {genealogy} of power influenced media criticism.','푸코의 권력 계보학은 미디어 비평에 영향을 미쳤어요.','genealogy','C2','news',3,'history origin theory Foucault'),
('w_news_C2_29','hermeneutic','/ˌhɜːrmɪˈnjuːtɪk/','adjective','해석학적인','Relating to the interpretation of texts, especially political or legal ones.','A {hermeneutic} reading of the resolution reveals ambiguities.','결의문의 해석학적 독해는 모호성을 드러내요.','hermeneutic','C2','news',3,'interpretation text law analysis'),
('w_news_C2_30','hegemonic','/ˌheɡɪˈmɒnɪk/','adjective','패권적인','Relating to the exercise of hegemony; dominant in power or influence.','The US sought to preserve its {hegemonic} position in the Pacific.','미국은 태평양에서 패권적 위치를 유지하려 했어요.','hegemonic','C2','news',3,'superpower dominance power Pacific'),
('w_news_C2_31','intersubjectivity','/ˌɪntəsʌbdʒekˈtɪvɪti/','noun','상호주관성','The sharing of cognitive or subjective states between individuals or groups.','Diplomatic norms emerge from {intersubjectivity} among states.','외교 규범은 국가들 간의 상호주관성에서 나와요.','intersubjectivity','C2','news',3,'theory norms shared understanding'),
('w_news_C2_32','deterritorialization','/diːˌterɪtɔːriəlaɪˈzeɪʃən/','noun','탈영토화','The loosening of the connection between culture and geographic territory.','Globalization has accelerated the {deterritorialization} of political identity.','세계화가 정치적 정체성의 탈영토화를 가속화했어요.','deterritorialization','C2','news',3,'globalization identity border culture'),
('w_news_C2_33','dialectic','/ˌdaɪəˈlektɪk/','noun','변증법','A method of examining opposing ideas to reach the truth.','The editorial used a {dialectic} of freedom versus security.','그 사설은 자유 대 안보의 변증법을 사용했어요.','dialectic','C2','news',3,'logic argument theory analysis'),
('w_news_C2_34','disarticulation','/dɪsɑːˌtɪkjʊˈleɪʃən/','noun','연결 해체','The unraveling of coherent political or social structures.','The crisis led to the {disarticulation} of the ruling coalition.','위기는 집권 연합의 연결 해체로 이어졌어요.','disarticulation','C2','news',3,'collapse breakdown coalition fragmentation'),
('w_news_C2_35','epistemocracy','/ɪˌpiːstɪˈmɒkrəsi/','noun','지식 기반 정치 체제','A form of government where political power rests on epistemic competence.','Advocates argue that {epistemocracy} can improve policy quality.','지지자들은 지식 기반 정치 체제가 정책 품질을 높일 수 있다고 주장해요.','epistemocracy','C2','news',3,'expertise knowledge governance theory');
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_news_A1_01','Did you hear about...?','...에 대해 들었어요?','Did you hear about','최근 소식이나 뉴스를 자연스럽게 공유할 때 쓰는 첫 마디예요. "Did you hear about the fire?" 처럼 명사를 바로 이어 붙여요.','뉴스 공유','A1','news','pattern',NULL,1),
('s_news_A1_02','I saw on the news that...','뉴스에서 ...라는 걸 봤어요.','I saw on the news','TV나 온라인 뉴스에서 본 내용을 전달할 때 써요. "I saw on the news that there was a big flood." 처럼 that절을 이어요.','뉴스 전달','A1','news','pattern',NULL,2),
('s_news_A1_03','What happened?','무슨 일이 있었어요?','What happened','사건에 대해 더 알고 싶을 때 쓰는 가장 기본적인 질문이에요. 간단하지만 어디서든 쓸 수 있어요.','사건 질문','A1','news','pattern',NULL,3),
('s_news_A1_04','Is it true that...?','...가 사실이에요?','Is it true that','들은 이야기가 사실인지 확인할 때 써요. "Is it true that the president resigned?" 처럼 that절을 이어요.','사실 확인','A1','news','pattern',NULL,4),
('s_news_A1_05','They said on the news that...','뉴스에서 ...라고 했어요.','They said on the news','불특정 뉴스 출처를 인용할 때 "They said"를 써요. 구어체에서 아주 자주 쓰이는 표현이에요.','뉴스 인용','A1','news','pattern',NULL,5),
('s_news_A1_06','A lot of people were hurt.','많은 사람들이 다쳤어요.','A lot of people were hurt','사고나 재난 보도에서 자주 나오는 문장 구조예요. "were hurt"는 수동태로 피해를 표현해요.','피해 상황','A1','news','pattern',NULL,6),
('s_news_A1_07','The government said...','정부가 ...라고 했어요.','The government said','공식 발표나 성명을 인용할 때 가장 기본적인 구조예요. 뒤에 직접 또는 간접 인용을 붙여요.','공식 발표 인용','A1','news','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_news_A2_01','According to reports, ...','보도에 따르면, ...','According to reports','뉴스 출처를 인용할 때 쓰는 표현이에요. 좀 더 격식 있는 느낌이 나고 사실 여부를 단정하지 않는 표현이에요.','출처 인용','A2','news','pattern',NULL,1),
('s_news_A2_02','The police are investigating...','경찰이 ...을 조사하고 있어요.','are investigating','범죄나 사고에 관한 뉴스에서 매우 자주 나오는 표현이에요. 현재진행형으로 진행 중임을 나타내요.','사건 보도','A2','news','pattern',NULL,2),
('s_news_A2_03','It is believed that...','...라고 여겨져요.','It is believed that','확실하지 않은 정보를 전달할 때 쓰는 수동태 표현이에요. 직접 단정하는 것을 피할 수 있어요.','불확실 정보','A2','news','pattern',NULL,3),
('s_news_A2_04','Protests broke out in...','...에서 시위가 발생했어요.','broke out','갑작스럽게 시작된 시위나 사건을 설명할 때 "break out"을 써요. 폭동, 화재, 전쟁 등에도 써요.','시위·사건 발생','A2','news','pattern',NULL,4),
('s_news_A2_05','The government has announced that...','정부는 ...라고 발표했어요.','has announced','현재완료형으로 방금 또는 최근에 이루어진 공식 발표를 자연스럽게 표현해요.','공식 발표','A2','news','pattern',NULL,5),
('s_news_A2_06','Thousands of people took to the streets.','수천 명이 거리로 나왔어요.','took to the streets','많은 사람들이 시위를 위해 나온 것을 표현할 때 "take to the streets"를 써요. 뉴스에서 자주 보이는 관용 표현이에요.','시위 묘사','A2','news','pattern',NULL,6),
('s_news_A2_07','A ceasefire has been agreed.','휴전이 합의됐어요.','has been agreed','수동태로 협상 결과를 간결하게 전달하는 뉴스 문체 표현이에요. 주어가 누구인지 모르거나 중요하지 않을 때 써요.','협상 결과','A2','news','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_news_B1_01','The government is under pressure to...','정부가 ...에 대한 압박을 받고 있어요.','is under pressure to','정치·외교 논의에서 자주 쓰이는 표현이에요. "under pressure to reform" 처럼 동사 원형을 이어 써요.','정치 논의','B1','news','pattern',NULL,1),
('s_news_B1_02','Critics have accused the minister of...','비평가들이 장관을 ...혐의로 비난했어요.','Critics have accused','현재완료형으로 최근의 비난·고발을 전달해요. "of + 동명사" 패턴을 외워두면 편리해요.','비난·고발','B1','news','pattern',NULL,2),
('s_news_B1_03','The opposition has called for an inquiry into...','야당이 ...에 대한 조사를 요구했어요.','has called for an inquiry into','야당의 공식 요구를 표현할 때 써요. "call for"는 공식적으로 요구하다는 뜻이에요.','야당 성명','B1','news','pattern',NULL,3),
('s_news_B1_04','Unemployment figures rose to... percent.','실업률이 ...%로 올랐어요.','rose to','경제 지표를 보도할 때 쓰는 패턴이에요. "rose to", "fell to", "hit a record high/low"와 함께 외워두세요.','경제 지표','B1','news','pattern',NULL,4),
('s_news_B1_05','The legislation was passed by a majority of...','법안이 ...의 다수결로 통과됐어요.','was passed by a majority','의회에서 법안이 통과됐을 때 쓰는 수동태 표현이에요. "slim majority(근소한 다수)" 등의 수식어를 붙여요.','입법 보도','B1','news','pattern',NULL,5),
('s_news_B1_06','The minister resigned amid allegations of...','장관이 ...혐의 속에 사임했어요.','resigned amid allegations of','스캔들로 인한 사임 보도에서 자주 나오는 구조예요. "amid"는 "~속에/~가운데"라는 뜻이에요.','스캔들 보도','B1','news','pattern',NULL,6),
('s_news_B1_07','Inflation has reached its highest level in... years.','인플레이션이 ...년 만에 최고치에 달했어요.','has reached its highest level','경제 기사에서 최고점을 강조할 때 쓰는 현재완료 표현이에요. "lowest level", "highest point" 등을 바꿔 써요.','경제 보도','B1','news','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_news_B2_01','Diplomatic tensions have escalated between... and...','...와 ... 사이의 외교적 긴장이 고조됐어요.','Diplomatic tensions have escalated','두 나라 간의 갈등 고조를 표현할 때 써요. "escalate"는 상황이 점점 심각해지는 것을 나타내요.','국제 분쟁','B2','news','pattern',NULL,1),
('s_news_B2_02','Sanctions have been imposed on... in response to...','...에 대응해 ...에 제재가 부과됐어요.','Sanctions have been imposed on','제재 부과를 수동태로 표현하는 국제 뉴스 정형 문구예요. "in response to"는 이유를 나타내요.','제재 보도','B2','news','pattern',NULL,2),
('s_news_B2_03','The two nations agreed to resume diplomatic talks.','두 나라가 외교 회담 재개에 합의했어요.','agreed to resume diplomatic talks','관계 정상화를 향한 첫 걸음을 표현할 때 써요. "resume"은 중단됐다가 다시 시작함을 의미해요.','외교 관계','B2','news','pattern',NULL,3),
('s_news_B2_04','The international community has condemned the attack.','국제 사회가 공격을 규탄했어요.','has condemned','규탄 성명에서 항상 나오는 표현이에요. "condemn"은 "강하게 비난하다"는 뜻이에요.','국제 규탄','B2','news','pattern',NULL,4),
('s_news_B2_05','A multilateral agreement was reached at the summit.','정상 회담에서 다자간 합의가 이루어졌어요.','multilateral agreement was reached','다자 외교의 결과를 보도할 때 쓰는 표현이에요. "bilateral"(양자), "multilateral"(다자)을 구분해서 써요.','정상 회담','B2','news','pattern',NULL,5),
('s_news_B2_06','The regime faces growing pressure from the international community.','그 정권은 국제 사회로부터 점점 커지는 압박에 직면해 있어요.','faces growing pressure','정권이 국내외 압박을 받는 상황을 설명할 때 써요. "growing"은 압박이 점점 강해지고 있음을 나타내요.','국제 압박','B2','news','pattern',NULL,6),
('s_news_B2_07','The referendum resulted in a vote for independence.','국민 투표 결과 독립 찬성으로 나왔어요.','referendum resulted in','국민 투표 결과를 보도할 때 쓰는 표현이에요. "result in"은 특정 결과로 이어짐을 나타내요.','국민 투표','B2','news','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_news_C1_01','The decision sets a significant precedent for international law.','그 결정은 국제법에 중요한 선례를 남겨요.','sets a significant precedent','법적·외교적 판단이 미래에 미치는 영향을 설명할 때 써요. "landmark precedent", "dangerous precedent"도 자주 쓰여요.','국제법 분석','C1','news','pattern',NULL,1),
('s_news_C1_02','The sanctions regime has failed to achieve its stated objectives.','제재 체제가 명시된 목표를 달성하는 데 실패했어요.','has failed to achieve its stated objectives','정책 효과를 비판적으로 분석할 때 쓰는 표현이에요. "stated objectives"는 공식적으로 밝힌 목표를 뜻해요.','정책 비판 분석','C1','news','pattern',NULL,2),
('s_news_C1_03','The bilateral relationship has deteriorated significantly in recent months.','양자 관계가 최근 몇 달 동안 크게 악화됐어요.','has deteriorated significantly','관계 악화를 표현할 때 "deteriorate"를 써요. "improve dramatically", "stabilize gradually"와 반대 표현으로 외워요.','외교 분석','C1','news','pattern',NULL,3),
('s_news_C1_04','There are growing concerns about the erosion of democratic norms.','민주주의 규범 침식에 대한 우려가 커지고 있어요.','growing concerns about the erosion of','추상적인 제도나 가치의 약화를 표현할 때 써요. "erosion of"는 서서히 무너지는 것을 나타내요.','민주주의 분석','C1','news','pattern',NULL,4),
('s_news_C1_05','The court''s ruling may have far-reaching implications for...','법원의 판결은 ...에 광범위한 영향을 미칠 수 있어요.','may have far-reaching implications for','법적 판결이 더 넓은 영역에 미치는 파급 효과를 분석할 때 써요. "far-reaching"은 "광범위한"이라는 뜻이에요.','사법 분석','C1','news','pattern',NULL,5),
('s_news_C1_06','The government invoked emergency powers to suppress dissent.','정부가 반대 의견을 억압하기 위해 비상 권한을 발동했어요.','invoked emergency powers to suppress','강압적 통치를 보도하거나 분석할 때 쓰는 표현이에요. "invoke"는 법이나 권한을 공식 발동하는 뜻이에요.','권위주의 분석','C1','news','pattern',NULL,6),
('s_news_C1_07','Analysts warn of the risk of further escalation in the region.','분석가들은 지역 내 추가 확전 위험을 경고해요.','warn of the risk of further escalation','분쟁 지역 상황 분석에서 자주 쓰이는 표현이에요. "escalation"은 갈등 심화를, "further"는 추가적임을 나타내요.','분쟁 분석','C1','news','pattern',NULL,7);
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
('s_news_C2_01','The hegemon''s unilateral actions undermine the multilateral rules-based order.','패권국의 일방적 행동이 다자 규칙 기반 질서를 약화시켜요.','unilateral actions undermine the multilateral rules-based order','국제 정치 분석에서 핵심 패턴이에요. "rules-based order"는 현 국제 체계를 가리키는 전문 용어예요.','국제 질서 분석','C2','news','pattern',NULL,1),
('s_news_C2_02','The conflict can be read as a manifestation of postcolonial tensions.','그 분쟁은 탈식민적 긴장의 표현으로 읽힐 수 있어요.','can be read as a manifestation of','학문적·비판적 분석에서 쓰이는 표현이에요. "manifestation of"는 어떤 현상의 구체적 발현을 뜻해요.','탈식민 분석','C2','news','pattern',NULL,2),
('s_news_C2_03','Securitization of the issue has foreclosed alternative policy responses.','그 문제의 안보화가 대안적 정책 대응을 차단했어요.','Securitization of the issue has foreclosed','코펜하겐 학파의 안보화 이론을 적용한 분석 표현이에요. "foreclose"는 가능성을 원천 봉쇄하는 것을 뜻해요.','안보화 이론','C2','news','pattern',NULL,3),
('s_news_C2_04','The normative framework underpinning the international order is being contested.','국제 질서를 뒷받침하는 규범적 틀이 도전받고 있어요.','normative framework underpinning the international order is being contested','국제 규범의 위기를 설명하는 학술적 표현이에요. "underpin"은 "뒷받침하다", "contest"는 "이의를 제기하다"는 뜻이에요.','규범 분석','C2','news','pattern',NULL,4),
('s_news_C2_05','The crisis exposes the epistemic limits of mainstream IR theory.','위기는 주류 국제 관계 이론의 인식론적 한계를 드러내요.','exposes the epistemic limits of','국제 관계(IR) 학문에서 이론의 설명력 한계를 비판할 때 써요. "epistemic"은 지식·인식에 관련된 형용사예요.','IR 이론 비판','C2','news','pattern',NULL,5),
('s_news_C2_06','Subaltern voices remain systematically excluded from diplomatic discourse.','하위 주체의 목소리는 외교 담론에서 체계적으로 배제돼요.','Subaltern voices remain systematically excluded','탈식민 이론과 비판 IR에서 쓰이는 표현이에요. "subaltern"은 권력 구조에서 소외된 주체를 뜻해요.','탈식민 비판','C2','news','pattern',NULL,6),
('s_news_C2_07','The state''s ontological security imperative drove its foreign policy choices.','국가의 존재론적 안보 요구가 외교 정책 선택을 이끌었어요.','ontological security imperative drove its foreign policy choices','미어샤이머나 스틸(Steele) 등의 이론에서 나온 분석 틀이에요. "ontological security"는 국가의 정체성 안정감을 뜻해요.','존재론적 안보','C2','news','pattern',NULL,7);
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order) VALUES
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, example_en_2, example_ko_2, example_en_3, example_ko_3, example_en_4, example_ko_4, example_en_5, example_ko_5, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('w_greeting_A1_36', 'wave', '/weɪv/', 'verb', '손을 흔들다', 'To move your hand to greet someone.', 'She waved at her friend across the street.', '그녀는 길 건너 친구에게 손을 흔들었어요.', 'He waved goodbye from the train window.', '그는 기차 창문에서 손을 흔들며 작별했어요.', 'The children waved as the bus drove away.', '버스가 떠나자 아이들이 손을 흔들었어요.', 'She waved to catch his attention in the crowd.', '그녀는 군중 속에서 그의 시선을 끌려고 손을 흔들었어요.', 'He gave a friendly wave and smiled.', '그는 친근하게 손을 흔들며 미소를 지었어요.', 'A1', 'greeting', 1, 'waving hand hello friendly', 36),
('w_greeting_A1_37', 'smile', '/smaɪl/', 'verb', '미소 짓다', 'To show happiness by curving your lips upward.', 'She smiled warmly when they first met.', '처음 만났을 때 그녀는 따뜻하게 미소를 지었어요.', 'He always smiles when greeting his colleagues.', '그는 동료들에게 인사할 때 항상 미소를 지어요.', 'A genuine smile is the best greeting of all.', '진심 어린 미소가 가장 좋은 인사예요.', 'She smiled and extended her hand for a handshake.', '그녀는 미소를 지으며 악수를 위해 손을 내밀었어요.', 'He could not help but smile at the warm welcome.', '따뜻한 환영에 그는 저절로 미소가 지어졌어요.', 'A1', 'greeting', 1, 'smiling face warm greeting happy', 37),
('w_greeting_A1_38', 'bow', '/baʊ/', 'verb', '절하다, 고개를 숙이다', 'To bend your head or body as a sign of respect.', 'He bowed politely when meeting the elder.', '어른을 만날 때 그는 정중하게 절을 했어요.', 'She bowed her head as a sign of gratitude.', '감사의 표시로 그녀는 고개를 숙였어요.', 'In Japan, people bow instead of shaking hands.', '일본에서는 악수 대신 절을 해요.', 'He bowed deeply to show his sincere respect.', '깊은 존경을 나타내기 위해 그는 깊이 절을 했어요.', 'She bowed and said thank you after the performance.', '공연 후 그녀는 절을 하며 감사합니다라고 했어요.', 'A1', 'greeting', 1, 'bowing respect polite east asian', 38),
('w_greeting_A1_39', 'hug', '/hʌɡ/', 'verb', '포옹하다', 'To put your arms around someone to show affection.', 'She hugged her friend at the airport.', '그녀는 공항에서 친구를 포옹했어요.', 'They hugged warmly after not seeing each other for a year.', '일 년 만에 만나 그들은 따뜻하게 포옹했어요.', 'He gave his grandmother a long hug.', '그는 할머니를 오랫동안 포옹했어요.', 'She hugged everyone goodbye before leaving the party.', '파티를 떠나기 전 그녀는 모두에게 작별 포옹을 했어요.', 'A hug can say more than a hundred words.', '포옹은 백 마디 말보다 더 많은 것을 말할 수 있어요.', 'A1', 'greeting', 2, 'hugging friends warm reunion affection', 39),
('w_greeting_A1_40', 'look', '/lʊk/', 'verb', '바라보다, 보다', 'To direct your eyes toward something or someone.', 'He looked up and recognized his old friend.', '그는 고개를 들었다가 오랜 친구를 알아봤어요.', 'She looked around for a familiar face at the event.', '그녀는 행사에서 낯익은 얼굴을 찾으려 둘러봤어요.', 'He looked surprised when she greeted him by name.', '그녀가 이름으로 인사하자 그는 놀란 표정이었어요.', 'She looked pleased to see him after such a long time.', '오랜만에 그를 보자 그녀는 기뻐 보였어요.', 'Look up and make eye contact when greeting someone.', '인사할 때 눈을 들어 눈을 맞추세요.', 'A1', 'greeting', 1, 'eye contact looking greeting attention', 40),
('w_greeting_A1_41', 'speak', '/spiːk/', 'verb', '말하다', 'To say words to someone.', 'She spoke kindly to the new student.', '그녀는 새 학생에게 친절하게 말했어요.', 'He spoke clearly when he introduced himself.', '자기소개를 할 때 그는 명확하게 말했어요.', 'She speaks a little English, so we managed to greet each other.', '그녀는 영어를 조금 해서 우리는 인사를 나눌 수 있었어요.', 'He spoke warmly to every guest who entered the room.', '그는 방에 들어오는 모든 손님에게 따뜻하게 말했어요.', 'Do not be afraid to speak first when meeting someone new.', '새로운 사람을 만날 때 먼저 말하는 것을 두려워하지 마세요.', 'A1', 'greeting', 1, 'speaking talking conversation introduction', 41),
('w_greeting_A1_42', 'ask', '/æsk/', 'verb', '묻다, 질문하다', 'To say a question to get information.', 'She asked his name when they first met.', '처음 만났을 때 그녀는 그의 이름을 물었어요.', 'He asked where she was from to start a conversation.', '대화를 시작하기 위해 그는 어디 출신인지 물었어요.', 'She asked if the seat next to him was taken.', '옆 자리가 비어 있는지 그녀가 물었어요.', 'He asked how she was doing after a long absence.', '오랜 부재 후 그는 어떻게 지내고 있는지 물었어요.', 'Always feel free to ask someone their name.', '항상 편하게 이름을 물어보세요.', 'A1', 'greeting', 1, 'asking question conversation curious', 42),
('w_greeting_A1_43', 'remember', '/rɪˈmɛmbər/', 'verb', '기억하다', 'To keep something in your mind from the past.', 'He remembered her name from their last meeting.', '그는 지난 만남에서 그녀의 이름을 기억했어요.', 'She was happy that he remembered her.', '그가 자신을 기억한다는 것에 그녀는 기뻤어요.', 'It is polite to remember the names of people you meet.', '만나는 사람들의 이름을 기억하는 것이 예의 바른 행동이에요.', 'He always remembered to say good morning to his coworkers.', '그는 항상 동료들에게 좋은 아침이에요라고 인사하는 것을 기억했어요.', 'She remembered meeting him at the conference last year.', '그녀는 작년 컨퍼런스에서 그를 만났던 것을 기억했어요.', 'A1', 'greeting', 1, 'memory remember name face recall', 43),
('w_greeting_A1_44', 'wait', '/weɪt/', 'verb', '기다리다', 'To stay in a place until something happens.', 'He waited at the entrance to greet the guests.', '그는 손님들을 맞이하기 위해 입구에서 기다렸어요.', 'She waited patiently for her turn to introduce herself.', '자기소개 차례를 위해 그녀는 인내심 있게 기다렸어요.', 'Do not keep your guest waiting — greet them as soon as they arrive.', '손님을 기다리게 하지 마세요 — 도착하자마자 인사하세요.', 'He waited by the door, ready to welcome the new employee.', '그는 신입 직원을 환영할 준비를 하고 문 옆에서 기다렸어요.', 'She waited until everyone arrived before beginning the introductions.', '그녀는 모두가 도착할 때까지 기다렸다가 소개를 시작했어요.', 'A1', 'greeting', 1, 'waiting entrance greeting arrival welcome', 44),
('w_greeting_A1_45', 'come', '/kʌm/', 'verb', '오다', 'To move toward a place or person.', 'Come in — welcome to our home!', '들어오세요 — 저희 집에 오신 것을 환영해요!', 'She came over to say hello when she spotted him.', '그녀는 그를 발견하고 인사하러 다가왔어요.', 'He came to the party just to meet the new colleague.', '그는 새 동료를 만나기 위해 파티에 왔어요.', 'Please come and say hello when you have a moment.', '시간이 나면 인사하러 와 주세요.', 'She was glad he came — she had been hoping to meet him.', '그가 와서 기뻤어요 — 그녀는 그를 만나기를 바라고 있었어요.', 'A1', 'greeting', 1, 'coming arriving welcome greeting door', 45),
('w_greeting_A1_46', 'sit', '/sɪt/', 'verb', '앉다', 'To rest with your body on a seat.', 'Please sit — make yourself comfortable.', '앉으세요 — 편히 계세요.', 'She sat next to the newcomer to make them feel welcome.', '신입이 환영받는 느낌을 갖도록 그녀는 옆에 앉았어요.', 'He sat down and immediately introduced himself.', '그는 앉자마자 바로 자기소개를 했어요.', 'Please sit and let me get you a drink first.', '앉으세요, 먼저 음료를 가져다 드릴게요.', 'She invited him to sit before starting the conversation.', '대화를 시작하기 전 그녀는 그를 앉도록 초대했어요.', 'A1', 'greeting', 1, 'sitting chair welcome comfortable relax', 46),
('w_greeting_A1_47', 'open', '/ˈoʊpən/', 'adjective', '열린, 개방적인', 'Willing to talk and easy to approach.', 'She has an open and welcoming personality.', '그녀는 열려 있고 환영하는 성격을 가졌어요.', 'He greeted everyone with an open smile.', '그는 모든 사람에게 열린 미소로 인사했어요.', 'Keep an open body language when meeting someone new.', '새로운 사람을 만날 때 열린 몸 자세를 유지하세요.', 'She was open about her background right away.', '그녀는 자신의 배경에 대해 바로 솔직하게 말했어요.', 'An open attitude makes you easy to talk to.', '열린 태도는 당신을 이야기하기 쉬운 사람으로 만들어요.', 'A1', 'greeting', 1, 'open attitude friendly approachable welcoming', 47),
('w_greeting_A1_48', 'door', '/dɔːr/', 'noun', '문', 'The entrance to a room or building.', 'He opened the door and said welcome.', '그는 문을 열고 환영한다고 했어요.', 'She was greeted at the door by the host.', '그녀는 문 앞에서 주최자의 인사를 받았어요.', 'He held the door open as a polite gesture.', '그는 예의 바른 제스처로 문을 잡아줬어요.', 'There was a warm welcome waiting just beyond the door.', '문 너머에 따뜻한 환영이 기다리고 있었어요.', 'She answered the door and greeted her guest with a big smile.', '그녀는 문을 열고 환한 미소로 손님을 맞이했어요.', 'A1', 'greeting', 1, 'door entrance welcome greeting host', 48),
('w_greeting_A1_49', 'together', '/təˈɡɛðər/', 'adverb', '함께', 'With each other; in company.', 'Let us all say hello together.', '모두 함께 인사해요.', 'They arrived together and greeted the host as a pair.', '그들은 함께 도착해서 한 쌍으로 주최자에게 인사했어요.', 'It is more fun to meet new people together with a friend.', '친구와 함께 새로운 사람을 만나면 더 재미있어요.', 'We greeted the visitors together as a team.', '우리는 팀으로 함께 방문객들에게 인사했어요.', 'Coming together to greet someone shows genuine care.', '함께 모여 인사하는 것은 진심 어린 관심을 보여줘요.', 'A1', 'greeting', 1, 'together group greeting team collective', 49),
('w_greeting_A1_50', 'first', '/fɜːrst/', 'adjective', '처음의, 첫 번째', 'Coming before all others.', 'First impressions matter a lot in a greeting.', '인사에서 첫인상은 매우 중요해요.', 'He was the first to say hello in the room.', '그는 방에서 처음으로 인사를 했어요.', 'She greeted the first guest with extra warmth.', '그녀는 첫 번째 손님을 각별한 따뜻함으로 맞이했어요.', 'It is always good to speak first when meeting someone.', '사람을 만날 때 먼저 말하는 것이 항상 좋아요.', 'Their first meeting was brief but left a lasting impression.', '그들의 첫 만남은 짧았지만 오래도록 남는 인상을 남겼어요.', 'A1', 'greeting', 1, 'first impression meeting encounter beginning', 50),
('w_greeting_A1_51', 'know', '/noʊ/', 'verb', '알다', 'To be familiar with a person or fact.', 'Do you know anyone here? Let me introduce you.', '여기 아는 분 있어요? 소개해 드릴게요.', 'She was glad to finally get to know him in person.', '드디어 직접 그를 알게 되어 기뻤어요.', 'It is nice to know the people you work with.', '함께 일하는 사람들을 아는 것은 좋은 일이에요.', 'He did not know anyone at the event, so he introduced himself.', '그는 행사에서 아는 사람이 없어서 자기소개를 했어요.', 'Getting to know someone starts with a simple greeting.', '누군가를 알아가는 것은 간단한 인사에서 시작돼요.', 'A1', 'greeting', 1, 'knowing familiar acquainted introduction', 51),
('w_greeting_A1_52', 'early', '/ˈɜːrli/', 'adverb', '일찍', 'Before the usual or expected time.', 'He arrived early to greet the guests as they came in.', '그는 손님들이 들어오는 것을 맞이하기 위해 일찍 도착했어요.', 'She sent an early greeting before the event started.', '그녀는 행사가 시작되기 전에 미리 인사를 보냈어요.', 'It is polite to arrive early and greet the host.', '일찍 도착해서 주최자에게 인사하는 것이 예의 바른 행동이에요.', 'The early morning hello sets a positive tone for the day.', '이른 아침 인사는 하루에 긍정적인 분위기를 만들어요.', 'She was always early so she could welcome each new arrival.', '그녀는 새 도착자를 환영할 수 있도록 항상 일찍 왔어요.', 'A1', 'greeting', 2, 'early arrival punctual welcome morning', 52),
('w_greeting_A1_53', 'talk', '/tɔːk/', 'verb', '이야기하다, 말하다', 'To say words and have a conversation.', 'It was nice to talk with you today.', '오늘 이야기 나눠서 좋았어요.', 'She talked to every new person at the event.', '그녀는 행사에서 모든 새로운 사람과 이야기를 나눴어요.', 'He talked for a while before realizing they had met before.', '그는 한참 이야기하다가 전에 만난 적이 있다는 것을 깨달았어요.', 'Do not be shy — just walk up and start talking.', '수줍어하지 마세요 — 그냥 다가가서 이야기를 시작하세요.', 'She loved talking to new people and learning their stories.', '그녀는 새로운 사람들과 이야기하며 그들의 이야기를 듣는 것을 좋아했어요.', 'A1', 'greeting', 1, 'talking conversation friends casual chat', 53),
('w_greeting_A1_54', 'back', '/bæk/', 'adverb', '다시, 돌아와서', 'Returning to a place or person.', 'Welcome back — it is great to see you again!', '돌아오신 것을 환영해요 — 다시 만나니 정말 좋아요!', 'She was greeted warmly when she came back from her trip.', '여행에서 돌아왔을 때 그녀는 따뜻한 인사를 받았어요.', 'He came back to say goodbye one more time.', '그는 한 번 더 작별 인사를 하러 돌아왔어요.', 'It is always nice to say welcome back to a returning colleague.', '돌아온 동료에게 돌아오신 것을 환영한다고 하는 것은 항상 좋은 일이에요.', 'She shouted welcome back as he walked through the door.', '그가 문을 들어서자 그녀는 돌아오신 것을 환영해요라고 외쳤어요.', 'A1', 'greeting', 1, 'welcome back returning reunion greeting', 54),
('w_greeting_A1_55', 'ready', '/ˈrɛdi/', 'adjective', '준비된', 'Prepared to do something.', 'She was ready to greet every guest with a smile.', '그녀는 미소로 모든 손님을 맞이할 준비가 되어 있었어요.', 'He got ready early so he could welcome the visitors.', '그는 방문객을 환영하기 위해 일찍 준비했어요.', 'Are you ready to introduce yourself to the team?', '팀에 자기소개를 할 준비가 됐어요?', 'Being ready with a warm smile makes greeting easier.', '따뜻한 미소로 준비하면 인사가 더 쉬워져요.', 'She took a breath, smiled, and was ready to say hello.', '그녀는 숨을 들이쉬고 미소를 지었어요, 인사할 준비가 됐어요.', 'A1', 'greeting', 2, 'ready prepared smile confident meeting', 55),
('w_greeting_A1_56', 'long', '/lɒŋ/', 'adjective', '긴, 오랜', 'Lasting or measuring a great amount of time.', 'It has been a long time since we last met!', '마지막으로 만난 지 오래됐어요!', 'She gave him a long hug after the long separation.', '긴 이별 끝에 그녀는 그를 오랫동안 포옹했어요.', 'They chatted for a long time after the event ended.', '행사가 끝난 후 그들은 오랫동안 이야기를 나눴어요.', 'It was a long wait, but the reunion was worth it.', '오랫동안 기다렸지만 재회할 만한 가치가 있었어요.', 'A long friendship begins with a simple hello.', '긴 우정은 간단한 안녕이라는 한마디에서 시작돼요.', 'A1', 'greeting', 1, 'long time reunion friendship waiting', 56),
('w_greeting_A1_57', 'morning', '/ˈmɔːrnɪŋ/', 'noun', '아침', 'The early part of the day before noon.', 'Good morning is the most common greeting of the day.', '좋은 아침이에요는 하루 중 가장 흔한 인사예요.', 'She always says good morning to her neighbors.', '그녀는 항상 이웃들에게 좋은 아침이에요라고 해요.', 'He starts every morning by greeting his team.', '그는 팀에게 인사하며 매일 아침을 시작해요.', 'A bright morning greeting sets a positive tone for the day.', '밝은 아침 인사는 하루에 긍정적인 분위기를 만들어요.', 'She stood at the door every morning to say hello.', '그녀는 매일 아침 문 앞에 서서 인사를 했어요.', 'A1', 'greeting', 1, 'morning greeting sunrise hello daily', 57),
('w_greeting_A1_58', 'person', '/ˈpɜːrsən/', 'noun', '사람', 'A human being.', 'She is the kind of person who always says hello first.', '그녀는 항상 먼저 인사하는 사람이에요.', 'He greeted every person in the room by name.', '그는 방의 모든 사람을 이름으로 인사했어요.', 'A person who greets warmly is easy to trust.', '따뜻하게 인사하는 사람은 신뢰하기 쉬워요.', 'She is a very outgoing person who loves to meet people.', '그녀는 사람 만나는 것을 좋아하는 외향적인 사람이에요.', 'Every person deserves a warm and respectful greeting.', '모든 사람은 따뜻하고 존중하는 인사를 받을 자격이 있어요.', 'A1', 'greeting', 1, 'person human being social interaction', 58),
('w_greeting_A1_59', 'day', '/deɪ/', 'noun', '날, 하루', 'A period of twenty-four hours.', 'Have a great day — it was nice meeting you!', '좋은 하루 보내세요 — 만나서 반가웠어요!', 'She wished him a good day as he left the office.', '그가 사무실을 떠나자 그녀는 좋은 하루 보내라고 했어요.', 'He starts each day by greeting everyone on his team.', '그는 팀의 모든 사람에게 인사하며 하루를 시작해요.', 'A simple good day greeting can brighten someone''s whole day.', '간단한 좋은 하루 인사가 누군가의 하루 전체를 밝게 할 수 있어요.', 'She ended every conversation with have a wonderful day.', '그녀는 모든 대화를 멋진 하루 보내세요로 마쳤어요.', 'A1', 'greeting', 1, 'day greeting farewell good day', 59),
('w_greeting_A1_60', 'right', '/raɪt/', 'adverb', '바로, 맞아요', 'Immediately; exactly the right moment.', 'She greeted him right away when he walked in.', '그가 들어오자마자 그녀는 바로 인사했어요.', 'He said right, let''s get started after the introductions.', '소개가 끝난 후 그는 좋아요, 시작하자고 했어요.', 'Right, I think we have all been introduced now.', '맞아요, 이제 모두 소개가 된 것 같아요.', 'She was right there at the entrance to welcome everyone.', '그녀는 모두를 환영하기 위해 바로 입구에 있었어요.', 'He shook her hand right away without hesitation.', '그는 망설임 없이 바로 그녀와 악수를 했어요.', 'A1', 'greeting', 1, 'right immediately prompt greeting welcome', 60);
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('col_greeting_01', 'make', 'an introduction', 'make an introduction', '소개를 하다', 'do', '"do an introduction"은 어색해요. 소개할 때는 make를 써요.', 'Let me make an introduction — this is my colleague, Ji-yeon.', '소개할게요 — 제 동료 지연이에요.', 'He made a brief introduction before the meeting started.', '그는 회의가 시작되기 전에 간단히 소개를 했어요.', 'B1', 'greeting', 2, 'handshake introduction meeting people', 1),
('col_greeting_02', 'give', 'a compliment', 'give a compliment', '칭찬을 하다', 'make', '"make a compliment"도 쓰이지만 give가 더 자연스러워요.', 'She gave him a sincere compliment on his presentation.', '그녀는 그의 발표에 진심 어린 칭찬을 했어요.', 'It''s always nice to give a compliment when someone does well.', '누군가 잘했을 때 칭찬을 하는 건 언제나 좋아요.', 'B1', 'greeting', 2, 'compliment smile praise conversation', 2),
('col_greeting_03', 'pay', 'attention', 'pay attention', '주의를 기울이다', 'give', '"give attention"보다 pay attention이 훨씬 자주 쓰여요.', 'Please pay attention when someone is speaking to you.', '누군가 말할 때 주의를 기울여 주세요.', 'He didn''t pay attention and missed the important details.', '그는 주의를 기울이지 않아서 중요한 세부 사항을 놓쳤어요.', 'B1', 'greeting', 1, 'listening attention focus conversation', 3),
('col_greeting_04', 'take', 'turns', 'take turns', '교대로 하다', 'do', '"do turns"는 틀린 표현이에요. 순서를 바꿀 때는 take turns를 써요.', 'We should take turns speaking so everyone gets a chance.', '모두가 기회를 얻을 수 있도록 교대로 말해야 해요.', 'The children took turns reading aloud in class.', '아이들은 수업에서 교대로 소리 내어 읽었어요.', 'B1', 'greeting', 2, 'turn-taking group conversation teamwork', 4),
